/// One outstanding `Atomics.waitAsync` of a realm: the waiter-table ticket id
/// and the promise to settle with "ok"/"timed-out" (see `settleAsyncWaiters`).
pub const AsyncWaiterEntry = struct { id: u64, promise: Value };

/// Robustness limits so adversarial input throws a catchable error instead of
/// crashing the process (stack overflow / runaway loop).
///
/// `max_call_depth` is the *absolute* logical recursion ceiling — a backstop
/// against a runaway self-call, not the real limiter. On a platform with
/// registered stack bounds the effective limit is the native stack itself:
/// `stackGuard` throws as soon as the stack pointer is within `stack_redzone`
/// of the OS limit (`stack_scan.nearLimit`), which adapts to the actual stack
/// size and per-frame cost (much larger under ThreadSanitizer). Raising the
/// ceiling from the old 128 lets ordinary deep recursion *run* — to many
/// hundreds of frames on a normal stack — instead of throwing far below what
/// the native stack can hold. When bounds are unavailable the probe is blind,
/// so a conservative cap (`conservative_call_depth`) still prevents a crash.
pub const max_call_depth: u32 = 16384;
/// Fallback recursion cap used only when the native stack-pointer probe can't
/// protect the thread (`!stack_scan.boundsKnown()`), so an unsupported platform
/// can't overflow. Matches the old hard limit.
const conservative_call_depth: u32 = 128;
pub const max_steps: u64 = 500_000_000;

/// Below this logical call depth, a chain can't have consumed enough native
/// stack to matter, so the call guard skips the stack-pointer probe and the
/// hot shallow-call path stays a single depth compare (serial-perf gate).
const stack_check_floor: u32 = 32;
/// Native-stack headroom kept free below the thread's real OS stack limit. If a
/// deeper call would leave less than this, the guard throws `RangeError` rather
/// than let the tree-walker's native recursion fault the guard page. It must
/// cover the deepest the throw/unwind path itself reaches. Under ThreadSanitizer
/// frames inflate ~10×, so the redzone does too; a normal build keeps it small
/// so the reserve doesn't needlessly cap recursion depth.
const stack_redzone: usize = if (builtin.sanitize_thread) 1 << 20 else 1 << 18; // 1 MiB TSan / 256 KiB normal
const max_typed_array_bytes: usize = 1 << 30;
const max_temporal_instant_ns: i128 = 8_640_000_000_000_000_000_000;

/// Coerce a JS number to a length/index, clamping NaN/negative to 0 and huge
/// values to a cap (so `@intFromFloat` never panics; oversized allocations then
/// fail gracefully as OutOfMemory).
pub fn toLen(n: f64) usize {
    if (std.math.isNan(n) or n <= 0) return 0;
    if (n > 4294967295) return 4294967295;
    return @intFromFloat(@trunc(n));
}

fn toArrayLikeLen(n: f64) usize {
    if (std.math.isNan(n) or n <= 0) return 0;
    if (n > 9007199254740991.0) return 9007199254740991;
    return @intFromFloat(@trunc(n));
}

/// True for any ECMAScript WhiteSpace or LineTerminator code point — the exact
/// set `String.prototype.trim`/`trimStart`/`trimEnd` strip, and the StrWhiteSpace
/// that `parseInt`/`parseFloat`/`Number(str)` skip at the start of their argument.
pub fn isJsTrimCp(cp: u21) bool {
    return switch (cp) {
        0x0009, 0x000A, 0x000B, 0x000C, 0x000D, 0x0020 => true,
        0x00A0, 0x1680 => true,
        0x2000...0x200A => true,
        0x2028, 0x2029, 0x202F, 0x205F, 0x3000, 0xFEFF => true,
        else => false,
    };
}

/// Trim leading and/or trailing ECMAScript WhiteSpace+LineTerminator code points
/// from `s`. UTF-8 aware: a non-ASCII byte at a boundary is decoded so e.g. NBSP
/// (U+00A0) and the ideographic space (U+3000) are stripped, not just ASCII.
fn jsTrim(s: []const u8, trim_start_: bool, trim_end_: bool) []const u8 {
    var lo: usize = 0;
    var hi: usize = s.len;
    if (trim_start_) {
        while (lo < hi) {
            const c = s[lo];
            const cp_len: usize = if (c < 0x80) 1 else (std.unicode.utf8ByteSequenceLength(c) catch break);
            if (lo + cp_len > hi) break;
            const cp: u21 = if (cp_len == 1) @as(u21, c) else (std.unicode.utf8Decode(s[lo .. lo + cp_len]) catch break);
            if (!isJsTrimCp(cp)) break;
            lo += cp_len;
        }
    }
    if (trim_end_) {
        var last_end: usize = lo;
        var i: usize = lo;
        while (i < hi) {
            const c = s[i];
            const cp_len: usize = if (c < 0x80) 1 else (std.unicode.utf8ByteSequenceLength(c) catch {
                last_end = hi;
                break;
            });
            if (i + cp_len > hi) {
                last_end = hi;
                break;
            }
            const cp: u21 = if (cp_len == 1) @as(u21, c) else (std.unicode.utf8Decode(s[i .. i + cp_len]) catch {
                last_end = i + cp_len;
                i += cp_len;
                continue;
            });
            i += cp_len;
            if (!isJsTrimCp(cp)) last_end = i;
        }
        hi = last_end;
    }
    return s[lo..hi];
}

fn localeIsTurkic(loc: []const u8) bool {
    return loc.len >= 2 and (std.mem.eql(u8, loc[0..2], "tr") or std.mem.eql(u8, loc[0..2], "az")) and
        (loc.len == 2 or loc[2] == '-');
}

fn localeIsLithuanian(loc: []const u8) bool {
    return loc.len >= 2 and std.mem.eql(u8, loc[0..2], "lt") and (loc.len == 2 or loc[2] == '-');
}

fn markLenAt(s: []const u8, i: usize, mark: []const u8) ?usize {
    if (i + mark.len <= s.len and std.mem.eql(u8, s[i .. i + mark.len], mark)) return mark.len;
    return null;
}

fn combiningAboveLen(s: []const u8, i: usize) ?usize {
    if (markLenAt(s, i, "\xcc\x80")) |n| return n; // U+0300 grave
    if (markLenAt(s, i, "\xcc\x81")) |n| return n; // U+0301 acute
    if (markLenAt(s, i, "\xcc\x83")) |n| return n; // U+0303 tilde
    if (markLenAt(s, i, "\xcc\x87")) |n| return n; // U+0307 dot above
    if (markLenAt(s, i, "\xf0\x9d\x86\x85")) |n| return n; // U+1D185 musical combining doit
    return null;
}

fn combiningBelowLen(s: []const u8, i: usize) ?usize {
    if (markLenAt(s, i, "\xcc\xa3")) |n| return n; // U+0323 dot below
    if (markLenAt(s, i, "\xcc\xa5")) |n| return n; // U+0325 ring below
    if (markLenAt(s, i, "\xf0\x90\x87\xbd")) |n| return n; // U+101FD Phaistos combining oblique stroke
    return null;
}

fn combiningLen(s: []const u8, i: usize) ?usize {
    if (combiningAboveLen(s, i)) |n| return n;
    if (combiningBelowLen(s, i)) |n| return n;
    return null;
}

fn turkicUpper(self: *Interpreter, s: []const u8) EvalError![]const u8 {
    var buf: std.ArrayListUnmanaged(u8) = .empty;
    var i: usize = 0;
    while (i < s.len) {
        if (s[i] == 'i') {
            try buf.appendSlice(self.arena, "\xc4\xb0");
            i += 1;
        } else if (i + 1 < s.len and s[i] == 0xc4 and s[i + 1] == 0xb1) {
            try buf.append(self.arena, 'I');
            i += 2;
        } else {
            try buf.append(self.arena, s[i]);
            i += 1;
        }
    }
    return unicode_case.toUpper(self.arena, try buf.toOwnedSlice(self.arena));
}

fn turkicLower(self: *Interpreter, s: []const u8) EvalError![]const u8 {
    var buf: std.ArrayListUnmanaged(u8) = .empty;
    var i: usize = 0;
    while (i < s.len) {
        if (i + 1 < s.len and s[i] == 0xc4 and s[i + 1] == 0xb0) {
            try buf.append(self.arena, 'i');
            i += 2;
        } else if (s[i] == 'I') {
            var j = i + 1;
            var remove_dot = false;
            while (j < s.len) {
                if (markLenAt(s, j, "\xcc\x87") != null) {
                    remove_dot = true;
                    break;
                }
                if (combiningBelowLen(s, j)) |n| {
                    j += n;
                    continue;
                }
                break;
            }
            if (remove_dot) {
                try buf.append(self.arena, 'i');
                i += 1;
                while (i < s.len) {
                    if (i + 1 < s.len and s[i] == 0xcc and s[i + 1] == 0x87) {
                        i += 2;
                        break;
                    }
                    try buf.append(self.arena, s[i]);
                    i += 1;
                }
            } else {
                try buf.appendSlice(self.arena, "\xc4\xb1");
                i += 1;
            }
        } else {
            try buf.append(self.arena, s[i]);
            i += 1;
        }
    }
    return unicode_case.toLower(self.arena, try buf.toOwnedSlice(self.arena));
}

fn lithuanianLower(self: *Interpreter, s: []const u8) EvalError![]const u8 {
    const nfd = try unicode_normalize.normalize(self.arena, s, .nfd);
    var buf: std.ArrayListUnmanaged(u8) = .empty;
    var i: usize = 0;
    while (i < nfd.len) {
        if (i + 2 <= nfd.len) {
            const two = nfd[i .. i + 2];
            if (std.mem.eql(u8, two, "\xc3\x8c")) { // Ì
                try buf.appendSlice(self.arena, "i\xcc\x87\xcc\x80");
                i += 2;
                continue;
            }
            if (std.mem.eql(u8, two, "\xc3\x8d")) { // Í
                try buf.appendSlice(self.arena, "i\xcc\x87\xcc\x81");
                i += 2;
                continue;
            }
            if (std.mem.eql(u8, two, "\xc4\xa8")) { // Ĩ
                try buf.appendSlice(self.arena, "i\xcc\x87\xcc\x83");
                i += 2;
                continue;
            }
        }
        const base: ?[]const u8 = if (nfd[i] == 'I')
            "i"
        else if (nfd[i] == 'J')
            "j"
        else if (i + 2 <= nfd.len and std.mem.eql(u8, nfd[i .. i + 2], "\xc4\xae"))
            "\xc4\xaf"
        else
            null;
        if (base) |lower| {
            var j = i + if (nfd[i] < 0x80) @as(usize, 1) else @as(usize, 2);
            var has_above = false;
            while (j < nfd.len) {
                if (combiningAboveLen(nfd, j)) |n| {
                    has_above = true;
                    j += n;
                    continue;
                }
                if (combiningBelowLen(nfd, j)) |n| {
                    j += n;
                    continue;
                }
                break;
            }
            try buf.appendSlice(self.arena, lower);
            if (has_above) try buf.appendSlice(self.arena, "\xcc\x87");
            i += if (nfd[i] < 0x80) 1 else 2;
            continue;
        }
        if (nfd[i] < 0x80) {
            try buf.append(self.arena, if (nfd[i] >= 'A' and nfd[i] <= 'Z') nfd[i] + 32 else nfd[i]);
            i += 1;
        } else {
            const seq_len: usize = std.unicode.utf8ByteSequenceLength(nfd[i]) catch 1;
            const j = @min(i + seq_len, nfd.len);
            try buf.appendSlice(self.arena, try unicode_case.toLower(self.arena, nfd[i..j]));
            i = j;
        }
    }
    return buf.toOwnedSlice(self.arena);
}

fn softDottedLen(s: []const u8, i: usize) ?usize {
    const marks = [_][]const u8{
        "i",            "j",            "\xc4\xaf",     "\xc9\x89",     "\xc9\xa8",     "\xca\x9d",
        "\xca\xb2",     "\xcf\xb3",     "\xd1\x96",     "\xd1\x98",     "\xe1\xb5\xa2", "\xe1\xb6\x96",
        "\xe1\xb6\xa4", "\xe1\xb6\xa8", "\xe1\xb8\xad", "\xe1\xbb\x8b", "\xe2\x81\xb1", "\xe2\x85\x88",
        "\xe2\x85\x89", "\xe2\xb1\xbc",
    };
    for (marks) |m| if (markLenAt(s, i, m)) |n| return n;
    if (i + 4 <= s.len and s[i] == 0xf0 and s[i + 1] == 0x9d) return 4; // mathematical soft-dotted letters in the test262 list
    return null;
}

fn lithuanianUpper(self: *Interpreter, s: []const u8) EvalError![]const u8 {
    var buf: std.ArrayListUnmanaged(u8) = .empty;
    var i: usize = 0;
    while (i < s.len) {
        if (softDottedLen(s, i)) |base_len| {
            try buf.appendSlice(self.arena, try unicode_case.toUpper(self.arena, s[i .. i + base_len]));
            i += base_len;
            while (i < s.len) {
                if (markLenAt(s, i, "\xcc\x87")) |n| {
                    i += n;
                    break;
                }
                if (combiningBelowLen(s, i)) |n| {
                    try buf.appendSlice(self.arena, s[i .. i + n]);
                    i += n;
                    continue;
                }
                break;
            }
            continue;
        }
        const seq_len: usize = if (s[i] < 0x80) 1 else (std.unicode.utf8ByteSequenceLength(s[i]) catch 1);
        const j = @min(i + seq_len, s.len);
        try buf.appendSlice(self.arena, try unicode_case.toUpper(self.arena, s[i..j]));
        i = j;
    }
    return buf.toOwnedSlice(self.arena);
}

/// `error.Throw` is the carrier for *any* JS exception: the thrown value lives
/// in `Interpreter.exception`. `error.OutOfMemory` is the only genuine host
/// failure. (ReferenceError/TypeError are no longer Zig errors — they are real,
/// catchable JS `Error` objects raised via `error.Throw`.)
pub const EvalError = error{ OutOfMemory, Throw, OptShortCircuit };

/// A lexical scope with a parent chain. Function calls push a fresh scope whose
/// `parent` is the function's closure environment, which gives real closures.
/// Variable names are duplicated into `arena` on first definition so they
/// outlive the source buffer of any single evaluation.
/// A `using`/`await using` resource registered for disposal at scope exit:
/// its value and the (pre-resolved) `[Symbol.dispose]`/`[Symbol.asyncDispose]`
/// method. `method == undefined` is the async null/undefined no-op sentinel.
pub const Disposable = struct { value: Value, method: Value, is_async: bool, await_result: bool = false };

pub const Environment = struct {
    vars: std.StringHashMapUnmanaged(Value) = .{},
    /// `using` resources declared in this scope, in declaration order (disposed
    /// in reverse when the scope exits).
    disposables: std.ArrayListUnmanaged(Disposable) = .empty,
    /// Pending error while a VM async-disposal step is suspended at an await.
    dispose_pending: ?Value = null,
    /// Names in `vars` declared `const` — assigning to them is a TypeError.
    consts: std.StringHashMapUnmanaged(void) = .{},
    /// Names that are *non-strict* immutable bindings — a named function
    /// expression's own name. Reassignment throws in strict code but is a silent
    /// no-op in sloppy code (unlike `const`, which always throws).
    fn_names: std.StringHashMapUnmanaged(void) = .{},
    /// Names that are *deletable* bindings — a sloppy direct eval's top-level
    /// `var`/function declarations create deletable (configurable) bindings in the
    /// surrounding variable environment (EvalDeclarationInstantiation step 16.b),
    /// unlike ordinary declarations. `delete x` removes such a binding and returns
    /// true; a subsequent reference is then unresolvable (ReferenceError).
    deletable: std.StringHashMapUnmanaged(void) = .{},
    /// Module *indirect bindings* (`import { x } from "m"`): `local` resolves
    /// live to `name` in another module's environment, so a mutation of the
    /// exporter's binding is visible here. Assigning to one is a TypeError.
    aliases: std.StringHashMapUnmanaged(Alias) = .{},
    arena: std.mem.Allocator,
    /// Optional allocator for binding-table buckets and duplicated binding
    /// names. Null keeps the legacy arena-owned path; GC contexts set this to
    /// the context backing allocator so an Environment finalizer can reclaim
    /// its side tables before context teardown.
    bindings_allocator: ?std.mem.Allocator = null,
    /// Internal accounting for GC-owned duplicated binding-name bytes.
    gc_name_bytes_live: ?*usize = null,
    parent: ?*Environment = null,
    /// True for a function or the global scope (a *variable* environment); false
    /// for a block `{…}` scope. `var`/function declarations hoist to the nearest
    /// variable environment, while `let`/`const`/`class` bind in the block.
    fn_scope: bool = false,
    /// True for the *function body* block — a real block env (so it can hold the
    /// body's top-level `let`/`const`) but treated like the variable scope for
    /// function-declaration hoisting and Annex B B.3.3 analysis: a function
    /// declared directly in the body is var-scoped, not block-scoped.
    fn_body: bool = false,
    /// True for the declarative environment that holds a *simple* (single
    /// BindingIdentifier) catch parameter. Annex B.3.5 lets a direct eval's `var`
    /// match such a binding without the lexical-conflict SyntaxError, so
    /// EvalDeclarationInstantiation skips this environment in its conflict walk.
    is_catch_param: bool = false,
    /// An object Environment Record for a `with (obj) {…}` block: identifier
    /// resolution at this chain position consults `obj`'s properties (honoring
    /// `Symbol.unscopables`). Because it sits in the lexical chain, a binding
    /// declared *inside* the `with` (innermost) shadows it, and it in turn
    /// shadows outer scopes — and a function defined inside the `with` captures
    /// it through its closure.
    with_object: ?*value.Object = null,
    /// Phase 7 / M3: serializes the binding storage a concurrent GC marker reads
    /// in `traceEnv` (`vars` values, `disposables`, `aliases`) against the
    /// mutator's binding writes (`put`/`assign`/`putAlias`, `using` registration).
    /// Like `Object.property_lock`: writers take it; lookups (`get`/`isConst`/…),
    /// which only read, do not. Uncontended when the GC is off or not marking
    /// concurrently (a single atomic CAS, mirroring the Object element locks).
    binding_lock: std.atomic.Mutex = .unlocked,

    /// Binding locks are only needed when a context runs the GC marker
    /// concurrently (`concurrent_gc`) or multiple mutators in parallel
    /// (`parallel_gc`). The default engine is GIL-serialized / single-threaded,
    /// where they would be pure overhead on the hottest paths (`get` on every
    /// variable read, `put` on every binding). So gate every `binding_lock`
    /// acquisition on this process-global flag — set once when such a context is
    /// created (before any thread runs), so a lock/unlock pair always observes
    /// the same value. Off → `lockBindings`/`unlockBindings` are a single relaxed
    /// load and return (no CAS), keeping the default path fast.
    pub var binding_locks_enabled: std.atomic.Value(bool) = .init(false);

    pub fn lockBindings(self: *Environment) void {
        if (!binding_locks_enabled.load(.acquire)) return;
        var spins: usize = 0;
        while (!self.binding_lock.tryLock()) : (spins += 1) {
            if ((spins & 0xff) == 0) std.Thread.yield() catch {} else std.atomic.spinLoopHint();
        }
    }
    pub fn unlockBindings(self: *Environment) void {
        if (!binding_locks_enabled.load(.acquire)) return;
        self.binding_lock.unlock();
    }

    /// Define (or overwrite) a binding in *this* scope (used by let/const).
    pub fn put(self: *Environment, name: []const u8, v: Value) EvalError!void {
        gc_mod.barrierValue(v); // binding stored into this (GC-cell) environment
        const a = self.bindingAllocator();
        self.lockBindings();
        defer self.unlockBindings();
        const gop = try self.vars.getOrPut(a, name);
        if (!gop.found_existing) gop.key_ptr.* = try self.dupeBindingName(name);
        gop.value_ptr.* = v;
    }

    /// Define a `const` binding in this scope (marks it immutable for `assign`).
    pub fn putConst(self: *Environment, name: []const u8, v: Value) EvalError!void {
        try self.put(name, v);
        const a = self.bindingAllocator();
        self.lockBindings(); // serialize the consts table vs a concurrent isConst read
        defer self.unlockBindings();
        const gop = try self.consts.getOrPut(a, name);
        if (!gop.found_existing) gop.key_ptr.* = try self.dupeBindingName(name);
    }

    /// Bind a named function expression's own name (immutable, non-strict).
    pub fn putFnName(self: *Environment, name: []const u8, v: Value) EvalError!void {
        try self.put(name, v);
        const a = self.bindingAllocator();
        self.lockBindings(); // serialize the fn_names table vs a concurrent isFnName read
        defer self.unlockBindings();
        const gop = try self.fn_names.getOrPut(a, name);
        if (!gop.found_existing) gop.key_ptr.* = try self.dupeBindingName(name);
    }

    /// Mark a binding in *this* scope as deletable (a sloppy eval-created var/fn).
    pub fn markDeletable(self: *Environment, name: []const u8) EvalError!void {
        const a = self.bindingAllocator();
        self.lockBindings();
        defer self.unlockBindings();
        const gop = try self.deletable.getOrPut(a, name);
        if (!gop.found_existing) gop.key_ptr.* = try self.dupeBindingName(name);
    }

    /// Remove a binding from *this* scope entirely (DeleteBinding for a deletable
    /// eval var). Drops it from `vars` and every side table so it no longer
    /// resolves. Returns whether a binding was present.
    pub fn removeVar(self: *Environment, name: []const u8) bool {
        self.lockBindings();
        defer self.unlockBindings();
        const removed = self.vars.remove(name);
        _ = self.consts.remove(name);
        _ = self.fn_names.remove(name);
        _ = self.deletable.remove(name);
        return removed;
    }

    /// Whether the nearest binding named `name` is a non-strict immutable
    /// (function-expression name) binding. Matches where `assign` would write.
    pub fn isFnName(self: *Environment, name: []const u8) bool {
        var env: ?*Environment = self;
        while (env) |e| {
            e.lockBindings(); // see `get`: per-env read lock vs concurrent binding writes
            if (e.vars.contains(name)) {
                const r = e.fn_names.contains(name);
                e.unlockBindings();
                return r;
            }
            e.unlockBindings();
            env = e.parent;
        }
        return false;
    }

    /// Whether the nearest binding named `name` is `const` (null if no binding).
    /// Matches where `assign` would write, so shadowing is handled correctly.
    pub fn isConst(self: *Environment, name: []const u8) ?bool {
        var env: ?*Environment = self;
        while (env) |e| {
            e.lockBindings();
            if (e.vars.contains(name)) {
                const r = e.consts.contains(name);
                e.unlockBindings();
                return r;
            }
            e.unlockBindings();
            env = e.parent;
        }
        return null;
    }

    /// The nearest enclosing variable environment (function or global), where
    /// `var`/function declarations live.
    pub fn varScope(self: *Environment) *Environment {
        var e = self;
        while (!e.fn_scope) {
            e = e.parent orelse return e;
        }
        return e;
    }

    /// Assign to the nearest existing binding (used by `=`); if none exists,
    /// create it on the global (root) scope, matching sloppy-mode semantics.
    pub fn assign(self: *Environment, name: []const u8, v: Value) EvalError!void {
        var env: ?*Environment = self;
        while (env) |e| {
            if (e.vars.getPtr(name)) |ptr| {
                gc_mod.barrierValue(v); // reassigned binding in a (GC-cell) env
                // Lock `e` around the value write so it serializes with a
                // concurrent marker reading `e.vars`. `ptr` stays valid: only a
                // structural `put` rehashes, and a single mutator never races its
                // own put here (the marker only reads).
                e.lockBindings();
                ptr.* = v;
                e.unlockBindings();
                return;
            }
            env = e.parent;
        }
        var root = self;
        while (root.parent) |p| root = p;
        try root.put(name, v);
    }

    /// An indirect (module import) binding: `name` in module environment `env`.
    pub const Alias = struct { env: *Environment, name: []const u8 };

    /// Install an indirect binding `local` → `target.name` (a module import).
    pub fn putAlias(self: *Environment, local: []const u8, target: *Environment, name: []const u8) EvalError!void {
        const a = self.bindingAllocator();
        self.lockBindings(); // traceEnv reads `aliases`; serialize the structural write
        defer self.unlockBindings();
        const gop = try self.aliases.getOrPut(a, local);
        if (!gop.found_existing) gop.key_ptr.* = try self.dupeBindingName(local);
        gop.value_ptr.* = .{ .env = target, .name = try self.dupeBindingName(name) };
    }

    /// Whether `name` resolves (in the nearest scope that binds it) to a module
    /// import — an immutable indirect binding.
    pub fn isAlias(self: *Environment, name: []const u8) bool {
        var env: ?*Environment = self;
        while (env) |e| {
            e.lockBindings();
            if (e.aliases.contains(name)) {
                e.unlockBindings();
                return true;
            }
            if (e.vars.contains(name)) {
                e.unlockBindings();
                return false;
            }
            e.unlockBindings();
            env = e.parent;
        }
        return false;
    }

    /// Look up a binding, walking outward through enclosing scopes. A module
    /// import (`aliases`) resolves live in its exporting module's environment.
    pub fn get(self: *Environment, name: []const u8) ?Value {
        var env: ?*Environment = self;
        while (env) |e| {
            // Read each scope's binding tables under its own `binding_lock` so a
            // concurrent `put`/`putAlias` rehash on a shared env (post-GIL) can't
            // tear the read or free the table under us. Locked per-env, never
            // nested (the alias recursion runs after unlock), so no deadlock; and
            // `get` is never called while a `binding_lock` is held.
            e.lockBindings();
            if (e.aliases.get(name)) |a| {
                e.unlockBindings();
                return a.env.get(a.name);
            }
            if (e.vars.get(name)) |v| {
                e.unlockBindings();
                return v;
            }
            e.unlockBindings();
            env = e.parent;
        }
        return null;
    }

    pub fn bindingAllocator(self: *const Environment) std.mem.Allocator {
        return self.bindings_allocator orelse self.arena;
    }

    fn dupeBindingName(self: *Environment, name: []const u8) EvalError![]u8 {
        const copy = try self.bindingAllocator().dupe(u8, name);
        if (self.bindings_allocator != null) {
            if (self.gc_name_bytes_live) |live| _ = @atomicRmw(usize, live, .Add, copy.len, .monotonic);
        }
        return copy;
    }

    pub fn freeBindingName(self: *Environment, name: []const u8) void {
        if (self.bindings_allocator) |a| {
            a.free(name);
            if (self.gc_name_bytes_live) |live| {
                _ = @atomicRmw(usize, live, .Sub, name.len, .monotonic);
            }
        }
    }
};

/// The shared, mutable `this` binding of a derived constructor activation. A
/// derived ctor starts uninitialized and is bound exactly once by `super()`;
/// arrows defined lexically inside it share THIS cell (not the interpreter's
/// ambient this-state), so an arrow's `super()` initializes the enclosing ctor's
/// `this` even when the arrow is invoked from an unrelated dynamic context (e.g.
/// an iterator's `return()` running during the ctor's IteratorClose).
pub const ThisCell = struct {
    value: Value = Value.undef(),
    initialized: bool = false,
};

pub const ImportMetaSlot = struct {
    obj: ?*value.Object = null,
};

/// A JS-defined function value: parameter names, body AST, and the environment
/// captured at definition (the closure). Stored type-erased on `Object.js_func`.
pub const Function = struct {
    params: []const ast.Param,
    body: *ast.Node,
    is_expr_body: bool,
    is_arrow: bool = false,
    closure: *Environment,
    name: []const u8 = "",
    /// Exact source text of the function definition, for `Function.prototype.
    /// toString`. Empty when the parser didn't capture it (then toString falls
    /// back to native-function syntax).
    source: []const u8 = "",
    /// Compiled body for the bytecode VM. Set when the function was created by
    /// the VM (`make_closure`); null for tree-walk-created closures, which are
    /// invoked via `callFunction`.
    chunk: ?*bc.Chunk = null,
    /// VM closure capture: the defining function's frame (type-erased `*vm.Frame`),
    /// for resolving upvalues. Null at the top level. The slot count to allocate
    /// for this function's own frame.
    frame: ?*anyopaque = null,
    local_count: u32 = 0,
    /// Class method support: the object on which this method/constructor lives
    /// (its [[HomeObject]]); `super.x` resolves on `home_object.protoAtomic()`.
    home_object: ?*value.Object = null,
    /// For a derived class constructor: the superclass object, called by `super(...)`.
    super_ctor: ?*value.Object = null,
    /// The declaring class evaluation's private-name map (`#x` → its unique storage
    /// key). A direct eval inside this function's body resolves the private names it
    /// references through this map (`getWithEval(){ return eval("this.#x") }`).
    /// Null for non-class functions; arrows inherit the enclosing one at call time.
    private_map: ?*const std.StringHashMapUnmanaged([]const u8) = null,
    /// Arrow functions capture `this` lexically at creation (like `home_object`
    /// and `super_ctor`); every call uses this captured value and ignores any
    /// provided `this` (a `.call`/`.apply`/`.bind` thisArg, or the receiver of a
    /// method/bare call). Only meaningful when `is_arrow` is set.
    arrow_this: Value = Value.undef(),
    /// Arrow functions also capture `new.target` lexically at creation: an arrow
    /// has no own new.target, so every call resolves it to the value that was in
    /// effect where the arrow was defined — F's new.target if defined inside a
    /// `new F()` activation, even when the arrow is called later. Only meaningful
    /// when `is_arrow` is set.
    arrow_new_target: Value = Value.undef(),
    // Whether this arrow is lexically inside a derived constructor — so `super()`
    // is legal in it (captured at creation; an arrow's super()-validity is
    // lexical, not the dynamic caller's, e.g. an arrow invoked by an iterator's
    // `return()` during the constructor's IteratorClose).
    arrow_in_derived_ctor: bool = false,
    /// For an arrow defined lexically inside a derived constructor: a pointer to
    /// that ctor activation's shared `this` cell, so the arrow's `super()` /
    /// `this` reads target the enclosing ctor's binding. Null for non-arrows and
    /// for arrows not inside a derived ctor. Captured at creation.
    this_cell: ?*ThisCell = null,
    /// Class constructors have [[FunctionKind]] "classConstructor": they cannot
    /// be called without [[Construct]], and derived constructors must initialize
    /// `this` through `super()` before completing normally.
    is_class_constructor: bool = false,
    is_derived_constructor: bool = false,
    // A synthesized default derived constructor (`constructor(...args){ super(...args) }`):
    // it forwards its arguments to the super constructor DIRECTLY, without the
    // observable @@iterator of a real spread.
    is_default_ctor: bool = false,
    /// True when this (arrow) function was created lexically inside a class field
    /// initializer / static block. The field-initializer eval restrictions
    /// (`new.target` ⇒ undefined; a direct eval may not reference `arguments` or
    /// call `super()`) are lexical, so an arrow defined there carries the context
    /// even when invoked later (`x = () => eval('arguments')`). Only meaningful for
    /// arrows; a non-arrow call always resets the field-initializer context.
    field_init_ctx: bool = false,
    /// A derived class constructor's instance field initializers, run when
    /// `super()` returns (not at the start of the body). Empty for a base class,
    /// whose field initializers are prepended to the body and run at its start.
    field_inits: []const *ast.Node = &.{},
    /// The private instance member names (fields/methods/accessors) this class's
    /// constructor brands each instance with: a base class at the start of the
    /// constructor, a derived class when `super()` returns.
    private_brand_names: []const []const u8 = &.{},
    /// `function*`: calling this returns a generator object instead of running
    /// the body. `gen_chunk` is the body compiled for the suspendable VM (null if
    /// the body falls outside the VM's lowered subset — then calling it throws).
    is_generator: bool = false,
    gen_chunk: ?*bc.Chunk = null,
    /// Back-pointer to the object wrapping this function, set at creation. Lets
    /// `makeGenerator` read the function's (lazily-materialized) `.prototype`
    /// property to use as the new generator instance's [[Prototype]].
    obj: ?*value.Object = null,
    /// `async function` / `async () => …` (and, with `is_generator`, an async
    /// generator). The Promise + microtask runtime is not yet implemented, so
    /// *calling* an async function throws; it parses and binds like any other
    /// function (a never-called async function is fully valid).
    is_async: bool = false,
    /// A plain async function's body compiled for the suspendable VM, where
    /// `await` is a suspend point driven by promise settlement (null if the body
    /// falls outside the VM's lowered subset → the tree-walker handles it).
    async_chunk: ?*bc.Chunk = null,
    /// Strict-mode function (see `ast.FunctionNode.is_strict`). Gates sloppy-only
    /// behaviors — currently `this`-substitution on a null/undefined receiver.
    is_strict: bool = false,
    /// A concise method (object/class method, get/set) — has no [[Construct]], so
    /// it is not a constructor (e.g. `%TypedArray%.from.call(method)` is a TypeError).
    is_method: bool = false,
    /// The module-local `import.meta` cell captured at function creation. Null in
    /// Script code, where `import.meta` is a syntax error.
    import_meta_slot: ?*ImportMetaSlot = null,
    /// The `with`-scope chain captured at definition (object environment records
    /// enclosing the function). A function called from inside a `with` does NOT
    /// see the caller's `with` object — only the ones lexically enclosing its own
    /// definition — so the call restores this snapshot for the duration.
    with_stack: []*value.Object = &.{},
};

/// Non-local control flow the tree-walker propagates up the statement list:
/// `ret` unwinds to the enclosing function, `brk`/`cont` to the enclosing loop.
const Signal = enum { none, ret, brk, cont };

/// Legacy static RegExp match state (Annex B 22.2.4.x). All slices are owned by
/// the interpreter arena; the empty string is the initial/no-match value.
const RegExpLegacy = struct {
    input: []const u8 = "",
    last_match: []const u8 = "",
    last_paren: []const u8 = "",
    left_context: []const u8 = "",
    right_context: []const u8 = "",
    groups: [9][]const u8 = .{ "", "", "", "", "", "", "", "", "" },
};

/// Tree-walking evaluator. Evaluating a program/block returns the completion
/// value of the last statement, which is what `JSEvaluateScript` hands back.
pub const Interpreter = struct {
    arena: std.mem.Allocator,
    env: *Environment,
    /// The Context-owned microtask queue (Promise reactions). Drained after the
    /// main script in `Context.evaluate` and inline by `await`.
    microtasks: ?*promise.MicrotaskQueue = null,
    /// When non-null (only under `parallel_js`), serializes content mutation of
    /// `microtasks` so a cross-thread enqueue (e.g. an `asyncJoin` settlement on
    /// the finishing thread) can't race the joiner's drain. Points at the
    /// Context's `microtask_lock`; null on the default GIL-serialized path.
    microtask_lock: ?*std.atomic.Mutex = null,
    /// Microtask currently popped from the queue and executing. It is no longer
    /// present in `microtasks`, so GC must trace it separately.
    current_microtask: ?promise.Microtask = null,
    /// The realm's SharedArrayBuffer storage references (Context-owned, like
    /// `microtasks`; agent realms own their own). Every SAB wrapper created in
    /// this realm tracks one reference here so the realm's teardown releases
    /// it — the arena itself runs no per-object destructors. Null only in
    /// hosts that never touch SABs (then wrappers leak their ref, harmlessly).
    sab_retains: ?*shared_buffer.RetainList = null,
    /// Outstanding `Atomics.waitAsync` promises of this realm (Context-owned,
    /// like `microtasks`). The list's address doubles as the realm's owner
    /// token in the waiter table; `settleAsyncWaiters` resolves entries as
    /// their tickets settle.
    async_waiters: ?*std.ArrayListUnmanaged(AsyncWaiterEntry) = null,
    /// Context-owned FinalizationRegistry cleanup job queue. GC marks records
    /// ready and enqueues registries; this interpreter drains callbacks at host
    /// checkpoints, outside collection.
    finalization_cleanup_jobs: ?*std.ArrayListUnmanaged(*value.Object) = null,
    /// Cooperative termination (a worker's `terminate()`): when set and true,
    /// evaluation throws at the next step checkpoint in either engine (the
    /// tree-walker's `eval` and the VM's dispatch loop both poll it every
    /// 1024 steps).
    stop_flag: ?*const std.atomic.Value(bool) = null,
    /// The Context's VM lock when `enable_threads` is on (Phase 6): the step
    /// checkpoints yield it when contended, and blocking operations release
    /// it while parked. Null = no threads, zero cost.
    gil: ?*gil_mod.Gil = null,
    /// Test-only Layer-C bring-up: when false, this interpreter belongs to an
    /// `enable_threads` context but does not hold/yield the context GIL while
    /// running JS bytecode. Blocking APIs acquire the GIL only for their legacy
    /// waiter/result bookkeeping.
    use_thread_gil: bool = true,
    /// Phase 7: the precise-GC heap (type-erased `Context.gc`), or null for the
    /// arena engine. Cell allocation funnels through `gc_mod.allocObject` etc.,
    /// which use this when set. See docs/threads/P7-gc-design.md.
    gc: ?*anyopaque = null,
    /// Backing allocator for GC-owned object side data. Null keeps the legacy
    /// arena ownership path; non-null means ArrayBuffer metadata/bytes must be
    /// released by the GC finalizer.
    gc_backing: ?std.mem.Allocator = null,
    /// Internal byte accounting for GC-owned non-shared ArrayBuffer slabs.
    gc_array_buffer_bytes_live: ?*usize = null,
    /// Internal entry accounting for GC-owned Promise reaction lists.
    gc_promise_reactions_live: ?*usize = null,
    /// Internal byte accounting for GC-owned Environment binding-name strings.
    gc_environment_name_bytes_live: ?*usize = null,
    /// Context-owned pending collection request set by the JS shell `gc()`
    /// helper. M1 collection is precise and quiescent-only, so the request is
    /// serviced by `Context` at the next safe entry point.
    gc_requested: ?*bool = null,
    /// Optional Context callback used by microtask checkpoints to service a
    /// pending shell GC request after a job has unwound but before the next job
    /// runs. The callback owns the full safety policy: no active thread stacks,
    /// no untraced module graph, and no-op when GC is disabled.
    gc_checkpoint_ctx: ?*anyopaque = null,
    gc_checkpoint_fn: ?*const fn (ctx: *anyopaque) void = null,
    /// Optional Context callback invoked at the engine step checkpoints
    /// (`(steps & 1023) == 0`) to run a guarded mid-script collection. Set only
    /// when the GC is on; null = zero cost. The callback owns the safety policy
    /// (no other running JS threads; conservative native-stack scan available).
    /// See `stack_scan.zig` and docs/threads/P7-gc-design.md.
    gc_safepoint_ctx: ?*anyopaque = null,
    gc_safepoint_fn: ?*const fn (ctx: *anyopaque, machine: *anyopaque) void = null,
    /// Root-publication generation this interpreter last published for, under the
    /// parallel mid-script collector (issue #1 M3). Written by this interpreter's
    /// own thread (at a safepoint or when parking), read by the collector to know
    /// every peer has published the current generation. Atomic for the cross-thread
    /// read; `0` until the first publish.
    gc_published_gen: std.atomic.Value(u64) = .init(0),
    /// True while this interpreter's thread is blocked in native park code
    /// (Thread.join, Atomics.wait, contended Lock/Condition) with no GIL — it is
    /// not running JS, so its roots are frozen. The mid-script parallel collector
    /// then traces it *directly* (safe: frozen) instead of waiting for it to
    /// publish at a safepoint it won't reach. Set by the park sites, read by the
    /// collector. Atomic for the cross-thread read.
    gc_parked: std.atomic.Value(bool) = .init(false),
    /// Active VM `Exec` frames on this interpreter, innermost last. The VM
    /// operand stack is arena-backed (not a GC cell), so its live `Value`s are
    /// invisible to both the precise tracer and a conservative native-stack
    /// scan; registering each running `Exec` lets `gc.zig` trace them precisely
    /// during a mid-script collection. Populated only when the GC is on; the
    /// list itself is gpa-backed and freed on interpreter teardown.
    gc_execs: std.ArrayListUnmanaged(*vm.Exec) = .empty,
    /// Tree-walker temporaries that must survive calls/checkpoints while they
    /// live only in Zig locals. VM values are covered by `gc_execs`; this stack
    /// covers interpreter paths such as iterator records/results in `for...of`.
    gc_temp_roots: std.ArrayListUnmanaged(Value) = .empty,
    /// Context-owned serial used to mint per-class private-name storage keys.
    /// Null only in isolated interpreter unit helpers.
    private_name_serial: ?*u64 = null,
    private_name_serial_local: u64 = 0,
    /// Host-defined `[[CanBlock]]` policy for this VM. Spawned `$262.agent`
    /// threads override it through their threadlocal agent record.
    main_can_block: bool = true,
    /// The native-function object currently being invoked (set around each
    /// native call), so a native can reach its own `private_data` — used by
    /// Promise executor resolve/reject closures.
    active_native: ?*value.Object = null,
    /// The non-arrow JS function currently being invoked. `super()` needs this
    /// function object's current [[Prototype]] (GetSuperConstructor), which can
    /// be mutated after class definition.
    active_function: ?*value.Object = null,
    /// Context-owned buffer the global `print` appends to (the async harness's
    /// `$DONE` reports completion through `print`).
    print_buffer: ?*std.ArrayListUnmanaged(u8) = null,
    /// While binding a destructuring declaration, whether it's a `var` (leaves
    /// hoist to the variable scope) vs `let`/`const` (block-scoped).
    binding_hoisted: bool = false,
    /// While binding a declaration, whether it's `const` (so the bound names are
    /// marked immutable and later assignment throws a TypeError).
    binding_const: bool = false,
    /// One-shot flag: tag the next block env created (the function body) as
    /// `fn_body` (consumed by `evalBlockScope`).
    mark_fn_body: bool = false,
    /// Annex B B.3.3: names of block-nested function declarations in the current
    /// variable scope that are eligible for the legacy var-scoped binding. A
    /// block-level function declaration whose name is in this set also creates/
    /// updates a var-scoped binding when its block is evaluated; one absent from
    /// the set stays purely block-scoped (the "skip" cases). Null in strict code.
    annexb_legacy: ?*std.StringHashMapUnmanaged(void) = null,
    /// The specific function-declaration nodes eligible for the legacy copy.
    /// Names are used to pre-create var bindings; nodes decide whether a
    /// particular same-named declaration updates that binding at runtime.
    annexb_legacy_nodes: ?*std.AutoHashMapUnmanaged(*const Node, void) = null,
    /// The formal-parameter names of the current function activation (used by the
    /// Annex B B.3.3 eligibility analysis to exclude parameter-shadowing names).
    cur_params: []const []const u8 = &.{},
    /// Sentinel object for a `let`/`const` binding in its temporal dead zone
    /// (hoisted into scope but not yet initialized). Reading it throws.
    tdz_marker: ?*value.Object = null,
    /// The context's global object — the value of `globalThis` and of top-level
    /// `this`. Global `var`/function bindings also surface as its properties, so
    /// `this.x`, `"x" in globalThis`, and reflection over the global all work.
    global_object: ?*value.Object = null,
    /// The Context's empty root shape — the origin of every object's shape
    /// transition chain (see shape.zig).
    root_shape: *Shape,
    /// Symbol objects indexed by their encoded property key (`sym_key`), so the
    /// original Symbol can be recovered from a stored key — used by
    /// Object.getOwnPropertySymbols and the Proxy traps (which must hand the
    /// Symbol, not its encoded string, to the handler). Populated whenever a
    /// Symbol is used as a property key (see `keyOf`).
    symbols: std.StringHashMapUnmanaged(*value.Object) = .{},
    /// Dynamic-import support (set by the module driver in context.zig). `cur_module`
    /// is the referrer path; `dyn_import`/`dyn_import_ctx` resolve+load+evaluate a
    /// specifier and write the module namespace into `out`, returning true on
    /// success (false leaves the failure in `self.exception`). Null in plain
    /// script evaluation (where `import(...)` rejects).
    cur_module: []const u8 = "",
    dyn_import_ctx: ?*anyopaque = null,
    dyn_import: ?*const fn (ctx: *anyopaque, self: *Interpreter, referrer: []const u8, specifier: []const u8, phase: []const u8, module_type: []const u8, out: *Value) bool = null,
    /// Deferred-evaluation trigger (set by the module driver): evaluates the
    /// `import defer` module identified by `module` (an opaque `*Context.Module`)
    /// the first time a binding of its deferred namespace is accessed. Idempotent
    /// (the module's own `evaluated` flag makes a re-trigger a no-op).
    defer_trigger_ctx: ?*anyopaque = null,
    defer_trigger: ?*const fn (ctx: *anyopaque, self: *Interpreter, module: *anyopaque) EvalError!void = null,
    /// The active module's `import.meta` cell. Functions capture this at creation
    /// so `import.meta` remains lexical when an exported function is called by a
    /// different module.
    import_meta_slot: ?*ImportMetaSlot = null,
    /// Script fallback for `import.meta` storage. Module code uses
    /// `import_meta_slot`; this keeps the existing root for non-module internals.
    import_meta_obj: ?*value.Object = null,
    /// Legacy static RegExp match state (Annex B): updated after a successful
    /// match, read by `RegExp.input`/`$_`/`lastMatch`/`$&`/`lastParen`/`$+`/
    /// `leftContext`/`$\``/`rightContext`/`$'`/`$1`..`$9`.
    re_legacy: RegExpLegacy = .{},
    signal: Signal = .none,
    ret_value: Value = Value.undef(),
    /// The `this` binding for the currently-executing function (undefined at
    /// top level / in plain calls; the receiver in method calls; the new object
    /// in constructor calls).
    this_value: Value = Value.undef(),
    /// Whether the currently-executing code is strict mode (set from the
    /// program's directive prologue and each function's `is_strict`). Gates
    /// strict runtime errors: assignment to an undeclared binding or a
    /// non-writable/​non-extensible property throws instead of silently failing.
    strict: bool = false,
    /// The in-flight thrown value while `error.Throw` propagates. Read by
    /// `catch` and by the Context/C-API boundary.
    exception: Value = Value.undef(),
    /// Target label of a pending labeled `break`/`continue` (null = unlabeled).
    signal_label: ?[]const u8 = null,
    /// Label of the enclosing `labeled_stmt`, handed to the loop it wraps.
    current_label: ?[]const u8 = null,
    /// GetTemplateObject's per-realm cache: a tagged template's frozen strings
    /// object is built once per call site (keyed by the template AST node) and
    /// reused on every later evaluation, so `tag`...`` hands the tag the SAME
    /// object each time. A child realm re-parses its source, producing distinct
    /// nodes, so realms never share an entry.
    template_cache: std.AutoHashMapUnmanaged(*const anyopaque, Value) = .empty,
    /// Set by `lookupIdent` when an identifier resolved through a `with` binding
    /// object; `evalCall` reads it right after evaluating a bare-identifier
    /// callee to bind `this` to that object (WithBaseObject), then it's stale.
    with_this_pending: ?*value.Object = null,
    /// [[HomeObject]] of the executing method (for `super.x`) and the superclass
    /// constructor of the executing derived constructor (for `super(...)`).
    home_object: ?*value.Object = null,
    super_ctor: ?*value.Object = null,
    /// Scoped flag for a running derived class constructor. `super()` flips this
    /// from false to true; completion reads it to implement GetThisBinding.
    this_initialized: bool = true,
    /// The shared `this` cell of the derived constructor activation currently in
    /// scope (set on entry to a derived ctor, and inherited by its lexical arrows
    /// via their captured `Function.this_cell`). Null outside a derived ctor. The
    /// cell is the source of truth for the binding across nested calls: `super()`
    /// writes it, the ctor's completion reads it, and every call's epilogue
    /// re-syncs the ambient this-state from it (so an arrow's `super()` invoked
    /// during an intervening ordinary call still initializes the ctor's `this`).
    this_cell: ?*ThisCell = null,
    /// Whether the most recently completed statement list produced an EMPTY
    /// completion (only declarations / empty statements / empty blocks ran), so
    /// the eval/program completion value carries the last non-empty value forward
    /// (UpdateEmpty).
    completion_empty: bool = true,
    /// `new.target`: the constructor of the in-flight `new` call (undefined in a
    /// plain call). Inherited lexically by arrow functions.
    new_target: Value = Value.undef(),
    /// Set only while invoking a syntactic `eval(...)` call. The eval native
    /// uses this to distinguish direct eval from member/indirect eval.
    direct_eval_call: bool = false,
    /// Whether the current syntactic function body permits a direct eval to
    /// contain `new.target`. Ordinary functions/methods do; arrows, scripts,
    /// modules, class fields, and indirect eval do not introduce that context.
    direct_eval_new_target_allowed: bool = false,
    /// A derived constructor's instance field initializers, awaiting the `super()`
    /// that runs them. Set when entering the constructor; consumed (and cleared)
    /// by the SuperCall once `this` is initialized.
    pending_field_inits: []const *ast.Node = &.{},
    /// A derived constructor's private brand names, awaiting the `super()` that
    /// brands `this` with them.
    pending_brand_names: []const []const u8 = &.{},
    /// True while a class field initializer (or static block) is executing, so a
    /// direct eval inside it inherits the field-initializer early errors:
    /// `super()` and `arguments` are forbidden (`super.prop` stays legal).
    in_field_initializer: bool = false,
    /// True while a non-arrow function's parameter default expressions are being
    /// evaluated (the parameter scope, which has an `arguments` binding). A direct
    /// eval there may not declare `arguments` — an early error.
    in_param_expr: bool = false,
    /// True while *any* function's parameter default Initializer is being
    /// evaluated (including arrows, unlike `in_param_expr`). A function with
    /// parameter expressions keeps its parameters in an environment distinct from
    /// the body's var environment, so a direct eval in a default that declares a
    /// `var` shadowing a parameter name is a SyntaxError. Reset to false when
    /// entering any function body so a nested call's eval doesn't inherit it.
    in_param_default: bool = false,
    /// True while executing the body of a derived class constructor (extends a
    /// value OR `extends null`), where a `super()` call is syntactically valid.
    /// Arrows and direct eval inherit it (a `super()` reachable through them is
    /// still bound to the enclosing derived constructor); a non-arrow function
    /// resets it. Distinguishes the SyntaxError of `super()` in a disallowed
    /// context (global eval, a method, a base constructor) from the runtime
    /// TypeError of `super()` in an `extends null` constructor.
    in_derived_ctor: bool = false,
    in_default_ctor: bool = false, // executing a synthesized default derived constructor
    /// The private-name map of the class whose method/constructor/static element is
    /// currently executing (see Function.private_map). A direct eval uses it to
    /// rewrite the private names in the eval'd code to the right storage keys.
    current_private_map: ?*const std.StringHashMapUnmanaged([]const u8) = null,
    /// True while executing eval'd code: EvalDeclarationInstantiation creates
    /// new global var/function bindings as *deletable* (configurable), unlike a
    /// script's GlobalDeclarationInstantiation (D = false). Saved/restored
    /// around the eval body.
    eval_decl_deletable: bool = false,
    /// Active `with` scope objects (innermost last); bare identifiers consult
    /// these before the lexical environment.
    with_stack: std.ArrayListUnmanaged(*value.Object) = .empty,
    /// Robustness counters: function call depth and total evaluation steps.
    depth: u32 = 0,
    steps: u64 = 0,

    /// Guard a function call against native-stack exhaustion: throw a catchable
    /// `RangeError` when either the logical call-depth limit or the real OS
    /// stack (probed via `stack_scan.nearLimit`) would be exceeded by recursing
    /// one level deeper. The stack probe only runs once a call chain is already
    /// deep (`stack_check_floor`), so the common shallow-call hot path stays a
    /// single compare. The probe matters for large-frame builds (ThreadSanitizer,
    /// deep host callbacks) where the fixed depth limit would otherwise let the
    /// tree-walker's native recursion overflow first — on whichever thread is
    /// recursing, so a deep-recursing peer throws instead of crashing the
    /// process. Each spawned `Thread` registered its stack bounds on entry
    /// (`stack_scan.enter` → `registerThreadBounds`).
    inline fn stackGuard(self: *Interpreter) EvalError!void {
        // Shallow-call hot path: a single compare, identical to the old guard.
        // Only once a chain is already deep do we pay the logical-limit check
        // plus the native stack-pointer probe (the latter matters for
        // large-frame builds — TSan, deep host callbacks — where the native
        // stack can overflow before `max_call_depth`).
        if (self.depth < stack_check_floor) return;
        if (self.depth >= max_call_depth or stack_scan.nearLimit(stack_redzone))
            return self.throwError("RangeError", "Maximum call stack size exceeded");
        // If the native stack-pointer probe can't see this thread's bounds, it
        // can't catch a real overflow — fall back to the conservative depth cap
        // so an unsupported platform can't run off the end of the stack.
        if (!stack_scan.boundsKnown() and self.depth >= conservative_call_depth)
            return self.throwError("RangeError", "Maximum call stack size exceeded");
    }

    // ---- exception helpers ------------------------------------------------

    /// Set a named property on an object via its shape (see `Object.setOwn`).
    pub fn setProp(self: *Interpreter, obj: *value.Object, key: []const u8, v: Value) EvalError!void {
        try obj.setOwn(self.arena, self.root_shape, key, v);
    }

    /// Bind `name` in the current scope; at global scope (no enclosing
    /// function), also surface it as an own property of the global object —
    /// global `var`/function declarations are own properties of `globalThis`
    /// ({ writable, enumerable, !configurable }), so `hasOwnProperty(globalThis,
    /// name)` and reflection see them (the test262 async harness relies on this).
    pub fn globalDefine(self: *Interpreter, name: []const u8, v: Value) EvalError!void {
        const vs = self.env.varScope(); // `var`/function declarations hoist here
        const existed_local = vs.vars.contains(name);
        try vs.put(name, v);
        if (vs.parent == null) {
            if (self.global_object) |g| {
                const existed = g.getOwn(name) != null;
                // CanDeclareGlobalVar: a new global var binding requires the global
                // object to be extensible (an existing property may be reused).
                if (!existed and !g.extensible)
                    return self.throwError("TypeError", "cannot declare global variable (global object is not extensible)");
                try self.setProp(g, name, v);
                // EvalDeclarationInstantiation makes new global bindings deletable
                // (configurable); a script's GlobalDeclarationInstantiation does not.
                if (!existed) try g.setAttr(self.arena, name, .{ .writable = true, .enumerable = true, .configurable = self.eval_decl_deletable });
            }
        } else if (!existed_local and self.eval_decl_deletable) {
            // A sloppy direct eval's top-level var/function in a *function* variable
            // environment is a fresh deletable binding (no global object backs it).
            try vs.markDeletable(name);
        }
    }

    /// Create a `var`-style binding if declaration instantiation needs one,
    /// without reinitializing an existing global object binding. In the spec, a
    /// Global Environment Record's object binding continues to read/write the
    /// property; in this interpreter, leaving `vars` empty for an existing
    /// global property lets identifier resolution fall through to that property.
    fn createVarBinding(self: *Interpreter, name: []const u8) EvalError!void {
        const vs = self.env.varScope();
        if (vs.vars.contains(name)) return; // param / hoisted function / earlier var
        if (vs.parent == null) {
            if (self.global_object) |g| {
                if (objectHasOwn(g, name)) return;
                if (!g.extensible)
                    return self.throwError("TypeError", "cannot declare global variable (global object is not extensible)");
                try vs.put(name, Value.undef());
                try self.setProp(g, name, Value.undef());
                try g.setAttr(self.arena, name, .{ .writable = true, .enumerable = true, .configurable = self.eval_decl_deletable });
                return;
            }
        }
        try vs.put(name, Value.undef());
        if (vs.parent != null and self.eval_decl_deletable)
            try vs.markDeletable(name);
    }

    /// A top-level function declaration (script GlobalDeclarationInstantiation or
    /// eval EvalDeclarationInstantiation). Implements CanDeclareGlobalFunction +
    /// CreateGlobalFunctionBinding: a new/configurable target takes a fresh
    /// `{ writable, enumerable, configurable: D }` descriptor (D = deletable for
    /// eval); a non-configurable existing property must already be a writable,
    /// enumerable data property or the declaration is a TypeError.
    /// CanDeclareGlobalFunction: whether a global function binding `name` may be
    /// (re)declared on the global object `g`.
    fn canDeclareGlobalFunction(g: *value.Object, name: []const u8) bool {
        if (g.getOwn(name) != null or g.getAccessor(name) != null) {
            const a = g.getAttr(name);
            if (a.configurable) return true;
            // A non-configurable existing property is only redefinable as a
            // function if it is a writable, enumerable data property.
            if (g.getAccessor(name) != null or !a.writable or !a.enumerable) return false;
            return true;
        }
        return g.extensible;
    }

    /// EvalDeclarationInstantiation does all the CanDeclareGlobalFunction /
    /// CanDeclareGlobalVar checks *before* declaring anything, so a conflict
    /// throws without leaving earlier declarations behind. Run that pre-check when
    /// a (sloppy) eval's variable environment is the global object.
    fn checkGlobalEvalDeclarable(self: *Interpreter, stmts: []const *Node) EvalError!void {
        if (self.env.varScope().parent != null) return; // not declaring to global
        const g = self.global_object orelse return;
        for (stmts) |s| if (s.* == .func_decl) {
            const nm = s.func_decl.name;
            if (nm.len != 0 and !canDeclareGlobalFunction(g, nm))
                return self.throwError("TypeError", "cannot declare global function (existing property is not configurable)");
        };
        if (!g.extensible) {
            var vars: std.ArrayListUnmanaged([]const u8) = .empty;
            try self.collectEvalVarNames(stmts, &vars);
            for (vars.items) |nm| {
                if (g.getOwn(nm) == null and self.env.varScope().vars.get(nm) == null)
                    return self.throwError("TypeError", "cannot declare global variable (global object is not extensible)");
            }
        }
    }

    /// EvalDeclarationInstantiation lexical-conflict early error (19.2.1.3 step 5,
    /// sloppy direct eval). Walk the lexical environments from the eval's scope up
    /// to — but not including — the variable environment; a `var` the eval would
    /// introduce that collides with an intervening lexical binding (`let`/`const`/
    /// `class`, a block-scoped function) is a SyntaxError: `let x; eval('var x')`.
    ///
    /// In our model var/function declarations hoist past block and function-body
    /// environments to the nearest `fn_scope`, so those intervening environments
    /// hold only lexical bindings — any name match there is a genuine conflict.
    /// `with` (object) environments use Annex B alternate semantics (var hoists
    /// over them) and are skipped. At the global variable environment, a global
    /// lexical (in the root bindings but not an own global property) still conflicts.
    fn checkEvalLexicalConflicts(self: *Interpreter, stmts: []*Node) EvalError!void {
        var vars: std.ArrayListUnmanaged([]const u8) = .empty;
        try self.collectEvalVarNames(stmts, &vars);
        if (vars.items.len == 0) return;
        const var_env = self.env.varScope();
        // A direct eval inside a parameter default: the parameter environment is
        // distinct from the body's variable environment, so a `var` shadowing a
        // parameter name is a SyntaxError. The parameters live in `var_env` (the
        // parameter scope); `arguments` has its own separate restriction.
        if (self.in_param_default) {
            for (vars.items) |n|
                if (!eq(n, "arguments") and var_env.vars.contains(n))
                    return self.throwError("SyntaxError", "eval cannot var-declare a parameter name in a parameter default");
        }
        var env: *Environment = self.env;
        while (env != var_env) {
            // A simple catch parameter is exempt (Annex B.3.5: a direct eval's
            // `var` may match it); other declarative records are checked.
            if (env.with_object == null and !env.is_catch_param) {
                for (vars.items) |n|
                    if (env.vars.contains(n))
                        return self.throwError("SyntaxError", "var declaration in eval conflicts with a lexical binding");
            }
            env = env.parent orelse break;
        }
        if (var_env.parent == null) {
            // Global variable environment: a global lexical lives in the root
            // bindings without a matching own property on the global object.
            const g = self.global_object orelse return;
            for (vars.items) |n|
                if (var_env.vars.contains(n) and !objectHasOwn(g, n))
                    return self.throwError("SyntaxError", "var declaration in eval conflicts with a global lexical binding");
        }
    }

    /// GlobalDeclarationInstantiation early errors (16.1.7 steps 3–12). Run at the
    /// top of a Script's GlobalDeclarationInstantiation, *before* any binding is
    /// created, so a conflict throws SyntaxError without leaving partial state.
    ///
    /// In our model a global `var`/function binding lives in BOTH the root
    /// environment's `vars` and as an own property of the global object, while a
    /// global lexical (`let`/`const`/`class`) lives ONLY in the root `vars`. That
    /// lets us reconstruct the global environment record's predicates:
    ///   HasLexicalDeclaration(n) := root.vars has n AND global has no own n
    ///   HasVarDeclaration(n)     := root.vars has n AND global has own n
    ///   HasRestrictedGlobalProperty(n) := global has own non-configurable n
    fn checkGlobalDeclConflicts(self: *Interpreter, stmts: []*Node) EvalError!void {
        if (self.env.parent != null) return; // only a Script's global scope
        const g = self.global_object orelse return;
        const root = self.env;

        // lexNames: the script's top-level LexicallyDeclaredNames (let/const/class).
        // Each must not collide with an existing var or lexical binding, nor name a
        // restricted (non-configurable) global property.
        var lex_names: std.ArrayListUnmanaged([]const u8) = .empty;
        try self.collectTopLexNames(stmts, &lex_names);
        for (lex_names.items) |n| {
            // HasLexicalDeclaration(n): in root `vars` but not an own global
            // property (a global `var`/function lives in both).
            if (root.vars.contains(n) and !objectHasOwn(g, n))
                return self.throwError("SyntaxError", "redeclaration of global lexical binding");
            // HasRestrictedGlobalProperty(n): an own non-configurable property.
            // (A `var` introduced by non-strict direct eval is configurable, so it
            // is NOT restricted — a later `let` may legally shadow it.)
            if (objectHasOwn(g, n) and !g.getAttr(n).configurable)
                return self.throwError("SyntaxError", "cannot declare restricted global property");
        }

        // declaredVarNames: the script's VarDeclaredNames (nested `var` + top-level
        // function declarations). None may collide with an existing lexical binding.
        var vars: std.ArrayListUnmanaged([]const u8) = .empty;
        try self.collectEvalVarNames(stmts, &vars);
        for (stmts) |s| if (s.* == .func_decl and s.func_decl.name.len > 0)
            try vars.append(self.arena, s.func_decl.name);
        for (vars.items) |n| {
            // HasLexicalDeclaration(n): in root `vars` but not an own global property.
            if (root.vars.contains(n) and !objectHasOwn(g, n))
                return self.throwError("SyntaxError", "var declaration conflicts with global lexical binding");
        }
    }

    /// The top-level (statement-list-level) lexical names of a program: `let`/
    /// `const`/`class` declarations, including those wrapped in a `decl_group` or
    /// `export`. Block-nested lexicals are not part of LexicallyDeclaredNames.
    fn collectTopLexNames(self: *Interpreter, stmts: []const *Node, out: *std.ArrayListUnmanaged([]const u8)) EvalError!void {
        for (stmts) |s| try self.collectTopLexNamesNode(s, out);
    }

    fn collectTopLexNamesNode(self: *Interpreter, node: *Node, out: *std.ArrayListUnmanaged([]const u8)) EvalError!void {
        switch (node.*) {
            .var_decl => |d| if (d.kind != .@"var" and d.name.len > 0) try out.append(self.arena, d.name),
            .destructure_decl => |d| if (d.kind != .@"var") try self.evalPatternVarNames(d.pattern, out),
            .class_expr => |c| if (c.name.len > 0) try out.append(self.arena, c.name),
            .decl_group => |g| for (g) |d2| try self.collectTopLexNamesNode(d2, out),
            .export_decl => |e| if (e.declaration) |d| try self.collectTopLexNamesNode(d, out),
            else => {},
        }
    }

    /// Collect top-level + block-nested `var` names of an eval program (does not
    /// cross function boundaries).
    fn collectEvalVarNames(self: *Interpreter, stmts: []const *Node, out: *std.ArrayListUnmanaged([]const u8)) EvalError!void {
        for (stmts) |s| try self.collectEvalVarNamesNode(s, out);
    }

    fn collectEvalVarNamesNode(self: *Interpreter, node: *Node, out: *std.ArrayListUnmanaged([]const u8)) EvalError!void {
        switch (node.*) {
            .var_decl => |d| if (d.kind == .@"var" and d.name.len > 0) try out.append(self.arena, d.name),
            .destructure_decl => |d| if (d.kind == .@"var") try self.evalPatternVarNames(d.pattern, out),
            .decl_group => |g| for (g) |d2| try self.collectEvalVarNamesNode(d2, out),
            .block => |b| for (b) |s| try self.collectEvalVarNamesNode(s, out),
            .if_stmt => |i| {
                try self.collectEvalVarNamesNode(i.consequent, out);
                if (i.alternate) |a| try self.collectEvalVarNamesNode(a, out);
            },
            .while_stmt => |w| try self.collectEvalVarNamesNode(w.body, out),
            .do_while_stmt => |w| try self.collectEvalVarNamesNode(w.body, out),
            .for_stmt => |f| {
                if (f.init) |ini| try self.collectEvalVarNamesNode(ini, out);
                try self.collectEvalVarNamesNode(f.body, out);
            },
            .for_in => |f| {
                if (f.decl_kind) |k| if (k == .@"var") try self.evalPatternVarNames(f.target, out);
                try self.collectEvalVarNamesNode(f.body, out);
            },
            .labeled_stmt => |l| try self.collectEvalVarNamesNode(l.body, out),
            .try_stmt => |t| {
                try self.collectEvalVarNamesNode(t.block, out);
                if (t.catch_block) |c| try self.collectEvalVarNamesNode(c, out);
                if (t.finally_block) |fb| try self.collectEvalVarNamesNode(fb, out);
            },
            .switch_stmt => |sw| for (sw.cases) |cs| for (cs.body) |s| try self.collectEvalVarNamesNode(s, out),
            else => {},
        }
    }

    fn evalPatternVarNames(self: *Interpreter, node: *Node, out: *std.ArrayListUnmanaged([]const u8)) EvalError!void {
        switch (node.*) {
            .identifier => |n| try out.append(self.arena, n),
            .obj_pattern => |p| {
                for (p.props) |prop| try self.evalPatternVarNames(prop.target, out);
                if (p.rest) |r| if (r.* == .identifier) try out.append(self.arena, r.identifier);
            },
            .arr_pattern => |p| {
                for (p.elems) |elem| if (elem.target) |t| try self.evalPatternVarNames(t, out);
                if (p.rest) |r| try self.evalPatternVarNames(r, out);
            },
            else => {},
        }
    }

    pub fn globalDefineFunc(self: *Interpreter, name: []const u8, v: Value) EvalError!void {
        const vs = self.env.varScope();
        if (vs.parent != null or self.global_object == null) {
            const existed = vs.vars.contains(name);
            try vs.put(name, v);
            // A sloppy direct eval's top-level function declaration in a function
            // variable env is a deletable binding, like its `var` siblings.
            if (!existed and vs.parent != null and self.eval_decl_deletable) try vs.markDeletable(name);
            return;
        }
        const g = self.global_object.?;
        if (g.getOwn(name) != null or g.getAccessor(name) != null) {
            const a = g.getAttr(name);
            if (!a.configurable) {
                // CanDeclareGlobalFunction: a non-configurable property is only
                // redefinable if it is a writable, enumerable *data* property.
                if (g.getAccessor(name) != null or !a.writable or !a.enumerable)
                    return self.throwError("TypeError", "cannot declare global function (existing property is not configurable)");
                try vs.put(name, v);
                try self.setProp(g, name, v); // keep the existing attributes
                return;
            }
        } else if (!g.extensible) {
            return self.throwError("TypeError", "cannot declare global function (global object is not extensible)");
        }
        try vs.put(name, v);
        try self.setProp(g, name, v);
        try g.setAttr(self.arena, name, .{ .writable = true, .enumerable = true, .configurable = self.eval_decl_deletable });
    }

    /// Create the global var binding for an Annex B B.3.3 legacy block-level
    /// function. Per CreateGlobalVarBinding(F, D), the new property's
    /// deletability D follows the surrounding instantiation: a Script's
    /// GlobalDeclarationInstantiation uses D = false (non-configurable, like an
    /// ordinary global `var`), whereas a direct eval's EvalDeclarationInstantiation
    /// uses D = true. An already-existing property keeps its attributes.
    fn globalDefineDeletable(self: *Interpreter, name: []const u8, v: Value) EvalError!void {
        const vs = self.env.varScope();
        try vs.put(name, v);
        if (vs.parent == null) {
            if (self.global_object) |g| {
                const existed = g.getOwn(name) != null;
                try self.setProp(g, name, v);
                if (!existed) try g.setAttr(self.arena, name, .{ .writable = true, .enumerable = true, .configurable = self.eval_decl_deletable });
            }
        }
    }

    /// The TDZ sentinel as a Value.
    fn tdzVal(self: *Interpreter) Value {
        return Value.obj(self.tdz_marker.?);
    }

    /// Whether `v` is the TDZ sentinel (an uninitialized let/const binding).
    fn isTdz(self: *Interpreter, v: Value) bool {
        return v.isObject() and self.tdz_marker != null and v.asObj() == self.tdz_marker.?;
    }

    /// PrivateFieldAdd / PrivateMethodOrAccessorAdd: branding an object that
    /// already carries the private name `name` is a TypeError — reachable when the
    /// same object undergoes instance-element initialization twice (a base that
    /// `return`s an already-constructed instance, so a later `new` re-installs the
    /// derived class's private members on it).
    fn addPrivateBrandChecked(self: *Interpreter, o: *value.Object, name: []const u8) EvalError!void {
        // PrivateFieldAdd / PrivateMethodOrAccessorAdd step 1: a private member
        // cannot be added to a non-extensible object.
        if (!o.extensible)
            return self.throwError("TypeError", "Cannot add a private member to a non-extensible object");
        if (o.hasPrivateBrand(name))
            return self.throwError("TypeError", "Cannot initialize a private member twice on the same object");
        try o.addPrivateBrand(self.arena, name);
    }

    fn addPrivateMethodOrAccessorChecked(self: *Interpreter, o: *value.Object, home: ?*value.Object, name: []const u8) EvalError!void {
        try self.addPrivateBrandChecked(o, name);
        const h = home orelse return;
        if (h.getAccessor(name)) |acc| {
            try o.setAccessor(self.arena, name, acc.get, acc.set);
            try o.setAttr(self.arena, name, .{ .enumerable = false, .configurable = false });
        } else if (h.getOwn(name)) |v| {
            try o.setOwn(self.arena, self.root_shape, name, v);
            try o.setAttr(self.arena, name, .{ .writable = false, .enumerable = false, .configurable = false });
        }
    }

    /// Pre-bind every identifier in a destructuring pattern to the TDZ sentinel.
    fn tdzBindPattern(self: *Interpreter, target: *Node, tdz: Value) void {
        switch (target.*) {
            .identifier => |name| self.env.put(name, tdz) catch {},
            .obj_pattern => |p| {
                for (p.props) |pr| self.tdzBindPattern(pr.target, tdz);
                if (p.rest) |r| if (r.* == .identifier) self.env.put(r.identifier, tdz) catch {}; // a binding object rest is a name
            },
            .arr_pattern => |p| {
                for (p.elems) |e| if (e.target) |t| self.tdzBindPattern(t, tdz);
                if (p.rest) |r| self.tdzBindPattern(r, tdz);
            },
            else => {},
        }
    }

    fn checkRestrictedGlobalLexical(self: *Interpreter, name: []const u8) EvalError!void {
        if (self.env.parent != null) return;
        if (!eq(name, "undefined") and !eq(name, "NaN") and !eq(name, "Infinity")) return;
        const g = self.global_object orelse return;
        if (objectHasOwn(g, name) and !g.getAttr(name).configurable)
            return self.throwError("SyntaxError", "Cannot declare restricted global property");
    }

    fn checkRestrictedGlobalLexicalPattern(self: *Interpreter, target: *Node) EvalError!void {
        switch (target.*) {
            .identifier => |name| try self.checkRestrictedGlobalLexical(name),
            .obj_pattern => |p| {
                for (p.props) |pr| try self.checkRestrictedGlobalLexicalPattern(pr.target);
                if (p.rest) |r| if (r.* == .identifier) try self.checkRestrictedGlobalLexical(r.identifier);
            },
            .arr_pattern => |p| {
                for (p.elems) |e| if (e.target) |t| try self.checkRestrictedGlobalLexicalPattern(t);
                if (p.rest) |r| try self.checkRestrictedGlobalLexicalPattern(r);
            },
            else => {},
        }
    }

    /// An own data property of the global object, used as the fallback for a
    /// bare global reference (`this.x = 1` at top level → bare `x`).
    fn currentGlobalObject(self: *Interpreter) ?*value.Object {
        var env: ?*Environment = self.env;
        while (env) |e| {
            if (e.get("globalThis")) |gt| {
                if (gt.isObject()) return gt.asObj();
            }
            if (e.parent == null) break;
            env = e.parent;
        }
        return self.global_object;
    }

    /// A bare global reference's value: a proper [[Get]] on the global object —
    /// invoking an accessor's getter — when `name` is an own property (data or
    /// accessor), else null (the name is unresolved). Mirrors the tree-walker's
    /// identifier global fallback so the VM's `load_var` resolves global
    /// accessor properties, not just data ones.
    pub fn globalProp(self: *Interpreter, name: []const u8) EvalError!?Value {
        const g = self.currentGlobalObject() orelse return null;
        if (objectHasOwn(g, name)) return try self.getProperty(Value.obj(g), name);
        return null;
    }

    /// Whether the global object has an own binding `name` (data OR accessor),
    /// without invoking a getter — the existence test behind strict
    /// "assignment to an undeclared global" and `typeof <unresolved>`.
    pub fn globalHasOwn(self: *Interpreter, name: []const u8) bool {
        const g = self.currentGlobalObject() orelse return false;
        return objectHasOwn(g, name);
    }

    fn globalBindingObject(self: *Interpreter, name: []const u8) ?*value.Object {
        const g = self.currentGlobalObject() orelse return null;
        var env: ?*Environment = self.env;
        while (env) |e| {
            if (e.vars.contains(name))
                return if (e.parent == null and objectHasOwn(g, name)) g else null;
            env = e.parent;
        }
        return null;
    }

    /// ToObject(v): an ordinary object is returned as-is, a primitive is boxed
    /// into the matching wrapper (whose prototype is that constructor's
    /// `.prototype`), and null/undefined throw a TypeError. BigInt/Symbol are
    /// represented as object-tagged primitives internally, so they still need
    /// fresh wrappers here.
    pub fn toObject(self: *Interpreter, v: Value) EvalError!*value.Object {
        if (v.isObject() and !v.asObj().is_symbol and !v.asObj().is_bigint) return v.asObj();
        if (v.isNull() or v.isUndefined())
            return self.throwError("TypeError", "Cannot convert undefined or null to object");
        const ctor_name: []const u8 = switch (v.kind()) {
            .string => "String",
            .number => "Number",
            .boolean => "Boolean",
            .object => if (v.asObj().is_symbol) "Symbol" else if (v.asObj().is_bigint) "BigInt" else unreachable,
            else => unreachable,
        };
        const o = try gc_mod.allocObj(self.arena);
        o.* = .{ .prim = v };
        if (self.env.get(ctor_name)) |ctor| {
            if (ctor.isObject()) o.setProtoAtomic(try self.protoObject(ctor.asObj()));
        }
        return o;
    }

    /// ToObject for property references whose base is a primitive.
    fn boxPrimitiveBase(self: *Interpreter, v: Value) EvalError!*value.Object {
        return self.toObject(v);
    }

    /// Resolve an identifier through the lexical environment chain, consulting
    /// each scope's bindings (live `import` aliases, then `var`/`let`/`const`),
    /// and — at a `with` object Environment Record — that object's properties, in
    /// chain order. Returns the value, or null when unresolved (the caller then
    /// tries the global object and finally throws a ReferenceError).
    pub fn lookupIdent(self: *Interpreter, name: []const u8) EvalError!?Value {
        // Read each scope's binding tables under its `binding_lock` (via the
        // flag-gated `lockBindings`, like `Environment.get`): a peer thread may
        // be mutating `vars`/`aliases` through `Environment.put` (which locks),
        // so an unlocked `.get` here races the grow — the systemic no-GIL
        // Environment race the Linux-TSan corpus gate surfaced (it hit even
        // smoke.js: main defines a global while a worker resolves one). In the
        // default engine `binding_locks_enabled` is false, so `lockBindings` is a
        // single relaxed-ish load that returns immediately — the walk stays
        // lock-free and full-speed.
        var env: ?*Environment = self.env;
        while (env) |e| {
            e.lockBindings();
            const alias = e.aliases.get(name);
            const found_var: ?Value = if (alias == null) e.vars.get(name) else null;
            e.unlockBindings();
            if (alias) |a| return a.env.get(a.name);
            if (found_var) |v| {
                if (e.parent == null and !e.consts.contains(name)) {
                    const g = self.currentGlobalObject() orelse return v;
                    if (objectHasOwn(g, name)) return try self.getProperty(Value.obj(g), name);
                }
                return v;
            }
            if (e.with_object) |wo| {
                if (try self.withHasBinding(wo, name)) {
                    // Record the WithBaseObject so a call with this identifier as
                    // callee binds `this` to it (consumed by evalCall).
                    self.with_this_pending = wo;
                    // Object Environment Record GetBindingValue does its OWN
                    // HasProperty(N) before Get(N) — distinct from the HasBinding
                    // check above — so a proxy env observes a second `has`. If the
                    // binding vanished in between (e.g. a `@@unscopables` getter
                    // deleted it), GetBindingValue with S=true throws a
                    // ReferenceError; a sloppy reference reads undefined.
                    if (!try self.hasPropertyResult(wo, name)) {
                        if (self.strict) return self.throwError("ReferenceError", name);
                        return Value.undef();
                    }
                    return try self.getProperty(Value.obj(wo), name);
                }
            }
            env = e.parent;
        }
        return null;
    }

    /// Resolve an identifier *for assignment*: a `with` object that provides the
    /// binding takes the write (returns true); otherwise the caller assigns to
    /// the lexical/global binding. Stops at the first scope (binding or `with`)
    /// that owns `name`.
    /// The declarative environment that currently holds `name` (a `var`/`let`/
    /// `const` binding), searching outward from `start`. Used to capture an
    /// assignment's target binding BEFORE its right-hand side runs, so a direct
    /// eval in the RHS that introduces a closer binding can't retarget the write
    /// (PutValue uses the initially-created Reference). Returns null when no
    /// declarative binding exists (the target is a `with`/global/new binding).
    fn bindingEnvOf(start: *Environment, name: []const u8) ?*Environment {
        var env: ?*Environment = start;
        while (env) |e| {
            // Existence check under the binding lock (same no-GIL race class as
            // lookupIdent); the `getPtr` result is not escaped, only its
            // presence, so nothing dangles after unlock.
            e.lockBindings();
            const owns = e.vars.getPtr(name) != null or e.aliases.get(name) != null;
            e.unlockBindings();
            if (owns) return e;
            env = e.parent;
        }
        return null;
    }

    fn catchParamBindingEnvOf(start: *Environment, name: []const u8) ?*Environment {
        var env: ?*Environment = start;
        while (env) |e| {
            e.lockBindings();
            const owns = e.vars.contains(name) or e.aliases.get(name) != null;
            e.unlockBindings();
            if (owns) return if (e.is_catch_param) e else null;
            env = e.parent;
        }
        return null;
    }

    pub fn assignWithObject(self: *Interpreter, name: []const u8) EvalError!?*value.Object {
        var env: ?*Environment = self.env;
        while (env) |e| {
            e.lockBindings();
            const owned = e.aliases.get(name) != null or e.vars.get(name) != null;
            e.unlockBindings();
            if (owned) return null; // a real binding owns it
            if (e.with_object) |wo| {
                if (try self.withHasBinding(wo, name)) return wo;
            }
            env = e.parent;
        }
        return null;
    }

    /// Whether a `with` binding object provides a binding for `name`: it has the
    /// property AND `name` is not listed truthy in the object's
    /// `[Symbol.unscopables]` (which hides selected names from `with` scope).
    pub fn withHasBinding(self: *Interpreter, o: *value.Object, name: []const u8) EvalError!bool {
        if (!try self.hasPropertyResult(o, name)) return false;
        const unsc_key = self.wellKnownSymbolKey("unscopables") orelse return true;
        const unsc = try self.getProperty(Value.obj(o), unsc_key);
        if (unsc.isObject()) {
            if ((try self.getProperty(unsc, name)).toBoolean()) return false;
        }
        return true;
    }

    /// Build an `Error`-family instance with `name`/`message` properties.
    /// Register a `using`/`await using` resource on the current scope. Validates
    /// it has a [Symbol.dispose] / [Symbol.asyncDispose] method (null/undefined is
    /// a permitted no-op resource).
    pub fn addDisposable(self: *Interpreter, val: Value, is_async: bool) EvalError!void {
        if (val.isNull() or val.isUndefined()) {
            if (!is_async) return;
            self.env.lockBindings(); // traceEnv reads disposables; serialize the append
            defer self.env.unlockBindings();
            try self.env.disposables.append(self.env.bindingAllocator(), .{ .value = Value.undef(), .method = Value.undef(), .is_async = true, .await_result = true });
            return;
        }
        if (!val.isObject()) return self.throwError("TypeError", "a 'using' declaration value must be an object or null/undefined");
        var method: Value = Value.undef();
        var await_result = false;
        if (is_async) {
            if (self.wellKnownSymbolKey("asyncDispose")) |k| method = try self.getProperty(val, k);
            await_result = !(method.isUndefined() or method.isNull());
            if (method.isUndefined() or method.isNull()) {
                if (self.wellKnownSymbolKey("dispose")) |k| method = try self.getProperty(val, k);
            }
        } else if (self.wellKnownSymbolKey("dispose")) |k| {
            method = try self.getProperty(val, k);
        }
        if (!method.isCallable()) return self.throwError("TypeError", "a 'using' declaration value must have a [Symbol.dispose] method");
        gc_mod.barrierValue(val);
        gc_mod.barrierValue(method);
        self.env.lockBindings(); // traceEnv reads disposables; serialize the append
        defer self.env.unlockBindings();
        try self.env.disposables.append(self.env.bindingAllocator(), .{ .value = val, .method = method, .is_async = is_async, .await_result = await_result });
    }

    /// Dispose a scope's `using` resources in reverse declaration order, threading
    /// `body_err` (the scope body's thrown value, if any). A disposal error
    /// becomes the pending completion, wrapping any earlier one in a
    /// SuppressedError. Returns the value to re-throw, or null on clean exit.
    pub fn disposeScope(self: *Interpreter, env: *Environment, body_err: ?Value) EvalError!?Value {
        var pending = body_err orelse env.dispose_pending;
        env.dispose_pending = null;
        var i = env.disposables.items.len;
        while (i > 0) {
            i -= 1;
            const d = env.disposables.items[i];
            var dispose_err: ?Value = null;
            if (d.method.isUndefined()) {
                if (d.is_async) {
                    const tick = try promiseResolveAfterTick(self, Value.undef());
                    _ = self.awaitValue(tick) catch |e| {
                        if (e != error.Throw) return e;
                        dispose_err = self.exception;
                        self.exception = Value.undef();
                    };
                }
            } else if (self.callValueWithThis(d.method, &.{}, d.value)) |rv| {
                if (d.is_async) {
                    _ = self.awaitValue(rv) catch |e| {
                        if (e != error.Throw) return e;
                        dispose_err = self.exception;
                        self.exception = Value.undef();
                    };
                }
            } else |e| {
                if (e != error.Throw) return e;
                dispose_err = self.exception;
                self.exception = Value.undef();
            }
            if (dispose_err) |this_err| {
                pending = if (pending) |prev|
                    (self.makeErrorWithArgs("SuppressedError", &.{ this_err, prev }) catch this_err)
                else
                    this_err;
            }
        }
        if (env.bindings_allocator != null) {
            env.disposables.deinit(env.bindingAllocator());
            env.disposables = .empty;
        } else {
            env.disposables.clearRetainingCapacity();
        }
        return pending;
    }

    pub fn disposeScopeAsyncStep(self: *Interpreter, env: *Environment) EvalError!?Value {
        var pending: ?Value = env.dispose_pending;
        env.dispose_pending = null;
        while (env.disposables.items.len > 0) {
            const idx = env.disposables.items.len - 1;
            const d = env.disposables.items[idx];
            env.disposables.shrinkRetainingCapacity(idx);
            var dispose_err: ?Value = null;
            if (d.method.isUndefined()) {
                if (d.is_async and d.await_result) return Value.undef();
            } else if (self.callValueWithThis(d.method, &.{}, d.value)) |rv| {
                if (d.is_async and d.await_result) return rv;
            } else |e| {
                if (e != error.Throw) return e;
                dispose_err = self.exception;
                self.exception = Value.undef();
            }
            if (dispose_err) |this_err| {
                pending = if (pending) |prev|
                    (self.makeErrorWithArgs("SuppressedError", &.{ this_err, prev }) catch this_err)
                else
                    this_err;
            }
            env.dispose_pending = pending;
        }
        clear: {
            if (env.bindings_allocator != null) {
                env.disposables.deinit(env.bindingAllocator());
                env.disposables = .empty;
                break :clear;
            }
            env.disposables.clearRetainingCapacity();
        }
        if (pending) |err| {
            env.dispose_pending = null;
            self.exception = err;
            return error.Throw;
        }
        return null;
    }

    pub fn initEnvironment(self: *Interpreter, env: *Environment, parent: ?*Environment, fn_scope: bool) void {
        env.* = .{
            .arena = self.arena,
            .bindings_allocator = self.gc_backing,
            .gc_name_bytes_live = self.gc_environment_name_bytes_live,
            .parent = parent,
            .fn_scope = fn_scope,
        };
    }

    /// Evaluate a `{…}` block in its own lexical scope, disposing any `using`
    /// resources declared in it when it exits (normally or abruptly).
    fn evalBlockScope(self: *Interpreter, stmts: []*Node) EvalError!Value {
        // A label on a block (`L: { … }`) labels the BLOCK, not a loop nested inside
        // it — so consume the pending label here, keeping it from being adopted by an
        // inner loop (`L: { do { break L; } while (true); … }` must break the block).
        // The matching break is consumed at the `.labeled_stmt` level.
        _ = self.takeLabel();
        const block_env = try gc_mod.allocEnv(self.arena);
        self.initEnvironment(block_env, self.env, false);
        if (self.mark_fn_body) {
            block_env.fn_body = true;
            self.mark_fn_body = false;
        }
        const saved_env = self.env;
        self.env = block_env;
        defer self.env = saved_env;
        const result = self.evalStatements(stmts);
        if (block_env.disposables.items.len == 0) return result;
        var body_err: ?Value = null;
        const val: Value = result catch |e| blk: {
            if (e != error.Throw) return e;
            body_err = self.exception;
            break :blk Value.undef();
        };
        if (try self.disposeScope(block_env, body_err)) |err| {
            self.exception = err;
            return error.Throw;
        }
        return val;
    }

    fn makeErrorWithProto(self: *Interpreter, name: []const u8, message: []const u8, proto: ?*value.Object) EvalError!Value {
        const obj = try gc_mod.allocObj(self.arena);
        obj.* = .{ .is_error = true, .error_name = name };
        // Link to `<name>.prototype` so `name` (and `toString`) are inherited and
        // `instanceof` / `Object.getPrototypeOf` see a real chain.
        if (proto) |p| {
            obj.setProtoAtomic(p);
        } else if (self.env.get(name)) |ctor_v| {
            if (ctor_v.isObject()) {
                if (ctor_v.asObj().getOwn("prototype")) |proto_v| {
                    if (proto_v.isObject()) obj.setProtoAtomic(proto_v.asObj());
                }
            }
        }
        // `message` is an own property only when one was supplied (else inherited,
        // = "" from the prototype); `name` is always inherited from the prototype.
        if (message.len > 0) {
            try self.setProp(obj, "message", Value.str(message));
            try obj.setAttr(self.arena, "message", .{ .enumerable = false, .configurable = true, .writable = true });
        }
        return Value.obj(obj);
    }

    pub fn makeError(self: *Interpreter, name: []const u8, message: []const u8) EvalError!Value {
        return self.makeErrorWithProto(name, message, null);
    }

    /// Raise a JS exception of the given error class. Always returns
    /// `error.Throw` (or `error.OutOfMemory` if the error object can't be built).
    pub fn throwError(self: *Interpreter, name: []const u8, message: []const u8) EvalError {
        self.exception = try self.makeError(name, message);
        return error.Throw;
    }

    pub fn eval(self: *Interpreter, node: *const Node) EvalError!Value {
        self.steps += 1;
        if (self.steps > max_steps) return self.throwError("RangeError", "evaluation step budget exceeded");
        if ((self.steps & 1023) == 0) {
            if (self.stop_flag) |sf| if (sf.load(.monotonic))
                return self.throwError("Error", "worker terminated");
            if (self.use_thread_gil) if (self.gil) |g| g.yieldIfContended();
            // Mid-script GC: the tree-walker holds live `Value`s only as native
            // Zig locals/registers, which the conservative native-stack scan
            // covers; run a guarded collection. No-op when the GC is off.
            if (self.gc_safepoint_fn != null) self.serviceGcSafepoint();
        }
        return switch (node.*) {
            .number => |n| Value.num(n),
            .bigint_lit => |b| if (b.text) |s| try self.makeBigIntText(s) else try self.makeBigInt(b.value),
            .string => |s| Value.str(s),
            .boolean => |b| Value.boolVal(b),
            .null_lit => Value.nul(),
            .undefined_lit => Value.undef(),
            .elision => Value.undef(), // only meaningful inside an array literal
            // GetThisBinding: in a derived constructor, `this` is in its TDZ until
            // `super()` initializes it — reading it (e.g. `super(this.x)`) is a
            // ReferenceError. `this_initialized` is true everywhere else (base
            // ctors, methods, ordinary functions), so this only fires before super().
            .this_expr => if (self.this_initialized) self.this_value else return self.throwError("ReferenceError", "Must call super constructor before using 'this'"),
            // A class field initializer / static block is run as a method-like
            // function (it is [[Call]]ed, never [[Construct]]ed), so `new.target`
            // inside it — including inside a direct `eval` in it — is undefined.
            // `callPlain` clears `in_field_initializer` for any non-arrow call, so a
            // `new X()` made from a field initializer still sees its own new.target.
            .new_target_expr => if (self.in_field_initializer) Value.undef() else self.new_target,
            .identifier => |name| blk: {
                // Walk the lexical chain (bindings and `with` objects in chain
                // order), so a `with` object shadows outer scopes but is itself
                // shadowed by any binding more local than it.
                if (try self.lookupIdent(name)) |v| {
                    if (self.isTdz(v)) return self.throwError("ReferenceError", name); // accessed in its TDZ
                    break :blk v;
                }
                // A property added to the global object (e.g. `this.x = 1` at top
                // level) is reachable as a bare global reference.
                if (self.global_object) |g| {
                    if (objectHasOwn(g, name)) break :blk try self.getProperty(Value.obj(g), name);
                }
                return self.throwError("ReferenceError", name);
            },

            .unary => |u| try self.evalUnary(u.op, u.operand),
            .delete_expr => |target| blk: {
                // `delete super.x` / `delete super[expr]` is always a ReferenceError
                // (the reference is a SuperReference). SuperProperty creation does
                // GetThisBinding first — a derived constructor before `super()` has
                // uninitialized `this`, a ReferenceError thrown BEFORE the key is
                // evaluated — then evaluates the computed key (for its side effects,
                // but without ToPropertyKey), and finally delete rejects the
                // SuperReference. So `delete super[{toString(){throw}}]` yields the
                // ReferenceError, not the toString error.
                if (target.* == .super_member) {
                    if (!self.this_initialized) return self.throwError("ReferenceError", "Must call super constructor before using 'this'");
                    if (target.super_member.computed) |c| _ = try self.eval(c);
                    return self.throwError("ReferenceError", "Cannot delete a super property");
                }
                // `delete obj.prop` / `delete obj[expr]`: remove an own property
                // (honoring [[Configurable]]). `delete <non-reference>` is true.
                if (target.* == .member) {
                    const m = target.member;
                    const obj = try self.eval(m.object);
                    if (obj.isNull() or obj.isUndefined()) {
                        // `delete a?.b` with a nullish base short-circuits to true;
                        // otherwise `delete null.x` / `delete undefined[e]` performs
                        // ToObject on the base, which throws a TypeError (the key
                        // expression is still evaluated first, for its side effects).
                        if (m.optional) break :blk Value.boolVal(true);
                        if (m.computed) |ce| _ = try self.eval(ce);
                        return self.throwError("TypeError", "Cannot convert undefined or null to object");
                    }
                    if (!obj.isObject()) break :blk Value.boolVal(true);
                    const key = try self.memberKey(m.property, m.computed);
                    const ok = try self.deleteOwn(obj.asObj(), key);
                    // Strict mode: a failed delete (a non-configurable property)
                    // is a TypeError rather than a `false` result.
                    if (!ok and self.strict) return self.throwError("TypeError", "Cannot delete property");
                    break :blk Value.boolVal(ok);
                }
                // `delete <name>` inside a `with` deletes from the binding object
                // (an object environment record); elsewhere a bare-name delete
                // resolves the reference's base. A property of the global object
                // (a built-in like `JSON`, a global `var`/`function`, or a sloppy
                // implicit global) deletes per [[Configurable]] — so configurable
                // built-ins go, non-configurable global vars stay (false). A name
                // bound only in a declarative record (`let`/`const`, or a
                // function-local) is not deletable → false.
                if (target.* == .identifier) {
                    if (try self.assignWithObject(target.identifier)) |o| {
                        const ok = try self.deleteOwn(o, target.identifier);
                        if (!ok and self.strict) return self.throwError("TypeError", "Cannot delete property");
                        break :blk Value.boolVal(ok);
                    }
                    if (self.global_object) |g| {
                        if (objectHasOwn(g, target.identifier)) {
                            const ok = try self.deleteOwn(g, target.identifier);
                            if (!ok and self.strict) return self.throwError("TypeError", "Cannot delete property");
                            break :blk Value.boolVal(ok);
                        }
                    }
                    if (bindingEnvOf(self.env, target.identifier)) |e| {
                        // A deletable binding (a sloppy eval-created var/function in a
                        // function variable env) is removed and `delete` is true; a
                        // later reference is then unresolvable. Any other declarative
                        // binding (`let`/`const`/param/ordinary var) is non-deletable.
                        if (e.deletable.contains(target.identifier)) {
                            _ = e.removeVar(target.identifier);
                            break :blk Value.boolVal(true);
                        }
                        if (self.strict) return self.throwError("TypeError", "Cannot delete binding");
                        break :blk Value.boolVal(false);
                    }
                    break :blk Value.boolVal(true);
                }
                // Any other operand (a CallExpression, literal, parenthesized
                // expression, …) is not a Reference: evaluate it for its side
                // effects, then `delete` is simply true.
                _ = try self.eval(target);
                break :blk Value.boolVal(true);
            },
            .update => |u| try self.evalUpdate(u.inc, u.prefix, u.target),
            .binary => |b| try self.evalBinary(b.op, b.left, b.right),
            .logical => |l| try self.evalLogical(l.op, l.left, l.right),
            .sequence => |s| blk: {
                _ = try self.eval(s.first);
                break :blk try self.eval(s.second);
            },

            .assign => |a| blk: {
                // A PUBLIC class field initializer desugars to `this.<name> =
                // <field_init_value>`, but DefineField is CreateDataPropertyOrThrow,
                // not [[Set]]: it defines an own data property (shadowing any
                // same-named accessor up the prototype chain) and throws on a
                // non-extensible receiver. The anonymous RHS is named with the
                // field name.
                if (a.value.* == .field_init_value and a.target.* == .member) {
                    const m = a.target.member;
                    const obj = try self.eval(m.object);
                    const key = try self.memberKey(m.property, m.computed);
                    const v = try self.eval(a.value);
                    try self.maybeNameAnon(v, a.value.field_init_value, key);
                    if (obj.isObject()) {
                        const o = obj.asObj();
                        if (o.proxy_handler != null or o.proxy_revoked or isModuleNs(o)) {
                            // A Proxy / module-namespace receiver must observe the
                            // field through [[DefineOwnProperty]] (the `defineProperty`
                            // trap, or — for a deferred namespace — its evaluation
                            // trigger), as a CreateDataPropertyOrThrow {w,e,c}=true
                            // data descriptor.
                            const desc = (try self.newObject()).asObj();
                            try self.setProp(desc, "value", v);
                            try self.setProp(desc, "writable", Value.boolVal(true));
                            try self.setProp(desc, "enumerable", Value.boolVal(true));
                            try self.setProp(desc, "configurable", Value.boolVal(true));
                            try builtins.defineOne(self, o, key, desc);
                        } else {
                            if (!objectHasOwn(o, key) and !o.extensible)
                                return self.throwError("TypeError", "Cannot define class field on a non-extensible object");
                            try self.setProp(o, key, v);
                        }
                    }
                    break :blk v;
                }
                if (a.target.* == .call) {
                    _ = try self.eval(a.target);
                    return self.throwError("ReferenceError", "invalid assignment target");
                }
                // Capture the target reference BEFORE the RHS: PutValue uses the
                // initially-created Reference even if the RHS deletes the `with`
                // binding or a direct eval introduces a closer one.
                if (a.target.* == .identifier) {
                    const name = a.target.identifier;
                    if (try self.assignWithObject(name)) |wo| {
                        const v = try self.eval(a.value);
                        try self.maybeNameAnon(v, a.value, name);
                        // SetMutableBinding: step 2 HasProperty (always — observable
                        // on a proxy env), step 3 throws only if absent and strict.
                        const still = try self.hasPropertyResult(wo, name);
                        if (!still and self.strict)
                            return self.throwError("ReferenceError", "binding is no longer defined");
                        try self.setMember(Value.obj(wo), name, v);
                        break :blk v;
                    }
                    if (bindingEnvOf(self.env, name)) |e| {
                        // Read the 4 binding tables under one lock hold (no-GIL
                        // race class); isTdz on the copied value needs no lock.
                        e.lockBindings();
                        const eligible = e.parent != null and !e.consts.contains(name) and
                            !e.fn_names.contains(name) and e.aliases.get(name) == null;
                        const cur = e.vars.get(name) orelse Value.undef();
                        e.unlockBindings();
                        if (eligible and !self.isTdz(cur)) {
                            const v = try self.eval(a.value);
                            try self.maybeNameAnon(v, a.value, name);
                            try e.assign(name, v); // write to the captured binding
                            break :blk v;
                        }
                    }
                }
                // `base[key] = value`: the LeftHandSide is evaluated before the RHS,
                // but RequireObjectCoercible(base) and ToPropertyKey(key) are deferred
                // to PutValue — so the spec order is base, key expression, RHS, THEN
                // the null/undefined check and ToPropertyKey. assignTo would run the
                // RHS first (its caller already evaluated it), tripping a key
                // `toString` / the base check before the RHS.
                if (a.target.* == .member) {
                    const m = a.target.member;
                    if (m.computed) |ce| {
                        const recv = try self.eval(m.object);
                        const kv = try self.eval(ce);
                        const v = try self.eval(a.value);
                        if (recv.isNull() or recv.isUndefined())
                            return self.throwError("TypeError", "cannot set property of null or undefined");
                        if (fastNumericIndex(kv)) |idx| {
                            if (try self.setFastArrayNumericIndex(recv, idx, v)) break :blk v;
                            var fast_key_buf: [24]u8 = undefined;
                            const key = std.fmt.bufPrint(&fast_key_buf, "{d}", .{idx}) catch unreachable;
                            try self.setMember(recv, key, v);
                        } else {
                            try self.setMember(recv, try self.keyOf(kv), v);
                        }
                        break :blk v;
                    }
                }
                // `super[key] = value`: the SuperReference is created before the
                // RHS, so GetThisBinding/GetSuperBase and the computed expression
                // run first. ToPropertyKey(key) is part of PutValue, so it remains
                // after the RHS.
                if (a.target.* == .super_member) {
                    const m = a.target.super_member;
                    const home = self.home_object orelse return self.throwError("SyntaxError", "'super' outside a method");
                    if (!self.this_initialized) return self.throwError("ReferenceError", "Must call super constructor before using 'this'");
                    const parent = home.protoAtomic();
                    const key_val: ?Value = if (m.computed) |ce| try self.eval(ce) else null;
                    const v = try self.eval(a.value);
                    const parent_obj = parent orelse return self.throwError("TypeError", "Cannot set property of null (super)");
                    const key = if (key_val) |kv| try self.keyOf(kv) else m.property;
                    if (!try self.setMemberResult(Value.obj(parent_obj), key, v, self.this_value)) {
                        if (self.strict) return self.throwError("TypeError", "Cannot set property");
                    }
                    break :blk v;
                }
                // PutValue resolves the LHS reference BEFORE the RHS runs: a
                // strict assignment to an unresolvable bare identifier is a
                // ReferenceError even when the RHS then creates a same-named
                // global (`undeclared = (this.undeclared = 5)`) — the reference
                // was already unresolvable. assignTo's own check runs post-RHS and
                // would miss this. (Skip when a `with` is in scope: its object-env
                // HasBinding is observable and assignTo handles it; running it here
                // too would double-fire a proxy `has` trap.)
                if (a.target.* == .identifier and self.strict) {
                    const name = a.target.identifier;
                    var has_with = false;
                    var we: ?*Environment = self.env;
                    while (we) |env| : (we = env.parent) if (env.with_object != null) {
                        has_with = true;
                        break;
                    };
                    if (!has_with and self.env.get(name) == null and !self.globalHasOwn(name)) {
                        _ = try self.eval(a.value); // RHS still runs for its side effects
                        return self.throwError("ReferenceError", name);
                    }
                }
                const v = try self.eval(a.value);
                // NamedEvaluation: `f = function(){}` names the function "f"
                // (only a bare, *unparenthesized* identifier target — a
                // parenthesized `(f) =` is not an IdentifierRef).
                if (a.target.* == .identifier and !a.target_parenthesized) try self.maybeNameAnon(v, a.value, a.target.identifier);
                try self.assignTo(a.target, v);
                break :blk v;
            },

            // Compound assignment `target op= value`: resolve the LeftHandSide
            // reference ONCE, GetValue, then PutValue on the SAME reference.
            .op_assign => |oa| blk: {
                switch (oa.target.*) {
                    .identifier => |name| {
                        // If a `with` object owns the binding, get AND set go to it
                        // (even a self-deleting getter writes back to that object).
                        if (try self.assignWithObject(name)) |wo| {
                            const old = blk_old: {
                                if (!try self.hasPropertyResult(wo, name)) {
                                    if (self.strict) return self.throwError("ReferenceError", name);
                                    break :blk_old Value.undef();
                                }
                                break :blk_old try self.getProperty(Value.obj(wo), name);
                            };
                            const rhs = try self.eval(oa.value);
                            const new = try self.applyBinary(oa.op, old, rhs);
                            // Object env record SetMutableBinding: in strict mode a
                            // binding the getter deleted no longer exists → ReferenceError.
                            if (!try self.hasPropertyResult(wo, name)) {
                                if (self.strict) return self.throwError("ReferenceError", "binding is no longer defined");
                            }
                            try self.setMember(Value.obj(wo), name, new);
                            break :blk new;
                        }
                        // Capture the target's declarative binding BEFORE the RHS,
                        // so a direct eval in the RHS that introduces a closer
                        // binding can't retarget the write (PutValue uses the
                        // initially-created Reference).
                        const benv = bindingEnvOf(self.env, name);
                        const old = try self.eval(oa.target);
                        const rhs = try self.eval(oa.value);
                        const new = try self.applyBinary(oa.op, old, rhs);
                        if (benv) |e| {
                            e.lockBindings();
                            const eligible = e.parent != null and !e.consts.contains(name) and
                                !e.fn_names.contains(name) and e.aliases.get(name) == null;
                            const cur = e.vars.get(name) orelse Value.undef();
                            e.unlockBindings();
                            if (eligible and !self.isTdz(cur)) {
                                try e.assign(name, new); // write to the captured binding
                                break :blk new;
                            }
                        }
                        try self.assignTo(oa.target, new);
                        break :blk new;
                    },
                    .member => |m| {
                        // The base (and a computed key expression) evaluate exactly
                        // once. Mirror a member read's order: the key expression is
                        // evaluated, then the null/undefined base is rejected BEFORE
                        // ToPropertyKey (so `null[obj.toString]` throws without
                        // calling toString), then the property key is formed.
                        const obj = try self.eval(m.object);
                        var fast_key_buf: [24]u8 = undefined;
                        const key: []const u8 = if (m.computed) |ce| blk2: {
                            const kv = try self.eval(ce);
                            if (m.optional and (obj.isNull() or obj.isUndefined())) break :blk Value.undef();
                            if (obj.isNull() or obj.isUndefined())
                                return self.throwError("TypeError", "cannot read property of null or undefined");
                            if (fastNumericIndex(kv)) |idx|
                                break :blk2 std.fmt.bufPrint(&fast_key_buf, "{d}", .{idx}) catch unreachable;
                            break :blk2 try self.keyOf(kv);
                        } else m.property;
                        const old = try self.getProperty(obj, key);
                        const rhs = try self.eval(oa.value);
                        const new = try self.applyBinary(oa.op, old, rhs);
                        try self.setMember(obj, key, new);
                        break :blk new;
                    },
                    else => {
                        if (oa.target.* == .call) {
                            _ = try self.eval(oa.target);
                            return self.throwError("ReferenceError", "invalid assignment target");
                        }
                        // super.x etc.: the base is stable, so read + assignTo are safe.
                        const old = try self.eval(oa.target);
                        const rhs = try self.eval(oa.value);
                        const new = try self.applyBinary(oa.op, old, rhs);
                        try self.assignTo(oa.target, new);
                        break :blk new;
                    },
                }
            },

            .logical_assign => |la| blk: {
                // The LeftHandSide reference is resolved ONCE; the short-circuit
                // predicate then decides whether the RHS runs and the store
                // happens (so `obj[f()] &&= g()` evaluates `f()` once and skips
                // `g()` when the held value is falsy/truthy/non-nullish).
                switch (la.target.*) {
                    .member => |m| {
                        const obj = try self.eval(m.object);
                        var fast_key_buf: [24]u8 = undefined;
                        const key: []const u8 = if (m.computed) |ce| blk2: {
                            const kv = try self.eval(ce);
                            if (obj.isNull() or obj.isUndefined())
                                return self.throwError("TypeError", "cannot read property of null or undefined");
                            if (fastNumericIndex(kv)) |idx|
                                break :blk2 std.fmt.bufPrint(&fast_key_buf, "{d}", .{idx}) catch unreachable;
                            break :blk2 try self.keyOf(kv);
                        } else m.property;
                        const old = try self.getProperty(obj, key);
                        const short = switch (la.op) {
                            .@"and" => !old.toBoolean(),
                            .@"or" => old.toBoolean(),
                            .nullish => !(old.isNull() or old.isUndefined()),
                        };
                        if (short) break :blk old;
                        const rhs = try self.eval(la.value);
                        try self.setMember(obj, key, rhs);
                        break :blk rhs;
                    },
                    else => {
                        // super.x &&= …: the base (home object / `this`) is stable,
                        // so a read followed by assignTo resolves it consistently.
                        const old = try self.eval(la.target);
                        const short = switch (la.op) {
                            .@"and" => !old.toBoolean(),
                            .@"or" => old.toBoolean(),
                            .nullish => !(old.isNull() or old.isUndefined()),
                        };
                        if (short) break :blk old;
                        const rhs = try self.eval(la.value);
                        try self.assignTo(la.target, rhs);
                        break :blk rhs;
                    },
                }
            },

            .function => |fnode| blk: {
                // A *named* function expression binds its own name as an
                // immutable binding in a fresh scope enclosing the body, so the
                // body can refer to itself (recursion) and can't rebind the name.
                if (fnode.has_name_binding and !fnode.is_arrow) {
                    const fenv = try gc_mod.allocEnv(self.arena);
                    self.initEnvironment(fenv, self.env, false);
                    const fv = try self.makeFunction(fnode, fenv);
                    try fenv.putFnName(fnode.name, fv);
                    break :blk fv;
                }
                break :blk try self.makeFunction(fnode, self.env);
            },
            .class_expr => |c| try self.evalClass(c.name, c.superclass, c.members, c.source),

            // `yield` only executes inside a compiled generator body (on the
            // suspendable VM). Reaching it in the tree-walker means a generator
            // body fell outside the VM's lowered subset — report it clearly
            // rather than producing a wrong value.
            .yield_expr => return self.throwError("SyntaxError", "yield is only supported in VM-compiled generator bodies"),

            .await_expr => |a| try self.evalAwait(a.argument),

            .import_meta => try self.evalImportMeta(),
            .import_call => |ic| try self.evalImportCall(ic.specifier, ic.options, ic.phase),

            .super_call => |sc| blk: {
                // `super()` is a SyntaxError outside a derived constructor — the
                // case the parser can't catch is eval'd code (`eval("super()")` in
                // global code, a method, or an arrow not enclosed by a derived
                // constructor). When it IS a derived constructor, a null super
                // constructor is `class … extends null`: GetSuperConstructor yields
                // %Function.prototype%, not a constructor → a runtime TypeError.
                if (!self.in_derived_ctor) return self.throwError("SyntaxError", "'super' keyword unexpected here");
                const sup = blk2: {
                    if (self.active_function) |fn_obj| if (fn_obj.js_func) |erased| {
                        const active: *Function = @ptrCast(@alignCast(erased));
                        if (active.is_derived_constructor) {
                            break :blk2 self.effectiveProto(fn_obj) orelse
                                return self.throwError("TypeError", "Super constructor null is not a constructor");
                        }
                    };
                    break :blk2 self.super_ctor orelse return self.throwError("TypeError", "Super constructor null is not a constructor");
                };
                // A synthesized default derived constructor forwards its arguments
                // to the super constructor DIRECTLY — its `super(...args)` does not
                // run a user-observable spread, so a hijacked Array.prototype
                // @@iterator is never invoked. (`args` is its rest-parameter array.)
                const args = if (self.in_default_ctor) dblk: {
                    const av = self.env.get("args") orelse Value.undef();
                    break :dblk if (av.isObject() and av.asObj().is_array) av.asObj().elements.items else &[_]Value{};
                } else try self.evalArgs(sc);
                // Construct the superclass with the most-derived class as NewTarget,
                // so the produced object's prototype is the derived class's.
                const sup_ret = try self.constructNT(Value.obj(sup), args, self.new_target);
                // BindThisValue: `super()` initializes `this` exactly once — a
                // second call (after the construct's side effects) is a ReferenceError.
                if (self.this_initialized) return self.throwError("ReferenceError", "Super constructor may only be called once");
                // The object the super constructor produces (a built-in exotic from
                // `extends Map/Array/...`, or an object a JS base explicitly returns)
                // *becomes* the `this` binding — its prototype was already set from
                // new_target. Rebind `this` to it (the eagerly-allocated placeholder
                // is discarded); the field initializers / private brands below target it.
                self.this_value = sup_ret;
                self.this_initialized = true;
                // Persist the binding into the shared cell so it survives past this
                // activation — the enclosing derived ctor (and any sibling arrow)
                // reads `this` through the cell.
                if (self.this_cell) |c| {
                    c.value = sup_ret;
                    c.initialized = true;
                }
                // InitializeInstanceElements: a derived class brands `this` with
                // its private names and runs its field initializers now, once
                // `super()` has returned and `this` exists. Clear the pending sets
                // so they apply exactly once.
                const bns = self.pending_brand_names;
                self.pending_brand_names = &.{};
                if (self.this_value.isObject())
                    for (bns) |bn| try self.addPrivateMethodOrAccessorChecked(self.this_value.asObj(), self.home_object, bn);
                const fis = self.pending_field_inits;
                self.pending_field_inits = &.{};
                for (fis) |fi| _ = try self.eval(fi);
                // SuperCall evaluates to the new `this` (BindThisValue's result),
                // so `value = super()` observes the bound object.
                break :blk self.this_value;
            },
            .super_member => |m| blk: {
                const home = self.home_object orelse return self.throwError("SyntaxError", "'super' outside a method");
                // GetThisBinding (SuperProperty step 2) precedes evaluating the
                // property key (step 3): in a derived constructor before `super()`,
                // `super[expr]` / `super.x` is a ReferenceError and `expr` never runs.
                if (!self.this_initialized) return self.throwError("ReferenceError", "Must call super constructor before using 'this'");
                // GetSuperBase is captured BEFORE ToPropertyKey of the computed key,
                // so a key whose `toString` mutates the home object's prototype
                // can't change which base the lookup uses (RequireObjectCoercible:
                // a null/absent prototype is a TypeError). The receiver is `this`,
                // so an inherited accessor observes the current instance.
                const parent = home.protoAtomic() orelse return self.throwError("TypeError", "Cannot read property of null (super)");
                const key = try self.memberKey(m.property, m.computed);
                break :blk try self.getPropertyWithReceiver(Value.obj(parent), key, self.this_value);
            },

            .call => |c| try self.evalCall(c.callee, c.args, c.optional),
            .tagged_template => |t| try self.evalTaggedTemplate(node, t.tag, t.cooked, t.raw, t.exprs),
            .new_expr => |n| try self.evalNew(n.callee, n.args),
            .member => |m| blk: {
                const obj = try self.eval(m.object);
                if (m.optional and (obj.isNull() or obj.isUndefined())) return error.OptShortCircuit;
                if (m.computed) |ce| {
                    // Spec order: GetValue of the key expression first (its side
                    // effects run), THEN the null/undefined base check, THEN
                    // ToPropertyKey — so `base[prop()]` with a throwing `prop()`
                    // surfaces that throw, while `null[obj]` is a TypeError before
                    // the key's `toString` is ever called.
                    const kv = try self.eval(ce);
                    if (obj.isNull() or obj.isUndefined())
                        return self.throwError("TypeError", "cannot read property of null or undefined");
                    var fast_key_buf: [24]u8 = undefined;
                    const key = if (fastNumericIndex(kv)) |idx|
                        std.fmt.bufPrint(&fast_key_buf, "{d}", .{idx}) catch unreachable
                    else
                        try self.keyOf(kv);
                    break :blk try self.getProperty(obj, key);
                }
                break :blk try self.getProperty(obj, m.property);
            },
            .optional_chain => |inner| self.eval(inner) catch |e|
                if (e == error.OptShortCircuit) Value.undef() else return e,
            .field_init_value => |inner| blk: {
                // Evaluate a class instance field initializer with the
                // field-initializer context active, so a direct eval inside it
                // inherits the `super()`/`arguments` early errors.
                const saved_fi = self.in_field_initializer;
                self.in_field_initializer = true;
                defer self.in_field_initializer = saved_fi;
                break :blk try self.eval(inner);
            },
            .private_field_def => |d| blk: {
                // PrivateFieldAdd: brand `this` with this field's name (in
                // declaration order) as an own, writable, non-enumerable,
                // non-configurable property. Per DefineField, the initializer is
                // evaluated FIRST and PrivateFieldAdd (the brand + the
                // extensibility check + the store) happens AFTER — so a field
                // whose initializer seals `this` (`#g = (preventExtensions(this),
                // …)`) makes its own add throw, and a field cannot reference itself.
                const fv = try self.eval(d.value);
                // An anonymous initializer takes the field's source name (`#x`,
                // the part of the storage key before the NUL marker).
                const raw_init = if (d.value.* == .field_init_value) d.value.field_init_value else d.value;
                try self.maybeNameAnon(fv, raw_init, std.mem.sliceTo(d.name, 0));
                if (self.this_value.isObject()) {
                    const o = self.this_value.asObj();
                    try self.addPrivateBrandChecked(o, d.name);
                    try o.setOwn(self.arena, self.root_shape, d.name, fv);
                    try o.setAttr(self.arena, d.name, .{ .writable = true, .enumerable = false, .configurable = false });
                }
                break :blk Value.undef();
            },
            .object_lit => |props| try self.evalObjectLit(props),
            .array_lit => |elems| try self.evalArrayLit(elems),
            .regex_literal => |r| try self.makeRegex(r.pattern, r.flags),
            // Spreads are consumed by array/argument evaluation, never on their own.
            .spread => return self.throwError("SyntaxError", "unexpected spread element"),
            // Patterns are binding targets, not expressions.
            .obj_pattern, .arr_pattern => return self.throwError("SyntaxError", "unexpected destructuring pattern"),

            .conditional => |c| if ((try self.eval(c.cond)).toBoolean())
                try self.eval(c.consequent)
            else
                try self.eval(c.alternate),

            .var_decl => |d| blk: {
                // ResolveBinding happens BEFORE the Initializer is evaluated:
                // for a `var x = init` whose name a `with` object provides,
                // capture that target object first, so a side effect in the
                // initializer (e.g. `delete obj.x`) can't retarget the write.
                const with_target: ?*value.Object = if (d.kind == .@"var" and d.init != null)
                    try self.assignWithObject(d.name)
                else
                    null;
                var v: Value = Value.undef();
                if (d.init) |init_node| {
                    v = try self.eval(init_node);
                    try self.maybeNameAnon(v, init_node, d.name); // `var f = function(){}` ⇒ name "f"
                }
                // `var` hoists to the variable scope (and mirrors onto the global
                // object); `let`/`const` bind in the current (possibly block) scope.
                if (d.kind == .@"var") {
                    // A `var x = init` inside a `with` whose object provides `x`
                    // assigns the initializer to that object (ResolveBinding walks
                    // the object Environment Record), leaving the hoisted var
                    // binding untouched — exactly like a bare `x = init`. Without
                    // an initializer, or when no `with` shadows the name, the var
                    // scope binding takes the value as before.
                    if (d.init != null) {
                        if (with_target) |o| {
                            try self.setMember(Value.obj(o), d.name, v);
                            break :blk Value.undef();
                        }
                        if (catchParamBindingEnvOf(self.env, d.name)) |catch_env| {
                            try catch_env.assign(d.name, v);
                            break :blk Value.undef();
                        }
                        try self.globalDefine(d.name, v);
                    }
                    // A bare `var x;` (no initializer) is a runtime no-op: the
                    // binding already exists from declaration instantiation
                    // (hoistVarNames runs at the var scope before the body). Calling
                    // globalDefine here would clobber a prior value (`var x=5; var x;`
                    // ⇒ 5, not undefined) and resurrect a binding a preceding
                    // `delete` removed (a sloppy eval's deletable var).
                } else if (d.kind == .@"const") {
                    try self.checkRestrictedGlobalLexical(d.name);
                    try self.env.putConst(d.name, v);
                } else {
                    try self.checkRestrictedGlobalLexical(d.name);
                    try self.env.put(d.name, v);
                }
                // A `using`/`await using` binding registers its resource for
                // disposal when the enclosing scope exits.
                if (d.dispose != 0) try self.addDisposable(v, d.dispose == 2);
                break :blk Value.undef();
            },

            .func_decl => |fnode| blk: {
                // Reached only for a function declaration that is the *bare* body
                // of an `if`/loop/label (a function in a statement list is hoisted
                // by `evalStatements`, not evaluated here). Annex B B.3.3 treats it
                // as block-scoped: it creates the legacy var binding only when the
                // name is eligible; otherwise the binding is purely local (and dies
                // with the statement, so nothing leaks to the enclosing scope).
                const block_env = try gc_mod.allocEnv(self.arena);
                self.initEnvironment(block_env, self.env, false);
                const saved_env = self.env;
                self.env = block_env;
                defer self.env = saved_env;
                const fnv = try self.makeFunction(fnode, block_env);
                try block_env.put(fnode.name, fnv);
                if (self.annexb_legacy_nodes) |set| {
                    if (set.contains(node)) try self.globalDefineDeletable(fnode.name, fnv);
                }
                break :blk Value.undef();
            },

            // Module declarations. Import bindings are wired during linking
            // (`Context.linkModule`), so an `import` is a runtime no-op. An
            // `export` evaluates its inner declaration/expression so the local
            // bindings exist; the module's export map (built at link time) reads
            // those bindings live from the module environment.
            .import_decl => Value.undef(),
            .export_decl => |e| blk: {
                if (e.declaration) |d| break :blk try self.eval(d);
                if (e.default_expr) |dx| {
                    const v = switch (dx.*) {
                        // `export default function/class` — a named or anonymous
                        // declaration whose value binds to the synthetic "*default*"
                        // (and its own name, when present, for self-reference).
                        .func_decl => |fnode| try self.makeFunction(fnode, self.env),
                        .class_expr => |c| try self.evalClass(
                            if (c.name.len > 0) c.name else "default",
                            c.superclass,
                            c.members,
                            c.source,
                        ),
                        else => try self.eval(dx),
                    };
                    if (e.default_name.len > 0) {
                        try self.env.put(e.default_name, v);
                    } else if (v.isObject()) {
                        // `export default function(){}` / `class{}` / arrow / other
                        // anonymous AssignmentExpression: NamedEvaluation names it
                        // "default".
                        try self.maybeNameAnon(v, dx, "default");
                    }
                    try self.env.put("*default*", v);
                    break :blk Value.undef();
                }
                break :blk Value.undef(); // `export { … }` / `export * …`: no runtime effect
            },

            .destructure_decl => |d| blk: {
                const v = try self.eval(d.init);
                const saved = self.binding_hoisted;
                const saved_c = self.binding_const;
                self.binding_hoisted = (d.kind == .@"var");
                self.binding_const = (d.kind == .@"const");
                defer self.binding_hoisted = saved;
                defer self.binding_const = saved_c;
                try self.bindPattern(d.pattern, v, true);
                break :blk Value.undef();
            },

            .return_stmt => |maybe| blk: {
                const v: Value = if (maybe) |e| try self.eval(e) else Value.undef();
                self.ret_value = v;
                self.signal = .ret;
                break :blk v;
            },

            .throw_stmt => |e| {
                self.exception = try self.eval(e);
                return error.Throw;
            },

            .try_stmt => |t| try self.evalTry(t),

            .break_stmt => |label| blk: {
                self.signal = .brk;
                self.signal_label = label;
                break :blk Value.undef();
            },
            .continue_stmt => |label| blk: {
                self.signal = .cont;
                self.signal_label = label;
                break :blk Value.undef();
            },
            .labeled_stmt => |l| blk: {
                self.current_label = l.label; // adopted by the loop it wraps
                const result = try self.eval(l.body);
                // A labeled break that reached here (e.g. on a labeled block) is consumed.
                if (self.signal == .brk and labelEq(self.signal_label, l.label)) {
                    self.signal = .none;
                    self.signal_label = null;
                }
                break :blk result;
            },

            .expr_stmt => |e| try self.eval(e),

            // A `{…}` block is its own lexical scope: `let`/`const`/`class` and
            // block function declarations live here, `var` hoists past it; any
            // `using` resources are disposed when it exits.
            .block => |stmts| try self.evalBlockScope(stmts),
            // A multi-declarator group runs in the current scope (no new block).
            .decl_group => |stmts| try self.evalStatements(stmts),
            .program => |stmts| blk: {
                // GlobalDeclarationInstantiation early errors run once per Script,
                // here at the program root — NOT inside evalStatements, which is
                // re-entered for `decl_group`s (`let a, b`) in the same scope.
                try self.checkGlobalDeclConflicts(stmts);
                break :blk try self.evalStatements(stmts);
            },

            .if_stmt => |s| if ((try self.eval(s.cond)).toBoolean())
                try self.eval(s.consequent)
            else if (s.alternate) |alt|
                try self.eval(alt)
            else
                Value.undef(),

            .with_stmt => |w| blk: {
                // The binding object is ToObject(expr): a primitive is boxed,
                // null/undefined throw — only those throw, not every non-object.
                const obj = try self.toObject(try self.eval(w.obj));
                // Push an object Environment Record onto the lexical chain. A
                // function defined in the body captures it via its closure, and a
                // binding declared inside the body shadows it — both fall out of
                // the chain position automatically.
                const wenv = try gc_mod.allocEnv(self.arena);
                self.initEnvironment(wenv, self.env, false);
                wenv.with_object = obj;
                const saved_env = self.env;
                self.env = wenv;
                defer self.env = saved_env;
                break :blk try self.eval(w.body);
            },
            .while_stmt => |s| try self.evalWhile(s.cond, s.body),
            .do_while_stmt => |s| blk: {
                const my_label = self.takeLabel();
                var last: Value = Value.undef();
                while (true) {
                    last = try self.eval(s.body);
                    if (self.loopSignal(my_label)) |stop| if (stop) break;
                    if (!(try self.eval(s.cond)).toBoolean()) break;
                }
                break :blk last;
            },
            .for_stmt => |f| try self.evalFor(f.init, f.cond, f.update, f.body),
            .switch_stmt => |s| try self.evalSwitch(s.disc, s.cases),
            .for_in => |f| try self.evalForInOf(f.decl_kind, f.target, f.var_init, f.iterable, f.body, f.is_of, f.is_await, f.dispose),
        };
    }

    /// `for-of` (values of arrays/strings) and `for-in` (own keys of objects /
    /// indices of arrays). Each iteration binds the loop variable then runs the
    /// body, honoring break/continue/return.
    fn evalForInOf(self: *Interpreter, decl_kind: ?ast.DeclKind, target: *Node, var_init: ?*Node, iterable: *Node, body: *Node, is_of: bool, is_await: bool, dispose: u8) EvalError!Value {
        const my_label = self.takeLabel();
        // A `let`/`const` loop binding gets a fresh declarative environment per
        // iteration, so a closure created in the head or body captures *that*
        // iteration's binding (`var` is function-scoped, so it doesn't).
        const lexical = decl_kind != null and decl_kind.? != .@"var";
        const outer_env = self.env;
        if (var_init) |ini| {
            const init_value = try self.eval(ini);
            try self.bindLoopTarget(decl_kind, target, init_value);
        }
        // Head evaluation: per spec the loop bindings are declared (in their TDZ)
        // in a fresh environment while the iterable expression runs, so a closure
        // captured there sees them uninitialized (`typeof x` throws).
        var iter: Value = undefined;
        if (lexical and self.tdz_marker != null) {
            const head_env = try gc_mod.allocEnv(self.arena);
            self.initEnvironment(head_env, outer_env, false);
            self.env = head_env;
            self.tdzBindPattern(target, self.tdzVal());
            iter = self.eval(iterable) catch |e| {
                self.env = outer_env;
                return e;
            };
            self.env = outer_env;
        } else {
            iter = try self.eval(iterable);
        }
        var last: Value = Value.undef();
        if (is_of) {
            // Generic iterator protocol: obtain the iterator (generators are
            // their own; arrays/strings get an index cursor; a user object's
            // `[Symbol.iterator]()` is honored), then pull `.next()` until done.
            // `for await`: the async iterator (Symbol.asyncIterator, else a sync
            // iterator) and each `next()` result is awaited.
            const iter_obj = if (is_await) try self.asyncIteratorOf(iter) else try self.iteratorOf(iter);
            const iter_root = try self.pushTempRoot(iter_obj);
            defer self.restoreTempRoots(iter_root);
            // GetIterator reads the iterator's `next` method exactly ONCE (it
            // becomes the Iterator Record's [[NextMethod]]); IteratorNext reuses
            // it. A `next` accessor must therefore not be re-read per iteration.
            const next_method = try self.getProperty(iter_obj, "next");
            const next_root = try self.pushTempRoot(next_method);
            defer self.restoreTempRoots(next_root);
            while (true) {
                const res0 = try self.callValueWithThis(next_method, &.{}, iter_obj);
                const res0_root = try self.pushTempRoot(res0);
                defer self.restoreTempRoots(res0_root);
                const res = if (is_await) try self.awaitValue(res0) else res0;
                const res_root = try self.pushTempRoot(res);
                defer self.restoreTempRoots(res_root);
                // IteratorNext: the result of `next()` must be an Object (a Symbol
                // or BigInt is object-tagged here but is not an Object per Type()).
                if (!builtins.isRealObject(res)) return self.throwError("TypeError", "iterator result is not an object");
                if ((try self.getProperty(res, "done")).toBoolean()) break; // exhausted — no close
                const saved_env = self.env;
                defer self.env = saved_env;
                // The per-iteration env also holds a `for (using x of …)` resource,
                // disposed (DisposeResources) at the END of each iteration.
                var iter_env: ?*Environment = null;
                if (lexical) {
                    const e = try gc_mod.allocEnv(self.arena);
                    self.initEnvironment(e, saved_env, false);
                    self.env = e;
                    iter_env = e;
                }
                // Binding/assigning the loop target is also an abrupt-completion
                // close site: if PutValue or a destructuring assignment throws
                // (e.g. a setter on `for (x.attr of it)`), IteratorClose runs
                // before the error propagates. (IteratorValue itself — the
                // `.value` get — does NOT close, so it stays outside the catch.)
                const next_value = try self.getProperty(res, "value");
                self.bindLoopTarget(decl_kind, target, next_value) catch |e| {
                    self.iteratorCloseKeepingThrow(iter_obj);
                    return e;
                };
                // `for (using/await using x of …)`: register the bound resource for
                // disposal at the end of this iteration.
                if (dispose != 0) self.addDisposable(next_value, dispose == 2) catch |e| {
                    self.iteratorCloseKeepingThrow(iter_obj);
                    return e;
                };
                // A throw in the body closes the iterator before propagating. On a
                // throw completion any error from IteratorClose is discarded AND the
                // original thrown value is preserved (iteratorClose can overwrite
                // `self.exception` via a throwing `return`/get-method).
                last = self.eval(body) catch |e| {
                    if (e == error.Throw) if (iter_env) |ie| if (ie.disposables.items.len > 0) {
                        const body_err = self.exception;
                        if (self.disposeScope(ie, body_err) catch null) |de| self.exception = de;
                    };
                    self.iteratorCloseKeepingThrow(iter_obj);
                    return e;
                };
                // DisposeResources at the end of a normal iteration; a disposal error
                // is a throw completion that also closes the iterator.
                if (iter_env) |ie| if (ie.disposables.items.len > 0) {
                    if (try self.disposeScope(ie, null)) |de| {
                        self.exception = de;
                        self.iteratorCloseKeepingThrow(iter_obj);
                        return error.Throw;
                    }
                };
                // `break`/`return` (an abrupt loop exit) also closes the iterator.
                // Unlike the throw case above, this is a normal/return completion,
                // so an error from IteratorClose (a non-callable `return`, or a
                // `return()` that yields a non-object) PROPAGATES rather than being
                // swallowed.
                if (self.loopSignal(my_label)) |stop| if (stop) {
                    const ss = self.signal;
                    const sr = self.ret_value;
                    self.signal = .none;
                    try self.iteratorClose(iter_obj);
                    self.signal = ss;
                    self.ret_value = sr;
                    break;
                };
            }
        } else {
            // for-in: enumerate keys (skip null/undefined per spec, ToObject any
            // other primitive — e.g. a string's character indices).
            switch (iter.kind()) {
                .undefined, .null => {}, // iterating null/undefined is a no-op
                else => {
                    const o = try self.toObject(iter);
                    // EnumerateObjectProperties: own + inherited enumerable string
                    // keys with prototype-chain shadowing (see forInKeyList).
                    for (try self.forInKeyList(o)) |k| {
                        // A property deleted (or made non-enumerable) before it is
                        // reached must not be visited: the key list is a snapshot,
                        // so re-check the property still exists on the chain.
                        if (!try self.hasPropertyResult(o, k)) continue;
                        const saved_env = self.env;
                        defer self.env = saved_env;
                        if (lexical) {
                            const ie = try gc_mod.allocEnv(self.arena);
                            self.initEnvironment(ie, saved_env, false);
                            self.env = ie;
                        }
                        try self.bindLoopTarget(decl_kind, target, Value.str(k));
                        last = try self.eval(body);
                        if (self.loopSignal(my_label)) |stop| if (stop) break;
                    }
                },
            }
        }
        return last;
    }

    /// EnumerateObjectProperties: the ordered string keys visited by `for-in`,
    /// walking the prototype chain. A key is emitted once (the first time it is
    /// seen on the chain); a shadowing own property — enumerable or not —
    /// suppresses any same-named property further up. Array dense element indices
    /// (skipping holes) are own enumerable keys outside the shape. Symbol/private
    /// keys are excluded.
    pub fn forInKeyList(self: *Interpreter, start: *value.Object) EvalError![]const []const u8 {
        var out: std.ArrayListUnmanaged([]const u8) = .empty;
        var visited: std.StringHashMapUnmanaged(void) = .empty;
        var cur: ?*value.Object = start;
        while (cur) |o| {
            // A String wrapper's own enumerable character indices "0".."len-1".
            if (o.prim) |p| if (p.isString()) {
                var i: usize = 0;
                while (i < utf16LenOfString(p.asStr())) : (i += 1) {
                    const key = try std.fmt.allocPrint(self.arena, "{d}", .{i});
                    if (visited.contains(key)) continue;
                    try visited.put(self.arena, key, {});
                    try out.append(self.arena, key);
                }
            };
            if (o.is_array or o.elements.items.len != 0) {
                var i: usize = 0;
                while (i < o.elementsLen()) : (i += 1) {
                    if (!o.denseElementPresent(i)) continue;
                    const key = try std.fmt.allocPrint(self.arena, "{d}", .{i});
                    // Accessor at this index comes from ownKeys below.
                    if (o.getAccessor(key) != null) continue;
                    if (visited.contains(key)) continue;
                    try visited.put(self.arena, key, {});
                    if (o.getAttr(key).enumerable) try out.append(self.arena, key);
                }
            }
            // A TypedArray's integer-indexed elements are own enumerable keys
            // (outside the shape); enumerate the current length (which a resizable
            // backing buffer may have shrunk or grown).
            if (o.typed_array) |ta| {
                var i: usize = 0;
                const len = ta.currentLength() orelse 0;
                while (i < len) : (i += 1) {
                    const key = try std.fmt.allocPrint(self.arena, "{d}", .{i});
                    if (visited.contains(key)) continue;
                    try visited.put(self.arena, key, {});
                    try out.append(self.arena, key);
                }
            }
            const own_keys = if (o.proxy_handler != null or o.proxy_revoked or o.module_ns != null)
                try self.objectOwnKeysList(o)
            else
                try o.ownKeys(self.arena);
            for (own_keys) |k| {
                if (value.isSymbolKey(k) or value.isPrivateKey(k)) continue;
                if (visited.contains(k)) continue;
                try visited.put(self.arena, k, {});
                const enumerable = if (moduleNsOf(o) != null) blk: {
                    const desc = try moduleNsDesc(self, o, k);
                    break :blk desc.isObject() and if (desc.asObj().getOwn("enumerable")) |e| e.toBoolean() else false;
                } else if (o.proxy_handler != null or o.proxy_revoked) blk: {
                    const desc = try builtins.objectGetOwnPropertyDescriptor(@ptrCast(self), Value.undef(), &.{ Value.obj(o), self.keyToValue(k) });
                    break :blk desc.isObject() and if (desc.asObj().getOwn("enumerable")) |e| e.toBoolean() else false;
                } else o.getAttr(k).enumerable;
                if (enumerable) try out.append(self.arena, k);
            }
            cur = o.protoAtomic();
        }
        return out.items;
    }

    /// The for-in key list of `v` as a fresh array. Null/undefined (and
    /// primitives) yield an empty array. Used by the generator VM's `enum_keys`
    /// opcode to drive for-in via the for-of machinery.
    pub fn forInKeysArray(self: *Interpreter, v: Value) EvalError!Value {
        const arr = (try self.newArray()).asObj();
        // ForIn/OfHeadEvaluation: undefined/null enumerate nothing; any other
        // value is ToObject'd first (so a primitive string yields its indices).
        if (!v.isUndefined() and !v.isNull()) {
            const o = try self.toObject(v);
            for (try self.forInKeyList(o)) |k| {
                try arr.elements.append(arr.elementsAllocator(self.arena), Value.str(k));
            }
        }
        return Value.obj(arr);
    }

    /// Bind one iteration's value to the loop target: a declaration declares
    /// (identifier or destructuring pattern), an assignment form assigns to an
    /// existing identifier / member / pattern.
    fn bindLoopTarget(self: *Interpreter, decl_kind: ?ast.DeclKind, target: *Node, v: Value) EvalError!void {
        if (decl_kind) |k| {
            if (k == .@"var") return self.assignTo(target, v);
            const saved = self.binding_const;
            self.binding_const = (k == .@"const");
            defer self.binding_const = saved;
            try self.bindPattern(target, v, true);
        } else try self.assignTo(target, v);
    }

    /// `switch`: evaluate the discriminant, find the first strictly-equal `case`
    /// (or `default`), then run from there with fall-through until a `break`.
    fn evalSwitch(self: *Interpreter, disc_node: *Node, cases: []ast.SwitchCase) EvalError!Value {
        // The discriminant evaluates in the enclosing scope; the whole CaseBlock
        // is then one lexical (declarative) environment, so a `let`/`const`/class
        // in any case is block-scoped to the switch (and case-test expressions
        // evaluate within it).
        const disc = try self.eval(disc_node);
        const block_env = try gc_mod.allocEnv(self.arena);
        self.initEnvironment(block_env, self.env, false);
        const saved_env = self.env;
        self.env = block_env;
        defer self.env = saved_env;
        // Instantiate the CaseBlock's lexical declarations (across all cases):
        // function declarations are block-scoped (with the Annex B B.3.3 legacy
        // copy), and let/const/class get the temporal-dead-zone sentinel.
        for (cases) |c| for (c.body) |s| switch (s.*) {
            .func_decl => |fnode| {
                const fnv = try self.makeFunction(fnode, self.env);
                try self.env.put(fnode.name, fnv);
                if (self.annexb_legacy_nodes) |set| if (set.contains(s)) try self.globalDefineDeletable(fnode.name, fnv);
            },
            else => {},
        };
        if (self.tdz_marker) |_| {
            const tdz = self.tdzVal();
            for (cases) |c| for (c.body) |s| switch (s.*) {
                .var_decl => |d| if (d.kind != .@"var") try self.env.put(d.name, tdz),
                .decl_group => |g| for (g) |gs| switch (gs.*) {
                    .var_decl => |d| if (d.kind != .@"var") try self.env.put(d.name, tdz),
                    else => {},
                },
                .destructure_decl => |d| if (d.kind != .@"var") self.tdzBindPattern(d.pattern, tdz),
                .class_expr => |c2| if (c2.name.len > 0) try self.env.put(c2.name, tdz),
                else => {},
            };
        }
        var start: ?usize = null;
        for (cases, 0..) |c, i| {
            if (c.@"test") |t| {
                if (value.strictEquals(disc, try self.eval(t))) {
                    start = i;
                    break;
                }
            }
        }
        if (start == null) {
            for (cases, 0..) |c, i| {
                if (c.@"test" == null) {
                    start = i;
                    break;
                }
            }
        }
        var last: Value = Value.undef();
        if (start) |si| {
            var i = si;
            outer: while (i < cases.len) : (i += 1) {
                for (cases[i].body) |stmt| {
                    if (stmt.* == .func_decl) continue; // hoisted above
                    const r = try self.eval(stmt);
                    if (self.signal != .none) {
                        // UpdateEmpty: a raw break/continue is empty (keep `last`);
                        // a compound statement carries its own folded value.
                        if (!abruptCompletionEmpty(stmt)) last = r;
                        break :outer;
                    }
                    // UpdateEmpty: an empty statement completion (declarations,
                    // empty statement/block) does not replace the case block's value.
                    if (!self.stmtCompletionEmpty(stmt)) last = r;
                }
            }
            // An unlabeled `break` exits the switch; a labeled one targets an
            // enclosing loop and must keep propagating.
            if (self.signal == .brk and self.signal_label == null) self.signal = .none;
        }
        if (block_env.disposables.items.len != 0) {
            if (try self.disposeScope(block_env, null)) |err| {
                self.exception = err;
                return error.Throw;
            }
        }
        // CaseBlockEvaluation returns NormalCompletion(undefined) when no case
        // statement produced a value — a concrete value, never an empty completion.
        self.completion_empty = false;
        return last;
    }

    fn evalWhile(self: *Interpreter, cond: *Node, body: *Node) EvalError!Value {
        const my_label = self.takeLabel();
        var last: Value = Value.undef();
        while ((try self.eval(cond)).toBoolean()) {
            last = try self.eval(body);
            if (self.loopSignal(my_label)) |stop| if (stop) break;
        }
        return last;
    }

    fn evalFor(self: *Interpreter, init_node: ?*Node, cond: ?*Node, update: ?*Node, body: *Node) EvalError!Value {
        const my_label = self.takeLabel();
        // Collect the lexical (`let`/`const`) binding names declared in the init,
        // if any. They get a fresh, value-copied environment each iteration so a
        // closure created in the body captures that iteration's binding.
        var names: std.ArrayListUnmanaged([]const u8) = .empty;
        if (init_node) |ini| collectForLexNames(ini, &names, self.arena);
        const lexical = names.items.len > 0;

        const outer = self.env;
        defer if (lexical) {
            self.env = outer;
        };
        // The for-head's lexical environment, which holds any `using`/`await using`
        // resource declared in the init — disposed at the END of the ForStatement.
        var loop_env: ?*Environment = null;
        if (init_node) |ini| {
            if (lexical) {
                // The loop's lexical declaration lives in its own environment.
                const le = try gc_mod.allocEnv(self.arena);
                self.initEnvironment(le, outer, false);
                self.env = le;
                loop_env = le;
            }
            // A later initializer in the head can throw after an earlier `using`
            // resource was registered (`for (using a = x, b = throws(); …)`); the
            // already-acquired resources are disposed before the error propagates.
            _ = self.eval(ini) catch |e| {
                if (e == error.Throw) if (loop_env) |le| if (le.disposables.items.len > 0) {
                    const body_err = self.exception;
                    if (self.disposeScope(le, body_err) catch null) |de| self.exception = de;
                };
                return e;
            };
        }
        // CreatePerIterationEnvironment (initial copy, before the first test).
        if (lexical) self.env = try self.perIterEnv(outer, names.items, self.env);

        const last = self.runForBody(cond, update, body, my_label, lexical, outer, names.items) catch |e| {
            // DisposeResources runs on an abrupt completion too, threading the error.
            if (loop_env) |le| if (le.disposables.items.len > 0 and e == error.Throw) {
                const body_err = self.exception;
                if (try self.disposeScope(le, body_err)) |err| self.exception = err;
            };
            return e;
        };
        if (loop_env) |le| if (le.disposables.items.len > 0) {
            if (try self.disposeScope(le, null)) |err| {
                self.exception = err;
                return error.Throw;
            }
        };
        return last;
    }

    /// The `for` loop's iteration, factored out so `evalFor` can run DisposeResources
    /// for a for-head `using` on both normal and abrupt completion.
    fn runForBody(self: *Interpreter, cond: ?*Node, update: ?*Node, body: *Node, my_label: ?[]const u8, lexical: bool, outer: *Environment, names: []const []const u8) EvalError!Value {
        var last: Value = Value.undef();
        while (true) {
            if (cond) |c| {
                if (!(try self.eval(c)).toBoolean()) break;
            }
            last = try self.eval(body);
            if (self.loopSignal(my_label)) |stop| if (stop) break;
            // CreatePerIterationEnvironment: copy this iteration's bindings into a
            // fresh env, then run the update against it.
            if (lexical) self.env = try self.perIterEnv(outer, names, self.env);
            if (update) |u| _ = try self.eval(u);
        }
        return last;
    }

    /// A fresh per-iteration environment for a `for (let …; …; …)` loop: a child
    /// of `outer` holding each lexical binding, value-copied from `prev`.
    fn perIterEnv(self: *Interpreter, outer: *Environment, names: []const []const u8, prev: *Environment) EvalError!*Environment {
        const e = try gc_mod.allocEnv(self.arena);
        self.initEnvironment(e, outer, false);
        for (names) |n| {
            const v = prev.get(n) orelse Value.undef();
            // Preserve const-ness across the per-iteration copy so a `const`
            // loop binding stays immutable — `for (const i = 0; …; i++)` is a
            // TypeError at the update, not a silent reassignment.
            if (prev.isConst(n)) |is_const| {
                if (is_const) try e.putConst(n, v) else try e.put(n, v);
            } else try e.put(n, v);
        }
        return e;
    }

    /// Collect the names bound by a `for` loop's lexical (`let`/`const`) init.
    /// Returns nothing for a `var`/expression init (no per-iteration scope).
    fn collectForLexNames(node: *Node, out: *std.ArrayListUnmanaged([]const u8), arena: std.mem.Allocator) void {
        switch (node.*) {
            .var_decl => |d| if (d.kind != .@"var") {
                out.append(arena, d.name) catch {};
            },
            .destructure_decl => |d| if (d.kind != .@"var") {
                collectPatternNames(d.pattern, out, arena);
            },
            .decl_group => |group| for (group) |n| collectForLexNames(n, out, arena),
            else => {},
        }
    }

    /// Append every identifier bound by a destructuring pattern.
    fn collectPatternNames(target: *Node, out: *std.ArrayListUnmanaged([]const u8), arena: std.mem.Allocator) void {
        switch (target.*) {
            .identifier => |name| out.append(arena, name) catch {},
            .obj_pattern => |p| {
                for (p.props) |pr| collectPatternNames(pr.target, out, arena);
                if (p.rest) |r| if (r.* == .identifier) out.append(arena, r.identifier) catch {};
            },
            .arr_pattern => |p| {
                for (p.elems) |e| if (e.target) |t| collectPatternNames(t, out, arena);
                if (p.rest) |r| collectPatternNames(r, out, arena);
            },
            else => {},
        }
    }

    /// Consume the label of the enclosing `labeled_stmt`, if any. A loop calls
    /// this at entry so it knows which labeled break/continue target it, and so
    /// nested loops don't inherit the label.
    fn takeLabel(self: *Interpreter) ?[]const u8 {
        const l = self.current_label;
        self.current_label = null;
        return l;
    }

    /// Inspect the control-flow signal at a loop boundary, given the loop's own
    /// label (`my_label`). Returns null (nothing pending), true (break this
    /// loop), or false (continue). A labeled break/continue aimed at an *outer*
    /// loop breaks this loop but leaves the signal set to keep propagating.
    fn loopSignal(self: *Interpreter, my_label: ?[]const u8) ?bool {
        switch (self.signal) {
            .none => return null,
            .ret => return true, // leave set; the function unwinds
            .brk => {
                if (self.signal_label == null or labelEq(self.signal_label, my_label)) {
                    self.signal = .none;
                    self.signal_label = null;
                    return true;
                }
                return true; // labeled break for an outer loop: exit, keep signal
            },
            .cont => {
                if (self.signal_label == null or labelEq(self.signal_label, my_label)) {
                    self.signal = .none;
                    self.signal_label = null;
                    return false;
                }
                return true; // labeled continue for an outer loop: exit, keep signal
            },
        }
    }

    fn evalUpdate(self: *Interpreter, inc: bool, prefix: bool, target: *Node) EvalError!Value {
        // A read-modify-write through a `with` binding resolves the binding object
        // ONCE: a getter that mutates the scope (e.g. deletes its own property)
        // must not let the write retarget a different binding. (op_assign does the
        // same; see its identifier branch.)
        if (target.* == .identifier) {
            if (try self.assignWithObject(target.identifier)) |wo| {
                const name = target.identifier;
                var ov = try self.getProperty(Value.obj(wo), name);
                if (ov.isObject() and !ov.asObj().is_bigint and !ov.asObj().is_symbol)
                    ov = try self.toPrimitive(ov, .number);
                // Object env record SetMutableBinding: in strict mode, a binding the
                // getter deleted no longer exists → ReferenceError on write-back.
                if (ov.isObject() and ov.asObj().is_bigint) {
                    const b = ov.asObj().bigint;
                    const up = try self.makeBigInt(if (inc) b +% 1 else b -% 1);
                    if (self.strict and !(try self.hasPropertyResult(wo, name)))
                        return self.throwError("ReferenceError", "binding is no longer defined");
                    try self.setMember(Value.obj(wo), name, up);
                    return if (prefix) up else ov;
                }
                const o = ov.toNumber();
                const up = if (inc) o + 1 else o - 1;
                if (self.strict and !(try self.hasPropertyResult(wo, name)))
                    return self.throwError("ReferenceError", "binding is no longer defined");
                try self.setMember(Value.obj(wo), name, Value.num(up));
                return Value.num(if (prefix) up else o);
            }
        }
        // A computed member target `base[prop]++` evaluates its reference (base
        // and the ToPropertyKey of prop) exactly once — read and write go through
        // the same captured (recv, key). (Non-computed/private members have no
        // side-effecting key, so they fall through to the eval+assignTo path.)
        if (target.* == .member and target.member.computed != null and !target.member.optional) {
            const recv = try self.eval(target.member.object);
            // Evaluate the key expression (GetValue) but defer ToPropertyKey: a
            // nullish base is a TypeError BEFORE the key is coerced, so
            // `++null[{toString(){throw}}]` throws TypeError, not the toString error.
            const key_val = try self.eval(target.member.computed.?);
            if (recv.isNull() or recv.isUndefined())
                return self.throwError("TypeError", "Cannot read properties of null or undefined");
            const key = try self.keyOf(key_val);
            var ov = try self.getProperty(recv, key);
            if (ov.isObject() and !ov.asObj().is_bigint and !ov.asObj().is_symbol)
                ov = try self.toPrimitive(ov, .number);
            if (ov.isObject() and ov.asObj().is_bigint) {
                const b = ov.asObj().bigint;
                const up = try self.makeBigInt(if (inc) b +% 1 else b -% 1);
                try self.setMember(recv, key, up);
                return if (prefix) up else ov;
            }
            const o = ov.toNumber();
            const up = if (inc) o + 1 else o - 1;
            try self.setMember(recv, key, Value.num(up));
            return Value.num(if (prefix) up else o);
        }
        if (target.* == .call) {
            _ = try self.eval(target);
            return self.throwError("ReferenceError", "invalid assignment target");
        }
        var old_val = try self.eval(target);
        // ToNumeric: an object operand coerces via ToPrimitive(number); a BigInt
        // is incremented/decremented by 1n (not the Number 1), and the result
        // stays a BigInt.
        if (old_val.isObject() and !old_val.asObj().is_bigint and !old_val.asObj().is_symbol)
            old_val = try self.toPrimitive(old_val, .number);
        if (old_val.isObject() and old_val.asObj().is_bigint) {
            const b = old_val.asObj().bigint;
            const updated = try self.makeBigInt(if (inc) b +% 1 else b -% 1);
            try self.assignTo(target, updated);
            return if (prefix) updated else old_val;
        }
        const old = old_val.toNumber();
        const updated = if (inc) old + 1 else old - 1;
        try self.assignTo(target, Value.num(updated));
        return Value.num(if (prefix) updated else old);
    }

    /// Pre-declare every `var`-scoped name in `stmts` as `undefined` (hoisting),
    /// so a forward reference reads `undefined` instead of throwing a
    /// ReferenceError. Recurses through nested control-flow statements but stops
    /// at function boundaries (their vars belong to their own scope); existing
    /// bindings (parameters, hoisted functions, earlier vars) are left untouched.
    pub fn hoistVarNames(self: *Interpreter, stmts: []*Node) EvalError!void {
        for (stmts) |s| try self.hoistVarsIn(s);
    }

    fn hoistVarsIn(self: *Interpreter, node: *Node) EvalError!void {
        switch (node.*) {
            .var_decl => |d| if (d.kind == .@"var") try self.hoistOneVar(d.name),
            .destructure_decl => |d| if (d.kind == .@"var") try self.hoistPatternVars(d.pattern),
            .decl_group => |g| for (g) |gs| try self.hoistVarsIn(gs),
            .export_decl => |e| if (e.declaration) |d| try self.hoistVarsIn(d),
            .block => |b| for (b) |bs| try self.hoistVarsIn(bs),
            .if_stmt => |i| {
                try self.hoistVarsIn(i.consequent);
                if (i.alternate) |alt| try self.hoistVarsIn(alt);
            },
            .while_stmt => |w| try self.hoistVarsIn(w.body),
            .do_while_stmt => |w| try self.hoistVarsIn(w.body),
            .with_stmt => |w| try self.hoistVarsIn(w.body),
            .for_stmt => |f| {
                if (f.init) |ini| try self.hoistVarsIn(ini);
                try self.hoistVarsIn(f.body);
            },
            .for_in => |f| {
                if (f.decl_kind) |k| if (k == .@"var") try self.hoistPatternVars(f.target);
                try self.hoistVarsIn(f.body);
            },
            .try_stmt => |t| {
                try self.hoistVarsIn(t.block);
                if (t.catch_block) |c| try self.hoistVarsIn(c);
                if (t.finally_block) |fb| try self.hoistVarsIn(fb);
            },
            .switch_stmt => |sw| for (sw.cases) |c| for (c.body) |cs| try self.hoistVarsIn(cs),
            .labeled_stmt => |l| try self.hoistVarsIn(l.body),
            else => {}, // function decls/exprs and expressions hoist nothing here
        }
    }

    fn hoistOneVar(self: *Interpreter, name: []const u8) EvalError!void {
        try self.createVarBinding(name);
    }

    fn hoistPatternVars(self: *Interpreter, pat: *Node) EvalError!void {
        switch (pat.*) {
            .identifier => |name| try self.hoistOneVar(name),
            else => {}, // destructuring patterns bind on execution (rare to forward-ref)
        }
    }

    // ---- Annex B B.3.3 block-level function legacy-binding analysis -----------

    const NameStack = std.ArrayListUnmanaged([]const u8);

    fn annexbStackHas(stack: NameStack, name: []const u8) bool {
        for (stack.items) |n| if (eq(n, name)) return true;
        return false;
    }

    fn appendPatternNames(arena: std.mem.Allocator, pat: *Node, list: *NameStack) EvalError!void {
        switch (pat.*) {
            .identifier => |nm| try list.append(arena, nm),
            .obj_pattern => |p| {
                for (p.props) |pr| try appendPatternNames(arena, pr.target, list);
                if (p.rest) |r| if (r.* == .identifier) try list.append(arena, r.identifier);
            },
            .arr_pattern => |p| {
                for (p.elems) |e| if (e.target) |t| try appendPatternNames(arena, t, list);
                if (p.rest) |r| try appendPatternNames(arena, r, list);
            },
            else => {},
        }
    }

    /// Bound names of a parameter list (used to exclude parameter-shadowing
    /// function names from the Annex B legacy var binding).
    fn collectParamNames(arena: std.mem.Allocator, params: []const ast.Param) EvalError![]const []const u8 {
        var list: NameStack = .empty;
        for (params) |p| {
            if (p.pattern) |pat| {
                try appendPatternNames(arena, pat, &list);
            } else if (p.name.len > 0) try list.append(arena, p.name);
        }
        return list.items;
    }

    /// Push the lexically-declared (let/const/class) names of one statement.
    fn annexbPushLexical(self: *Interpreter, s: *Node, stack: *NameStack) EvalError!void {
        switch (s.*) {
            .var_decl => |d| if (d.kind != .@"var") try stack.append(self.arena, d.name),
            .decl_group => |g| for (g) |gs| {
                if (gs.* == .var_decl and gs.var_decl.kind != .@"var") try stack.append(self.arena, gs.var_decl.name);
            },
            .destructure_decl => |d| if (d.kind != .@"var") try appendPatternNames(self.arena, d.pattern, stack),
            .class_expr => |c| if (c.name.len > 0) try stack.append(self.arena, c.name),
            // An async/generator/async-generator function declaration is an
            // ordinary lexical (block-scoped) binding, never an Annex B B.3.3
            // legacy candidate — so it shadows like let/const/class. (A *plain*
            // function declaration is handled by the candidate loops below.)
            .func_decl => |f| if (f.is_generator or f.is_async) try stack.append(self.arena, f.name),
            else => {},
        }
    }

    /// Entry point: collect the eligible legacy-binding function names of a
    /// variable scope's statement list. `stack` is seeded with parameter names
    /// and "arguments" (both block the legacy binding).
    fn annexbAddCandidate(self: *Interpreter, node: *const Node, name: []const u8, out: *std.StringHashMapUnmanaged(void), nodes: *std.AutoHashMapUnmanaged(*const Node, void)) EvalError!void {
        try out.put(self.arena, name, {});
        try nodes.put(self.arena, node, {});
    }

    fn collectAnnexBLegacy(self: *Interpreter, stmts: []*Node, depth: u32, out: *std.StringHashMapUnmanaged(void), nodes: *std.AutoHashMapUnmanaged(*const Node, void)) EvalError!void {
        var stack: NameStack = .empty;
        if (!self.eval_decl_deletable)
            for (self.cur_params) |pn| try stack.append(self.arena, pn);
        try stack.append(self.arena, "arguments");
        try self.annexbScanList(stmts, &stack, depth, out, nodes);
    }

    fn annexbScanList(self: *Interpreter, stmts: []*Node, stack: *NameStack, depth: u32, out: *std.StringHashMapUnmanaged(void), nodes: *std.AutoHashMapUnmanaged(*const Node, void)) EvalError!void {
        const base = stack.items.len;
        // This block's own let/const/class names shadow the legacy binding.
        for (stmts) |s| try self.annexbPushLexical(s, stack);
        // A function declaration directly in a nested block (depth >= 1) is a
        // legacy-binding candidate unless its name is already lexically bound.
        // A *block*-level function declaration is itself block-lexical, so it
        // blocks a deeper same-named declaration's legacy binding (replacing it
        // with `var F` would early-error) — but a *top-level* (var-scoped)
        // function declaration does not block, hence the depth >= 1 gate.
        if (depth >= 1) {
            for (stmts) |s| switch (s.*) {
                .func_decl => |f| if (!f.is_generator and !f.is_async and !annexbStackHas(stack.*, f.name)) try self.annexbAddCandidate(s, f.name, out, nodes),
                else => {},
            };
            for (stmts) |s| switch (s.*) {
                .func_decl => |f| if (!f.is_generator and !f.is_async) try stack.append(self.arena, f.name),
                else => {},
            };
        }
        for (stmts) |s| try self.annexbScanStmt(s, stack, depth, out, nodes);
        stack.shrinkRetainingCapacity(base);
    }

    /// Scan a single statement that is the *body* of an if/loop/label — a block,
    /// a bare function declaration (treated as a one-statement block), or other.
    fn annexbScanBranch(self: *Interpreter, node: *Node, stack: *NameStack, depth: u32, out: *std.StringHashMapUnmanaged(void), nodes: *std.AutoHashMapUnmanaged(*const Node, void)) EvalError!void {
        switch (node.*) {
            .block => |b| try self.annexbScanList(b, stack, depth + 1, out, nodes),
            .func_decl => |f| if (!f.is_generator and !f.is_async and !annexbStackHas(stack.*, f.name)) try self.annexbAddCandidate(node, f.name, out, nodes),
            else => try self.annexbScanStmt(node, stack, depth, out, nodes),
        }
    }

    fn annexbScanStmt(self: *Interpreter, s: *Node, stack: *NameStack, depth: u32, out: *std.StringHashMapUnmanaged(void), nodes: *std.AutoHashMapUnmanaged(*const Node, void)) EvalError!void {
        switch (s.*) {
            .block => |b| try self.annexbScanList(b, stack, depth + 1, out, nodes),
            .if_stmt => |i| {
                try self.annexbScanBranch(i.consequent, stack, depth, out, nodes);
                if (i.alternate) |a| try self.annexbScanBranch(a, stack, depth, out, nodes);
            },
            .while_stmt => |w| try self.annexbScanBranch(w.body, stack, depth, out, nodes),
            .do_while_stmt => |w| try self.annexbScanBranch(w.body, stack, depth, out, nodes),
            .for_stmt => |f| {
                const base = stack.items.len;
                if (f.init) |ini| try self.annexbPushLexical(ini, stack);
                try self.annexbScanBranch(f.body, stack, depth, out, nodes);
                stack.shrinkRetainingCapacity(base);
            },
            .for_in => |f| {
                const base = stack.items.len;
                if (f.decl_kind) |k| if (k != .@"var") try appendPatternNames(self.arena, f.target, stack);
                try self.annexbScanBranch(f.body, stack, depth, out, nodes);
                stack.shrinkRetainingCapacity(base);
            },
            .labeled_stmt => |l| try self.annexbScanStmt(l.body, stack, depth, out, nodes),
            .switch_stmt => |sw| {
                const base = stack.items.len;
                // The whole switch is one lexical (CaseBlock) scope across all cases.
                for (sw.cases) |c| for (c.body) |cs| try self.annexbPushLexical(cs, stack);
                for (sw.cases) |c| for (c.body) |cs| switch (cs.*) {
                    .func_decl => |fd| if (!fd.is_generator and !fd.is_async and !annexbStackHas(stack.*, fd.name)) try self.annexbAddCandidate(cs, fd.name, out, nodes),
                    else => {},
                };
                for (sw.cases) |c| for (c.body) |cs| switch (cs.*) {
                    .func_decl => |fd| if (!fd.is_generator and !fd.is_async) try stack.append(self.arena, fd.name),
                    else => {},
                };
                for (sw.cases) |c| for (c.body) |cs| try self.annexbScanStmt(cs, stack, depth + 1, out, nodes);
                stack.shrinkRetainingCapacity(base);
            },
            .try_stmt => |t| {
                try self.annexbScanBranch(t.block, stack, depth, out, nodes);
                if (t.catch_block) |cb| {
                    const cbase = stack.items.len;
                    // A *simple* (identifier) catch parameter does not block the
                    // legacy binding (Annex B B.3.5 allows `catch(e){var e}`); a
                    // destructuring catch parameter does.
                    if (t.catch_param) |cp| if (cp.* != .identifier) try appendPatternNames(self.arena, cp, stack);
                    try self.annexbScanBranch(cb, stack, depth, out, nodes);
                    stack.shrinkRetainingCapacity(cbase);
                }
                if (t.finally_block) |fb| try self.annexbScanBranch(fb, stack, depth, out, nodes);
            },
            else => {},
        }
    }

    pub fn evalStatements(self: *Interpreter, stmts: []*Node) EvalError!Value {
        // A function-declaration directly in the variable scope (function body /
        // script / eval top level) is var-scoped; one inside a nested block is
        // block-scoped, with an additional legacy var binding under Annex B B.3.3.
        const at_fn_top = self.env.fn_body or self.env == self.env.varScope();
        // Annex B B.3.3: at the variable scope, work out which block-nested
        // function names get a legacy var binding, and pre-create those bindings
        // as `undefined`. Sloppy code only (strict block functions stay purely
        // block-scoped). The set stays live for nested blocks via `annexb_legacy`.
        var annexb_set: std.StringHashMapUnmanaged(void) = .empty;
        var annexb_nodes: std.AutoHashMapUnmanaged(*const Node, void) = .empty;
        const saved_annexb = self.annexb_legacy;
        const saved_annexb_nodes = self.annexb_legacy_nodes;
        defer self.annexb_legacy = saved_annexb;
        defer self.annexb_legacy_nodes = saved_annexb_nodes;
        if (at_fn_top and !self.strict) {
            try self.collectAnnexBLegacy(stmts, 0, &annexb_set, &annexb_nodes);
            self.annexb_legacy = &annexb_set;
            self.annexb_legacy_nodes = &annexb_nodes;
            const vs = self.env.varScope();
            var it = annexb_set.keyIterator();
            while (it.next()) |k| {
                if (!vs.vars.contains(k.*)) try self.createVarBinding(k.*);
            }
        }
        // Hoist function declarations to the top of the scope so forward
        // references work (`bar(); function bar() {}`). Each is bound exactly
        // once here; the main loop then skips them, preserving function identity
        // (`var g = bar; function bar() {}` ⇒ `g === bar`).
        for (stmts) |s| switch (s.*) {
            .func_decl => |fnode| {
                const fnv = try self.makeFunction(fnode, self.env);
                if (at_fn_top) {
                    try self.globalDefineFunc(fnode.name, fnv);
                } else {
                    // Block-scoped function declaration: bind in this block...
                    try self.env.put(fnode.name, fnv);
                    // ...and (Annex B) copy to the var scope when eligible.
                    if (self.annexb_legacy_nodes) |set| {
                        if (set.contains(s)) try self.globalDefineDeletable(fnode.name, fnv);
                    }
                }
            },
            // `export function f(){}` / direct `export default function f(){}`
            // hoist just like bare function declarations. Parenthesized
            // `export default (function(){})` is an expression and must wait for
            // source-order evaluation.
            .export_decl => |e| {
                if (e.declaration) |d| {
                    if (d.* == .func_decl) try self.globalDefine(d.func_decl.name, try self.makeFunction(d.func_decl, self.env));
                } else if (e.default_expr) |dx| {
                    const fv: ?Value = switch (dx.*) {
                        .function => |f| if (f.is_default_export_decl) try self.makeFunction(f, self.env) else null,
                        else => null,
                    };
                    if (fv) |v| {
                        if (e.default_name.len > 0) try self.globalDefine(e.default_name, v) else try self.maybeNameAnon(v, dx, "default");
                        try self.env.put("*default*", v);
                    }
                }
            },
            else => {},
        };
        // `var` hoisting: once per function/script var-scope, pre-declare every
        // `var` name (in nested control-flow too) as `undefined`. Runs after the
        // function-declaration hoist above (declare-if-absent, so it never
        // clobbers a hoisted function or parameter).
        if (self.env == self.env.varScope()) try self.hoistVarNames(stmts);
        for (stmts) |s| switch (s.*) {
            .var_decl => |d| if (d.kind != .@"var") try self.checkRestrictedGlobalLexical(d.name),
            .decl_group => |group| for (group) |gs| switch (gs.*) {
                .var_decl => |d| if (d.kind != .@"var") try self.checkRestrictedGlobalLexical(d.name),
                else => {},
            },
            .destructure_decl => |d| if (d.kind != .@"var") try self.checkRestrictedGlobalLexicalPattern(d.pattern),
            .class_expr => |c| if (c.name.len > 0) try self.checkRestrictedGlobalLexical(c.name),
            else => {},
        };
        // Temporal dead zone: `let`/`const` (and `class`) declarations are
        // hoisted into this scope as uninitialized bindings; reading one before
        // its declaration runs throws a ReferenceError.
        if (self.tdz_marker) |_| {
            const tdz = self.tdzVal();
            for (stmts) |s| switch (s.*) {
                .var_decl => |d| if (d.kind != .@"var") try self.env.put(d.name, tdz),
                .decl_group => |group| for (group) |gs| switch (gs.*) {
                    .var_decl => |d| if (d.kind != .@"var") try self.env.put(d.name, tdz),
                    else => {},
                },
                .destructure_decl => |d| if (d.kind != .@"var") self.tdzBindPattern(d.pattern, tdz),
                .class_expr => |c| if (c.name.len > 0) try self.env.put(c.name, tdz),
                else => {},
            };
        }
        var last: Value = Value.undef();
        var seen_value = false; // any non-empty completion accumulated yet
        for (stmts) |s| {
            if (s.* == .func_decl) continue; // already hoisted above
            // An exported function declaration was hoisted above too (preserving
            // its identity); skip it so it isn't rebuilt with a fresh identity.
            if (s.* == .export_decl) {
                const e = s.export_decl;
                if (e.declaration) |d| {
                    if (d.* == .func_decl) continue;
                } else if (e.default_expr) |dx| {
                    if (dx.* == .function and dx.function.is_default_export_decl) continue;
                }
            }
            const r = try self.eval(s);
            // An abrupt completion (break/continue/return) unwinds to the caller.
            // UpdateEmpty: a raw break/continue carries an EMPTY value, so the
            // list's accumulated value (`last`) flows through; anything else
            // (return, or a compound statement that already folded its nested
            // value) carries its own value.
            if (self.signal != .none) {
                if (!abruptCompletionEmpty(s)) last = r;
                return last;
            }
            // UpdateEmpty: a declaration / empty statement / empty block does not
            // replace the statement list's value.
            if (!self.stmtCompletionEmpty(s)) {
                last = r;
                seen_value = true;
            }
        }
        self.completion_empty = !seen_value;
        return last;
    }

    /// Whether statement `s` produces an EMPTY completion (so it doesn't update
    /// the enclosing list's completion value). Declarations and empty statements
    /// are empty; a `{ … }` block defers to the brand its own list set.
    /// Whether an ABRUPT completion produced by `s` carries an EMPTY value (so
    /// UpdateEmpty lets the enclosing list's accumulated value flow through). A
    /// raw `break`/`continue` has an empty completion value; `return` carries its
    /// argument, and a compound statement already folded its own nested value in.
    fn abruptCompletionEmpty(s: *Node) bool {
        return switch (s.*) {
            .break_stmt, .continue_stmt => true,
            else => false,
        };
    }

    fn stmtCompletionEmpty(self: *Interpreter, s: *Node) bool {
        return switch (s.*) {
            .var_decl, .decl_group, .destructure_decl => true,
            .class_expr => true, // a class *declaration* statement
            .block => self.completion_empty,
            else => false,
        };
    }

    fn makeFunction(self: *Interpreter, fnode: *const ast.FunctionNode, closure: *Environment) EvalError!Value {
        const func = try gc_mod.allocFunction(self.arena);
        func.* = .{
            .params = fnode.params,
            .body = fnode.body,
            .is_expr_body = fnode.is_expr_body,
            .is_arrow = fnode.is_arrow,
            .closure = closure,
            .name = fnode.name,
            .source = fnode.source,
            .is_generator = fnode.is_generator,
            .is_async = fnode.is_async,
            .is_strict = fnode.is_strict,
            .is_method = fnode.is_method,
            .import_meta_slot = self.import_meta_slot,
        };
        // A `with` block's object Environment Record is part of the lexical chain
        // (`Environment.with_object`), so a function defined inside a `with`
        // captures it automatically through its `closure` — no separate capture.
        // Arrows capture `super` (home object + super constructor) lexically from
        // the enclosing method, just as they capture `this`/`new.target`. A
        // non-arrow gets its home object later (e.g. when installed as a method).
        if (fnode.is_arrow) {
            func.home_object = self.home_object;
            func.super_ctor = self.super_ctor;
            func.arrow_this = self.this_value; // captured lexically; used on every call
            func.arrow_new_target = self.new_target; // new.target is lexical for arrows too
            func.arrow_in_derived_ctor = self.in_derived_ctor; // super()-legality is lexical
            func.this_cell = self.this_cell; // share the enclosing derived ctor's `this` binding
            func.field_init_ctx = self.in_field_initializer; // field-init eval restrictions are lexical
        }
        // Compile a generator body up front for the suspendable VM. Bodies
        // outside the VM's lowered subset leave `gen_chunk` null, so calling the
        // generator throws a clear TypeError rather than running incorrectly.
        if (fnode.is_generator) {
            func.gen_chunk = Compiler.compileGenerator(self.arena, fnode) catch |e| switch (e) {
                error.Unsupported => null,
                error.OutOfMemory => return error.OutOfMemory,
            };
        } else if (fnode.is_async) {
            // A plain async function compiles to a suspendable body (await is a
            // suspend point); null on unsupported syntax → tree-walk fallback.
            func.async_chunk = Compiler.compileAsync(self.arena, fnode) catch |e| switch (e) {
                error.Unsupported => null,
                error.OutOfMemory => return error.OutOfMemory,
            };
        }
        // A function object's [[Prototype]] is the kind-specific function
        // prototype intrinsic: %GeneratorFunction.prototype% for `function*`,
        // %AsyncFunction.prototype% for `async function`,
        // %AsyncGeneratorFunction.prototype% for `async function*`, else
        // %Function.prototype%. So `Object.getPrototypeOf(function*(){}).
        // constructor === GeneratorFunction`, etc.
        const fproto: ?*value.Object = blk: {
            const tag: ?[]const u8 = if (fnode.is_generator and fnode.is_async)
                "\x00AsyncGenFuncProto"
            else if (fnode.is_generator)
                "\x00GenFuncProto"
            else if (fnode.is_async)
                "\x00AsyncFuncProto"
            else
                null;
            if (tag) |t| if (self.env.get(t)) |v| if (v.isObject()) break :blk v.asObj();
            break :blk self.functionProto();
        };
        const obj = try gc_mod.allocObj(self.arena);
        obj.* = .{ .js_func = @ptrCast(func), .proto = fproto };
        func.obj = obj;
        try installFunctionProps(self.arena, self.root_shape, obj, fnode.params, func.name);
        return Value.obj(obj);
    }

    pub fn funcOf(v: Value) ?*Function {
        if (v.isObject()) {
            if (v.asObj().js_func) |e| return @ptrCast(@alignCast(e));
        }
        return null;
    }

    pub fn jsFunctionHasOwnPrototypeSlot(o: *value.Object) bool {
        const erased = o.js_func orelse return false;
        const f: *Function = @ptrCast(@alignCast(erased));
        // Ordinary functions expose a constructor `.prototype`. Generator and
        // async-generator functions, including concise methods, expose one for
        // the yielded iterator prototype. Arrows, non-generator concise methods,
        // accessors, and plain async functions do not.
        return !f.is_arrow and (f.is_generator or (!f.is_method and !f.is_async));
    }

    /// `Function.prototype.toString`. A user function returns its exact captured
    /// source; a native, bound, or not-yet-captured function returns the spec's
    /// NativeFunction syntax `function NAME() { [native code] }`.
    fn functionToString(self: *Interpreter, o: *value.Object) EvalError!Value {
        if (funcOf(Value.obj(o))) |func| {
            if (func.source.len > 0) return Value.str(func.source);
        }
        const raw_name: []const u8 = if (o.getOwn("name")) |n| (if (n.isString()) n.asStr() else "") else "";
        const nm: []const u8 = if (raw_name.len > 0 and raw_name[0] == 0) "" else raw_name;
        return Value.str(try std.mem.concat(self.arena, u8, &.{ "function ", nm, "() { [native code] }" }));
    }

    /// True if `node` is an *anonymous* function/class definition — the
    /// syntactic predicate `IsAnonymousFunctionDefinition` that drives
    /// NamedEvaluation (`var f = function(){}` ⇒ `f.name === "f"`).
    fn isAnonFnDef(node: *Node) bool {
        return switch (node.*) {
            .function => |f| f.name.len == 0,
            // `export default function(){}` parses the body as a `func_decl`; an
            // anonymous one is named "default" by NamedEvaluation.
            .func_decl => |f| f.name.len == 0,
            .class_expr => |c| c.name.len == 0,
            else => false,
        };
    }

    /// NamedEvaluation: when an anonymous function/class produced by `init_node`
    /// is bound to the name `name` (a declaration, assignment, property, or
    /// destructuring default), give the still-unnamed function that name. The
    /// `name` own property is { writable:false, enumerable:false,
    /// configurable:true }, like every function name.
    /// Name an accessor function `"get name"` / `"set name"` (a non-writable,
    /// non-enumerable, configurable own `name` property), overriding the
    /// parser-assigned bare name.
    fn nameAccessor(self: *Interpreter, fnv: Value, prefix: []const u8, name_str: []const u8) EvalError!void {
        if (!fnv.isObject() or !fnv.asObj().isCallableObject()) return;
        const nm = try std.fmt.allocPrint(self.arena, "{s} {s}", .{ prefix, name_str });
        try fnv.asObj().setOwn(self.arena, self.root_shape, "name", Value.str(nm));
        try fnv.asObj().setAttr(self.arena, "name", .{ .writable = false, .enumerable = false, .configurable = true });
        if (funcOf(fnv)) |f| f.name = nm;
    }

    /// The function-name string a property key contributes (PropertyName's name):
    /// a string key as-is, a symbol as `[description]` (or `""` when undescribed),
    /// else ToString. Used to name concise methods/accessors from their key.
    fn keyDisplayName(self: *Interpreter, kv: Value) EvalError![]const u8 {
        if (kv.isObject() and kv.asObj().is_symbol)
            return if (kv.asObj().sym_desc) |d| try std.fmt.allocPrint(self.arena, "[{s}]", .{d}) else "";
        if (kv.isString()) return kv.asStr();
        return self.toStringV(kv);
    }

    fn maybeNameAnon(self: *Interpreter, val: Value, init_node: *Node, name: []const u8) EvalError!void {
        if (name.len == 0) return;
        if (!isAnonFnDef(init_node)) return;
        if (!val.isObject() or !val.asObj().isCallableObject()) return;
        const o = val.asObj();
        if (o.getOwn("name")) |c| {
            // Already has a meaningful own `name`: a non-empty string, or — for a
            // class with an explicit `static name(){}`/field — a non-string value.
            // Only an empty-string placeholder (a freshly-built anonymous class)
            // is overridable.
            if (!c.isString() or c.asStr().len != 0) return;
        }
        try o.setOwn(self.arena, self.root_shape, "name", Value.str(name));
        try o.setAttr(self.arena, "name", .{ .writable = false, .enumerable = false, .configurable = true });
        if (funcOf(val)) |f| f.name = name; // keep Function.name in sync
    }

    fn nextPrivateStorageKey(self: *Interpreter, name: []const u8) ![]const u8 {
        const id = if (self.private_name_serial) |serial| blk: {
            const n = serial.*;
            serial.* += 1;
            break :blk n;
        } else blk: {
            const n = self.private_name_serial_local;
            self.private_name_serial_local += 1;
            break :blk n;
        };
        return std.fmt.allocPrint(self.arena, "{s}\x00{d}", .{ name, id });
    }

    fn remapPrivateName(map: *std.StringHashMapUnmanaged([]const u8), name: []const u8) []const u8 {
        if (!value.isRawPrivateName(name)) return name;
        return map.get(name) orelse name;
    }

    fn rewritePrivateNamesInFunction(self: *Interpreter, f: *ast.FunctionNode, map: *std.StringHashMapUnmanaged([]const u8)) EvalError!void {
        for (f.params) |p| {
            if (p.default) |d| try self.rewritePrivateNamesInNode(d, map);
            if (p.pattern) |pat| try self.rewritePrivateNamesInNode(pat, map);
        }
        try self.rewritePrivateNamesInNode(f.body, map);
    }

    fn rewritePrivateNamesInNode(self: *Interpreter, node: *Node, map: *std.StringHashMapUnmanaged([]const u8)) EvalError!void {
        switch (node.*) {
            .identifier => |name| node.* = .{ .identifier = remapPrivateName(map, name) },
            .unary => |u| try self.rewritePrivateNamesInNode(u.operand, map),
            .delete_expr => |n| try self.rewritePrivateNamesInNode(n, map),
            .update => |u| try self.rewritePrivateNamesInNode(u.target, map),
            .binary => |b| {
                try self.rewritePrivateNamesInNode(b.left, map);
                try self.rewritePrivateNamesInNode(b.right, map);
            },
            .logical => |l| {
                try self.rewritePrivateNamesInNode(l.left, map);
                try self.rewritePrivateNamesInNode(l.right, map);
            },
            .sequence => |s| {
                try self.rewritePrivateNamesInNode(s.first, map);
                try self.rewritePrivateNamesInNode(s.second, map);
            },
            .assign => |a| {
                try self.rewritePrivateNamesInNode(a.target, map);
                try self.rewritePrivateNamesInNode(a.value, map);
            },
            .op_assign => |oa| {
                try self.rewritePrivateNamesInNode(oa.target, map);
                try self.rewritePrivateNamesInNode(oa.value, map);
            },
            .logical_assign => |la| {
                try self.rewritePrivateNamesInNode(la.target, map);
                try self.rewritePrivateNamesInNode(la.value, map);
            },
            .conditional => |c| {
                try self.rewritePrivateNamesInNode(c.cond, map);
                try self.rewritePrivateNamesInNode(c.consequent, map);
                try self.rewritePrivateNamesInNode(c.alternate, map);
            },
            .function => |f| try self.rewritePrivateNamesInFunction(f, map),
            .yield_expr => |y| if (y.argument) |a| try self.rewritePrivateNamesInNode(a, map),
            .await_expr => |a| try self.rewritePrivateNamesInNode(a.argument, map),
            .class_expr => |c| {
                if (c.superclass) |sc| try self.rewritePrivateNamesInNode(sc, map);
                var nested_map: std.StringHashMapUnmanaged([]const u8) = .empty;
                defer nested_map.deinit(self.arena);
                var it = map.iterator();
                while (it.next()) |entry| try nested_map.put(self.arena, entry.key_ptr.*, entry.value_ptr.*);
                for (c.members) |m| {
                    if (m.key_expr == null and value.isRawPrivateName(m.key)) _ = nested_map.remove(m.key);
                }
                for (c.members) |m| {
                    if (m.key_expr) |key_expr| try self.rewritePrivateNamesInNode(key_expr, map);
                    if (m.field_init) |init| try self.rewritePrivateNamesInNode(init, &nested_map);
                    if (m.func) |func| try self.rewritePrivateNamesInNode(func, &nested_map);
                    if (m.static_block) |block| try self.rewritePrivateNamesInNode(block, &nested_map);
                }
            },
            .super_call => |args| for (args) |arg_node| try self.rewritePrivateNamesInNode(arg_node, map),
            .super_member => |sm| {
                if (sm.computed) |c| {
                    try self.rewritePrivateNamesInNode(c, map);
                } else {
                    node.* = .{ .super_member = .{ .property = remapPrivateName(map, sm.property), .computed = null } };
                }
            },
            .call => |c| {
                try self.rewritePrivateNamesInNode(c.callee, map);
                for (c.args) |arg_node| try self.rewritePrivateNamesInNode(arg_node, map);
            },
            .new_expr => |n| {
                try self.rewritePrivateNamesInNode(n.callee, map);
                for (n.args) |arg_node| try self.rewritePrivateNamesInNode(arg_node, map);
            },
            .tagged_template => |t| {
                try self.rewritePrivateNamesInNode(t.tag, map);
                for (t.exprs) |expr| try self.rewritePrivateNamesInNode(expr, map);
            },
            .member => |m| {
                try self.rewritePrivateNamesInNode(m.object, map);
                if (m.computed) |c| {
                    try self.rewritePrivateNamesInNode(c, map);
                } else {
                    node.* = .{ .member = .{ .object = m.object, .property = remapPrivateName(map, m.property), .computed = null, .optional = m.optional } };
                }
            },
            .optional_chain => |n| try self.rewritePrivateNamesInNode(n, map),
            .field_init_value => |n| try self.rewritePrivateNamesInNode(n, map),
            .private_field_def => |d| try self.rewritePrivateNamesInNode(d.value, map),
            .object_lit => |props| for (props) |p| {
                if (p.key_expr) |ke| try self.rewritePrivateNamesInNode(ke, map);
                try self.rewritePrivateNamesInNode(p.value, map);
            },
            .array_lit => |items| for (items) |item| try self.rewritePrivateNamesInNode(item, map),
            .spread => |n| try self.rewritePrivateNamesInNode(n, map),
            .obj_pattern => |pat| {
                for (pat.props) |p| {
                    if (p.key_expr) |ke| try self.rewritePrivateNamesInNode(ke, map);
                    try self.rewritePrivateNamesInNode(p.target, map);
                    if (p.default) |d| try self.rewritePrivateNamesInNode(d, map);
                }
                // `({...this.#x} = …)`: the rest target may reference a private name.
                if (pat.rest) |r| try self.rewritePrivateNamesInNode(r, map);
            },
            .arr_pattern => |pat| {
                for (pat.elems) |el| {
                    if (el.target) |t| try self.rewritePrivateNamesInNode(t, map);
                    if (el.default) |d| try self.rewritePrivateNamesInNode(d, map);
                }
                if (pat.rest) |r| try self.rewritePrivateNamesInNode(r, map);
            },
            .var_decl => |vd| if (vd.init) |init| try self.rewritePrivateNamesInNode(init, map),
            .destructure_decl => |dd| {
                try self.rewritePrivateNamesInNode(dd.pattern, map);
                try self.rewritePrivateNamesInNode(dd.init, map);
            },
            .func_decl => |f| try self.rewritePrivateNamesInFunction(f, map),
            .return_stmt => |maybe| if (maybe) |r| try self.rewritePrivateNamesInNode(r, map),
            .throw_stmt => |n| try self.rewritePrivateNamesInNode(n, map),
            .try_stmt => |t| {
                try self.rewritePrivateNamesInNode(t.block, map);
                if (t.catch_param) |p| try self.rewritePrivateNamesInNode(p, map);
                if (t.catch_block) |b| try self.rewritePrivateNamesInNode(b, map);
                if (t.finally_block) |f| try self.rewritePrivateNamesInNode(f, map);
            },
            .labeled_stmt => |l| try self.rewritePrivateNamesInNode(l.body, map),
            .expr_stmt => |n| try self.rewritePrivateNamesInNode(n, map),
            .block, .decl_group, .program => |stmts| for (stmts) |stmt| try self.rewritePrivateNamesInNode(stmt, map),
            .if_stmt => |i| {
                try self.rewritePrivateNamesInNode(i.cond, map);
                try self.rewritePrivateNamesInNode(i.consequent, map);
                if (i.alternate) |a| try self.rewritePrivateNamesInNode(a, map);
            },
            .while_stmt => |w| {
                try self.rewritePrivateNamesInNode(w.cond, map);
                try self.rewritePrivateNamesInNode(w.body, map);
            },
            .do_while_stmt => |d| {
                try self.rewritePrivateNamesInNode(d.body, map);
                try self.rewritePrivateNamesInNode(d.cond, map);
            },
            .for_stmt => |f| {
                if (f.init) |n| try self.rewritePrivateNamesInNode(n, map);
                if (f.cond) |n| try self.rewritePrivateNamesInNode(n, map);
                if (f.update) |n| try self.rewritePrivateNamesInNode(n, map);
                try self.rewritePrivateNamesInNode(f.body, map);
            },
            .for_in => |f| {
                try self.rewritePrivateNamesInNode(f.target, map);
                if (f.var_init) |ini| try self.rewritePrivateNamesInNode(ini, map);
                try self.rewritePrivateNamesInNode(f.iterable, map);
                try self.rewritePrivateNamesInNode(f.body, map);
            },
            .switch_stmt => |s| {
                try self.rewritePrivateNamesInNode(s.disc, map);
                for (s.cases) |case| {
                    if (case.@"test") |t| try self.rewritePrivateNamesInNode(t, map);
                    for (case.body) |stmt| try self.rewritePrivateNamesInNode(stmt, map);
                }
            },
            .with_stmt => |w| {
                try self.rewritePrivateNamesInNode(w.obj, map);
                try self.rewritePrivateNamesInNode(w.body, map);
            },
            .export_decl => |e| {
                if (e.declaration) |d| try self.rewritePrivateNamesInNode(d, map);
            },
            .import_call => |ic| {
                try self.rewritePrivateNamesInNode(ic.specifier, map);
                if (ic.options) |o| try self.rewritePrivateNamesInNode(o, map);
            },
            .number, .bigint_lit, .string, .boolean, .null_lit, .undefined_lit, .elision, .this_expr, .new_target_expr, .regex_literal, .break_stmt, .continue_stmt, .import_decl, .import_meta => {},
        }
    }

    // ---- AST deep copy (for per-evaluation private-name rewriting) -------------
    // A class with private names is rewritten in place (`#x` → a unique storage
    // key). Two evaluations of the SAME class source (`classfactory()`) must get
    // DISTINCT keys, so each evaluation first deep-copies its member ASTs and
    // rewrites the copy — leaving the runtime (which reads the rewritten keys
    // directly, and works for nested classes / async / the VM) unchanged.

    fn deepCopyNodes(self: *Interpreter, nodes: []const *Node) EvalError![]*Node {
        const out = try self.arena.alloc(*Node, nodes.len);
        for (nodes, 0..) |n, i| out[i] = try self.deepCopyNode(n);
        return out;
    }

    fn deepCopyOpt(self: *Interpreter, n: ?*Node) EvalError!?*Node {
        return if (n) |x| try self.deepCopyNode(x) else null;
    }

    fn deepCopyFunction(self: *Interpreter, f: *const ast.FunctionNode) EvalError!*ast.FunctionNode {
        const nf = try self.arena.create(ast.FunctionNode);
        nf.* = f.*; // scalars + flags
        const params = try self.arena.alloc(ast.Param, f.params.len);
        for (f.params, 0..) |p, i| params[i] = .{
            .name = p.name,
            .default = try self.deepCopyOpt(p.default),
            .is_rest = p.is_rest,
            .pattern = try self.deepCopyOpt(p.pattern),
        };
        nf.params = params;
        nf.body = try self.deepCopyNode(f.body);
        return nf;
    }

    fn deepCopyClassMembers(self: *Interpreter, members: []const ast.ClassMember) EvalError![]ast.ClassMember {
        const out = try self.arena.alloc(ast.ClassMember, members.len);
        for (members, 0..) |m, i| {
            out[i] = m; // scalars (key, flags, accessor/auto-accessor)
            out[i].key_expr = try self.deepCopyOpt(m.key_expr);
            out[i].func = try self.deepCopyOpt(m.func);
            out[i].field_init = try self.deepCopyOpt(m.field_init);
            out[i].static_block = try self.deepCopyOpt(m.static_block);
        }
        return out;
    }

    /// Deep-copy an AST subtree (string/number leaves share their immutable
    /// payloads; every node gets a fresh allocation so a later rewrite mutates
    /// only this copy). Exhaustive — the compiler flags any unhandled variant.
    fn deepCopyNode(self: *Interpreter, node: *const Node) EvalError!*Node {
        const n = try self.arena.create(Node);
        n.* = switch (node.*) {
            .number, .bigint_lit, .string, .boolean, .null_lit, .undefined_lit, .elision, .this_expr, .new_target_expr, .regex_literal, .identifier, .break_stmt, .continue_stmt, .import_decl, .import_meta => node.*,
            .unary => |u| .{ .unary = .{ .op = u.op, .operand = try self.deepCopyNode(u.operand) } },
            .delete_expr => |x| .{ .delete_expr = try self.deepCopyNode(x) },
            .update => |u| .{ .update = .{ .inc = u.inc, .prefix = u.prefix, .target = try self.deepCopyNode(u.target) } },
            .binary => |b| .{ .binary = .{ .op = b.op, .left = try self.deepCopyNode(b.left), .right = try self.deepCopyNode(b.right) } },
            .logical => |l| .{ .logical = .{ .op = l.op, .left = try self.deepCopyNode(l.left), .right = try self.deepCopyNode(l.right) } },
            .sequence => |s| .{ .sequence = .{ .first = try self.deepCopyNode(s.first), .second = try self.deepCopyNode(s.second) } },
            .assign => |a| .{ .assign = .{ .target = try self.deepCopyNode(a.target), .value = try self.deepCopyNode(a.value) } },
            .op_assign => |a| .{ .op_assign = .{ .target = try self.deepCopyNode(a.target), .op = a.op, .value = try self.deepCopyNode(a.value) } },
            .logical_assign => |a| .{ .logical_assign = .{ .target = try self.deepCopyNode(a.target), .op = a.op, .value = try self.deepCopyNode(a.value) } },
            .conditional => |c| .{ .conditional = .{ .cond = try self.deepCopyNode(c.cond), .consequent = try self.deepCopyNode(c.consequent), .alternate = try self.deepCopyNode(c.alternate) } },
            .function => |f| .{ .function = try self.deepCopyFunction(f) },
            .yield_expr => |y| .{ .yield_expr = .{ .argument = try self.deepCopyOpt(y.argument), .delegate = y.delegate } },
            .await_expr => |a| .{ .await_expr = .{ .argument = try self.deepCopyNode(a.argument) } },
            .class_expr => |c| .{ .class_expr = .{ .name = c.name, .superclass = try self.deepCopyOpt(c.superclass), .members = try self.deepCopyClassMembers(c.members), .source = c.source } },
            .super_call => |args| .{ .super_call = try self.deepCopyNodes(args) },
            .super_member => |sm| .{ .super_member = .{ .property = sm.property, .computed = try self.deepCopyOpt(sm.computed) } },
            .call => |c| .{ .call = .{ .callee = try self.deepCopyNode(c.callee), .args = try self.deepCopyNodes(c.args), .optional = c.optional } },
            .new_expr => |x| .{ .new_expr = .{ .callee = try self.deepCopyNode(x.callee), .args = try self.deepCopyNodes(x.args) } },
            .tagged_template => |t| .{ .tagged_template = .{ .tag = try self.deepCopyNode(t.tag), .cooked = t.cooked, .raw = t.raw, .exprs = try self.deepCopyNodes(t.exprs) } },
            .member => |m| .{ .member = .{ .object = try self.deepCopyNode(m.object), .property = m.property, .computed = try self.deepCopyOpt(m.computed), .optional = m.optional } },
            .optional_chain => |x| .{ .optional_chain = try self.deepCopyNode(x) },
            .field_init_value => |x| .{ .field_init_value = try self.deepCopyNode(x) },
            .private_field_def => |d| .{ .private_field_def = .{ .name = d.name, .value = try self.deepCopyNode(d.value) } },
            .object_lit => |props| blk: {
                const out = try self.arena.alloc(ast.Property, props.len);
                for (props, 0..) |p, i| out[i] = .{ .key = p.key, .key_expr = try self.deepCopyOpt(p.key_expr), .value = try self.deepCopyNode(p.value), .accessor = p.accessor, .is_spread = p.is_spread, .proto_setter = p.proto_setter };
                break :blk .{ .object_lit = out };
            },
            .array_lit => |items| .{ .array_lit = try self.deepCopyNodes(items) },
            .spread => |x| .{ .spread = try self.deepCopyNode(x) },
            .obj_pattern => |pat| blk: {
                const props = try self.arena.alloc(ast.ObjPatProp, pat.props.len);
                for (pat.props, 0..) |p, i| props[i] = .{ .key = p.key, .key_expr = try self.deepCopyOpt(p.key_expr), .target = try self.deepCopyNode(p.target), .default = try self.deepCopyOpt(p.default) };
                break :blk .{ .obj_pattern = .{ .props = props, .rest = try self.deepCopyOpt(pat.rest) } };
            },
            .arr_pattern => |pat| blk: {
                const elems = try self.arena.alloc(ast.ArrPatElem, pat.elems.len);
                for (pat.elems, 0..) |el, i| elems[i] = .{ .target = try self.deepCopyOpt(el.target), .default = try self.deepCopyOpt(el.default) };
                break :blk .{ .arr_pattern = .{ .elems = elems, .rest = try self.deepCopyOpt(pat.rest) } };
            },
            .var_decl => |vd| .{ .var_decl = .{ .kind = vd.kind, .name = vd.name, .init = try self.deepCopyOpt(vd.init), .dispose = vd.dispose } },
            .destructure_decl => |dd| .{ .destructure_decl = .{ .kind = dd.kind, .pattern = try self.deepCopyNode(dd.pattern), .init = try self.deepCopyNode(dd.init) } },
            .func_decl => |f| .{ .func_decl = try self.deepCopyFunction(f) },
            .return_stmt => |x| .{ .return_stmt = try self.deepCopyOpt(x) },
            .throw_stmt => |x| .{ .throw_stmt = try self.deepCopyNode(x) },
            .try_stmt => |t| blk: {
                const nt = try self.arena.create(ast.TryNode);
                nt.* = .{ .block = try self.deepCopyNode(t.block), .catch_param = try self.deepCopyOpt(t.catch_param), .catch_block = try self.deepCopyOpt(t.catch_block), .finally_block = try self.deepCopyOpt(t.finally_block) };
                break :blk .{ .try_stmt = nt };
            },
            .labeled_stmt => |l| .{ .labeled_stmt = .{ .label = l.label, .body = try self.deepCopyNode(l.body) } },
            .expr_stmt => |x| .{ .expr_stmt = try self.deepCopyNode(x) },
            .block => |stmts| .{ .block = try self.deepCopyNodes(stmts) },
            .decl_group => |stmts| .{ .decl_group = try self.deepCopyNodes(stmts) },
            .if_stmt => |i| .{ .if_stmt = .{ .cond = try self.deepCopyNode(i.cond), .consequent = try self.deepCopyNode(i.consequent), .alternate = try self.deepCopyOpt(i.alternate) } },
            .while_stmt => |w| .{ .while_stmt = .{ .cond = try self.deepCopyNode(w.cond), .body = try self.deepCopyNode(w.body) } },
            .do_while_stmt => |d| .{ .do_while_stmt = .{ .body = try self.deepCopyNode(d.body), .cond = try self.deepCopyNode(d.cond) } },
            .for_stmt => |f| .{ .for_stmt = .{ .init = try self.deepCopyOpt(f.init), .cond = try self.deepCopyOpt(f.cond), .update = try self.deepCopyOpt(f.update), .body = try self.deepCopyNode(f.body) } },
            .for_in => |f| .{ .for_in = .{ .decl_kind = f.decl_kind, .target = try self.deepCopyNode(f.target), .var_init = try self.deepCopyOpt(f.var_init), .iterable = try self.deepCopyNode(f.iterable), .body = try self.deepCopyNode(f.body), .is_of = f.is_of, .is_await = f.is_await, .dispose = f.dispose } },
            .switch_stmt => |s| blk: {
                const cases = try self.arena.alloc(ast.SwitchCase, s.cases.len);
                for (s.cases, 0..) |c, i| cases[i] = .{ .@"test" = try self.deepCopyOpt(c.@"test"), .body = try self.deepCopyNodes(c.body) };
                break :blk .{ .switch_stmt = .{ .disc = try self.deepCopyNode(s.disc), .cases = cases } };
            },
            .with_stmt => |w| .{ .with_stmt = .{ .obj = try self.deepCopyNode(w.obj), .body = try self.deepCopyNode(w.body) } },
            .export_decl => node.*, // exports never appear inside a class body
            .import_call => |ic| .{ .import_call = .{ .specifier = try self.deepCopyNode(ic.specifier), .options = try self.deepCopyOpt(ic.options), .phase = ic.phase } },
            .program => |stmts| .{ .program = try self.deepCopyNodes(stmts) },
        };
        return n;
    }

    /// Rewrite this class's private names (`#x` → a unique storage key) in member
    /// keys and bodies, and return the raw→storage map (persisted in the arena) so
    /// the class's functions can resolve private names a direct eval references.
    /// Returns null when the class declares no private names.
    fn rewriteClassPrivateNames(self: *Interpreter, members: []ast.ClassMember) EvalError!?*const std.StringHashMapUnmanaged([]const u8) {
        const map = try self.arena.create(std.StringHashMapUnmanaged([]const u8));
        map.* = .empty;
        for (members) |m| {
            if (m.key_expr != null or !value.isRawPrivateName(m.key) or map.contains(m.key)) continue;
            try map.put(self.arena, m.key, try self.nextPrivateStorageKey(m.key));
        }
        if (map.count() == 0) return null;
        for (members) |*m| {
            m.key = remapPrivateName(map, m.key);
            // A computed key (`[expr]`) may itself reference a private name —
            // `[self.#f]` — so rewrite it too, else the raw `#f` is mistaken for a
            // public property at runtime.
            if (m.key_expr) |ke| try self.rewritePrivateNamesInNode(ke, map);
            if (m.field_init) |init| try self.rewritePrivateNamesInNode(init, map);
            if (m.func) |func| try self.rewritePrivateNamesInNode(func, map);
            if (m.static_block) |block| try self.rewritePrivateNamesInNode(block, map);
        }
        return map;
    }

    /// Evaluate a `class` to a constructor function value: methods go on its
    /// `.prototype`, static members on the class object itself, and instance
    /// fields are desugared into the constructor (`this.f = init`). With
    /// `extends`, the prototypes are linked and methods get a home object so
    /// `super.x` / `super(...)` resolve. (Accessors are still deferred.)
    fn evalClass(self: *Interpreter, name: []const u8, superclass: ?*Node, members: []ast.ClassMember, source: []const u8) EvalError!Value {
        return self.evalClassWithComputedKeys(name, superclass, members, source, null);
    }

    pub fn evalClassWithComputedKeys(self: *Interpreter, name: []const u8, superclass: ?*Node, members: []ast.ClassMember, source: []const u8, computed_keys: ?[]const Value) EvalError!Value {
        var super_obj: ?*value.Object = null;
        var super_proto: ?*value.Object = null;
        // A class with ClassHeritage is a *derived* class even when the heritage
        // is `null` (`class C extends null`): the constructor is a derived
        // constructor (its `this` is uninitialized until a — here impossible —
        // `super()`), its prototype's [[Prototype]] is null, and its constructor's
        // [[Prototype]] is %Function.prototype% (the makeFunction default).
        const derived = superclass != null;
        // The class name is a binding in a scope that wraps the WHOLE class,
        // including the heritage expression — where the name is in TDZ, so
        // `class x extends x {}` is a ReferenceError. Create that scope before
        // evaluating heritage; buildClass installs the actual (const) binding once
        // the constructor exists.
        const outer_env = self.env;
        const class_env = try gc_mod.allocEnv(self.arena);
        self.initEnvironment(class_env, outer_env, false);
        self.env = class_env;
        defer self.env = outer_env;
        if (name.len > 0) try class_env.put(name, self.tdzVal());
        if (superclass) |sc| {
            const sv = try self.eval(sc);
            if (sv.isNull()) {
                // `extends null`: derived, null parent (handled above via `derived`).
            } else if (isConstructorValue(sv)) {
                super_obj = sv.asObj();
                // protoParent = ? Get(superclass, "prototype"); it must be an Object
                // or null (a bound function has no `prototype`; a `prototype` getter
                // may return anything), else a TypeError.
                const proto_v = try self.getProperty(sv, "prototype");
                if (proto_v.isObject() and !proto_v.asObj().is_symbol and !proto_v.asObj().is_bigint) {
                    super_proto = proto_v.asObj();
                } else if (proto_v.isNull()) {
                    super_proto = null;
                } else {
                    return self.throwError("TypeError", "class heritage's 'prototype' is not an object or null");
                }
            } else {
                // Any non-null heritage that is not a constructor — a non-object, or
                // a callable that lacks [[Construct]] (arrow / method / generator /
                // async function) — is a TypeError.
                return self.throwError("TypeError", "class extends value is not a constructor");
            }
        }
        return self.buildClass(name, members, super_obj, super_proto, source, derived, class_env, computed_keys);
    }

    fn buildClass(self: *Interpreter, name: []const u8, members_arg: []ast.ClassMember, super_obj: ?*value.Object, super_proto: ?*value.Object, source: []const u8, derived: bool, class_env: *Environment, computed_keys: ?[]const Value) EvalError!Value {
        // A class with private names is rewritten (`#x` → a unique storage key) in
        // place. Deep-copy the member ASTs first so EACH evaluation rewrites its
        // own copy — two evaluations of the same class source then have distinct
        // private names (the `classfactory()` / multiple-evaluations tests).
        var has_private = false;
        for (members_arg) |m| {
            if (m.key_expr == null and value.isRawPrivateName(m.key)) {
                has_private = true;
                break;
            }
        }
        const members = if (has_private) try self.deepCopyClassMembers(members_arg) else members_arg;
        const private_map = try self.rewriteClassPrivateNames(members);
        // Execute the class's static elements / field initializers with this
        // class's private map active, so a direct eval in them resolves the
        // class's private names.
        const saved_pm = self.current_private_map;
        self.current_private_map = private_map;
        defer self.current_private_map = saved_pm;

        // `class_env` (created by evalClass, already the current scope) is the
        // scope wrapping the class body; the class name is bound there once the
        // constructor exists, so methods, static initializers, and instance-field
        // initializers can refer to the class by name (`static x = C.m()`).

        // Instance field initializers, prepended to the constructor body.
        var field_inits: std.ArrayListUnmanaged(*Node) = .empty;
        const auto_storage_keys = try self.arena.alloc([]const u8, members.len);
        for (members, 0..) |m, i| {
            auto_storage_keys[i] = if (m.is_auto_accessor)
                try self.nextPrivateStorageKey("#<auto-accessor>")
            else
                "";
        }
        // The desugared `this.<name> = init` member node of each PUBLIC instance
        // field with a computed name, by member index. A computed field name is
        // evaluated ONCE (at class definition, in source order); the member loop
        // below bakes that key into the node so it is not re-evaluated for every
        // instance.
        const field_member_nodes = try self.arena.alloc(?*Node, members.len);
        @memset(field_member_nodes, null);
        for (members, 0..) |m, i| {
            if (!m.is_field or m.is_static) continue;
            const this_node = try self.arena.create(Node);
            this_node.* = .this_expr;
            const member_node = try self.arena.create(Node);
            member_node.* = .{ .member = .{ .object = this_node, .property = m.key, .computed = m.key_expr } };
            if (m.key_expr != null) field_member_nodes[i] = member_node;
            const raw_value = m.field_init orelse blk: {
                const u = try self.arena.create(Node);
                u.* = .undefined_lit;
                break :blk u;
            };
            // Wrap the initializer so a direct eval inside it sees the
            // field-initializer context (no `super()` / `arguments`).
            const value_node = if (m.field_init != null) vn: {
                const w = try self.arena.create(Node);
                w.* = .{ .field_init_value = raw_value };
                break :vn w;
            } else raw_value;
            const stmt = try self.arena.create(Node);
            // A private field is *defined* (PrivateFieldAdd) on `this`, not
            // assigned via PrivateSet; a public field is an ordinary assignment.
            if (m.is_auto_accessor) {
                stmt.* = .{ .private_field_def = .{ .name = auto_storage_keys[i], .value = value_node } };
            } else if (m.key_expr == null and value.isPrivateKey(m.key)) {
                stmt.* = .{ .private_field_def = .{ .name = m.key, .value = value_node } };
            } else {
                const assign_node = try self.arena.create(Node);
                assign_node.* = .{ .assign = .{ .target = member_node, .value = value_node } };
                stmt.* = .{ .expr_stmt = assign_node };
            }
            try field_inits.append(self.arena, stmt);
        }

        // Constructor: explicit (augmented with field inits) or default. For a
        // derived class with no explicit constructor, synthesize
        // `constructor(...args) { super(...args); }`.
        var ctor_node: ?*const ast.FunctionNode = null;
        for (members) |m| {
            if (m.is_ctor) ctor_node = m.func.?.function;
        }
        var default_params: []const ast.Param = &.{};
        var default_super: []*Node = &.{};
        if (ctor_node == null and derived) {
            const args_id = try self.arena.create(Node);
            args_id.* = .{ .identifier = "args" };
            const spread_node = try self.arena.create(Node);
            spread_node.* = .{ .spread = args_id };
            const super_args = try self.arena.dupe(*Node, &.{spread_node});
            const super_node = try self.arena.create(Node);
            super_node.* = .{ .super_call = super_args };
            const stmt = try self.arena.create(Node);
            stmt.* = .{ .expr_stmt = super_node };
            default_super = try self.arena.dupe(*Node, &.{stmt});
            default_params = try self.arena.dupe(ast.Param, &.{.{ .name = "args", .is_rest = true }});
        }
        const orig: []*Node = if (ctor_node) |cf| cf.body.block else default_super;
        // A base class runs its field initializers at the start of the
        // constructor (prepend); a derived class runs them when `super()` returns,
        // so they are stored on the constructor and not prepended here.
        const body_stmts = if (derived)
            orig
        else
            try std.mem.concat(self.arena, *Node, &.{ field_inits.items, orig });
        const body = try self.arena.create(Node);
        body.* = .{ .block = body_stmts };
        const fnode = try self.arena.create(ast.FunctionNode);
        fnode.* = .{
            .name = name,
            .params = if (ctor_node) |cf| cf.params else default_params,
            .body = body,
            .source = source,
            .is_expr_body = false,
            // All class code is strict, so the constructor is a strict function
            // (e.g. its `.caller`/`.arguments` hit the %ThrowTypeError% poison pill
            // rather than the legacy sloppy `null`).
            .is_strict = true,
        };
        const class_val = try self.makeFunction(fnode, self.env);
        const class_obj = class_val.asObj();
        // Now that the constructor exists, bind the class name in the class-body
        // scope so the body can reference it. It is a STRICT immutable (const)
        // binding — assigning to the class name inside the body throws a TypeError
        // even in sloppy code (unlike a named function expression's name). An
        // anonymous class (`class {}` / `var X = class {}`) has no inner binding.
        if (name.len > 0) try class_env.putConst(name, class_val);
        const proto = try self.protoObject(class_obj);
        // A class's `prototype` is non-writable, non-enumerable, non-configurable.
        try class_obj.setAttr(self.arena, "prototype", .{ .writable = false, .enumerable = false, .configurable = false });
        // The `constructor` back-link is created BEFORE the class element methods,
        // so a same-named element — e.g. a *computed* `['constructor']() {}`, which
        // is an ordinary method, not the class constructor — overrides it.
        try self.setProp(proto, "constructor", class_val);
        try proto.setAttr(self.arena, "constructor", .{ .writable = true, .enumerable = false, .configurable = true });

        // Link the prototype chains for inheritance.
        if (super_obj) |so| {
            proto.setProtoAtomic(super_proto);
            class_obj.setProtoAtomic(so); // static methods inherit
        } else if (derived) {
            // `extends null`: the prototype object's [[Prototype]] is null; the
            // constructor's [[Prototype]] stays %Function.prototype%.
            proto.setProtoAtomic(null);
        }
        // The constructor's home object is the prototype; super(...) targets the superclass.
        if (funcOf(class_val)) |cf| {
            cf.home_object = proto;
            cf.super_ctor = super_obj;
            cf.private_map = private_map; // a direct eval in a field initializer resolves private names
            cf.is_class_constructor = true;
            cf.is_derived_constructor = derived;
            cf.is_default_ctor = derived and ctor_node == null;
            if (derived) cf.field_inits = field_inits.items;
            // Private brands. Methods/accessors are added all at once before field
            // initializers run, so they brand the instance up front; *fields* are
            // added in declaration order, so each field brands the instance at its
            // own initializer (`private_field_def`) — a field referenced before its
            // declaration must still throw. Static members brand the class object.
            var brand_names: std.ArrayListUnmanaged([]const u8) = .empty;
            for (members) |m| {
                if (m.key_expr != null or m.static_block != null or m.key.len == 0 or m.key[0] != '#') continue;
                if (m.is_field) continue; // fields brand at their initializer
                if (m.is_static) {
                    try class_obj.addPrivateBrand(self.arena, m.key);
                } else {
                    // A `get #x` / `set #x` pair shares one private name, so the
                    // instance is branded with it only once.
                    var dup = false;
                    for (brand_names.items) |bn| if (eq(bn, m.key)) {
                        dup = true;
                        break;
                    };
                    if (!dup) try brand_names.append(self.arena, m.key);
                }
            }
            cf.private_brand_names = brand_names.items;
        }

        // ClassDefinitionEvaluation splits into two source-order passes. Pass 1
        // (this loop) is step 28: evaluate EVERY computed element name and define
        // methods/accessors; field names are evaluated here but their initializers
        // are deferred. Static field names/displaynames are stashed for pass 2.
        const static_keys = try self.arena.alloc([]const u8, members.len);
        const static_names = try self.arena.alloc([]const u8, members.len);
        var computed_i: usize = 0;
        for (members, 0..) |m, i| {
            // A `static { ... }` block has no name to evaluate; it runs in pass 2
            // (step 34), interleaved with static-field initializers in source order.
            if (m.static_block != null) continue;
            const kv: ?Value = if (m.key_expr) |ke| blk: {
                if (computed_keys) |keys| {
                    if (computed_i >= keys.len)
                        return self.throwError("TypeError", "missing computed class name");
                    const key = try self.toPropertyKeyValue(keys[computed_i]);
                    computed_i += 1;
                    break :blk key;
                }
                break :blk try self.toPropertyKeyValue(try self.eval(ke));
            } else null;
            const key = if (kv) |k| try self.keyOf(k) else m.key;
            // The name an anonymous field/method initializer takes from this key.
            // A private name (`#x`) was rewritten to the `#x\x00<serial>` storage
            // key, but its function name is the source form `#x` (the part before
            // the NUL marker).
            const name_str = if (kv) |k|
                try self.keyDisplayName(k)
            else if (value.isPrivateKey(m.key))
                std.mem.sliceTo(m.key, 0)
            else
                m.key;
            // A public instance field's computed NAME was just evaluated here,
            // once and in source order. Bake the resulting key into its desugared
            // per-instance initializer so the name expression does not re-run for
            // every `new` (and its side effects happen exactly once).
            if (kv != null and m.is_field and !m.is_static) {
                if (field_member_nodes[i]) |mn| {
                    mn.member.property = key;
                    mn.member.computed = null;
                }
            }
            // A static class element may not have the key "prototype" — the
            // constructor's `prototype` is a reserved, non-configurable own
            // property. The non-computed form is a parse SyntaxError; a computed
            // key resolving to "prototype" is a runtime TypeError.
            if (m.is_static and !m.is_ctor and !value.isPrivateKey(key) and eq(key, "prototype"))
                return self.throwError("TypeError", "Classes may not have a static property named 'prototype'");
            if (m.is_field) {
                if (m.is_auto_accessor) {
                    const home = if (m.is_static) class_obj else proto;
                    try self.defineAutoAccessor(home, key, auto_storage_keys[i], name_str);
                    try home.setAttr(self.arena, key, .{ .writable = false, .enumerable = false, .configurable = true });
                }
                // A static field's name is now resolved; its initializer (DefineField)
                // is deferred to pass 2 so every element's name is evaluated first.
                if (m.is_static) {
                    static_keys[i] = key;
                    static_names[i] = name_str;
                }
                continue;
            }
            if (m.is_ctor) continue;
            const fv = try self.eval(m.func.?);
            const home = if (m.is_static) class_obj else proto;
            if (funcOf(fv)) |mf| {
                mf.home_object = home;
                mf.super_ctor = super_obj;
                mf.private_map = private_map; // a direct eval in this method resolves the class's private names
            }
            switch (m.accessor) {
                .none => {
                    // Name a computed/symbol-keyed method ("[desc]"); a plain
                    // `m(){}` already carries its parser-assigned name.
                    try self.maybeNameAnon(fv, m.func.?, name_str);
                    try self.setProp(home, key, fv);
                },
                .get => {
                    try self.nameAccessor(fv, "get", name_str);
                    try self.defineAccessor(home, key, fv, null);
                },
                .set => {
                    try self.nameAccessor(fv, "set", name_str);
                    try self.defineAccessor(home, key, null, fv);
                },
            }
            // Class methods/accessors are non-enumerable (writable + configurable),
            // unlike object-literal properties.
            try home.setAttr(self.arena, key, .{ .writable = !(value.isPrivateKey(key) and m.accessor == .none), .enumerable = false, .configurable = true });
        }
        if (computed_keys) |keys| if (computed_i != keys.len)
            return self.throwError("TypeError", "too many computed class names");

        // Pass 2 (step 34): run the static elements — `static { }` blocks and
        // static-field initializers — in source order, now that EVERY computed
        // name (including later instance/static field names) has been evaluated.
        // `this`/home is the class object so `super` and arrows resolve correctly.
        for (members, 0..) |m, i| {
            if (m.static_block) |block| {
                const saved_this = self.this_value;
                const saved_home = self.home_object;
                const saved_env = self.env;
                self.this_value = class_val;
                self.home_object = class_obj;
                // A `static {}` block is its own function-like scope: it gets a
                // fresh variable environment so its `var` declarations stay local
                // (each block, and the outer scope, are independent).
                const block_env = try gc_mod.allocEnv(self.arena);
                self.initEnvironment(block_env, class_env, true);
                self.env = block_env;
                if (block.* == .block) try self.hoistVarNames(block.block);
                _ = self.eval(block) catch |e| {
                    self.this_value = saved_this;
                    self.home_object = saved_home;
                    self.env = saved_env;
                    return e;
                };
                self.this_value = saved_this;
                self.home_object = saved_home;
                self.env = saved_env;
                continue;
            }
            if (!m.is_field or !m.is_static) continue;
            const key = static_keys[i];
            const name_str = static_names[i];
            const saved_this = self.this_value;
            const saved_home = self.home_object;
            const saved_fi = self.in_field_initializer;
            self.this_value = class_val;
            self.home_object = class_obj;
            self.in_field_initializer = true;
            // DefineField order: evaluate the initializer FIRST, then
            // PrivateFieldAdd (brand + extensibility check) — so a static private
            // field whose initializer seals the class object makes its own add throw.
            const fv2 = if (m.field_init) |init_node| self.eval(init_node) catch |e| {
                self.this_value = saved_this;
                self.home_object = saved_home;
                self.in_field_initializer = saved_fi;
                return e;
            } else Value.undef();
            self.this_value = saved_this;
            self.home_object = saved_home;
            self.in_field_initializer = saved_fi;
            if (m.field_init) |fi| try self.maybeNameAnon(fv2, fi, name_str);
            if (m.is_auto_accessor) {
                const storage_key = auto_storage_keys[i];
                try self.addPrivateBrandChecked(class_obj, storage_key);
                try class_obj.setOwn(self.arena, self.root_shape, storage_key, fv2);
                try class_obj.setAttr(self.arena, storage_key, .{ .writable = true, .enumerable = false, .configurable = false });
            } else {
                if (value.isPrivateKey(key)) try self.addPrivateBrandChecked(class_obj, key);
                try self.setProp(class_obj, key, fv2);
            }
        }
        return class_val;
    }

    fn evalArgs(self: *Interpreter, arg_nodes: []*Node) EvalError![]Value {
        // Fast path: no spreads → fixed-size slice.
        var has_spread = false;
        for (arg_nodes) |an| {
            if (an.* == .spread) has_spread = true;
        }
        if (!has_spread) {
            const args = try self.arena.alloc(Value, arg_nodes.len);
            for (arg_nodes, 0..) |an, i| args[i] = try self.eval(an);
            return args;
        }
        var list: std.ArrayListUnmanaged(Value) = .empty;
        for (arg_nodes) |an| {
            if (an.* == .spread) {
                try self.spreadInto(&list, try self.eval(an.spread));
            } else {
                try list.append(self.arena, try self.eval(an));
            }
        }
        return list.items;
    }

    /// Expand an iterable into `list` — for `...spread`. Arrays take a fast
    /// path; everything else (strings, generators, Sets/Maps, user objects with
    /// `[Symbol.iterator]`) goes through the iterator protocol.
    pub fn spreadInto(self: *Interpreter, list: *std.ArrayListUnmanaged(Value), v: Value) EvalError!void {
        if (v.isObject() and v.asObj().is_array and self.arrayIterIntact()) {
            for (v.asObj().elements.items) |e| try list.append(self.arena, e);
            return;
        }
        const iter_obj = try self.iteratorOf(v); // throws TypeError if not iterable
        while (true) {
            const res = try self.callMethod(iter_obj, "next", &.{});
            if ((try self.getProperty(res, "done")).toBoolean()) break;
            try list.append(self.arena, try self.getProperty(res, "value"));
        }
    }

    fn evalCall(self: *Interpreter, callee_node: *Node, arg_nodes: []*Node, optional: bool) EvalError!Value {
        if (callee_node.* == .optional_chain and callee_node.optional_chain.* == .member) {
            const m = callee_node.optional_chain.member;
            const recv = try self.eval(m.object);
            if (m.optional and (recv.isNull() or recv.isUndefined())) return error.OptShortCircuit;
            const key = try self.memberKey(m.property, m.computed);
            if (optional) {
                const method = try self.getProperty(recv, key);
                if (method.isNull() or method.isUndefined()) return error.OptShortCircuit;
                return self.callValueWithThis(method, try self.evalArgs(arg_nodes), recv);
            }
            const args = try self.evalArgs(arg_nodes);
            return self.callMethod(recv, key, args);
        }
        // Method call `obj.m(...)`: evaluate the receiver once so it can both
        // resolve the method and bind `this`. Array/string builtins (push,
        // pop, ...) that aren't own properties are dispatched here too.
        if (callee_node.* == .member) {
            const m = callee_node.member;
            const recv = try self.eval(m.object);
            if (m.optional and (recv.isNull() or recv.isUndefined())) return error.OptShortCircuit;
            const key = try self.memberKey(m.property, m.computed);
            // `recv.m?.(...)`: short-circuit if the method itself is nullish.
            if (optional) {
                const method = try self.getProperty(recv, key);
                if (method.isNull() or method.isUndefined()) return error.OptShortCircuit;
                return self.callValueWithThis(method, try self.evalArgs(arg_nodes), recv);
            }
            // Evaluating the callee MemberExpression does RequireObjectCoercible on
            // the base, so a nullish receiver throws BEFORE the arguments are
            // evaluated — `o.bar.gar(foo())` must not run `foo()` when `o.bar` is
            // undefined.
            if (recv.isNull() or recv.isUndefined())
                return self.throwError("TypeError", "cannot read property of null or undefined");
            const args = try self.evalArgs(arg_nodes);
            return self.callMethod(recv, key, args);
        }
        // `super.m(args)`: look the method up on the home object's prototype,
        // but invoke it with the current `this`.
        if (callee_node.* == .super_member) {
            const sm = callee_node.super_member;
            const home = self.home_object orelse return self.throwError("SyntaxError", "'super' outside a method");
            // GetThisBinding precedes the key/lookup (see the super read path): a
            // derived-ctor `super.m()` before `super()` is a ReferenceError.
            if (!self.this_initialized) return self.throwError("ReferenceError", "Must call super constructor before using 'this'");
            const parent = home.protoAtomic() orelse
                return self.throwError("TypeError", "no superclass method");
            const key = try self.memberKey(sm.property, sm.computed);
            const method = try self.getProperty(Value.obj(parent), key);
            const args = try self.evalArgs(arg_nodes);
            return self.callValueWithThis(method, args, self.this_value);
        }
        // A bare-identifier callee resolved through a `with` binding object is
        // invoked with that object as `this` (its WithBaseObject), e.g.
        // `with (obj) { method(); }` calls `method` with `this === obj`.
        // `lookupIdent` records the providing object during the SAME resolution,
        // so this needs no extra `HasProperty` (which a proxy env would observe).
        self.with_this_pending = null;
        const callee = try self.eval(callee_node);
        const with_this: ?*value.Object = if (callee_node.* == .identifier) self.with_this_pending else null;
        if (optional and (callee.isNull() or callee.isUndefined())) return error.OptShortCircuit;
        const args = try self.evalArgs(arg_nodes);
        const saved_direct_eval = self.direct_eval_call;
        // A direct eval requires the callee to be THIS realm's %eval% intrinsic.
        // A syntactic `eval(...)` whose binding resolves to another realm's eval
        // (or a reassigned `eval`) is an *indirect* eval — it runs as global code
        // in that eval's own realm, not in the caller's scope.
        const eval_named = !optional and callee_node.* == .identifier and std.mem.eql(u8, callee_node.identifier, "eval");
        self.direct_eval_call = eval_named and callee.isObject() and blk: {
            const realm_eval = rootEnv(self.env).get("eval") orelse break :blk false;
            break :blk realm_eval.isObject() and realm_eval.asObj() == callee.asObj();
        };
        defer self.direct_eval_call = saved_direct_eval;
        if (with_this) |wo| return self.callValueWithThis(callee, args, Value.obj(wo));
        return self.callValue(callee, args);
    }

    /// `tag`a${x}b`` → `tag(strings, x)` where `strings` is the frozen cooked
    /// array carrying a frozen `raw` array. The tag's `this` is the member
    /// receiver for `obj.tag`...`` (e.g. `String.raw`...``), else undefined.
    fn evalTaggedTemplate(self: *Interpreter, site: *const Node, tag_node: *Node, cooked: []?[]const u8, raw: [][]const u8, expr_nodes: []*Node) EvalError!Value {
        // GetTemplateObject: the frozen "strings" object is cached by call site
        // (this AST node) and reused on every evaluation, so the tag receives the
        // same object each time. Build it only on a cache miss.
        const strings = if (self.template_cache.get(@ptrCast(site))) |cached|
            cached.asObj()
        else blk: {
            const s = (try self.newArray()).asObj();
            for (cooked) |c| try s.elements.append(s.elementsAllocator(self.arena), if (c) |cv| Value.str(cv) else Value.undef());
            const raw_arr = (try self.newArray()).asObj();
            for (raw) |c| try raw_arr.elements.append(raw_arr.elementsAllocator(self.arena), Value.str(c));
            try freezeTemplateArray(self, raw_arr);
            try s.setOwn(self.arena, self.root_shape, "raw", Value.obj(raw_arr));
            try s.setAttr(self.arena, "raw", .{ .writable = false, .enumerable = false, .configurable = false });
            try freezeTemplateArray(self, s);
            try self.template_cache.put(self.arena, @ptrCast(site), Value.obj(s));
            break :blk s;
        };

        // Build the argument list: strings, then each substitution value.
        var args: std.ArrayListUnmanaged(Value) = .empty;
        try args.append(self.arena, Value.obj(strings));
        for (expr_nodes) |en| try args.append(self.arena, try self.eval(en));

        // Resolve the tag and its `this` (member receiver, else undefined).
        if (tag_node.* == .member) {
            const m = tag_node.member;
            const recv = try self.eval(m.object);
            const key = try self.memberKey(m.property, m.computed);
            return self.callMethod(recv, key, args.items);
        }
        return self.callValue(try self.eval(tag_node), args.items);
    }

    fn freezeTemplateArray(self: *Interpreter, obj: *value.Object) EvalError!void {
        var i: usize = 0;
        while (i < obj.elementsLen()) : (i += 1) {
            const key = try std.fmt.allocPrint(self.arena, "{d}", .{i});
            try obj.setAttr(self.arena, key, .{ .writable = false, .enumerable = true, .configurable = false });
        }
        try obj.setAttr(self.arena, "length", .{ .writable = false, .enumerable = false, .configurable = false });
        obj.extensible = false;
    }

    /// Invoke a callable value with `this = undefined`.
    pub fn callValue(self: *Interpreter, callee: Value, args: []const Value) EvalError!Value {
        return self.callValueWithThis(callee, args, Value.undef());
    }

    /// Invoke a callable value with an explicit `this`. Zig-native builtins run
    /// directly; JS functions push a call scope over their closure; builtin
    /// error constructors fabricate an error instance.
    pub fn callValueWithThis(self: *Interpreter, callee: Value, args: []const Value, this_val: Value) EvalError!Value {
        if (!callee.isObject()) return self.throwError("TypeError", "value is not a function");
        const obj = callee.asObj();
        if (obj.proxy_handler != null or obj.proxy_revoked) {
            const target = obj.proxy_target orelse return self.throwError("TypeError", "Cannot perform 'apply' on a proxy that has been revoked");
            if (try self.proxyTrap(obj, "apply")) |trap| {
                const arr = try self.newArray();
                for (args) |a| try arr.asObj().elements.append(arr.asObj().elementsAllocator(self.arena), a);
                return self.callValueWithThis(trap, &.{ Value.obj(target), this_val, arr }, Value.obj(obj.proxy_handler.?));
            }
            return self.callValueWithThis(Value.obj(target), args, this_val);
        }
        if (obj.bound) |erased| {
            const bf: *BoundFn = @ptrCast(@alignCast(erased));
            return self.callValueWithThis(bf.target, try self.concatArgs(bf.args, args), bf.this);
        }
        if (obj.error_ctor) |name| return self.makeErrorWithArgs(name, args);
        if (obj.native) |nf| {
            try self.stackGuard();
            self.depth += 1;
            defer self.depth -= 1;
            // Expose the callee object to the native (it isn't a parameter), so
            // closures-over-data like Promise resolve/reject can find their slot.
            const saved_native = self.active_native;
            self.active_native = obj;
            defer self.active_native = saved_native;
            const saved_nt = self.new_target;
            if (!self.direct_eval_call) self.new_target = Value.undef();
            defer self.new_target = saved_nt;
            return nf(@ptrCast(self), this_val, args);
        }
        if (obj.js_func) |erased| {
            const func: *Function = @ptrCast(@alignCast(erased));
            return self.callFunction(func, args, this_val);
        }
        return self.throwError("TypeError", "value is not a function");
    }

    /// A bound function: target + the `this`/leading args fixed by `fn.bind`.
    pub const BoundFn = struct { target: Value, this: Value, args: []const Value };

    /// `fn.bind(this, ...bound)`: a new callable that prepends `bound` to its args.
    /// CreateListFromArrayLike: the argument list for `Function.prototype.apply`
    /// (and Reflect.apply). `undefined`/`null` → empty; a non-object throws; an
    /// object is read by `length` (ToLength) and indices 0..length via [[Get]],
    /// so a real array-like (e.g. `arguments`) works, not only a dense array.
    fn argListFromArrayLike(self: *Interpreter, v: Value) EvalError![]const Value {
        if (v.isUndefined() or v.isNull()) return &.{};
        if (!builtins.isRealObject(v)) return self.throwError("TypeError", "CreateListFromArrayLike called on non-object");
        const o = v.asObj();
        const len = toLen((try self.toPrimitive(try self.getProperty(v, "length"), .number)).toNumber());
        if (len > (1 << 24)) return self.throwError("RangeError", "argument list too large");
        // Dense fast path for a plain array with no accessors.
        if (o.is_array and o.accessors == null and len <= o.elements.items.len) return o.elements.items[0..len];
        const buf = try self.arena.alloc(Value, len);
        for (buf, 0..) |*slot, i| slot.* = try self.getProperty(v, try std.fmt.allocPrint(self.arena, "{d}", .{i}));
        return buf;
    }

    fn makeBound(self: *Interpreter, target: *value.Object, this: Value, bound_args: []const Value) EvalError!Value {
        const bf = try gc_mod.allocBoundFn(self.arena);
        bf.* = .{ .target = Value.obj(target), .this = this, .args = try self.arena.dupe(Value, bound_args) };
        const obj = try gc_mod.allocObj(self.arena);
        const target_proto = if (target.proxy_handler != null or target.proxy_revoked) blk: {
            const p = try self.proxyGetProto(target);
            break :blk if (p.isObject()) p.asObj() else null;
        } else self.effectiveProto(target);
        obj.* = .{ .bound = @ptrCast(bf), .proto = target_proto };
        // Per spec: a bound function's `length` is max(0, target.length - args)
        // and its `name` is "bound " + target.name. Both are
        // { writable: false, enumerable: false, configurable: true }.
        const ro_attr: value.PropAttr = .{ .writable = false, .enumerable = false, .configurable = true };
        const bound_len: f64 = if (objectHasOwn(target, "length")) blk: {
            const tgt_len_v = try self.getProperty(Value.obj(target), "length");
            if (!tgt_len_v.isNumber()) break :blk 0;
            const len_int = if (std.math.isNan(tgt_len_v.asNum())) @as(f64, 0) else @trunc(tgt_len_v.asNum());
            const bound_count: f64 = @floatFromInt(bound_args.len);
            break :blk if (len_int <= bound_count) 0 else len_int - bound_count;
        } else 0;
        try obj.setOwn(self.arena, self.root_shape, "length", Value.num(bound_len));
        try obj.setAttr(self.arena, "length", ro_attr);
        const tgt_name = try self.getProperty(Value.obj(target), "name");
        const base_name = if (tgt_name.isString()) tgt_name.asStr() else "";
        const bound_name = try std.fmt.allocPrint(self.arena, "bound {s}", .{base_name});
        try obj.setOwn(self.arena, self.root_shape, "name", Value.str(bound_name));
        try obj.setAttr(self.arena, "name", ro_attr);
        return Value.obj(obj);
    }

    /// Concatenate bound args with call args (for invoking a bound function).
    fn concatArgs(self: *Interpreter, a: []const Value, b: []const Value) EvalError![]const Value {
        if (a.len == 0) return b;
        if (b.len == 0) return a;
        const out = try self.arena.alloc(Value, a.len + b.len);
        @memcpy(out[0..a.len], a);
        @memcpy(out[a.len..], b);
        return out;
    }

    pub fn makeErrorWithArgs(self: *Interpreter, name: []const u8, args: []const Value) EvalError!Value {
        return self.makeErrorWithArgsNT(name, args, Value.undef());
    }

    fn makeErrorWithArgsNT(self: *Interpreter, name: []const u8, args: []const Value, new_target: Value) EvalError!Value {
        // AggregateError(errors, message, options) shifts message/options by one
        // and carries an own `errors` array built from the first (iterable) arg.
        const aggregate = std.mem.eql(u8, name, "AggregateError");
        const suppressed = std.mem.eql(u8, name, "SuppressedError");
        const msg_i: usize = if (aggregate) 1 else if (suppressed) 2 else 0;
        const opt_i: usize = if (aggregate) 2 else if (suppressed) 3 else 1;

        // The message is ToString'd (via ToPrimitive(string), so an object's
        // toString/valueOf runs); a Symbol message throws a TypeError.
        const has_msg = args.len > msg_i and !args[msg_i].isUndefined();
        const msg = if (has_msg) blk: {
            const prim = try self.toPrimitive(args[msg_i], .string);
            if (prim.isObject() and prim.asObj().is_symbol)
                return self.throwError("TypeError", "Cannot convert a Symbol value to a string");
            break :blk try prim.toString(self.arena);
        } else "";
        const proto = if (new_target.isObject()) try self.ctorRealmIntrinsicProto(new_target.asObj(), name) else null;
        const err = try self.makeErrorWithProto(name, msg, proto);
        if (has_msg and msg.len == 0) {
            try self.setProp(err.asObj(), "message", Value.str(""));
            try err.asObj().setAttr(self.arena, "message", .{ .enumerable = false, .configurable = true, .writable = true });
        }

        if (aggregate) {
            // `errors` is a fresh Array built from the (iterable) first argument.
            const errs = try self.iterableToArray(if (args.len > 0) args[0] else Value.undef());
            try self.setProp(err.asObj(), "errors", errs);
            try err.asObj().setAttr(self.arena, "errors", .{ .enumerable = false, .configurable = true, .writable = true });
        }

        if (suppressed) {
            // SuppressedError(error, suppressed, message): the first two arguments
            // become non-enumerable own `error` / `suppressed` properties.
            try self.setProp(err.asObj(), "error", if (args.len > 0) args[0] else Value.undef());
            try err.asObj().setAttr(self.arena, "error", .{ .enumerable = false, .configurable = true, .writable = true });
            try self.setProp(err.asObj(), "suppressed", if (args.len > 1) args[1] else Value.undef());
            try err.asObj().setAttr(self.arena, "suppressed", .{ .enumerable = false, .configurable = true, .writable = true });
        }

        // ES2022 `cause` option: `new Error(msg, { cause })` installs a
        // non-enumerable `cause` own property when the options object HAS one —
        // a real HasProperty (walks the prototype chain and fires a Proxy `has`
        // trap), then [[Get]] reads the value.
        if (args.len > opt_i and args[opt_i].isObject()) {
            if (try self.inOperator(Value.str("cause"), args[opt_i])) {
                const cause = try self.getProperty(args[opt_i], "cause");
                try self.setProp(err.asObj(), "cause", cause);
                try err.asObj().setAttr(self.arena, "cause", .{ .enumerable = false, .configurable = true, .writable = true });
            }
        }
        return err;
    }

    fn iterableToArray(self: *Interpreter, v: Value) EvalError!Value {
        const arr = try self.newArray();
        const it = try self.iteratorOf(v);
        while (true) {
            const step = try self.iterStep(it);
            if (step.done) break;
            try arr.asObj().elements.append(arr.asObj().elementsAllocator(self.arena), step.value);
        }
        return arr;
    }

    fn callFunction(self: *Interpreter, func: *Function, args: []const Value, this_val: Value) EvalError!Value {
        return self.callFunctionNT(func, args, this_val, Value.undef());
    }

    /// `callFunction` with an explicit `new.target` (set by `construct`; a plain
    /// call passes undefined). Arrow functions inherit the enclosing new.target.
    fn callFunctionNT(self: *Interpreter, func: *Function, args: []const Value, this_val: Value, new_target: Value) EvalError!Value {
        // An async (non-generator) function runs its body synchronously and wraps
        // the completion in a Promise: a normal return resolves it, a throw
        // rejects it. `await` inside drives the microtask queue inline until the
        // awaited promise settles (the synchronous-settling model). Async
        // generators still need the suspendable VM, so they fall through.
        if (func.is_async and !func.is_generator) {
            // A body the VM could lower runs as a suspendable activation driven
            // by promise settlement (spec-correct await ordering). Otherwise fall
            // back to the synchronous-settling tree-walk model below.
            if (func.async_chunk) |_| return vm.runAsync(self, func, args, this_val);
            const result = try promise.newPromise(self);
            const rp: *promise.Promise = @ptrCast(@alignCast(result.promise.?));
            if (self.callPlain(func, args, this_val, new_target)) |rv| {
                try promise.resolve(self, rp, rv);
            } else |err| {
                if (err == error.Throw) {
                    const reason = self.exception;
                    self.exception = Value.undef();
                    try promise.reject(self, rp, reason);
                } else return err;
            }
            return Value.obj(result);
        }
        // A VM-lowered plain function MUST run on the VM regardless of how it was
        // *entered*: its body resolves captured variables as frame upvalues
        // (`load_upval`), which only the VM's activation frames provide — the
        // tree-walker's `callPlain` resolves names through the lexical
        // `Environment` chain, where a frame-local upvalue does not exist. When
        // such a closure is invoked from a tree-walker entry (e.g. a spawned
        // `Thread`'s `callValueWithThis`, or any host call that lands here while
        // the top-level ran on the VM), tree-walking the body raises a spurious
        // `ReferenceError`. `vm.callValue` already dispatches chunk functions to
        // the VM; mirror that here so the two entry paths agree. Constructors
        // (`new_target` set) keep the tree-walk path — `construct` threads
        // `new.target`, which `runFunction` does not. (A surfaced concurrent-JS
        // fuzzer regression: a shared closure read across threads.)
        if (new_target.isUndefined() and !func.is_generator and !func.is_async) {
            if (func.chunk) |fchunk| return vm.runFunction(self, func, fchunk, args, this_val);
        }
        return self.callPlain(func, args, this_val, new_target);
    }

    /// The body of a plain (sync) function call: scope setup, param binding, and
    /// evaluation. Async functions route through `callFunctionNT`, which wraps
    /// this in a Promise.
    fn callPlain(self: *Interpreter, func: *Function, args: []const Value, this_val: Value, new_target: Value) EvalError!Value {
        // Calling a `function*` builds a generator object (its body runs lazily,
        // on the suspendable VM, via `.next()`). Async generators can't yet run
        // their body (need yield+await suspension), but per spec their parameters
        // still bind eagerly on the call — so a computed-key/default side effect
        // (e.g. `async function*({ [thrower()]: x }) {}`) must propagate before we
        // give up. We fall through to the normal scope-setup + bindParams path and
        // return an inert async-generator stub once binding succeeds.
        if (func.is_generator and !func.is_async) return vm.makeGenerator(self, func, args, this_val);
        // An async generator whose body the VM lowered runs as a real async
        // generator; an unlowerable body falls through to the inert stub below.
        if (func.is_generator and func.is_async and func.gen_chunk != null)
            return vm.makeAsyncGenerator(self, func, args, this_val);
        try self.stackGuard();
        self.depth += 1;
        defer self.depth -= 1;

        const call_env = try gc_mod.allocEnv(self.arena);
        self.initEnvironment(call_env, func.closure, true);

        const saved_env = self.env;
        const saved_signal = self.signal;
        const saved_ret = self.ret_value;
        const saved_this = self.this_value;
        const saved_home = self.home_object;
        const saved_super = self.super_ctor;
        const saved_nt = self.new_target;
        const saved_strict = self.strict;
        const saved_global = self.global_object;
        const saved_import_meta_slot = self.import_meta_slot;
        const saved_import_meta_obj = self.import_meta_obj;
        const saved_this_initialized = self.this_initialized;
        const saved_this_cell = self.this_cell;
        const saved_active_function = self.active_function;
        const saved_eval_nt = self.direct_eval_new_target_allowed;
        const saved_fi = self.in_field_initializer;
        const saved_pe = self.in_param_expr;
        const saved_pd = self.in_param_default;
        self.in_param_default = false; // a function body is not a parameter default
        const saved_edd = self.eval_decl_deletable;
        self.eval_decl_deletable = false; // a function's own vars aren't eval-deletable, even if called from eval
        const saved_idc = self.in_derived_ctor;
        const saved_dfc = self.in_default_ctor;
        const saved_pm = self.current_private_map;
        if (!func.is_arrow) self.current_private_map = func.private_map; // arrows inherit the enclosing class's map
        if (!func.is_arrow) self.active_function = func.obj;
        const saved_pfi = self.pending_field_inits;
        const saved_pbn = self.pending_brand_names;
        // A derived constructor's field initializers + private brands wait for its
        // SuperCall.
        self.pending_field_inits = func.field_inits;
        self.pending_brand_names = if (func.is_derived_constructor) func.private_brand_names else &.{};
        self.env = call_env;
        self.signal = .none;
        self.strict = func.is_strict;
        self.import_meta_slot = func.import_meta_slot;
        self.import_meta_obj = if (func.import_meta_slot) |slot| slot.obj else null;
        if (self.env.get("globalThis")) |gt| {
            if (gt.isObject()) self.global_object = gt.asObj();
        }
        // Sloppy-mode this-substitution: null/undefined become the callee
        // realm's global object; primitive receivers are boxed in the callee
        // realm. Strict functions keep the original value, and arrows inherit
        // `this` lexically.
        self.this_value = if (func.is_arrow)
            // Arrows ignore the provided `this` and use the lexically captured one.
            func.arrow_this
        else if (!func.is_strict) blk: {
            if (this_val.isNull() or this_val.isUndefined()) {
                if (self.env.get("globalThis")) |gt| if (gt.isObject()) break :blk gt;
                break :blk if (self.global_object) |g| Value.obj(g) else this_val;
            }
            if (!this_val.isObject() or this_val.asObj().is_symbol or this_val.asObj().is_bigint)
                break :blk Value.obj(try self.toObject(this_val));
            break :blk this_val;
        } else this_val;
        self.home_object = func.home_object;
        self.super_ctor = func.super_ctor;
        self.new_target = if (func.is_arrow) func.arrow_new_target else new_target; // arrows capture lexically at creation
        self.direct_eval_new_target_allowed = !func.is_arrow;
        // A non-arrow function call is a fresh context that is not a field
        // initializer; an arrow carries the field-initializer context LEXICALLY from
        // where it was defined (so `field = () => eval('arguments')` keeps the
        // restriction even when invoked later, after the field has been built).
        self.in_field_initializer = func.is_arrow and func.field_init_ctx;
        // Arrows inherit the enclosing super()-call legality; a non-arrow function
        // establishes it (only a derived constructor permits `super()`).
        // `super()`-legality is lexical: an arrow uses the value captured where it
        // was defined (so it stays legal even when invoked from a non-constructor
        // context, e.g. an iterator's `return()`); a non-arrow establishes it.
        self.in_derived_ctor = if (func.is_arrow) func.arrow_in_derived_ctor else func.is_derived_constructor;
        if (!func.is_arrow) self.in_default_ctor = func.is_default_ctor;
        // An arrow has no own `this` binding: it inherits the enclosing function's
        // this-initialization state (a non-arrow establishes it — only a derived
        // constructor starts uninitialized).
        if (!func.is_arrow) self.this_initialized = !func.is_derived_constructor;
        // The `this` binding is a shared cell so an arrow's `super()` reaches the
        // enclosing derived ctor's binding across intervening calls. A derived ctor
        // opens a fresh cell; an arrow adopts its captured one (the enclosing ctor's)
        // and reads the live binding through it; every other call clears it.
        if (func.is_arrow) {
            self.this_cell = func.this_cell;
            if (func.this_cell) |c| {
                self.this_value = c.value;
                self.this_initialized = c.initialized;
            }
        } else if (func.is_derived_constructor) {
            const cell = try self.arena.create(ThisCell);
            cell.* = .{ .value = self.this_value, .initialized = false };
            self.this_cell = cell;
        } else {
            self.this_cell = null;
        }
        defer {
            self.env = saved_env;
            self.signal = saved_signal;
            self.ret_value = saved_ret;
            self.home_object = saved_home;
            self.super_ctor = saved_super;
            self.new_target = saved_nt;
            self.strict = saved_strict;
            self.global_object = saved_global;
            self.import_meta_slot = saved_import_meta_slot;
            self.import_meta_obj = saved_import_meta_obj;
            self.this_value = saved_this;
            self.this_initialized = saved_this_initialized;
            self.this_cell = saved_this_cell;
            self.active_function = saved_active_function;
            // Re-sync the ambient this-state from the (restored) enclosing derived
            // ctor's shared cell: a `super()` that ran during this call — possibly
            // via an arrow invoked from an unrelated context — initialized the
            // cell, and that binding must remain visible to the enclosing ctor.
            if (self.this_cell) |c| if (c.initialized) {
                self.this_value = c.value;
                self.this_initialized = true;
            };
            self.direct_eval_new_target_allowed = saved_eval_nt;
            self.in_field_initializer = saved_fi;
            self.in_param_expr = saved_pe;
            self.in_param_default = saved_pd;
            self.eval_decl_deletable = saved_edd;
            self.in_derived_ctor = saved_idc;
            self.in_default_ctor = saved_dfc;
            self.current_private_map = saved_pm;
            self.pending_field_inits = saved_pfi;
            self.pending_brand_names = saved_pbn;
        }
        if (func.is_class_constructor and new_target.isUndefined())
            return self.throwError("TypeError", "Class constructor cannot be invoked without 'new'");

        // Non-arrow functions get an `arguments` array-like over the call args.
        if (!func.is_arrow) {
            const args_obj = try self.newArray();
            args_obj.asObj().is_arguments = true;
            // The arguments exotic object's [[Prototype]] is %Object.prototype%
            // (not Array.prototype): it has no inherited array methods, and
            // `arguments.toString()` is Object.prototype.toString → "[object
            // Arguments]". Index storage and for-of still use the `is_array` path.
            if (self.objectProto()) |op| args_obj.asObj().proto = op;
            // It does have an own @@iterator = %Array.prototype.values% (so
            // `arguments[Symbol.iterator]()` yields an Array Iterator).
            if (self.arrayProtoObj()) |ap| if (self.symbolIteratorKey()) |ik| {
                if (ap.getOwn(ik)) |it| {
                    try args_obj.asObj().setOwn(self.arena, self.root_shape, ik, it);
                    try args_obj.asObj().setAttr(self.arena, ik, .{ .writable = true, .enumerable = false, .configurable = true });
                }
            };
            try args_obj.asObj().setOwn(self.arena, self.root_shape, "length", Value.num(@floatFromInt(args.len)));
            try args_obj.asObj().setAttr(self.arena, "length", .{ .writable = true, .enumerable = false, .configurable = true });
            for (args) |av| try args_obj.asObj().elements.append(args_obj.asObj().elementsAllocator(self.arena), av);
            // Strict mode's `arguments.callee` is a poison-pill accessor whose
            // get and set are both `%ThrowTypeError%`. Reading or writing it
            // throws, but `Object.getOwnPropertyDescriptor(arguments, "callee").
            // get` returns the shared intrinsic (its identity and properties are
            // what test262 probes).
            var non_simple_params = false;
            for (func.params) |p| {
                if (p.default != null or p.is_rest or p.pattern != null) {
                    non_simple_params = true;
                    break;
                }
            }
            if (func.is_strict or non_simple_params) {
                if (self.throwTypeError()) |tte| {
                    try args_obj.asObj().setAccessor(self.arena, "callee", Value.obj(tte), Value.obj(tte));
                    try args_obj.asObj().setAttr(self.arena, "callee", .{ .enumerable = false, .configurable = false });
                }
            } else if (func.obj) |fo| {
                // A mapped (sloppy, simple-parameter) arguments object's `callee` is
                // an own data property = the callee function itself, {writable: true,
                // enumerable: false, configurable: true}.
                try args_obj.asObj().setOwn(self.arena, self.root_shape, "callee", Value.obj(fo));
                try args_obj.asObj().setAttr(self.arena, "callee", .{ .writable = true, .enumerable = false, .configurable = true });
            }
            // Mapped arguments [[ParameterMap]]: in sloppy mode with simple
            // parameters, each in-range index aliases its parameter binding (a
            // two-way live link; reads/writes go to `call_env`).
            if (!func.is_strict and !non_simple_params and func.params.len > 0) {
                const n = @min(args.len, func.params.len);
                const names = try args_obj.asObj().argMapNamesAllocator(self.arena).alloc([]const u8, n);
                for (names, 0..) |*nm, i| nm.* = func.params[i].name;
                // A duplicated parameter name maps only its last index.
                for (names, 0..) |nm, i| {
                    var j = i + 1;
                    while (j < n) : (j += 1) if (std.mem.eql(u8, nm, names[j])) {
                        names[i] = "";
                        break;
                    };
                }
                args_obj.asObj().arg_map_env = @ptrCast(call_env);
                args_obj.asObj().arg_map_names = names;
            }
            try call_env.put("arguments", args_obj);
        }
        // Bind parameters in `call_env` (so a default can reference earlier
        // params). A non-arrow parameter scope owns `arguments`, so a direct eval
        // in a default expression may not redeclare it (checked in evalFn).
        try self.bindParams2(func.params, args, func.is_arrow);

        // A base class brands `this` with its private names at the start of the
        // constructor (a derived class does so when `super()` returns).
        if (func.is_class_constructor and !func.is_derived_constructor and self.this_value.isObject()) {
            for (func.private_brand_names) |bn| try self.addPrivateMethodOrAccessorChecked(self.this_value.asObj(), func.home_object, bn);
        }

        // Async generator: params have now bound (propagating any side-effect
        // throws). We can't run the body yet, so hand back an inert object
        // standing in for the async-generator instance — the sync `*-err` dstr
        // tests only check the binding throw; the body-running tests are
        // async-flagged and skipped.
        if (func.is_async and func.is_generator) return self.newObject();

        if (func.is_expr_body) return self.eval(func.body);
        // FunctionDeclarationInstantiation: when the formals contain a parameter
        // expression (a default Initializer), the body runs in a SEPARATE variable
        // environment, so a closure created in the parameter list cannot see the
        // body's `var`/function declarations (and vice-versa). A body `var` that
        // names a parameter inherits the parameter's bound value.
        var has_param_expr = false;
        for (func.params) |p| if (p.default != null) {
            has_param_expr = true;
            break;
        };
        if (func.body.* == .block) {
            if (has_param_expr) {
                const body_env = try gc_mod.allocEnv(self.arena);
                self.initEnvironment(body_env, call_env, true);
                self.env = body_env;
                try self.hoistVarNames(func.body.block);
                for (func.params) |p| {
                    if (p.pattern == null and !p.is_rest and body_env.vars.contains(p.name)) {
                        if (call_env.get(p.name)) |pv| try body_env.put(p.name, pv);
                    }
                }
            } else {
                // Hoist the body's `var`s into the (shared) function scope.
                try self.hoistVarNames(func.body.block);
            }
        }
        // Expose this activation's parameter names + tag the body block as the
        // function-body scope, for Annex B B.3.3 block-function analysis.
        const saved_params = self.cur_params;
        self.cur_params = collectParamNames(self.arena, func.params) catch &.{};
        defer self.cur_params = saved_params;
        self.mark_fn_body = true;
        _ = try self.eval(func.body);
        self.mark_fn_body = false;
        if (func.is_class_constructor and func.is_derived_constructor) {
            if (self.signal == .ret) {
                if (self.ret_value.isObject() and !self.ret_value.asObj().is_symbol and !self.ret_value.asObj().is_bigint) return self.ret_value;
                if (!self.ret_value.isUndefined()) {
                    self.env = saved_env;
                    self.global_object = saved_global;
                    return self.throwError("TypeError", "Derived constructors may only return object or undefined");
                }
            }
            // GetThisBinding reads the shared cell: `super()` may have run during
            // an intervening call (e.g. an iterator `return()` handler invoking a
            // `() => super()` arrow as the abrupt `return` was processed), so the
            // cell — not the ambient flag — is authoritative.
            const inited = if (self.this_cell) |c| c.initialized else self.this_initialized;
            if (!inited) {
                self.env = saved_env;
                self.global_object = saved_global;
                return self.throwError("ReferenceError", "Must call super constructor before using 'this'");
            }
            // The bound `this` (the object `super()` produced) is what `new`
            // yields — not the discarded eager placeholder.
            return if (self.this_cell) |c| c.value else self.this_value;
        }
        return if (self.signal == .ret) self.ret_value else Value.undef();
    }

    /// Bind a function's parameters to `args` in the current environment
    /// (`self.env`): a rest param (`...r`) collects the remaining args into an
    /// array; an absent/undefined arg falls back to the param's default; a
    /// destructuring pattern is bound via `bindPattern`. Shared by ordinary
    /// calls and generators (which bind into the generator's own environment).
    pub fn bindParams(self: *Interpreter, params: []const ast.Param, args: []const Value) EvalError!void {
        return self.bindParams2(params, args, false);
    }

    /// Whether any parameter binds the name `arguments` (a simple param, a rest
    /// param, or a name inside a destructuring pattern).
    fn paramsBindArguments(params: []const ast.Param) bool {
        for (params) |p| {
            if (p.pattern) |pat| {
                if (patternBindsName(pat, "arguments")) return true;
            } else if (std.mem.eql(u8, p.name, "arguments")) return true;
        }
        return false;
    }

    fn patternBindsName(node: *Node, name: []const u8) bool {
        switch (node.*) {
            .identifier => |n| return std.mem.eql(u8, n, name),
            .obj_pattern => |p| {
                for (p.props) |prop| if (patternBindsName(prop.target, name)) return true;
                if (p.rest) |r| if (r.* == .identifier and std.mem.eql(u8, r.identifier, name)) return true;
            },
            .arr_pattern => |p| {
                for (p.elems) |elem| if (elem.target) |t| {
                    if (patternBindsName(t, name)) return true;
                };
                if (p.rest) |r| if (patternBindsName(r, name)) return true;
            },
            else => {},
        }
        return false;
    }

    pub fn createArgumentsObject(self: *Interpreter, func: *Function, args: []const Value, call_env: *Environment) EvalError!Value {
        const args_obj = try self.newArray();
        args_obj.asObj().is_arguments = true;
        // The arguments exotic object's [[Prototype]] is %Object.prototype%
        // (not Array.prototype): it has no inherited array methods, and
        // `arguments.toString()` is Object.prototype.toString -> "[object
        // Arguments]". Index storage and for-of still use the `is_array` path.
        if (self.objectProto()) |op| args_obj.asObj().proto = op;
        // It does have an own @@iterator = %Array.prototype.values% (so
        // `arguments[Symbol.iterator]()` yields an Array Iterator).
        if (self.arrayProtoObj()) |ap| if (self.symbolIteratorKey()) |ik| {
            if (ap.getOwn(ik)) |it| {
                try args_obj.asObj().setOwn(self.arena, self.root_shape, ik, it);
                try args_obj.asObj().setAttr(self.arena, ik, .{ .writable = true, .enumerable = false, .configurable = true });
            }
        };
        try args_obj.asObj().setOwn(self.arena, self.root_shape, "length", Value.num(@floatFromInt(args.len)));
        try args_obj.asObj().setAttr(self.arena, "length", .{ .writable = true, .enumerable = false, .configurable = true });
        for (args) |av| try args_obj.asObj().elements.append(args_obj.asObj().elementsAllocator(self.arena), av);

        // Strict mode's `arguments.callee` is a poison-pill accessor whose get
        // and set are both `%ThrowTypeError%`. Non-simple sloppy formals also
        // use an unmapped arguments object with the poison pill.
        var non_simple_params = false;
        for (func.params) |p| {
            if (p.default != null or p.is_rest or p.pattern != null) {
                non_simple_params = true;
                break;
            }
        }
        if (func.is_strict or non_simple_params) {
            if (self.throwTypeError()) |tte| {
                try args_obj.asObj().setAccessor(self.arena, "callee", Value.obj(tte), Value.obj(tte));
                try args_obj.asObj().setAttr(self.arena, "callee", .{ .enumerable = false, .configurable = false });
            }
        } else if (func.obj) |fo| {
            // A mapped (sloppy, simple-parameter) arguments object's `callee` is
            // an own data property = the callee function itself.
            try args_obj.asObj().setOwn(self.arena, self.root_shape, "callee", Value.obj(fo));
            try args_obj.asObj().setAttr(self.arena, "callee", .{ .writable = true, .enumerable = false, .configurable = true });
        }

        // Mapped arguments [[ParameterMap]]: in sloppy mode with simple
        // parameters, each in-range index aliases its parameter binding.
        if (!func.is_strict and !non_simple_params and func.params.len > 0) {
            const n = @min(args.len, func.params.len);
            const names = try args_obj.asObj().argMapNamesAllocator(self.arena).alloc([]const u8, n);
            for (names, 0..) |*nm, i| nm.* = func.params[i].name;
            // A duplicated parameter name maps only its last index.
            for (names, 0..) |nm, i| {
                var j = i + 1;
                while (j < n) : (j += 1) if (std.mem.eql(u8, nm, names[j])) {
                    names[i] = "";
                    break;
                };
            }
            args_obj.asObj().arg_map_env = @ptrCast(call_env);
            args_obj.asObj().arg_map_names = names;
        }
        return args_obj;
    }

    pub fn bindParams2(self: *Interpreter, params: []const ast.Param, args: []const Value, is_arrow: bool) EvalError!void {
        // The parameter scope binds `arguments` when this is a non-arrow function
        // (the arguments object) or when a parameter is named `arguments`; in
        // either case a direct eval in a default may not declare `arguments`.
        const param_scope_has_arguments = !is_arrow or paramsBindArguments(params);
        for (params, 0..) |p, i| {
            if (p.is_rest) {
                const rest = try self.newArray();
                var j = i;
                while (j < args.len) : (j += 1) try rest.asObj().elements.append(rest.asObj().elementsAllocator(self.arena), args[j]);
                if (p.pattern) |pat| try self.bindPattern(pat, rest, true) else try self.env.put(p.name, rest);
                break;
            }
            var v: Value = if (i < args.len) args[i] else Value.undef();
            if (v.isUndefined()) {
                if (p.default) |d| {
                    // A parameter is in scope (in its TDZ) across its own
                    // Initializer, so a self-reference `function f(x = x)` reads
                    // the still-uninitialized parameter — a ReferenceError — not
                    // an outer binding of the same name. Pre-bind it to the TDZ
                    // sentinel; the real value overwrites it below.
                    if (p.pattern == null and self.tdz_marker != null) try self.env.put(p.name, self.tdzVal());
                    // The default runs in the parameter scope; a non-arrow's owns
                    // `arguments`, so a direct eval there can't declare it. The
                    // `in_param_default` flag (all functions) marks that a direct
                    // eval here may not `var`-declare a parameter name.
                    const saved_pe = self.in_param_expr;
                    const saved_pd = self.in_param_default;
                    self.in_param_expr = param_scope_has_arguments;
                    self.in_param_default = true;
                    v = self.eval(d) catch |e| {
                        self.in_param_expr = saved_pe;
                        self.in_param_default = saved_pd;
                        return e;
                    };
                    self.in_param_expr = saved_pe;
                    self.in_param_default = saved_pd;
                    if (p.pattern == null) try self.maybeNameAnon(v, d, p.name); // `function f(x = () => {})` ⇒ name "x"
                }
            }
            if (p.pattern) |pat| try self.bindPattern(pat, v, true) else try self.env.put(p.name, v);
        }
    }

    /// `new Callee(args)`: builtin error constructors mint an error instance;
    /// JS functions get a fresh `this` object (tagged with `ctor_ref` for
    /// `instanceof`) and may override it by explicitly returning an object.
    fn evalNew(self: *Interpreter, callee_node: *Node, arg_nodes: []*Node) EvalError!Value {
        const callee = try self.eval(callee_node);
        const args = try self.evalArgs(arg_nodes);
        return self.construct(callee, args);
    }

    /// Construct an instance from `callee` with already-evaluated `args`. Shared
    /// by the `new` operator and the C-API `JSObjectCallAsConstructor`.
    /// Copy a built-in super constructor's result (`src`, a fresh exotic object)
    /// onto the derived instance (`dst`) in place, so the instance gains the
    /// internal slots — [[SetData]]/[[MapData]]/array elements/[[PromiseState]]/
    /// wrapper [[…Data]]/etc. — plus any maintained own properties (e.g. a Set's
    /// `size`). `dst`'s prototype (its derived `.prototype`) is preserved; `dst`
    /// is otherwise pristine (a derived constructor cannot touch `this` before
    /// `super()` returns). `src` is discarded, so transfer ownership of any
    /// GC-owned backing stores to `dst`; otherwise both cells would finalize the
    /// same slots/elements/accessor storage.
    fn adoptInternalSlots(dst: *value.Object, src: *value.Object) void {
        const keep_proto = dst.protoAtomic();
        dst.* = src.*;
        dst.setProtoAtomic(keep_proto);
        src.* = .{};
    }

    pub fn construct(self: *Interpreter, callee: Value, args: []const Value) EvalError!Value {
        return self.constructNT(callee, args, callee);
    }

    /// [[Construct]] with an explicit NewTarget (Reflect.construct / subclassing):
    /// `new_target` drives the new instance's prototype and the `new.target` seen
    /// by the constructor; `callee` is the function actually invoked.
    pub fn constructNT(self: *Interpreter, callee: Value, args: []const Value, new_target: Value) EvalError!Value {
        if (!callee.isObject()) return self.throwError("TypeError", "value is not a constructor");
        const obj = callee.asObj();
        if (obj.proxy_handler != null or obj.proxy_revoked) {
            const target = obj.proxy_target orelse return self.throwError("TypeError", "Cannot perform 'construct' on a proxy that has been revoked");
            if (try self.proxyTrap(obj, "construct")) |trap| {
                const arr = try self.newArray();
                for (args) |a| try arr.asObj().elements.append(arr.asObj().elementsAllocator(self.arena), a);
                const res = try self.callValueWithThis(trap, &.{ Value.obj(target), arr, new_target }, Value.obj(obj.proxy_handler.?));
                // The [[Construct]] trap must return an Object (9.5.14 step 9).
                if (!res.isObject() or res.asObj().is_symbol or res.asObj().is_bigint)
                    return self.throwError("TypeError", "proxy 'construct' trap must return an object");
                return res;
            }
            return self.constructNT(Value.obj(target), args, new_target);
        }
        if (obj.bound) |erased| {
            // `new (fn.bind(...))(...)`: construct the target with bound args
            // prepended (the bound `this` is ignored by `new`, per spec).
            const bf: *BoundFn = @ptrCast(@alignCast(erased));
            const nt = if (std.meta.eql(new_target, callee)) bf.target else new_target;
            return self.constructNT(bf.target, try self.concatArgs(bf.args, args), nt);
        }
        if (obj.error_ctor) |name| return self.makeErrorWithArgsNT(name, args, new_target);
        if (obj.native) |nf| {
            // Most built-ins aren't constructors; only flagged ones are `new`-able.
            if (!obj.native_ctor) return self.throwError("TypeError", "value is not a constructor");
            // Signal [[Construct]] to the native via `new_target` (restored after),
            // so e.g. `new Number(x)` boxes a wrapper object while `Number(x)`
            // returns a primitive.
            const saved_nt = self.new_target;
            self.new_target = new_target;
            defer self.new_target = saved_nt;
            const saved_native = self.active_native;
            self.active_native = obj;
            defer self.active_native = saved_native;
            return nf(@ptrCast(self), Value.undef(), args); // native ctor (Array, Map, RegExp, ...)
        }
        if (obj.js_func) |erased| {
            const func: *Function = @ptrCast(@alignCast(erased));
            // Arrow / async / generator functions and concise methods / accessors
            // are not constructors (a class constructor is not flagged is_method).
            if (func.is_arrow or func.is_async or func.is_generator or func.is_method)
                return self.throwError("TypeError", "value is not a constructor");
            // OrdinaryCreateFromConstructor: the instance proto comes from NewTarget.
            const inst = try gc_mod.allocObj(self.arena);
            inst.* = .{ .ctor_ref = obj, .proto = if (new_target.isObject()) try self.ctorRealmIntrinsicProto(new_target.asObj(), "Object") else try self.protoObject(obj) };
            const this_val = Value.obj(inst);
            const ret = try self.callFunctionNT(func, args, this_val, new_target);
            return if (ret.isObject()) ret else this_val;
        }
        return self.throwError("TypeError", "value is not a constructor");
    }

    // ---- objects, arrays, members -----------------------------------------

    fn memberKey(self: *Interpreter, static: []const u8, computed: ?*Node) EvalError![]const u8 {
        if (computed) |ce| return self.keyOf(try self.eval(ce));
        return static;
    }

    fn fastNumericIndex(v: Value) ?usize {
        if (!v.isNumber()) return null;
        const n = v.asNum();
        if (std.math.isNan(n) or std.math.isInf(n) or @trunc(n) != n or n < 0 or n >= 4294967295)
            return null;
        return @intFromFloat(n);
    }

    fn arrayProtoChainCleanForIndexedSet(self: *Interpreter, o: *value.Object) bool {
        var cur = self.effectiveProto(o);
        while (cur) |c| {
            if (c.proxy_handler != null or c.proxy_revoked or c.typed_array != null or c.has_indexed_property.load(.monotonic))
                return false;
            if (c.indexed_own_seen.load(.acquire)) return false;
            cur = self.effectiveProto(c);
        }
        return true;
    }

    fn arrayProtoChainCleanForDenseAppend(self: *Interpreter, o: *value.Object) bool {
        var cur = self.effectiveProto(o);
        while (cur) |c| {
            if (c.proxy_handler != null or c.proxy_revoked or c.typed_array != null or c.has_indexed_property.load(.monotonic))
                return false;
            if (c.indexed_own_seen.load(.acquire)) return false;
            cur = self.effectiveProto(c);
        }
        return true;
    }

    fn arrayProtoMayAffectIndexedHas(self: *Interpreter, o: *value.Object) bool {
        var cur = self.effectiveProto(o);
        while (cur) |c| {
            if (c.proxy_handler != null or c.proxy_revoked or c.typed_array != null or c.has_indexed_property.load(.monotonic))
                return true;
            if (c.indexed_own_seen.load(.acquire)) return true;
            cur = self.effectiveProto(c);
        }
        return false;
    }

    fn setFastArrayNumericIndex(self: *Interpreter, recv: Value, index: usize, v: Value) EvalError!bool {
        if (!recv.isObject()) return false;
        const o = recv.asObj();
        try self.checkRestricted(o);
        if (!o.is_array or o.is_arguments or o.accessors != null or o.attrs != null or
            o.has_indexed_property.load(.monotonic) or !o.extensible or !self.arrayProtoChainCleanForIndexedSet(o))
            return false;
        const dense_cap: usize = 1 << 24;
        return try o.setOrGrowDenseElement(self.arena, index, v, dense_cap);
    }

    /// ToPropertyKey: a Symbol key uses its unique internal encoding (so
    /// symbol-keyed properties don't collide with string keys and stay out of
    /// string enumeration); other keys coerce to string.
    /// ToString(v): the spec abstract operation — `ToString(ToPrimitive(v,
    /// string))` for an object (running its `toString`/`valueOf`, propagating any
    /// throw), and a TypeError for a Symbol. Unlike `Value.toString` (a Zig-level
    /// rendering), this observes user methods and rejects Symbols.
    pub fn toStringV(self: *Interpreter, v: Value) EvalError![]const u8 {
        if (v.isObject() and v.asObj().is_symbol)
            return self.throwError("TypeError", "Cannot convert a Symbol value to a string");
        if (v.isObject()) {
            const prim = try self.toPrimitive(v, .string);
            if (prim.isObject() and prim.asObj().is_symbol)
                return self.throwError("TypeError", "Cannot convert a Symbol value to a string");
            return prim.toString(self.arena);
        }
        return v.toString(self.arena);
    }

    /// ToNumber(v): runs `[Symbol.toPrimitive]`/`valueOf`/`toString` for an
    /// object (propagating throws), and a TypeError for a Symbol.
    pub fn toNumberV(self: *Interpreter, v: Value) EvalError!f64 {
        if (v.isObject() and v.asObj().is_symbol)
            return self.throwError("TypeError", "Cannot convert a Symbol value to a number");
        if (v.isObject() and v.asObj().is_bigint)
            return self.throwError("TypeError", "Cannot convert a BigInt value to a number");
        if (v.isObject()) {
            const prim = try self.toPrimitive(v, .number);
            if (prim.isObject() and prim.asObj().is_symbol)
                return self.throwError("TypeError", "Cannot convert a Symbol value to a number");
            if (prim.isObject() and prim.asObj().is_bigint)
                return self.throwError("TypeError", "Cannot convert a BigInt value to a number");
            return prim.toNumber();
        }
        return v.toNumber();
    }

    /// ArraySetLength's numeric path: ToUint32(value), then ToNumber(value)
    /// again, so observable coercions run in spec order before descriptor checks.
    pub fn arrayLengthFromValue(self: *Interpreter, v: Value) EvalError!u32 {
        const uint_n = try self.toNumberV(v);
        const new_len = Value.uint32FromF64(uint_n);
        const number_len = try self.toNumberV(v);
        if (@as(f64, @floatFromInt(new_len)) != number_len)
            return self.throwError("RangeError", "Invalid array length");
        return new_len;
    }

    /// Apply the deletion half of ArraySetLength after writability/coercion
    /// checks. Returns false when a non-configurable element blocks the shrink.
    pub fn setArrayLength(self: *Interpreter, o: *value.Object, requested_len: usize) EvalError!bool {
        if (!o.is_arguments and o.attrs == null and o.accessors == null and !o.has_indexed_property.load(.monotonic)) {
            o.truncateDenseElementsAndSetLength(requested_len);
            return true;
        }

        const old_len = o.arrayLength();
        var new_len = requested_len;
        var blocked = false;

        if (requested_len < old_len) {
            const DeleteEntry = struct {
                idx: usize,
                key: []const u8,
            };
            var entries: std.ArrayListUnmanaged(DeleteEntry) = .empty;
            for (try self.objectOwnKeysList(o)) |k| {
                if (arrayElementIndex(k)) |idx| {
                    if (idx >= requested_len and idx < old_len)
                        try entries.append(self.arena, .{ .idx = idx, .key = k });
                }
            }
            std.mem.sort(DeleteEntry, entries.items, {}, struct {
                fn lt(_: void, a: DeleteEntry, b: DeleteEntry) bool {
                    return a.idx > b.idx;
                }
            }.lt);

            for (entries.items) |entry| {
                if (!objectHasOwn(o, entry.key)) continue;
                if (!o.getAttr(entry.key).configurable) {
                    new_len = entry.idx + 1;
                    blocked = true;
                    break;
                }
                _ = try self.deleteOwn(o, entry.key);
            }
        }

        o.truncateDenseElementsAndSetLength(new_len);
        return !blocked;
    }

    /// ToPropertyKey as a primitive Value: ToPrimitive(key, string) keeping a
    /// Symbol as-is. Unlike `keyOf` it returns the primitive (not a storage
    /// string), so a caller can derive BOTH a storage key and a display name
    /// from a single — possibly side-effecting — coercion. (Computing them with
    /// two `keyOf`/`keyDisplayName` calls would run `valueOf`/`@@toPrimitive`
    /// twice and, when the result is a Symbol, throw in the ToString half.)
    pub fn toPropertyKeyValue(self: *Interpreter, k: Value) EvalError!Value {
        if (!k.isObject() or k.asObj().is_symbol) return k;
        return self.toPrimitive(k, .string);
    }

    pub fn keyOf(self: *Interpreter, k: Value) EvalError![]const u8 {
        if (k.isObject() and k.asObj().is_symbol) return self.registerSymbol(k.asObj());
        // ToPropertyKey: an object key is first ToPrimitive(key, string) — running
        // its `[Symbol.toPrimitive]`/`toString`/`valueOf` (a TypeError if none
        // yields a primitive) — and a resulting Symbol keeps its key.
        if (k.isObject()) {
            const prim = try self.toPrimitive(k, .string);
            if (prim.isObject() and prim.asObj().is_symbol) return self.registerSymbol(prim.asObj());
            return prim.toString(self.arena);
        }
        return k.toString(self.arena);
    }

    /// Index a Symbol by its encoded `sym_key` so it can later be recovered (by
    /// getOwnPropertySymbols / proxy traps), then return that key.
    fn registerSymbol(self: *Interpreter, sym: *value.Object) []const u8 {
        self.symbols.put(self.arena, sym.sym_key, sym) catch {};
        return sym.sym_key;
    }

    /// Allocate a fresh plain object. The single creation point so later tiers
    /// (object shapes) have one seam to hook.
    pub fn newObject(self: *Interpreter) EvalError!Value {
        const obj = try gc_mod.allocObject(self.gc, self.arena);
        // An ordinary object's [[Prototype]] is %Object.prototype%. Callers that
        // need a null-proto object (`Object.create(null)`, dictionary holders)
        // overwrite `obj.protoAtomic()` right after this returns.
        obj.* = .{ .proto = self.objectProto() };
        return Value.obj(obj);
    }

    /// The `.prototype` object of a constructor, creating it on first use (every
    /// function/class has one; instances proto to it).
    /// GetPrototypeFromConstructor(ctor, %Intl.<service>.prototype%): the
    /// constructor's own `prototype` when it is an object, else the intrinsic
    /// prototype of the constructor's *realm* (recovered from a JS function's
    /// closure root environment), so cross-realm `Reflect.construct` derives the
    /// proto from the NewTarget's realm. Falls back to the current realm.
    pub fn ctorRealmProto(self: *Interpreter, ctor: *value.Object, service: []const u8) EvalError!*value.Object {
        const p = try self.getProperty(Value.obj(ctor), "prototype");
        if (p.isObject() and !p.asObj().is_symbol) return p.asObj();
        if (ctor.js_func) |jf| {
            const fnp: *Function = @ptrCast(@alignCast(jf));
            var env: ?*Environment = fnp.closure;
            while (env) |e| {
                // The realm's intrinsics live on its global object (globalThis).
                const g: ?*value.Object = if (e.get("globalThis")) |gt| (if (gt.isObject()) gt.asObj() else null) else null;
                if (g) |gobj| {
                    if (gobj.getOwn("Intl")) |intl| if (intl.isObject())
                        if (intl.asObj().getOwn(service)) |sv| if (sv.isObject())
                            if (sv.asObj().getOwn("prototype")) |pp| if (pp.isObject()) return pp.asObj();
                    break;
                }
                if (e.parent == null) break;
                env = e.parent;
            }
        }
        return try self.protoObject(ctor);
    }

    fn envIntrinsicProto(env: *Environment, intrinsic: []const u8) ?*value.Object {
        if (env.get("globalThis")) |gt| {
            if (gt.isObject()) {
                if (gt.asObj().getOwn(intrinsic)) |ctor_v| {
                    if (ctor_v.isObject()) {
                        if (ctor_v.asObj().getOwn("prototype")) |proto_v| {
                            if (proto_v.isObject()) return proto_v.asObj();
                        }
                    }
                }
            }
        }
        if (env.get(intrinsic)) |ctor_v| {
            if (ctor_v.isObject()) {
                if (ctor_v.asObj().getOwn("prototype")) |proto_v| {
                    if (proto_v.isObject()) return proto_v.asObj();
                }
            }
        }
        return null;
    }

    fn envIntrinsicObject(env: *Environment, intrinsic: []const u8) ?*value.Object {
        if (env.get(intrinsic)) |v| {
            if (v.isObject()) return v.asObj();
        }
        return null;
    }

    fn functionRealmIntrinsicProto(self: *Interpreter, ctor: *value.Object, intrinsic: []const u8) EvalError!?*value.Object {
        if (ctor.proxy_handler != null or ctor.proxy_revoked) {
            const target = ctor.proxy_target orelse return self.throwError("TypeError", "Cannot get function realm from a revoked proxy");
            return try self.functionRealmIntrinsicProto(target, intrinsic);
        }
        if ((ctor.native_ctor or ctor.error_ctor != null) and ctor.private_data != null) {
            const env: *Environment = @ptrCast(@alignCast(ctor.private_data.?));
            if (envIntrinsicProto(env, intrinsic)) |proto| return proto;
        }
        if (ctor.js_func) |jf| {
            const fnp: *Function = @ptrCast(@alignCast(jf));
            var env: ?*Environment = fnp.closure;
            while (env) |e| {
                if (envIntrinsicProto(e, intrinsic)) |proto| return proto;
                if (e.parent == null) break;
                env = e.parent;
            }
        }
        if (ctor.bound) |erased| {
            const bf: *BoundFn = @ptrCast(@alignCast(erased));
            if (bf.target.isObject()) return try self.functionRealmIntrinsicProto(bf.target.asObj(), intrinsic);
        }
        return null;
    }

    fn functionRealmIntrinsicObject(self: *Interpreter, ctor: *value.Object, intrinsic: []const u8) EvalError!?*value.Object {
        if (ctor.proxy_handler != null or ctor.proxy_revoked) {
            const target = ctor.proxy_target orelse return self.throwError("TypeError", "Cannot get function realm from a revoked proxy");
            return try self.functionRealmIntrinsicObject(target, intrinsic);
        }
        if ((ctor.native_ctor or ctor.error_ctor != null) and ctor.private_data != null) {
            const env: *Environment = @ptrCast(@alignCast(ctor.private_data.?));
            if (envIntrinsicObject(env, intrinsic)) |obj| return obj;
        }
        if (ctor.js_func) |jf| {
            const fnp: *Function = @ptrCast(@alignCast(jf));
            var env: ?*Environment = fnp.closure;
            while (env) |e| {
                if (envIntrinsicObject(e, intrinsic)) |obj| return obj;
                if (e.parent == null) break;
                env = e.parent;
            }
        }
        if (ctor.bound) |erased| {
            const bf: *BoundFn = @ptrCast(@alignCast(erased));
            if (bf.target.isObject()) return try self.functionRealmIntrinsicObject(bf.target.asObj(), intrinsic);
        }
        return null;
    }

    /// GetPrototypeFromConstructor for global intrinsics such as
    /// `%AggregateError.prototype%`: own `newTarget.prototype` wins; otherwise
    /// use the NewTarget realm's intrinsic prototype when that realm is known.
    pub fn ctorRealmIntrinsicProto(self: *Interpreter, ctor: *value.Object, intrinsic: []const u8) EvalError!*value.Object {
        const p = try self.getProperty(Value.obj(ctor), "prototype");
        if (p.isObject() and !p.asObj().is_symbol) return self.preparePrototypeUse(p.asObj());
        if (try self.functionRealmIntrinsicProto(ctor, intrinsic)) |proto| return proto;
        if (envIntrinsicProto(self.env, intrinsic)) |proto| return proto;
        return try self.protoObject(ctor);
    }

    /// GetPrototypeFromConstructor(newTarget, %ctor_name.prototype%): read
    /// `newTarget.prototype` via [[Get]] (a getter runs and may throw); if the
    /// result isn't an object, fall back to the named intrinsic's prototype.
    /// Returns null when there is no new.target (the caller keeps its default).
    fn protoFromCtor(self: *Interpreter, ctor_name: []const u8) EvalError!?*value.Object {
        if (!self.new_target.isObject()) return null;
        // GetPrototypeFromConstructor: new.target.prototype, or — when that is not
        // an Object — the *new.target's realm's* named intrinsic prototype.
        return try self.ctorRealmIntrinsicProto(self.new_target.asObj(), ctor_name);
    }

    pub fn protoObject(self: *Interpreter, ctor: *value.Object) EvalError!*value.Object {
        if (ctor.getOwn("prototype")) |p| {
            if (p.isObject()) return self.preparePrototypeUse(p.asObj());
        }
        // Lazy install is a check-then-act over shared object storage: with the
        // GIL dropped, two threads `new`-ing (or reading `.prototype` of) the same
        // not-yet-materialized constructor could both miss above and install
        // *distinct* prototypes, breaking `F.prototype === F.prototype`. Take the
        // realm lazy-init lock and RE-CHECK (double-checked locking), so exactly
        // one thread installs and the others observe it. No-op when threads are
        // off (gil == null), so the single-thread path is unchanged.
        if (self.gil) |g| {
            g.lockLazyInit();
            defer g.unlockLazyInit();
            if (ctor.getOwn("prototype")) |p| {
                if (p.isObject()) return self.preparePrototypeUse(p.asObj());
            }
            return try self.installProtoObject(ctor);
        }
        return try self.installProtoObject(ctor);
    }

    fn preparePrototypeUse(self: *Interpreter, proto: *value.Object) *value.Object {
        _ = self;
        if (proto.elementsLen() != 0) proto.indexed_own_seen.store(true, .release);
        return proto;
    }

    fn installProtoObject(self: *Interpreter, ctor: *value.Object) EvalError!*value.Object {
        const proto = (try self.newObject()).asObj();
        try self.setProp(ctor, "prototype", Value.obj(proto));
        // `F.prototype.constructor === F` (writable, non-enumerable,
        // configurable), so an instance's `.constructor` resolves through the
        // prototype chain to F — not the `Object` fallback. Matches the lazy
        // materialization in `getProperty`.
        try self.setProp(proto, "constructor", Value.obj(ctor));
        try proto.setAttr(self.arena, "constructor", .{ .writable = true, .enumerable = false, .configurable = true });
        return proto;
    }

    /// Lazily materialize a generator function's `.prototype` (no `constructor`
    /// back-link; its [[Prototype]] is %(Async)GeneratorPrototype%). Same
    /// check-then-act race as `protoObject`, so it shares the double-checked
    /// realm lazy-init lock.
    pub fn genProtoObject(self: *Interpreter, o: *value.Object, is_async: bool) EvalError!*value.Object {
        if (o.getOwn("prototype")) |p| {
            if (p.isObject()) return p.asObj();
        }
        if (self.gil) |g| {
            g.lockLazyInit();
            defer g.unlockLazyInit();
            if (o.getOwn("prototype")) |p| {
                if (p.isObject()) return p.asObj();
            }
            return try self.installGenProto(o, is_async);
        }
        return try self.installGenProto(o, is_async);
    }

    fn installGenProto(self: *Interpreter, o: *value.Object, is_async: bool) EvalError!*value.Object {
        const tag = if (is_async) "\x00AsyncGenProto" else "\x00GenProto";
        const proto = try gc_mod.allocObj(self.arena);
        const gen_proto = (try self.functionRealmIntrinsicObject(o, tag)) orelse
            if (Interpreter.envIntrinsicObject(self.env, tag)) |gp| gp else null;
        proto.* = .{ .proto = gen_proto };
        try o.setOwn(self.arena, self.root_shape, "prototype", Value.obj(proto));
        try o.setAttr(self.arena, "prototype", .{ .writable = true, .enumerable = false, .configurable = false });
        return proto;
    }

    /// Run queued Promise reactions to completion (the event loop's microtask
    /// checkpoint). Each job may enqueue more; the step budget bounds runaways.
    pub fn drainMicrotasks(self: *Interpreter) EvalError!void {
        if (self.microtasks == null) return;
        // Pop one job at a time under `microtask_lock` (when engaged), run it
        // unlocked (it may enqueue more, re-entering the lock), and repeat until
        // the queue is empty. The per-pop lock makes the dequeue atomic against
        // a peer thread's concurrent enqueue under `parallel_js`; the previous
        // trailing `clearRetainingCapacity()` is gone because it could discard a
        // task a peer appended after the empties check (and the loop already
        // leaves the queue empty).
        while (self.microtaskDequeue()) |job| {
            self.current_microtask = job;
            promise.runJob(self, job) catch |err| {
                self.current_microtask = null;
                return err;
            };
            self.current_microtask = null;
            self.serviceRequestedGcCheckpoint();
        }
    }

    /// Atomically pop the next microtask (front of the queue), or null if empty.
    /// Holds `microtask_lock` only across the queue mutation — never across the
    /// job's execution — so it stays a brief leaf-lock that can't deadlock with
    /// the GIL or any per-structure lock.
    fn microtaskDequeue(self: *Interpreter) ?promise.Microtask {
        const q = self.microtasks orelse return null;
        self.lockMicrotasks();
        defer self.unlockMicrotasks();
        return q.pop();
    }

    /// Spin-acquire the realm's microtask lock (only engaged under
    /// `parallel_js`; a single null check otherwise). Mirrors `Object`'s
    /// `tryLock` spin since the enum mutex has no blocking `lock()`, and the
    /// critical section is a single queue append/pop, never JS.
    pub fn lockMicrotasks(self: *Interpreter) void {
        const m = self.microtask_lock orelse return;
        var spins: usize = 0;
        while (!m.tryLock()) : (spins += 1) {
            if ((spins & 0xff) == 0) std.Thread.yield() catch {} else std.atomic.spinLoopHint();
        }
    }

    pub fn unlockMicrotasks(self: *Interpreter) void {
        if (self.microtask_lock) |m| m.unlock();
    }

    fn serviceRequestedGcCheckpoint(self: *Interpreter) void {
        const requested = self.gc_requested orelse return;
        if (!requested.*) return;
        const f = self.gc_checkpoint_fn orelse return;
        const ctx = self.gc_checkpoint_ctx orelse return;
        f(ctx);
    }

    /// Register a running VM `Exec` as a precise GC root for the duration of its
    /// instruction loop. No-op when the GC is off (the common path), so the VM
    /// pays only a null check. The list is arena-backed; symmetric `popExecRoot`
    /// keeps it bounded by the live call-nesting depth.
    pub fn pushExecRoot(self: *Interpreter, exec: *vm.Exec) void {
        if (self.gc == null) return;
        self.gc_execs.append(self.arena, exec) catch {};
    }

    pub fn popExecRoot(self: *Interpreter, exec: *vm.Exec) void {
        if (self.gc == null) return;
        var i = self.gc_execs.items.len;
        while (i > 0) {
            i -= 1;
            if (self.gc_execs.items[i] == exec) {
                _ = self.gc_execs.orderedRemove(i);
                return;
            }
        }
    }

    pub fn pushTempRoot(self: *Interpreter, v: Value) EvalError!usize {
        const mark = self.gc_temp_roots.items.len;
        try self.gc_temp_roots.append(self.arena, v);
        return mark;
    }

    pub fn restoreTempRoots(self: *Interpreter, mark: usize) void {
        self.gc_temp_roots.shrinkRetainingCapacity(mark);
    }

    /// Run a guarded mid-script collection at a step checkpoint. The Context
    /// callback owns the safety policy (GC on, no other running JS threads,
    /// conservative native-stack scan available); a no-op otherwise.
    pub fn serviceGcSafepoint(self: *Interpreter) void {
        const f = self.gc_safepoint_fn orelse return;
        const ctx = self.gc_safepoint_ctx orelse return;
        f(ctx, self);
    }

    /// Host cleanup jobs for FinalizationRegistry. Explicit `cleanupSome()` and
    /// automatic cleanup share the same ready-record queue; if user code already
    /// consumed a record, the automatic job simply finds nothing to deliver.
    pub fn drainFinalizationCleanupJobs(self: *Interpreter) EvalError!void {
        const q = self.finalization_cleanup_jobs orelse return;
        var i: usize = 0;
        while (i < q.items.len) : (i += 1) {
            const registry = q.items[i];
            if (!registry.is_finalization_registry) continue;
            const cb = registry.finalization_callback;
            if (!cb.isCallable()) continue;
            // Pop each ready record under the lock; run its callback unlocked.
            while (registry.finRecordTakeReady()) |record| {
                if (self.callValue(cb, &.{record.held})) |_| {} else |err| {
                    if (err == error.Throw) {
                        self.exception = Value.undef();
                    } else return err;
                }
            }
        }
        q.clearRetainingCapacity();
    }

    /// Event-loop tail for `Atomics.waitAsync`: while this realm has
    /// outstanding async waiters, block until tickets settle (a notify, the
    /// deadline, or group teardown), resolve their promises, and drain the
    /// reactions — repeating until none remain or none can ever settle
    /// (infinite deadline with no live agent to notify; those promises are
    /// abandoned pending, the host's prerogative). Called after the main
    /// microtask drain in Context.evaluate/evaluateModule and agent realms.
    pub fn settleAsyncWaiters(self: *Interpreter) void {
        const park_with_gil = self.use_thread_gil and self.gil != null;
        if (self.gil) |g| {
            // Quiescence loop: pumped tasks queue microtasks which can queue
            // further tasks — keep going until both are empty.
            while (true) {
                jsthread.pumpTasks(self);
                jsthread.pollPropAsync(self);
                self.drainMicrotasks() catch {};
                // A peer thread settling an asyncJoin/propAsync can `enqueue`
                // (locked append) into this shared realm queue concurrently, so
                // read its length under the same `microtask_lock`.
                self.lockMicrotasks();
                const q_empty = if (self.microtasks) |q| q.isEmpty() else true;
                self.unlockMicrotasks();
                const tasks_empty = g.tasks_queued.load(.acquire) == 0;
                if (q_empty and tasks_empty) {
                    if (jsthread.nextPropAsyncDeadline(self)) |deadline| {
                        const now = std.Io.Timestamp.now(agent.engineIo(), .awake).nanoseconds;
                        if (deadline > now) {
                            if (park_with_gil) g.release();
                            std.Io.sleep(agent.engineIo(), .fromNanoseconds(@intCast(deadline - now)), .awake) catch {};
                            if (park_with_gil) g.acquire();
                        }
                        continue;
                    }
                    break;
                }
            }
        }
        const listp = self.async_waiters orelse return;
        if (listp.items.len == 0) return;
        const owner: *const anyopaque = @ptrCast(listp);
        var buf: [16]agent.Settled = undefined;
        while (listp.items.len > 0) {
            // harvestAsync blocks; under a GIL the notifier needs the VM lock.
            if (park_with_gil) self.gil.?.release();
            const n = agent.harvestAsync(owner, &buf);
            if (park_with_gil) self.gil.?.acquire();
            if (n == 0) break;
            for (buf[0..n]) |s| {
                var i: usize = 0;
                while (i < listp.items.len) : (i += 1) {
                    if (listp.items[i].id != s.id) continue;
                    const e = listp.swapRemove(i);
                    if (promise.promiseOf(e.promise)) |pp| {
                        const outcome: Value = Value.str(if (s.outcome == .ok) "ok" else "timed-out");
                        promise.resolve(self, pp, outcome) catch {};
                    }
                    break;
                }
            }
            self.drainMicrotasks() catch {};
        }
        agent.abandonAsync(owner);
        listp.clearRetainingCapacity();
    }

    /// `await expr` (synchronous-settling): if the awaited value is a promise,
    /// drive the microtask queue until it settles, then return its value (or
    /// throw its rejection). A non-promise (or thenable-free value) is returned
    /// as-is. Not spec-faithful on ordering, but correct on values.
    fn evalAwait(self: *Interpreter, arg_node: *Node) EvalError!Value {
        return self.awaitValue(try self.eval(arg_node));
    }

    /// `import.meta` — the surrounding module's meta-object (an ordinary
    /// extensible object with a null [[Prototype]]), created once and cached.
    fn evalImportMeta(self: *Interpreter) EvalError!Value {
        if (self.import_meta_slot) |slot| {
            if (slot.obj) |o| return Value.obj(o);
            const o = try gc_mod.allocObj(self.arena);
            o.* = .{ .proto = null };
            slot.obj = o;
            self.import_meta_obj = o;
            return Value.obj(o);
        }
        if (self.import_meta_obj) |o| return Value.obj(o);
        const o = try gc_mod.allocObj(self.arena);
        o.* = .{ .proto = null };
        self.import_meta_obj = o;
        return Value.obj(o);
    }

    /// `import(specifier [, options])` — returns a promise for the module
    /// namespace. Abrupt evaluation of the specifier/options expressions throws
    /// synchronously; later coercion/validation failures reject the promise.
    fn evalImportCall(self: *Interpreter, spec_node: *Node, options_node: ?*Node, phase: []const u8) EvalError!Value {
        const specv = try self.eval(spec_node);
        const optionsv: Value = if (options_node) |on| try self.eval(on) else Value.undef();

        return self.finishImportCall(specv, optionsv, phase);
    }

    /// Finish `import(specifier [, options])` after the argument expressions have
    /// already evaluated. Shared by the tree-walker and the bytecode VM so a
    /// `yield` inside a generator argument suspends before the import promise is
    /// created, while later coercion/validation failures still reject it.
    pub fn finishImportCall(self: *Interpreter, specv: Value, optionsv: Value, phase: []const u8) EvalError!Value {
        const pobj = try promise.newPromise(self);
        const p = promise.promiseOf(Value.obj(pobj)).?;
        const spec = self.toStringV(specv) catch {
            try promise.reject(self, p, self.exception);
            return Value.obj(pobj);
        };
        // EvaluateImportCall steps 10-11: validate the options/import-attributes
        // argument. A non-undefined options that is not an Object, a non-Object
        // `with`, or a non-String attribute value all reject with a TypeError.
        // (Attributes are otherwise ignored — every module is the host's source.)
        const module_type = self.validateImportOptions(optionsv) catch {
            try promise.reject(self, p, self.exception);
            return Value.obj(pobj);
        };
        // Resolve+load the module synchronously through the host (set by the
        // module driver). With no host (plain script), reject with a TypeError.
        if (self.dyn_import) |f| {
            var out: Value = Value.undef();
            if (f(self.dyn_import_ctx.?, self, self.cur_module, spec, phase, module_type, &out)) {
                try promise.resolve(self, p, out);
            } else {
                try promise.reject(self, p, self.exception);
            }
        } else {
            const err = try self.makeError("TypeError", "dynamic import is not available in this context");
            try promise.reject(self, p, err);
        }
        return Value.obj(pobj);
    }

    /// Validate the second argument of `import(specifier, options)` per
    /// EvaluateImportCall: options (when present) must be an Object; its `with`
    /// attribute (when present) must be an Object whose every own enumerable
    /// value is a String. Throws a TypeError otherwise. Returns the `type`
    /// attribute value when present.
    fn validateImportOptions(self: *Interpreter, options: Value) EvalError![]const u8 {
        if (options.isUndefined()) return "";
        if (!options.isObject() or options.asObj().is_symbol or options.asObj().is_bigint)
            return self.throwError("TypeError", "import() options must be an object");
        const attrs = try self.getProperty(options, "with");
        if (attrs.isUndefined()) return "";
        if (!attrs.isObject() or attrs.asObj().is_symbol or attrs.asObj().is_bigint)
            return self.throwError("TypeError", "import() 'with' attributes must be an object");
        var module_type: []const u8 = "";
        const attrs_obj = attrs.asObj();
        const keys = try self.objectOwnKeysList(attrs_obj);
        for (keys) |k| {
            if (value.isSymbolKey(k)) continue;
            if (!try self.objectProtoPropertyIsEnumerable(attrs_obj, k)) continue;
            const v = try self.getProperty(attrs, k);
            if (!v.isString()) return self.throwError("TypeError", "import attribute values must be strings");
            if (std.mem.eql(u8, k, "type")) module_type = v.asStr();
        }
        return module_type;
    }

    /// `await v` on an already-evaluated value (synchronous-settling): perform
    /// Await's `PromiseResolve(%Promise%, v)` step, then drive the microtask
    /// queue until the promise settles and return its value (or throw its
    /// rejection). The PromiseResolve step is observable for promises through a
    /// `.constructor` lookup and assimilates thenables exactly once.
    pub fn awaitValue(self: *Interpreter, v: Value) EvalError!Value {
        const wrapped = try promiseResolveValue(self, v);
        const p = promise.promiseOf(wrapped).?;
        while (promise.snapshot(p).state == .pending) {
            if (self.microtaskDequeue()) |job| {
                self.current_microtask = job;
                promise.runJob(self, job) catch |err| {
                    self.current_microtask = null;
                    return err;
                };
                self.current_microtask = null;
                continue;
            }
            if (self.microtasks == null) break;
            // Threads mode: another thread can settle this shared promise
            // (asyncJoin, cross-thread resolve, asyncHold task delivery). In
            // serialized mode the current interpreter owns the context GIL and
            // must hand it over while waiting. Under `parallel_js`, the GIL
            // object still exists for bookkeeping but this interpreter does not
            // hold it, so yielding is enough after pumping realm tasks.
            if (self.gil) |g| {
                jsthread.pumpTasks(self);
                jsthread.pollPropAsync(self); // expire property waitAsync deadlines
                if (self.use_thread_gil) {
                    g.release();
                    std.Thread.yield() catch {};
                    g.acquire();
                } else {
                    std.Thread.yield() catch {};
                }
                continue;
            }
            if (self.async_waiters) |waiters| {
                if (waiters.items.len > 0) {
                    self.settleAsyncWaiters();
                    continue;
                }
            }
            break; // nothing left to settle it
        }
        const done = promise.snapshot(p);
        return switch (done.state) {
            .fulfilled => done.value,
            .rejected => blk: {
                self.exception = done.value;
                break :blk error.Throw;
            },
            .pending => Value.undef(), // never settled synchronously
        };
    }

    /// A BigInt primitive value with the given `i128` magnitude.
    pub fn makeBigInt(self: *Interpreter, v: i128) EvalError!Value {
        const o = try gc_mod.allocObj(self.arena);
        o.* = .{ .is_bigint = true, .bigint = v };
        try self.finishBigInt(o);
        return Value.obj(o);
    }

    pub fn makeBigIntText(self: *Interpreter, s: []const u8) EvalError!Value {
        if (std.fmt.parseInt(i128, s, 10)) |v| return self.makeBigInt(v) else |_| {}
        const o = try gc_mod.allocObj(self.arena);
        o.* = .{ .is_bigint = true, .bigint_text = s };
        try self.finishBigInt(o);
        return Value.obj(o);
    }

    fn finishBigInt(self: *Interpreter, o: *value.Object) EvalError!void {
        if (self.env.get("BigInt")) |c| {
            if (c.isObject()) o.setProtoAtomic(try self.protoObject(c.asObj()));
        }
    }

    /// ToBigInt(v): a boolean/number(integer)/string/BigInt converts; a
    /// non-integer Number is a RangeError; null/undefined/Symbol a TypeError.
    /// ToBigInt(v) (`number_ok = false`) or the `BigInt(v)` constructor's
    /// NumberToBigInt (`number_ok = true`). The only difference is a Number
    /// argument: ToBigInt rejects it (TypeError), while the constructor converts
    /// an integral Number to the matching BigInt.
    pub fn toBigIntValue(self: *Interpreter, v: Value) EvalError!Value {
        return self.toBigIntValueImpl(v, false);
    }

    pub fn toBigIntValueImpl(self: *Interpreter, v: Value, number_ok: bool) EvalError!Value {
        switch (v.kind()) {
            .object => {
                const o = v.asObj();
                if (o.is_bigint) return v;
                if (o.is_symbol) return self.throwError("TypeError", "Cannot convert a Symbol value to a BigInt");
                const p = try self.toPrimitive(v, .number);
                if (p.isObject() and !p.asObj().is_bigint and !p.asObj().is_symbol) return self.throwError("TypeError", "Cannot convert object to a BigInt");
                return self.toBigIntValueImpl(p, number_ok);
            },
            .boolean => return self.makeBigInt(if (v.asBool()) 1 else 0),
            .number => {
                const n = v.asNum();
                if (!number_ok) return self.throwError("TypeError", "Cannot convert a Number to a BigInt; use BigInt()");
                if (std.math.isNan(n) or std.math.isInf(n) or @trunc(n) != n)
                    return self.throwError("RangeError", "The number is not a safe integer");
                return self.makeBigInt(@intFromFloat(n));
            },
            .string => {
                const s = v.asStr();
                // StringToBigInt: trim whitespace; empty → 0n; otherwise a decimal
                // (optional sign) or a `0x`/`0o`/`0b` literal (no sign).
                const t = std.mem.trim(u8, s, " \t\r\n\x0b\x0c\u{00a0}\u{feff}");
                if (t.len == 0) return self.makeBigInt(0);
                if (t.len > 2 and t[0] == '0' and (t[1] == 'x' or t[1] == 'X')) {
                    return self.makeBigIntText((try canonicalBigIntRadixString(self.arena, t[2..], 16)) orelse
                        return self.throwError("SyntaxError", "Cannot convert string to a BigInt"));
                }
                if (t.len > 2 and t[0] == '0' and (t[1] == 'o' or t[1] == 'O')) {
                    return self.makeBigIntText((try canonicalBigIntRadixString(self.arena, t[2..], 8)) orelse
                        return self.throwError("SyntaxError", "Cannot convert string to a BigInt"));
                }
                if (t.len > 2 and t[0] == '0' and (t[1] == 'b' or t[1] == 'B')) {
                    return self.makeBigIntText((try canonicalBigIntRadixString(self.arena, t[2..], 2)) orelse
                        return self.throwError("SyntaxError", "Cannot convert string to a BigInt"));
                }
                return self.makeBigIntText((try canonicalBigIntDecimalString(self.arena, t)) orelse
                    return self.throwError("SyntaxError", "Cannot convert string to a BigInt"));
            },
            .null, .undefined => return self.throwError("TypeError", "Cannot convert undefined or null to a BigInt"),
        }
    }

    /// Box a primitive into a wrapper object (`new Number/String/Boolean`). Its
    /// prototype is the in-flight constructor's `.prototype`, so methods,
    /// `instanceof`, and `[object Number|String|Boolean]` all resolve correctly.
    pub fn makeWrapper(self: *Interpreter, p: Value) EvalError!Value {
        const o = try gc_mod.allocObj(self.arena);
        o.* = .{ .prim = p };
        if (self.new_target.isObject()) {
            const intrinsic: []const u8 = switch (p.kind()) {
                .string => "String",
                .number => "Number",
                .boolean => "Boolean",
                else => "Object",
            };
            o.setProtoAtomic(try self.ctorRealmIntrinsicProto(self.new_target.asObj(), intrinsic));
        }
        return Value.obj(o);
    }

    /// Create an instance for `new ctor(...)`: a fresh object whose prototype is
    /// the constructor's `.prototype`.
    pub fn newInstance(self: *Interpreter, ctor: *value.Object) EvalError!Value {
        const obj = try gc_mod.allocObj(self.arena);
        obj.* = .{ .ctor_ref = ctor, .proto = try self.protoObject(ctor) };
        return Value.obj(obj);
    }

    /// Allocate a fresh array object.
    pub fn newArray(self: *Interpreter) EvalError!Value {
        const obj = try gc_mod.allocObj(self.arena);
        obj.* = .{ .is_array = true, .proto = self.arrayProto() };
        return Value.obj(obj);
    }

    fn newArrayInRealm(self: *Interpreter, env: *Environment) EvalError!Value {
        const obj = try gc_mod.allocObj(self.arena);
        const proto: ?*value.Object = blk: {
            const av = env.get("Array") orelse break :blk null;
            if (!av.isObject()) break :blk null;
            const p = av.asObj().getOwn("prototype") orelse break :blk null;
            break :blk if (p.isObject()) p.asObj() else null;
        };
        obj.* = .{ .is_array = true, .proto = proto };
        return Value.obj(obj);
    }

    /// ArrayCreate(length): allocate a fresh array with a logical length.
    fn newArrayWithLength(self: *Interpreter, len: usize) EvalError!Value {
        if (len > 4294967295) return self.throwError("RangeError", "Invalid array length");
        const arr = try self.newArray();
        arr.asObj().extendArrayLengthFloor(len);
        return arr;
    }

    fn newArrayWithLengthInRealm(self: *Interpreter, env: *Environment, len: usize) EvalError!Value {
        if (len > 4294967295) return self.throwError("RangeError", "Invalid array length");
        const arr = try self.newArrayInRealm(env);
        arr.asObj().extendArrayLengthFloor(len);
        return arr;
    }

    /// `Array.prototype`, resolved from the live `Array` binding, so array
    /// instances inherit from it (inherited index access, `in`, iteration over
    /// inherited indices). Null only before globals are installed.
    fn arrayProto(self: *Interpreter) ?*value.Object {
        const av = self.env.get("Array") orelse return null;
        if (!av.isObject()) return null;
        const p = av.asObj().getOwn("prototype") orelse return null;
        return if (p.isObject()) p.asObj() else null;
    }

    /// `%Object.prototype%`, the [[Prototype]] of an ordinary plain object —
    /// resolved through the live `Object` binding so it's the *current realm's*
    /// prototype (mirrors `arrayProto`/`functionProto`). Null during the early
    /// bootstrap window before `Object` is installed (then a plain object is
    /// created proto-less, which is fine — the intrinsics wire their protos
    /// explicitly and don't go through `newObject`).
    fn objectProto(self: *Interpreter) ?*value.Object {
        const ov = self.env.get("Object") orelse return null;
        if (!ov.isObject()) return null;
        const p = ov.asObj().getOwn("prototype") orelse return null;
        return if (p.isObject()) p.asObj() else null;
    }

    /// The shared `%ThrowTypeError%` intrinsic, stashed as the get/set of
    /// `Function.prototype.caller` during setup — reused by the strict
    /// `arguments.callee` and `arguments.caller` poison-pill accessors.
    pub fn throwTypeError(self: *Interpreter) ?*value.Object {
        if (self.env.get("\x00ThrowTypeError")) |v| {
            if (v.isObject()) return v.asObj();
        }
        const fp = self.functionProto() orelse return null;
        const acc = fp.getAccessor("caller") orelse return null;
        if (acc.get) |g| if (g.isObject()) return g.asObj();
        return null;
    }

    /// `Function.prototype`, the [[Prototype]] of every function object — so
    /// `fn instanceof Function`, `Object.getPrototypeOf(fn)`, and inherited
    /// `call`/`apply`/`bind`/`toString` all resolve through the chain.
    pub fn functionProto(self: *Interpreter) ?*value.Object {
        const fv = self.env.get("Function") orelse return null;
        if (!fv.isObject()) return null;
        const p = fv.asObj().getOwn("prototype") orelse return null;
        return if (p.isObject()) p.asObj() else null;
    }

    /// `{ ...src }` CopyDataProperties: copy `src`'s own enumerable properties /
    /// array elements into `target` (a string spreads its chars by index).
    /// Shared by the tree-walker object literal and the VM `init_spread` op.
    pub fn spreadDataProps(self: *Interpreter, target: Value, src: Value) EvalError!void {
        switch (src.kind()) {
            .object => {
                const so = src.asObj();
                // A Proxy source must go through [[OwnPropertyKeys]] then, per key,
                // [[GetOwnProperty]] — invoking the `ownKeys` and
                // `getOwnPropertyDescriptor` traps in order (and reading only
                // enumerable keys via Get) rather than its empty raw key set.
                if (so.proxy_handler != null or so.proxy_revoked) {
                    for (try self.objectOwnKeysList(so)) |k| {
                        if (value.isPrivateKey(k)) continue;
                        const desc = try builtins.objectGetOwnPropertyDescriptor(self, Value.undef(), &.{ src, self.keyToValue(k) });
                        if (!(desc.isObject() and (try self.getProperty(desc, "enumerable")).toBoolean())) continue;
                        try self.setMember(target, k, try self.getProperty(src, k));
                    }
                    return;
                }
                if (so.is_array) {
                    for (so.elements.items, 0..) |el, i| {
                        try self.setMember(target, try std.fmt.allocPrint(self.arena, "{d}", .{i}), el);
                    }
                }
                for (try so.ownKeys(self.arena)) |k| {
                    if (value.isPrivateKey(k)) continue;
                    if (!so.getAttr(k).enumerable) continue;
                    try self.setMember(target, k, try self.getProperty(src, k));
                }
            },
            .string => for (src.asStr(), 0..) |ch, i| {
                try self.setMember(target, try std.fmt.allocPrint(self.arena, "{d}", .{i}), Value.str(try self.arena.dupe(u8, &.{ch})));
            },
            else => {}, // null/undefined/number/boolean spread → no own enumerable props
        }
    }

    /// Install an object-literal getter/setter (the VM `init_getter`/`init_setter`
    /// ops). Mirrors the `.get`/`.set` arms of `evalObjectLit`.
    pub fn vmInitAccessor(self: *Interpreter, obj: Value, key: Value, fn_val: Value, is_get: bool) EvalError!void {
        const k = try self.keyOf(key);
        const name = try self.keyDisplayName(key);
        if (funcOf(fn_val)) |f| f.home_object = obj.asObj();
        try self.nameAccessor(fn_val, if (is_get) "get" else "set", name);
        if (is_get)
            try self.defineAccessor(obj.asObj(), k, fn_val, null)
        else
            try self.defineAccessor(obj.asObj(), k, null, fn_val);
    }

    fn evalObjectLit(self: *Interpreter, props: []ast.Property) EvalError!Value {
        const v = try self.newObject();
        for (props) |p| {
            if (p.is_spread) {
                const src = try self.eval(p.value);
                try self.spreadDataProps(v, src);
                continue;
            }
            // ToPropertyKey ONCE (its valueOf/@@toPrimitive runs a single time);
            // keyOf and keyDisplayName then read the resulting primitive without
            // re-coercing.
            const kv: ?Value = if (p.key_expr) |ke| try self.toPropertyKeyValue(try self.eval(ke)) else null;
            const key = if (kv) |k| try self.keyOf(k) else p.key;
            // The name a method/accessor takes from this key (a symbol shows as
            // `[description]`, not its internal key).
            const name_str = if (kv) |k| try self.keyDisplayName(k) else p.key;
            switch (p.accessor) {
                .none => {
                    const pv = try self.eval(p.value);
                    if (p.proto_setter) { // only the `__proto__: value` colon form
                        // Only an Object or null sets [[Prototype]]; any other
                        // value (incl. a Symbol/BigInt, which are object-tagged) is
                        // discarded without creating an own `__proto__` property.
                        if (builtins.isRealObject(pv)) v.asObj().proto = pv.asObj();
                        if (pv.isNull()) v.asObj().proto = null;
                        continue;
                    }
                    // A concise method's [[HomeObject]] is the object being built,
                    // so `super` inside it resolves on the object's prototype.
                    if (p.value.* == .function and p.value.function.is_method)
                        if (funcOf(pv)) |f| {
                            f.home_object = v.asObj();
                        };
                    try self.maybeNameAnon(pv, p.value, name_str); // `{ x: function(){} }` ⇒ name "x"
                    try self.setProp(v.asObj(), key, pv);
                },
                .get => {
                    const gv = try self.eval(p.value);
                    if (funcOf(gv)) |f| f.home_object = v.asObj();
                    try self.nameAccessor(gv, "get", name_str);
                    try self.defineAccessor(v.asObj(), key, gv, null);
                },
                .set => {
                    const sv = try self.eval(p.value);
                    if (funcOf(sv)) |f| f.home_object = v.asObj();
                    try self.nameAccessor(sv, "set", name_str);
                    try self.defineAccessor(v.asObj(), key, null, sv);
                },
            }
        }
        return v;
    }

    /// Build a `RegExp` instance with `source`/`flags`/`lastIndex` and the
    /// `global`/`ignoreCase`/`multiline` booleans. Matching (test/exec) is
    /// dispatched in `regexMethod`, backed by zig-regex.
    pub fn regexpPrototypeFromNewTarget(self: *Interpreter) EvalError!?*value.Object {
        if (self.new_target.isObject()) {
            const p = try self.getProperty(self.new_target, "prototype");
            if (p.isObject() and !p.asObj().is_symbol and !p.asObj().is_bigint) return p.asObj();
        }
        return null;
    }

    pub fn makeRegex(self: *Interpreter, pattern: []const u8, flags: []const u8) EvalError!Value {
        try self.validateRegExpFlags(flags);
        const o = (try self.newObject()).asObj();
        o.is_regex = true;
        // An empty pattern's [[OriginalSource]] is "(?:)" (so `//`, `new RegExp()`,
        // `new RegExp("")` all match the empty string and report that source).
        const source = if (pattern.len == 0) "(?:)" else pattern;
        // source / flags live in internal slots; `lastIndex` is the one real own
        // data property (writable). source/flags/global/… resolve via the
        // RegExp.prototype accessor getters.
        o.regex_source = try self.arena.dupe(u8, source);
        o.regex_flags = try self.arena.dupe(u8, flags);
        try self.setProp(o, "lastIndex", Value.num(0));
        try o.setAttr(self.arena, "lastIndex", .{ .writable = true, .enumerable = false, .configurable = false });
        if (self.new_target.isObject()) {
            // GetPrototypeFromConstructor: new.target.prototype, or new.target's
            // realm's %RegExp.prototype% when that is not an Object.
            o.setProtoAtomic(try self.ctorRealmIntrinsicProto(self.new_target.asObj(), "RegExp"));
        } else if (self.env.get("RegExp")) |c| {
            if (c.isObject()) o.setProtoAtomic(try self.protoObject(c.asObj()));
        }
        // Eagerly compile to validate the pattern — RegExp construction reports a
        // SyntaxError for an invalid pattern (the compiled form is discarded;
        // methods recompile on demand).
        _ = try self.compileRegex(o);
        return Value.obj(o);
    }

    fn validateRegExpFlags(self: *Interpreter, flags: []const u8) EvalError!void {
        // Each flag must be one of `dgimsuvy` with no duplicates. `u` and `v` are
        // mutually exclusive.
        var seen = std.mem.zeroes([128]bool);
        for (flags) |f| {
            if (f >= 128 or std.mem.indexOfScalar(u8, "dgimsuvy", f) == null or seen[f])
                return self.throwError("SyntaxError", "Invalid regular expression flags");
            seen[f] = true;
        }
        if (seen['u'] and seen['v']) return self.throwError("SyntaxError", "Invalid regular expression flags");
    }

    fn setRegExpLastIndexValue(self: *Interpreter, o: *value.Object, v: Value) EvalError!void {
        if (o.getOwn("lastIndex") != null and !o.getAttr("lastIndex").writable)
            return self.throwError("TypeError", "Cannot assign to read only property 'lastIndex'");
        try self.setProp(o, "lastIndex", v);
    }

    fn setRegExpLastIndex(self: *Interpreter, o: *value.Object, n: f64) EvalError!void {
        try self.setRegExpLastIndexValue(o, Value.num(n));
    }

    fn compileRegex(self: *Interpreter, o: *value.Object) EvalError!*regex.Regex {
        if (o.regex_compiled) |cached| return @ptrCast(@alignCast(cached));
        const raw_src = o.regex_source;
        const flags = o.regex_flags;
        const unicode = std.mem.indexOfScalar(u8, flags, 'u') != null or std.mem.indexOfScalar(u8, flags, 'v') != null;
        const src = if (unicode) raw_src else try self.regexpSearchInput(raw_src, false);
        const cf = regex.common.CompileFlags{
            .case_insensitive = std.mem.indexOfScalar(u8, flags, 'i') != null,
            .multiline = std.mem.indexOfScalar(u8, flags, 'm') != null,
            // `s` (dotAll): `.` also matches line terminators.
            .dot_all = std.mem.indexOfScalar(u8, flags, 's') != null,
            // `u`/`v` (unicode): pattern is interpreted as Unicode code points
            // (enables `\u{...}` and code-point-aware classes in the engine).
            .unicode = unicode,
            .unicode_sets = std.mem.indexOfScalar(u8, flags, 'v') != null,
            .ecmascript = true,
        };
        const compiled = try self.arena.create(regex.Regex);
        compiled.* = regex.Regex.compileWithFlags(self.arena, src, cf) catch
            return self.throwError("SyntaxError", "invalid regular expression");
        o.regex_compiled = @ptrCast(compiled);
        return compiled;
    }

    /// Whether `o` is the `%RegExp.prototype%` intrinsic (which the source/flags
    /// accessors special-case: they return "(?:)" / "" / undefined rather than
    /// throwing).
    fn isRegExpProto(self: *Interpreter, o: *value.Object) bool {
        if (self.env.get("RegExp")) |c| if (c.isObject()) {
            if (c.asObj().getOwn("prototype")) |p| if (p.isObject()) return p.asObj() == o;
        };
        return false;
    }

    fn regexMethod(self: *Interpreter, o: *value.Object, name: []const u8, args: []const Value) EvalError!?Value {
        if (eq(name, "test")) {
            const r = (try self.regexMethod(o, "exec", args)).?;
            return Value.boolVal(!r.isNull());
        }
        if (eq(name, "compile")) {
            if (regExpAccessorData(self)) |data| {
                if (o.protoAtomic() != data.proto)
                    return throwErrorInRealm(self, data.realm, "TypeError", "RegExp.prototype.compile called on an incompatible RegExp");
            }
            var pattern: []const u8 = "";
            var flags: []const u8 = "";
            const pattern_v = if (args.len > 0) args[0] else Value.undef();
            const flags_v = if (args.len > 1) args[1] else Value.undef();
            if (pattern_v.isObject() and pattern_v.asObj().is_regex) {
                if (!flags_v.isUndefined()) return self.throwError("TypeError", "flags supplied with a RegExp pattern");
                pattern = pattern_v.asObj().regex_source;
                flags = pattern_v.asObj().regex_flags;
            } else {
                if (!pattern_v.isUndefined()) pattern = try self.toStringV(pattern_v);
                if (!flags_v.isUndefined()) flags = try self.toStringV(flags_v);
            }
            try self.validateRegExpFlags(flags);
            const source = if (pattern.len == 0) "(?:)" else pattern;
            const old_source = o.regex_source;
            const old_flags = o.regex_flags;
            const old_compiled = o.regex_compiled;
            o.regex_source = try self.arena.dupe(u8, source);
            o.regex_flags = try self.arena.dupe(u8, flags);
            o.regex_compiled = null;
            _ = self.compileRegex(o) catch |err| {
                o.regex_source = old_source;
                o.regex_flags = old_flags;
                o.regex_compiled = old_compiled;
                return err;
            };
            try self.setRegExpLastIndex(o, 0);
            return Value.obj(o);
        }
        if (eq(name, "exec")) {
            const input = try self.toStringV(arg0(args));
            // RegExpBuiltinExec always reads/coerces `lastIndex`; it only uses it
            // as the search start for global/sticky regexps.
            const li = toLen(try self.toNumberV(try self.getProperty(Value.obj(o), "lastIndex")));
            const flags = o.regex_flags;
            const global = std.mem.indexOfScalar(u8, flags, 'g') != null;
            const sticky = std.mem.indexOfScalar(u8, flags, 'y') != null;
            const unicode = std.mem.indexOfScalar(u8, flags, 'u') != null or std.mem.indexOfScalar(u8, flags, 'v') != null;
            const search_input = try self.regexpSearchInput(input, unicode);
            const start_units = if (global or sticky) li else 0;
            if (start_units > utf16LenOfString(input)) {
                if (global or sticky) try self.setRegExpLastIndex(o, 0);
                return Value.nul();
            }
            const start = byteOffsetForUtf16Index(search_input, start_units);
            const re = try self.compileRegex(o);
            const found = re.findFrom(search_input, start) catch null;
            if (found) |m| {
                // Sticky matches must begin exactly at lastIndex.
                if (sticky and m.start != start) {
                    try self.setRegExpLastIndex(o, 0);
                    return Value.nul();
                }
                const mstart = m.start;
                const mend = m.end;
                if (global or sticky) try self.setRegExpLastIndex(o, @floatFromInt(utf16IndexForByteOffset(search_input, mend)));
                recordRegexpLegacy(self, search_input, mstart, mend, m.captures);
                const arr = try self.newArray();
                try arr.asObj().elements.append(arr.asObj().elementsAllocator(self.arena), Value.str(try self.stringSliceFromSearchSpan(input, search_input, mstart, mend)));
                for (0..m.captures.len) |i| try arr.asObj().elements.append(arr.asObj().elementsAllocator(self.arena), try self.captureVal(m, i));
                try self.setProp(arr.asObj(), "index", Value.num(@floatFromInt(utf16IndexForByteOffset(search_input, mstart))));
                try self.setProp(arr.asObj(), "input", Value.str(input));
                const groups = try self.regexGroups(re, m);
                try self.setProp(arr.asObj(), "groups", if (groups) |g| Value.obj(g) else Value.undef());
                // The `d` (hasIndices) flag adds a parallel match-indices array.
                if (std.mem.indexOfScalar(u8, flags, 'd') != null)
                    try self.setProp(arr.asObj(), "indices", Value.obj(try self.makeIndicesArray(re, m, search_input, 0)));
                return arr;
            }
            if (global or sticky) try self.setRegExpLastIndex(o, 0);
            return Value.nul();
        }
        if (eq(name, "toString")) {
            return try self.regexpToString(Value.obj(o));
        }
        return null;
    }

    /// RegExpExec(R, S): use a callable `exec` method when present, validate its
    /// result, otherwise fall back to the built-in matcher only for true RegExp
    /// instances.
    fn regexpExecGeneric(self: *Interpreter, rx: Value, s: []const u8) EvalError!Value {
        if (!rx.isObject()) return self.throwError("TypeError", "RegExpExec receiver must be an object");
        const exec = try self.getProperty(rx, "exec");
        if (exec.isCallable()) {
            const result = try self.callValueWithThis(exec, &.{Value.str(s)}, rx);
            if (result.isNull() or (result.isObject() and !result.asObj().is_symbol and !result.asObj().is_bigint)) return result;
            return self.throwError("TypeError", "RegExp exec result must be an object or null");
        }
        if (rx.asObj().is_regex) return (try self.regexMethod(rx.asObj(), "exec", &.{Value.str(s)})).?;
        return self.throwError("TypeError", "RegExp exec property is not callable");
    }

    fn setRegExpLikeLastIndex(self: *Interpreter, rx: Value, n: f64) EvalError!void {
        try self.setRegExpLikeLastIndexValue(rx, Value.num(n));
    }

    fn setRegExpLikeLastIndexValue(self: *Interpreter, rx: Value, v: Value) EvalError!void {
        if (rx.isObject() and rx.asObj().is_regex) return self.setRegExpLastIndexValue(rx.asObj(), v);
        if (rx.isObject()) {
            const was_strict = self.strict;
            self.strict = true;
            defer self.strict = was_strict;
            return self.setMember(rx, "lastIndex", v);
        }
        return self.throwError("TypeError", "RegExp receiver must be an object");
    }

    fn regexpSameValue(a: Value, b: Value) bool {
        if (a.isNumber() and b.isNumber()) {
            const x = a.asNum();
            const y = b.asNum();
            if (std.math.isNan(x) and std.math.isNan(y)) return true;
            if (x == 0 and y == 0) return (1.0 / x) == (1.0 / y);
            return x == y;
        }
        return value.strictEquals(a, b);
    }

    fn jsStringSeqLen(s: []const u8, i: usize) usize {
        if (wtf8SurrogateAt(s, i) != null) return 3;
        return utf8SeqLen(s, i);
    }

    fn utf16LenOfSeq(s: []const u8, i: usize) usize {
        if (wtf8SurrogateAt(s, i) != null) return 1;
        return if (utf8SeqLen(s, i) == 4) @as(usize, 2) else 1;
    }

    fn utf16LenOfString(s: []const u8) usize {
        var units: usize = 0;
        var i: usize = 0;
        while (i < s.len) {
            units += utf16LenOfSeq(s, i);
            i += jsStringSeqLen(s, i);
        }
        return units;
    }

    const StringCodeUnit = struct {
        unit: u16,
        astral: ?u21 = null,
    };

    fn stringCodeUnitAt(s: []const u8, index: usize) ?StringCodeUnit {
        var units: usize = 0;
        var i: usize = 0;
        while (i < s.len) {
            if (wtf8SurrogateAt(s, i)) |cp| {
                if (units == index) return .{ .unit = @intCast(cp) };
                units += 1;
                i += 3;
                continue;
            }

            const seq_len = utf8SeqLen(s, i);
            if (seq_len == 4 and i + seq_len <= s.len) {
                if (std.unicode.utf8Decode(s[i .. i + seq_len])) |cp| {
                    if (cp > 0xFFFF) {
                        const u = cp - 0x10000;
                        if (units == index) return .{ .unit = @intCast(0xD800 + (u >> 10)), .astral = cp };
                        if (units + 1 == index) return .{ .unit = @intCast(0xDC00 + (u & 0x3FF)) };
                        units += 2;
                        i += seq_len;
                        continue;
                    }
                } else |_| {}
            }

            const cp = if (seq_len > 1 and i + seq_len <= s.len)
                std.unicode.utf8Decode(s[i .. i + seq_len]) catch @as(u21, s[i])
            else
                @as(u21, s[i]);
            if (units == index) return .{ .unit = @intCast(cp & 0xFFFF) };
            units += 1;
            i += seq_len;
        }
        return null;
    }

    fn stringFromCodeUnit(self: *Interpreter, unit: u16) EvalError![]const u8 {
        var buf: std.ArrayListUnmanaged(u8) = .empty;
        if (unit >= 0xD800 and unit <= 0xDFFF) {
            try appendWtf8CodeUnit(&buf, self.arena, unit);
        } else {
            var tmp: [3]u8 = undefined;
            const n = std.unicode.utf8Encode(@intCast(unit), &tmp) catch 1;
            if (n == 1 and unit > 0x7F) {
                try appendWtf8CodeUnit(&buf, self.arena, unit);
            } else {
                try buf.appendSlice(self.arena, tmp[0..n]);
            }
        }
        return buf.toOwnedSlice(self.arena);
    }

    fn stringIndexValue(self: *Interpreter, s: []const u8, index: usize) EvalError!?Value {
        const cu = stringCodeUnitAt(s, index) orelse return null;
        return Value.str(try self.stringFromCodeUnit(cu.unit));
    }

    fn appendStringUtf16Prefix(self: *Interpreter, buf: *std.ArrayListUnmanaged(u8), s: []const u8, units: usize) EvalError!void {
        var copied: usize = 0;
        var i: usize = 0;
        while (i < s.len and copied < units) {
            const seq_len = jsStringSeqLen(s, i);
            const seq_units = utf16LenOfSeq(s, i);
            if (copied + seq_units <= units) {
                try buf.appendSlice(self.arena, s[i .. i + seq_len]);
                copied += seq_units;
            } else {
                const cu = stringCodeUnitAt(s, copied) orelse return;
                try buf.appendSlice(self.arena, try self.stringFromCodeUnit(cu.unit));
                copied += 1;
            }
            i += seq_len;
        }
    }

    fn stringSliceUtf16(self: *Interpreter, s: []const u8, start: usize, end: usize) EvalError![]const u8 {
        var buf: std.ArrayListUnmanaged(u8) = .empty;
        var units: usize = 0;
        var i: usize = 0;
        while (i < s.len and units < end) {
            const seq_len = jsStringSeqLen(s, i);
            const seq_units = utf16LenOfSeq(s, i);
            const seq_start = units;
            const seq_end = units + seq_units;
            if (seq_end <= start) {
                units = seq_end;
                i += seq_len;
                continue;
            }
            if (start <= seq_start and seq_end <= end) {
                try buf.appendSlice(self.arena, s[i .. i + seq_len]);
            } else {
                var u = @max(start, seq_start);
                while (u < @min(end, seq_end)) : (u += 1) {
                    const cu = stringCodeUnitAt(s, u) orelse break;
                    try buf.appendSlice(self.arena, try self.stringFromCodeUnit(cu.unit));
                }
            }
            units = seq_end;
            i += seq_len;
        }
        return buf.toOwnedSlice(self.arena);
    }

    fn stringPosition(self: *Interpreter, s: []const u8, v: Value) EvalError!?usize {
        const n = try self.toNumberV(v);
        const pos = if (std.math.isNan(n)) @as(f64, 0) else @trunc(n);
        if (pos < 0 or pos >= @as(f64, @floatFromInt(utf16LenOfString(s)))) return null;
        return @intFromFloat(pos);
    }

    fn stringClampPosition(self: *Interpreter, s: []const u8, v: Value, default_pos: usize) EvalError!usize {
        if (v.isUndefined()) return default_pos;
        const n = try self.toNumberV(v);
        if (std.math.isNan(n) or n <= 0) return 0;
        const len = utf16LenOfString(s);
        if (n >= @as(f64, @floatFromInt(len))) return len;
        return @intFromFloat(@trunc(n));
    }

    fn byteOffsetForUtf16Index(s: []const u8, index: usize) usize {
        var units: usize = 0;
        var i: usize = 0;
        while (i < s.len) {
            if (index <= units) return i;
            const seq_len = jsStringSeqLen(s, i);
            const seq_units = utf16LenOfSeq(s, i);
            if (index < units + seq_units) return i + seq_len;
            units += seq_units;
            i += seq_len;
        }
        return s.len;
    }

    fn utf16IndexForByteOffset(s: []const u8, byte_offset: usize) usize {
        var units: usize = 0;
        var i: usize = 0;
        const target = @min(byte_offset, s.len);
        while (i < s.len and i < target) {
            units += utf16LenOfSeq(s, i);
            i += jsStringSeqLen(s, i);
        }
        return units;
    }

    fn appendWtf8CodeUnit(buf: *std.ArrayListUnmanaged(u8), a: std.mem.Allocator, cu: u16) !void {
        try buf.append(a, @intCast(0xE0 | (cu >> 12)));
        try buf.append(a, @intCast(0x80 | ((cu >> 6) & 0x3F)));
        try buf.append(a, @intCast(0x80 | (cu & 0x3F)));
    }

    fn regexpSearchInput(self: *Interpreter, input: []const u8, unicode: bool) ![]const u8 {
        if (unicode) return input;
        var out: std.ArrayListUnmanaged(u8) = .empty;
        var changed = false;
        var i: usize = 0;
        while (i < input.len) {
            const seq_len = utf8SeqLen(input, i);
            if (seq_len == 4) {
                const cp = std.unicode.utf8Decode(input[i .. i + seq_len]) catch 0;
                if (cp > 0xFFFF) {
                    const u = cp - 0x10000;
                    try appendWtf8CodeUnit(&out, self.arena, @intCast(0xD800 + (u >> 10)));
                    try appendWtf8CodeUnit(&out, self.arena, @intCast(0xDC00 + (u & 0x3FF)));
                    changed = true;
                    i += seq_len;
                    continue;
                }
            }
            try out.appendSlice(self.arena, input[i .. i + seq_len]);
            i += seq_len;
        }
        return if (changed) out.items else input;
    }

    fn stringSliceFromSearchSpan(self: *Interpreter, input: []const u8, search_input: []const u8, start: usize, end: usize) EvalError![]const u8 {
        const start_units = utf16IndexForByteOffset(search_input, start);
        const end_units = utf16IndexForByteOffset(search_input, end);
        var buf: std.ArrayListUnmanaged(u8) = .empty;
        try appendUtf16Slice(&buf, self.arena, input, start_units, end_units);
        return try buf.toOwnedSlice(self.arena);
    }

    fn appendUtf16Slice(buf: *std.ArrayListUnmanaged(u8), a: std.mem.Allocator, s: []const u8, start: usize, end: usize) !void {
        if (start >= end) return;
        var units: usize = 0;
        var i: usize = 0;
        while (i < s.len and units < end) {
            const seq_len = jsStringSeqLen(s, i);
            const seq_units = utf16LenOfSeq(s, i);
            if (units + seq_units <= start) {
                units += seq_units;
                i += seq_len;
                continue;
            }
            if (seq_units == 2 and seq_len == 4) {
                const cp = std.unicode.utf8Decode(s[i .. i + seq_len]) catch 0;
                if (cp > 0xFFFF) {
                    const u = cp - 0x10000;
                    const high: u16 = @intCast(0xD800 + (u >> 10));
                    const low: u16 = @intCast(0xDC00 + (u & 0x3FF));
                    const include_high = start <= units and units < end;
                    const include_low = start <= units + 1 and units + 1 < end;
                    if (include_high and include_low) {
                        try buf.appendSlice(a, s[i .. i + seq_len]);
                    } else {
                        if (include_high) try appendWtf8CodeUnit(buf, a, high);
                        if (include_low) try appendWtf8CodeUnit(buf, a, low);
                    }
                    units += seq_units;
                    i += seq_len;
                    continue;
                }
            }
            if (units >= start and units < end) try buf.appendSlice(a, s[i .. i + seq_len]);
            units += seq_units;
            i += seq_len;
        }
    }

    fn advanceStringIndex(s: []const u8, index: usize, unicode: bool) usize {
        if (!unicode) return index + 1;
        var units: usize = 0;
        var b: usize = 0;
        while (b < s.len) {
            const seq_len = jsStringSeqLen(s, b);
            const seq_units = utf16LenOfSeq(s, b);
            if (index == units) {
                if (seq_units == 2) return index + 2;
                const first = wtf8SurrogateAt(s, b);
                if (first != null and first.? >= 0xD800 and first.? <= 0xDBFF) {
                    const next = b + seq_len;
                    if (wtf8SurrogateAt(s, next)) |second| {
                        if (second >= 0xDC00 and second <= 0xDFFF) return index + 2;
                    }
                }
                return index + 1;
            }
            if (index < units + seq_units) return index + 1;
            units += seq_units;
            b += seq_len;
        }
        return index + 1;
    }

    fn isRegExpObjectValue(v: Value) bool {
        return v.isObject() and !v.asObj().is_symbol and !v.asObj().is_bigint;
    }

    /// RegExp.prototype[@@matchAll]: build a lazy %RegExpStringIterator% over a
    /// species-constructed matcher (so a subclass's exec/lastIndex drive iteration).
    fn regexpMatchAll(self: *Interpreter, this: Value, s: []const u8) EvalError!Value {
        if (!this.isObject()) return self.throwError("TypeError", "RegExp.prototype[Symbol.matchAll] called on a non-object");
        const default_ctor = self.env.get("RegExp") orelse return self.throwError("TypeError", "RegExp is not defined");
        const c = try self.speciesConstructor(this, default_ctor);
        const flags = try self.toStringV(try self.getProperty(this, "flags"));
        const matcher = try self.construct(c, &.{ this, Value.str(flags) });
        const last_index = toLen(try self.toNumberV(try self.getProperty(this, "lastIndex")));
        try self.setRegExpLikeLastIndex(matcher, @floatFromInt(last_index));
        const global = std.mem.indexOfScalar(u8, flags, 'g') != null;
        const unicode = std.mem.indexOfScalar(u8, flags, 'u') != null or std.mem.indexOfScalar(u8, flags, 'v') != null;
        return self.createRegExpStringIterator(matcher, s, global, unicode);
    }

    fn createRegExpStringIterator(self: *Interpreter, matcher: Value, s: []const u8, global: bool, unicode: bool) EvalError!Value {
        const it = try gc_mod.allocObj(self.arena);
        it.* = .{};
        if (self.env.get("\x00ReStrIterProto")) |p| {
            if (p.isObject()) it.setProtoAtomic(p.asObj());
        }
        try self.setProp(it, "__re", matcher);
        try self.setProp(it, "__str", Value.str(try self.arena.dupe(u8, s)));
        try self.setProp(it, "__g", Value.boolVal(global));
        try self.setProp(it, "__u", Value.boolVal(unicode));
        try self.setProp(it, "__done", Value.boolVal(false));
        return Value.obj(it);
    }

    fn regexpMatch(self: *Interpreter, rx: Value, s: []const u8) EvalError!Value {
        if (!isRegExpObjectValue(rx)) return self.throwError("TypeError", "RegExp.prototype[Symbol.match] called on a non-object");
        const flags = try self.toStringV(try self.getProperty(rx, "flags"));
        const global = std.mem.indexOfScalar(u8, flags, 'g') != null;
        if (!global) return try self.regexpExecGeneric(rx, s);
        const full_unicode = std.mem.indexOfScalar(u8, flags, 'u') != null or std.mem.indexOfScalar(u8, flags, 'v') != null;

        try self.setRegExpLikeLastIndex(rx, 0);
        const arr = try self.newArray();
        while (true) {
            const result = try self.regexpExecGeneric(rx, s);
            if (result.isNull()) return if (arr.asObj().elements.items.len == 0) Value.nul() else arr;

            const match_v = try self.getProperty(result, "0");
            const match_s = try self.toStringV(match_v);
            try arr.asObj().elements.append(arr.asObj().elementsAllocator(self.arena), Value.str(try self.arena.dupe(u8, match_s)));

            if (match_s.len == 0) {
                const li = toLen(try self.toNumberV(try self.getProperty(rx, "lastIndex")));
                try self.setRegExpLikeLastIndex(rx, @floatFromInt(advanceStringIndex(s, li, full_unicode)));
            }
        }
    }

    fn regexpSearch(self: *Interpreter, rx: Value, s: []const u8) EvalError!Value {
        if (!isRegExpObjectValue(rx)) return self.throwError("TypeError", "RegExp.prototype[Symbol.search] called on a non-object");
        const previous_last_index = try self.getProperty(rx, "lastIndex");
        if (!regexpSameValue(previous_last_index, Value.num(0))) try self.setRegExpLikeLastIndex(rx, 0);
        const result = try self.regexpExecGeneric(rx, s);
        const current_last_index = try self.getProperty(rx, "lastIndex");
        if (!regexpSameValue(current_last_index, previous_last_index)) try self.setRegExpLikeLastIndexValue(rx, previous_last_index);
        if (result.isNull()) return Value.num(-1);
        const index = try self.toNumberV(try self.getProperty(result, "index"));
        return Value.num(@floatFromInt(toLen(index)));
    }

    fn regexpReplace(self: *Interpreter, rx: Value, s: []const u8, replace_value: Value) EvalError!Value {
        if (!isRegExpObjectValue(rx)) return self.throwError("TypeError", "RegExp.prototype[Symbol.replace] called on a non-object");
        const functional_replace = replace_value.isCallable();
        const replace_string = if (functional_replace) "" else try self.toStringV(replace_value);
        const flags = try self.toStringV(try self.getProperty(rx, "flags"));
        const global = std.mem.indexOfScalar(u8, flags, 'g') != null;
        const full_unicode = global and (std.mem.indexOfScalar(u8, flags, 'u') != null or std.mem.indexOfScalar(u8, flags, 'v') != null);

        if (global) try self.setRegExpLikeLastIndex(rx, 0);

        var results: std.ArrayListUnmanaged(Value) = .empty;
        while (true) {
            const result = try self.regexpExecGeneric(rx, s);
            if (result.isNull()) break;
            try results.append(self.arena, result);
            if (!global) break;

            const match = try self.toStringV(try self.getProperty(result, "0"));
            if (match.len == 0) {
                const li = toArrayLikeLen(try self.toNumberV(try self.getProperty(rx, "lastIndex")));
                try self.setRegExpLikeLastIndex(rx, @floatFromInt(advanceStringIndex(s, li, full_unicode)));
            }
        }

        const string_len = utf16LenOfString(s);
        var accumulated: usize = 0;
        var out: std.ArrayListUnmanaged(u8) = .empty;
        for (results.items) |result| {
            const length = toLen(try self.toNumberV(try self.getProperty(result, "length")));
            const captures_len = if (length == 0) 0 else length - 1;
            const matched = try self.toStringV(try self.getProperty(result, "0"));
            const position = @min(toLen(try self.toNumberV(try self.getProperty(result, "index"))), string_len);

            var captures: std.ArrayListUnmanaged(Value) = .empty;
            var i: usize = 1;
            while (i <= captures_len) : (i += 1) {
                const key = try std.fmt.allocPrint(self.arena, "{d}", .{i});
                const capture = try self.getProperty(result, key);
                if (capture.isUndefined()) {
                    try captures.append(self.arena, Value.undef());
                } else {
                    try captures.append(self.arena, Value.str(try self.toStringV(capture)));
                }
            }
            const named_captures = try self.getProperty(result, "groups");

            var replacement: []const u8 = "";
            if (functional_replace) {
                var call_args: std.ArrayListUnmanaged(Value) = .empty;
                try call_args.append(self.arena, Value.str(matched));
                try call_args.appendSlice(self.arena, captures.items);
                try call_args.append(self.arena, Value.num(@floatFromInt(position)));
                try call_args.append(self.arena, Value.str(s));
                if (!named_captures.isUndefined()) try call_args.append(self.arena, named_captures);
                replacement = try self.toStringV(try self.callValue(replace_value, call_args.items));
            } else {
                const substitution_groups: Value = if (named_captures.isUndefined())
                    Value.undef()
                else
                    Value.obj(try self.toObject(named_captures));
                var repl_buf: std.ArrayListUnmanaged(u8) = .empty;
                try self.getSubstitutionValues(&repl_buf, replace_string, matched, s, position, captures.items, substitution_groups);
                replacement = try repl_buf.toOwnedSlice(self.arena);
            }

            if (position >= accumulated) {
                try appendUtf16Slice(&out, self.arena, s, accumulated, position);
                try out.appendSlice(self.arena, replacement);
                accumulated = @min(position + utf16LenOfString(matched), string_len);
            }
        }
        try appendUtf16Slice(&out, self.arena, s, accumulated, string_len);
        return Value.str(try out.toOwnedSlice(self.arena));
    }

    fn appendSplitSegment(self: *Interpreter, out: *std.ArrayListUnmanaged(Value), s: []const u8, start: usize, end: usize) EvalError!void {
        var buf: std.ArrayListUnmanaged(u8) = .empty;
        try appendUtf16Slice(&buf, self.arena, s, start, end);
        try out.append(self.arena, Value.str(try buf.toOwnedSlice(self.arena)));
    }

    fn regexpSplit(self: *Interpreter, rx: Value, s: []const u8, limit_value: Value) EvalError!Value {
        if (!isRegExpObjectValue(rx)) return self.throwError("TypeError", "RegExp.prototype[Symbol.split] called on a non-object");
        const result = try self.newArray();
        const out = &result.asObj().elements;

        const default_ctor = self.env.get("RegExp") orelse Value.undef();
        const ctor = try self.speciesConstructor(rx, default_ctor);
        const flags = try self.toStringV(try self.getProperty(rx, "flags"));
        const full_unicode = std.mem.indexOfScalar(u8, flags, 'u') != null or std.mem.indexOfScalar(u8, flags, 'v') != null;
        const splitter_flags = if (std.mem.indexOfScalar(u8, flags, 'y') != null) flags else try std.mem.concat(self.arena, u8, &.{ flags, "y" });
        const splitter = try self.construct(ctor, &.{ rx, Value.str(splitter_flags) });
        const lim: usize = if (limit_value.isUndefined()) std.math.maxInt(u32) else value.Value.uint32FromF64(try self.toNumberV(limit_value));
        if (lim == 0) return result;

        const size = utf16LenOfString(s);
        if (size == 0) {
            const z = try self.regexpExecGeneric(splitter, s);
            if (z.isNull()) try out.append(self.arena, Value.str(s));
            return result;
        }

        var p: usize = 0;
        var q: usize = 0;
        while (q < size) {
            try self.setRegExpLikeLastIndex(splitter, @floatFromInt(q));
            const z = try self.regexpExecGeneric(splitter, s);
            if (z.isNull()) {
                q = advanceStringIndex(s, q, full_unicode);
                continue;
            }

            const e = toLen(try self.toNumberV(try self.getProperty(splitter, "lastIndex")));
            if (e == p) {
                q = advanceStringIndex(s, q, full_unicode);
                continue;
            }

            try self.appendSplitSegment(out, s, p, q);
            if (out.items.len >= lim) return result;

            const length = toLen(try self.toNumberV(try self.getProperty(z, "length")));
            var i: usize = 1;
            while (i < length) : (i += 1) {
                const key = try std.fmt.allocPrint(self.arena, "{d}", .{i});
                try out.append(self.arena, try self.getProperty(z, key));
                if (out.items.len >= lim) return result;
            }

            p = e;
            q = p;
        }
        try self.appendSplitSegment(out, s, p, size);
        return result;
    }

    fn regexpToString(self: *Interpreter, this: Value) EvalError!Value {
        if (!this.isObject()) return self.throwError("TypeError", "RegExp.prototype.toString called on a non-object");
        if (self.isRegExpProto(this.asObj())) return Value.str("/(?:)/");
        const src = try self.toStringV(try self.getProperty(this, "source"));
        const flags = try self.toStringV(try self.getProperty(this, "flags"));
        return Value.str(try std.mem.concat(self.arena, u8, &.{ "/", src, "/", flags }));
    }

    const ms_per_day: i64 = 86400000;

    /// Build a `Date` whose time is `t` ms since the Unix epoch.
    pub fn makeDate(self: *Interpreter, t: f64) EvalError!Value {
        const o = (try self.newObject()).asObj();
        o.is_date = true;
        // Proto from the in-flight constructor's new.target (`new Date`, or a
        // `class extends Date` subclass), else %Date.prototype% — so
        // `Date.prototype.isPrototypeOf(d)` and `d.constructor` resolve. Date
        // methods still dispatch via the `is_date` branch in builtinMethod.
        if (self.new_target.isObject()) {
            o.setProtoAtomic(try self.ctorRealmIntrinsicProto(self.new_target.asObj(), "Date"));
        } else if (self.env.get("Date")) |ctor| {
            if (ctor.isObject()) {
                if (ctor.asObj().getOwn("prototype")) |p| {
                    if (p.isObject()) o.setProtoAtomic(p.asObj());
                }
            }
        }
        // TimeClip(t): a non-finite or out-of-±8.64e15 time is NaN, otherwise the
        // integer part (toward zero), with -0 normalized to +0.
        o.setDateMs(if (std.math.isNan(t) or @abs(t) > 8.64e15) std.math.nan(f64) else blk: {
            const tr = @trunc(t);
            break :blk if (tr == 0) 0 else tr;
        });
        return Value.obj(o);
    }

    /// Civil date (year, month 1-12, day 1-31) from days since the epoch
    /// (Howard Hinnant's algorithm).
    fn civilFromDays(z0: i64) struct { y: i64, m: i64, d: i64 } {
        const z = z0 + 719468;
        const era = @divTrunc(if (z >= 0) z else z - 146096, 146097);
        const doe = z - era * 146097;
        const yoe = @divFloor(doe - @divFloor(doe, 1460) + @divFloor(doe, 36524) - @divFloor(doe, 146096), 365);
        const y = yoe + era * 400;
        const doy = doe - (365 * yoe + @divFloor(yoe, 4) - @divFloor(yoe, 100));
        const mp = @divFloor(5 * doy + 2, 153);
        const d = doy - @divFloor(153 * mp + 2, 5) + 1;
        const m = if (mp < 10) mp + 3 else mp - 9;
        return .{ .y = y + @as(i64, if (m <= 2) 1 else 0), .m = m, .d = d };
    }

    /// Clamp a signed component to a non-negative integer for `{d}` formatting
    /// (negative years/fields are out of this engine's rendered range).
    fn dnz(x: i64) u64 {
        return if (x < 0) 0 else @intCast(x);
    }

    /// Days since the epoch for a civil date (inverse of `civilFromDays`).
    fn daysFromCivil(y0: i64, m: i64, d: i64) i64 {
        const y = y0 - @as(i64, if (m <= 2) 1 else 0);
        const era = @divTrunc(if (y >= 0) y else y - 399, 400);
        const yoe = y - era * 400;
        const mp = if (m > 2) m - 3 else m + 9;
        const doy = @divFloor(153 * mp + 2, 5) + d - 1;
        const doe = yoe * 365 + @divFloor(yoe, 4) - @divFloor(yoe, 100) + doy;
        return era * 146097 + doe - 719468;
    }

    const day_names = [_][]const u8{ "Sun", "Mon", "Tue", "Wed", "Thu", "Fri", "Sat" };
    const month_names = [_][]const u8{ "Jan", "Feb", "Mar", "Apr", "May", "Jun", "Jul", "Aug", "Sep", "Oct", "Nov", "Dec" };
    const DateParts = struct { y: i64, mo: i64, d: i64, h: i64, mi: i64, s: i64, ms: i64, wday: i64 };

    /// Decompose a finite epoch-ms time into broken-down (UTC) components.
    fn dateDecompose(t: f64) DateParts {
        const ti: i64 = @intFromFloat(t);
        const days = @divFloor(ti, ms_per_day);
        const tod = @mod(ti, ms_per_day);
        const c = civilFromDays(days);
        return .{
            .y = c.y,
            .mo = c.m - 1,
            .d = c.d,
            .h = @divFloor(tod, 3600000),
            .mi = @mod(@divFloor(tod, 60000), 60),
            .s = @mod(@divFloor(tod, 1000), 60),
            .ms = @mod(tod, 1000),
            .wday = @mod(days + 4, 7),
        };
    }

    fn dateYearString(self: *Interpreter, y: i64) EvalError![]const u8 {
        if (y < 0) return std.fmt.allocPrint(self.arena, "-{d:0>4}", .{@as(u64, @intCast(-y))});
        return std.fmt.allocPrint(self.arena, "{d:0>4}", .{@as(u64, @intCast(y))});
    }

    fn dateISOYearString(self: *Interpreter, y: i64) EvalError![]const u8 {
        if (y >= 0 and y <= 9999) return std.fmt.allocPrint(self.arena, "{d:0>4}", .{@as(u64, @intCast(y))});
        if (y < 0) return std.fmt.allocPrint(self.arena, "-{d:0>6}", .{@as(u64, @intCast(-y))});
        return std.fmt.allocPrint(self.arena, "+{d:0>6}", .{@as(u64, @intCast(y))});
    }

    fn dateTimeClip(t: f64) f64 {
        if (!std.math.isFinite(t) or @abs(t) > 8.64e15) return std.math.nan(f64);
        const tr = @trunc(t);
        return if (tr == 0) 0 else tr;
    }

    /// Recompose broken-down components into an epoch-ms time, set it on `o`, and
    /// return it — the shared back half of every `Date.prototype.set*`. Out-of-range
    /// fields roll over (e.g. `setHours(0,0,0,-1)`); a non-finite or absurd field, or
    /// a result past the ±8.64e15 ms range (TimeClip), yields NaN.
    fn dateCommit(self: *Interpreter, o: *value.Object, y: f64, mo: f64, d: f64, h: f64, mi: f64, s: f64, ms: f64) EvalError!Value {
        _ = self; // [[DateValue]] now lives in the `date_ms` field, no property write
        const nan = std.math.nan(f64);
        var tf: f64 = nan;
        const fields = [_]f64{ y, mo, d, h, mi, s, ms };
        var ok = true;
        for (fields) |f| {
            if (!std.math.isFinite(f) or @abs(f) > 1e9) ok = false;
        }
        if (ok) {
            var yi: i64 = @intFromFloat(@trunc(y));
            var moi: i64 = @intFromFloat(@trunc(mo));
            yi += @divFloor(moi, 12);
            moi = @mod(moi, 12);
            const days = daysFromCivil(yi, moi + 1, @intFromFloat(@trunc(d)));
            const tod = @as(i64, @intFromFloat(@trunc(h))) * 3600000 + @as(i64, @intFromFloat(@trunc(mi))) * 60000 +
                @as(i64, @intFromFloat(@trunc(s))) * 1000 + @as(i64, @intFromFloat(@trunc(ms)));
            tf = @as(f64, @floatFromInt(days)) * @as(f64, @floatFromInt(ms_per_day)) + @as(f64, @floatFromInt(tod));
            if (@abs(tf) > 8.64e15) tf = nan;
        }
        o.setDateMs(tf);
        return Value.num(tf);
    }

    /// `Date.prototype` methods (UTC-based; v1 ignores local timezone, so
    /// get*/getUTC* coincide). Time is the internal-slot field `date_ms`.
    fn dateMethod(self: *Interpreter, o: *value.Object, name: []const u8, args: []const Value) EvalError!?Value {
        const t = o.dateMs();
        const nan = std.math.nan(f64);
        if (eq(name, "getTime") or eq(name, "valueOf")) return Value.num(t);
        // toLocale{,Date,Time}String(locales, options) === new Intl.DateTimeFormat
        // (locales, options).format(this), with the method's required/defaults.
        if (eq(name, "toLocaleString") or eq(name, "toLocaleDateString") or eq(name, "toLocaleTimeString")) {
            if (std.math.isNan(t)) return Value.str("Invalid Date");
            const required: DtfRequired = if (eq(name, "toLocaleDateString")) .date else if (eq(name, "toLocaleTimeString")) .time else .any;
            const defaults: DtfDefaults = if (eq(name, "toLocaleDateString")) .date else if (eq(name, "toLocaleTimeString")) .time else .all;
            const dtf = (try self.newObject()).asObj();
            try self.setProp(dtf, "\x00intl", Value.str("DateTimeFormat"));
            const locs = try canonicalizeLocaleList(self, if (args.len > 0) args[0] else Value.undef());
            const loc = if (locs.elements.items.len > 0) locs.elements.items[0].asStr() else "en";
            try self.setProp(dtf, "\x00locale", Value.str(loc));
            const r = try dtfProcessOptionsKind(self, if (args.len > 1) args[1] else Value.undef(), required, defaults);
            try dtfStoreOptions(self, dtf, r);
            return try intlDateTimeFormatFn(@ptrCast(self), Value.obj(dtf), &.{Value.num(t)});
        }
        if (eq(name, "setTime")) {
            var nt = try self.toNumberV(arg0(args));
            if (@abs(nt) > 8.64e15) nt = nan;
            o.setDateMs(nt);
            return Value.num(nt);
        }

        // ---- setters ----------------------------------------------------------
        if (std.mem.startsWith(u8, name, "set")) {
            const fy = eq(name, "setFullYear") or eq(name, "setUTCFullYear");
            const sy = eq(name, "setYear"); // Annex B B.2.4.2 (revives like setFullYear)
            // ToNumber each provided argument once, left-to-right (object args
            // invoke valueOf exactly once), BEFORE consulting the stored time —
            // the spec reads [[DateValue]] first (captured in `t` above) but still
            // coerces every argument even when the date is invalid. A Symbol/
            // BigInt argument throws here (toNumberV).
            const a = try self.arena.alloc(Value, args.len);
            for (args, 0..) |av, idx| a[idx] = Value.num(try self.toNumberV(av));
            // Non-fullyear setters on an invalid date stay invalid (arguments were
            // still coerced above); setFullYear revives it from a zero base.
            if (std.math.isNan(t) and !fy and !sy) return Value.num(nan);
            const c = dateDecompose(if (std.math.isNan(t)) 0 else t);
            var y: f64 = @floatFromInt(c.y);
            var mo: f64 = @floatFromInt(c.mo);
            var d: f64 = @floatFromInt(c.d);
            var h: f64 = @floatFromInt(c.h);
            var mi: f64 = @floatFromInt(c.mi);
            var s: f64 = @floatFromInt(c.s);
            var ms: f64 = @floatFromInt(c.ms);
            if (fy) {
                y = arg0(a).toNumber();
                if (a.len > 1) mo = a[1].toNumber();
                if (a.len > 2) d = a[2].toNumber();
                return try self.dateCommit(o, y, mo, d, h, mi, s, ms);
            }
            if (sy) {
                const yv = arg0(a).toNumber();
                if (std.math.isNan(yv)) {
                    o.setDateMs(nan);
                    return Value.num(nan);
                }
                const yi = @trunc(yv);
                y = if (yi >= 0 and yi <= 99) 1900 + yi else yv;
                return try self.dateCommit(o, y, mo, d, h, mi, s, ms);
            }
            if (eq(name, "setMonth") or eq(name, "setUTCMonth")) {
                mo = arg0(a).toNumber();
                if (a.len > 1) d = a[1].toNumber();
                return try self.dateCommit(o, y, mo, d, h, mi, s, ms);
            }
            if (eq(name, "setDate") or eq(name, "setUTCDate")) {
                d = arg0(a).toNumber();
                return try self.dateCommit(o, y, mo, d, h, mi, s, ms);
            }
            if (eq(name, "setHours") or eq(name, "setUTCHours")) {
                h = arg0(a).toNumber();
                if (a.len > 1) mi = a[1].toNumber();
                if (a.len > 2) s = a[2].toNumber();
                if (a.len > 3) ms = a[3].toNumber();
                return try self.dateCommit(o, y, mo, d, h, mi, s, ms);
            }
            if (eq(name, "setMinutes") or eq(name, "setUTCMinutes")) {
                mi = arg0(a).toNumber();
                if (a.len > 1) s = a[1].toNumber();
                if (a.len > 2) ms = a[2].toNumber();
                return try self.dateCommit(o, y, mo, d, h, mi, s, ms);
            }
            if (eq(name, "setSeconds") or eq(name, "setUTCSeconds")) {
                s = arg0(a).toNumber();
                if (a.len > 1) ms = a[1].toNumber();
                return try self.dateCommit(o, y, mo, d, h, mi, s, ms);
            }
            if (eq(name, "setMilliseconds") or eq(name, "setUTCMilliseconds")) {
                ms = arg0(a).toNumber();
                return try self.dateCommit(o, y, mo, d, h, mi, s, ms);
            }
        }

        // ---- string conversions ----------------------------------------------
        if (eq(name, "toISOString")) {
            if (std.math.isNan(t)) return self.throwError("RangeError", "Invalid time value");
            return Value.str(try self.dateISO(t));
        }
        if (eq(name, "toJSON")) {
            // The Date-receiver fast path (the generic `dateToJSONFn` native
            // handles a borrowed/non-Date `this`): a non-finite time is null.
            if (!std.math.isFinite(t)) return Value.nul();
            return Value.str(try self.dateISO(t));
        }
        if (eq(name, "toUTCString") or eq(name, "toGMTString")) {
            if (std.math.isNan(t)) return Value.str("Invalid Date");
            const c = dateDecompose(t);
            return Value.str(try std.fmt.allocPrint(self.arena, "{s}, {d:0>2} {s} {s} {d:0>2}:{d:0>2}:{d:0>2} GMT", .{
                day_names[@intCast(c.wday)], dnz(c.d), month_names[@intCast(c.mo)], try self.dateYearString(c.y), dnz(c.h), dnz(c.mi), dnz(c.s),
            }));
        }
        if (eq(name, "toDateString") or eq(name, "toString") or eq(name, "toTimeString") or
            eq(name, "toLocaleString") or eq(name, "toLocaleDateString") or eq(name, "toLocaleTimeString"))
        {
            if (std.math.isNan(t)) return Value.str("Invalid Date");
            const c = dateDecompose(t);
            const date_str = try std.fmt.allocPrint(self.arena, "{s} {s} {d:0>2} {s}", .{ day_names[@intCast(c.wday)], month_names[@intCast(c.mo)], dnz(c.d), try self.dateYearString(c.y) });
            const time_str = try std.fmt.allocPrint(self.arena, "{d:0>2}:{d:0>2}:{d:0>2} GMT+0000 (Coordinated Universal Time)", .{ dnz(c.h), dnz(c.mi), dnz(c.s) });
            if (eq(name, "toDateString") or eq(name, "toLocaleDateString")) return Value.str(date_str);
            if (eq(name, "toTimeString") or eq(name, "toLocaleTimeString")) return Value.str(time_str);
            return Value.str(try std.mem.concat(self.arena, u8, &.{ date_str, " ", time_str }));
        }

        // ---- getters ----------------------------------------------------------
        if (std.math.isNan(t)) return Value.num(nan);
        const ti: i64 = @intFromFloat(t);
        const days = @divFloor(ti, ms_per_day);
        const tod = @mod(ti, ms_per_day);
        const c = civilFromDays(days);
        if (eq(name, "getFullYear") or eq(name, "getUTCFullYear")) return Value.num(@floatFromInt(c.y));
        if (eq(name, "getYear")) return Value.num(@floatFromInt(c.y - 1900)); // Annex B B.2.4.1
        if (eq(name, "getMonth") or eq(name, "getUTCMonth")) return Value.num(@floatFromInt(c.m - 1));
        if (eq(name, "getDate") or eq(name, "getUTCDate")) return Value.num(@floatFromInt(c.d));
        if (eq(name, "getDay") or eq(name, "getUTCDay")) return Value.num(@floatFromInt(@mod(days + 4, 7)));
        if (eq(name, "getHours") or eq(name, "getUTCHours")) return Value.num(@floatFromInt(@divFloor(tod, 3600000)));
        if (eq(name, "getMinutes") or eq(name, "getUTCMinutes")) return Value.num(@floatFromInt(@mod(@divFloor(tod, 60000), 60)));
        if (eq(name, "getSeconds") or eq(name, "getUTCSeconds")) return Value.num(@floatFromInt(@mod(@divFloor(tod, 1000), 60)));
        if (eq(name, "getMilliseconds") or eq(name, "getUTCMilliseconds")) return Value.num(@floatFromInt(@mod(tod, 1000)));
        if (eq(name, "getTimezoneOffset")) return Value.num(0);
        return null;
    }

    /// ISO 8601 rendering of a finite epoch-ms time (`2020-01-15T00:00:00.000Z`).
    fn dateISO(self: *Interpreter, t: f64) EvalError![]const u8 {
        const c = dateDecompose(t);
        return std.fmt.allocPrint(self.arena, "{s}-{d:0>2}-{d:0>2}T{d:0>2}:{d:0>2}:{d:0>2}.{d:0>3}Z", .{
            try self.dateISOYearString(c.y), dnz(c.mo + 1), dnz(c.d), dnz(c.h), dnz(c.mi), dnz(c.s), dnz(c.ms),
        });
    }

    /// Compute a Date's epoch-ms from constructor arguments.
    pub fn dateTimeFromArgs(args: []const Value) f64 {
        if (args.len == 0) return 0; // (a real clock isn't wired; epoch is deterministic)
        if (args.len == 1) return dateTimeClip(args[0].toNumber());
        const nan = std.math.nan(f64);
        const fields = [_]f64{
            args[0].toNumber(),
            args[1].toNumber(),
            if (args.len > 2) args[2].toNumber() else 1,
            if (args.len > 3) args[3].toNumber() else 0,
            if (args.len > 4) args[4].toNumber() else 0,
            if (args.len > 5) args[5].toNumber() else 0,
            if (args.len > 6) args[6].toNumber() else 0,
        };
        for (fields) |f| if (!std.math.isFinite(f)) return nan;
        const y_f = @trunc(fields[0]);
        const mo_f = @trunc(fields[1]);
        const d_f = @trunc(fields[2]);
        const h = @trunc(fields[3]);
        const mi = @trunc(fields[4]);
        const s = @trunc(fields[5]);
        const millis = @trunc(fields[6]);
        if (@abs(y_f) > 1_000_000 or @abs(mo_f) > 12_000_000) return nan;
        var y: i64 = @intFromFloat(y_f);
        var mo: i64 = @intFromFloat(mo_f);
        y += @divFloor(mo, 12);
        mo = @mod(mo, 12);
        const month_start: f64 = @floatFromInt(daysFromCivil(y, mo + 1, 1));
        const day = month_start + d_f - 1;
        const time = ((h * 3_600_000 + mi * 60_000) + s * 1000) + millis;
        return dateTimeClip(day * @as(f64, @floatFromInt(ms_per_day)) + time);
    }

    /// Build a `Map`, optionally populated from an iterable of `[k,v]` pairs.
    /// Whether `start`'s [[Prototype]] chain reaches the named constructor's
    /// `.prototype` — used to tell a WeakMap/WeakSet (whose chain includes
    /// %WeakMap.prototype%/%WeakSet.prototype%) from a Map/Set, including
    /// subclasses, since both kinds share the `is_map`/`is_set` storage.
    fn protoReachesCtorProto(self: *Interpreter, ctor_name: []const u8, start: ?*value.Object) bool {
        const cv = self.env.get(ctor_name) orelse return false;
        if (!cv.isObject()) return false;
        const wp = cv.asObj().getOwn("prototype") orelse return false;
        if (!wp.isObject()) return false;
        var cur = start;
        while (cur) |c| : (cur = c.protoAtomic()) {
            if (c == wp.asObj()) return true;
        }
        return false;
    }

    pub fn makeMap(self: *Interpreter, init_v: Value) EvalError!Value {
        return self.makeMapWithIntrinsic(init_v, "Map");
    }

    pub fn makeWeakMap(self: *Interpreter, init_v: Value) EvalError!Value {
        return self.makeMapWithIntrinsic(init_v, "WeakMap");
    }

    fn makeMapWithIntrinsic(self: *Interpreter, init_v: Value, intrinsic: []const u8) EvalError!Value {
        const o = (try self.newObject()).asObj();
        o.is_map = true;
        if (self.new_target.isObject()) {
            o.setProtoAtomic(try self.ctorRealmIntrinsicProto(self.new_target.asObj(), intrinsic));
        } else if (self.env.get("Map")) |ctor| {
            if (ctor.isObject()) {
                if (ctor.asObj().getOwn("prototype")) |p| {
                    if (p.isObject()) o.setProtoAtomic(p.asObj());
                }
            }
        }
        o.is_weak = self.protoReachesCtorProto("WeakMap", o.protoAtomic());
        try self.addEntriesFromIterable(o, init_v, false);
        return Value.obj(o);
    }

    /// Build a `Set`, optionally populated from an iterable of values.
    pub fn makeSet(self: *Interpreter, init_v: Value) EvalError!Value {
        return self.makeSetWithIntrinsic(init_v, "Set");
    }

    pub fn makeWeakSet(self: *Interpreter, init_v: Value) EvalError!Value {
        return self.makeSetWithIntrinsic(init_v, "WeakSet");
    }

    fn makeSetWithIntrinsic(self: *Interpreter, init_v: Value, intrinsic: []const u8) EvalError!Value {
        const o = (try self.newObject()).asObj();
        o.is_set = true;
        // Proto from the in-flight constructor (`new Set`/`new WeakSet`), so a
        // WeakSet doesn't inherit Set.prototype; internal results default to Set.
        if (self.new_target.isObject()) {
            o.setProtoAtomic(try self.ctorRealmIntrinsicProto(self.new_target.asObj(), intrinsic));
        } else if (self.env.get("Set")) |ctor| {
            if (ctor.isObject()) {
                if (ctor.asObj().getOwn("prototype")) |p| {
                    if (p.isObject()) o.setProtoAtomic(p.asObj());
                }
            }
        }
        o.is_weak = self.protoReachesCtorProto("WeakSet", o.protoAtomic());
        try self.addEntriesFromIterable(o, init_v, true);
        return Value.obj(o);
    }

    /// Map's AddEntriesFromIterable and the Set constructor's add loop: drain
    /// `iterable` through its iterator protocol, invoking the instance's own
    /// `set`/`add` (so a user override and the WeakMap/WeakSet variants are
    /// honored). A non-callable adder, a non-iterable argument, or — for a Map —
    /// a non-object entry is a TypeError; any abrupt completion mid-iteration
    /// closes the iterator (preserving the original exception) before propagating.
    fn addEntriesFromIterable(self: *Interpreter, o: *value.Object, iterable: Value, is_set: bool) EvalError!void {
        if (iterable.isUndefined() or iterable.isNull()) return;
        const adder = try self.getProperty(Value.obj(o), if (is_set) "add" else "set");
        if (!adder.isCallable())
            return self.throwError("TypeError", if (is_set) "Set add method is not callable" else "Map set method is not callable");
        const iter = try self.iteratorOf(iterable);
        while (true) {
            const r = try self.callMethod(iter, "next", &.{});
            if (!r.isObject()) return self.throwError("TypeError", "iterator.next() did not return an object");
            if ((try self.getProperty(r, "done")).toBoolean()) break;
            const item = try self.getProperty(r, "value");
            self.addOneEntry(o, adder, item, is_set) catch |e| {
                // IteratorClose, keeping the original abrupt completion's value.
                const saved = self.exception;
                self.iteratorClose(iter) catch {};
                self.exception = saved;
                return e;
            };
        }
    }

    /// Add one drained iterator value to the collection via `adder` (bound to
    /// `o`). For a Map the value must be an entry object `{0: key, 1: value}`.
    fn addOneEntry(self: *Interpreter, o: *value.Object, adder: Value, item: Value, is_set: bool) EvalError!void {
        const self_v = Value.obj(o);
        if (is_set) {
            _ = try self.callValueWithThis(adder, &.{item}, self_v);
            return;
        }
        if (!builtins.isRealObject(item)) return self.throwError("TypeError", "Iterator value is not an entry object");
        const k = try self.getProperty(item, "0");
        const v = try self.getProperty(item, "1");
        _ = try self.callValueWithThis(adder, &.{ k, v }, self_v);
    }

    fn mapMethod(self: *Interpreter, o: *value.Object, name: []const u8, args: []const Value) EvalError!?Value {
        const self_v = Value.obj(o);
        const key = canonicalCollectionKey(arg0(args));
        // A WeakMap key (`set`/`getOrInsert`/`getOrInsertComputed`) must be a
        // value that can be held weakly — an object or a (non-registered) symbol;
        // a primitive throws before any insertion or callback runs.
        if (o.is_weak and (eq(name, "set") or eq(name, "getOrInsert") or eq(name, "getOrInsertComputed"))) {
            if (!canBeHeldWeakly(arg0(args)))
                return self.throwError("TypeError", "Invalid value used as WeakMap key");
        }
        if (o.is_weak) {
            const key_obj = weakKeyPtr(key);
            // weak_entries access goes through the elements_lock'd helpers so a
            // concurrent GC marker reading them never races an append/remove.
            if (eq(name, "set")) {
                try o.weakEntrySet(self.arena, key_obj, arg(args, 1));
                return self_v;
            }
            if (eq(name, "get")) {
                return o.weakEntryGet(key_obj) orelse Value.undef();
            }
            if (eq(name, "has")) {
                return Value.boolVal(o.weakEntryHas(key_obj));
            }
            if (eq(name, "delete")) {
                return Value.boolVal(o.weakEntryDelete(key_obj));
            }
            if (eq(name, "getOrInsert") or eq(name, "getOrInsertComputed")) {
                const cb = if (eq(name, "getOrInsertComputed")) cb: {
                    const candidate = arg(args, 1);
                    if (!candidate.isCallable()) return self.throwError("TypeError", "Map.prototype.getOrInsertComputed: callback is not a function");
                    break :cb candidate;
                } else Value.undef();
                if (o.weakEntryGet(key_obj)) |existing| return existing;
                // The callback runs with no lock held (it may re-enter the map);
                // the upsert then keeps existing-entry-wins semantics.
                const v = if (eq(name, "getOrInsertComputed")) try self.callValue(cb, &.{key}) else arg(args, 1);
                try o.weakEntrySet(self.arena, key_obj, v);
                return v;
            }
            return null;
        }
        if (eq(name, "set")) {
            const val = arg(args, 1);
            const pair = (try self.newArray()).asObj();
            try pair.appendElement(self.arena, key);
            try pair.appendElement(self.arena, val);
            o.lockElements();
            defer o.unlockElements();
            for (o.elements.items) |e| {
                if (liveMapEntry(e)) |entry| if (mapEntryMatches(entry, key)) {
                    _ = entry.setElementAt(1, val);
                    return self_v;
                };
            }
            gc_mod.barrierCell(@ptrCast(pair)); // new entry hidden behind the live map
            try o.elements.append(o.elementsAllocator(self.arena), Value.obj(pair));
            return self_v;
        }
        if (eq(name, "get")) {
            o.lockElements();
            defer o.unlockElements();
            for (o.elements.items) |e| {
                if (liveMapEntry(e)) |entry| if (mapEntryMatches(entry, key)) return mapEntryValue(entry);
            }
            return Value.undef();
        }
        if (eq(name, "has")) {
            o.lockElements();
            defer o.unlockElements();
            for (o.elements.items) |e| {
                if (liveMapEntry(e)) |entry| if (mapEntryMatches(entry, key)) return Value.boolVal(true);
            }
            return Value.boolVal(false);
        }
        if (eq(name, "delete")) {
            o.lockElements();
            defer o.unlockElements();
            for (o.elements.items) |e| {
                if (liveMapEntry(e)) |entry| if (mapEntryMatches(entry, key)) {
                    entry.clearElementsRetainingCapacity();
                    return Value.boolVal(true);
                };
            }
            return Value.boolVal(false);
        }
        if (eq(name, "clear")) {
            o.clearElementsRetainingCapacity();
            return Value.undef();
        }
        if (eq(name, "forEach")) {
            const cb = arg0(args);
            if (!cb.isCallable()) return self.throwError("TypeError", "Map.prototype.forEach callback is not callable");
            var i: usize = 0;
            while (true) : (i += 1) {
                var end = false;
                const entry = blk: {
                    o.lockElements();
                    defer o.unlockElements();
                    if (i >= o.elements.items.len) {
                        end = true;
                        break :blk null;
                    }
                    break :blk liveMapEntry(o.elements.items[i]);
                };
                if (end) break;
                const live_entry = entry orelse continue;
                _ = try self.callValueWithThis(cb, &.{ mapEntryValue(live_entry), live_entry.elementAt(0) orelse Value.undef(), self_v }, arg(args, 1));
            }
            return Value.undef();
        }
        // Upsert proposal: return the existing value for `key`, else insert and
        // return a default (`getOrInsert`) or a computed value (`getOrInsertComputed`).
        if (eq(name, "getOrInsert") or eq(name, "getOrInsertComputed")) {
            const cb = if (eq(name, "getOrInsertComputed")) cb: {
                const candidate = arg(args, 1);
                if (!candidate.isCallable()) return self.throwError("TypeError", "Map.prototype.getOrInsertComputed: callback is not a function");
                break :cb candidate;
            } else Value.undef();
            {
                o.lockElements();
                defer o.unlockElements();
                for (o.elements.items) |e| {
                    if (liveMapEntry(e)) |entry| if (mapEntryMatches(entry, key)) return mapEntryValue(entry);
                }
            }
            const v = if (eq(name, "getOrInsertComputed")) blk: {
                break :blk try self.callValue(cb, &.{key});
            } else arg(args, 1);
            _ = try self.mapMethod(o, "set", &.{ key, v });
            return v;
        }
        if (eq(name, "keys") or eq(name, "values") or eq(name, "entries"))
            return try self.makeCursorIteratorWithKind(self_v, collectionIterKind(name));
        return null;
    }

    fn setMethod(self: *Interpreter, o: *value.Object, name: []const u8, args: []const Value) EvalError!?Value {
        const self_v = Value.obj(o);
        // A WeakSet value must be holdable weakly (object or non-registered
        // symbol); a primitive throws before insertion.
        if (o.is_weak and eq(name, "add") and !canBeHeldWeakly(arg0(args)))
            return self.throwError("TypeError", "Invalid value used in WeakSet");
        const key = canonicalCollectionKey(arg0(args));
        if (o.is_weak) {
            const key_obj = weakKeyPtr(key);
            // elements_lock'd helpers — race-free against a concurrent GC marker.
            if (eq(name, "add")) {
                try o.weakEntryAdd(self.arena, key_obj);
                return self_v;
            }
            if (eq(name, "has")) {
                return Value.boolVal(o.weakEntryHas(key_obj));
            }
            if (eq(name, "delete")) {
                return Value.boolVal(o.weakEntryDelete(key_obj));
            }
            return null;
        }
        if (eq(name, "add")) {
            o.lockElements();
            defer o.unlockElements();
            for (o.elements.items) |e| {
                if (liveSetEntry(e)) |entry| if (value.sameValueZero(entry, key)) return self_v;
            }
            gc_mod.barrierValue(key); // new key hidden behind the live set
            try o.elements.append(o.elementsAllocator(self.arena), key);
            return self_v;
        }
        if (eq(name, "has")) {
            o.lockElements();
            defer o.unlockElements();
            for (o.elements.items) |e| {
                if (liveSetEntry(e)) |entry| if (value.sameValueZero(entry, key)) return Value.boolVal(true);
            }
            return Value.boolVal(false);
        }
        if (eq(name, "delete")) {
            const tomb = try gc_mod.allocObj(self.arena);
            tomb.* = .{ .is_set_deleted = true };
            o.lockElements();
            defer o.unlockElements();
            for (o.elements.items, 0..) |e, i| {
                if (liveSetEntry(e)) |entry| if (value.sameValueZero(entry, key)) {
                    o.elements.items[i] = Value.obj(tomb);
                    return Value.boolVal(true);
                };
            }
            return Value.boolVal(false);
        }
        if (eq(name, "clear")) {
            o.clearElementsRetainingCapacity();
            return Value.undef();
        }
        if (eq(name, "forEach")) {
            const cb = arg0(args);
            if (!cb.isCallable()) return self.throwError("TypeError", "Set.prototype.forEach callback is not callable");
            var i: usize = 0;
            while (true) : (i += 1) {
                var end = false;
                const e = blk: {
                    o.lockElements();
                    defer o.unlockElements();
                    if (i >= o.elements.items.len) {
                        end = true;
                        break :blk null;
                    }
                    break :blk liveSetEntry(o.elements.items[i]);
                };
                if (end) break;
                const live_entry = e orelse continue;
                _ = try self.callValueWithThis(cb, &.{ live_entry, live_entry, self_v }, arg(args, 1));
            }
            return Value.undef();
        }
        // ES2024 set-operation methods. They take a set-like argument (the
        // set-record protocol: `size`, `has`, `keys`) and either return a new
        // Set (union/intersection/difference/symmetricDifference) or a boolean.
        const is_setop = eq(name, "union") or eq(name, "intersection") or eq(name, "difference") or
            eq(name, "symmetricDifference") or eq(name, "isSubsetOf") or eq(name, "isSupersetOf") or
            eq(name, "isDisjointFrom");
        if (is_setop) {
            const rec = try self.getSetRecord(arg0(args));
            if (eq(name, "union")) {
                const result = (try self.makeSet(Value.undef())).asObj();
                for (o.elements.items) |e| {
                    const entry = liveSetEntry(e) orelse continue;
                    _ = try self.setMethod(result, "add", &.{entry});
                }
                for (try self.collectSetKeys(rec)) |k| _ = try self.setMethod(result, "add", &.{k});
                return Value.obj(result);
            }
            const this_size: f64 = @floatFromInt(liveSetEntryCount(o));
            if (eq(name, "intersection")) {
                const result = (try self.makeSet(Value.undef())).asObj();
                if (this_size <= rec.size) {
                    // Smaller `this`: walk this, probe the other set's `has`.
                    for (o.elements.items) |e| {
                        const entry = liveSetEntry(e) orelse continue;
                        if (try self.recordHas(rec, entry)) _ = try self.setMethod(result, "add", &.{entry});
                    }
                } else {
                    // Smaller other: walk the other set's keys, keep those in this.
                    for (try self.collectSetKeys(rec)) |k| {
                        if (setContains(o, k)) _ = try self.setMethod(result, "add", &.{k});
                    }
                }
                return Value.obj(result);
            }
            if (eq(name, "difference")) {
                // result starts as a copy of this; the smaller operand drives the walk.
                const result = (try self.makeSet(Value.undef())).asObj();
                for (o.elements.items) |e| {
                    const entry = liveSetEntry(e) orelse continue;
                    _ = try self.setMethod(result, "add", &.{entry});
                }
                if (this_size <= rec.size) {
                    for (o.elements.items) |e| {
                        const entry = liveSetEntry(e) orelse continue;
                        if (try self.recordHas(rec, entry)) _ = try self.setMethod(result, "delete", &.{entry});
                    }
                } else {
                    for (try self.collectSetKeys(rec)) |k| {
                        _ = try self.setMethod(result, "delete", &.{k});
                    }
                }
                return Value.obj(result);
            }
            if (eq(name, "symmetricDifference")) {
                const result = (try self.makeSet(Value.undef())).asObj();
                for (o.elements.items) |e| {
                    const entry = liveSetEntry(e) orelse continue;
                    _ = try self.setMethod(result, "add", &.{entry});
                }
                for (try self.collectSetKeys(rec)) |k| {
                    if ((try self.setMethod(o, "has", &.{k})).?.asBool())
                        _ = try self.setMethod(result, "delete", &.{k})
                    else
                        _ = try self.setMethod(result, "add", &.{k});
                }
                return Value.obj(result);
            }
            if (eq(name, "isSubsetOf")) {
                // A larger `this` cannot be a subset (and must not probe `has`).
                if (this_size > rec.size) return Value.boolVal(false);
                // Iterate the LIVE [[SetData]] by index: `rec.has` may mutate `this`
                // (e.g. delete a trailing element), and a removed slot must be
                // skipped rather than re-probed from a stale snapshot.
                var i: usize = 0;
                while (i < o.elements.items.len) : (i += 1) {
                    const entry = liveSetEntry(o.elements.items[i]) orelse continue;
                    if (!(try self.recordHas(rec, entry)))
                        return Value.boolVal(false);
                }
                return Value.boolVal(true);
            }
            if (eq(name, "isSupersetOf")) {
                // A smaller `this` cannot be a superset (and must not iterate keys).
                if (this_size < rec.size) return Value.boolVal(false);
                // Stop (closing the iterator) at the first other-key absent from this.
                return Value.boolVal(!(try self.setKeysAny(rec, o, false)));
            }
            if (eq(name, "isDisjointFrom")) {
                if (this_size <= rec.size) {
                    var i: usize = 0;
                    while (i < o.elements.items.len) : (i += 1) {
                        const entry = liveSetEntry(o.elements.items[i]) orelse continue;
                        if (try self.recordHas(rec, entry)) return Value.boolVal(false);
                    }
                    return Value.boolVal(true);
                }
                // Stop (closing the iterator) at the first other-key present in this.
                return Value.boolVal(!(try self.setKeysAny(rec, o, true)));
            }
        }
        if (eq(name, "keys") or eq(name, "values") or eq(name, "entries"))
            return try self.makeCursorIteratorWithKind(self_v, collectionIterKind(name));
        return null;
    }

    const SetRecord = struct { obj: *value.Object, has: Value, keys: Value, size: f64, is_set: bool };

    /// GetSetRecord: a set-like argument must be an object with a numeric `size`
    /// and callable `has`/`keys`. A native Set is recognized directly (its
    /// `has`/`keys` are dispatched, not stored properties), so it's served from
    /// its own elements rather than the protocol.
    fn getSetRecord(self: *Interpreter, v: Value) EvalError!SetRecord {
        if (!v.isObject()) return self.throwError("TypeError", "argument is not an object");
        // GetSetRecord: rawSize = Get(obj,"size"); numSize = ToNumber(rawSize)
        // (a Symbol/BigInt size throws a TypeError); NaN throws; intSize < 0 is a
        // RangeError. ToNumber runs before `has`/`keys` are read.
        const size = try self.toNumberV(try self.getProperty(v, "size"));
        if (std.math.isNan(size)) return self.throwError("TypeError", "set-like 'size' is NaN");
        if (@trunc(size) < 0) return self.throwError("RangeError", "set-like 'size' is negative"); // intSize = ToIntegerOrInfinity
        if (v.asObj().is_set) return .{ .obj = v.asObj(), .has = Value.undef(), .keys = Value.undef(), .size = size, .is_set = true };
        const has = try self.getProperty(v, "has");
        if (!has.isCallable()) return self.throwError("TypeError", "set-like 'has' is not callable");
        const keys = try self.getProperty(v, "keys");
        if (!keys.isCallable()) return self.throwError("TypeError", "set-like 'keys' is not callable");
        return .{ .obj = v.asObj(), .has = has, .keys = keys, .size = size, .is_set = false };
    }

    /// Lazily walk `rec`'s keys (GetIteratorDirect — `next` captured once),
    /// stopping as soon as `setContains(o, key) == want`. On an early stop the
    /// key iterator is closed (IteratorClose) and `true` is returned; if the keys
    /// are exhausted without a match, `false` (no close — the iterator finished).
    fn setKeysAny(self: *Interpreter, rec: SetRecord, o: *value.Object, want: bool) EvalError!bool {
        if (rec.is_set) {
            for (try self.collectSetKeys(rec)) |entry| if (setContains(o, entry) == want) return true;
            return false;
        }
        const iter = try self.callValueWithThis(rec.keys, &.{}, Value.obj(rec.obj));
        const next_m = try self.getProperty(iter, "next");
        while (true) {
            const r = try self.callValueWithThis(next_m, &.{}, iter);
            if (!r.isObject()) return self.throwError("TypeError", "iterator.next() did not return an object");
            if ((try self.getProperty(r, "done")).toBoolean()) return false;
            const k = try self.getProperty(r, "value");
            if (setContains(o, k) == want) {
                try self.iteratorClose(iter);
                return true;
            }
        }
    }

    /// SetDataHas: whether the native Set `o` contains `elem` (SameValueZero) —
    /// used by the set operations when they iterate the *other* operand.
    fn setContains(o: *value.Object, elem: Value) bool {
        o.lockElements();
        defer o.unlockElements();
        for (o.elements.items) |e| {
            const entry = liveSetEntry(e) orelse continue;
            if (value.sameValueZero(entry, elem)) return true;
        }
        return false;
    }

    /// Whether the set-like contains `elem` (a native Set scans its elements; a
    /// set-like calls its `has`).
    fn recordHas(self: *Interpreter, rec: SetRecord, elem: Value) EvalError!bool {
        if (rec.is_set) {
            rec.obj.lockElements();
            defer rec.obj.unlockElements();
            for (rec.obj.elements.items) |e| {
                const entry = liveSetEntry(e) orelse continue;
                if (value.sameValueZero(entry, elem)) return true;
            }
            return false;
        }
        return (try self.callValueWithThis(rec.has, &.{elem}, Value.obj(rec.obj))).toBoolean();
    }

    /// The set-like's elements (a native Set's `elements`, else its `keys()`).
    fn collectSetKeys(self: *Interpreter, rec: SetRecord) EvalError![]Value {
        if (rec.is_set) {
            var list: std.ArrayListUnmanaged(Value) = .empty;
            rec.obj.lockElements();
            defer rec.obj.unlockElements();
            for (rec.obj.elements.items) |e| {
                const entry = liveSetEntry(e) orelse continue;
                try list.append(self.arena, entry);
            }
            return list.items;
        }
        const iter = try self.callValueWithThis(rec.keys, &.{}, Value.obj(rec.obj));
        // GetIteratorDirect: capture `next` ONCE, then call it each step (the
        // spec does not re-read the `next` property on every iteration).
        const next_method = try self.getProperty(iter, "next");
        var list: std.ArrayListUnmanaged(Value) = .empty;
        while (true) {
            const r = try self.callValueWithThis(next_method, &.{}, iter);
            if (!r.isObject()) return self.throwError("TypeError", "iterator.next() did not return an object");
            if ((try self.getProperty(r, "done")).toBoolean()) break;
            try list.append(self.arena, try self.getProperty(r, "value"));
        }
        return list.items;
    }

    fn evalArrayLit(self: *Interpreter, elems: []*Node) EvalError!Value {
        const v = try self.newArray();
        for (elems) |en| {
            if (en.* == .spread) {
                try self.spreadInto(&v.asObj().elements, try self.eval(en.spread));
            } else if (en.* == .elision) {
                // A hole: a slot that reads as absent (skipped by iteration).
                try v.asObj().markHole(self.arena, v.asObj().elements.items.len);
                try v.asObj().elements.append(v.asObj().elementsAllocator(self.arena), Value.undef());
            } else {
                try v.asObj().elements.append(v.asObj().elementsAllocator(self.arena), try self.eval(en));
            }
        }
        return v;
    }

    /// `index`-as-string -> array element index, or null if not an integer.
    pub fn arrayIndex(key: []const u8) ?usize {
        if (key.len == 0) return null;
        for (key) |c| if (!std.ascii.isDigit(c)) return null;
        return std.fmt.parseInt(usize, key, 10) catch null;
    }

    fn arrayElementIndex(key: []const u8) ?usize {
        const i = arrayIndex(key) orelse return null;
        return if (i < 4294967295) i else null;
    }

    // ---- Proxy ------------------------------------------------------------

    /// Fetch trap `name` from a proxy's handler. Returns null when the trap is
    /// absent/undefined (the caller forwards to the target). Throws if the proxy
    /// is revoked or the trap isn't callable.
    fn proxyTrap(self: *Interpreter, o: *value.Object, name: []const u8) EvalError!?Value {
        if (o.proxy_revoked or o.proxy_handler == null)
            return self.throwError("TypeError", "Cannot perform 'get' on a proxy that has been revoked");
        const trap = try self.getProperty(Value.obj(o.proxy_handler.?), name);
        if (trap.isUndefined() or trap.isNull()) return null;
        if (!trap.isCallable()) return self.throwError("TypeError", "proxy trap is not a function");
        return trap;
    }

    /// A property key as a JS value for passing to a trap. (String keys only for
    /// now; symbol-keyed trap arguments aren't reconstructed yet.)
    pub fn keyToValue(self: *Interpreter, key: []const u8) Value {
        // A symbol-encoded key recovers the original Symbol (registered in
        // `keyOf` when it was used as a property key); other keys are strings.
        if (value.isSymbolKey(key)) {
            if (self.symbols.get(key)) |sym| return Value.obj(sym);
            // Fallback: a well-known symbol (Symbol.iterator / toStringTag / …)
            // whose key wasn't registered via `keyOf` this evaluation — find the
            // canonical Symbol object on the global `Symbol` so identity holds
            // (e.g. getOwnPropertySymbols/Reflect.ownKeys surfacing @@toStringTag).
            if (self.env.get("Symbol")) |symv| if (symv.isObject()) {
                const ks = symv.asObj().ownKeys(self.arena) catch &.{};
                for (ks) |k| {
                    const v = symv.asObj().getOwn(k) orelse continue;
                    if (v.isObject() and v.asObj().is_symbol and std.mem.eql(u8, v.asObj().sym_key, key)) {
                        self.symbols.put(self.arena, key, v.asObj()) catch {};
                        return Value.obj(v.asObj());
                    }
                }
            };
        }
        return Value.str(key);
    }

    /// Guard against unbounded proxy→target→proxy forwarding (which recurses
    /// without a JS call frame, so the normal call-depth limit wouldn't catch it).
    fn proxyDepth(self: *Interpreter) EvalError!void {
        try self.stackGuard();
    }

    /// [[GetPrototypeOf]] of an (unwrapped) prototype value for a target object,
    /// honoring a target that is itself a Proxy.
    fn ordinaryProtoValue(self: *Interpreter, o: *value.Object) EvalError!Value {
        if (o.proxy_handler != null or o.proxy_revoked) return self.proxyGetProto(o);
        return if (o.protoAtomic()) |p| Value.obj(p) else Value.nul();
    }

    fn sameProtoValue(proto: ?*value.Object, v: Value) bool {
        return (proto == null and v.isNull()) or (proto != null and v.isObject() and proto.? == v.asObj());
    }

    fn ordinarySetPrototypeOf(self: *Interpreter, o: *value.Object, new_proto: ?*value.Object) EvalError!bool {
        const current = if (o.protoAtomic()) |p| Value.obj(p) else Value.nul();
        if (sameProtoValue(new_proto, current)) return true;
        if (self.objectProto()) |op| {
            if (o == op) return false;
        }
        if (!o.extensible) return false;
        var cur = new_proto;
        while (cur) |c| {
            if (c == o) return false;
            // OrdinarySetPrototypeOf only continues the cycle walk through
            // ordinary objects. A Proxy in the candidate prototype chain is
            // exotic; reaching it stops the walk rather than invoking its
            // [[GetPrototypeOf]] trap.
            if (c.proxy_handler != null or c.proxy_revoked) break;
            cur = self.effectiveProto(c);
        }
        if (new_proto) |np| {
            _ = self.preparePrototypeUse(np);
            gc_mod.barrierCell(@ptrCast(np)); // proto reparent on a live object
        }
        o.setProtoAtomic(new_proto);
        return true;
    }

    /// [[SetPrototypeOf]] honoring Proxy targets and Proxy invariants.
    pub fn setPrototypeOfObject(self: *Interpreter, o: *value.Object, new_proto: ?*value.Object) EvalError!bool {
        try self.checkRestricted(o);
        if (o.proxy_handler != null or o.proxy_revoked) return self.proxySetProto(o, new_proto);
        return self.ordinarySetPrototypeOf(o, new_proto);
    }

    /// [[GetPrototypeOf]] for a Proxy (9.5.1): invoke the trap, require an Object
    /// or null result, and enforce the non-extensible-target invariant.
    pub fn proxyGetProto(self: *Interpreter, o: *value.Object) EvalError!Value {
        try self.proxyDepth();
        const target = o.proxy_target orelse return self.throwError("TypeError", "Cannot perform 'getPrototypeOf' on a proxy that has been revoked");
        const trap = (try self.proxyTrap(o, "getPrototypeOf")) orelse return self.ordinaryProtoValue(target);
        const res = try self.callValueWithThis(trap, &.{Value.obj(target)}, Value.obj(o.proxy_handler.?));
        if (!res.isNull() and (!res.isObject() or res.asObj().is_symbol or res.asObj().is_bigint))
            return self.throwError("TypeError", "proxy 'getPrototypeOf' trap must return an object or null");
        if (!try self.ordinaryIsExtensible(target)) {
            const tp = try self.ordinaryProtoValue(target);
            const same = (res.isNull() and tp.isNull()) or (res.isObject() and tp.isObject() and res.asObj() == tp.asObj());
            if (!same) return self.throwError("TypeError", "proxy 'getPrototypeOf' trap result must match the prototype of a non-extensible target");
        }
        return res;
    }

    /// [[IsExtensible]] honoring a Proxy target.
    fn ordinaryIsExtensible(self: *Interpreter, o: *value.Object) EvalError!bool {
        if (o.proxy_handler != null or o.proxy_revoked) return self.proxyIsExtensible(o);
        if (o.module_ns != null) return false; // a module namespace is never extensible
        return o.extensible;
    }

    /// [[IsExtensible]] for a Proxy (9.5.3): the boolean trap result must equal
    /// the target's own extensibility.
    pub fn proxyIsExtensible(self: *Interpreter, o: *value.Object) EvalError!bool {
        try self.proxyDepth();
        const target = o.proxy_target orelse return self.throwError("TypeError", "Cannot perform 'isExtensible' on a proxy that has been revoked");
        const trap = (try self.proxyTrap(o, "isExtensible")) orelse return self.ordinaryIsExtensible(target);
        const res = (try self.callValueWithThis(trap, &.{Value.obj(target)}, Value.obj(o.proxy_handler.?))).toBoolean();
        if (res != try self.ordinaryIsExtensible(target))
            return self.throwError("TypeError", "proxy 'isExtensible' trap result must match the target's extensibility");
        return res;
    }

    /// [[PreventExtensions]] for a Proxy (9.5.4): a truthy trap result requires
    /// the target to already be non-extensible.
    pub fn proxyPreventExt(self: *Interpreter, o: *value.Object) EvalError!bool {
        try self.proxyDepth();
        const target = o.proxy_target orelse return self.throwError("TypeError", "Cannot perform 'preventExtensions' on a proxy that has been revoked");
        const trap = (try self.proxyTrap(o, "preventExtensions")) orelse {
            if (target.proxy_handler != null) return self.proxyPreventExt(target);
            target.extensible = false;
            return true;
        };
        const res = (try self.callValueWithThis(trap, &.{Value.obj(target)}, Value.obj(o.proxy_handler.?))).toBoolean();
        if (res and try self.ordinaryIsExtensible(target))
            return self.throwError("TypeError", "proxy 'preventExtensions' cannot report success while the target is extensible");
        return res;
    }

    /// [[SetPrototypeOf]] for a Proxy: forward when the trap is absent, otherwise
    /// coerce the trap result and enforce the non-extensible target invariant.
    pub fn proxySetProto(self: *Interpreter, o: *value.Object, new_proto: ?*value.Object) EvalError!bool {
        try self.proxyDepth();
        const target = o.proxy_target orelse return self.throwError("TypeError", "Cannot perform 'setPrototypeOf' on a proxy that has been revoked");
        const proto_v: Value = if (new_proto) |p| Value.obj(p) else Value.nul();
        const trap = (try self.proxyTrap(o, "setPrototypeOf")) orelse return self.setPrototypeOfObject(target, new_proto);
        const ok = (try self.callValueWithThis(trap, &.{ Value.obj(target), proto_v }, Value.obj(o.proxy_handler.?))).toBoolean();
        if (!ok) return false;
        if (try self.ordinaryIsExtensible(target)) return true;
        const target_proto = try self.ordinaryProtoValue(target);
        if (!sameProtoValue(new_proto, target_proto))
            return self.throwError("TypeError", "proxy 'setPrototypeOf' cannot report success with a different prototype on a non-extensible target");
        return true;
    }

    fn proxyGet(self: *Interpreter, o: *value.Object, key: []const u8, receiver: Value) EvalError!Value {
        try self.proxyDepth();
        self.depth += 1;
        defer self.depth -= 1;
        const target = o.proxy_target orelse return self.throwError("TypeError", "Cannot perform 'get' on a proxy that has been revoked");
        if (try self.proxyTrap(o, "get")) |trap| {
            const res = try self.callValueWithThis(trap, &.{ Value.obj(target), self.keyToValue(key), receiver }, Value.obj(o.proxy_handler.?));
            // [[Get]] invariant (9.5.8): a non-configurable non-writable data
            // property must report its value; a non-configurable accessor with
            // no getter must report undefined.
            if (target.proxy_handler == null and !target.proxy_revoked and objectHasOwn(target, key) and !target.getAttr(key).configurable) {
                if (target.getAccessor(key)) |acc| {
                    if ((acc.get == null or acc.get.?.isUndefined()) and !res.isUndefined())
                        return self.throwError("TypeError", "proxy 'get' must report undefined for a non-configurable accessor with no getter");
                } else if (!target.getAttr(key).writable) {
                    if (target.getOwn(key)) |tv| if (!value.strictEquals(res, tv))
                        return self.throwError("TypeError", "proxy 'get' must report the target value for a non-configurable non-writable property");
                }
            }
            return res;
        }
        return self.getPropertyWithReceiver(Value.obj(target), key, receiver);
    }

    fn proxySet(self: *Interpreter, o: *value.Object, key: []const u8, v: Value, receiver: Value) EvalError!bool {
        try self.proxyDepth();
        self.depth += 1;
        defer self.depth -= 1;
        const target = o.proxy_target orelse return self.throwError("TypeError", "Cannot perform 'set' on a proxy that has been revoked");
        if (try self.proxyTrap(o, "set")) |trap| {
            const ok = (try self.callValueWithThis(trap, &.{ Value.obj(target), self.keyToValue(key), v, receiver }, Value.obj(o.proxy_handler.?))).toBoolean();
            // [[Set]] invariant (9.5.9): a successful set can't disagree with a
            // non-configurable non-writable data property, nor target a
            // non-configurable accessor that has no setter.
            if (ok and target.proxy_handler == null and !target.proxy_revoked and objectHasOwn(target, key) and !target.getAttr(key).configurable) {
                if (target.getAccessor(key)) |acc| {
                    if (acc.set == null or acc.set.?.isUndefined()) return self.throwError("TypeError", "proxy 'set' cannot succeed for a non-configurable accessor with no setter");
                } else if (!target.getAttr(key).writable) {
                    if (target.getOwn(key)) |tv| if (!value.strictEquals(v, tv))
                        return self.throwError("TypeError", "proxy 'set' cannot change a non-configurable non-writable property");
                }
            }
            return ok;
        }
        return self.setMemberResult(Value.obj(target), key, v, receiver);
    }

    fn proxyHas(self: *Interpreter, o: *value.Object, key: []const u8) EvalError!bool {
        try self.proxyDepth();
        self.depth += 1;
        defer self.depth -= 1;
        const target = o.proxy_target orelse return self.throwError("TypeError", "Cannot perform 'has' on a proxy that has been revoked");
        if (try self.proxyTrap(o, "has")) |trap| {
            const b = (try self.callValueWithThis(trap, &.{ Value.obj(target), self.keyToValue(key) }, Value.obj(o.proxy_handler.?))).toBoolean();
            // [[HasProperty]] invariant (9.5.7): can't hide a non-configurable
            // own property, nor an own property of a non-extensible target.
            if (!b and target.proxy_handler == null and !target.proxy_revoked and objectHasOwn(target, key)) {
                if (!target.getAttr(key).configurable) return self.throwError("TypeError", "proxy 'has' cannot report a non-configurable own property as absent");
                if (!try self.ordinaryIsExtensible(target)) return self.throwError("TypeError", "proxy 'has' cannot report an own property of a non-extensible target as absent");
            }
            return b;
        }
        return self.hasPropertyResult(target, key);
    }

    fn proxyDelete(self: *Interpreter, o: *value.Object, key: []const u8) EvalError!bool {
        try self.proxyDepth();
        self.depth += 1;
        defer self.depth -= 1;
        const target = o.proxy_target orelse return self.throwError("TypeError", "Cannot perform 'deleteProperty' on a proxy that has been revoked");
        if (try self.proxyTrap(o, "deleteProperty")) |trap| {
            const b = (try self.callValueWithThis(trap, &.{ Value.obj(target), self.keyToValue(key) }, Value.obj(o.proxy_handler.?))).toBoolean();
            // [[Delete]] invariant (9.5.10): can't report deleting a
            // non-configurable property, nor any property of a non-extensible target.
            if (b and target.proxy_handler == null and !target.proxy_revoked and objectHasOwn(target, key)) {
                if (!target.getAttr(key).configurable) return self.throwError("TypeError", "proxy 'deleteProperty' cannot delete a non-configurable property");
                if (!try self.ordinaryIsExtensible(target)) return self.throwError("TypeError", "proxy 'deleteProperty' cannot delete a property of a non-extensible target");
            }
            return b;
        }
        return self.deleteOwn(target, key);
    }

    /// `ownKeys` trap → an array of keys (string values). Falls back to the
    /// target's own string keys.
    /// An object's [[OwnPropertyKeys]] as encoded key strings — proxy-aware, and
    /// including an array's dense element indices and `length` (which live
    /// outside the shape).
    pub fn objectOwnKeysList(self: *Interpreter, t: *value.Object) EvalError![]const []const u8 {
        if (t.proxy_handler != null or t.proxy_revoked) return self.proxyOwnKeys(t);
        const appendReflectable = struct {
            fn f(arena: std.mem.Allocator, list: *std.ArrayListUnmanaged([]const u8), k: []const u8) !void {
                if (value.isPrivateKey(k)) return;
                if (value.isSymbolKey(k) and !value.isRealSymbolKey(k)) return;
                try list.append(arena, k);
            }
        }.f;
        if (moduleNsOf(t)) |ns| {
            try triggerDeferModule(self, ns); // `import defer`: [[OwnPropertyKeys]] evaluates first
            // Sorted string export names first, then the @@toStringTag symbol key.
            var list: std.ArrayListUnmanaged([]const u8) = .empty;
            try list.appendSlice(self.arena, ns.names);
            try list.append(self.arena, ns.tag_key);
            return list.items;
        }
        if (t.prim) |p| {
            if (p.isString()) {
                // String exotic [[OwnPropertyKeys]]: the char-index keys merged with
                // any user integer-index keys (all ascending), then "length", then
                // other string keys in insertion order, then symbols.
                var indices: std.ArrayListUnmanaged([]const u8) = .empty;
                var seen: std.AutoHashMapUnmanaged(usize, void) = .empty;
                for (p.asStr(), 0..) |_, i| {
                    try indices.append(self.arena, try std.fmt.allocPrint(self.arena, "{d}", .{i}));
                    try seen.put(self.arena, i, {});
                }
                var dense_i: usize = 0;
                while (dense_i < t.elements.items.len) : (dense_i += 1) {
                    if (t.isHole(dense_i) or seen.contains(dense_i)) continue;
                    try seen.put(self.arena, dense_i, {});
                    try indices.append(self.arena, try std.fmt.allocPrint(self.arena, "{d}", .{dense_i}));
                }
                var strings: std.ArrayListUnmanaged([]const u8) = .empty;
                var symbols: std.ArrayListUnmanaged([]const u8) = .empty;
                for (try t.ownKeys(self.arena)) |k| {
                    if (std.mem.eql(u8, k, "length") or value.isPrivateKey(k)) continue;
                    if (value.isSymbolKey(k)) {
                        if (value.isRealSymbolKey(k)) try symbols.append(self.arena, k);
                    } else if (value.canonicalIndex(k)) |idx| {
                        if (!seen.contains(idx)) {
                            try seen.put(self.arena, idx, {});
                            try indices.append(self.arena, k);
                        }
                    } else try strings.append(self.arena, k);
                }
                std.mem.sort([]const u8, indices.items, {}, struct {
                    fn lt(_: void, x: []const u8, y: []const u8) bool {
                        return value.canonicalIndex(x).? < value.canonicalIndex(y).?;
                    }
                }.lt);
                var list: std.ArrayListUnmanaged([]const u8) = .empty;
                try list.appendSlice(self.arena, indices.items);
                try list.append(self.arena, "length");
                try list.appendSlice(self.arena, strings.items);
                try list.appendSlice(self.arena, symbols.items);
                return list.items;
            }
        }
        if (t.typed_array) |ta| {
            // Integer-Indexed Exotic [[OwnPropertyKeys]]: the in-bounds element
            // indices (ascending) first, then any ordinary own string/symbol keys.
            var list: std.ArrayListUnmanaged([]const u8) = .empty;
            var i: usize = 0;
            const cur = ta.currentLength() orelse 0;
            while (i < cur) : (i += 1) try list.append(self.arena, try std.fmt.allocPrint(self.arena, "{d}", .{i}));
            for (try t.ownKeys(self.arena)) |k| try appendReflectable(self.arena, &list, k);
            return list.items;
        }
        if (t.is_array) {
            // OrdinaryOwnPropertyKeys order: integer indices ascending (merging the
            // dense element store with any sparse/accessor index in the shape),
            // then string keys in creation order — "length" exists from
            // construction so it precedes any user-added string key — then symbols.
            var indices: std.ArrayListUnmanaged([]const u8) = .empty;
            var seen: std.AutoHashMapUnmanaged(usize, void) = .empty;
            var i: usize = 0;
            while (i < t.elements.items.len) : (i += 1) {
                if (t.isHole(i)) continue;
                try indices.append(self.arena, try std.fmt.allocPrint(self.arena, "{d}", .{i}));
                try seen.put(self.arena, i, {});
            }
            var strings: std.ArrayListUnmanaged([]const u8) = .empty;
            var symbols: std.ArrayListUnmanaged([]const u8) = .empty;
            for (try t.ownKeys(self.arena)) |k| {
                if (value.isPrivateKey(k)) continue;
                if (value.isSymbolKey(k)) {
                    if (value.isRealSymbolKey(k)) try symbols.append(self.arena, k);
                } else if (value.canonicalIndex(k)) |idx| {
                    if (!seen.contains(idx)) {
                        try seen.put(self.arena, idx, {});
                        try indices.append(self.arena, k);
                    }
                } else {
                    try strings.append(self.arena, k);
                }
            }
            std.mem.sort([]const u8, indices.items, {}, struct {
                fn lt(_: void, x: []const u8, y: []const u8) bool {
                    return value.canonicalIndex(x).? < value.canonicalIndex(y).?;
                }
            }.lt);
            var list: std.ArrayListUnmanaged([]const u8) = .empty;
            try list.appendSlice(self.arena, indices.items);
            try list.append(self.arena, "length");
            try list.appendSlice(self.arena, strings.items);
            try list.appendSlice(self.arena, symbols.items);
            return list.items;
        }
        var indices: std.ArrayListUnmanaged([]const u8) = .empty;
        var seen: std.AutoHashMapUnmanaged(usize, void) = .empty;
        var dense_i: usize = 0;
        while (dense_i < t.elements.items.len) : (dense_i += 1) {
            if (t.isHole(dense_i)) continue;
            try indices.append(self.arena, try std.fmt.allocPrint(self.arena, "{d}", .{dense_i}));
            try seen.put(self.arena, dense_i, {});
        }
        var strings: std.ArrayListUnmanaged([]const u8) = .empty;
        var symbols: std.ArrayListUnmanaged([]const u8) = .empty;
        for (try t.ownKeys(self.arena)) |k| {
            if (value.isPrivateKey(k)) continue;
            if (value.isSymbolKey(k)) {
                if (value.isRealSymbolKey(k)) try symbols.append(self.arena, k);
            } else if (value.canonicalIndex(k)) |idx| {
                if (!seen.contains(idx)) {
                    try seen.put(self.arena, idx, {});
                    try indices.append(self.arena, k);
                }
            } else {
                try strings.append(self.arena, k);
            }
        }
        std.mem.sort([]const u8, indices.items, {}, struct {
            fn lt(_: void, x: []const u8, y: []const u8) bool {
                return value.canonicalIndex(x).? < value.canonicalIndex(y).?;
            }
        }.lt);
        var list: std.ArrayListUnmanaged([]const u8) = .empty;
        try list.appendSlice(self.arena, indices.items);
        try list.appendSlice(self.arena, strings.items);
        try list.appendSlice(self.arena, symbols.items);
        return list.items;
    }

    pub fn proxyOwnKeys(self: *Interpreter, o: *value.Object) EvalError![]const []const u8 {
        try self.proxyDepth();
        self.depth += 1;
        defer self.depth -= 1;
        const target = o.proxy_target orelse return self.throwError("TypeError", "Cannot perform 'ownKeys' on a proxy that has been revoked");
        if (try self.proxyTrap(o, "ownKeys")) |trap| {
            const res = try self.callValueWithThis(trap, &.{Value.obj(target)}, Value.obj(o.proxy_handler.?));
            if (!res.isObject()) return self.throwError("TypeError", "ownKeys trap must return an object");
            // CreateListFromArrayLike(types: String, Symbol): every element must
            // be a String or Symbol.
            const len = toLen(try self.toNumberV(try self.getProperty(res, "length")));
            var list: std.ArrayListUnmanaged([]const u8) = .empty;
            var i: usize = 0;
            while (i < len) : (i += 1) {
                const k = try self.getProperty(res, try std.fmt.allocPrint(self.arena, "{d}", .{i}));
                if (!k.isString() and !(k.isObject() and k.asObj().is_symbol))
                    return self.throwError("TypeError", "ownKeys trap result includes a non-String, non-Symbol key");
                try list.append(self.arena, try self.keyOf(k));
            }
            // [[OwnPropertyKeys]] invariants: no duplicates; every
            // non-configurable target key must be present; for a non-extensible
            // target the result must be exactly the target's keys.
            var seen: std.StringHashMapUnmanaged(void) = .empty;
            for (list.items) |k| {
                if (seen.contains(k)) return self.throwError("TypeError", "ownKeys trap result contains duplicate keys");
                try seen.put(self.arena, k, {});
            }
            const extensible = target.extensible;
            const tkeys = try self.objectOwnKeysList(target);
            var has_nonconfig = false;
            for (tkeys) |tk| {
                if (objectHasOwn(target, tk) and !target.getAttr(tk).configurable) has_nonconfig = true;
            }
            if (!extensible or has_nonconfig) {
                var unchecked: std.StringHashMapUnmanaged(void) = .empty;
                for (list.items) |k| try unchecked.put(self.arena, k, {});
                // Every non-configurable target key must appear.
                for (tkeys) |tk| {
                    if (!objectHasOwn(target, tk) or target.getAttr(tk).configurable) continue;
                    if (!unchecked.remove(tk)) return self.throwError("TypeError", "ownKeys trap omitted a non-configurable key");
                }
                if (!extensible) {
                    // Non-extensible: the remaining (configurable) target keys must
                    // also appear, and nothing extra may be present.
                    for (tkeys) |tk| {
                        if (!objectHasOwn(target, tk) or !target.getAttr(tk).configurable) continue;
                        if (!unchecked.remove(tk)) return self.throwError("TypeError", "ownKeys trap omitted a key on a non-extensible target");
                    }
                    if (unchecked.count() != 0) return self.throwError("TypeError", "ownKeys trap added a key absent from a non-extensible target");
                }
            }
            return list.items;
        }
        return self.objectOwnKeysList(target);
    }

    /// `Thread.restrict` enforcement: every essential-internal-method funnel
    /// calls this (get/set/has/delete/define/ownKeys/proto/extensibility).
    pub fn checkRestricted(self: *Interpreter, o: *value.Object) EvalError!void {
        const owner = o.restricted_to.load(.acquire);
        if (owner != 0 and owner != @as(u64, @intCast(std.Thread.getCurrentId())))
            return self.throwError("ConcurrentAccessError", "object is restricted to another thread");
    }

    pub fn getProperty(self: *Interpreter, recv: Value, key: []const u8) EvalError!Value {
        if (recv.isObject()) try self.checkRestricted(recv.asObj());
        return self.getPropertyWithReceiver(recv, key, recv);
    }

    /// PrivateGet (`this.#x` read). Resolves the PrivateElement on the receiver's
    /// chain: a field/method returns its value; an accessor invokes its getter, or
    /// is a TypeError if it has only a setter; an object that was never branded
    /// with the name is a TypeError ("did not declare it"). Private fields are own
    /// properties of an instance; methods/accessors live on the home object.
    fn privateGet(self: *Interpreter, recv: Value, key: []const u8) EvalError!Value {
        // Brand check: the receiver must carry this private name (it is a proper
        // instance of the declaring class evaluation, and — for a derived `this` —
        // `super()` has already returned).
        if (!recv.isObject() or !recv.asObj().hasPrivateBrand(key))
            return self.throwError("TypeError", "Cannot read private member from an object whose class did not declare it");
        var cur: ?*value.Object = recv.asObj();
        while (cur) |c| {
            if (c.getAccessor(key)) |acc| {
                if (acc.get) |g| if (!g.isUndefined()) return self.callValueWithThis(g, &.{}, recv);
                return self.throwError("TypeError", "Cannot read private member: accessor has no getter");
            }
            if (c.getOwn(key)) |v| return v; // private field (own) or method (on home)
            // A private method lives on the declaring class's prototype; when the
            // instance is a Proxy (a base that `return`ed `new Proxy(this, …)`), the
            // method is reached through the proxy's target chain, not the proxy's
            // own [[Prototype]]. (Private access never invokes proxy traps.)
            cur = if (c.proxy_handler != null) (c.proxy_target orelse c.protoAtomic()) else c.protoAtomic();
        }
        return Value.undef(); // branded but value not yet present (TDZ-like); rare
    }

    /// PrivateSet (`this.#x = v`). Resolves the PrivateElement: a field is written;
    /// a method is non-writable (TypeError); an accessor invokes its setter, or is
    /// a TypeError if it has only a getter; an unbranded object is a TypeError.
    fn privateSet(self: *Interpreter, recv: Value, key: []const u8, v: Value) EvalError!void {
        if (!recv.isObject() or !recv.asObj().hasPrivateBrand(key))
            return self.throwError("TypeError", "Cannot write private member to an object whose class did not declare it");
        const o = recv.asObj();
        var cur: ?*value.Object = o;
        while (cur) |c| {
            if (c.getAccessor(key)) |acc| {
                if (acc.set) |s| if (!s.isUndefined()) {
                    _ = try self.callValueWithThis(s, &.{v}, recv);
                    return;
                };
                return self.throwError("TypeError", "Cannot write private member: accessor has no setter");
            }
            if (c.getOwn(key)) |_| {
                // A private field is an own, writable property of the instance; an
                // inherited (home-object) private data element is a method, which
                // is read-only.
                if (c == o and c.getAttr(key).writable) {
                    try o.setOwn(self.arena, self.root_shape, key, v);
                    return;
                }
                return self.throwError("TypeError", "Cannot write private method");
            }
            // See privateGet: reach a Proxy instance's private accessor (on the
            // declaring class's prototype) through the proxy's target chain.
            cur = if (c.proxy_handler != null) (c.proxy_target orelse c.protoAtomic()) else c.protoAtomic();
        }
        // Branded, but the field's own slot has not been materialized yet (a field
        // written before its own initializer ran, e.g. `#a = (this.#b = 1)`).
        // Define it now.
        try o.setOwn(self.arena, self.root_shape, key, v);
        try o.setAttr(self.arena, key, .{ .writable = true, .enumerable = false, .configurable = false });
    }

    /// Ordinary [[Get]] with the receiver kept separate from the object where
    /// lookup starts. Reflect.get and Proxy forwarding rely on this when an
    /// inherited accessor observes `this`.
    pub fn getPropertyWithReceiver(self: *Interpreter, recv: Value, key: []const u8, receiver: Value) EvalError!Value {
        // PrivateGet is not OrdinaryGet: it resolves the PrivateElement directly
        // (a setter-only accessor read is a TypeError; an absent brand is a
        // TypeError, never `undefined`).
        if (value.isPrivateKey(key)) return self.privateGet(recv, key);
        switch (recv.kind()) {
            .object => {
                const o = recv.asObj();
                if (o.is_symbol or o.is_bigint) return self.getPrimitiveMember(recv, key);
                if (o.proxy_handler != null or o.proxy_revoked) return self.proxyGet(o, key, receiver);
                if (moduleNsOf(o)) |ns| {
                    try triggerDeferIfString(self, ns, key); // `import defer`: a string [[Get]] evaluates first
                    return moduleNsGet(self, ns, key);
                }
                // Legacy `caller`: a *non-strict ordinary* function (not strict,
                // arrow, generator, async, or bound) reads `undefined` for `.caller`
                // (we don't expose the live call stack — the "extension not
                // supported" answer test262 accepts), shadowing the inherited
                // %ThrowTypeError% poison pill — which still fires for strict/bound
                // functions and for `.arguments`. (Not `null`: `fn.caller` is never
                // null in the legacy extension; code does `caller === undefined`.)
                if (std.mem.eql(u8, key, "caller") and o.bound == null and o.getOwn(key) == null) {
                    if (funcOf(recv)) |f| {
                        if (!f.is_strict and !f.is_arrow and !f.is_generator and !f.is_async) return Value.undef();
                    }
                }
                // A (non-arrow) function's `.prototype` is an own data property,
                // materialized lazily on first access — every [[Construct]]-able
                // function has one, with a `constructor` back-reference. Without
                // this a plain `Test262Error.prototype.toString = …` (and any
                // `f.prototype.x = …`) read undefined and threw.
                if (std.mem.eql(u8, key, "prototype") and o.js_func != null and Interpreter.jsFunctionHasOwnPrototypeSlot(o) and o.getOwn("prototype") == null and o.getAccessor("prototype") == null) {
                    if (funcOf(recv)) |f| {
                        // A generator function's `.prototype` is a fresh object whose
                        // [[Prototype]] is %GeneratorPrototype% and which has NO
                        // `constructor` back-link; it is the [[Prototype]] of every
                        // instance the generator produces.
                        if (f.is_generator) {
                            return Value.obj(try self.genProtoObject(o, f.is_async));
                        }
                        if (!f.is_arrow) {
                            const proto = try self.protoObject(o);
                            // `Ctor.prototype` is { writable, !enumerable, !configurable };
                            // its `constructor` back-link is { writable, !enumerable, configurable }.
                            try o.setAttr(self.arena, "prototype", .{ .writable = true, .enumerable = false, .configurable = false });
                            try self.setProp(proto, "constructor", recv);
                            try proto.setAttr(self.arena, "constructor", .{ .writable = true, .enumerable = false, .configurable = true });
                            return Value.obj(proto);
                        }
                    }
                }
                if (o.array_buffer) |ab| {
                    if (std.mem.eql(u8, key, "byteLength") and o.getOwn(key) == null and o.getAccessor(key) == null)
                        return Value.num(@floatFromInt(if (ab.isDetached()) 0 else ab.bytes().len));
                }
                if (o.typed_array) |ta| {
                    const cur = ta.currentLength(); // null when detached / out of bounds
                    if (std.mem.eql(u8, key, "length") and o.getOwn(key) == null and o.getAccessor(key) == null) return Value.num(@floatFromInt(cur orelse 0));
                    if (std.mem.eql(u8, key, "byteLength") and o.getOwn(key) == null and o.getAccessor(key) == null) return Value.num(@floatFromInt((cur orelse 0) * ta.kind.byteSize()));
                    if (std.mem.eql(u8, key, "byteOffset") and o.getOwn(key) == null and o.getAccessor(key) == null) return Value.num(@floatFromInt(if (cur == null) 0 else ta.byte_offset));
                    if (std.mem.eql(u8, key, "buffer") and o.getOwn(key) == null and o.getAccessor(key) == null) return Value.obj(ta.buffer);
                    if (std.mem.eql(u8, key, "BYTES_PER_ELEMENT") and o.getOwn(key) == null and o.getAccessor(key) == null) return Value.num(@floatFromInt(ta.kind.byteSize()));
                    if (arrayIndex(key)) |i| {
                        if (i >= (cur orelse 0)) return Value.undef();
                        if (ta.kind.isBigInt()) return self.makeBigInt(value.taReadBig(ta, i));
                        return value.taRead(ta, i);
                    }
                    // A canonical numeric key that isn't a plain in-range index
                    // ("-0", "-1", "1.5", out-of-bounds, …) reads as undefined and
                    // never consults the prototype (Integer-Indexed [[Get]]).
                    if (canonicalNumericIndexString(key) != null) return Value.undef();
                    // other keys (methods, constructor, @@toStringTag) fall through.
                }
                if (o.is_array) {
                    // An arguments object's `length` is an ordinary own data
                    // property (deletable / redefinable), not the Array exotic
                    // length — once deleted it is simply absent (fall through to
                    // the prototype lookup), with no element-count fallback.
                    if (o.is_arguments) {
                        if (std.mem.eql(u8, key, "length")) {
                            if (o.getOwn("length")) |l| return l;
                        }
                    } else if (std.mem.eql(u8, key, "length"))
                        return Value.num(@floatFromInt(o.arrayLength()));
                    // An accessor defined on an index (via defineProperty) wins
                    // over the dense element store, so the getter is invoked.
                    if (arrayElementIndex(key)) |i| {
                        // A mapped arguments index reads its parameter binding.
                        if (argMapName(o, i)) |nm| {
                            const aenv: *Environment = @ptrCast(@alignCast(o.arg_map_env.?));
                            return aenv.get(nm) orelse Value.undef();
                        }
                        // A present (non-hole) dense element with no index accessor
                        // is returned directly; a hole falls through to the proto
                        // chain so an inherited index (e.g. `Array.prototype[0]`) is
                        // seen, and an accessor likewise wins over the store.
                        if (o.getAccessor(key) == null) {
                            if (o.denseElement(i)) |v| return v;
                        }
                        // else fall through: hole, accessor, or a sparse named property.
                    }
                }
                if (!o.is_array) {
                    if (arrayElementIndex(key)) |i| {
                        if (o.getOwn(key) == null and o.getAccessor(key) == null) {
                            if (o.denseElement(i)) |v| return v;
                        }
                    }
                }
                // A String-wrapper object exposes `length` and indexed chars as
                // own integer-keyed properties (`new String("ab").length === 2`,
                // `[0] === "a"`).
                if (o.prim) |p| {
                    if (p.isString()) {
                        if (std.mem.eql(u8, key, "length")) return Value.num(@floatFromInt(utf16LenOfString(p.asStr())));
                        if (arrayIndex(key)) |i| {
                            if (try self.stringIndexValue(p.asStr(), i)) |v| return v;
                        }
                    }
                }
                // Accessor or data, then walk the prototype chain (a native/bound
                // function with no explicit prototype inherits from
                // %Function.prototype% — so `fn.constructor`, `fn.call` as a
                // value, etc. resolve).
                var cur: ?*value.Object = o;
                while (cur) |c| {
                    if (c.proxy_handler != null or c.proxy_revoked)
                        return self.proxyGet(c, key, receiver);
                    // A module namespace reached through the prototype chain (its
                    // exports live in the ModuleNs, not as own properties): a
                    // string [[Get]] triggers a deferred module's evaluation, then
                    // reads the export (its [[Prototype]] is null, so it ends here).
                    if (moduleNsOf(c)) |ns| {
                        try triggerDeferIfString(self, ns, key);
                        return moduleNsGet(self, ns, key);
                    }
                    if (c.is_array and std.mem.eql(u8, key, "length")) {
                        // arguments `length` is an ordinary own property (absent
                        // once deleted); a real Array's is the exotic length.
                        if (c.is_arguments) {
                            if (c.getOwn("length")) |l| return l;
                        } else return Value.num(@floatFromInt(c.arrayLength())); // locked length read (grow-vs-read)
                    }
                    if (c.getAccessor(key)) |acc| {
                        // An explicit `get: undefined` is stored as the undefined
                        // value but means "no getter".
                        if (acc.get) |g| {
                            if (!g.isUndefined()) return self.callValueWithThis(g, &.{}, receiver);
                        }
                        return Value.undef(); // accessor with no getter
                    }
                    if (c.is_array) {
                        if (arrayElementIndex(key)) |i| {
                            // A mapped arguments index reads its parameter binding.
                            if (argMapName(c, i)) |nm| {
                                const aenv: *Environment = @ptrCast(@alignCast(c.arg_map_env.?));
                                return aenv.get(nm) orelse Value.undef();
                            }
                            // Locked dense read (no-GIL grow-vs-read class): a peer
                            // append/realloc must not race this len/bounds/element read.
                            if (c.getAccessor(key) == null) if (c.denseElement(i)) |v| return v;
                        }
                    } else if (arrayElementIndex(key)) |i| {
                        if (c.getOwn(key) == null and c.getAccessor(key) == null) if (c.denseElement(i)) |v| return v;
                    }
                    if (c.prim) |p| {
                        if (p.isString()) {
                            if (std.mem.eql(u8, key, "length")) return Value.num(@floatFromInt(utf16LenOfString(p.asStr())));
                            if (arrayIndex(key)) |i| {
                                if (try self.stringIndexValue(p.asStr(), i)) |v| return v;
                            }
                        }
                    }
                    if (c.getOwn(key)) |v| return v;
                    cur = self.effectiveProto(c);
                }
                // On the global object, an absent own property falls back to the
                // global lexical bindings, so `globalThis.Math`, `this.parseInt`,
                // etc. resolve to the installed globals.
                if (self.global_object != null and o == self.global_object.?) {
                    if (rootEnv(self.env).get(key)) |v| return v;
                }
                // Accessing a private member the object doesn't carry is a brand
                // violation — a TypeError, not `undefined`.
                if (value.isPrivateKey(key)) return self.throwError("TypeError", "Cannot read private member from an object whose class did not declare it");
                // `.constructor` falls back to the kind's global constructor
                // (we don't wire instance prototypes yet).
                if (std.mem.eql(u8, key, "constructor")) {
                    if (self.constructorOf(recv)) |ctor| return ctor;
                }
                return Value.undef();
            },
            .string, .number, .boolean => return self.getPrimitiveMember(recv, key),
            .undefined, .null => return self.throwError("TypeError", "cannot read property of null or undefined"),
        }
    }

    /// [[Get]] on a primitive base: ToObject(base) for lookup, with the original
    /// primitive as the receiver passed to inherited accessors/proxy traps.
    fn getPrimitiveMember(self: *Interpreter, recv: Value, key: []const u8) EvalError!Value {
        if (recv.isString()) {
            const s = recv.asStr();
            if (std.mem.eql(u8, key, "length")) return Value.num(@floatFromInt(utf16LenOfString(s)));
            if (arrayIndex(key)) |i| {
                if (try self.stringIndexValue(s, i)) |v| return v;
                return Value.undef();
            }
        }
        const boxed = try self.boxPrimitiveBase(recv);
        var cur: ?*value.Object = boxed;
        while (cur) |c| {
            if (c.proxy_handler != null or c.proxy_revoked)
                return self.proxyGet(c, key, recv);
            if (c.getAccessor(key)) |acc| {
                if (acc.get) |g| {
                    if (!g.isUndefined()) return self.callValueWithThis(g, &.{}, recv);
                }
                return Value.undef();
            }
            if (c.getOwn(key)) |v| return v;
            cur = self.effectiveProto(c);
        }
        if (std.mem.eql(u8, key, "constructor")) {
            if (self.constructorOf(recv)) |ctor| return ctor;
        }
        return Value.undef();
    }

    /// The global constructor for a value's kind (`[].constructor === Array`).
    /// A fallback used when the prototype chain doesn't supply `constructor`
    /// (instance prototypes aren't wired yet).
    fn constructorOf(self: *Interpreter, recv: Value) ?Value {
        const name: []const u8 = switch (recv.kind()) {
            .string => "String",
            .number => "Number",
            .boolean => "Boolean",
            .object => blk: {
                const o = recv.asObj();
                break :blk if (o.is_array) "Array" else if (o.is_regex) "RegExp" else if (o.is_symbol) "Symbol" else if (o.is_error) (if (o.error_name.len > 0) o.error_name else "Error") else if (o.is_map) "Map" else if (o.is_set) "Set" else if (o.is_date) "Date" else if (o.prim) |p| (switch (p.kind()) {
                    .number => "Number",
                    .string => "String",
                    .boolean => "Boolean",
                    else => "Object",
                }) else if (o.isCallableObject()) "Function" else "Object";
            },
            else => return null,
        };
        return self.env.get(name);
    }

    // ---- destructuring ----------------------------------------------------

    /// Bind a value to a destructuring target. `declare` selects whether leaf
    /// identifiers are declared in the current scope (`let {a}=…`) or assigned
    /// to an existing binding / member (`({a}=…)` and parameter binding uses
    /// declare).
    /// VM entry for `bind_pattern`: destructure `val` into `target` with the
    /// given mode (0 var, 1 let, 2 const, 3 assignment), reusing `bindPattern`.
    pub fn bindPatternVM(self: *Interpreter, target: *Node, val: Value, mode: u32) EvalError!void {
        const saved_const = self.binding_const;
        const saved_hoist = self.binding_hoisted;
        self.binding_const = (mode == 2);
        self.binding_hoisted = false;
        defer {
            self.binding_const = saved_const;
            self.binding_hoisted = saved_hoist;
        }
        try self.bindPattern(target, val, mode != 3);
    }

    fn bindPattern(self: *Interpreter, target: *Node, val: Value, declare: bool) EvalError!void {
        switch (target.*) {
            .identifier => |name| if (declare)
                (if (self.binding_hoisted)
                    try self.globalDefine(name, val)
                else if (self.binding_const)
                    try self.env.putConst(name, val)
                else
                    try self.env.put(name, val))
            else
                // Assignment-form target: route through `assignTo` so const/TDZ/
                // strict/with checks apply (e.g. `[c] = …` with const `c`).
                try self.assignTo(target, val),
            .member => |m| { // assignment destructuring into obj.prop / arr[i]
                const recv = try self.eval(m.object);
                const key = try self.memberKey(m.property, m.computed);
                try self.setMember(recv, key, val);
            },
            .obj_pattern => |p| try self.destructureObject(p.props, p.rest, val, declare),
            .arr_pattern => |p| try self.destructureArray(p.elems, p.rest, val, declare),
            else => return self.throwError("SyntaxError", "invalid destructuring target"),
        }
    }

    fn destructureObject(self: *Interpreter, props: []ast.ObjPatProp, rest: ?*Node, val: Value, declare: bool) EvalError!void {
        if (val.isUndefined() or val.isNull())
            return self.throwError("TypeError", "cannot destructure null or undefined");
        var consumed: std.ArrayListUnmanaged([]const u8) = .empty;
        for (props) |prop| {
            const key = if (prop.key_expr) |ke| try self.keyOf(try self.eval(ke)) else prop.key;
            try consumed.append(self.arena, key);
            // KeyedDestructuringAssignmentEvaluation: when the target is a plain
            // member reference (assignment form), its reference (base, then the key
            // EXPRESSION) is evaluated BEFORE GetV(value, key) — and ToPropertyKey of
            // the target's computed key is deferred to PutValue, after GetV.
            const member_assign = !declare and prop.target.* == .member;
            var m_base: Value = undefined;
            var m_keyval: Value = undefined;
            if (member_assign) {
                const m = prop.target.member;
                m_base = try self.eval(m.object);
                if (m.computed) |ce| m_keyval = try self.eval(ce);
            }
            // KeyedBindingInitialization for a SingleNameBinding resolves the
            // target binding (step 2) BEFORE GetV(value, P) (step 3). Inside a
            // `with`, that ResolveBinding walk is observable — the object
            // Environment Record's [[HasBinding]] (a proxy `has` trap). Trigger
            // it now (a no-op when no `with` shadows the name).
            if (declare and prop.target.* == .identifier)
                _ = try self.assignWithObject(prop.target.identifier);
            var v = try self.getProperty(val, key);
            if (v.isUndefined()) {
                if (prop.default) |d| {
                    v = try self.eval(d);
                    if (prop.target.* == .identifier) try self.maybeNameAnon(v, d, prop.target.identifier);
                }
            }
            if (member_assign) {
                const m = prop.target.member;
                const tkey = if (m.computed != null) try self.keyOf(m_keyval) else m.property;
                try self.setMember(m_base, tkey, v);
            } else {
                try self.bindPattern(prop.target, v, declare);
            }
        }
        if (rest) |rest_target| {
            const rest_obj = try self.newObject();
            if (val.isObject()) {
                // Object rest copies only the *enumerable* own properties. A Proxy
                // source goes through [[OwnPropertyKeys]] + per-key
                // [[GetOwnProperty]] (the `ownKeys`/`getOwnPropertyDescriptor`
                // traps), since its raw key set is empty.
                const vo = val.asObj();
                const is_proxy = vo.proxy_handler != null or vo.proxy_revoked;
                const keys = if (is_proxy) try self.objectOwnKeysList(vo) else try vo.enumerableKeys(self.arena);
                outer: for (keys) |k| {
                    if (value.isPrivateKey(k)) continue;
                    for (consumed.items) |c| {
                        if (std.mem.eql(u8, c, k)) continue :outer;
                    }
                    if (is_proxy) {
                        const desc = try builtins.objectGetOwnPropertyDescriptor(self, Value.undef(), &.{ val, self.keyToValue(k) });
                        if (!(desc.isObject() and (try self.getProperty(desc, "enumerable")).toBoolean())) continue;
                    }
                    // Copy via [[Get]] so an accessor's getter runs (and a data
                    // property's value is read), landing as a plain data prop.
                    try self.setProp(rest_obj.asObj(), k, try self.getProperty(val, k));
                }
                // CopyDataProperties copies own enumerable *symbol* keys too,
                // ordered after the string keys. `enumerableKeys` (above) drops
                // them, so enumerate them here. (A Proxy source already surfaces
                // its symbol keys through `objectOwnKeysList` in the loop above.)
                if (!is_proxy) {
                    outer_sym: for (try vo.ownKeys(self.arena)) |k| {
                        if (!value.isSymbolKey(k) or !value.isRealSymbolKey(k)) continue;
                        if (!vo.getAttr(k).enumerable) continue;
                        for (consumed.items) |c| {
                            if (std.mem.eql(u8, c, k)) continue :outer_sym;
                        }
                        try self.setProp(rest_obj.asObj(), k, try self.getProperty(val, k));
                    }
                }
            } else if (val.isString()) {
                // ToObject(string): a String exotic object whose own *enumerable*
                // properties are its UTF-16 index chars (`{...r} = "foo"` ⇒
                // r = {0:"f",1:"o",2:"o"}; `length` is non-enumerable). Other
                // primitives (number/boolean/symbol/bigint) have no own enumerable
                // properties, so their rest object is correctly empty.
                const s = val.asStr();
                const n = utf16LenOfString(s);
                var i: usize = 0;
                outer_str: while (i < n) : (i += 1) {
                    const k = try std.fmt.allocPrint(self.arena, "{d}", .{i});
                    for (consumed.items) |c| {
                        if (std.mem.eql(u8, c, k)) continue :outer_str;
                    }
                    try self.setProp(rest_obj.asObj(), k, try self.elementAt(val, i));
                }
            }
            // A declaration binds the rest name; an assignment writes through the
            // target reference — which may be a member (`({...obj.y} = …)`), so it
            // runs a setter / honors a const binding like any other assignment.
            if (declare) {
                try self.bindPattern(rest_target, rest_obj, true);
            } else {
                try self.assignTo(rest_target, rest_obj);
            }
        }
    }

    fn destructureArray(self: *Interpreter, elems: []ast.ArrPatElem, rest: ?*Node, val: Value, declare: bool) EvalError!void {
        if (val.isUndefined() or val.isNull())
            return self.throwError("TypeError", "cannot destructure null or undefined");

        // Fast path: a real array (whose `Array.prototype[Symbol.iterator]` is
        // still the native one) or a string — index directly, no iterator object
        // churn. A deleted/overridden array iterator falls to the general path.
        if ((val.isObject() and val.asObj().is_array and self.arrayIterIntact()) or val.isString()) {
            var idx: usize = 0;
            for (elems) |elem| {
                var v = try self.elementAt(val, idx);
                idx += 1;
                if (elem.target) |t| {
                    if (v.isUndefined()) {
                        if (elem.default) |d| {
                            v = try self.eval(d);
                            if (t.* == .identifier) try self.maybeNameAnon(v, d, t.identifier);
                        }
                    }
                    try self.bindPattern(t, v, declare);
                }
            }
            if (rest) |rest_target| {
                const rest_arr = try self.newArray();
                const len = iterableLen(val);
                while (idx < len) : (idx += 1) {
                    try rest_arr.asObj().elements.append(rest_arr.asObj().elementsAllocator(self.arena), try self.elementAt(val, idx));
                }
                try self.bindPattern(rest_target, rest_arr, declare);
            }
            return;
        }

        // General path: drive the iterator protocol, so array destructuring
        // works over generators, Set/Map, the `arguments` object, and any user
        // value with `[Symbol.iterator]`. `iteratorOf` throws the spec's
        // TypeError for a genuinely non-iterable value (e.g. a number or a
        // plain object), so destructuring those still fails the right way.
        const iter_obj = try self.iteratorOf(val);
        const next_method = try self.getProperty(iter_obj, "next");
        var done = false;
        // IteratorClose on an abrupt completion: if any element step (target
        // reference, default expression, assignment, or pattern) throws while the
        // iterator is still open, close it (the original throw wins). A throw from
        // IteratorStep/IteratorValue itself marks the iterator done (no close).
        errdefer if (!done) self.iteratorCloseKeepingThrow(iter_obj);
        for (elems) |elem| {
            // Assignment destructuring evaluates a member target's Reference
            // (its object, then the computed key EXPRESSION) BEFORE IteratorStep, so
            // a throw there closes the still-open iterator without ever calling
            // `next()`. ToPropertyKey of the computed key is deferred to PutValue.
            var member_recv: Value = Value.undef();
            var member_keyval: Value = Value.undef();
            var is_member = false;
            if (!declare) if (elem.target) |t| if (t.* == .member) {
                is_member = true;
                member_recv = try self.eval(t.member.object);
                if (t.member.computed) |ce| member_keyval = try self.eval(ce);
            };
            var v: Value = Value.undef();
            if (!done) {
                const res = self.callValueWithThis(next_method, &.{}, iter_obj) catch |e| {
                    done = true;
                    return e;
                };
                if (!res.isObject() or res.asObj().is_symbol or res.asObj().is_bigint) {
                    done = true;
                    return self.throwError("TypeError", "iterator result is not an object");
                }
                const is_done = (self.getProperty(res, "done") catch |e| {
                    done = true;
                    return e;
                }).toBoolean();
                if (is_done) done = true else v = self.getProperty(res, "value") catch |e| {
                    done = true;
                    return e;
                };
            }
            if (elem.target) |t| {
                if (v.isUndefined()) {
                    if (elem.default) |d| v = try self.eval(d);
                }
                if (is_member) {
                    const tkey = if (t.member.computed != null) try self.keyOf(member_keyval) else t.member.property;
                    try self.setMember(member_recv, tkey, v);
                } else try self.bindPattern(t, v, declare);
            }
        }
        if (rest) |rest_target| {
            // Like an element, a member rest target's Reference is evaluated BEFORE
            // the iterator is drained (a throw here closes it, having stepped only
            // for the preceding elements).
            var rest_recv: Value = Value.undef();
            var rest_key: ?[]const u8 = null;
            if (!declare and rest_target.* == .member) {
                rest_recv = try self.eval(rest_target.member.object);
                rest_key = try self.memberKey(rest_target.member.property, rest_target.member.computed);
            }
            const rest_arr = try self.newArray();
            while (!done) {
                const res = self.callValueWithThis(next_method, &.{}, iter_obj) catch |e| {
                    done = true;
                    return e;
                };
                if (!res.isObject() or res.asObj().is_symbol or res.asObj().is_bigint) {
                    done = true;
                    return self.throwError("TypeError", "iterator result is not an object");
                }
                if ((self.getProperty(res, "done") catch |e| {
                    done = true;
                    return e;
                }).toBoolean()) {
                    done = true;
                    break;
                }
                try rest_arr.asObj().elements.append(rest_arr.asObj().elementsAllocator(self.arena), try self.getProperty(res, "value"));
            }
            if (rest_key) |k| try self.setMember(rest_recv, k, rest_arr) else try self.bindPattern(rest_target, rest_arr, declare); // iterator already exhausted
            return;
        }
        // IteratorClose: if destructuring finished before the iterator was
        // exhausted, call its `return()` to let it clean up. This is a NORMAL
        // completion close — its own throw must propagate — so disarm the abrupt
        // errdefer first (set `done`) to avoid a double close.
        const needs_close = !done;
        done = true;
        if (needs_close) try self.iteratorClose(iter_obj);
    }

    /// IteratorClose: invoke `iterator.return()` if present (generators are
    /// closed through their dispatched `return`). The result is discarded; a
    /// throw propagates (normal-completion close).
    pub fn iteratorClose(self: *Interpreter, iter: Value) EvalError!void {
        if (iter.isObject() and iter.asObj().gen != null) {
            const r = try self.callMethod(iter, "return", &.{});
            if (!r.isObject()) return self.throwError("TypeError", "iterator 'return' did not return an object");
            return;
        }
        // GetMethod(iterator, "return"): absent (undefined/null) → no close; a
        // present-but-non-callable `return` is a TypeError. A normal-completion
        // close also requires `return()` to return an object.
        const ret = try self.getProperty(iter, "return");
        if (ret.isUndefined() or ret.isNull()) return;
        if (!ret.isCallable()) return self.throwError("TypeError", "iterator 'return' is not a function");
        const r = try self.callValueWithThis(ret, &.{}, iter);
        if (!r.isObject()) return self.throwError("TypeError", "iterator 'return' did not return an object");
    }

    /// IteratorClose with an existing throw completion: close `iter`, but keep the
    /// pending exception (a throw from `return()` is discarded — the original
    /// completion wins). Used when an iterator-helper callback throws.
    pub fn iteratorCloseKeepingThrow(self: *Interpreter, iter: Value) void {
        const saved = self.exception;
        self.iteratorClose(iter) catch {};
        self.exception = saved;
    }

    /// Close every iterator in `list` in reverse list order while preserving the
    /// in-flight throw completion (its value in `self.exception`): any error a
    /// `return()` raises is discarded. Mirrors IteratorCloseAll over a Throw
    /// completion for the `Iterator.zip` setup phase.
    pub fn closeListKeepingThrow(self: *Interpreter, list: []const Value) void {
        const saved = self.exception;
        var i: usize = list.len;
        while (i > 0) {
            i -= 1;
            self.iteratorClose(list[i]) catch {};
            self.exception = saved;
        }
    }

    /// Element `i` of an array/string for array destructuring (undefined if out
    /// of range). Non-iterable values raise a TypeError.
    fn elementAt(self: *Interpreter, val: Value, i: usize) EvalError!Value {
        switch (val.kind()) {
            .object => {
                const o = val.asObj();
                if (!o.is_array) return self.throwError("TypeError", "value is not iterable");
                return o.elementAt(i) orelse Value.undef();
            },
            .string => {
                const s = val.asStr();
                if (i >= s.len) return Value.undef();
                return Value.str(try self.arena.dupe(u8, s[i .. i + 1]));
            },
            else => return self.throwError("TypeError", "value is not iterable"),
        }
    }

    fn iterableLen(val: Value) usize {
        return switch (val.kind()) {
            .object => if (val.asObj().is_array) val.asObj().elementsLen() else 0,
            .string => val.asStr().len,
            else => 0,
        };
    }

    /// Assign to a named variable with the same immutability checks `assignTo`
    /// applies, for the bytecode VM's `store_var` (which would otherwise bypass
    /// them): a `const` reassignment throws; a function-expression name throws in
    /// strict code and is a no-op in sloppy code.
    pub fn assignVarVM(self: *Interpreter, name: []const u8, v: Value) EvalError!void {
        // A `with` object that provides this name takes the write (its
        // SetMutableBinding: HasProperty re-check, then Set) — the VM store path
        // must consult it just like the tree-walker's assignTo, or the write
        // wrongly falls through to a fresh global.
        if (try self.assignWithObject(name)) |o| {
            const still = try self.hasPropertyResult(o, name); // SetMutableBinding step 2
            if (!still and self.strict) return self.throwError("ReferenceError", name);
            return self.setMember(Value.obj(o), name, v);
        }
        if (self.env.isAlias(name)) return self.throwError("TypeError", "Assignment to constant variable.");
        if (self.env.isConst(name)) |c| {
            if (c) return self.throwError("TypeError", "Assignment to constant variable.");
        }
        if (self.env.isFnName(name)) {
            if (self.strict) return self.throwError("TypeError", "Assignment to constant variable.");
            return;
        }
        if (self.env.get(name) == null) {
            if (self.strict and !self.globalHasOwn(name))
                return self.throwError("ReferenceError", name);
            if (self.currentGlobalObject()) |g| return self.setMember(Value.obj(g), name, v);
        }
        if (self.globalBindingObject(name)) |g| {
            try self.setMember(Value.obj(g), name, v);
            if (g.getOwn(name)) |nv| try self.env.assign(name, nv);
            return;
        }
        try self.env.assign(name, v);
    }

    pub fn defineLexicalVM(self: *Interpreter, name: []const u8, v: Value, is_const: bool) EvalError!void {
        try self.checkRestrictedGlobalLexical(name);
        if (is_const)
            try self.env.putConst(name, v)
        else
            try self.env.put(name, v);
    }

    fn assignTo(self: *Interpreter, target: *Node, v: Value) EvalError!void {
        switch (target.*) {
            .identifier => |name| {
                // A `with` object that provides this name (and isn't shadowed by a
                // closer binding) takes the write (honoring `[Symbol.unscopables]`).
                if (try self.assignWithObject(name)) |o| return self.setMember(Value.obj(o), name, v);
                // Assigning to a binding still in its TDZ is a ReferenceError.
                if (self.env.get(name)) |cur| {
                    if (self.isTdz(cur)) return self.throwError("ReferenceError", name);
                }
                // An imported binding is immutable (a module indirect binding):
                // assigning to it is a TypeError.
                if (self.env.isAlias(name)) return self.throwError("TypeError", "Assignment to constant variable.");
                // Assigning to a `const` binding is a TypeError.
                if (self.env.isConst(name)) |c| {
                    if (c) return self.throwError("TypeError", "Assignment to constant variable.");
                }
                // A named function expression's own name is immutable: throw in
                // strict code, silently ignore in sloppy code.
                if (self.env.isFnName(name)) {
                    if (self.strict) return self.throwError("TypeError", "Assignment to constant variable.");
                    return;
                }
                // Strict mode forbids creating a global by assigning to an
                // undeclared binding. Sloppy mode creates/configures a global
                // object property, not a non-deletable `var` binding.
                if (self.env.get(name) == null) {
                    if (self.strict and !self.globalHasOwn(name))
                        return self.throwError("ReferenceError", name);
                    if (self.global_object) |g| return self.setMember(Value.obj(g), name, v);
                }
                if (self.globalBindingObject(name)) |g| {
                    try self.setMember(Value.obj(g), name, v);
                    if (g.getOwn(name)) |nv| try self.env.assign(name, nv);
                    return;
                }
                try self.env.assign(name, v);
            },
            .member => |m| {
                const recv = try self.eval(m.object);
                if (m.computed) |ce| {
                    // Same spec order as a member read: key expression first, then
                    // the null/undefined base check, then ToPropertyKey.
                    const kv = try self.eval(ce);
                    if (recv.isNull() or recv.isUndefined())
                        return self.throwError("TypeError", "cannot set property of null or undefined");
                    var fast_key_buf: [24]u8 = undefined;
                    const key = if (fastNumericIndex(kv)) |idx| blk: {
                        if (try self.setFastArrayNumericIndex(recv, idx, v)) return;
                        break :blk std.fmt.bufPrint(&fast_key_buf, "{d}", .{idx}) catch unreachable;
                    } else try self.keyOf(kv);
                    return self.setMember(recv, key, v);
                }
                try self.setMember(recv, m.property, v);
            },
            // `super.x = v` / `super[e] = v`: PutValue on a super reference sets
            // the property with `this` as the receiver, so the write lands on (or
            // through an inherited setter of) the current instance.
            .super_member => |m| {
                const home = self.home_object orelse return self.throwError("SyntaxError", "'super' outside a method");
                // GetThisBinding precedes evaluating the key (see the read path): a
                // derived-ctor `super[expr] = …` before `super()` is a ReferenceError.
                if (!self.this_initialized) return self.throwError("ReferenceError", "Must call super constructor before using 'this'");
                // GetSuperBase before ToPropertyKey of the computed key (see the
                // read path), so a key `toString` that mutates the home prototype
                // can't redirect the write.
                const parent = home.protoAtomic() orelse return self.throwError("TypeError", "Cannot set property of null (super)");
                const key = try self.memberKey(m.property, m.computed);
                if (!try self.setMemberResult(Value.obj(parent), key, v, self.this_value)) {
                    if (self.strict) return self.throwError("TypeError", "Cannot set property");
                }
            },
            .call => {
                _ = try self.eval(target);
                return self.throwError("ReferenceError", "invalid assignment target");
            },
            // Assignment destructuring: `[a, b] = x` / `({a} = o)`.
            .obj_pattern, .arr_pattern => try self.bindPattern(target, v, false),
            else => return self.throwError("ReferenceError", "invalid assignment target"),
        }
    }

    /// Assign `recv[key] = v`. Arrays route integer keys to the dense element
    /// store (growing with holes); everything else is a named property. Shared
    /// by the tree-walker and the VM.
    pub fn setMember(self: *Interpreter, recv: Value, key: []const u8, v: Value) EvalError!void {
        if (!try self.setMemberResult(recv, key, v, recv)) {
            if (self.strict) return self.throwError("TypeError", "Cannot set property");
        }
    }

    /// Internal [[Set]] returning the spec boolean result. Assignment callers
    /// translate a false result into a strict-mode TypeError; Reflect.set returns
    /// the boolean directly.
    pub fn setMemberResult(self: *Interpreter, recv: Value, key: []const u8, v: Value, receiver: Value) EvalError!bool {
        if (recv.isObject()) try self.checkRestricted(recv.asObj());
        // PrivateSet is not OrdinarySet: it resolves the PrivateElement (writing a
        // field, invoking a setter, or a TypeError for a method / getter-only
        // accessor / unbranded object) — never creating a new own property.
        if (value.isPrivateKey(key)) {
            try self.privateSet(recv, key, v);
            return true;
        }
        if (recv.isObject() and (recv.asObj().is_symbol or recv.asObj().is_bigint))
            return self.setPrimitiveMemberResult(recv, key, v);
        if (!recv.isObject()) {
            if (recv.isNull() or recv.isUndefined())
                return self.throwError("TypeError", "Cannot set property of null or undefined");
            return self.setPrimitiveMemberResult(recv, key, v);
        }
        const o = recv.asObj();
        if (o.proxy_handler != null or o.proxy_revoked) return self.proxySet(o, key, v, receiver);
        // A module namespace's [[Set]] always fails: strict throws, sloppy is a
        // silent no-op.
        if (o.module_ns != null) return false;
        if (o.typed_array) |ta| {
            // Integer-Indexed Exotic [[Set]] for a canonical numeric key.
            const numkey: ?f64 = if (arrayIndex(key)) |i| @as(f64, @floatFromInt(i)) else canonicalNumericIndexString(key);
            if (numkey) |n| {
                const same = (receiver.isObject() and receiver.asObj() == o);
                if (same) {
                    // IntegerIndexedElementSet: ToNumber/ToBigInt always runs (an
                    // observable valueOf, can throw) even for an out-of-bounds /
                    // detached index — and BEFORE the validity check, because the
                    // coercion can resize the buffer and change which index is
                    // valid; the store happens only if the index is valid after.
                    if (ta.kind.isBigInt()) {
                        const bv = try self.toBigIntValueImpl(v, false);
                        if (isValidIntegerIndex(ta, n)) value.taWriteBig(ta, @intFromFloat(n), bv.asObj().bigint);
                    } else {
                        const num = try self.toNumberV(v);
                        if (isValidIntegerIndex(ta, n)) value.taWrite(ta, @intFromFloat(n), num);
                    }
                    return true;
                }
                // A different Receiver: an invalid index on the target is a no-op
                // that does NOT coerce the value. A valid target index does
                // OrdinarySet → CreateDataProperty(Receiver, P, V): on a typed-array
                // receiver that is a [[DefineOwnProperty]] (false for a bad index,
                // never an inherited setter); on any other object an ordinary set.
                if (!isValidIntegerIndex(ta, n)) return true;
                if (!receiver.isObject()) return true;
                const rcv = receiver.asObj();
                if (rcv.typed_array) |rta| {
                    if (!isValidIntegerIndex(rta, n)) return false;
                    if (rta.kind.isBigInt()) {
                        const bv = try self.toBigIntValueImpl(v, false);
                        value.taWriteBig(rta, @intFromFloat(n), bv.asObj().bigint);
                    } else {
                        value.taWrite(rta, @intFromFloat(n), try self.toNumberV(v));
                    }
                    return true;
                }
                if (rcv.proxy_handler != null or rcv.proxy_revoked) {
                    const existing = try builtins.objectGetOwnPropertyDescriptor(@ptrCast(self), Value.undef(), &.{ Value.obj(rcv), self.keyToValue(key) });
                    const desc = (try self.newObject()).asObj();
                    try desc.setOwn(self.arena, self.root_shape, "value", v);
                    if (existing.isObject()) {
                        if (existing.asObj().getOwn("get") != null or existing.asObj().getOwn("set") != null) return false;
                        if (existing.asObj().getOwn("writable")) |w| if (!w.toBoolean()) return false;
                    } else {
                        try desc.setOwn(self.arena, self.root_shape, "writable", Value.boolVal(true));
                        try desc.setOwn(self.arena, self.root_shape, "enumerable", Value.boolVal(true));
                        try desc.setOwn(self.arena, self.root_shape, "configurable", Value.boolVal(true));
                    }
                    return try builtins.defineOneResult(self, rcv, key, desc);
                }
                if (rcv.getAccessor(key) != null) return false;
                if (rcv.getOwn(key)) |_| {
                    if (!rcv.getAttr(key).writable) return false;
                    try self.setProp(rcv, key, v);
                    return true;
                }
                if (!rcv.extensible) return false;
                const desc = (try self.newObject()).asObj();
                try desc.setOwn(self.arena, self.root_shape, "value", v);
                try desc.setOwn(self.arena, self.root_shape, "writable", Value.boolVal(true));
                try desc.setOwn(self.arena, self.root_shape, "enumerable", Value.boolVal(true));
                try desc.setOwn(self.arena, self.root_shape, "configurable", Value.boolVal(true));
                return builtins.defineOneResult(self, rcv, key, desc);
            }
            // non-index keys fall through to ordinary [[Set]].
        }
        if (o.prim) |p| {
            if (p.isString()) {
                if (std.mem.eql(u8, key, "length")) return false;
                if (arrayIndex(key)) |i| if (i < utf16LenOfString(p.asStr())) return false;
            }
        }
        if (o.is_arguments) {
            if (std.mem.eql(u8, key, "length")) {
                try self.setProp(o, key, v);
                return true;
            }
            if (arrayElementIndex(key)) |i| {
                // A mapped index writes through to its parameter binding (the
                // element is kept in sync so the descriptor's value stays current).
                if (argMapName(o, i)) |nm| {
                    const aenv: *Environment = @ptrCast(@alignCast(o.arg_map_env.?));
                    try aenv.assign(nm, v);
                    _ = o.setElementAt(i, v);
                    return true;
                }
                // An accessor installed on this index (via defineProperty) routes
                // the write to its setter through the ordinary [[Set]] path below,
                // rather than overwriting the mapped element directly.
                if (o.getAccessor(key) == null and o.denseElementInBounds(i)) {
                    // A per-index descriptor may mark the element non-writable:
                    // sloppy ignores the write, strict throws (handled by caller).
                    if (o.attrs != null and !o.getAttr(key).writable) return false;
                    _ = o.setDenseElement(i, v);
                    return true;
                }
            }
        }
        if (o.is_array and !o.is_arguments) {
            if (std.mem.eql(u8, key, "length") and receiver.isObject() and receiver.asObj() == o) {
                const u = try self.arrayLengthFromValue(v);
                // ArraySetLength: a non-writable `length` rejects the assignment
                // (the RangeError above still precedes this) — sloppy silently,
                // strict throws.
                if (o.attrs != null and !o.getAttr("length").writable) return false;
                return try self.setArrayLength(o, u);
            }
            // An accessor defined on an index routes the write to its setter
            // (handled by the prototype-chain setter walk below), not the store.
            if (arrayElementIndex(key) != null and o.getAccessor(key) != null) {
                // fall through to the setter walk
            } else if (arrayElementIndex(key) != null and self.arrayProtoMayInterceptSet(o, key) and
                !o.denseElementPresent(arrayElementIndex(key).?))
            {
                // The index isn't an own present element and an inherited
                // accessor or Proxy can intercept the write — OrdinarySet routes
                // through the prototype chain before creating a local element.
            } else if (arrayElementIndex(key)) |i| {
                // A per-index descriptor (recorded in `attrs`) may mark the
                // element non-writable: sloppy ignores the write, strict throws.
                if (o.attrs != null and !o.getAttr(key).writable) return false;
                if (receiver.isObject() and receiver.asObj() == o and o.denseElementPresent(i)) {
                    _ = o.setDenseElement(i, v); // an assignment fills a hole
                    return true;
                }
                // Holes and out-of-bounds writes must first run OrdinarySet's
                // prototype walk: inherited setters and non-writable data
                // descriptors block creating a local dense element.
            }
        }
        // A generator function's own `.prototype` is materialized lazily, so an
        // assignment that arrives before any read finds no own slot. OrdinarySet
        // would then walk up to the function's [[Prototype]]
        // (%GeneratorFunction.prototype% / the async variant), whose own
        // non-writable `prototype` (%GeneratorPrototype%) wrongly rejects the
        // write. Realize the own writable slot first so it shadows that. (Plain
        // and async functions are unaffected: their [[Prototype]] has no
        // `prototype` property.)
        if (std.mem.eql(u8, key, "prototype") and receiver.isObject() and receiver.asObj() == o and
            o.getOwn("prototype") == null and o.getAccessor("prototype") == null)
        {
            if (funcOf(recv)) |f| if (f.is_generator) {
                _ = try self.getProperty(Value.obj(o), "prototype");
            };
        }
        // A setter anywhere on the prototype chain intercepts the assignment.
        var cur: ?*value.Object = o;
        while (cur) |c| {
            if (c.proxy_handler != null or c.proxy_revoked)
                return self.proxySet(c, key, v, receiver);
            // OrdinarySet delegates to an ancestor's [[Set]]: an Integer-Indexed
            // Exotic ancestor handles a canonical numeric key itself (writing to a
            // valid index of the Receiver, else a no-op), so a same-keyed accessor
            // further up the chain is never reached.
            if (c.typed_array != null and canonicalNumericIndexString(key) != null)
                return self.setMemberResult(Value.obj(c), key, v, receiver);
            if (c.getAccessor(key)) |acc| {
                if (acc.set) |s| {
                    // An explicit `set: undefined` means "no setter".
                    if (!s.isUndefined()) {
                        _ = try self.callValueWithThis(s, &.{v}, receiver);
                        return true;
                    }
                }
                return false;
            }
            // OrdinarySet consults only the FIRST own descriptor on the chain: an
            // own data property here shadows any inherited accessor above it. A
            // non-writable one fails the set; a writable one falls through to the
            // ordinary data-write on the receiver.
            if (objectHasOwn(c, key)) {
                if (!c.getAttr(key).writable) return false;
                break;
            }
            cur = self.effectiveProto(c);
        }
        // [[Set]] attribute checks.
        if (o.getOwn(key)) |_| {
            if (!o.getAttr(key).writable) return false;
        }
        if (!receiver.isObject()) return false;
        const ro = receiver.asObj();
        if (ro.proxy_handler != null or ro.proxy_revoked) {
            const existing = try builtins.objectGetOwnPropertyDescriptor(@ptrCast(self), Value.undef(), &.{ Value.obj(ro), self.keyToValue(key) });
            const desc = (try self.newObject()).asObj();
            try desc.setOwn(self.arena, self.root_shape, "value", v);
            if (existing.isObject()) {
                if (existing.asObj().getOwn("get") != null or existing.asObj().getOwn("set") != null) return false;
                if (existing.asObj().getOwn("writable")) |w| {
                    if (!w.toBoolean()) return false;
                }
            } else {
                try desc.setOwn(self.arena, self.root_shape, "writable", Value.boolVal(true));
                try desc.setOwn(self.arena, self.root_shape, "enumerable", Value.boolVal(true));
                try desc.setOwn(self.arena, self.root_shape, "configurable", Value.boolVal(true));
            }
            return try builtins.defineOneResult(self, ro, key, desc);
        }
        if (moduleNsOf(ro) != null) {
            // OrdinarySetWithOwnDescriptor's [[GetOwnProperty]] on a namespace
            // receiver (e.g. `super[k] = v` whose receiver is a namespace): a
            // string key triggers a deferred module's evaluation. The define
            // itself fails (exports are non-configurable).
            try triggerDeferForKey(self, ro, key);
            _ = try moduleNsDesc(self, ro, key);
            return false;
        }
        if (ro.getAccessor(key) != null) return false;
        const had_receiver_own = ro.getOwn(key) != null or
            (if (arrayElementIndex(key)) |i| ro.denseElementPresent(i) else false);
        if (had_receiver_own) {
            if (!ro.getAttr(key).writable) return false;
        } else if (!ro.extensible) return false;
        if (ro.is_array and !ro.is_arguments) {
            if (arrayElementIndex(key)) |i| {
                const old_len = ro.arrayLength();
                if (i >= old_len and ro.attrs != null and !ro.getAttr("length").writable) return false;
                if (ro.attrs != null and !ro.getAttr(key).writable) return false;
                const dense_cap: usize = 1 << 24;
                const dense_len = ro.elementsLen();
                if (i < dense_cap and i <= dense_len + 1024) {
                    _ = try ro.growDenseElement(self.arena, i, v);
                    return true;
                }
                ro.extendArrayLengthFloor(i + 1);
            }
        } else if (arrayElementIndex(key)) |i| {
            if (ro.attrs != null or ro.accessors != null or ro.has_indexed_property.load(.monotonic) or
                ro.key_order != null or !self.arrayProtoChainCleanForIndexedSet(ro))
            {
                try self.setProp(ro, key, v);
                if (self.global_object != null and ro == self.global_object.? and had_receiver_own) {
                    const root = rootEnv(self.env);
                    if (!root.consts.contains(key)) {
                        root.lockBindings();
                        defer root.unlockBindings();
                        if (root.vars.getPtr(key)) |slot| slot.* = v;
                    }
                }
                return true;
            }
            const dense_cap: usize = 1 << 24;
            const dense_len = ro.elementsLen();
            if (i < dense_cap and i <= dense_len + 1024 and ro.getAccessor(key) == null) {
                _ = try ro.growDenseElement(self.arena, i, v);
                return true;
            }
        }
        try self.setProp(ro, key, v);
        if (self.global_object != null and ro == self.global_object.? and had_receiver_own) {
            const root = rootEnv(self.env);
            if (!root.consts.contains(key)) {
                root.lockBindings(); // serialize vs a concurrent marker reading root.vars
                defer root.unlockBindings();
                if (root.vars.getPtr(key)) |slot| slot.* = v;
            }
        }
        return true;
    }

    /// [[Set]] on a primitive base: ToObject(base), then walk inherited setters
    /// and Proxy set traps, but a data-property/no-property write ultimately
    /// fails because the original receiver is not an Object. Sloppy code ignores
    /// that false result; strict code throws.
    fn setPrimitiveMemberResult(self: *Interpreter, recv: Value, key: []const u8, v: Value) EvalError!bool {
        const boxed = try self.boxPrimitiveBase(recv);
        var cur: ?*value.Object = boxed;
        while (cur) |c| {
            if (c.proxy_handler != null or c.proxy_revoked)
                return self.proxySet(c, key, v, recv);
            if (c.getAccessor(key)) |acc| {
                if (acc.set) |s| {
                    if (!s.isUndefined()) {
                        _ = try self.callValueWithThis(s, &.{v}, recv);
                        return true;
                    }
                }
                return false;
            }
            if (c.getOwn(key)) |_| return false;
            cur = self.effectiveProto(c);
        }
        return false;
    }

    /// `delete obj[key]`: remove an own property, returning whether the object
    /// no longer has it. Non-configurable own properties can't be deleted
    /// (returns false); a missing property "deletes" successfully (true).
    pub fn deleteOwn(self: *Interpreter, o: *value.Object, key: []const u8) EvalError!bool {
        try self.checkRestricted(o);
        if (o.proxy_handler != null or o.proxy_revoked) return self.proxyDelete(o, key);
        // A module namespace's own properties (exports + @@toStringTag) are
        // non-configurable → [[Delete]] returns false; a non-own key "deletes".
        if (moduleNsOf(o)) |ns| {
            try triggerDeferIfString(self, ns, key);
            return !moduleNsHas(ns, key);
        }
        // Integer-Indexed Exotic [[Delete]]: a canonical numeric key cannot be
        // deleted when it is a valid index (returns false); any other numeric key
        // (out of bounds, "-0", fractional) "deletes" as a no-op (returns true).
        if (o.typed_array) |ta| {
            if (canonicalNumericIndexString(key)) |n| return !isValidIntegerIndex(ta, n);
        }
        if (o.prim) |p| {
            if (p.isString()) {
                if (std.mem.eql(u8, key, "length")) return false;
                if (arrayIndex(key)) |i| if (i < utf16LenOfString(p.asStr())) return false;
            }
        }
        // Accessor property.
        switch (try o.deleteAccessorOwn(self.arena, key)) {
            .absent => {},
            .blocked => return false,
            .deleted => return true,
            .removed_continue => {},
        }
        // Dense indexed element → leave a hole (reads as absent), length unchanged.
        // A per-index descriptor may mark it non-configurable (delete fails).
        if (o.is_array and std.mem.eql(u8, key, "length")) {
            // A real Array's `length` is non-configurable (not deletable); an
            // arguments object's is an ordinary own property → delete it,
            // honoring [[Configurable]].
            if (!o.is_arguments) return false;
            return o.deleteNamedDataOwn(self.arena, self.root_shape, key);
        }
        if (arrayElementIndex(key)) |i| {
            if (o.getOwn(key) == null and o.denseElementInBounds(i)) {
                if (o.attrs != null and !o.getAttr(key).configurable) return false;
                // Deleting a mapped arguments index severs its parameter link.
                if (o.is_arguments and i < o.arg_map_names.len) o.arg_map_names[i] = "";
                _ = try o.deleteDenseElement(self.arena, i);
                return true;
            }
        }
        if (std.mem.eql(u8, key, "prototype") and o.js_func != null and o.getOwn("prototype") == null and o.getAccessor("prototype") == null)
            _ = try self.getProperty(Value.obj(o), key);
        return try o.deleteNamedDataOwn(self.arena, self.root_shape, key);
    }

    /// Define an accessor (get/set) on an object via its `setAccessor`.
    fn defineAccessor(self: *Interpreter, obj: *value.Object, name: []const u8, get: ?Value, set: ?Value) EvalError!void {
        try obj.setAccessor(self.arena, name, get, set);
    }

    const AutoAccessorData = struct { storage_key: []const u8 };

    fn autoAccessorGetFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
        _ = args;
        const self: *Interpreter = @ptrCast(@alignCast(ctx));
        const fnobj = self.active_native orelse return Value.undef();
        const data: *AutoAccessorData = @ptrCast(@alignCast(fnobj.private_data.?));
        return self.privateGet(this, data.storage_key);
    }

    fn autoAccessorSetFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
        const self: *Interpreter = @ptrCast(@alignCast(ctx));
        const fnobj = self.active_native orelse return Value.undef();
        const data: *AutoAccessorData = @ptrCast(@alignCast(fnobj.private_data.?));
        try self.privateSet(this, data.storage_key, if (args.len > 0) args[0] else Value.undef());
        return Value.undef();
    }

    fn defineAutoAccessor(self: *Interpreter, obj: *value.Object, name: []const u8, storage_key: []const u8, display: []const u8) EvalError!void {
        const data = try self.arena.create(AutoAccessorData);
        data.* = .{ .storage_key = storage_key };

        const getter = try gc_mod.allocObj(self.arena);
        getter.* = .{ .native = autoAccessorGetFn, .private_data = @ptrCast(data) };
        try installNativeProps(self.arena, self.root_shape, getter, try std.fmt.allocPrint(self.arena, "get {s}", .{display}), 0);

        const setter = try gc_mod.allocObj(self.arena);
        setter.* = .{ .native = autoAccessorSetFn, .private_data = @ptrCast(data) };
        try installNativeProps(self.arena, self.root_shape, setter, try std.fmt.allocPrint(self.arena, "set {s}", .{display}), 1);

        try obj.setAccessor(self.arena, name, Value.obj(getter), Value.obj(setter));
    }

    /// Call `recv[name](args)` with `this = recv`. Dispatches the builtin
    /// methods that aren't stored as own properties first. Shared by the
    /// tree-walker's `evalCall` and the VM's `call_method`.
    pub fn callMethod(self: *Interpreter, recv: Value, name: []const u8, args: []const Value) EvalError!Value {
        // A real (possibly user-reassigned) method property found on the receiver
        // or its prototype chain takes precedence over the engine's native
        // fast-path, so an override like `Date.prototype.toString =
        // Object.prototype.toString` is honored. The brand fast-paths
        // (dateMethod / arrayMethod / mapMethod / …) remain the implementation of
        // the unshadowed intrinsics and the fallback for method names that aren't
        // installed as real own properties (synthesized push/getDay/etc.).
        const method = try self.getProperty(recv, name);
        if (method.isObject() and method.asObj().isCallableObject())
            return self.callValueWithThis(method, args, recv);
        if (try self.builtinMethod(recv, name, args)) |result| return result;
        return self.callValueWithThis(method, args, recv);
    }

    /// Obtain an iterator (an object with a `.next()` returning `{value, done}`)
    /// for `v` — the iterator-protocol entry point used by `yield*` (and, later,
    /// spread / `Array.from` / VM `for-of`). Generators are their own iterator;
    /// an object that already has a `next` method is returned as-is; arrays and
    /// strings are wrapped in an index cursor.
    pub fn iteratorOf(self: *Interpreter, v: Value) EvalError!Value {
        switch (v.kind()) {
            .object => {
                const o = v.asObj();
                if (o.gen != null) return v;
                // A user-defined `[Symbol.iterator]()` method takes precedence.
                if (self.symbolIteratorKey()) |ik| {
                    const itfn = try self.getProperty(v, ik);
                    if (!itfn.isUndefined() and !itfn.isNull()) {
                        if (itfn.isObject() and itfn.asObj().isCallableObject())
                            return try self.requireIteratorObject(try self.callValueWithThis(itfn, &.{}, v));
                        return self.throwError("TypeError", "value is not iterable");
                    }
                }
                // An array honors a deleted/overridden `Array.prototype[Symbol.iterator]`.
                if (o.is_array) {
                    switch (self.arrayIterState()) {
                        .intact => return self.makeCursorIterator(v),
                        .deleted => return self.throwError("TypeError", "value is not iterable"),
                        .custom => |m| {
                            if (!m.isCallable()) return self.throwError("TypeError", "value is not iterable");
                            return try self.requireIteratorObject(try self.callValueWithThis(m, &.{}, v));
                        },
                    }
                }
                if (hasProperty(o, "next")) return v; // already an iterator (manual or generator-like)
                // Sets (element = value) and Maps (element = [k,v] pair) iterate
                // their dense `elements` store via an index cursor.
                if (o.is_set or o.is_map) return self.makeCursorIterator(v);
                return self.throwError("TypeError", "value is not iterable");
            },
            .string, .number, .boolean => {
                if (self.symbolIteratorKey()) |ik| {
                    const itfn = try self.getProperty(v, ik);
                    if (!itfn.isUndefined() and !itfn.isNull()) {
                        if (itfn.isObject() and itfn.asObj().isCallableObject())
                            return try self.requireIteratorObject(try self.callValueWithThis(itfn, &.{}, v));
                        return self.throwError("TypeError", "value is not iterable");
                    }
                    return self.throwError("TypeError", "value is not iterable");
                }
                if (v.isString()) return self.makeCursorIterator(v);
                return self.throwError("TypeError", "value is not iterable");
            },
            else => return self.throwError("TypeError", "value is not iterable"),
        }
    }

    fn requireIteratorObject(self: *Interpreter, it: Value) EvalError!Value {
        if (!it.isObject() or it.asObj().is_symbol or it.asObj().is_bigint)
            return self.throwError("TypeError", "iterator is not an object");
        return it;
    }

    /// Whether `v` is iterable: a string, array, generator, or an object with a
    /// `[Symbol.iterator]` method. (Used by `Array.from` to choose the iterator
    /// path vs the array-like/length path.)
    pub fn isIterable(self: *Interpreter, v: Value) bool {
        switch (v.kind()) {
            .string => return true,
            .object => {
                const o = v.asObj();
                if (o.is_array or o.is_set or o.is_map or o.gen != null) return true;
                if (hasProperty(o, "next")) return true; // a manual iterator object
                if (self.symbolIteratorKey()) |ik| return hasProperty(o, ik);
                return false;
            },
            else => return false,
        }
    }

    /// The internal key of the well-known `Symbol.iterator`, for resolving
    /// `obj[Symbol.iterator]`.
    fn symbolIteratorKey(self: *Interpreter) ?[]const u8 {
        return self.wellKnownSymbolKey("iterator");
    }

    fn symbolAsyncIteratorKey(self: *Interpreter) ?[]const u8 {
        return self.wellKnownSymbolKey("asyncIterator");
    }

    fn wellKnownSymbolHiddenName(name: []const u8) ?[]const u8 {
        inline for (.{ "iterator", "asyncIterator", "hasInstance", "isConcatSpreadable", "match", "matchAll", "replace", "search", "species", "split", "toPrimitive", "toStringTag", "unscopables", "dispose", "asyncDispose" }) |known| {
            if (std.mem.eql(u8, name, known)) return "\x00Symbol." ++ known;
        }
        return null;
    }

    /// The internal property key of a well-known `Symbol.<name>` (e.g. `species`).
    pub fn wellKnownSymbolKey(self: *Interpreter, name: []const u8) ?[]const u8 {
        if (wellKnownSymbolHiddenName(name)) |hidden| {
            if (self.env.get(hidden)) |intrinsic| {
                if (intrinsic.isObject() and intrinsic.asObj().is_symbol) return intrinsic.asObj().sym_key;
            }
        }
        const sym = self.env.get("Symbol") orelse return null;
        if (!sym.isObject()) return null;
        const it = sym.asObj().getOwn(name) orelse return null;
        if (!it.isObject() or !it.asObj().is_symbol) return null;
        return it.asObj().sym_key;
    }

    /// SpeciesConstructor(O, defaultConstructor): `O.constructor[Symbol.species]`,
    /// falling back to the default when `constructor` or its species slot is
    /// undefined/null; a non-constructor species throws a TypeError.
    pub fn speciesConstructor(self: *Interpreter, o: Value, default_ctor: Value) EvalError!Value {
        const ctor = try self.getProperty(o, "constructor");
        if (ctor.isUndefined()) return default_ctor;
        // Type(C) must be Object: Symbol/BigInt primitives are wrapped as objects
        // (is_symbol/is_bigint) in this engine, so reject them explicitly too.
        if (!ctor.isObject() or ctor.asObj().is_symbol or ctor.asObj().is_bigint)
            return self.throwError("TypeError", "constructor is not an object");
        const skey = self.wellKnownSymbolKey("species") orelse return default_ctor;
        const s = try self.getProperty(ctor, skey);
        if (s.isUndefined() or s.isNull()) return default_ctor;
        if (!isConstructorValue(s)) return self.throwError("TypeError", "Symbol.species is not a constructor");
        return s;
    }

    /// ArraySpeciesCreate(originalArray, length): the result array a method like
    /// `map`/`filter`/`slice` produces. The default is a plain Array, but
    /// `originalArray.constructor[Symbol.species]` can redirect it: a null/
    /// undefined species (or the intrinsic Array) gives a plain array, a
    /// non-constructor species throws a TypeError, and any other constructor is
    /// `new`-ed with the length (its abrupt completion propagates).
    pub fn arraySpeciesCreate(self: *Interpreter, original: Value, len: usize) EvalError!Value {
        const default_realm: *Environment = if (self.active_native) |nat| blk: {
            if (nat.private_data) |pd| break :blk @ptrCast(@alignCast(pd));
            break :blk self.env;
        } else self.env;
        if (!original.isObject() or !try objectToStringIsArray(self, original.asObj())) return self.newArrayWithLengthInRealm(default_realm, len);
        const c = try self.getProperty(original, "constructor");
        if (c.isObject() and (c.asObj().is_symbol or c.asObj().is_bigint))
            return self.throwError("TypeError", "Array species is not a constructor");
        // GetFunctionRealm cross-realm check: a `constructor` that is another
        // realm's %Array% is treated as the default — ArrayCreate, WITHOUT
        // consulting its @@species (so a cross-realm species getter is untouched).
        if (c.isObject() and c.asObj().native == builtins.arrayConstructor) {
            const cur = default_realm.get("Array");
            if (cur == null or !cur.?.isObject() or c.asObj() != cur.?.asObj()) return self.newArrayWithLengthInRealm(default_realm, len);
        }
        var ctor: Value = c;
        if (c.isObject()) {
            const skey = self.wellKnownSymbolKey("species") orelse return self.newArrayWithLengthInRealm(default_realm, len);
            const s = try self.getProperty(c, skey);
            if (s.isNull() or s.isUndefined()) return self.newArrayWithLengthInRealm(default_realm, len);
            ctor = s;
        } else if (c.isUndefined()) {
            return self.newArrayWithLengthInRealm(default_realm, len);
        }
        // The intrinsic Array constructor → a plain array (fast path, matching
        // `new Array(len)` then filling in 0..len).
        if (default_realm.get("Array")) |arr| {
            if (ctor.isObject() and arr.isObject() and ctor.asObj() == arr.asObj()) return self.newArrayWithLengthInRealm(default_realm, len);
        }
        if (!isConstructorValue(ctor)) return self.throwError("TypeError", "Array species is not a constructor");
        return self.construct(ctor, &.{Value.num(@floatFromInt(len))});
    }

    /// TypedArraySpeciesCreate(exemplar, «length»): the result a method like
    /// `map`/`filter`/`slice`/`toSorted` produces. `exemplar.constructor`'s
    /// `Symbol.species` (a real constructor, else TypeError) is `new`-ed with the
    /// length; the result must be a non-detached typed array of at least `len`
    /// elements and the same content type (BigInt vs Number) as the exemplar.
    fn typedArraySpeciesCreate(self: *Interpreter, exemplar: *value.Object, len: usize, immutable_same_buffer_ok: ?*value.Object) EvalError!*value.Object {
        const kind = exemplar.typed_array.?.kind;
        const default_ctor = self.env.get(kind.ctorName()) orelse return newTypedArray(self, kind, len);
        const ctor = try self.speciesConstructor(Value.obj(exemplar), default_ctor);
        // Fast path: the intrinsic constructor for this view kind.
        if (ctor.isObject() and default_ctor.isObject() and ctor.asObj() == default_ctor.asObj())
            return newTypedArray(self, kind, len);
        const res = try self.construct(ctor, &.{Value.num(@floatFromInt(len))});
        if (!res.isObject() or res.asObj().typed_array == null)
            return self.throwError("TypeError", "TypedArray species did not return a TypedArray");
        const rta = res.asObj().typed_array.?;
        if (rta.kind.isBigInt() != kind.isBigInt())
            return self.throwError("TypeError", "TypedArray species content type does not match");
        // The callers write into the result, so ValidateTypedArray is normally
        // in ~write~ mode: an immutable destination buffer is a TypeError. Slice
        // has one spec-visible overlap case where the species result aliases the
        // source buffer; its byte-copy loop is allowed to perform those internal
        // writes even when the shared buffer is immutable.
        if (rta.buffer.array_buffer.?.immutable and (immutable_same_buffer_ok == null or rta.buffer != immutable_same_buffer_ok.?))
            return self.throwError("TypeError", "TypedArray species result is backed by an immutable buffer");
        // ValidateTypedArray + the single-Number length guard use the LIVE length:
        // a result whose (resizable) buffer is detached/out-of-bounds, or now
        // shorter than requested, is a TypeError.
        if ((rta.currentLength() orelse 0) < len)
            return self.throwError("TypeError", "TypedArray species result is too short or out of bounds");
        return res.asObj();
    }

    /// TypedArraySpeciesCreate(exemplar, «buffer, byteOffset, length?») — the
    /// form `subarray` uses: the species constructor is `new`-ed with the shared
    /// buffer and a byte range (so the result is a view, not a copy). Constructing
    /// over a detached buffer throws TypeError (ValidateTypedArray); a wrong
    /// content type or non-TypedArray result also throws.
    fn typedArraySubarrayCreate(self: *Interpreter, exemplar: *value.Object, buffer: *value.Object, byte_offset: usize, len: ?usize) EvalError!Value {
        const kind = exemplar.typed_array.?.kind;
        const default_ctor = self.env.get(kind.ctorName()) orelse return self.throwError("TypeError", "missing TypedArray constructor");
        const ctor = try self.speciesConstructor(Value.obj(exemplar), default_ctor);
        const res = if (len) |length| try self.construct(ctor, &.{
            Value.obj(buffer),
            Value.num(@floatFromInt(byte_offset)),
            Value.num(@floatFromInt(length)),
        }) else try self.construct(ctor, &.{
            Value.obj(buffer),
            Value.num(@floatFromInt(byte_offset)),
        });
        if (!res.isObject() or res.asObj().typed_array == null)
            return self.throwError("TypeError", "TypedArray species did not return a TypedArray");
        if (res.asObj().typed_array.?.buffer.array_buffer.?.isDetached())
            return self.throwError("TypeError", "TypedArray species returned a detached TypedArray");
        if (res.asObj().typed_array.?.kind.isBigInt() != kind.isBigInt())
            return self.throwError("TypeError", "TypedArray species content type does not match");
        return res;
    }

    /// Create a zero-filled `ArrayBuffer` object of `len` bytes. The bytes are
    /// 8-byte aligned so every typed-array element is naturally aligned (the
    /// atomic element paths in value.zig rely on this).
    pub fn makeArrayBuffer(self: *Interpreter, len: usize) EvalError!*value.Object {
        const o = (try self.newObject()).asObj();
        const data = try self.allocArrayBufferBytes(len);
        errdefer self.freeArrayBufferBytes(data, self.gc_backing != null);
        const ab = try self.allocArrayBufferData();
        errdefer self.destroyArrayBufferData(ab);
        ab.* = .{ .local_data = data, .gc_owned = self.gc_backing != null };
        o.array_buffer = ab;
        errdefer o.array_buffer = null;
        if (self.env.get("ArrayBuffer")) |c| {
            if (c.isObject()) o.setProtoAtomic(try self.protoObject(c.asObj()));
        }
        return o;
    }

    pub fn makeImmutableUint8ArrayFromBytes(self: *Interpreter, bytes: []const u8) EvalError!*value.Object {
        const o = try newTypedArray(self, .u8, bytes.len);
        const ab = o.typed_array.?.buffer.array_buffer.?;
        if (bytes.len > 0) @memcpy(ab.bytes()[0..bytes.len], bytes);
        ab.immutable = true;
        return o;
    }

    fn allocArrayBufferBytes(self: *Interpreter, len: usize) EvalError![]u8 {
        if (len == 0) return &.{};
        const data = if (self.gc_backing) |a| blk: {
            const p = a.rawAlloc(len, .@"8", @returnAddress()) orelse return error.OutOfMemory;
            if (self.gc_array_buffer_bytes_live) |live| _ = @atomicRmw(usize, live, .Add, len, .monotonic);
            break :blk p[0..len];
        } else try self.arena.alignedAlloc(u8, .@"8", len);
        @memset(data, 0);
        return data;
    }

    fn freeArrayBufferBytes(self: *Interpreter, bytes: []u8, gc_owned: bool) void {
        if (!gc_owned or bytes.len == 0) return;
        const a = self.gc_backing orelse return;
        a.rawFree(bytes, .@"8", @returnAddress());
        if (self.gc_array_buffer_bytes_live) |live| {
            _ = @atomicRmw(usize, live, .Sub, bytes.len, .monotonic);
        }
    }

    fn allocArrayBufferData(self: *Interpreter) EvalError!*value.ArrayBufferData {
        if (self.gc_backing) |a| return a.create(value.ArrayBufferData);
        return self.arena.create(value.ArrayBufferData);
    }

    fn destroyArrayBufferData(self: *Interpreter, ab: *value.ArrayBufferData) void {
        if (!ab.gc_owned) return;
        const a = self.gc_backing orelse return;
        a.destroy(ab);
    }

    fn typedArrayLengthLimit(size: usize) usize {
        return @min(std.math.maxInt(usize) / size, max_typed_array_bytes / size);
    }

    fn initTypedArrayProto(self: *Interpreter, o: *value.Object, kind: value.TAKind) EvalError!void {
        // GetPrototypeFromConstructor(newTarget, %TAPrototype%): newTarget.prototype
        // (a getter runs and may throw), or — when that is not an Object — the
        // *newTarget's realm's* typed-array prototype for this kind.
        if (self.new_target.isObject()) {
            o.setProtoAtomic(try self.ctorRealmIntrinsicProto(self.new_target.asObj(), kind.ctorName()));
        } else if (self.env.get(kind.ctorName())) |c| {
            if (c.isObject()) {
                o.setProtoAtomic(try self.protoObject(c.asObj()));
            }
        }
    }

    /// Construct a typed array of `kind` from the constructor arguments: a
    /// length, an `(buffer, byteOffset?, length?)` view, or a copy of a typed
    /// array / array-like / iterable.
    pub fn makeTypedArray(self: *Interpreter, kind: value.TAKind, args: []const Value) EvalError!Value {
        const size = kind.byteSize();
        const a0 = if (args.len > 0) args[0] else Value.undef();
        const o = (try self.newObject()).asObj();
        const ta = try o.typedArrayAllocator(self.arena).create(value.TypedArrayData);
        o.typed_array = ta;

        if (a0.isObject() and a0.asObj().array_buffer != null) {
            // new TA(buffer, byteOffset?, length?). byteOffset/length are ToIndex
            // (a negative or non-integer-huge value is a RangeError), the offset
            // alignment is checked before the length coerces, and the buffer is
            // re-checked for detachment AFTER both coercions run user code.
            const buffer = a0.asObj();
            const byte_offset: usize = @intCast(if (args.len > 1) try toIndexArg(self, args[1]) else 0);
            if (byte_offset % size != 0) return self.throwError("RangeError", "invalid typed array offset");
            const has_len = args.len > 2 and !args[2].isUndefined();
            const req_len: usize = if (has_len) @intCast(try toIndexArg(self, args[2])) else 0;
            // Snapshot detached + byte length under the buffer lock: a peer's
            // ArrayBuffer.resize swaps `local_data` concurrently (no-GIL), which
            // this read of `bytes()` would otherwise race. The earlier
            // byteOffset/length coercions run user code, so they stay outside.
            const abuf = buffer.array_buffer.?;
            abuf.lockBuffer();
            const ab_detached = abuf.isDetached();
            const buflen = if (ab_detached) 0 else abuf.bytes().len;
            abuf.unlockBuffer();
            if (ab_detached) return self.throwError("TypeError", "Cannot construct a TypedArray on a detached buffer");
            if (byte_offset > buflen) return self.throwError("RangeError", "invalid typed array offset");
            var length: usize = undefined;
            // Omitting the length on a resizable buffer makes the view
            // length-tracking; on a fixed buffer it spans the remaining bytes.
            const track = !has_len and buffer.array_buffer.?.max_byte_length != null;
            if (has_len) {
                length = req_len;
            } else {
                // A length-tracking view over a resizable buffer just tracks
                // floor(available / elementSize); only a fixed-length view
                // requires the byte length to be an exact multiple.
                if (!track and (buflen - byte_offset) % size != 0) return self.throwError("RangeError", "byte length not a multiple of element size");
                length = (buflen - byte_offset) / size;
            }
            if (byte_offset + length * size > buflen) return self.throwError("RangeError", "invalid typed array length");
            try self.initTypedArrayProto(o, kind);
            ta.* = .{ .buffer = buffer, .byte_offset = byte_offset, .length = length, .kind = kind, .track_length = track };
            return Value.obj(o);
        }
        if (a0.isObject() and a0.asObj().typed_array != null) {
            // new TA(typedArray): copy elements (converting numeric types). A
            // BigInt and a non-BigInt element type can't be mixed.
            const src = a0.asObj().typed_array.?;
            if (src.kind.isBigInt() != kind.isBigInt()) return self.throwError("TypeError", "Cannot mix BigInt and other types when constructing a TypedArray");
            const length = src.currentLength() orelse return self.throwError("TypeError", "Cannot construct from an out-of-bounds TypedArray");
            try self.initTypedArrayProto(o, kind);
            ta.* = .{ .buffer = try self.makeArrayBuffer(length * size), .byte_offset = 0, .length = length, .kind = kind };
            var i: usize = 0;
            while (i < length) : (i += 1) {
                if (kind.isBigInt()) value.taWriteBig(ta, i, value.taReadBig(src, i)) else value.taWrite(ta, i, value.taRead(src, i).asNum());
            }
            return Value.obj(o);
        }
        if (a0.isObject() and !a0.asObj().is_symbol and !a0.asObj().is_bigint) {
            // new TA(arrayLike | iterable): collect the values, then coerce + copy
            // (ToBigInt for a BigInt view, ToNumber otherwise). The iterable path
            // is taken only when GetMethod(@@iterator) yields a callable — a null
            // or undefined @@iterator falls back to the array-like length path.
            const ik = self.symbolIteratorKey();
            const itm = if (ik) |k| try self.getProperty(a0, k) else Value.undef();
            const use_iter = !itm.isUndefined() and !itm.isNull();
            if (use_iter and !itm.isCallable()) return self.throwError("TypeError", "@@iterator is not a function");
            const list = if (use_iter) try self.iterableOrArrayLikeToList(a0) else blk: {
                const len = toLen(try self.toNumberV(try self.getProperty(a0, "length")));
                if (len > typedArrayLengthLimit(size)) return self.throwError("RangeError", "invalid typed array length");
                break :blk try self.arrayLikeToListLen(a0, len);
            };
            if (list.len > typedArrayLengthLimit(size)) return self.throwError("RangeError", "invalid typed array length");
            try self.initTypedArrayProto(o, kind);
            ta.* = .{ .buffer = try self.makeArrayBuffer(list.len * size), .byte_offset = 0, .length = list.len, .kind = kind };
            var i: usize = 0;
            while (i < list.len) : (i += 1) try self.taStore(ta, i, list[i]);
            return Value.obj(o);
        }
        // new TA(length): ToIndex(length) — truncates (0.9→0, 1.9→1), a Symbol or
        // BigInt throws (ToNumber), a negative or >2^53-1 value is a RangeError.
        const len_idx = try toIndexArg(self, a0);
        if (len_idx > typedArrayLengthLimit(size)) return self.throwError("RangeError", "invalid typed array length");
        const length: usize = @intCast(len_idx);
        try self.initTypedArrayProto(o, kind);
        ta.* = .{ .buffer = try self.makeArrayBuffer(length * size), .byte_offset = 0, .length = length, .kind = kind };
        return Value.obj(o);
    }

    /// Store `v` into typed-array element `i`, coercing per the element type:
    /// ToBigInt for a BigInt view (rejecting a Number), ToNumber otherwise.
    fn taStoreInternal(self: *Interpreter, ta: *value.TypedArrayData, i: usize, v: Value, allow_immutable: bool) EvalError!void {
        if (ta.kind.isBigInt()) {
            const bv = try self.toBigIntValueImpl(v, false);
            // TypedArraySetElement coerces first, then skips the store for an
            // invalid/out-of-bounds index or immutable buffer (a silent no-op,
            // not a throw).
            if (i >= (ta.currentLength() orelse 0) or (ta.buffer.array_buffer.?.immutable and !allow_immutable)) return;
            value.taWriteBig(ta, i, bv.asObj().bigint);
        } else {
            const num = try self.toNumberV(v);
            if (i >= (ta.currentLength() orelse 0) or (ta.buffer.array_buffer.?.immutable and !allow_immutable)) return;
            value.taWrite(ta, i, num);
        }
    }

    fn taStore(self: *Interpreter, ta: *value.TypedArrayData, i: usize, v: Value) EvalError!void {
        return self.taStoreInternal(ta, i, v, false);
    }

    /// Read typed-array element `i` as a Value (a BigInt for a BigInt view, a
    /// Number otherwise).
    fn taLoad(self: *Interpreter, ta: *const value.TypedArrayData, i: usize) EvalError!Value {
        if (ta.kind.isBigInt()) return self.makeBigInt(value.taReadBig(ta, i));
        return value.taRead(ta, i);
    }

    /// `taLoad` but yielding `undefined` for an index at/past the current length
    /// (a resizable buffer shrank, or detached, mid-iteration) — matching `[[Get]]`
    /// on the integer-indexed exotic, which the iteration methods read through.
    fn taLoadIdx(self: *Interpreter, ta: *const value.TypedArrayData, i: usize) EvalError!Value {
        if (i >= (ta.currentLength() orelse 0)) return Value.undef();
        return self.taLoad(ta, i);
    }

    /// Collect an iterable's values (via `Symbol.iterator`) or an array-like's
    /// `0..length` elements into a freshly-allocated slice.
    fn iterableOrArrayLikeToList(self: *Interpreter, v: Value) EvalError![]Value {
        var out: std.ArrayListUnmanaged(Value) = .empty;
        // An iterable (array, Set/Map, generator, string, or any object with a
        // `Symbol.iterator`) is drained through its iterator; otherwise the value
        // is treated as an array-like and read by `0..ToLength(length)`.
        if ((v.isObject() and self.isIterable(v)) or v.isString()) {
            const it = try self.iteratorOf(v);
            while (true) {
                const r = try self.callMethod(it, "next", &.{});
                if ((try self.getProperty(r, "done")).toBoolean()) break;
                try out.append(self.arena, try self.getProperty(r, "value"));
            }
            return out.items;
        }
        // Array-like: read 0..ToLength(length).
        const len = toLen((try self.toNumberV(try self.getProperty(v, "length"))));
        var i: usize = 0;
        while (i < len) : (i += 1) {
            var kb: [24]u8 = undefined;
            const k = std.fmt.bufPrint(&kb, "{d}", .{i}) catch unreachable;
            try out.append(self.arena, try self.getProperty(v, k));
        }
        return out.items;
    }

    /// GetIteratorFlattenable(obj, reject-primitives) per the joint-iteration
    /// proposal: `obj` must be an Object (strings and other primitives throw).
    /// Reads `@@iterator` (GetMethod); if absent uses `obj` itself, else calls
    /// it. The resulting iterator must be an Object; its `next` is read eagerly
    /// (GetIteratorDirect). Returns the iterator object.
    pub fn getIteratorFlattenableObj(self: *Interpreter, obj: Value) EvalError!Value {
        if (!obj.isObject() or obj.asObj().is_bigint or obj.asObj().is_symbol)
            return self.throwError("TypeError", "value is not an iterable object");
        var iterator: Value = obj;
        if (self.symbolIteratorKey()) |ik| {
            const method = try self.getProperty(obj, ik);
            if (!method.isUndefined() and !method.isNull()) {
                if (!method.isObject() or !method.asObj().isCallableObject())
                    return self.throwError("TypeError", "Symbol.iterator is not callable");
                iterator = try self.callValueWithThis(method, &.{}, obj);
            }
        }
        if (!iterator.isObject()) return self.throwError("TypeError", "iterator is not an object");
        // GetIteratorDirect reads `next` (observable) before returning.
        _ = try self.getProperty(iterator, "next");
        return iterator;
    }

    fn arrayLikeToListLen(self: *Interpreter, v: Value, len: usize) EvalError![]Value {
        var out: std.ArrayListUnmanaged(Value) = .empty;
        var i: usize = 0;
        while (i < len) : (i += 1) {
            var kb: [24]u8 = undefined;
            const k = std.fmt.bufPrint(&kb, "{d}", .{i}) catch unreachable;
            try out.append(self.arena, try self.getProperty(v, k));
        }
        return out.items;
    }

    /// Append `v` as the next element of a method's result (an array uses its
    /// dense store; a custom species object gets a `[[Set]]` at `idx`).
    fn arrayResultPush(self: *Interpreter, result: Value, idx: usize, v: Value) EvalError!void {
        if (result.isObject() and result.asObj().is_array and result.asObj().accessors == null and
            result.asObj().attrs == null and !result.asObj().proxy_revoked and result.asObj().proxy_handler == null and
            idx == result.asObj().elements.items.len)
        {
            try result.asObj().appendElement(self.arena, v);
        } else {
            // CreateDataPropertyOrThrow(result, ToString(idx), v) — a non-Array
            // species result (or one carrying accessors) takes the generic define
            // path, which throws if the index is non-writable / non-extensible.
            const k = try std.fmt.allocPrint(self.arena, "{d}", .{idx});
            const desc = (try self.newObject()).asObj();
            try desc.setOwn(self.arena, self.root_shape, "value", v);
            try desc.setOwn(self.arena, self.root_shape, "writable", Value.boolVal(true));
            try desc.setOwn(self.arena, self.root_shape, "enumerable", Value.boolVal(true));
            try desc.setOwn(self.arena, self.root_shape, "configurable", Value.boolVal(true));
            if (!result.isObject() or !try builtins.defineOneResult(self, result.asObj(), k, desc))
                return self.throwError("TypeError", "Cannot create array result property");
        }
    }

    fn makeAsyncFromSyncIterator(self: *Interpreter, sync_iter: Value) EvalError!Value {
        const it = (try self.newObject()).asObj();
        try self.setProp(it, "__sync", sync_iter);
        try self.setProp(it, "__next", try self.getProperty(sync_iter, "next"));
        try setNative(self.arena, self.root_shape, it, "next", 1, asyncFromSyncNextFn);
        try setNative(self.arena, self.root_shape, it, "return", 1, asyncFromSyncReturnFn);
        try setNative(self.arena, self.root_shape, it, "throw", 1, asyncFromSyncThrowFn);
        return Value.obj(it);
    }

    /// The async iterator for `for await`: `obj[Symbol.asyncIterator]()` if
    /// present, else an Async-from-Sync wrapper over `obj[Symbol.iterator]()`.
    pub fn asyncIteratorOf(self: *Interpreter, v: Value) EvalError!Value {
        if (self.symbolAsyncIteratorKey()) |ik| {
            if (v.isObject() and hasProperty(v.asObj(), ik)) {
                const m = try self.getProperty(v, ik);
                // GetMethod: undefined/null → method absent (fall back to sync);
                // present but not callable → TypeError.
                if (!m.isUndefined() and !m.isNull()) {
                    if (m.isObject() and m.asObj().isCallableObject())
                        return try self.callValueWithThis(m, &.{}, v);
                    return self.throwError("TypeError", "[Symbol.asyncIterator] is not a function");
                }
            }
        }
        return self.makeAsyncFromSyncIterator(try self.iteratorOf(v));
    }

    /// Wrap an array/string/collection in an iterator object: `__src` + `__i`
    /// own properties plus a shared native `next` that reads/advances them.
    fn makeCursorIterator(self: *Interpreter, src: Value) EvalError!Value {
        return self.makeCursorIteratorWithKind(src, 0);
    }

    fn makeCursorIteratorWithKind(self: *Interpreter, src: Value, kind: u8) EvalError!Value {
        const it = try gc_mod.allocObj(self.arena);
        it.* = .{};
        try self.setProp(it, "__src", src);
        try self.setProp(it, "__i", Value.num(0));
        try self.setProp(it, "__kind", Value.num(@floatFromInt(kind)));
        // Inherit the per-kind built-in iterator prototype (%ArrayIteratorPrototype%
        // etc.) — which carries `next`, the @@toStringTag, and (via
        // %IteratorPrototype%) the iterator-helper methods.
        const proto_key: []const u8 = switch (src.kind()) {
            .string => "\x00StrIterProto",
            .object => if (src.asObj().is_map) "\x00MapIterProto" else if (src.asObj().is_set) "\x00SetIterProto" else "\x00ArrIterProto",
            else => "\x00ArrIterProto",
        };
        if (self.env.get(proto_key)) |p| {
            if (p.isObject()) it.setProtoAtomic(p.asObj());
        } else {
            // Before %IteratorPrototype% exists (early bootstrap): a plain `next`.
            try setNative(self.arena, self.root_shape, it, "next", 0, cursorIterNext);
        }
        return Value.obj(it);
    }

    /// A fresh `{ value, done }` IteratorResult object.
    pub fn iterResultObj(self: *Interpreter, val: Value, done: bool) EvalError!Value {
        const o = (try self.newObject()).asObj();
        try self.setProp(o, "value", val);
        try self.setProp(o, "done", Value.boolVal(done));
        return Value.obj(o);
    }

    /// The `{ read, written }` record returned by Uint8Array.prototype.setFrom*.
    fn readWrittenResult(self: *Interpreter, read: usize, written: usize) EvalError!Value {
        const o = (try self.newObject()).asObj();
        try self.setProp(o, "read", Value.num(@floatFromInt(read)));
        try self.setProp(o, "written", Value.num(@floatFromInt(written)));
        return Value.obj(o);
    }

    /// Pull the next result from iterator `it`, returning `{ done, value }`.
    const IterStepResult = struct { done: bool, value: Value };

    fn iterStep(self: *Interpreter, it: Value) EvalError!IterStepResult {
        return self.iterStepM(it, Value.undef());
    }

    /// Pull one step from an iterator. If `next_method` is a callable (captured
    /// once via GetIteratorDirect), call it with `it` as the receiver rather than
    /// re-reading `it.next` each step — so a `next` accessor runs only once.
    fn iterStepM(self: *Interpreter, it: Value, next_method: Value) EvalError!IterStepResult {
        const r = if (next_method.isObject() and next_method.asObj().isCallableObject())
            try self.callValueWithThis(next_method, &.{}, it)
        else
            try self.callMethod(it, "next", &.{});
        if (!r.isObject()) return self.throwError("TypeError", "iterator result is not an object");
        const done = (try self.getProperty(r, "done")).toBoolean();
        const val = if (done) Value.undef() else try self.getProperty(r, "value");
        return .{ .done = done, .value = val };
    }

    /// IteratorStep: pull one step and report only whether the iterator is done
    /// (the `value` is not read). Used by `Iterator.zip` strict-mode checking.
    fn iterStepDoneOnly(self: *Interpreter, it: Value) EvalError!bool {
        const r = try self.callMethod(it, "next", &.{});
        if (!r.isObject()) return self.throwError("TypeError", "iterator result is not an object");
        return (try self.getProperty(r, "done")).toBoolean();
    }

    /// `Array.prototype` (the global), for consulting/observing its
    /// `[Symbol.iterator]` slot. Arrays don't carry a `proto` pointer, so this
    /// resolves it through the `Array` global instead.
    fn arrayProtoObj(self: *Interpreter) ?*value.Object {
        const av = self.env.get("Array") orelse return null;
        if (!av.isObject()) return null;
        const p = av.asObj().getOwn("prototype") orelse return null;
        return if (p.isObject()) p.asObj() else null;
    }

    /// The current `Array.prototype[Symbol.iterator]` slot: `.intact` (still the
    /// native array-values iterator → fast index cursor is valid), `.deleted`
    /// (no iterator → not iterable), or `.custom` (a user replacement to call).
    const ArrayIter = union(enum) { intact, deleted, custom: Value };
    fn arrayIterState(self: *Interpreter) ArrayIter {
        const ap = self.arrayProtoObj() orelse return .intact;
        const ik = self.symbolIteratorKey() orelse return .intact;
        const slot = ap.getOwn(ik) orelse return .deleted;
        if (slot.isObject() and slot.asObj().native == arrayValuesIterFn) return .intact;
        return .{ .custom = slot };
    }

    /// Whether `Array.prototype[Symbol.iterator]` is still the native iterator,
    /// so the array index fast paths are valid.
    fn arrayIterIntact(self: *Interpreter) bool {
        return switch (self.arrayIterState()) {
            .intact => true,
            else => false,
        };
    }

    fn objectProtoHasOwn(self: *Interpreter, o: *value.Object, key: []const u8) EvalError!bool {
        if (moduleNsOf(o)) |ns| {
            try triggerDeferIfString(self, ns, key);
            return !(try moduleNsDesc(self, o, key)).isUndefined();
        }
        if (o.proxy_handler != null or o.proxy_revoked) {
            const desc = try builtins.objectGetOwnPropertyDescriptor(@ptrCast(self), Value.undef(), &.{ Value.obj(o), self.keyToValue(key) });
            return !desc.isUndefined();
        }
        return objectHasOwn(o, key);
    }

    fn objectProtoPropertyIsEnumerable(self: *Interpreter, o: *value.Object, key: []const u8) EvalError!bool {
        if (moduleNsOf(o)) |ns| {
            try triggerDeferIfString(self, ns, key);
            _ = try moduleNsDesc(self, o, key);
            return moduleNsEnumerable(o, key);
        }
        if (o.proxy_handler != null or o.proxy_revoked) {
            const desc = try builtins.objectGetOwnPropertyDescriptor(@ptrCast(self), Value.undef(), &.{ Value.obj(o), self.keyToValue(key) });
            if (!desc.isObject()) return false;
            if (desc.asObj().getOwn("enumerable")) |enumerable| return enumerable.toBoolean();
            return false;
        }
        return objectHasOwn(o, key) and o.getAttr(key).enumerable and
            !(o.is_array and std.mem.eql(u8, key, "length"));
    }

    /// Dispatch `Array.prototype` / `String.prototype` methods (which aren't
    /// stored as own properties). Returns null when `name` isn't a recognized
    /// builtin for `recv`, so the caller falls back to a property lookup + call.
    pub fn objectPrototypeMethod(self: *Interpreter, recv: Value, name: []const u8, args: []const Value) EvalError!?Value {
        if (eq(name, "hasOwnProperty")) {
            const k = if (args.len > 0) try self.keyOf(args[0]) else "undefined";
            const o = try self.toObject(recv);
            return Value.boolVal(try self.objectProtoHasOwn(o, k));
        }
        if (eq(name, "propertyIsEnumerable")) {
            const k = if (args.len > 0) try self.keyOf(args[0]) else "undefined";
            const o = try self.toObject(recv);
            return Value.boolVal(try self.objectProtoPropertyIsEnumerable(o, k));
        }
        if (eq(name, "isPrototypeOf")) {
            if (!(args.len > 0 and args[0].isObject() and !args[0].asObj().is_symbol and !args[0].asObj().is_bigint)) return Value.boolVal(false);
            const o = try self.toObject(recv);
            var cur: Value = args[0];
            while (cur.isObject()) {
                const next = if (cur.asObj().proxy_handler != null or cur.asObj().proxy_revoked)
                    try self.proxyGetProto(cur.asObj())
                else if (cur.asObj().proto) |p| Value.obj(p) else Value.nul();
                if (!next.isObject()) return Value.boolVal(false);
                if (next.asObj() == o) return Value.boolVal(true);
                cur = next;
            }
            return Value.boolVal(false);
        }
        const o = try self.toObject(recv);
        if (eq(name, "valueOf")) return Value.obj(o);
        if (eq(name, "__defineGetter__") or eq(name, "__defineSetter__")) {
            const f = arg(args, 1);
            if (!f.isCallable()) return self.throwError("TypeError", "Object.prototype.__define[GS]etter__: Expecting function");
            const key = try self.keyOf(arg0(args));
            const desc = (try self.newObject()).asObj();
            try desc.setOwn(self.arena, self.root_shape, if (eq(name, "__defineGetter__")) "get" else "set", f);
            try desc.setOwn(self.arena, self.root_shape, "enumerable", Value.boolVal(true));
            try desc.setOwn(self.arena, self.root_shape, "configurable", Value.boolVal(true));
            try builtins.defineOne(self, o, key, desc);
            return Value.undef();
        }
        if (eq(name, "__lookupGetter__") or eq(name, "__lookupSetter__")) {
            const key = try self.keyOf(arg0(args));
            const key_v = self.keyToValue(key);
            const want_get = eq(name, "__lookupGetter__");
            var cur: Value = recv;
            while (cur.isObject()) {
                const desc = try builtins.objectGetOwnPropertyDescriptor(@ptrCast(self), Value.undef(), &.{ cur, key_v });
                if (desc.isObject()) {
                    const d = desc.asObj();
                    if (d.getOwn("get") != null or d.getOwn("set") != null)
                        return (if (want_get) d.getOwn("get") else d.getOwn("set")) orelse Value.undef();
                    return Value.undef();
                }
                const c = cur.asObj();
                cur = if (c.proxy_handler != null or c.proxy_revoked)
                    try self.proxyGetProto(c)
                else if (c.protoAtomic()) |p| Value.obj(p) else Value.nul();
            }
            return Value.undef();
        }
        return null;
    }

    pub fn builtinMethod(self: *Interpreter, recv: Value, name: []const u8, args: []const Value) EvalError!?Value {
        switch (recv.kind()) {
            .object => {
                const o = recv.asObj();
                if (o.gen != null) {
                    const sent: Value = if (args.len > 0) args[0] else Value.undef();
                    if (eq(name, "next")) return try vm.genNext(self, o, sent);
                    if (eq(name, "return")) return try vm.genReturn(self, o, sent);
                    if (eq(name, "throw")) return try vm.genThrow(self, o, sent);
                }
                // Universal prototype methods (Function.prototype +
                // Object.prototype), checked before the array/regex/map/set
                // builtins so they reach every object kind. Own properties of
                // the same name shadow them.
                if (o.getOwn(name) == null) {
                    if (o.isCallableObject()) {
                        if (eq(name, "call")) {
                            const t: Value = if (args.len > 0) args[0] else Value.undef();
                            return try self.callValueWithThis(recv, if (args.len > 1) args[1..] else &.{}, t);
                        }
                        if (eq(name, "apply")) {
                            const t: Value = if (args.len > 0) args[0] else Value.undef();
                            const list = try self.argListFromArrayLike(if (args.len > 1) args[1] else Value.undef());
                            return try self.callValueWithThis(recv, list, t);
                        }
                        if (eq(name, "bind")) {
                            return try self.makeBound(o, if (args.len > 0) args[0] else Value.undef(), if (args.len > 1) args[1..] else &.{});
                        }
                        if (eq(name, "toString")) return try self.functionToString(o);
                    }
                    if (eq(name, "hasOwnProperty")) {
                        const k = if (args.len > 0) try self.keyOf(args[0]) else "undefined";
                        return Value.boolVal(try self.objectProtoHasOwn(o, k));
                    }
                    if (eq(name, "propertyIsEnumerable")) {
                        const k = if (args.len > 0) try self.keyOf(args[0]) else "undefined";
                        return Value.boolVal(try self.objectProtoPropertyIsEnumerable(o, k));
                    }
                    if (eq(name, "isPrototypeOf")) {
                        if (!(args.len > 0 and args[0].isObject() and !args[0].asObj().is_symbol and !args[0].asObj().is_bigint)) return Value.boolVal(false);
                        var cur: Value = args[0];
                        while (cur.isObject()) {
                            const next = if (cur.asObj().proxy_handler != null or cur.asObj().proxy_revoked)
                                try self.proxyGetProto(cur.asObj())
                            else if (cur.asObj().proto) |p| Value.obj(p) else Value.nul();
                            if (!next.isObject()) return Value.boolVal(false);
                            if (next.asObj() == o) return Value.boolVal(true);
                            cur = next;
                        }
                        return Value.boolVal(false);
                    }
                    // Annex-B legacy accessor helpers.
                    if (eq(name, "__defineGetter__") or eq(name, "__defineSetter__")) {
                        const f = arg(args, 1);
                        if (!f.isCallable()) return self.throwError("TypeError", "Object.prototype.__define[GS]etter__: Expecting function");
                        // ToPropertyKey(P): a Symbol key is honored and a thrown
                        // valueOf/toString propagates.
                        const key = try self.keyOf(arg0(args));
                        // DefinePropertyOrThrow with { get|set, enumerable, configurable }:
                        // route through the shared descriptor machinery so a
                        // non-configurable existing property or a non-extensible
                        // object throws a TypeError (not a silent overwrite).
                        const desc = (try self.newObject()).asObj();
                        try desc.setOwn(self.arena, self.root_shape, if (eq(name, "__defineGetter__")) "get" else "set", f);
                        try desc.setOwn(self.arena, self.root_shape, "enumerable", Value.boolVal(true));
                        try desc.setOwn(self.arena, self.root_shape, "configurable", Value.boolVal(true));
                        try builtins.defineOne(self, o, key, desc);
                        return Value.undef();
                    }
                    if (eq(name, "__lookupGetter__") or eq(name, "__lookupSetter__")) {
                        // Spec walk: at each level take [[GetOwnProperty]](key); if it
                        // exists, return its accessor get/set (or undefined for a data
                        // property); else step [[GetPrototypeOf]]. Both steps are
                        // proxy-aware, so a throwing trap propagates (per the err tests).
                        const key = try self.keyOf(arg0(args)); // ToPropertyKey once
                        const key_v = self.keyToValue(key);
                        const want_get = eq(name, "__lookupGetter__");
                        var cur: Value = recv;
                        while (cur.isObject()) {
                            const desc = try builtins.objectGetOwnPropertyDescriptor(@ptrCast(self), Value.undef(), &.{ cur, key_v });
                            if (desc.isObject()) {
                                const d = desc.asObj();
                                if (d.getOwn("get") != null or d.getOwn("set") != null)
                                    return (if (want_get) d.getOwn("get") else d.getOwn("set")) orelse Value.undef();
                                return Value.undef(); // a data property shadows
                            }
                            const c = cur.asObj();
                            cur = if (c.proxy_handler != null or c.proxy_revoked)
                                try self.proxyGetProto(c)
                            else if (c.protoAtomic()) |p| Value.obj(p) else Value.nul();
                        }
                        return Value.undef();
                    }
                    // Error.prototype.toString — before the generic Array `toString`
                    // (join) fallback below would wrongly intercept error objects.
                    if (o.is_error and eq(name, "toString")) return try errorToStringFn(@ptrCast(self), recv, args);
                    if (o.is_symbol and eq(name, "toString")) return try symbolToStringFn(@ptrCast(self), recv, args);
                    if (o.is_symbol and eq(name, "valueOf")) return recv;
                }
                if (o.is_regex) return try self.regexMethod(o, name, args);
                if (o.is_date) return try self.dateMethod(o, name, args);
                if (o.is_map) return try self.mapMethod(o, name, args);
                if (o.is_set) return try self.setMethod(o, name, args);
                // A typed array's own methods take precedence over the Array-like
                // coercion path (slice/indexOf/map/… are shared names).
                if (o.typed_array != null and o.getOwn(name) == null) {
                    if (try typedArrayMethod(self, o, name, args)) |r| return r;
                }
                // A String wrapper object (`new String("…")`): its String.prototype
                // methods take precedence over the generic Array-like coercion for
                // names both share (slice/indexOf/lastIndexOf/includes/concat/at).
                if (o.prim != null and o.prim.?.isString() and o.getOwn(name) == null) {
                    if (try self.stringMethod(o.prim.?.asStr(), name, args, true)) |r| return r;
                }
                if (o.is_array and o.getOwn(name) == null) return try self.arrayMethod(o, name, args);
                // Generic Array.prototype methods on an array-like `this`
                // (`Array.prototype.map.call(obj, …)`).
                if (o.getOwn(name) == null and isArrayGeneric(name)) {
                    if (try self.arrayMethod(o, name, args)) |r| return r;
                }
                // Generic String.prototype methods coerce `this` to string
                // (`String.prototype.split.call(obj)`).
                if (o.getOwn(name) == null and isStringGeneric(name)) {
                    return try self.stringMethod(try self.toStringV(recv), name, args, true);
                }
                // `Object.prototype.valueOf` for an ordinary object returns the
                // object itself (ToObject(this)). Reached only after the kind
                // dispatch above (Date/Array/Map/… handle their own valueOf) and
                // only for a non-wrapper (a wrapper delegates to its `.prim` below).
                if (o.getOwn(name) == null and o.prim == null and eq(name, "valueOf")) return recv;
                // A primitive-wrapper object (`new Number/String/Boolean`)
                // delegates unmatched methods to its boxed primitive, so
                // `(new Number(5)).valueOf()`, `.toFixed(2)`, `.charAt(0)`, … work.
                if (o.prim) |p| {
                    if (o.getOwn(name) == null) {
                        if (try self.builtinMethod(p, name, args)) |r| return r;
                    }
                }
            },
            .string => return try self.stringMethod(recv.asStr(), name, args, true),
            .number => {
                if (try self.numberMethod(recv.asNum(), name, args)) |r| return r;
                if (isStringGeneric(name)) return try self.stringMethod(try recv.toString(self.arena), name, args, true);
            },
            .boolean => {
                if (try self.booleanMethod(recv.asBool(), name, args)) |r| return r;
                if (isStringGeneric(name)) return try self.stringMethod(try recv.toString(self.arena), name, args, true);
            },
            else => {},
        }
        return null;
    }

    /// String.prototype methods that coerce `this` to a string (so e.g.
    /// `String.prototype.trim.call(42)` works). Excludes toString/valueOf.
    fn isStringGeneric(name: []const u8) bool {
        const names = [_][]const u8{
            "charAt",        "charCodeAt", "codePointAt", "indexOf",      "lastIndexOf",       "includes",
            "startsWith",    "endsWith",   "slice",       "substring",    "substr",            "toUpperCase",
            "toLowerCase",   "trim",       "trimStart",   "trimEnd",      "repeat",            "concat",
            "split",         "at",         "padStart",    "padEnd",       "replace",           "replaceAll",
            "localeCompare", "normalize",  "search",      "match",        "toLocaleUpperCase", "toLocaleLowerCase",
            "matchAll",      "trimLeft",   "trimRight",   "isWellFormed", "toWellFormed",      "anchor",
            "big",           "blink",      "bold",        "fixed",        "fontcolor",         "fontsize",
            "italics",       "link",       "small",       "strike",       "sub",               "sup",
        };
        for (names) |n| if (eq(name, n)) return true;
        return false;
    }

    /// Generic read-only Array.prototype methods that work on any array-like
    /// `this` (e.g. `Array.prototype.map.call(arrayLikeObj, fn)`). Mutators stay
    /// real-array-only.
    /// Methods that ArraySpeciesCreate (or otherwise ArrayCreate) a result whose
    /// length comes from the source `length` — so a length above 2^32-1 is a
    /// RangeError. Read-only / in-place methods don't create such a result.
    fn arrayCreatesResult(name: []const u8) bool {
        const names = [_][]const u8{
            "map", "concat", "with", "toReversed", "toSorted",
        };
        for (names) |n| if (eq(name, n)) return true;
        return false;
    }

    /// Methods that read an array-like through live short-circuiting [[Get]]
    /// (returning as soon as a match is found, or only touching the tail) — so
    /// they accept a huge-length array-like without iterating it to exhaustion.
    /// Every OTHER method that loops the full length bails (returns null) on a
    /// pathological array-like length to avoid an unbounded native loop.
    fn arraySearchReadsLive(name: []const u8) bool {
        return eq(name, "indexOf") or eq(name, "lastIndexOf") or eq(name, "includes") or
            eq(name, "push") or eq(name, "pop") or
            eq(name, "forEach") or eq(name, "filter") or eq(name, "reduce") or
            eq(name, "reduceRight") or
            eq(name, "some") or eq(name, "every") or eq(name, "find") or
            eq(name, "findIndex") or eq(name, "findLast") or eq(name, "findLastIndex");
    }

    fn isArrayGeneric(name: []const u8) bool {
        const names = [_][]const u8{
            "join",          "indexOf",   "lastIndexOf", "includes",       "slice", "concat",     "map",       "filter",
            "forEach",       "reduce",    "reduceRight", "some",           "every", "find",       "findIndex", "findLast",
            "findLastIndex", "at",        "flat",        "flatMap",        "keys",  "values",     "entries",   "toReversed",
            "toSorted",      "toSpliced", "with",        "toLocaleString",
            // fill/copyWithin operate purely through [[Get]]/[[Set]] over the
            // receiver, so they work on an array-like `this` (and read its
            // `length` via ToLength, throwing for a Symbol/BigInt length).
            "fill",  "copyWithin",
        };
        // NB: `toString` is intentionally NOT generic here — a plain object's
        // `.toString()` must reach `Object.prototype.toString` (the `[object
        // Tag]` native), not join an array-like into "". Real arrays still join
        // via the `is_array` branch in `builtinMethod`.
        for (names) |n| if (eq(name, n)) return true;
        return false;
    }

    /// Whether array/array-like index `i` is present (own dense non-hole, own
    /// sparse named, or inherited) — the HasProperty the iteration methods use to
    /// skip holes.
    fn arrIndexPresent(self: *Interpreter, o: *value.Object, i: usize) EvalError!bool {
        // Dense fast path: a real (non-hole) in-range element of a plain array
        // is definitely present — no per-index string allocation. A *hole*
        // falls through, because an index property inherited from the prototype
        // chain can still make it present (HasProperty walks the chain).
        if (o.is_array and o.accessors == null and o.denseElementPresent(i))
            return true;
        if (o.typed_array) |ta| {
            if (i < (ta.currentLength() orelse 0)) return true;
        }
        const ks = try std.fmt.allocPrint(self.arena, "{d}", .{i});
        return try self.hasPropertyResult(o, ks);
    }

    /// `o[i]` via [[Get]] (so an accessor index runs its getter, and inherited
    /// indices resolve) — used by the iteration methods.
    fn arrIndexGet(self: *Interpreter, o: *value.Object, i: usize) EvalError!Value {
        // Dense fast path mirrors `arrIndexPresent`; a hole goes through [[Get]]
        // so an inherited index (accessor or value) on the prototype resolves.
        if (o.is_array and o.accessors == null) {
            if (o.denseElement(i)) |v| return v;
        }
        const ks = try std.fmt.allocPrint(self.arena, "{d}", .{i});
        return self.getProperty(Value.obj(o), ks);
    }

    /// Set(O, ToString(i), v, true) — SetPropertyOrThrow on an integer index.
    fn arrIndexSetOrThrow(self: *Interpreter, o: *value.Object, i: usize, v: Value) EvalError!void {
        const ks = try std.fmt.allocPrint(self.arena, "{d}", .{i});
        if (!try self.setMemberResult(Value.obj(o), ks, v, Value.obj(o)))
            return self.throwError("TypeError", "Cannot set array index");
    }

    /// DeletePropertyOrThrow(O, ToString(i)).
    fn arrIndexDeleteOrThrow(self: *Interpreter, o: *value.Object, i: usize) EvalError!void {
        const ks = try std.fmt.allocPrint(self.arena, "{d}", .{i});
        if (!try self.deleteOwn(o, ks))
            return self.throwError("TypeError", "Cannot delete array index");
    }

    /// Spread one concat-spreadable source into `dst`, preserving holes: a real
    /// Array uses its sparse `length`, an array-like reads ToLength(.length).
    /// A pathological 2**53-style length throws (instead of OOM-crashing).
    fn concatSpreadInto(self: *Interpreter, dst: Value, src: *value.Object, n: *usize) EvalError!void {
        const slen: usize = if (src.is_array and !src.is_arguments) src.arrayLength() else blk: {
            break :blk toArrayLikeLen((try self.toPrimitive(try self.getProperty(Value.obj(src), "length"), .number)).toNumber());
        };
        const max_safe_len: usize = 9007199254740991;
        if (slen > max_safe_len - n.*) return self.throwError("TypeError", "Invalid array length");
        // A plain dense Array result preserves holes (append + markHole); a
        // species/exotic result leaves a hole as an absent index (CreateDataProperty
        // only for present elements).
        const dense = dst.isObject() and dst.asObj().is_array and dst.asObj().accessors == null and
            dst.asObj().attrs == null and dst.asObj().proxy_handler == null and !dst.asObj().proxy_revoked;
        var j: usize = 0;
        while (j < slen) : (j += 1) {
            if (j > (1 << 22)) return self.throwError("TypeError", "Invalid array length");
            if (try self.arrIndexPresent(src, j)) {
                try self.arrayResultPush(dst, n.*, try self.arrIndexGet(src, j));
            } else if (dense) {
                const base = dst.asObj().elementsLen();
                try dst.asObj().appendElement(self.arena, Value.undef());
                try dst.asObj().markHole(self.arena, base);
            }
            n.* += 1;
        }
    }

    /// Process one concat operand: spread it when concat-spreadable (per the
    /// `Symbol.isConcatSpreadable` override, else only real Arrays), else
    /// CreateDataProperty it whole at the running result index `n`. `ck` is the
    /// cached `Symbol.isConcatSpreadable` property key.
    fn concatProcessOne(self: *Interpreter, dst: Value, v: Value, ck: ?[]const u8, n: *usize) EvalError!void {
        var spread: bool = false;
        if (v.isObject() and !v.asObj().is_symbol and !v.asObj().is_bigint) {
            if (ck) |k| {
                const flag = try self.getProperty(v, k);
                spread = if (!flag.isUndefined()) flag.toBoolean() else try objectToStringIsArray(self, v.asObj());
            } else {
                spread = try objectToStringIsArray(self, v.asObj());
            }
        }
        if (spread) {
            try self.concatSpreadInto(dst, v.asObj(), n);
        } else {
            try self.arrayResultPush(dst, n.*, v);
            n.* += 1;
        }
    }

    /// ToIntegerOrInfinity-based start index for the forward searches
    /// (indexOf/includes): a negative `fromIndex` counts from the end, `+∞`
    /// (or any value ≥ len) yields `len` (no iterations), NaN/undefined → 0.
    fn fromIndexForward(self: *Interpreter, v: Value, len: usize) EvalError!usize {
        const n = try self.toNumberV(v);
        if (std.math.isNan(n)) return 0;
        const flen: f64 = @floatFromInt(len);
        const fl = @trunc(n);
        if (fl >= flen) return len;
        if (fl < 0) {
            const from_end = flen + fl;
            return if (from_end < 0) 0 else @intFromFloat(from_end);
        }
        return @intFromFloat(fl);
    }

    /// The real array's *sparse* own integer-index keys lying in `[lo, hi)`,
    /// returned in ascending order. These are indices stored as named
    /// properties (past the dense `elements` store, e.g. `a[2**31]=x`), so the
    /// search methods can visit them without walking the whole logical length.
    fn arrSparseIndices(self: *Interpreter, o: *value.Object, lo: usize, hi: usize) EvalError![]usize {
        var list: std.ArrayListUnmanaged(usize) = .empty;
        const keys = try o.ownKeys(self.arena);
        for (keys) |k| {
            if (arrayIndex(k)) |idx| {
                if (idx >= lo and idx < hi) try list.append(self.arena, idx);
            }
        }
        std.mem.sort(usize, list.items, {}, std.sort.asc(usize));
        return list.items;
    }

    /// Whether a real array's `length` is writable — `Set(O, "length", …, true)`
    /// (the final step of pop/push/shift/unshift/splice) throws when it is not.
    fn arrayLenWritable(o: *value.Object) bool {
        return !(o.attrs != null and !o.getAttr("length").writable);
    }

    /// Whether some object on `o`'s *prototype* chain can intercept a
    /// (array-index) write — so an assignment to a hole/out-of-range index routes
    /// through OrdinarySet instead of the dense store.
    fn arrayProtoMayInterceptSet(self: *Interpreter, o: *value.Object, key: []const u8) bool {
        var cur: ?*value.Object = self.effectiveProto(o);
        while (cur) |c| {
            if (c.proxy_handler != null or c.proxy_revoked) return true;
            if (c.typed_array != null and canonicalNumericIndexString(key) != null) return true;
            if (c.getAccessor(key) != null) return true;
            if (objectHasOwn(c, key)) return true;
            cur = self.effectiveProto(c);
        }
        return false;
    }

    /// `Set(O, ToString(i), v, true)` — the throwing element store used by
    /// push/unshift: fires an inherited index setter and rejects a non-extensible
    /// / non-writable slot (forcing strict so the rejection throws). User setters
    /// keep their own strictness.
    fn arraySetIndexThrowing(self: *Interpreter, o: *value.Object, i: usize, v: Value) EvalError!void {
        const idx = try std.fmt.allocPrint(self.arena, "{d}", .{i});
        const saved = self.strict;
        self.strict = true;
        defer self.strict = saved;
        return self.setMember(Value.obj(o), idx, v);
    }

    /// `Set(O, "length", newLen, true)` for a grow (push/unshift): a real array
    /// with non-writable `length` throws; otherwise the logical length advances.
    /// An array-like routes through [[Set]].
    fn arraySetLengthThrowing(self: *Interpreter, o: *value.Object, new_len: usize) EvalError!void {
        if (o.is_array) {
            if (new_len > 4294967295) return self.throwError("RangeError", "Invalid array length");
            if (!arrayLenWritable(o)) return self.throwError("TypeError", "Cannot assign to read only property 'length'");
            if (!try self.setArrayLength(o, new_len))
                return self.throwError("TypeError", "Cannot delete a non-configurable array element");
            return;
        }
        // Set(O, "length", newLen, true) — force strict so a non-writable /
        // setter-less length on an array-like rejects with a TypeError.
        const saved = self.strict;
        self.strict = true;
        defer self.strict = saved;
        try self.setMember(Value.obj(o), "length", Value.num(@floatFromInt(new_len)));
    }

    /// Whether the array's element at dense index `i` carries an explicit
    /// non-configurable attribute (only possible after `seal`/`freeze` or a
    /// `defineProperty`) — so deleting it (pop/shift) must throw.
    fn arrayElemNonConfigurable(o: *value.Object, i: usize) bool {
        if (o.attrs == null) return false;
        var kb: [24]u8 = undefined;
        const k = std.fmt.bufPrint(&kb, "{d}", .{i}) catch return false;
        return !o.getAttr(k).configurable;
    }

    fn arrayMethod(self: *Interpreter, o: *value.Object, name: []const u8, args: []const Value) EvalError!?Value {
        // sort/toSorted validate comparefn before LengthOfArrayLike(this), so a
        // borrowed call with a poisoned `length` still reports the comparator
        // TypeError first.
        if (eq(name, "sort") or eq(name, "toSorted")) {
            const cmp = arg0(args);
            if (!cmp.isUndefined() and !cmp.isCallable())
                return self.throwError("TypeError", "Array.prototype sort comparator is not a function");
        }
        // Real arrays use the dense element store directly; an array-like `this`
        // (via `.call`) materializes its `length`/indexed properties into a
        // temporary slice so the read-only methods below work unchanged.
        // An array-like `this` (via `.call`) is read on demand through [[Get]]
        // (`arrIndexGet`) by each method, over the logical length computed here —
        // no materialized snapshot (which would double-read getters). For a real
        // array the dense element store is used directly.
        var array_like_len: usize = 0;
        if (!o.is_array and !eq(name, "concat")) {
            // ToLength(ToNumber(obj.length)) — `toNumberV` runs valueOf/toString
            // and throws a TypeError for a Symbol/BigInt `length`.
            const lenf = try self.toNumberV(try self.getProperty(Value.obj(o), "length"));
            // Result-creating methods ArraySpeciesCreate a result of ToLength(len);
            // ArrayCreate rejects a length above 2^32-1 with a RangeError. Check
