            }
            return Value.num(-1);
        }
        if (eq(name, "fill")) {
            const v = arg0(args);
            const start = try relIndex(self, arg(args, 1), ilen, 0);
            const end = try relIndex(self, arg(args, 2), ilen, @floatFromInt(ilen));
            if (end > start and end - start > (1 << 22)) {
