            const depth: f64 = if (std.math.isNan(depth_raw)) 0 else @trunc(depth_raw);
            const result = try self.arraySpeciesCreate(Value.obj(o), 0);
            _ = try self.flattenIntoLen(result, o, ilen, depth, 0);
