                backward = true;
                from += count - 1;
                to += count - 1;
            }
            while (count > 0) {
                if (try self.arrIndexPresent(o, from))
                    try self.arrIndexSetOrThrow(o, to, try self.arrIndexGet(o, from))
                else
                    try self.arrIndexDeleteOrThrow(o, to);
                count -= 1;
                if (count == 0) break;
