                }
                // GetMethod(regexp, @@matchAll) — only an object can carry one; a
                // primitive argument (string/number, and the object-boxed
                // BigInt/Symbol) is left to the RegExpCreate fallback below.
                if (isRegExpObjectValue(regexp)) if (skey) |k| {
                    const m = try self.getProperty(regexp, k);
                    if (!m.isUndefined() and !m.isNull()) {
                        if (!m.isCallable()) return self.throwError("TypeError", "regexp[Symbol.matchAll] is not callable");
                        return try self.callValueWithThis(m, &.{Value.str(s)}, regexp);
                    }
                };
            }
            // RegExpCreate(regexp, "g"), then Invoke(rx, @@matchAll, « S ») so a
            // replaced/deleted RegExp.prototype[@@matchAll] is honoured.
            const src = if (regexp.isObject() and regexp.asObj().is_regex)
                regexp.asObj().regex_source
            else if (regexp.isUndefined())
                ""
            else
                try self.toStringV(regexp);
            const rx = try self.makeRegex(src, "g");
            if (skey) |k| {
                const m = try self.getProperty(rx, k);
                return try self.callValueWithThis(m, &.{Value.str(s)}, rx);
            }
            return try self.regexpMatchAll(rx, s);
        }
        return null;
    }

    /// Coerce a value to a RegExp object: a regex stays as-is; anything else
    /// becomes `new RegExp(String(v))`.
    fn toRegexObject(self: *Interpreter, v: Value) EvalError!*value.Object {
        if (v.isObject() and v.asObj().is_regex) return v.asObj();
        const pat = if (v.isUndefined()) "" else try self.toStringV(v);
        return (try self.makeRegex(pat, "")).asObj();
    }

    /// A capture group's value: `undefined` when the group did not participate
    /// in the match (an unmatched optional), else its matched substring.
    fn captureVal(self: *Interpreter, m: regex.Match, i: usize) EvalError!Value {
        if (i < m.captures_present.len and !m.captures_present[i]) return Value.undef();
        return Value.str(try self.arena.dupe(u8, m.captures[i]));
    }

    /// The `groups` object for a match — `{ name: capture }` for each named
    /// group — or null when the pattern has no named groups (then `groups` is
    /// `undefined`).
    fn regexGroups(self: *Interpreter, re: *regex.Regex, m: regex.Match) EvalError!?*value.Object {
        if (re.named_capture_list.len == 0) return null;
        const o = (try self.newObject()).asObj();
        o.setProtoAtomic(null); // RegExpBuiltinExec: the groups object is ObjectCreate(null)
        for (re.named_capture_list) |entry| {
            const v: Value = if (re.getNamedCapture(&m, entry.name)) |capture|
                Value.str(try self.arena.dupe(u8, capture))
            else
                Value.undef();
            try self.setProp(o, entry.name, v);
        }
        return o;
    }

    fn namedCaptureSpan(re: *regex.Regex, m: regex.Match, name: []const u8) ?[2]usize {
        for (re.named_capture_list) |entry| {
            if (!std.mem.eql(u8, entry.name, name)) continue;
            if (entry.index == 0) continue;
            const i = entry.index - 1;
            if (i >= m.captures_present.len or i >= m.capture_spans.len) continue;
            if (!m.captures_present[i]) continue;
            return m.capture_spans[i];
        }
        return null;
    }

    /// A two-element `[start, end]` array, as used by the match-indices array.
    fn indexPair(self: *Interpreter, lo: usize, hi: usize) EvalError!Value {
        const p = (try self.newArray()).asObj();
        try p.elements.append(p.elementsAllocator(self.arena), Value.num(@floatFromInt(lo)));
        try p.elements.append(p.elementsAllocator(self.arena), Value.num(@floatFromInt(hi)));
        return Value.obj(p);
    }

    /// MakeIndicesArray: the `.indices` property an `exec` result carries when the
    /// regexp has the `d` (hasIndices) flag — element 0 is `[start, end]` of the
    /// whole match, element i+1 is the i-th capture's `[start, end]` (or undefined
    /// if it did not participate), and `.groups` maps each named group likewise.
    /// `base` is the byte offset of the search window within the original input.
    fn makeIndicesArray(self: *Interpreter, re: *regex.Regex, m: regex.Match, input: []const u8, base: usize) EvalError!*value.Object {
        const idx = (try self.newArray()).asObj();
        try idx.elements.append(idx.elementsAllocator(self.arena), try self.indexPair(
            utf16IndexForByteOffset(input, base + m.start),
            utf16IndexForByteOffset(input, base + m.end),
        ));
        for (0..m.captures.len) |i| {
            const present = i < m.captures_present.len and m.captures_present[i];
            if (present and i < m.capture_spans.len) {
                try idx.elements.append(idx.elementsAllocator(self.arena), try self.indexPair(
                    utf16IndexForByteOffset(input, base + m.capture_spans[i][0]),
                    utf16IndexForByteOffset(input, base + m.capture_spans[i][1]),
                ));
            } else {
                try idx.elements.append(idx.elementsAllocator(self.arena), Value.undef());
            }
        }
        if (re.named_capture_list.len > 0) {
            const g = (try self.newObject()).asObj();
            g.setProtoAtomic(null); // MakeIndicesArray: groups is ObjectCreate(null)
            for (re.named_capture_list) |entry| {
                const v: Value = if (namedCaptureSpan(re, m, entry.name)) |span|
                    try self.indexPair(
                        utf16IndexForByteOffset(input, base + span[0]),
                        utf16IndexForByteOffset(input, base + span[1]),
                    )
                else
                    Value.undef();
                try self.setProp(g, entry.name, v);
            }
            try self.setProp(idx, "groups", Value.obj(g));
        } else {
            try self.setProp(idx, "groups", Value.undef());
        }
        return idx;
    }

    /// GetSubstitution: append `template` to `buf`, expanding the `$` forms —
    /// `$$`, `$&` (matched), `` $` `` (prefix), `$'` (suffix), `$n`/`$nn`
    /// (capture groups, 1-based), and `$<name>` (named groups).
    fn getSubstitution(
        self: *Interpreter,
        buf: *std.ArrayListUnmanaged(u8),
        template: []const u8,
        matched: []const u8,
        str: []const u8,
        position: usize,
        captures: []const []const u8,
        groups: ?*value.Object,
    ) EvalError!void {
        const a = self.arena;
        var i: usize = 0;
        while (i < template.len) : (i += 1) {
            if (template[i] != '$' or i + 1 >= template.len) {
                try buf.append(a, template[i]);
                continue;
            }
            switch (template[i + 1]) {
                '$' => {
                    try buf.append(a, '$');
                    i += 1;
                },
                '&' => {
                    try buf.appendSlice(a, matched);
                    i += 1;
                },
                '`' => {
                    try buf.appendSlice(a, str[0..position]);
                    i += 1;
                },
                '\'' => {
                    const end = position + matched.len;
                    try buf.appendSlice(a, if (end <= str.len) str[end..] else "");
                    i += 1;
                },
                '<' => {
                    // `$<name>` — only when the pattern had named groups.
                    if (groups == null) {
                        try buf.append(a, '$');
                        continue;
                    }
                    const close = std.mem.indexOfScalarPos(u8, template, i + 2, '>') orelse {
                        try buf.append(a, '$');
                        continue;
                    };
                    const gv = groups.?.getOwn(template[i + 2 .. close]) orelse Value.undef();
                    if (gv.isString()) try buf.appendSlice(a, gv.asStr());
                    i = close;
                },
                '0'...'9' => {
                    var idx: usize = template[i + 1] - '0';
                    var consumed: usize = 1;
                    if (i + 2 < template.len and template[i + 2] >= '0' and template[i + 2] <= '9') {
                        const two = idx * 10 + (template[i + 2] - '0');
                        if (two >= 1 and two <= captures.len) {
                            idx = two;
                            consumed = 2;
                        }
                    }
                    if (idx >= 1 and idx <= captures.len) {
                        try buf.appendSlice(a, captures[idx - 1]);
                        i += consumed;
                    } else {
                        try buf.append(a, '$'); // not a valid group reference → literal `$`
                    }
                },
                else => try buf.append(a, '$'),
            }
        }
    }

    fn getSubstitutionValues(
        self: *Interpreter,
        buf: *std.ArrayListUnmanaged(u8),
        template: []const u8,
        matched: []const u8,
        str: []const u8,
        position: usize,
        captures: []const Value,
        groups: Value,
    ) EvalError!void {
        const a = self.arena;
        var i: usize = 0;
        while (i < template.len) : (i += 1) {
            if (template[i] != '$' or i + 1 >= template.len) {
                try buf.append(a, template[i]);
                continue;
            }
            switch (template[i + 1]) {
                '$' => {
                    try buf.append(a, '$');
                    i += 1;
                },
                '&' => {
                    try buf.appendSlice(a, matched);
                    i += 1;
                },
                '`' => {
                    try appendUtf16Slice(buf, a, str, 0, position);
                    i += 1;
                },
                '\'' => {
                    const end = position + utf16LenOfString(matched);
                    try appendUtf16Slice(buf, a, str, @min(end, utf16LenOfString(str)), utf16LenOfString(str));
                    i += 1;
                },
                '<' => {
                    if (groups.isUndefined()) {
                        try buf.append(a, '$');
                        continue;
                    }
                    const close = std.mem.indexOfScalarPos(u8, template, i + 2, '>') orelse {
                        try buf.append(a, '$');
                        continue;
                    };
                    const gv = try self.getProperty(groups, template[i + 2 .. close]);
                    if (!gv.isUndefined()) try buf.appendSlice(a, try self.toStringV(gv));
                    i = close;
                },
                '0'...'9' => {
                    var idx: usize = template[i + 1] - '0';
                    var consumed: usize = 1;
                    if (i + 2 < template.len and template[i + 2] >= '0' and template[i + 2] <= '9') {
                        const two = idx * 10 + (template[i + 2] - '0');
                        if (two >= 1 and two <= captures.len) {
                            idx = two;
                            consumed = 2;
                        }
                    }
                    if (idx >= 1 and idx <= captures.len) {
                        if (!captures[idx - 1].isUndefined()) try buf.appendSlice(a, captures[idx - 1].asStr());
                        i += consumed;
                    } else {
                        try buf.append(a, '$');
                    }
                },
                else => try buf.append(a, '$'),
            }
        }
    }

    // ---- try / catch / finally --------------------------------------------

    fn evalTry(self: *Interpreter, t: *ast.TryNode) EvalError!Value {
        // Evaluate the try block (and catch, on a caught throw), capturing its
        // completion — a value, a pending signal (break/continue/return), or a
        // held error — so finally can run with a clean slate and override it.
        var result: Value = Value.undef();
        var held_err: ?EvalError = null;
        // The pending exception *value* lives in `self.exception`; a finally
        // block that internally throws-and-catches clobbers it, so hold it
        // alongside `held_err` and restore it if the held throw resumes.
        var held_exc: Value = Value.undef();
        if (self.eval(t.block)) |v| {
            result = v;
        } else |err| {
            if (err == error.Throw and t.catch_block != null) {
                const exc = self.exception;
                self.exception = Value.undef();
                const catch_env = try gc_mod.allocEnv(self.arena);
                self.initEnvironment(catch_env, self.env, false);
                const saved = self.env;
                self.env = catch_env;
                // Bind the catch target (identifier or destructuring pattern)
                // into the catch scope. A simple identifier binding is Annex
                // B.3.5-exempt from the eval var-conflict check.
                if (t.catch_param) |p| {
                    if (p.* == .identifier) catch_env.is_catch_param = true;
                    try self.bindPattern(p, exc, true);
                }
                const catch_result = self.eval(t.catch_block.?);
                self.env = saved;
                if (catch_result) |v| {
                    result = v;
                } else |cerr| {
                    held_err = cerr;
                    held_exc = self.exception;
                }
            } else {
                held_err = err;
                held_exc = self.exception;
            }
        }
        if (t.finally_block) |fb| {
            // The try/catch completion may have left an abrupt signal pending; a
            // statement list short-circuits on it, so clear it before running
            // finally and hold it aside. If finally completes normally the held
            // completion resumes; if finally is itself abrupt (break/continue/
            // return/throw) it OVERRIDES the held one (the spec's UpdateEmpty +
            // "if F is abrupt, return F").
            const saved_signal = self.signal;
            const saved_label = self.signal_label;
            self.signal = .none;
            self.signal_label = null;
            if (self.eval(fb)) |fval| {
                if (self.signal == .none) {
                    self.signal = saved_signal;
                    self.signal_label = saved_label;
                    if (held_err) |e| {
                        // Restore the held exception value: finally may have run
                        // its own throw-and-catch, leaving `self.exception` stale.
                        self.exception = held_exc;
                        return e;
                    }
                    return result;
                }
                // finally produced its own abrupt completion: it wins, and any
                // held throw is swallowed.
                if (held_err != null) self.exception = Value.undef();
                return fval;
            } else |ferr| {
                return ferr;
            }
        }
        if (held_err) |e| return e;
        return result;
    }

    fn evalUnary(self: *Interpreter, op: ast.UnaryOp, operand: *Node) EvalError!Value {
        // `typeof <unresolved identifier>` is "undefined" rather than a thrown
        // ReferenceError — the one context where an unbound name doesn't throw.
        if (op == .typeof and operand.* == .identifier and self.env.get(operand.identifier) == null and !self.globalHasOwn(operand.identifier))
            return Value.str("undefined");
        const v = try self.eval(operand);
        // `-`/`+`/`~` begin with ToNumeric: reduce a wrapper object to a numeric
        // primitive (one valueOf) so `~new Boolean(true)`, `~Object(1n)`, etc.
        // dispatch on the underlying value, not on the object reference. BigInt
        // unary: `-`/`~` stay BigInt; unary `+` is a TypeError; `typeof`/`!`/`void`
        // do NOT coerce.
        const nv = if (op == .neg or op == .pos or op == .bit_not) try self.toNumericPrimitive(v) else v;
        if (nv.isObject() and nv.asObj().is_bigint and (op == .neg or op == .pos or op == .bit_not)) {
            return switch (op) {
                .neg => try negateBigIntObject(self, nv.asObj()),
                .bit_not => try bitNotBigIntObject(self, nv.asObj()),
                .pos => self.throwError("TypeError", "Cannot convert a BigInt value to a number"),
                else => unreachable,
            };
        }
        return switch (op) {
            .neg => Value.num(-(try self.toNumberV(nv))),
            .pos => Value.num(try self.toNumberV(nv)),
            .not => Value.boolVal(!v.toBoolean()),
            .typeof => Value.str(v.typeOf()),
            .bit_not => Value.num(@floatFromInt(~Value.num(try self.toNumberV(nv)).toInt32())),
            .void_op => Value.undef(),
            .to_string => Value.str(try self.toStringV(v)), // template-substitution ToString
        };
    }

    /// ToNumeric's reduction step for unary `-`/`+`/`~`: turn a wrapper object
    /// into a numeric primitive (running valueOf/toString once). A BigInt value
    /// (`is_bigint`) and a Symbol are already primitives here and pass through;
    /// a `Object(1n)` BigInt-wrapper reduces to its `1n` so it negates/complements
    /// as a BigInt rather than throwing in ToNumber.
    pub fn toNumericPrimitive(self: *Interpreter, v: Value) EvalError!Value {
        if (v.isObject() and !v.asObj().is_bigint and !v.asObj().is_symbol)
            return self.toPrimitive(v, .number);
        return v;
    }

    fn evalLogical(self: *Interpreter, op: ast.LogicalOp, left: *Node, right: *Node) EvalError!Value {
        const l = try self.eval(left);
        return switch (op) {
            .@"and" => if (l.toBoolean()) try self.eval(right) else l,
            .@"or" => if (l.toBoolean()) l else try self.eval(right),
            .nullish => if (l.isNull() or l.isUndefined()) try self.eval(right) else l,
        };
    }

    fn evalBinary(self: *Interpreter, op: ast.BinaryOp, left_node: *Node, right_node: *Node) EvalError!Value {
        // `#field in obj` — a private-name brand check. The LHS is a private-name
        // reference (an identifier whose text starts with `#`), which can't be
        // evaluated as an ordinary value.
        if (op == .in_op and left_node.* == .identifier and value.isPrivateKey(left_node.identifier)) {
            const robj = try self.eval(right_node);
            return Value.boolVal(try self.privateIn(left_node.identifier, robj));
        }
        const l = try self.eval(left_node);
        const r = try self.eval(right_node);
        return self.applyBinary(op, l, r);
    }

    pub fn privateIn(self: *Interpreter, key: []const u8, robj: Value) EvalError!bool {
        if (!robj.isObject())
            return self.throwError("TypeError", "Cannot use 'in' to search for a private name in a non-object");
        // Private elements are hidden from ordinary reflection, so look them up
        // directly. A field is an own data slot; a method/accessor lives on the
        // class prototype, so walk the prototype chain too.
        var cur: ?*value.Object = robj.asObj();
        while (cur) |c| {
            if (c.getOwn(key) != null or c.getAccessor(key) != null) return true;
            cur = c.protoAtomic();
        }
        return false;
    }

    /// Apply a binary operator to two already-evaluated operands. Shared by the
    /// tree-walker and the bytecode VM.
    /// ToPrimitive: coerce a value to a primitive. Non-objects pass through; a
    /// Symbol is returned as-is. For an object, try `valueOf` then `toString`
    /// (order flipped for a string hint) via `callMethod` — so the universal
    /// `valueOf`/`toString` apply even to proto-less plain objects — and the
    /// first primitive result wins.
    pub fn toPrimitive(self: *Interpreter, v: Value, hint: enum { default, number, string }) EvalError!Value {
        if (!v.isObject() or v.asObj().is_symbol or v.asObj().is_bigint) return v;
        const o = v.asObj();
        // GetMethod(v, @@toPrimitive): if present, it alone decides — it is called
        // with the hint string and must return a non-object (an object result is
        // the "Cannot convert" TypeError); a non-callable @@toPrimitive throws.
        if (self.wellKnownSymbolKey("toPrimitive")) |tpkey| {
            const exotic = try self.getProperty(v, tpkey);
            if (!exotic.isUndefined() and !exotic.isNull()) {
                if (!exotic.isCallable()) return self.throwError("TypeError", "@@toPrimitive value is not callable");
                const hint_str: []const u8 = switch (hint) {
                    .string => "string",
                    .number => "number",
                    .default => "default",
                };
                const res = try self.callValueWithThis(exotic, &.{Value.str(hint_str)}, v);
                if (!res.isObject() or res.asObj().is_symbol or res.asObj().is_bigint) return res;
                return self.throwError("TypeError", "Cannot convert object to primitive value");
            }
        }
        // Honor a *user-defined* valueOf/toString (a JS function found on the
        // object or its prototype chain — e.g. `{ valueOf() {…} }` or a class
        // method) in the hint's order; the first primitive result wins. The
        // engine's built-in `valueOf`/`toString` (native prototype thunks) are
        // skipped here — falling through to the built-in coercion below — which
        // also avoids looping back through method dispatch.
        const names: [2][]const u8 = if (hint == .string) .{ "toString", "valueOf" } else .{ "valueOf", "toString" };
        var user_tried: u8 = 0;
        var builtin_wrapper_value_of = false;
        var builtin_to_string = false;
        var builtin_to_string_method: ?Value = null;
        outer: for (names) |m| {
            if (moduleNsOf(o) != null) {
                const method = try self.getProperty(v, m);
                if (method.isUndefined() or method.isNull()) continue;
                if (!method.isCallable()) break :outer;
                user_tried += 1;
                const res = try self.callValueWithThis(method, &.{}, v);
                if (!res.isObject() or res.asObj().is_bigint or res.asObj().is_symbol) return res;
                continue;
            }
            if (o.proxy_handler != null or o.proxy_revoked) {
                const method = try self.getProperty(v, m);
                if (method.isUndefined() or method.isNull()) continue;
                if (!method.isCallable()) break :outer;
                user_tried += 1;
                const res = try self.callValueWithThis(method, &.{}, v);
                if (!res.isObject() or res.asObj().is_bigint or res.asObj().is_symbol) return res;
                continue;
            }
            // OrdinaryToPrimitive resolves each method via `Get(O, name)`, so an
            // *accessor* `valueOf`/`toString` getter is run (and its abrupt
            // completion must propagate — `{ get valueOf() { throw } }`). A data
            // property that is a JS function is the method directly; the engine's
            // native prototype thunks / non-callable shadows are left to the
            // built-in coercion below (calling them would loop through dispatch).
            var method: ?Value = null;
            var cur: ?*value.Object = o;
            while (cur) |c| : (cur = c.protoAtomic()) {
                if (c.getAccessor(m)) |acc| {
                    if (acc.get) |g| {
                        if (!g.isUndefined()) method = try self.callValueWithThis(g, &.{}, v);
                    }
                    break;
                }
                if (c.getOwn(m)) |fv| {
                    if (fv.isObject() and (fv.asObj().js_func != null or (c == o and fv.asObj().native != null) or (o.temporal != null and std.mem.eql(u8, m, "valueOf") and fv.asObj().native != null))) method = fv
                        // Primitive wrappers' native valueOf is a spec builtin that
                        // produces the boxed primitive at this position in the
                        // OrdinaryToPrimitive order, so do not continue to a later
                        // user toString accessor for default/number hints.
                    else if (std.mem.eql(u8, m, "valueOf") and o.prim != null and fv.isCallable()) builtin_wrapper_value_of = true
                        // A callable native `toString` thunk yields a primitive string
                        // (the built-in coercion below); it must run at *this* position
                        // in the hint order — so stop here rather than trying a later
                        // user `valueOf` (e.g. String({ valueOf() {…} }) is
                        // "[object Object]", not the valueOf result).
                    else if (std.mem.eql(u8, m, "toString") and fv.isCallable()) {
                        builtin_to_string = true;
                        builtin_to_string_method = fv;
                    }
                    break; // native thunk or non-callable shadow → built-in coercion
                }
            }
            if (builtin_wrapper_value_of or builtin_to_string) break :outer;
            if (method) |fnv| {
                if (fnv.isCallable()) {
                    user_tried += 1;
                    const res = try self.callValueWithThis(fnv, &.{}, v);
                    // A BigInt or Symbol result is a primitive (it is represented
                    // as an object internally), so it ends ToPrimitive too.
                    if (!res.isObject() or res.asObj().is_bigint or res.asObj().is_symbol) return res;
                }
            }
        }
        // Both `toString` and `valueOf` were user-defined and each returned an
        // object — there's no built-in to fall back to, so this is the spec's
        // "Cannot convert object to primitive value" TypeError.
        if (user_tried == 2) return self.throwError("TypeError", "Cannot convert object to primitive value");
        // A callable object with no user-defined valueOf/toString stringifies via
        // Function.prototype.toString (its source text / native syntax). `valueOf`
        // returns the object itself, so `toString` always wins regardless of hint.
        if (o.isCallableObject()) return try self.functionToString(o);
        // A primitive-wrapper object (`new Number/String/Boolean`) with no user
        // override unwraps to its boxed primitive — except for a string hint,
        // where it stringifies (so `new Number(5) + 1 === 6` but `String hint`
        // gives "5").
        if (o.prim) |p| {
            if (builtin_wrapper_value_of) return p;
            if (builtin_to_string) {
                if (p.isObject() and p.asObj().is_symbol) {
                    const ds = p.asObj().sym_desc orelse "";
                    return Value.str(try std.mem.concat(self.arena, u8, &.{ "Symbol(", ds, ")" }));
                }
                return Value.str(try p.toString(self.arena));
            }
            return self.throwError("TypeError", "Cannot convert object to primitive value");
        }
        // A Date with the built-in coercion: a number hint (`Number(date)`,
        // `+date`, `date - date`) yields its time value; string/default hints
        // (Date's default hint is "string": `\`${date}\``, `date + ""`) yield the
        // built-in Date toString, which OrdinaryToPrimitive above skipped as a
        // native thunk.
        if (o.is_date) {
            if (hint == .number) return Value.num(o.dateMs());
            return (try self.dateMethod(o, "toString", &.{})) orelse Value.str("Invalid Date");
        }
        // The built-in "[object …]" / array-join / Date / error fallback is the
        // result of the *built-in* `toString`; it is only reachable when
        // `toString` still resolves to that built-in. If it is shadowed — by a
        // non-callable own value (`toString: undefined`) or by a user method
        // (which, having been tried in the loop above, must have returned an
        // object, since we're at the fallback) — there is no primitive and no
        // built-in to fall back to: the spec's "Cannot convert object to
        // primitive value" TypeError.
        const own_ts = o.getOwn("toString");
        const ts_shadowed = (own_ts != null and !own_ts.?.isCallable()) or userMethodOf(o, "toString") != null;
        if (ts_shadowed) return self.throwError("TypeError", "Cannot convert object to primitive value");
        if (!builtin_to_string) return self.throwError("TypeError", "Cannot convert object to primitive value");
        if (builtin_to_string_method) |m| {
            const res = try self.callValueWithThis(m, &.{}, v);
            if (!res.isObject() or res.asObj().is_symbol or res.asObj().is_bigint) return res;
        }
        return self.throwError("TypeError", "Cannot convert object to primitive value");
    }

    /// A *user-defined* `name` method on `o`'s own properties or prototype chain
    /// — a JS function (`js_func`), not one of the engine's native built-in
    /// prototype thunks (calling those would loop back through dispatch). The
    /// nearest definition shadows: if it's a native thunk we stop and report
    /// none, so ToPrimitive uses the built-in coercion instead.
    fn userMethodOf(o: *value.Object, name: []const u8) ?Value {
        var cur: ?*value.Object = o;
        while (cur) |c| : (cur = c.protoAtomic()) {
            if (c.getOwn(name)) |fv| {
                return if (fv.isObject() and fv.asObj().js_func != null) fv else null;
            }
        }
        return null;
    }

    pub fn applyBinary(self: *Interpreter, op_in: ast.BinaryOp, l_in: Value, r_in: Value) EvalError!Value {
        const op = op_in;
        var l = l_in;
        var r = r_in;
        // Coerce object operands to primitives first (ToPrimitive). `+` uses the
        // "default" hint; the other arithmetic / relational / bitwise ops use
        // "number". Equality and instanceof/in handle objects themselves.
        switch (op) {
            .add => {
                l = try self.toPrimitive(l, .default);
                r = try self.toPrimitive(r, .default);
            },
            .sub, .mul, .div, .mod, .pow, .lt, .le, .gt, .ge, .bit_and, .bit_or, .bit_xor, .shl, .shr, .ushr => {
                // ApplyStringOrNumericBinaryOperator evaluates ToNumeric(lhs)
                // *completely* — ToPrimitive(number) then the Symbol → TypeError
                // of ToNumber — before ToNumeric(rhs). So coerce and Symbol-check
                // each operand in order: a throwing lhs conversion must abort
                // before the rhs operand is coerced at all (its `valueOf` must not
                // run). (BigInt mixing is diagnosed later, after both ToNumerics.)
                l = try self.toPrimitive(l, .number);
                if (l.isObject() and l.asObj().is_symbol)
                    return self.throwError("TypeError", "Cannot convert a Symbol value to a number");
                r = try self.toPrimitive(r, .number);
                if (r.isObject() and r.asObj().is_symbol)
                    return self.throwError("TypeError", "Cannot convert a Symbol value to a number");
            },
            .eq, .neq => {
                // Abstract equality (IsLooselyEqual): when one operand is an
                // ordinary object and the other is a primitive, the object is
                // ToPrimitive'd (default hint) and the comparison retried — so
                // `Object("1") == "1"` and `{valueOf(){return 1}} == 1` hold. Two
                // objects compare by identity, and an object vs null/undefined is
                // always unequal, so neither is coerced. A BigInt/Symbol value is
                // boxed as an object here but counts as a primitive operand.
                const l_obj = l.isObject() and !l.asObj().is_bigint and !l.asObj().is_symbol;
                const r_obj = r.isObject() and !r.asObj().is_bigint and !r.asObj().is_symbol;
                if (l_obj and !r_obj and !r.isUndefined() and !r.isNull()) l = try self.toPrimitive(l, .default);
                if (r_obj and !l_obj and !l.isUndefined() and !l.isNull()) r = try self.toPrimitive(r, .default);
            },
            else => {},
        }
        // (Symbol operands for the number-hint ops above were already rejected
        // in-order during their ToNumeric coercion.)
        // BigInt operands. Arithmetic/bitwise require both to be BigInt (mixing
        // with a Number is a TypeError); relational ops compare mathematically;
        // `+` with a string still concatenates.
        const l_big = l.isObject() and l.asObj().is_bigint;
        const r_big = r.isObject() and r.asObj().is_bigint;
        if (l_big or r_big) {
            switch (op) {
                .add => if (l.isString() or r.isString()) {} else return self.bigIntBinary(op, l, r, l_big, r_big),
                .sub, .mul, .div, .mod, .pow, .bit_and, .bit_or, .bit_xor, .shl, .shr => return self.bigIntBinary(op, l, r, l_big, r_big),
                .ushr => return self.throwError("TypeError", "BigInts have no unsigned right shift, use >> instead"),
                // A null order is the spec's "undefined" comparison result (a
                // NaN Number operand or a non-BigInt-shaped String) — every
                // relational operator then yields false.
                .lt => return Value.boolVal(if (try self.bigCmp(l, r)) |o| o == .lt else false),
                .le => return Value.boolVal(if (try self.bigCmp(l, r)) |o| o != .gt else false),
                .gt => return Value.boolVal(if (try self.bigCmp(l, r)) |o| o == .gt else false),
                .ge => return Value.boolVal(if (try self.bigCmp(l, r)) |o| o != .lt else false),
                .eq => return Value.boolVal(try self.bigLooseEqual(l, r)),
                .neq => return Value.boolVal(!(try self.bigLooseEqual(l, r))),
                else => {},
            }
        }
        return switch (op) {
            .add => blk: {
                // String concatenation if either operand is a string.
                if (l.isString() or r.isString()) {
                    const ls = try self.toStringV(l);
                    const rs = try self.toStringV(r);
                    break :blk Value.str(try std.mem.concat(self.arena, u8, &.{ ls, rs }));
                }
                // Numeric `+`: both operands were already ToPrimitive'd (default
                // hint) above; ToNumeric(lhs) then ToNumeric(rhs) follow in order,
                // each throwing on a Symbol operand.
                if (l.isObject() and l.asObj().is_symbol)
                    return self.throwError("TypeError", "Cannot convert a Symbol value to a number");
                if (r.isObject() and r.asObj().is_symbol)
                    return self.throwError("TypeError", "Cannot convert a Symbol value to a number");
                break :blk Value.num(l.toNumber() + r.toNumber());
            },
            .sub => Value.num(l.toNumber() - r.toNumber()),
            .mul => Value.num(l.toNumber() * r.toNumber()),
            .div => Value.num(l.toNumber() / r.toNumber()),
            // JS `%` is the truncated remainder (result takes the sign of the
            // dividend), i.e. `@rem`, not the floored `@mod`: `-5 % 3` is `-2`.
            .mod => Value.num(@rem(l.toNumber(), r.toNumber())),
            .pow => blk: {
                const base = l.toNumber();
                const exp = r.toNumber();
                // Number::exponentiate diverges from C `pow` here: when the base
                // is ±1 and the exponent is ±∞ the result is NaN, not 1.
                if (std.math.isInf(exp) and @abs(base) == 1) break :blk Value.num(std.math.nan(f64));
                break :blk Value.num(std.math.pow(f64, base, exp));
            },
            .lt => Value.boolVal(try lessThan(self, l, r)),
            .le => Value.boolVal(!(try lessThan(self, r, l)) and !relationalNaN(l, r)),
            .gt => Value.boolVal(try lessThan(self, r, l)),
            .ge => Value.boolVal(!(try lessThan(self, l, r)) and !relationalNaN(l, r)),
            .eq => Value.boolVal(value.looseEquals(l, r)),
            .neq => Value.boolVal(!value.looseEquals(l, r)),
            .eq_strict => Value.boolVal(value.strictEquals(l, r)),
            .neq_strict => Value.boolVal(!value.strictEquals(l, r)),
            .instanceof => Value.boolVal(try self.instanceOf(l, r)),
            .in_op => Value.boolVal(try self.inOperator(l, r)),
            .bit_and => Value.num(@floatFromInt(l.toInt32() & r.toInt32())),
            .bit_or => Value.num(@floatFromInt(l.toInt32() | r.toInt32())),
            .bit_xor => Value.num(@floatFromInt(l.toInt32() ^ r.toInt32())),
            .shl => blk: {
                const sh: u5 = @intCast(r.toUint32() & 31);
                break :blk Value.num(@floatFromInt(@as(i32, @bitCast(l.toUint32() << sh))));
            },
            .shr => blk: {
                const sh: u5 = @intCast(r.toUint32() & 31);
                break :blk Value.num(@floatFromInt(l.toInt32() >> sh));
            },
            .ushr => blk: {
                const sh: u5 = @intCast(r.toUint32() & 31);
                break :blk Value.num(@floatFromInt(l.toUint32() >> sh));
            },
        };
    }

    /// A BigInt binary op (both operands must be BigInt — mixing is a TypeError).
    fn bigIntBinary(self: *Interpreter, op: ast.BinaryOp, l: Value, r: Value, l_big: bool, r_big: bool) EvalError!Value {
        if (!l_big or !r_big) return self.throwError("TypeError", "Cannot mix BigInt and other types, use explicit conversions");
        const lo = l.asObj();
        const ro = r.asObj();
        // `**` and the shifts can produce results far past i128, and a
        // text-backed operand already doesn't fit, so they always take the
        // arbitrary-precision path. Bitwise ops never overflow and i128's
        // two's-complement matches BigInt's, so they stay on the fast path
        // unless an operand is text-backed.
        if (lo.bigint_text != null or ro.bigint_text != null)
            return self.bigIntBinaryBig(op, lo, ro);
        switch (op) {
            .pow, .shl, .shr => return self.bigIntBinaryBig(op, lo, ro),
            else => {},
        }
        const a = lo.bigint;
        const b = ro.bigint;
        switch (op) {
            // Arithmetic can overflow i128 even when both operands fit; fall back
            // to the bignum path on overflow so the result is exact.
            .add => {
                const res = @addWithOverflow(a, b);
                return if (res[1] == 0) self.makeBigInt(res[0]) else self.bigIntBinaryBig(op, lo, ro);
            },
            .sub => {
                const res = @subWithOverflow(a, b);
                return if (res[1] == 0) self.makeBigInt(res[0]) else self.bigIntBinaryBig(op, lo, ro);
            },
            .mul => {
                const res = @mulWithOverflow(a, b);
                return if (res[1] == 0) self.makeBigInt(res[0]) else self.bigIntBinaryBig(op, lo, ro);
            },
            .div => {
                if (b == 0) return self.throwError("RangeError", "Division by zero");
                if (a == std.math.minInt(i128) and b == -1) return self.bigIntBinaryBig(op, lo, ro);
                return self.makeBigInt(@divTrunc(a, b));
            },
            .mod => {
                if (b == 0) return self.throwError("RangeError", "Division by zero");
                if (a == std.math.minInt(i128) and b == -1) return self.makeBigInt(0);
                return self.makeBigInt(@rem(a, b));
            },
            .bit_and => return self.makeBigInt(a & b),
            .bit_or => return self.makeBigInt(a | b),
            .bit_xor => return self.makeBigInt(a ^ b),
            else => return self.makeBigInt(0),
        }
    }

    /// Arbitrary-precision BigInt binary op via `std.math.big`, used when an
    /// operand doesn't fit i128 or the i128 result would overflow. `**` and the
    /// shifts always route here.
    fn bigIntBinaryBig(self: *Interpreter, op: ast.BinaryOp, lo: *value.Object, ro: *value.Object) EvalError!Value {
        if (op == .shl or op == .shr) return self.bigIntShift(lo, ro, op == .shr);
        var a = try managedBigIntFromObject(self.arena, lo);
        var b = try managedBigIntFromObject(self.arena, ro);
        var out = try std.math.big.int.Managed.init(self.arena);
        switch (op) {
            .add => try out.add(&a, &b),
            .sub => try out.sub(&a, &b),
            .mul => try out.mul(&a, &b),
            .div => {
                if (b.toConst().eqlZero()) return self.throwError("RangeError", "Division by zero");
                var rem = try std.math.big.int.Managed.init(self.arena);
                try out.divTrunc(&rem, &a, &b);
            },
            .mod => {
                if (b.toConst().eqlZero()) return self.throwError("RangeError", "Division by zero");
                var q = try std.math.big.int.Managed.init(self.arena);
                try q.divTrunc(&out, &a, &b);
            },
            .pow => {
                const ec = b.toConst();
                if (!ec.positive and !ec.eqlZero()) return self.throwError("RangeError", "Exponent must be non-negative");
                const exp = b.toInt(u32) catch return self.throwError("RangeError", "Maximum BigInt size exceeded");
                try out.pow(&a, exp);
            },
            .bit_and => try out.bitAnd(&a, &b),
            .bit_or => try out.bitOr(&a, &b),
            .bit_xor => try out.bitXor(&a, &b),
            else => {},
        }
        return makeBigIntFromManaged(self, &out);
    }

    /// BigInt `<<`/`>>`. `>>` is an arithmetic (floor) shift, so a right shift is
    /// `floor(a / 2^n)` (via `divFloor`, which rounds toward −∞ like the spec) and
    /// a left shift is `a · 2^n`. A negative count reverses the direction. A left
    /// shift past the engine BigInt size cap is a RangeError.
    fn bigIntShift(self: *Interpreter, lo: *value.Object, ro: *value.Object, is_shr: bool) EvalError!Value {
        var a = try managedBigIntFromObject(self.arena, lo);
        var count = try managedBigIntFromObject(self.arena, ro);
        const count_nonneg = count.toConst().positive; // sign-magnitude (zero is +)
        const left = (!is_shr and count_nonneg) or (is_shr and !count_nonneg);
        count.abs();
        const max_bits: usize = 1 << 30; // arbitrary engine-style BigInt size cap
        const mag: usize = count.toInt(usize) catch (max_bits + 1);
        var out = try std.math.big.int.Managed.init(self.arena);
        if (mag == 0) {
            try out.copy(a.toConst());
            return makeBigIntFromManaged(self, &out);
        }
        if (left) {
            if (mag > max_bits) return self.throwError("RangeError", "Maximum BigInt size exceeded");
            try out.shiftLeft(&a, mag);
            return makeBigIntFromManaged(self, &out);
        }
        // Right shift = floor(a / 2^mag). When 2^mag exceeds |a|, the floor is 0
        // for a ≥ 0 and −1 for a < 0 (so we never build an enormous divisor).
        const ac = a.toConst();
        if (mag > ac.bitCountAbs()) {
            try out.set(@as(i8, if (!ac.positive and !ac.eqlZero()) -1 else 0));
            return makeBigIntFromManaged(self, &out);
        }
        var one = try std.math.big.int.Managed.initSet(self.arena, 1);
        var divisor = try std.math.big.int.Managed.init(self.arena);
        try divisor.shiftLeft(&one, mag);
        var rem = try std.math.big.int.Managed.init(self.arena);
        try out.divFloor(&rem, &a, &divisor);
        return makeBigIntFromManaged(self, &out);
    }

    /// Mathematical comparison of two BigInt/Number operands (for `< <= > >=`),
    /// returning negative/zero/positive. (Lossy for BigInts beyond 2^53.)
    /// Abstract relational comparison when at least one operand is a BigInt.
    /// Returns the order of `(l, r)`, or null for the spec's "undefined" result
    /// (a NaN Number operand, or a String that is not a valid BigInt). All
    /// comparisons are exact: BigInts are arbitrary-precision (an f64 round-trip
    /// loses precision past 2^53, and 300-digit literals overflow i128), and a
    /// BigInt-vs-Number compare decomposes the f64 into M·2^E, so even
    /// `Number.MAX_VALUE` against a huge BigInt is exact.
    fn bigCmp(self: *Interpreter, l: Value, r: Value) EvalError!?std.math.Order {
        const l_big = l.isObject() and l.asObj().is_bigint;
        const r_big = r.isObject() and r.asObj().is_bigint;
        if (l_big and r_big) {
            var a = try managedBigIntFromObject(self.arena, l.asObj());
            const b = try managedBigIntFromObject(self.arena, r.asObj());
            return a.toConst().order(b.toConst());
        }
        if (l_big) {
            var a = try managedBigIntFromObject(self.arena, l.asObj());
            return self.bigVsOther(&a, r);
        }
        // r is the BigInt; compute order(r, l) and invert it.
        var b = try managedBigIntFromObject(self.arena, r.asObj());
        const o = try self.bigVsOther(&b, l);
        return if (o) |ord| ord.invert() else null;
    }

    /// Order of `(big, other)`, where `other` is a primitive Number/String/
    /// Boolean/null/undefined (Symbols were already rejected). A String uses
    /// StringToBigInt (a non-BigInt-shaped string ⇒ null/"undefined"); any other
    /// operand goes through ToNumber and an exact BigInt-vs-Number compare.
    fn bigVsOther(self: *Interpreter, big: *std.math.big.int.Managed, other: Value) EvalError!?std.math.Order {
        if (other.isString()) {
            var ny = (try stringToBigIntManaged(self.arena, other.asStr())) orelse return null;
            return big.toConst().order(ny.toConst());
        }
        const n = other.toNumber();
        if (std.math.isNan(n)) return null;
        if (std.math.isInf(n)) return if (n > 0) std.math.Order.lt else std.math.Order.gt;
        return try bigVsFiniteF64(self.arena, big, n);
    }

    /// IsLooselyEqual when at least one (already-primitive) operand is a BigInt.
    /// `bigint == null/undefined/Symbol` is false; otherwise the other side is
    /// compared exactly — a Boolean/Number through ToNumber (a non-integer or
    /// NaN/±∞ is unequal), a String through StringToBigInt (an invalid string is
    /// unequal) — with no precision loss, so `0n == ""` is true and a 300-digit
    /// BigInt never equals `Number.MAX_VALUE`.
    fn bigLooseEqual(self: *Interpreter, l: Value, r: Value) EvalError!bool {
        const l_big = l.isObject() and l.asObj().is_bigint;
        const r_big = r.isObject() and r.asObj().is_bigint;
        if (l_big and r_big)
            return if (try self.bigCmp(l, r)) |o| o == .eq else false;
        const big = if (l_big) l else r;
        const other = if (l_big) r else l;
        if (other.isUndefined() or other.isNull()) return false;
        if (other.isObject() and other.asObj().is_symbol) return false;
        var bm = try managedBigIntFromObject(self.arena, big.asObj());
        return if (try self.bigVsOther(&bm, other)) |o| o == .eq else false;
    }

    /// `x instanceof C`: OrdinaryHasInstance walks the live prototype chain.
    /// Spec [[HasProperty]]: own property first, then prototype chain, invoking
    /// Proxy `has` traps at whichever object in the chain provides them.
    fn hasPropertyResult(self: *Interpreter, o: *value.Object, key: []const u8) EvalError!bool {
        // Integer-Indexed Exotic [[HasProperty]]: a canonical numeric key resolves
        // purely to index validity — it never consults the prototype chain.
        if (o.typed_array) |ta| {
            if (canonicalNumericIndexString(key)) |n| return isValidIntegerIndex(ta, n);
        }
        var cur: ?*value.Object = o;
        while (cur) |c| {
            if (c.proxy_handler != null or c.proxy_revoked) return self.proxyHas(c, key);
            if (moduleNsOf(c)) |ns| {
                try triggerDeferIfString(self, ns, key);
                return moduleNsHas(ns, key);
            }
            if (objectHasOwn(c, key)) return true;
            cur = self.effectiveProto(c);
        }
        return false;
    }

    pub fn inOperator(self: *Interpreter, l: Value, r: Value) EvalError!bool {
        if (r.isObject()) try self.checkRestricted(r.asObj());
        if (!r.isObject()) return self.throwError("TypeError", "cannot use 'in' on a non-object");
        const o = r.asObj();
        const key = try self.keyOf(l);
        if (try self.hasPropertyResult(o, key)) return true;
        // The global object carries the installed globals as properties.
        if (self.global_object != null and o == self.global_object.? and rootEnv(self.env).get(key) != null) return true;
        return false;
    }

    pub fn instanceOf(self: *Interpreter, l: Value, r: Value) EvalError!bool {
        if (!r.isObject())
            return self.throwError("TypeError", "Right-hand side of 'instanceof' is not an object");
        // InstanceofOperator: GetMethod(r, @@hasInstance) takes precedence — a
        // custom `[Symbol.hasInstance]` (even on a non-callable object) decides
        // membership, with ToBoolean applied to its result.
        if (self.wellKnownSymbolKey("hasInstance")) |hk| {
            const handler = try self.getProperty(r, hk);
            if (!handler.isUndefined() and !handler.isNull()) {
                if (!handler.isCallable())
                    return self.throwError("TypeError", "Symbol.hasInstance method is not callable");
                // Fast path: the default %Function.prototype[@@hasInstance]% just
                // does OrdinaryHasInstance — skip building a call frame for it.
                if (handler.isObject() and handler.asObj().native == functionHasInstanceFn)
                    return if (r.asObj().isCallableObject()) self.ordinaryHasInstance(r.asObj(), l) else false;
                return (try self.callValueWithThis(handler, &.{l}, r)).toBoolean();
            }
        }
        if (!r.asObj().isCallableObject())
            return self.throwError("TypeError", "Right-hand side of 'instanceof' is not callable");
        return self.ordinaryHasInstance(r.asObj(), l);
    }

    /// OrdinaryHasInstance(C=`rc`, O=`l`): is `rc.prototype` in `l`'s prototype
    /// chain? Assumes `rc` is already known callable (false otherwise).
    /// An object's effective [[Prototype]]: its `proto`, or — for a callable
    /// (native/bound) function that was never given one — %Function.prototype%,
    /// which every function inherits.
    pub fn effectiveProto(self: *Interpreter, o: *value.Object) ?*value.Object {
        if (o.protoAtomic()) |p| return p;
        if (o.native != null or o.js_func != null or o.bound != null) return self.functionProto();
        return null;
    }

    fn objectGetPrototypeValue(self: *Interpreter, o: *value.Object) EvalError!Value {
        if (o.proxy_handler != null or o.proxy_revoked) return self.proxyGetProto(o);
        return if (self.effectiveProto(o)) |p| Value.obj(p) else Value.nul();
    }

    pub fn ordinaryHasInstance(self: *Interpreter, rc: *value.Object, l: Value) EvalError!bool {
        if (!rc.isCallableObject()) return false;
        if (rc.bound) |erased| {
            const bf: *BoundFn = @ptrCast(@alignCast(erased));
            return self.instanceOf(l, bf.target);
        }
        if (!builtins.isRealObject(l)) return false;
        const lo = l.asObj();
        const p = try self.getProperty(Value.obj(rc), "prototype");
        if (!builtins.isRealObject(p)) return self.throwError("TypeError", "Function has non-object prototype in instanceof check");
        var cur = try self.objectGetPrototypeValue(lo);
        while (cur.isObject()) {
            if (cur.asObj() == p.asObj()) return true;
            cur = try self.objectGetPrototypeValue(cur.asObj());
        }
        if (rc.error_ctor) |name| {
            if (lo.is_error and (std.mem.eql(u8, lo.error_name, name) or std.mem.eql(u8, name, "Error")))
                return true;
        }
        return false;
    }
};

/// `Function.prototype[Symbol.hasInstance](O)` — OrdinaryHasInstance with the
/// bound function `this` as the constructor (false when `this` isn't callable).
fn functionHasInstanceFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (!this.isObject()) return Value.boolVal(false);
    return Value.boolVal(try self.ordinaryHasInstance(this.asObj(), if (args.len > 0) args[0] else Value.undef()));
}

/// The global `eval`. Direct eval runs in the caller's lexical environment;
/// member/indirect eval runs as global eval in the realm captured by the eval
/// function object.
fn evalFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (args.len == 0) return Value.undef();
    if (!args[0].isString()) return args[0]; // eval of a non-string is the identity
    const src = args[0].asStr();
    var parser = Parser.init(self.arena, src) catch return self.throwError("SyntaxError", "eval: invalid source");
    // Direct eval inherits the caller's strictness for early errors; indirect
    // eval is global code in the eval function's realm and only becomes strict
    // from its own directive prologue.
    if (self.direct_eval_call and self.strict) parser.strict = true;
    if (self.direct_eval_call and self.direct_eval_new_target_allowed) parser.new_target_depth = 1;
    // A direct eval inside a class element may reference the class's private names
    // (`eval("this.#x")`): allow them in the parse (and skip the undeclared-private
    // check), then rewrite them below to the class's storage keys.
    if (self.direct_eval_call and self.current_private_map != null) {
        parser.in_class = true;
        parser.eval_private_allowed = true;
    }
    const prog = parser.parseProgram() catch return self.throwError("SyntaxError", "eval: parse error");
    if (self.direct_eval_call) if (self.current_private_map) |pm|
        try self.rewritePrivateNamesInNode(prog, @constCast(pm));

    // Eval inherits the caller's syntactic restrictions as *early errors* — they
    // must reject the code before any of it runs. Indirect eval is global code:
    // a top-level SuperCall or SuperProperty is a SyntaxError. Direct eval outside
    // methods has the same `super` restriction, while a direct eval inside a
    // method but outside a derived constructor permits SuperProperty and rejects
    // only SuperCall. A class field initializer also forbids `arguments`. These
    // scans only cover the eval program's top level (descending into arrows but
    // not nested ordinary functions/classes), so `super` legitimately inside a
    // nested class/method is unaffected.
    if (prog.* == .program) {
        if (!self.direct_eval_call) {
            parser.scanEvalContext(prog.program, true, true) catch
                return self.throwError("SyntaxError", "eval: 'super' is only valid inside a method");
        } else if (self.in_field_initializer) {
            parser.scanEvalContext(prog.program, false, false) catch
                return self.throwError("SyntaxError", "eval: 'super()'/'arguments' not allowed in a field initializer");
        } else if (self.home_object == null) {
            parser.scanEvalContext(prog.program, true, true) catch
                return self.throwError("SyntaxError", "eval: 'super' is only valid inside a method");
        } else if (!self.in_derived_ctor) {
            parser.scanEvalContext(prog.program, true, false) catch
                return self.throwError("SyntaxError", "eval: 'super()' is only valid inside a derived constructor");
        }
        // A direct eval in a non-arrow function's parameter scope may not declare
        // `arguments` (the parameter environment already binds the arguments
        // object) — an early error before any eval'd code runs.
        if (self.direct_eval_call and self.in_param_expr) {
            if (parser.evalDeclaresArguments(prog.program) catch false)
                return self.throwError("SyntaxError", "eval: cannot declare 'arguments' in a parameter expression");
        }
    }

    const saved_env = self.env;
    const saved_this = self.this_value;
    const saved_glob = self.global_object;
    if (!self.direct_eval_call) {
        const fnobj = self.active_native orelse return Value.undef();
        const genv: *Environment = @ptrCast(@alignCast(fnobj.private_data orelse return Value.undef()));
        self.env = genv;
        if (genv.get("globalThis")) |gt| if (gt.isObject()) {
            self.this_value = Value.obj(gt.asObj());
            self.global_object = gt.asObj();
        };
    }

    const eval_env = try gc_mod.allocEnv(self.arena);
    // Eval's lexical environment holds the eval'd code's let/const/class. In
    // *sloppy* eval its top-level function/var declarations target the
    // surrounding variable scope (EvalDeclarationInstantiation) — `fn_body`
    // marks it as a function-top scope so those functions hoist var-scoped (to
    // the caller / realm global) and the Annex B B.3.3 analysis runs. *Strict*
    // eval has its OWN variable environment (declarations stay local), so it is
    // a real variable scope (`fn_scope`).
    self.initEnvironment(eval_env, self.env, parser.strict);
    eval_env.fn_body = !parser.strict;
    self.env = eval_env;
    // Non-strict eval's var/function declarations target the surrounding
    // variable scope and, when that is the global object, must be deletable.
    // (Strict eval keeps them local in `eval_env`, so the flag is moot there.)
    const saved_deletable = self.eval_decl_deletable;
    self.eval_decl_deletable = !parser.strict;
    // The eval'd code is strict if the call is a direct eval in strict code OR the
    // code's own Directive Prologue has a Use Strict directive (`parser.strict`
    // captured both). Run the body under that strictness — e.g. `eval('"use
    // strict"; x = 1')` from sloppy code is a ReferenceError on the undeclared `x`.
    const saved_strict = self.strict;
    self.strict = parser.strict;
    defer {
        self.env = saved_env;
        self.this_value = saved_this;
        self.global_object = saved_glob;
        self.eval_decl_deletable = saved_deletable;
        self.strict = saved_strict;
    }

    // Eval creates a fresh lexical environment for let/const/class declarations,
    // while var/function declarations target the surrounding variable
    // environment (the caller for direct eval, the realm global for indirect).
    if (prog.* == .program) {
        // EvalDeclarationInstantiation: reject undeclarable global var/function
        // bindings and var/lexical conflicts up front, before any declaration runs.
        try self.checkGlobalEvalDeclarable(prog.program);
        if (!parser.strict) try self.checkEvalLexicalConflicts(prog.program);
        try self.hoistVarNames(prog.program);
    }
    return self.eval(prog);
}

fn promiseRejectAbrupt(self: *Interpreter, err: value.HostError) value.HostError!Value {
    if (err != error.Throw) return err;
    const reason = self.exception;
    self.exception = Value.undef();
    return promiseRejectValue(self, reason);
}

fn asyncFromSyncUnderlying(self: *Interpreter, this: Value) value.HostError!Value {
    if (!this.isObject()) return self.throwError("TypeError", "Async-from-Sync iterator method called on a non-object");
    return this.asObj().getOwn("__sync") orelse self.throwError("TypeError", "Async-from-Sync iterator missing underlying iterator");
}

const AsyncFromSyncData = struct {
    sync_iter: Value,
    promise: *promise.Promise,
    done: bool,
    close_on_rejection: bool,
};

fn asyncFromSyncContinuation(self: *Interpreter, sync_iter: Value, result: Value, close_on_rejection: bool) value.HostError!Value {
    if (!result.isObject())
        return promiseRejectValue(self, try self.makeError("TypeError", "iterator result is not an object"));
    const done = (self.getProperty(result, "done") catch |err| return promiseRejectAbrupt(self, err)).toBoolean();
    const value_v = self.getProperty(result, "value") catch |err| return promiseRejectAbrupt(self, err);
    const out = try promise.newPromise(self);
    const out_p: *promise.Promise = @ptrCast(@alignCast(out.promise.?));
    const wrapped = promiseResolveValue(self, value_v) catch |err| {
        if (err != error.Throw) return err;
        const reason = self.exception;
        if (close_on_rejection and !done) {
            self.iteratorCloseKeepingThrow(sync_iter);
        }
        self.exception = Value.undef();
        try promise.reject(self, out_p, reason);
        return Value.obj(out);
    };
    const data = try self.arena.create(AsyncFromSyncData);
    data.* = .{ .sync_iter = sync_iter, .promise = out_p, .done = done, .close_on_rejection = close_on_rejection };
    const onf = try gc_mod.allocObj(self.arena);
    onf.* = .{ .native = asyncFromSyncFulfillFn, .private_data = @ptrCast(data) };
    try installNativeProps(self.arena, self.root_shape, onf, "", 1);
    const onr = try gc_mod.allocObj(self.arena);
    onr.* = .{ .native = asyncFromSyncRejectFn, .private_data = @ptrCast(data) };
    try installNativeProps(self.arena, self.root_shape, onr, "", 1);
    _ = try promise.then(self, promise.promiseOf(wrapped).?, Value.obj(onf), Value.obj(onr));
    return Value.obj(out);
}

fn asyncFromSyncFulfillFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const data: *AsyncFromSyncData = @ptrCast(@alignCast(self.active_native.?.private_data.?));
    const value_v = if (args.len > 0) args[0] else Value.undef();
    try promise.resolve(self, data.promise, try self.iterResultObj(value_v, data.done));
    return Value.undef();
}

fn asyncFromSyncRejectFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const data: *AsyncFromSyncData = @ptrCast(@alignCast(self.active_native.?.private_data.?));
    const reason = if (args.len > 0) args[0] else Value.undef();
    if (data.close_on_rejection and !data.done) self.iteratorCloseKeepingThrow(data.sync_iter);
    try promise.reject(self, data.promise, reason);
    return Value.undef();
}

fn asyncFromSyncNextFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const sync_iter = try asyncFromSyncUnderlying(self, this);
    const next = this.asObj().getOwn("__next") orelse return promiseRejectValue(self, try self.makeError("TypeError", "Async-from-Sync iterator missing next method"));
    const call_args = if (args.len > 0) args[0..1] else args[0..0];
    const result = self.callValueWithThis(next, call_args, sync_iter) catch |err| return promiseRejectAbrupt(self, err);
    return asyncFromSyncContinuation(self, sync_iter, result, true);
}

fn asyncFromSyncReturnFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const sync_iter = try asyncFromSyncUnderlying(self, this);
    const sent = if (args.len > 0) args[0] else Value.undef();
    const ret = self.getProperty(sync_iter, "return") catch |err| return promiseRejectAbrupt(self, err);
    if (ret.isUndefined() or ret.isNull()) {
        const resolved = self.awaitValue(sent) catch |err| return promiseRejectAbrupt(self, err);
        return promiseResolveValue(self, try self.iterResultObj(resolved, true));
    }
    if (!ret.isCallable()) return promiseRejectValue(self, try self.makeError("TypeError", "iterator return is not callable"));
    const call_args = if (args.len > 0) args[0..1] else args[0..0];
    const result = self.callValueWithThis(ret, call_args, sync_iter) catch |err| return promiseRejectAbrupt(self, err);
    return asyncFromSyncContinuation(self, sync_iter, result, false);
}

fn asyncFromSyncThrowFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const sync_iter = try asyncFromSyncUnderlying(self, this);
    const throw_m = self.getProperty(sync_iter, "throw") catch |err| return promiseRejectAbrupt(self, err);
    if (throw_m.isUndefined() or throw_m.isNull()) {
        self.iteratorClose(sync_iter) catch |err| return promiseRejectAbrupt(self, err);
        return promiseRejectValue(self, try self.makeError("TypeError", "iterator throw is not callable"));
    }
    if (!throw_m.isCallable()) return promiseRejectValue(self, try self.makeError("TypeError", "iterator throw is not callable"));
    const call_args = if (args.len > 0) args[0..1] else args[0..0];
    const result = self.callValueWithThis(throw_m, call_args, sync_iter) catch |err| return promiseRejectAbrupt(self, err);
    return asyncFromSyncContinuation(self, sync_iter, result, true);
}

// --- Promise built-ins ----------------------------------------------------

/// `new Promise(executor)` — create a pending promise and synchronously call
/// `executor(resolve, reject)`. The resolve/reject closures carry the promise
/// in their `private_data`; an executor that throws rejects the promise.
fn promiseConstructorFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    // `Promise(...)` without `new` is a TypeError (only [[Construct]] sets new.target).
    if (self.new_target.isUndefined()) return self.throwError("TypeError", "Promise constructor cannot be invoked without 'new'");
    const executor = if (args.len > 0) args[0] else Value.undef();
    if (!executor.isCallable()) return self.throwError("TypeError", "Promise resolver is not a function");
    const pobj = try promise.newPromise(self);
    if (self.new_target.isObject()) pobj.setProtoAtomic(try self.ctorRealmIntrinsicProto(self.new_target.asObj(), "Promise"));
    const pp = pobj.promise.?;
    const resolving = try self.arena.create(promise.Resolving);
    resolving.* = .{ .promise = @ptrCast(@alignCast(pp)) };
    const res_fn = try gc_mod.allocObj(self.arena);
    res_fn.* = .{ .native = promiseResolveClosure, .private_data = @ptrCast(resolving) };
    const rej_fn = try gc_mod.allocObj(self.arena);
    rej_fn.* = .{ .native = promiseRejectClosure, .private_data = @ptrCast(resolving) };
    // The resolve/reject functions are anonymous, length 1 (spec).
    try installNativeProps(self.arena, self.root_shape, res_fn, "", 1);
    try installNativeProps(self.arena, self.root_shape, rej_fn, "", 1);
    if (self.callValueWithThis(executor, &.{ Value.obj(res_fn), Value.obj(rej_fn) }, Value.undef())) |_| {} else |err| {
        if (err == error.Throw) {
            const reason = self.exception;
            self.exception = Value.undef();
            if (!resolving.already) {
                resolving.already = true;
                try promise.reject(self, resolving.promise, reason);
            }
        } else return err;
    }
    return Value.obj(pobj);
}

fn promiseResolveClosure(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const fnobj = self.active_native orelse return Value.undef();
    const resolving: *promise.Resolving = @ptrCast(@alignCast(fnobj.private_data.?));
    if (resolving.already) return Value.undef();
    resolving.already = true;
    try promise.resolve(self, resolving.promise, if (args.len > 0) args[0] else Value.undef());
    return Value.undef();
}

fn promiseRejectClosure(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const fnobj = self.active_native orelse return Value.undef();
    const resolving: *promise.Resolving = @ptrCast(@alignCast(fnobj.private_data.?));
    if (resolving.already) return Value.undef();
    resolving.already = true;
    try promise.reject(self, resolving.promise, if (args.len > 0) args[0] else Value.undef());
    return Value.undef();
}

/// `Promise.prototype.then` — the result promise is built from
/// `SpeciesConstructor(this, %Promise%)`, so a subclass's `.then` yields a
/// subclass instance. The fast path (intrinsic species) skips the capability.
fn promiseThenImpl(self: *Interpreter, this: Value, on_f: Value, on_r: Value) value.HostError!Value {
    const p = promise.promiseOf(this) orelse return self.throwError("TypeError", "Promise.prototype.then called on a non-Promise");
    const default_ctor = self.env.get("Promise") orelse Value.undef();
    const c = try self.speciesConstructor(this, default_ctor);
    // Intrinsic Promise → cheap native capability; a subclass/custom → its own.
    if (c.isObject() and default_ctor.isObject() and c.asObj() == default_ctor.asObj())
        return promise.then(self, p, on_f, on_r);
    const cap = try newPromiseCapability(self, c);
    try promise.performThen(self, p, on_f, on_r, cap.resolve, cap.reject);
    return cap.promise;
}

/// A getter (or method) that simply returns its receiver — `get [@@species]() {
/// return this; }`.
fn returnThisFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = ctx;
    _ = args;
    return this;
}

fn promiseThenFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    return promiseThenImpl(self, this, if (args.len > 0) args[0] else Value.undef(), if (args.len > 1) args[1] else Value.undef());
}

fn promiseCatchFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    // `catch(f)` is `? Invoke(this, "then", «undefined, f»)` — a generic call to
    // this value's own `then`, so it works on any thenable, not just a Promise.
    return self.callMethod(this, "then", &.{ Value.undef(), if (args.len > 0) args[0] else Value.undef() });
}

/// Captured state for a `finally` reaction (`then`/`catch` side) and its inner
/// value-restoring thunk.
const FinallyData = struct { on_finally: Value, ctor: Value = Value.undef(), captured: Value = Value.undef(), is_catch: bool };

/// `thenFinally`/`catchFinally`: run `onFinally()`, then — once its result
/// settles — re-yield the original value (or re-throw the original reason),
/// so `finally` is transparent to the settled completion.
fn finallyReactionFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const fnobj = self.active_native orelse return Value.undef();
    const d: *FinallyData = @ptrCast(@alignCast(fnobj.private_data.?));
    const incoming = if (args.len > 0) args[0] else Value.undef();
    const result = try self.callValue(d.on_finally, &.{}); // may throw → propagates (rejects)
    const wrapped = try promiseResolveForConstructor(self, d.ctor, result);
    // After onFinally's result settles, a thunk that ignores its argument and
    // reinstates the original completion.
    const thunk = try gc_mod.allocObj(self.arena);
    const td = try self.arena.create(FinallyData);
    td.* = .{ .on_finally = Value.undef(), .captured = incoming, .is_catch = d.is_catch };
    thunk.* = .{ .native = finallyThunkFn, .private_data = @ptrCast(td) };
    try installNativeProps(self.arena, self.root_shape, thunk, "", 0);
    return self.callMethod(wrapped, "then", &.{Value.obj(thunk)});
}

fn finallyThunkFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    _ = args;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const fnobj = self.active_native orelse return Value.undef();
    const d: *FinallyData = @ptrCast(@alignCast(fnobj.private_data.?));
    if (d.is_catch) {
        self.exception = d.captured; // re-throw the original rejection reason
        return error.Throw;
    }
    return d.captured; // re-yield the original fulfillment value
}

fn promiseFinallyFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    // `finally` requires an Object `this` (not necessarily a Promise) and ends in
    // `Invoke(this, "then", …)`, so it composes over any thenable.
    if (!this.isObject()) return self.throwError("TypeError", "Promise.prototype.finally called on a non-object");
    const default_ctor = self.env.get("Promise") orelse Value.undef();
    const c = try self.speciesConstructor(this, default_ctor);
    const cb = if (args.len > 0) args[0] else Value.undef();
    // A non-callable `onFinally` is used directly for both reactions (spec).
    if (!cb.isCallable()) return self.callMethod(this, "then", &.{ cb, cb });
    const onf = try gc_mod.allocObj(self.arena);
    const ond = try self.arena.create(FinallyData);
    ond.* = .{ .on_finally = cb, .ctor = c, .is_catch = false };
    onf.* = .{ .native = finallyReactionFn, .private_data = @ptrCast(ond) };
    try installNativeProps(self.arena, self.root_shape, onf, "", 1);
    const onr = try gc_mod.allocObj(self.arena);
    const ord = try self.arena.create(FinallyData);
    ord.* = .{ .on_finally = cb, .ctor = c, .is_catch = true };
    onr.* = .{ .native = finallyReactionFn, .private_data = @ptrCast(ord) };
    try installNativeProps(self.arena, self.root_shape, onr, "", 1);
    return self.callMethod(this, "then", &.{ Value.obj(onf), Value.obj(onr) });
}

fn promiseResolveForConstructor(self: *Interpreter, c: Value, v: Value) EvalError!Value {
    if (promise.promiseOf(v) != null) {
        const ctor = try self.getProperty(v, "constructor");
        if (ctor.isObject() and c.isObject() and ctor.asObj() == c.asObj()) return v;
    }
    const cap = try newPromiseCapability(self, c);
    _ = try self.callValue(cap.resolve, &.{v});
    return cap.promise;
}

/// Internal `PromiseResolve(%Promise%, v)`: `v` itself only when it is a native
/// promise whose observable `constructor` is the intrinsic Promise, else a fresh
/// native promise fulfilled with `v` (adopting a thenable).
pub fn promiseResolveValue(self: *Interpreter, v: Value) EvalError!Value {
    if (promise.promiseOf(v) != null) {
        if (self.env.get("Promise")) |pc| if (pc.isObject()) {
            const ctor = try self.getProperty(v, "constructor");
            if (ctor.isObject() and ctor.asObj() == pc.asObj()) return v;
        };
    }
    const pobj = try promise.newPromise(self);
    try promise.resolve(self, @ptrCast(@alignCast(pobj.promise.?)), v);
    return Value.obj(pobj);
}

fn promiseResolveAfterTick(self: *Interpreter, v: Value) EvalError!Value {
    const result = try promise.newPromise(self);
    const rp: *promise.Promise = @ptrCast(@alignCast(result.promise.?));
    const tick = try promise.newPromise(self);
    const tp: *promise.Promise = @ptrCast(@alignCast(tick.promise.?));
    const nr = try promise.nativeResolveReject(self, rp);
    try promise.performThen(self, tp, Value.undef(), Value.undef(), nr.resolve, nr.reject);
    try promise.resolve(self, tp, v);
    return Value.obj(result);
}

/// A fresh promise already rejected with `reason`.
fn promiseRejectValue(self: *Interpreter, reason: Value) EvalError!Value {
    const pobj = try promise.newPromise(self);
    try promise.reject(self, @ptrCast(@alignCast(pobj.promise.?)), reason);
    return Value.obj(pobj);
}

/// `Promise.resolve(v)` — uses `this` as the constructor `C`: returns `v`
/// unchanged when it is a promise whose `constructor` is `C`, otherwise builds
/// `C`'s capability and resolves it with `v` (so a subclass's `resolve` yields a
/// subclass instance).
fn promiseResolveStaticFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (!this.isObject() or this.asObj().is_symbol or this.asObj().is_bigint)
        return self.throwError("TypeError", "Promise.resolve called on a non-object");
    const v = if (args.len > 0) args[0] else Value.undef();
    return promiseResolveForConstructor(self, this, v);
}

/// `Promise.reject(e)` — builds `this`'s capability and rejects it with `e`.
fn promiseRejectStaticFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const cap = try newPromiseCapability(self, this);
    _ = try self.callValue(cap.reject, &.{if (args.len > 0) args[0] else Value.undef()});
    return cap.promise;
}

/// `Object.groupBy(items, callback)` — group `items` into a null-prototype
/// object keyed by `callback(value, index)` (coerced to a property key), each
/// bucket an array of the values in iteration order.
fn objectGroupByFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const cb = if (args.len > 1) args[1] else Value.undef();
    if (!cb.isCallable()) return self.throwError("TypeError", "Object.groupBy: callback is not a function");
    const elems = try collectIterable(self, if (args.len > 0) args[0] else Value.undef());
    const obj = (try self.newObject()).asObj();
    obj.setProtoAtomic(null); // groupBy result has a null prototype
    for (elems, 0..) |el, i| {
        const kv = try self.callValue(cb, &.{ el, Value.num(@floatFromInt(i)) });
        const key = try self.keyOf(kv);
        if (obj.getOwn(key)) |bucket| {
            try bucket.asObj().elements.append(bucket.asObj().elementsAllocator(self.arena), el);
        } else {
            const arr = try self.newArray();
            try arr.asObj().elements.append(arr.asObj().elementsAllocator(self.arena), el);
            try self.setProp(obj, key, arr);
        }
    }
    return Value.obj(obj);
}

/// `Map.groupBy(items, callback)` — like Object.groupBy but the result is a Map
/// keyed by the (SameValueZero) callback result, each value an array.
fn mapGroupByFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const cb = if (args.len > 1) args[1] else Value.undef();
    if (!cb.isCallable()) return self.throwError("TypeError", "Map.groupBy: callback is not a function");
    const elems = try collectIterable(self, if (args.len > 0) args[0] else Value.undef());
    const map = (try self.makeMap(Value.undef())).asObj();
    for (elems, 0..) |el, i| {
        const key = try self.callValue(cb, &.{ el, Value.num(@floatFromInt(i)) });
        if ((try self.mapMethod(map, "has", &.{key})).?.asBool()) {
            const bucket = (try self.mapMethod(map, "get", &.{key})).?;
            try bucket.asObj().elements.append(bucket.asObj().elementsAllocator(self.arena), el);
        } else {
            const arr = try self.newArray();
            try arr.asObj().elements.append(arr.asObj().elementsAllocator(self.arena), el);
            _ = try self.mapMethod(map, "set", &.{ key, arr });
        }
    }
    return Value.obj(map);
}

/// Collect an iterable's elements into a slice: arrays use their dense store
/// directly; anything else is driven through the iterator protocol.
fn collectIterable(self: *Interpreter, v: Value) EvalError![]Value {
    if (v.isObject() and v.asObj().is_array) return v.asObj().elements.items;
    const iter = try self.iteratorOf(v);
    var list: std.ArrayListUnmanaged(Value) = .empty;
    while (true) {
        const r = try self.callMethod(iter, "next", &.{});
        if (!r.isObject()) return self.throwError("TypeError", "iterator.next() did not return an object");
        if ((try self.getProperty(r, "done")).toBoolean()) break;
        try list.append(self.arena, try self.getProperty(r, "value"));
    }
    return list.items;
}

/// One element's settle reaction for `Promise.all`/`allSettled`/`any`: record
/// the outcome at its index and, when the last input settles, settle the
/// combined promise.
fn combineElemFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const fnobj = self.active_native orelse return Value.undef();
    const e: *promise.Elem = @ptrCast(@alignCast(fnobj.private_data.?));
    // [[AlreadyCalled]]: a resolve/reject element function settles its element at
    // most once; subsequent calls are no-ops.
    if (e.already.*) return Value.undef();
    e.already.* = true;
    const c = e.combine;
    const val = if (args.len > 0) args[0] else Value.undef();
    switch (c.kind) {
        .all => {
            if (e.is_reject) {
                _ = try self.callValue(c.reject, &.{val}); // first rejection wins
                return Value.undef();
            }
            c.values.elements.items[e.index] = val;
        },
        .all_settled => {
            const o = (try self.newObject()).asObj();
            if (e.is_reject) {
                try self.setProp(o, "status", Value.str("rejected"));
                try self.setProp(o, "reason", val);
            } else {
                try self.setProp(o, "status", Value.str("fulfilled"));
                try self.setProp(o, "value", val);
            }
            c.values.elements.items[e.index] = Value.obj(o);
        },
        .all_keyed => {
            if (e.is_reject) {
                _ = try self.callValue(c.reject, &.{val}); // first rejection wins
                return Value.undef();
            }
            c.values.elements.items[e.index] = val;
        },
        .all_settled_keyed => {
            const o = (try self.newObject()).asObj();
            if (e.is_reject) {
                try self.setProp(o, "status", Value.str("rejected"));
                try self.setProp(o, "reason", val);
            } else {
                try self.setProp(o, "status", Value.str("fulfilled"));
                try self.setProp(o, "value", val);
            }
            c.values.elements.items[e.index] = Value.obj(o);
        },
        .any => {
            if (!e.is_reject) {
                _ = try self.callValue(c.resolve, &.{val}); // first fulfillment wins
                return Value.undef();
            }
            c.values.elements.items[e.index] = val; // collect the error
        },
    }
    c.remaining -= 1;
    if (c.remaining == 0) try combineSettle(self, c);
    return Value.undef();
}

/// Settle a combinator once its `remaining` count reaches zero: `all`/
/// `allSettled` fulfill with the values array; `any` rejects with an
/// AggregateError carrying the collected rejection reasons.
fn combineSettle(self: *Interpreter, c: *promise.Combine) value.HostError!void {
    if (c.kind == .any) {
        const agg = try self.makeErrorWithArgs("AggregateError", &.{Value.obj(c.values)});
        _ = try self.callValue(c.reject, &.{agg});
    } else if (c.keys) |keys| {
        const result = (try self.newObject()).asObj();
        result.setProtoAtomic(null);
        for (keys, 0..) |key, i| {
            try self.setProp(result, key, c.values.elements.items[i]);
        }
        try callCapabilityResolve(self, c, Value.obj(result));
    } else try callCapabilityResolve(self, c, Value.obj(c.values));
}

fn callCapabilityResolve(self: *Interpreter, c: *promise.Combine, value_arg: Value) value.HostError!void {
    if (self.callValue(c.resolve, &.{value_arg})) |_| return else |err| {
        if (err != error.Throw) return err;
        const reason = self.exception;
        self.exception = Value.undef();
        _ = try self.callValue(c.reject, &.{reason});
    }
}

inline fn tracePrivateValue(v: anytype, val: Value) void {
    if (val.isObject()) v.mark(val.asObj());
}

/// Trace engine-owned `private_data` carried by native closures allocated in
/// this file. The Object tracer already marks the closure object itself; this
/// hook keeps type-erased side records from hiding GC-managed Values/Objects.
pub fn traceNativePrivateData(o: *value.Object, v: anytype) void {
    const nf = o.native orelse return;
    const pd = o.private_data orelse return;

    if (nf == promiseResolveClosure or nf == promiseRejectClosure) {
        const data: *promise.Resolving = @ptrCast(@alignCast(pd));
        v.mark(data.promise);
        return;
    }

    if (nf == finallyReactionFn or nf == finallyThunkFn) {
        const data: *FinallyData = @ptrCast(@alignCast(pd));
        tracePrivateValue(v, data.on_finally);
        tracePrivateValue(v, data.captured);
        return;
    }

    if (nf == asyncFromSyncFulfillFn or nf == asyncFromSyncRejectFn) {
        const data: *AsyncFromSyncData = @ptrCast(@alignCast(pd));
        tracePrivateValue(v, data.sync_iter);
        v.mark(data.promise);
        return;
    }

    if (nf == combineElemFn) {
        const elem: *promise.Elem = @ptrCast(@alignCast(pd));
        const c = elem.combine;
        tracePrivateValue(v, c.resolve);
        tracePrivateValue(v, c.reject);
        v.mark(c.values);
        return;
    }

    if (nf == capabilityExecutorFn) {
        const cap: *CapCapture = @ptrCast(@alignCast(pd));
        tracePrivateValue(v, cap.resolve);
        tracePrivateValue(v, cap.reject);
    }
}

/// IteratorStep + IteratorValue: advance `iter`, returning the next value or
/// null when exhausted. A protocol violation (non-object result) throws.
fn iterStep(self: *Interpreter, iter: Value) EvalError!?Value {
    const r = try self.callMethod(iter, "next", &.{});
    if (!r.isObject()) return self.throwError("TypeError", "iterator.next() did not return an object");
    if ((try self.getProperty(r, "done")).toBoolean()) return null;
    return try self.getProperty(r, "value");
}

/// Shared setup for `Promise.all`/`allSettled`/`any`: build the combined promise
/// and wire a per-element reaction onto each input (coerced via the source's
/// `then`). An empty input settles immediately.
/// A `PromiseCapability` record: the constructed promise plus the resolve/reject
/// functions its executor handed out. Settling the combined promise goes through
/// these functions, so a subclass constructor's promise is the actual result.
const Capability = struct { promise: Value, resolve: Value, reject: Value };

/// Captures the (resolve, reject) pair the executor is invoked with.
const CapCapture = struct { resolve: Value = Value.undef(), reject: Value = Value.undef() };

fn capabilityExecutorFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const fnobj = self.active_native orelse return Value.undef();
    const cap: *CapCapture = @ptrCast(@alignCast(fnobj.private_data.?));
    // GetCapabilitiesExecutor: the executor may be invoked only once — if
    // [[Resolve]] or [[Reject]] is already set, a second call throws.
    if (!cap.resolve.isUndefined() or !cap.reject.isUndefined())
        return self.throwError("TypeError", "Promise capability executor already invoked");
    cap.resolve = if (args.len > 0) args[0] else Value.undef();
    cap.reject = if (args.len > 1) args[1] else Value.undef();
    return Value.undef();
}

/// `NewPromiseCapability(C)`: construct `new C(executor)`, capturing the resolve
/// and reject functions. Both must be callable. Works for the native `Promise`
/// and for any subclass/custom constructor that forwards to a Promise executor.
/// `Promise.withResolvers()` — `{ promise, resolve, reject }` built from a fresh
/// capability of `this` constructor (so a subclass's promise/functions are used).
fn promiseWithResolversFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = args;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const cap = try newPromiseCapability(self, this);
    const obj = (try self.newObject()).asObj();
    try self.setProp(obj, "promise", cap.promise);
    try self.setProp(obj, "resolve", cap.resolve);
    try self.setProp(obj, "reject", cap.reject);
    return Value.obj(obj);
}

/// `Promise.try(callback, ...args)` — run `callback(...args)` now, settling a
/// fresh capability of `this` constructor with its result or thrown reason.
fn promiseTryFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const cap = try newPromiseCapability(self, this);
    const cb = if (args.len > 0) args[0] else Value.undef();
    const extra = if (args.len > 1) args[1..] else &[_]Value{};
    const result = self.callValue(cb, extra) catch |e| {
        if (e != error.Throw) return e;
        _ = try self.callValue(cap.reject, &.{self.exception});
        return cap.promise;
    };
    _ = try self.callValue(cap.resolve, &.{result});
    return cap.promise;
}

fn newPromiseCapability(self: *Interpreter, c: Value) EvalError!Capability {
    if (!isConstructorValue(c)) return self.throwError("TypeError", "NewPromiseCapability called on a non-constructor");
    const capture = try self.arena.create(CapCapture);
    capture.* = .{};
    const executor = try gc_mod.allocObj(self.arena);
    executor.* = .{ .native = capabilityExecutorFn, .private_data = @ptrCast(capture) };
    try installNativeProps(self.arena, self.root_shape, executor, "", 2);
    const p = try self.construct(c, &.{Value.obj(executor)});
    if (!capture.resolve.isCallable() or !capture.reject.isCallable())
        return self.throwError("TypeError", "Promise capability resolve/reject is not callable");
    return .{ .promise = p, .resolve = capture.resolve, .reject = capture.reject };
}

/// `GetPromiseResolve(C)` — `Get(C, "resolve")`, which must be callable. The
/// combinators call this once per element (observably, so a replaced
/// `Promise.resolve` is honored), passing `C` as the receiver.
fn getPromiseResolve(self: *Interpreter, c: Value) EvalError!Value {
    const r = try self.getProperty(c, "resolve");
    if (!r.isCallable()) return self.throwError("TypeError", "Promise resolve is not a function");
    return r;
}

/// Resolve one combinator element through the constructor's `resolve` (spec:
/// `Call(promiseResolve, C, « nextValue »)`), yielding a promise to attach to.
fn elementPromise(self: *Interpreter, promise_resolve: Value, c: Value, el: Value) EvalError!*promise.Promise {
    const p = try self.callValueWithThis(promise_resolve, &.{el}, c);
    if (promise.promiseOf(p)) |pp| return pp;
    // A non-promise `resolve` result is adopted into a fresh native promise.
    const wrapped = try promiseResolveValue(self, p);
    return promise.promiseOf(wrapped).?;
}

fn setupCombinator(self: *Interpreter, this: Value, iterable: Value, kind: @TypeOf(@as(promise.Combine, undefined).kind)) value.HostError!Value {
    // NewPromiseCapability(C): C (the `this` value) must be a constructor. This
    // throws synchronously (it is before the IfAbruptRejectPromise region).
    const cap = try newPromiseCapability(self, this);
    // GetPromiseResolve + GetIterator are abrupt-rejected: a failure rejects the
    // returned promise (IfAbruptRejectPromise) rather than throwing out of the call.
    const promise_resolve = getPromiseResolve(self, this) catch |err| return rejectAbrupt(self, cap, err);
    const iter = self.iteratorOf(iterable) catch |err| return rejectAbrupt(self, cap, err);

    const values = (try self.newArray()).asObj();
    const combine = try self.arena.create(promise.Combine);
    // `remaining` starts at 1 for the loop itself, so a synchronously-settling
    // input can't fire the final settle before the iteration completes; it is
    // decremented once the iterator is exhausted (PerformPromiseAll pattern).
    combine.* = .{ .resolve = cap.resolve, .reject = cap.reject, .values = values, .remaining = 1, .kind = kind };
    var index: usize = 0;
    while (true) {
        // IteratorStep/IteratorValue errors leave the iterator done → reject
        // without closing it.
        const maybe = iterStep(self, iter) catch |err| return rejectAbrupt(self, cap, err);
        const el = maybe orelse break;
        try values.elements.append(values.elementsAllocator(self.arena), Value.undef());
        combine.remaining += 1;
        // `nextPromise = Call(promiseResolve, C, «el»)` — an abrupt completion
        // here closes the (still-open) iterator before rejecting.
        const next = self.callValueWithThis(promise_resolve, &.{el}, this) catch |err| return closeAndReject(self, cap, iter, err);
        // One [[AlreadyCalled]] record shared by this element's resolve & reject
        // functions — the element settles at most once.
        const already = try self.arena.create(bool);
        already.* = false;
        const f = try gc_mod.allocObj(self.arena);
        const fe = try self.arena.create(promise.Elem);
        fe.* = .{ .combine = combine, .index = index, .is_reject = false, .already = already };
        f.* = .{ .native = combineElemFn, .private_data = @ptrCast(fe) };
        try installNativeProps(self.arena, self.root_shape, f, "", 1); // anonymous, length 1
        const r = try gc_mod.allocObj(self.arena);
        const re = try self.arena.create(promise.Elem);
        re.* = .{ .combine = combine, .index = index, .is_reject = true, .already = already };
        r.* = .{ .native = combineElemFn, .private_data = @ptrCast(re) };
        try installNativeProps(self.arena, self.root_shape, r, "", 1);
        // Invoke(nextPromise, "then", «resolveElement, rejectElement»): for a
        // native promise this is the native `then`; for a thenable it runs its
        // own `then` (which may settle synchronously).
        const fulfill_element = if (kind == .any) cap.resolve else Value.obj(f);
        const reject_element = if (kind == .all) cap.reject else Value.obj(r);
        _ = self.callMethod(next, "then", &.{ fulfill_element, reject_element }) catch |err| return closeAndReject(self, cap, iter, err);
        index += 1;
    }
    combine.remaining -= 1; // the loop's own count
    if (combine.remaining == 0) try combineSettle(self, combine);
    return cap.promise;
}

fn addCombineElement(
    self: *Interpreter,
    cap: Capability,
    combine: *promise.Combine,
    promise_resolve: Value,
    c: Value,
    next_value: Value,
    index: usize,
) value.HostError!bool {
    try combine.values.appendElement(self.arena, Value.undef());
    combine.remaining += 1;
    const next = self.callValueWithThis(promise_resolve, &.{next_value}, c) catch |err| {
        _ = try rejectAbrupt(self, cap, err);
        return false;
    };
    const already = try self.arena.create(bool);
    already.* = false;
    const f = try gc_mod.allocObj(self.arena);
    const fe = try self.arena.create(promise.Elem);
    fe.* = .{ .combine = combine, .index = index, .is_reject = false, .already = already };
    f.* = .{ .native = combineElemFn, .private_data = @ptrCast(fe) };
    try installNativeProps(self.arena, self.root_shape, f, "", 1);
    const r = try gc_mod.allocObj(self.arena);
    const re = try self.arena.create(promise.Elem);
    re.* = .{ .combine = combine, .index = index, .is_reject = true, .already = already };
    r.* = .{ .native = combineElemFn, .private_data = @ptrCast(re) };
    try installNativeProps(self.arena, self.root_shape, r, "", 1);
    const reject_element = if (combine.kind == .all_keyed) cap.reject else Value.obj(r);
    _ = self.callMethod(next, "then", &.{ Value.obj(f), reject_element }) catch |err| {
        _ = try rejectAbrupt(self, cap, err);
        return false;
    };
    return true;
}

fn setupKeyedCombinator(self: *Interpreter, this: Value, promises: Value, kind: @TypeOf(@as(promise.Combine, undefined).kind)) value.HostError!Value {
    const cap = try newPromiseCapability(self, this);
    const promise_resolve = getPromiseResolve(self, this) catch |err| return rejectAbrupt(self, cap, err);
    if (!promises.isObject() or promises.asObj().is_symbol or promises.asObj().is_bigint) {
        _ = try self.callValue(cap.reject, &.{try self.makeError("TypeError", "Promise keyed combinator argument is not an object")});
        return cap.promise;
    }
    const source = promises.asObj();
    const all_keys = self.objectOwnKeysList(source) catch |err| return rejectAbrupt(self, cap, err);
    var kept_keys: std.ArrayListUnmanaged([]const u8) = .empty;
    const values = (try self.newArray()).asObj();
    const combine = try self.arena.create(promise.Combine);
    combine.* = .{ .resolve = cap.resolve, .reject = cap.reject, .values = values, .remaining = 1, .kind = kind };
    for (all_keys) |key| {
        const desc = builtins.objectGetOwnPropertyDescriptor(@ptrCast(self), Value.undef(), &.{ Value.obj(source), self.keyToValue(key) }) catch |err| return rejectAbrupt(self, cap, err);
        if (desc.isUndefined()) continue;
        const enumerable = self.getProperty(desc, "enumerable") catch |err| return rejectAbrupt(self, cap, err);
        if (!enumerable.toBoolean()) continue;
        try kept_keys.append(self.arena, key);
        const next_value = self.getProperty(promises, key) catch |err| return rejectAbrupt(self, cap, err);
        if (!try addCombineElement(self, cap, combine, promise_resolve, this, next_value, kept_keys.items.len - 1))
            return cap.promise;
    }
    combine.keys = kept_keys.items;
    combine.remaining -= 1;
    if (combine.remaining == 0) try combineSettle(self, combine);
    return cap.promise;
}

/// IfAbruptRejectPromise: a thrown completion rejects the capability and returns
/// its promise; any non-throw (host) error propagates unchanged.
fn rejectAbrupt(self: *Interpreter, cap: Capability, err: value.HostError) value.HostError!Value {
    if (err != error.Throw) return err;
    const reason = self.exception;
    self.exception = Value.undef();
    _ = try self.callValue(cap.reject, &.{reason});
    return cap.promise;
}

/// Abrupt completion mid-iteration: close the still-open iterator (its own
/// errors are swallowed — the original completion wins) and reject the result.
fn closeAndReject(self: *Interpreter, cap: Capability, iter: Value, err: value.HostError) value.HostError!Value {
    if (err != error.Throw) return err;
    const reason = self.exception;
    self.exception = Value.undef();
    self.iteratorClose(iter) catch {};
    self.exception = Value.undef();
    _ = try self.callValue(cap.reject, &.{reason});
    return cap.promise;
}

fn promiseAllFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    return setupCombinator(self, this, if (args.len > 0) args[0] else Value.undef(), .all);
}

fn promiseAllSettledFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    return setupCombinator(self, this, if (args.len > 0) args[0] else Value.undef(), .all_settled);
}

fn promiseAllKeyedFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    return setupKeyedCombinator(self, this, if (args.len > 0) args[0] else Value.undef(), .all_keyed);
}

fn promiseAllSettledKeyedFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    return setupKeyedCombinator(self, this, if (args.len > 0) args[0] else Value.undef(), .all_settled_keyed);
}

fn promiseAnyFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    return setupCombinator(self, this, if (args.len > 0) args[0] else Value.undef(), .any);
}

/// `Promise.race(iterable)` — settle with the first input to settle.
fn promiseRaceFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const cap = try newPromiseCapability(self, this);
    const promise_resolve = getPromiseResolve(self, this) catch |err| return rejectAbrupt(self, cap, err);
    const iter = self.iteratorOf(if (args.len > 0) args[0] else Value.undef()) catch |err| return rejectAbrupt(self, cap, err);
    while (true) {
        const maybe = iterStep(self, iter) catch |err| return rejectAbrupt(self, cap, err);
        const el = maybe orelse break;
        const next = self.callValueWithThis(promise_resolve, &.{el}, this) catch |err| return closeAndReject(self, cap, iter, err);
        // The capability's resolve/reject settle the result; the first input to
        // fire wins (later settlements are no-ops on an already-settled promise).
        _ = self.callMethod(next, "then", &.{ cap.resolve, cap.reject }) catch |err| return closeAndReject(self, cap, iter, err);
    }
    return cap.promise;
}

/// `print(...)` — appends a space-joined line to the Context's print buffer
/// (used by the test262 async harness's `$DONE`).
fn printFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const buf = self.print_buffer orelse return Value.undef();
    for (args, 0..) |a, i| {
        if (i != 0) try buf.append(self.arena, ' ');
        try buf.appendSlice(self.arena, try a.toString(self.arena));
    }
    try buf.append(self.arena, '\n');
    return Value.undef();
}

/// Test-shell compatibility: JSC's `noInline(fn)` affects tiering only. This
/// engine's tiering is not JIT-driven, so the observable behavior is identity.
fn noInlineFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = ctx;
    _ = this;
    return if (args.len > 0) args[0] else Value.undef();
}

/// Test-shell compatibility for PR-249 object-model/GC stress files. The M1
/// collector is precise and only sound at quiescent points, so in GC-enabled
/// contexts this requests collection for the next safe entry instead of tracing
/// while live JS values still sit in Zig locals/registers.
fn gcFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    _ = args;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (self.gc != null) {
        if (self.gc_requested) |requested| requested.* = true;
    }
    return Value.undef();
}

fn quitFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    _ = args;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    self.exception = Value.str("__zigjs_threads_quit__");
    return error.Throw;
}

fn vmUseThreadGILFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    _ = args;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    return Value.boolVal(self.gil != null and self.use_thread_gil);
}

fn vmIndexingModeFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = ctx;
    _ = this;
    const v = if (args.len > 0) args[0] else Value.undef();
    if (v.isObject() and v.asObj().is_array) {
        if (v.asObj().forced_array_storage) return Value.str("Array ArrayStorage");
        return Value.str("Array CopyOnWrite");
    }
    if (v.isObject()) {
        if (v.asObj().typed_array) |ta| return Value.str(ta.kind.ctorName());
    }
    return Value.str("Object");
}

fn vmEnsureArrayStorageFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const v = if (args.len > 0) args[0] else Value.undef();
    if (!v.isObject() or !v.asObj().is_array)
        return self.throwError("TypeError", "$vm.ensureArrayStorage expects an Array");
    v.asObj().forced_array_storage = true;
    return v;
}

fn installDollarVM(env: *Environment, rs: *Shape, object_proto: *value.Object) EvalError!void {
    const a = env.arena;
    const vm_obj = try gc_mod.allocObj(a);
    vm_obj.* = .{ .proto = object_proto };
    try setNative(a, rs, vm_obj, "gc", 0, gcFn);
    try setNative(a, rs, vm_obj, "edenGC", 0, gcFn);
    try setNative(a, rs, vm_obj, "ensureArrayStorage", 1, vmEnsureArrayStorageFn);
    try setNative(a, rs, vm_obj, "indexingMode", 1, vmIndexingModeFn);
    try setNative(a, rs, vm_obj, "noInline", 1, noInlineFn);
    try setNative(a, rs, vm_obj, "useThreadGIL", 0, vmUseThreadGILFn);
    try env.put("$vm", Value.obj(vm_obj));
}

/// Host timer used by test262's Atomics helper. This intentionally blocks the
/// current agent for the delay, services finite waitAsync tickets, then queues
/// the callback; the engine has no browser event loop yet.
fn setTimeoutFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const cb = if (args.len > 0) args[0] else Value.undef();
    if (!cb.isCallable()) return Value.num(0);
    const ms = if (args.len > 1) try self.toNumberV(args[1]) else 0;
    if (!std.math.isNan(ms) and ms > 0) agent.sleepMs(ms);
    if (self.async_waiters) |waiters| {
        if (waiters.items.len > 0) self.settleAsyncWaiters();
    }
    const tick = try promise.newPromise(self);
    const pp: *promise.Promise = @ptrCast(@alignCast(tick.promise.?));
    try promise.resolve(self, pp, Value.undef());
    _ = try promise.then(self, pp, cb, Value.undef());
    return Value.num(0);
}

/// Test-shell helper used by the PR-249 corpus. This is a microtask checkpoint
/// only: threaded run-loop tasks such as `Lock.asyncHold` grants are still
/// delivered by the evaluate tail / park pump, not by this hook.
fn drainMicrotasksFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    _ = args;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    try self.drainMicrotasks();
    return Value.undef();
}

/// Internal shell run-loop tick used by `conformance/threads_test.zig` while it
/// waits for `asyncTestPassed()` counters. Kept separate from drainMicrotasks()
/// because corpus tests assert that async lock grants do not settle merely by
/// draining the Promise queue inside the same script turn.
fn drainRunLoopFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    _ = args;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    var rounds: usize = 0;
    while (rounds < 8) : (rounds += 1) {
        self.lockMicrotasks();
        const before = if (self.microtasks) |q| q.pendingLen() else 0;
        self.unlockMicrotasks();
        jsthread.pumpTasks(self);
        jsthread.pollPropAsync(self);
        try self.drainMicrotasks();
        try self.drainFinalizationCleanupJobs();
        try self.drainMicrotasks();
        self.lockMicrotasks();
        const after = if (self.microtasks) |q| q.pendingLen() else 0;
        self.unlockMicrotasks();
        if (before == 0 and after == 0) break;
    }
    return Value.undef();
}

/// `Object.prototype.toString` → `"[object Tag]"`. The tag comes from the
/// object's kind (Array/Function/Error/Date/RegExp/Boolean/Number/String, else
/// "Object"), but an own/inherited `Symbol.toStringTag` *string* overrides it
/// (per spec). Distinct from the kind-specific `toString`s (e.g.
/// `[1,2].toString()` still joins) — this is the one on `Object.prototype`.
/// `Object.prototype.toLocaleString()` — by default just invokes `this.toString()`.
fn objectProtoToLocaleStringFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = args;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    return self.callMethod(this, "toString", &.{});
}

/// Getter for `Object.prototype.__proto__` — `[[GetPrototypeOf]]` of ToObject(this).
fn protoGetterFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = args;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const o = try self.toObject(this);
    if (o.proxy_handler != null or o.proxy_revoked) return self.proxyGetProto(o);
    if (self.effectiveProto(o)) |p| return Value.obj(p);
    return Value.nul();
}

/// Setter for `Object.prototype.__proto__` — sets the prototype to an object or
/// null; any other value is silently ignored (per spec).
fn protoSetterFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    // RequireObjectCoercible(this).
    if (this.isUndefined() or this.isNull())
        return self.throwError("TypeError", "Object.prototype.__proto__ setter called on null or undefined");
    const v = if (args.len > 0) args[0] else Value.undef();
    // Only an Object or null is a candidate prototype; anything else is a no-op.
    if (!v.isNull() and !builtins.isRealObject(v)) return Value.undef();
    if (!this.isObject()) return Value.undef(); // a primitive `this` has no own [[Prototype]]
    const o = this.asObj();
    const new_proto: ?*value.Object = if (v.isObject()) v.asObj() else null;
    // OrdinarySetPrototypeOf rejects setting the prototype of a non-extensible
    // object, or any change that would form a [[Prototype]] cycle. The
    // `__proto__` setter turns that false result into a TypeError.
    if (!try self.setPrototypeOfObject(o, new_proto))
        return self.throwError("TypeError", "Cannot set object prototype");
    return Value.undef();
}

fn objectProtoToStringFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = args;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const tag_obj: ?*value.Object = switch (this.kind()) {
        .undefined => return Value.str("[object Undefined]"),
        .null => return Value.str("[object Null]"),
        .object => this.asObj(),
        else => try self.toObject(this),
    };
    const builtin_tag: []const u8 = switch (this.kind()) {
        .number => "Number",
        .boolean => "Boolean",
        .string => "String",
        .object => blk: {
            const o = this.asObj();
            break :blk if (o.is_arguments) "Arguments" else if (try objectToStringIsArray(self, o)) "Array" else if (o.is_error) "Error" else if (o.is_date) "Date" else if (o.is_regex) "RegExp" else if (o.prim) |p| (switch (p.kind()) {
                .number => "Number",
                .string => "String",
                .boolean => "Boolean",
                else => "Object",
            }) else if (o.isCallableObject()) "Function" else "Object";
        },
        else => "Object",
    };
    // `Symbol.toStringTag` (a string) wins over the builtin tag.
    var tag = builtin_tag;
    if (tag_obj) |o| {
        if (symbolToStringTagKey(self)) |tk| {
            const tv = try self.getProperty(Value.obj(o), tk);
            if (tv.isString()) tag = tv.asStr();
        }
    }
    return Value.str(try std.mem.concat(self.arena, u8, &.{ "[object ", tag, "]" }));
}

pub fn objectToStringIsArray(self: *Interpreter, o: *value.Object) EvalError!bool {
    if (o.proxy_handler != null or o.proxy_revoked) {
        const target = o.proxy_target orelse return self.throwError("TypeError", "Cannot perform IsArray on a revoked proxy");
        return objectToStringIsArray(self, target);
    }
    return o.is_array;
}

/// Internal key of the well-known `Symbol.toStringTag`, for `@@toStringTag`.
fn symbolToStringTagKey(self: *Interpreter) ?[]const u8 {
    const sym = self.env.get("Symbol") orelse return null;
    if (!sym.isObject()) return null;
    const tt = sym.asObj().getOwn("toStringTag") orelse return null;
    if (!tt.isObject() or !tt.asObj().is_symbol) return null;
    return tt.asObj().sym_key;
}

/// `Error.isError(v)` — true iff `v` is an object with [[ErrorData]], looking
/// through a Proxy to its target (and false for a revoked proxy).
fn errorIsErrorFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = ctx;
    _ = this;
    const v = if (args.len > 0) args[0] else Value.undef();
    if (!v.isObject()) return Value.boolVal(false);
    var o = v.asObj();
    while (o.proxy_handler != null) {
        if (o.proxy_target) |t| o = t else break;
    }
    return Value.boolVal(o.is_error);
}

/// `Error.prototype.toString`: `"name: message"`, or just one when the other is
/// empty. Generic — reads `name`/`message` off `this` (so the prototype chain and
/// `.call(errorLike)` both work).
/// `Date.prototype[Symbol.toPrimitive](hint)`: OrdinaryToPrimitive over a string
/// hint — "string"/"default" try toString then valueOf, "number" the reverse;
/// any other hint (or a non-string) is a TypeError.
fn dateSymbolToPrimitiveFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (!this.isObject() or this.asObj().is_symbol or this.asObj().is_bigint)
        return self.throwError("TypeError", "Date.prototype[Symbol.toPrimitive] called on a non-object");
    const hint = if (args.len > 0) args[0] else Value.undef();
    if (!hint.isString()) return self.throwError("TypeError", "hint must be a string");
    const string_first = std.mem.eql(u8, hint.asStr(), "string") or std.mem.eql(u8, hint.asStr(), "default");
    if (!string_first and !std.mem.eql(u8, hint.asStr(), "number"))
        return self.throwError("TypeError", "invalid hint for Symbol.toPrimitive");
    const names: [2][]const u8 = if (string_first) .{ "toString", "valueOf" } else .{ "valueOf", "toString" };
    for (names) |m| {
        const method = try self.getProperty(this, m);
        if (method.isCallable()) {
            const res = try self.callValueWithThis(method, &.{}, this);
            if (!res.isObject() or res.asObj().is_symbol or res.asObj().is_bigint) return res;
        }
    }
    return self.throwError("TypeError", "Cannot convert object to primitive value");
}

fn errorToStringFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = args;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (!this.isObject() or this.asObj().is_symbol or this.asObj().is_bigint)
        return self.throwError("TypeError", "Error.prototype.toString called on a non-object");
    // ToString(name)/ToString(message) run ToPrimitive (throwing for a Symbol and
    // propagating an abrupt valueOf/toString).
    const name_v = try self.getProperty(this, "name");
    const name = if (name_v.isUndefined()) "Error" else try self.toStringV(name_v);
    const msg_v = try self.getProperty(this, "message");
    const msg = if (msg_v.isUndefined()) "" else try self.toStringV(msg_v);
    if (name.len == 0) return Value.str(msg);
    if (msg.len == 0) return Value.str(name);
    return Value.str(try std.mem.concat(self.arena, u8, &.{ name, ": ", msg }));
}

/// `Error.prototype.stack` getter (V8-style): a string for a receiver that has
/// `[[ErrorData]]` (an Error instance), otherwise undefined. The trace content
/// is implementation-defined; we return `"name: message"`.
fn errorStackGet(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = args;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (!this.isObject() or this.asObj().is_symbol or this.asObj().is_bigint)
        return self.throwError("TypeError", "Error.prototype.stack getter called on a non-object");
    // No [[ErrorData]] → undefined (e.g. Error.prototype, a plain object). For an
    // error, an implementation-defined trace string. Read the class name directly
    // off `[[ErrorData]]` rather than via [[Get]], so a hostile/recursive receiver
    // (proxy traps, getters) can't re-enter and blow the stack.
    if (!this.asObj().is_error) return Value.undef();
    const name = this.asObj().error_name;
    return Value.str(if (name.len == 0) "Error" else name);
}

/// SetterThatIgnoresPrototypeProperties(this, home, p, v): reject a non-object
/// receiver or the `home` object (which emulates a non-writable data property),
/// then — per the receiver's OWN descriptor — CreateDataPropertyOrThrow when the
/// property is absent (bypassing this inherited accessor) or Set(this, p, v,
/// true) when present (honoring an own accessor/writability).
fn setterIgnoringProto(self: *Interpreter, this: Value, home: ?*value.Object, key: []const u8, v: Value) EvalError!Value {
    if (!this.isObject() or this.asObj().is_symbol or this.asObj().is_bigint)
        return self.throwError("TypeError", "setter requires an object receiver");
    if (home) |h| if (this.asObj() == h) {
        const proto: ?*value.Object = if (h.getOwn("constructor")) |ctor|
            (if (ctor.isObject()) try self.functionRealmIntrinsicProto(ctor.asObj(), "TypeError") else null)
        else
            null;
        self.exception = try self.makeErrorWithProto("TypeError", "Cannot assign to the read-only property of the home object", proto);
        return error.Throw;
    };
    const o = this.asObj();
    // [[GetOwnProperty]](this, key): own data slot, own accessor, or proxy trap.
    const has_own = if (o.proxy_handler != null or o.proxy_revoked) blk: {
        const d = try builtins.objectGetOwnPropertyDescriptor(@ptrCast(self), Value.undef(), &.{ Value.obj(o), self.keyToValue(key) });
        break :blk d.isObject();
    } else (o.getOwn(key) != null or o.getAccessor(key) != null);
    if (!has_own) {
        // CreateDataPropertyOrThrow(this, key, v) — own {w,e,c}=true data property;
        // fails (TypeError) on a non-extensible receiver.
        const desc = (try self.newObject()).asObj();
        try desc.setOwn(self.arena, self.root_shape, "value", v);
        try desc.setOwn(self.arena, self.root_shape, "writable", Value.boolVal(true));
        try desc.setOwn(self.arena, self.root_shape, "enumerable", Value.boolVal(true));
        try desc.setOwn(self.arena, self.root_shape, "configurable", Value.boolVal(true));
        if (!try builtins.defineOneResult(self, o, key, desc))
            return self.throwError("TypeError", "Cannot create property");
        return Value.undef();
    }
    // Set(this, key, v, true) — honors an own accessor or writability.
    if (!try self.setMemberResult(Value.obj(o), key, v, Value.obj(o)))
        return self.throwError("TypeError", "Cannot set property");
    return Value.undef();
}

/// `Error.prototype.stack` setter. The home pointer (%Error.prototype%) is the
/// setter's `private_data`.
fn errorStackSet(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    // Step 1: a non-object receiver throws (handled in setterIgnoringProto).
    if (!this.isObject() or this.asObj().is_symbol or this.asObj().is_bigint)
        return self.throwError("TypeError", "Error.prototype.stack setter called on a non-object");
    // Step 2: v must already be a String (no coercion of an object/wrapper).
    const v = if (args.len > 0) args[0] else Value.undef();
    if (!v.isString())
        return self.throwError("TypeError", "Error.prototype.stack setter requires a string value");
    const home: ?*value.Object = if (self.active_native) |nat|
        (if (nat.private_data) |hd| @as(*value.Object, @ptrCast(@alignCast(hd))) else null)
    else
        null;
    return setterIgnoringProto(self, this, home, "stack", v);
}

/// Give `proto` a `constructor` own property pointing back to `ctor`
/// (non-enumerable, writable, configurable — the spec default for built-ins).
pub fn setConstructor(a: std.mem.Allocator, rs: *Shape, proto: *value.Object, ctor: *value.Object) EvalError!void {
    try proto.setOwn(a, rs, "constructor", Value.obj(ctor));
    try proto.setAttr(a, "constructor", .{ .enumerable = false, .configurable = true, .writable = true });
}

/// `Boolean.prototype.toString` / `valueOf` for a primitive boolean `this`.
fn booleanProtoFn(comptime to_string: bool) value.NativeFn {
    return struct {
        fn call(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
            _ = args;
            const self: *Interpreter = @ptrCast(@alignCast(ctx));
            const b: bool = switch (this.kind()) {
                .boolean => this.asBool(),
                // A Boolean wrapper object (`new Boolean(x)`) unwraps to its boxed value.
                .object => if (this.asObj().prim != null and this.asObj().prim.?.isBoolean()) this.asObj().prim.?.asBool() else return self.throwError("TypeError", "Boolean.prototype method requires that 'this' be a Boolean"),
                else => return self.throwError("TypeError", "Boolean.prototype method requires that 'this' be a Boolean"),
            };
            return if (to_string) Value.str(if (b) "true" else "false") else Value.boolVal(b);
        }
    }.call;
}

/// `Symbol.prototype.toString` → `"Symbol(description)"`. Requires a Symbol `this`.
fn symbolToStringFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = args;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const sym = try thisSymbol(self, this, "Symbol.prototype.toString");
    const ds = sym.sym_desc orelse "";
    return Value.str(try std.mem.concat(self.arena, u8, &.{ "Symbol(", ds, ")" }));
}

/// `Symbol.prototype.valueOf` → the Symbol itself. Requires a Symbol `this`.
fn symbolValueOfFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = args;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    _ = try thisSymbol(self, this, "Symbol.prototype.valueOf");
    return symbolThisValue(this);
}

/// `get Symbol.prototype.description` → the symbol's `[[Description]]` (a string
/// or `undefined`). Accepts a Symbol or a boxed Symbol wrapper as `this`.
fn symbolDescriptionGetFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = args;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const sym = try thisSymbol(self, this, "Symbol.prototype.description");
    return if (sym.sym_desc) |d| Value.str(d) else Value.undef();
}

/// `Symbol.prototype[@@toPrimitive]` → the symbol itself (any hint). Lets
/// `String(sym)`/`` `${sym}` `` route through it (and still throw on string
/// coercion via the normal ToString path, not here).
fn symbolToPrimitiveFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = args;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    _ = try thisSymbol(self, this, "Symbol.prototype[Symbol.toPrimitive]");
    return symbolThisValue(this);
}

/// The underlying Symbol value of `this` — the symbol itself, or the boxed
/// symbol of an `Object(sym)` wrapper.
fn symbolThisValue(this: Value) Value {
    if (this.isObject()) {
        if (this.asObj().is_symbol) return this;
        if (this.asObj().prim) |p| return p;
    }
    return this;
}

/// Brand-check helper: returns the Symbol object backing `this` (unwrapping an
/// `Object(sym)` wrapper), else throws a TypeError naming `method`.
fn thisSymbol(self: *Interpreter, this: Value, method: []const u8) EvalError!*value.Object {
    if (this.isObject()) {
        if (this.asObj().is_symbol) return this.asObj();
        if (this.asObj().prim) |p| {
            if (p.isObject() and p.asObj().is_symbol) return p.asObj();
        }
    }
    return self.throwError("TypeError", try std.fmt.allocPrint(self.arena, "{s} requires that 'this' be a Symbol", .{method}));
}

// ---- Proxy / Reflect natives ----------------------------------------------

fn proxyConstructorFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (self.new_target.isUndefined())
        return self.throwError("TypeError", "Constructor Proxy requires 'new'");
    const target = if (args.len > 0) args[0] else Value.undef();
    const handler = if (args.len > 1) args[1] else Value.undef();
    if (!builtins.isRealObject(target) or !builtins.isRealObject(handler))
        return self.throwError("TypeError", "Cannot create proxy with a non-object as target or handler");
    const o = try gc_mod.allocObj(self.arena);
    o.* = .{ .proxy_target = target.asObj(), .proxy_handler = handler.asObj(), .proxy_callable = target.asObj().isCallableObject() };
    return Value.obj(o);
}

/// `Proxy.revocable(target, handler)` → `{ proxy, revoke }`.
fn proxyRevocableFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const saved_nt = self.new_target;
    self.new_target = Value.undef(); // proxyConstructorFn requires new; emulate it
    defer self.new_target = saved_nt;
    const target = if (args.len > 0) args[0] else Value.undef();
    const handler = if (args.len > 1) args[1] else Value.undef();
    if (!builtins.isRealObject(target) or !builtins.isRealObject(handler))
        return self.throwError("TypeError", "Cannot create proxy with a non-object as target or handler");
    const p = try gc_mod.allocObj(self.arena);
    p.* = .{ .proxy_target = target.asObj(), .proxy_handler = handler.asObj(), .proxy_callable = target.asObj().isCallableObject() };
    const revoke = try gc_mod.allocObj(self.arena);
    revoke.* = .{ .native = proxyRevokeFn, .private_data = @ptrCast(p) };
    try installNativeProps(self.arena, self.root_shape, revoke, "", 0);
    const result = (try self.newObject()).asObj();
    try self.setProp(result, "proxy", Value.obj(p));
    try self.setProp(result, "revoke", Value.obj(revoke));
    return Value.obj(result);
}

fn proxyRevokeFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    _ = args;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (self.active_native) |nf| {
        if (nf.private_data) |pd| {
            const p: *value.Object = @ptrCast(@alignCast(pd));
            p.proxy_revoked = true;
            p.proxy_target = null;
            p.proxy_handler = null;
        }
    }
    return Value.undef();
}

fn reflectGetFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const target = if (args.len > 0) args[0] else Value.undef();
    if (!builtins.isRealObject(target)) return self.throwError("TypeError", "Reflect.get called on non-object");
    const receiver = if (args.len > 2) args[2] else target;
    return self.getPropertyWithReceiver(target, try self.keyOf(if (args.len > 1) args[1] else Value.undef()), receiver);
}

fn reflectSetFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const target = if (args.len > 0) args[0] else Value.undef();
    if (!builtins.isRealObject(target)) return self.throwError("TypeError", "Reflect.set called on non-object");
    // A module namespace's [[Set]] returns false (Reflect.set reports it without
    // throwing, unlike a strict assignment).
    if (target.isObject() and isModuleNs(target.asObj())) return Value.boolVal(false);
    const receiver = if (args.len > 3) args[3] else target;
    return Value.boolVal(try self.setMemberResult(target, try self.keyOf(if (args.len > 1) args[1] else Value.undef()), if (args.len > 2) args[2] else Value.undef(), receiver));
}

fn reflectHasFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const target = if (args.len > 0) args[0] else Value.undef();
    if (!builtins.isRealObject(target)) return self.throwError("TypeError", "Reflect.has called on non-object");
    return Value.boolVal(try self.inOperator(if (args.len > 1) args[1] else Value.undef(), target));
}

fn reflectDeleteFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const target = if (args.len > 0) args[0] else Value.undef();
    if (!builtins.isRealObject(target)) return self.throwError("TypeError", "Reflect.deleteProperty called on non-object");
    return Value.boolVal(try self.deleteOwn(target.asObj(), try self.keyOf(if (args.len > 1) args[1] else Value.undef())));
}

fn reflectOwnKeysFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (args.len > 0 and args[0].isObject()) try self.checkRestricted(args[0].asObj());
    const target = if (args.len > 0) args[0] else Value.undef();
    if (!builtins.isRealObject(target)) return self.throwError("TypeError", "Reflect.ownKeys called on non-object");
    // objectOwnKeysList is proxy- and module-namespace-aware (sorted exotic keys).
    const keys = try self.objectOwnKeysList(target.asObj());
    const arr = try self.newArray();
    for (keys) |k| try arr.asObj().elements.append(arr.asObj().elementsAllocator(self.arena), self.keyToValue(k));
    return arr;
}

fn reflectGetProtoFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const target = if (args.len > 0) args[0] else Value.undef();
    if (!builtins.isRealObject(target)) return self.throwError("TypeError", "Reflect.getPrototypeOf called on non-object");
    if (target.asObj().proxy_handler != null or target.asObj().proxy_revoked) return self.proxyGetProto(target.asObj());
    return if (target.asObj().proto) |p| Value.obj(p) else Value.nul();
}

/// CreateListFromArrayLike: a non-Array argumentsList is still read via its
/// `length` + indexed properties (a throwing `length`/index getter propagates);
/// a non-object is a TypeError. Real arrays take the dense fast path.
fn createListFromArrayLike(self: *Interpreter, v: Value) EvalError![]const Value {
    if (!builtins.isRealObject(v)) return self.throwError("TypeError", "Reflect: arguments list is not an object");
    if (v.asObj().is_array) return v.asObj().elements.items;
    const len = toLen((try self.toPrimitive(try self.getProperty(v, "length"), .number)).toNumber());
    if (len > (1 << 22)) return self.throwError("RangeError", "arguments list is too large");
    const buf = try self.arena.alloc(Value, len);
    for (buf, 0..) |*slot, i| slot.* = try self.getProperty(v, try std.fmt.allocPrint(self.arena, "{d}", .{i}));
    return buf;
}

fn reflectApplyFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const target = if (args.len > 0) args[0] else Value.undef();
    if (!target.isCallable()) return self.throwError("TypeError", "Reflect.apply target is not a function");
    const this_arg = if (args.len > 1) args[1] else Value.undef();
    const list = try createListFromArrayLike(self, if (args.len > 2) args[2] else Value.undef());
    return self.callValueWithThis(target, list, this_arg);
}

fn reflectConstructFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const target = if (args.len > 0) args[0] else Value.undef();
    if (!isConstructorValue(target)) return self.throwError("TypeError", "Reflect.construct target is not a constructor");
    // A new.target (3rd arg) must itself be a constructor — this is what the
    // `isConstructor` harness probes via `Reflect.construct(fn, [], target)`.
    if (args.len > 2 and !isConstructorValue(args[2]))
        return self.throwError("TypeError", "Reflect.construct newTarget is not a constructor");
    const list = try createListFromArrayLike(self, if (args.len > 1) args[1] else Value.undef());
    const new_target = if (args.len > 2) args[2] else target;
    return self.constructNT(target, list, new_target);
}

/// `Reflect.getOwnPropertyDescriptor(target, key)` — like the Object.* form but
/// a non-Object target is a TypeError (Object.* coerces / returns undefined).
fn reflectGetOwnDescFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (!builtins.isRealObject(if (args.len > 0) args[0] else Value.undef()))
        return self.throwError("TypeError", "Reflect.getOwnPropertyDescriptor called on non-object");
    return builtins.objectGetOwnPropertyDescriptor(ctx, this, args);
}

/// `Reflect.isExtensible(target)` — TypeError on a non-Object (Object.* returns false).
fn reflectIsExtensibleFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (args.len > 0 and args[0].isObject()) try self.checkRestricted(args[0].asObj());
    if (!builtins.isRealObject(if (args.len > 0) args[0] else Value.undef()))
        return self.throwError("TypeError", "Reflect.isExtensible called on non-object");
    return builtins.objectIsExtensible(ctx, this, args);
}

/// `Reflect.preventExtensions(target)` — TypeError on a non-Object, returns a
/// boolean (Object.preventExtensions returns the target / no-ops a primitive).
fn reflectPreventExtFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (args.len > 0 and args[0].isObject()) try self.checkRestricted(args[0].asObj());
    const target = if (args.len > 0) args[0] else Value.undef();
    if (!builtins.isRealObject(target))
        return self.throwError("TypeError", "Reflect.preventExtensions called on non-object");
    if (target.asObj().proxy_handler != null or target.asObj().proxy_revoked)
        return Value.boolVal(try self.proxyPreventExt(target.asObj()));
    target.asObj().extensible = false;
    return Value.boolVal(true);
}

/// `Reflect.setPrototypeOf(target, proto)` — OrdinarySetPrototypeOf returning a
/// boolean: TypeError if target is not an Object or proto is not Object|null;
/// otherwise true on success and false (NOT a throw) when the object is
/// non-extensible or the new prototype would form a cycle.
fn reflectSetProtoFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const target = if (args.len > 0) args[0] else Value.undef();
    if (!builtins.isRealObject(target))
        return self.throwError("TypeError", "Reflect.setPrototypeOf called on non-object");
    const p = if (args.len > 1) args[1] else Value.undef();
    if (!p.isNull() and !builtins.isRealObject(p))
        return self.throwError("TypeError", "Object prototype may only be an Object or null");
    const new_proto: ?*value.Object = if (p.isObject()) p.asObj() else null;
    return Value.boolVal(try self.setPrototypeOfObject(target.asObj(), new_proto));
}

/// Best-effort [[Construct]]-ability test: a native flagged `native_ctor`, an
/// error constructor, a non-arrow/non-generator/non-async JS function, a bound
/// function over a constructor, or a proxy whose target is a constructor.
pub fn isConstructorValue(v: Value) bool {
    if (!v.isObject()) return false;
    const o = v.asObj();
    if (o.proxy_handler != null) return if (o.proxy_target) |t| isConstructorValue(Value.obj(t)) else false;
    if (o.bound) |erased| {
        const bf: *Interpreter.BoundFn = @ptrCast(@alignCast(erased));
        return isConstructorValue(bf.target);
    }
    if (o.error_ctor != null) return true;
    if (o.native != null) return o.native_ctor;
    if (o.js_func) |erased| {
        const f: *Function = @ptrCast(@alignCast(erased));
        return !f.is_arrow and !f.is_async and !f.is_generator and !f.is_method;
    }
    return false;
}

/// Install the engine's global bindings into `env`: the `Error`-family
/// constructors, `NaN`/`Infinity`/`undefined`, the `Math` and `Object`/`Array`
/// namespaces, and the common global functions. `root_shape` backs the property
/// stores of the namespace objects. Called once per Context, before user code.
fn eq(a: []const u8, b: []const u8) bool {
    return std.mem.eql(u8, a, b);
}

/// Mirror a global environment's bindings onto its global object as own
/// properties (matching `Context.create`), so `globalThis.X` / reflection work.
pub fn mirrorGlobalsOnto(env: *Environment, gobj: *value.Object, rs: *Shape) EvalError!void {
    var it = env.vars.iterator();
    while (it.next()) |e| {
        const name = e.key_ptr.*;
        if (name.len > 0 and name[0] == 0) continue;
        if (gobj.getOwn(name) != null) continue;
        try gobj.setOwn(env.arena, rs, name, e.value_ptr.*);
        const frozen = eq(name, "undefined") or eq(name, "NaN") or eq(name, "Infinity");
        try gobj.setAttr(env.arena, name, if (frozen)
            .{ .writable = false, .enumerable = false, .configurable = false }
        else
            .{ .writable = true, .enumerable = false, .configurable = true });
    }
}

/// `$262.gc()` — a no-op (the engine uses an arena, no explicit GC).
fn host262GcFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = ctx;
    _ = this;
    _ = args;
    return Value.undef();
}

/// `$262.IsHTMLDDA()` — the [[Call]] of an [[IsHTMLDDA]] object (legacy
/// `document.all`): returns null when called with no arguments or a first
/// argument that is undefined or the empty string, else undefined.
fn host262IsHTMLDDACallFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = ctx;
    _ = this;
    if (args.len == 0) return Value.nul();
    if (args[0].isUndefined()) return Value.nul();
    if (args[0].isString() and args[0].asStr().len == 0) return Value.nul();
    return Value.undef();
}

/// `$262.detachArrayBuffer(buffer)` — detach an ArrayBuffer's backing store.
fn host262DetachFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    _ = ctx;
    const v = if (args.len > 0) args[0] else Value.undef();
    if (v.isObject()) if (v.asObj().array_buffer) |ab| {
        ab.setDetached(true);
    };
    return Value.undef();
}

/// `$262.evalScript(src)` / a realm's evalScript — parse + evaluate `src` as a
/// global script in the realm captured in this native's `private_data`.
fn host262EvalScriptFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const fnobj = self.active_native orelse return Value.undef();
    const genv: *Environment = @ptrCast(@alignCast(fnobj.private_data orelse return Value.undef()));
    if (args.len == 0 or !args[0].isString()) return if (args.len > 0) args[0] else Value.undef();
    var parser = Parser.init(self.arena, args[0].asStr()) catch return self.throwError("SyntaxError", "evalScript: invalid source");
    const prog = parser.parseProgram() catch return self.throwError("SyntaxError", "evalScript: parse error");
    const gobj: ?*value.Object = if (genv.get("globalThis")) |g| (if (g.isObject()) g.asObj() else null) else null;
    const s_env = self.env;
    const s_this = self.this_value;
    const s_glob = self.global_object;
    self.env = genv;
    if (gobj) |go| {
        self.this_value = Value.obj(go);
        self.global_object = go;
    }
    defer {
        self.env = s_env;
        self.this_value = s_this;
        self.global_object = s_glob;
    }
    return self.eval(prog);
}

/// `$262.createRealm()` — a fresh realm (its own global environment, intrinsics,
/// and global object), returned as `{ global, evalScript }`.
fn host262CreateRealmFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    _ = args;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const a = self.arena;
    const genv = try gc_mod.allocEnv(a);
    self.initEnvironment(genv, null, true);
    const gobj = try gc_mod.allocObj(a);
    gobj.* = .{};
    // Share the creating realm's well-known symbols with the new realm.
    const parent_symbol: ?*value.Object = if (self.env.get("Symbol")) |sv| (if (sv.isObject()) sv.asObj() else null) else null;
    try installGlobalsInner(genv, self.root_shape, parent_symbol);
    try genv.put("globalThis", Value.obj(gobj));
    try mirrorGlobalsOnto(genv, gobj, self.root_shape);
    // Point the new realm's own `$262.global` at its global object.
    if (genv.get("$262")) |d| {
        if (d.isObject()) try self.setProp(d.asObj(), "global", Value.obj(gobj));
    }
    // The realm record handed back to the caller (in the caller's realm).
    const realm = (try self.newObject()).asObj();
    try self.setProp(realm, "global", Value.obj(gobj));
    const es = try gc_mod.allocObj(a);
    es.* = .{ .native = host262EvalScriptFn, .private_data = @ptrCast(genv) };
    try installNativeProps(a, self.root_shape, es, "evalScript", 1);
    try self.setProp(realm, "evalScript", Value.obj(es));
    return Value.obj(realm);
}

fn host262AbstractModuleSourceFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    _ = args;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    return self.throwError("TypeError", "AbstractModuleSource is not constructible");
}

fn host262AbstractModuleSourceTagGetter(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = ctx;
    _ = this;
    _ = args;
    // Real module source objects will carry [[ModuleSourceClassName]] later.
    return Value.undef();
}

fn install262AbstractModuleSource(env: *Environment, rs: *Shape, host: *value.Object, object_proto: *value.Object) EvalError!void {
    const a = env.arena;
    const proto = try gc_mod.allocObj(a);
    proto.* = .{ .proto = object_proto };

    const ctor = try gc_mod.allocObj(a);
    const function_proto: ?*value.Object = blk: {
        if (env.get("Function")) |fv| if (fv.isObject()) {
            if (fv.asObj().getOwn("prototype")) |pv| if (pv.isObject()) break :blk pv.asObj();
        };
        break :blk null;
    };
    ctor.* = .{ .native = host262AbstractModuleSourceFn, .native_ctor = true, .proto = function_proto };
    try installNativeProps(a, rs, ctor, "AbstractModuleSource", 0);
    try ctor.setOwn(a, rs, "prototype", Value.obj(proto));
    try ctor.setAttr(a, "prototype", .{ .writable = false, .enumerable = false, .configurable = false });
    try setConstructor(a, rs, proto, ctor);

    if (env.get("Symbol")) |sym| if (sym.isObject()) {
        if (sym.asObj().getOwn("toStringTag")) |tag| if (tag.isObject() and tag.asObj().is_symbol) {
            const getter = try gc_mod.allocObj(a);
            getter.* = .{ .native = host262AbstractModuleSourceTagGetter };
            try installNativeProps(a, rs, getter, "get [Symbol.toStringTag]", 0);
            try proto.setAccessor(a, tag.asObj().sym_key, Value.obj(getter), null);
            try proto.setAttr(a, tag.asObj().sym_key, .{ .enumerable = false, .configurable = true });
        };
    };

    try host.setOwn(a, rs, "AbstractModuleSource", Value.obj(ctor));
    try host.setAttr(a, "AbstractModuleSource", .{ .writable = true, .enumerable = false, .configurable = true });
}

/// Build a fresh realm (own global env + global object + intrinsics), sharing
/// the creating realm's well-known symbols. Returns the new Environment.
fn makeChildRealm(self: *Interpreter) EvalError!*Environment {
    const a = self.arena;
    const genv = try gc_mod.allocEnv(a);
    self.initEnvironment(genv, null, true);
    const gobj = try gc_mod.allocObj(a);
    gobj.* = .{};
    const parent_symbol: ?*value.Object = if (self.env.get("Symbol")) |sv| (if (sv.isObject()) sv.asObj() else null) else null;
    const parent_symbol_registry = try symbolRegistry(self);
    try installGlobalsInner(genv, self.root_shape, parent_symbol);
    if (parent_symbol_registry) |reg| {
        if (genv.get("Symbol")) |sv| if (sv.isObject())
            try sv.asObj().setOwn(a, self.root_shape, "\x00registry", Value.obj(reg));
    }
    if (genv.get("Object")) |ov| if (ov.isObject()) {
        if (ov.asObj().getOwn("prototype")) |pv| {
            if (pv.isObject()) gobj.setProtoAtomic(pv.asObj());
        }
    };
    try genv.put("globalThis", Value.obj(gobj));
    try mirrorGlobalsOnto(genv, gobj, self.root_shape);
    if (genv.get("$262")) |d| {
        if (d.isObject()) try self.setProp(d.asObj(), "global", Value.obj(gobj));
    }
    return genv;
}

fn shadowRealmNativeRealm(self: *Interpreter) ?*Environment {
    const native = self.active_native orelse return null;
    return @ptrCast(@alignCast(native.private_data orelse return null));
}

fn throwErrorInRealm(self: *Interpreter, realm: *Environment, name: []const u8, message: []const u8) EvalError {
    const saved_env = self.env;
    self.env = realm;
    defer self.env = saved_env;
    return self.throwError(name, message);
}

fn objectFunctionRealm(o: *value.Object) ?*Environment {
    if (o.js_func) |erased| {
        const func: *Function = @ptrCast(@alignCast(erased));
        return func.closure;
    }
    return null;
}

fn symbolProtoInRealm(realm: *Environment) ?*value.Object {
    const sym = realm.get("Symbol") orelse return null;
    if (!sym.isObject()) return null;
    const p = sym.asObj().getOwn("prototype") orelse return null;
    return if (p.isObject()) p.asObj() else null;
}

const SrWrappedData = struct {
    target: *value.Object,
    caller_env: *Environment,
    target_env: *Environment,
};

/// GetWrappedValue across a ShadowRealm boundary: a primitive (incl. Symbol /
/// BigInt) passes through; a callable becomes a forwarding wrapper function; any
/// other object is a TypeError.
fn srWrapValue(self: *Interpreter, wrap_env: *Environment, error_env: *Environment, v: Value) EvalError!Value {
    if (!v.isObject()) return v;
    const o = v.asObj();
    if (o.is_symbol) {
        if (symbolProtoInRealm(wrap_env)) |p| o.setProtoAtomic(p);
        return v;
    }
    if (o.is_bigint) return v;
    if (o.isCallableObject()) {
        const saved_env = self.env;
        self.env = wrap_env;
        defer self.env = saved_env;
        const w = (try self.newObject()).asObj();
        w.native = srWrappedCallFn;
        const data = try self.arena.create(SrWrappedData);
        data.* = .{
            .target = o,
            .caller_env = wrap_env,
            .target_env = objectFunctionRealm(o) orelse wrap_env,
        };
        w.private_data = @ptrCast(data);
        // The wrapper's [[Prototype]] is the realm receiving the wrapped value.
        if (wrap_env.get("Function")) |fc| if (fc.isObject()) {
            if (fc.asObj().getOwn("prototype")) |fp| if (fp.isObject()) {
                w.setProtoAtomic(fp.asObj());
            };
        };
        // CopyNameAndLength(wrapped, target): a read that throws (a poisoned
        // length/name getter) aborts the wrap with a TypeError in error_env.
        const ro_attr: value.PropAttr = .{ .writable = false, .enumerable = false, .configurable = true };
        const len_desc = builtins.objectGetOwnPropertyDescriptor(self, Value.undef(), &.{ Value.obj(o), Value.str("length") }) catch
            return throwErrorInRealm(self, error_env, "TypeError", "ShadowRealm: wrapped function length is not accessible");
        const len_v = if (len_desc.isUndefined())
            Value.undef()
        else
            self.getProperty(Value.obj(o), "length") catch
                return throwErrorInRealm(self, error_env, "TypeError", "ShadowRealm: wrapped function length is not accessible");
        // ToIntegerOrInfinity(targetLen): +∞ is preserved; otherwise clamp to ≥ 0.
        const len: f64 = if (len_v.isNumber() and !std.math.isNan(len_v.asNum()))
            (if (std.math.isInf(len_v.asNum())) (if (len_v.asNum() > 0) len_v.asNum() else 0) else @max(0, @trunc(len_v.asNum())))
        else
            0;
        try w.setOwn(self.arena, self.root_shape, "length", Value.num(len));
        try w.setAttr(self.arena, "length", ro_attr);
        const name_v = self.getProperty(Value.obj(o), "name") catch
            return throwErrorInRealm(self, error_env, "TypeError", "ShadowRealm: wrapped function name is not accessible");
        try w.setOwn(self.arena, self.root_shape, "name", Value.str(if (name_v.isString()) name_v.asStr() else ""));
        try w.setAttr(self.arena, "name", ro_attr);
        return Value.obj(w);
    }
    return throwErrorInRealm(self, error_env, "TypeError", "ShadowRealm: a non-callable object cannot cross the realm boundary");
}

/// A wrapped ShadowRealm callable: wrap each argument inward, call the target,
/// and wrap the result outward.
fn srWrappedCallFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const fnobj = self.active_native orelse return Value.undef();
    const data: *SrWrappedData = @ptrCast(@alignCast(fnobj.private_data orelse return Value.undef()));
    const wargs = try self.arena.alloc(Value, args.len);
    for (args, 0..) |arg_v, i| wargs[i] = try srWrapValue(self, data.target_env, data.caller_env, arg_v);
    // WrappedFunction [[Call]]: a normal completion is wrapped outward; an abrupt
    // one is re-thrown as a TypeError in the *calling* realm.
    const r = self.callValueWithThis(Value.obj(data.target), wargs, Value.undef()) catch |e| {
        if (e == error.Throw) return throwErrorInRealm(self, data.caller_env, "TypeError", "WrappedFunction: the wrapped target threw");
        return e;
    };
    return srWrapValue(self, data.caller_env, data.caller_env, r);
}

fn shadowRealmConstructorFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = args;
    _ = this;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const ctor_env = shadowRealmNativeRealm(self) orelse self.env;
    if (self.new_target.isUndefined()) return throwErrorInRealm(self, ctor_env, "TypeError", "Constructor ShadowRealm requires 'new'");
    const saved_env = self.env;
    self.env = ctor_env;
    defer self.env = saved_env;
    const genv = try makeChildRealm(self);
    const o = (try self.newObject()).asObj();
    o.is_shadow_realm = true;
    o.private_data = @ptrCast(genv);
    if (self.new_target.isObject()) o.setProtoAtomic(try self.protoObject(self.new_target.asObj()));
    return Value.obj(o);
}

/// `ShadowRealm.prototype.importValue(specifier, exportName)` — validates the
/// receiver and arguments synchronously (ToString(specifier); exportName must be
/// a String), then returns a Promise. Module loading inside a ShadowRealm is not
/// wired up, so the returned promise rejects.
fn shadowRealmImportValueFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (!this.isObject() or !this.asObj().is_shadow_realm) return self.throwError("TypeError", "ShadowRealm.prototype.importValue called on a non-ShadowRealm");
    _ = try self.toStringV(if (args.len > 0) args[0] else Value.undef()); // ToString(specifier) — may throw
    const export_name = if (args.len > 1) args[1] else Value.undef();
    if (!export_name.isString()) return self.throwError("TypeError", "ShadowRealm.prototype.importValue: exportName must be a string");
    const reason = try self.makeError("TypeError", "ShadowRealm module import is not supported");
    return promiseRejectValue(self, reason);
}

fn shadowRealmEvaluateFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const caller_env = shadowRealmNativeRealm(self) orelse self.env;
    if (!this.isObject() or !this.asObj().is_shadow_realm) return throwErrorInRealm(self, caller_env, "TypeError", "ShadowRealm.prototype.evaluate called on a non-ShadowRealm");
    const src = if (args.len > 0) args[0] else Value.undef();
    if (!src.isString()) return throwErrorInRealm(self, caller_env, "TypeError", "ShadowRealm.prototype.evaluate expects a string");
    const genv: *Environment = @ptrCast(@alignCast(this.asObj().private_data orelse return throwErrorInRealm(self, caller_env, "TypeError", "ShadowRealm has no realm")));
    var parser = Parser.init(self.arena, src.asStr()) catch return throwErrorInRealm(self, caller_env, "SyntaxError", "evaluate: invalid source");
    const prog = parser.parseProgram() catch return throwErrorInRealm(self, caller_env, "SyntaxError", "evaluate: parse error");
    const prog_strict = parser.strict;
    const gobj: ?*value.Object = if (genv.get("globalThis")) |g| (if (g.isObject()) g.asObj() else null) else null;
    const s_env = self.env;
    const s_this = self.this_value;
    const s_glob = self.global_object;
    const s_strict = self.strict;
    const s_deletable = self.eval_decl_deletable;
    const eval_env = try gc_mod.allocEnv(self.arena);
    self.initEnvironment(eval_env, genv, prog_strict);
    eval_env.fn_body = !prog_strict;
    self.env = eval_env;
    self.strict = prog_strict;
    self.eval_decl_deletable = !prog_strict;
    errdefer {
        self.env = s_env;
        self.this_value = s_this;
        self.global_object = s_glob;
        self.strict = s_strict;
        self.eval_decl_deletable = s_deletable;
    }
    if (gobj) |go| {
        self.this_value = Value.obj(go);
        self.global_object = go;
    }
    if (prog.* == .program) {
        try self.checkGlobalEvalDeclarable(prog.program);
        if (!prog_strict) try self.checkEvalLexicalConflicts(prog.program);
        try self.hoistVarNames(prog.program);
    }
    const eval_result = self.eval(prog);
    // Restore the CALLER realm before converting an abrupt completion / wrapping
    // the result, so a boundary TypeError is created with the caller's %TypeError%
    // (and the result value is wrapped from the caller's perspective).
    self.env = s_env;
    self.this_value = s_this;
    self.global_object = s_glob;
    self.strict = s_strict;
    self.eval_decl_deletable = s_deletable;
    const result = eval_result catch |e| {
        // A throw inside the child realm surfaces as a TypeError in the caller
        // (the thrown value can't cross the boundary).
        if (e == error.Throw) {
            return throwErrorInRealm(self, caller_env, "TypeError", "ShadowRealm.prototype.evaluate: the evaluated code threw");
        }
        return e;
    };
    return srWrapValue(self, caller_env, caller_env, result);
}

/// Install the test262 `$262` host object into `env` (its `global` is wired up
/// by the caller once the realm's global object exists).
pub fn install262(env: *Environment, rs: *Shape, object_proto: *value.Object) EvalError!void {
    const a = env.arena;
    const d = try gc_mod.allocObj(a);
    d.* = .{ .proto = object_proto };
    try setNative(a, rs, d, "gc", 0, host262GcFn);
    try setNative(a, rs, d, "detachArrayBuffer", 1, host262DetachFn);
    try setNative(a, rs, d, "createRealm", 0, host262CreateRealmFn);
    // $262.IsHTMLDDA — an [[IsHTMLDDA]] exotic (typeof "undefined", falsy,
    // loosely-equal to null/undefined), callable per its legacy [[Call]].
    const htmldda = try gc_mod.allocObj(a);
    htmldda.* = .{ .proto = object_proto, .native = host262IsHTMLDDACallFn, .is_htmldda = true };
    try d.setOwn(a, rs, "IsHTMLDDA", Value.obj(htmldda));
    const es = try gc_mod.allocObj(a);
    es.* = .{ .native = host262EvalScriptFn, .private_data = @ptrCast(env) };
    try installNativeProps(a, rs, es, "evalScript", 1);
    try d.setOwn(a, rs, "evalScript", Value.obj(es));
    try install262AbstractModuleSource(env, rs, d, object_proto);
    try installAgent(a, rs, d);
    // On the main thread, each test gets a fresh Context → reset cross-test
    // agent coordination state. Agent threads must NOT reset it (the parent owns
    // the broadcast/report channels they're using).
    // A fresh *main* realm tears down the previous test's agent group (joins
    // agent threads, clears reports/broadcast, wakes stranded waiters). An
    // agent realm installing $262 must not reset the group it belongs to.
    if (agent.currentAgent() == null) agent.reset();
    try env.put("$262", Value.obj(d));
}

/// Render an `i128` in `radix` (2..36).
fn formatBigIntRadix(arena: std.mem.Allocator, val: i128, radix: u8) error{OutOfMemory}![]const u8 {
    if (val == 0) return "0";
    var buf: [200]u8 = undefined;
    var i: usize = buf.len;
    const neg = val < 0;
    // Magnitude in u128 (bitcast handles i128 minInt without overflow on negate).
    var v: u128 = if (neg) @as(u128, @bitCast(-%val)) else @intCast(val);
    const digits = "0123456789abcdefghijklmnopqrstuvwxyz";
    while (v > 0) {
        i -= 1;
        buf[i] = digits[@intCast(v % radix)];
        v /= radix;
    }
    if (neg) {
        i -= 1;
        buf[i] = '-';
    }
    return arena.dupe(u8, buf[i..]);
}

fn canonicalBigIntDecimalString(arena: std.mem.Allocator, raw: []const u8) error{OutOfMemory}!?[]const u8 {
    if (raw.len == 0) return null;
    var i: usize = 0;
    var neg = false;
    if (raw[i] == '+' or raw[i] == '-') {
        neg = raw[i] == '-';
        i += 1;
        if (i == raw.len) return null;
    }
    while (i < raw.len and raw[i] == '0') i += 1;
    if (i == raw.len) return "0";
    for (raw[i..]) |c| if (!std.ascii.isDigit(c)) return null;
    if (!neg) {
        const out = try arena.dupe(u8, raw[i..]);
        return out;
    }
    const out = try std.mem.concat(arena, u8, &.{ "-", raw[i..] });
    return out;
}

fn canonicalBigIntRadixString(arena: std.mem.Allocator, digits: []const u8, radix: u8) error{OutOfMemory}!?[]const u8 {
    if (digits.len == 0) return null;
    var non_zero = false;
    for (digits) |c| {
        const d = std.fmt.charToDigit(c, radix) catch return null;
        if (d != 0) non_zero = true;
    }
    if (!non_zero) return "0";
    if (std.fmt.parseInt(i128, digits, radix)) |n| {
        const out: []const u8 = try std.fmt.allocPrint(arena, "{d}", .{n});
        return out;
    } else |_| {}

    var decimal: std.ArrayListUnmanaged(u8) = .empty; // little-endian decimal digits
    try decimal.append(arena, 0);
    for (digits) |c| {
        const digit = std.fmt.charToDigit(c, radix) catch unreachable;
        var carry: u16 = digit;
        for (decimal.items) |*decimal_digit| {
            const value_ = @as(u16, decimal_digit.*) * radix + carry;
            decimal_digit.* = @intCast(value_ % 10);
            carry = value_ / 10;
        }
        while (carry > 0) {
            try decimal.append(arena, @intCast(carry % 10));
            carry /= 10;
        }
    }
    while (decimal.items.len > 1 and decimal.items[decimal.items.len - 1] == 0) decimal.items.len -= 1;
    var out = try arena.alloc(u8, decimal.items.len);
    for (decimal.items, 0..) |d, i| out[out.len - 1 - i] = '0' + d;
    return out;
}

/// `BigInt(value)` — NumberToBigInt for an integral Number, else ToBigInt.
/// It has [[Construct]] so IsConstructor(BigInt) is true, but `new BigInt`
/// throws before argument coercion.
fn bigIntFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const saved_env = self.env;
    var swapped_env = false;
    if (self.active_native) |callee| {
        if (callee.private_data) |pd| {
            self.env = @ptrCast(@alignCast(pd));
            swapped_env = true;
        }
    }
    defer if (swapped_env) {
        self.env = saved_env;
    };
    if (!self.new_target.isUndefined()) return self.throwError("TypeError", "BigInt is not a constructor");
    return self.toBigIntValueImpl(if (args.len > 0) args[0] else Value.undef(), true);
}

fn bigIntRoundSignificant(self: *Interpreter, digits_in: []const u8, max_sig: usize) EvalError![]const u8 {
    if (max_sig == 0 or digits_in.len <= max_sig) return digits_in;
    var kept = try self.arena.dupe(u8, digits_in[0..max_sig]);
    if (digits_in[max_sig] >= '5') {
        var i = kept.len;
        while (i > 0) {
            i -= 1;
            if (kept[i] < '9') {
                kept[i] += 1;
                break;
            }
            kept[i] = '0';
        } else {
            var carry: std.ArrayListUnmanaged(u8) = .empty;
            try carry.append(self.arena, '1');
            try carry.appendSlice(self.arena, kept);
            kept = try carry.toOwnedSlice(self.arena);
        }
    }
    var out: std.ArrayListUnmanaged(u8) = .empty;
    try out.appendSlice(self.arena, kept);
    var z = digits_in.len - max_sig;
    while (z > 0) : (z -= 1) try out.append(self.arena, '0');
    return out.toOwnedSlice(self.arena);
}

fn bigIntGroupedDecimal(self: *Interpreter, digits: []const u8, locale: []const u8, group: []const u8) EvalError![]const u8 {
    const indic = nfIndicGrouping(locale);
    var out: std.ArrayListUnmanaged(u8) = .empty;
    const n = digits.len;
    for (digits, 0..) |c, i| {
        const rem = n - i;
        const at_boundary = if (indic)
            (rem == 3 or (rem > 3 and (rem - 3) % 2 == 0))
        else
            (rem % 3 == 0);
        if (i != 0 and at_boundary) try out.appendSlice(self.arena, group);
        try out.append(self.arena, c);
    }
    return out.toOwnedSlice(self.arena);
}

fn bigIntFormatWithOptions(self: *Interpreter, big: *value.Object, loc: []const u8, ro: *value.Object) value.HostError![]const u8 {
    var s = try value.bigIntToString(big, self.arena);
    const neg = s.len > 0 and s[0] == '-';
    if (neg) s = s[1..];
    if (ro.getOwn("style")) |sv| if (sv.isString() and std.mem.eql(u8, sv.asStr(), "percent")) {
        s = try std.fmt.allocPrint(self.arena, "{s}00", .{s});
    };
    if (ro.getOwn("maximumSignificantDigits")) |msv| if (msv.isNumber()) {
        s = try bigIntRoundSignificant(self, s, @intFromFloat(msv.asNum()));
    };
    const syms = localeNumberSymbols(loc);
    const grouped = try bigIntGroupedDecimal(self, s, loc, syms.group);
    var buf: std.ArrayListUnmanaged(u8) = .empty;
    if (neg) try buf.appendSlice(self.arena, syms.minus);
    try buf.appendSlice(self.arena, grouped);
    if (ro.getOwn("minimumFractionDigits")) |mfv| if (mfv.isNumber()) {
        const n: usize = @intFromFloat(mfv.asNum());
        if (n > 0) {
            try buf.appendSlice(self.arena, syms.decimal);
            for (0..n) |_| try buf.append(self.arena, '0');
        }
    };
    if (ro.getOwn("style")) |sv| if (sv.isString() and std.mem.eql(u8, sv.asStr(), "percent")) {
        if (loc.len >= 2 and loc[0] == 'd' and loc[1] == 'e') try buf.appendSlice(self.arena, "\xc2\xa0");
        try buf.appendSlice(self.arena, syms.percent);
    };
    return buf.toOwnedSlice(self.arena);
}

fn bigIntToLocaleStringFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const big = if (this.isObject() and this.asObj().is_bigint) this.asObj() else if (this.isObject() and this.asObj().prim != null and this.asObj().prim.?.isObject() and this.asObj().prim.?.asObj().is_bigint) this.asObj().prim.?.asObj() else return self.throwError("TypeError", "BigInt.prototype.toLocaleString requires that 'this' be a BigInt");
    const locs = try canonicalizeLocaleList(self, if (args.len > 0) args[0] else Value.undef());
    const loc = if (locs.elements.items.len > 0) locs.elements.items[0].asStr() else "en";
    const ro = try nfProcessOptions(self, if (args.len > 1) args[1] else Value.undef());
    return Value.str(try bigIntFormatWithOptions(self, big, loc, ro));
}

/// `BigInt.prototype.toString(radix)` — the BigInt rendered in `radix` (2..36).
fn bigIntToStringFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const big = if (this.isObject() and this.asObj().is_bigint) this.asObj() else if (this.isObject() and this.asObj().prim != null and this.asObj().prim.?.isObject() and this.asObj().prim.?.asObj().is_bigint) this.asObj().prim.?.asObj() else return self.throwError("TypeError", "BigInt.prototype.toString requires that 'this' be a BigInt");
    const radix: u8 = if (args.len > 0 and !args[0].isUndefined()) @intFromFloat(@trunc(try self.toNumberV(args[0]))) else 10;
    if (radix < 2 or radix > 36) return self.throwError("RangeError", "toString() radix must be between 2 and 36");
    if (big.bigint_text != null and radix == 10) return Value.str(big.bigint_text.?);
    if (big.bigint_text != null) return self.throwError("RangeError", "BigInt value is too large for non-decimal radix conversion");
    return Value.str(try formatBigIntRadix(self.arena, big.bigint, radix));
}

fn bigIntValueOfFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = args;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (this.isObject() and this.asObj().is_bigint) return this;
    // A BigInt wrapper object (`Object(1n)`) unwraps to its boxed BigInt.
    if (this.isObject() and this.asObj().prim != null and this.asObj().prim.?.isObject() and this.asObj().prim.?.asObj().is_bigint) return this.asObj().prim.?;
    return self.throwError("TypeError", "BigInt.prototype.valueOf requires that 'this' be a BigInt");
}

/// StringToBigInt as a bignum, or null when the string is not a valid BigInt
/// (the relational operators treat that as the "undefined" result rather than
/// throwing). Mirrors the BigInt() string grammar: trim, then `0x`/`0o`/`0b`
/// radix literals or an optionally-signed decimal; empty ⇒ 0n.
fn stringToBigIntManaged(arena: std.mem.Allocator, s: []const u8) error{OutOfMemory}!?std.math.big.int.Managed {
    const t = std.mem.trim(u8, s, " \t\r\n\x0b\x0c\u{00a0}\u{feff}");
    var canon: ?[]const u8 = null;
    if (t.len == 0) {
        canon = "0";
    } else if (t.len > 2 and t[0] == '0' and (t[1] == 'x' or t[1] == 'X')) {
        canon = try canonicalBigIntRadixString(arena, t[2..], 16);
    } else if (t.len > 2 and t[0] == '0' and (t[1] == 'o' or t[1] == 'O')) {
        canon = try canonicalBigIntRadixString(arena, t[2..], 8);
    } else if (t.len > 2 and t[0] == '0' and (t[1] == 'b' or t[1] == 'B')) {
        canon = try canonicalBigIntRadixString(arena, t[2..], 2);
    } else {
        canon = try canonicalBigIntDecimalString(arena, t);
    }
    const cs = canon orelse return null;
    var out = try std.math.big.int.Managed.init(arena);
    out.setString(10, cs) catch |err| switch (err) {
        error.OutOfMemory => return error.OutOfMemory,
        else => return null,
    };
    return out;
}

/// Exact order of `(big, y)` for a finite f64 `y`. Decomposes `y = (±)M·2^E`
/// with integer significand M and integer exponent E, then compares integers —
/// shifting whichever side keeps both integral — so no precision is lost
/// regardless of magnitude (handles `Number.MAX_VALUE`, subnormals, ±0).
fn bigVsFiniteF64(arena: std.mem.Allocator, big: *std.math.big.int.Managed, y: f64) error{OutOfMemory}!std.math.Order {
    const bits: u64 = @bitCast(y);
    const neg = (bits >> 63) != 0;
    const exp_field: u64 = (bits >> 52) & 0x7FF;
    const frac: u64 = bits & 0xF_FFFF_FFFF_FFFF;
    var m: u64 = undefined;
    var e: i64 = undefined;
    if (exp_field == 0) {
        m = frac; // subnormal (also covers ±0, where m = 0)
        e = -1074;
    } else {
        m = frac | (@as(u64, 1) << 52);
        e = @as(i64, @intCast(exp_field)) - 1075;
    }
    var mb = try std.math.big.int.Managed.initSet(arena, m);
    if (neg) mb.negate();
    if (e >= 0) {
        var ms = try std.math.big.int.Managed.init(arena);
        try ms.shiftLeft(&mb, @intCast(e));
        return big.toConst().order(ms.toConst());
    }
    // E < 0: y may be fractional. Compare big·2^(-E) against M (both integers).
    var a = try std.math.big.int.Managed.init(arena);
    try a.shiftLeft(big, @intCast(-e));
    return a.toConst().order(mb.toConst());
}

fn managedBigIntFromObject(arena: std.mem.Allocator, big: *value.Object) error{OutOfMemory}!std.math.big.int.Managed {
    var out = try std.math.big.int.Managed.init(arena);
    if (big.bigint_text) |s| {
        out.setString(10, s) catch |err| switch (err) {
            error.OutOfMemory => return error.OutOfMemory,
            else => unreachable,
        };
    } else {
        try out.set(big.bigint);
    }
    return out;
}

fn makeBigIntFromManaged(self: *Interpreter, managed: *const std.math.big.int.Managed) EvalError!Value {
    if (managed.toInt(i128)) |small| {
        return self.makeBigInt(small);
    } else |_| {}
    const text = managed.toString(self.arena, 10, .lower) catch |err| switch (err) {
        error.OutOfMemory => return error.OutOfMemory,
        else => unreachable,
    };
    return self.makeBigIntText(text);
}

pub fn negateBigIntObject(self: *Interpreter, big: *value.Object) EvalError!Value {
    if (big.bigint_text == null) return self.makeBigInt(-%big.bigint);
    var input = try managedBigIntFromObject(self.arena, big);
    input.negate();
    return makeBigIntFromManaged(self, &input);
}

pub fn bitNotBigIntObject(self: *Interpreter, big: *value.Object) EvalError!Value {
    if (big.bigint_text == null) return self.makeBigInt(~big.bigint);
    var input = try managedBigIntFromObject(self.arena, big);
    input.negate();
    var out = try std.math.big.int.Managed.init(self.arena);
    try out.addScalar(&input, -1);
    return makeBigIntFromManaged(self, &out);
}

/// `BigInt.asIntN(bits, x)` / `asUintN(bits, x)` — wrap into a 2's-complement
/// signed / unsigned `bits`-bit integer.
fn bigIntAsIntNFn(comptime signed: bool) value.NativeFn {
    return struct {
        fn call(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
            _ = this;
            const self: *Interpreter = @ptrCast(@alignCast(ctx));
            // ToIndex(bits) first (the Number coercion runs valueOf and rejects a
            // Symbol/BigInt), then ToBigInt(x) (which rejects a Number) — matching
            // the spec's step order.
            const bits_f = if (args.len > 0) try self.toNumberV(args[0]) else 0;
            const bits_int = if (std.math.isNan(bits_f)) 0 else @trunc(bits_f);
            if (bits_int < 0 or bits_int > 9007199254740991.0) return self.throwError("RangeError", "BigInt.asIntN bit count is out of range");
            const bits_count: u64 = @intFromFloat(bits_int);
            const xv = try self.toBigIntValueImpl(if (args.len > 1) args[1] else Value.undef(), false);
            if (bits_count == 0) return self.makeBigInt(if (signed) 0 else 0);
            const bit_count: usize = std.math.cast(usize, bits_count) orelse
                return self.throwError("RangeError", "BigInt.asIntN bit count is out of range");
            var input = try managedBigIntFromObject(self.arena, xv.asObj());
            const sgn: std.builtin.Signedness = if (signed) .signed else .unsigned;
            const ic = input.toConst();
            // If the requested width already covers the operand, the result is the
            // operand unchanged, so skip the truncate — `std.math.big`'s truncate
            // allocates ~bit_count/64 limbs, which for a near-2^53 width is a
            // multi-petabyte request that returns error.OutOfMemory. That error is
            // not JS-catchable (only error.Throw is), so it crashes the host instead
            // of letting the script's try/catch see a RangeError. For unsigned this
            // no-op also requires a non-negative operand (a negative always wraps).
            if ((signed or ic.positive) and bit_count >= ic.bitCountTwosCompForSignedness(sgn))
                return makeBigIntFromManaged(self, &input);
            var truncated = try std.math.big.int.Managed.init(self.arena);
            try truncated.truncate(&input, sgn, bit_count);
            return makeBigIntFromManaged(self, &truncated);
        }
    }.call;
}

// ===== DataView =====================================================

/// ToIndex(v): ToIntegerOrInfinity, then RangeError outside [0, 2^53-1]. The
/// Number coercion runs valueOf/toString (so a Symbol/BigInt throws), matching
/// the spec's argument-coercion order.
fn toIndexArg(self: *Interpreter, v: Value) EvalError!u64 {
    if (v.isUndefined()) return 0;
    const n = try self.toNumberV(v);
    const i = if (std.math.isNan(n)) 0 else @trunc(n);
    if (i < 0 or i > 9007199254740991.0) return self.throwError("RangeError", "index out of range");
    return @intFromFloat(i);
}

const DVType = struct { name: []const u8, bytes: u8, signed: bool, float: bool, big: bool };
const dv_types = [_]DVType{
    .{ .name = "Int8", .bytes = 1, .signed = true, .float = false, .big = false },
    .{ .name = "Uint8", .bytes = 1, .signed = false, .float = false, .big = false },
    .{ .name = "Int16", .bytes = 2, .signed = true, .float = false, .big = false },
    .{ .name = "Uint16", .bytes = 2, .signed = false, .float = false, .big = false },
    .{ .name = "Int32", .bytes = 4, .signed = true, .float = false, .big = false },
    .{ .name = "Uint32", .bytes = 4, .signed = false, .float = false, .big = false },
    .{ .name = "Float16", .bytes = 2, .signed = true, .float = true, .big = false },
    .{ .name = "Float32", .bytes = 4, .signed = true, .float = true, .big = false },
    .{ .name = "Float64", .bytes = 8, .signed = true, .float = true, .big = false },
    .{ .name = "BigInt64", .bytes = 8, .signed = true, .float = false, .big = true },
    .{ .name = "BigUint64", .bytes = 8, .signed = false, .float = false, .big = true },
};

/// `new DataView(buffer, byteOffset?, byteLength?)`.
fn dataViewConstructorFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (self.new_target.isUndefined()) return self.throwError("TypeError", "Constructor DataView requires 'new'");
    const buf_v = if (args.len > 0) args[0] else Value.undef();
    if (!buf_v.isObject() or buf_v.asObj().array_buffer == null) return self.throwError("TypeError", "First argument to DataView must be an ArrayBuffer");
    const ab = buf_v.asObj().array_buffer.?;
    const offset = try toIndexArg(self, if (args.len > 1) args[1] else Value.undef());
    if (ab.isDetached()) return self.throwError("TypeError", "ArrayBuffer is detached");
    const buf_len = ab.bytes().len;
    if (offset > buf_len) return self.throwError("RangeError", "Start offset is outside the bounds of the buffer");
    var view_len: usize = buf_len - @as(usize, @intCast(offset));
    // Omitting byteLength on a resizable buffer makes the view length-tracking.
    const track = (args.len <= 2 or args[2].isUndefined()) and ab.max_byte_length != null;
    if (args.len > 2 and !args[2].isUndefined()) {
        const vl = try toIndexArg(self, args[2]);
        if (ab.isDetached()) return self.throwError("TypeError", "ArrayBuffer is detached");
        if (offset + vl > @as(u64, @intCast(ab.bytes().len))) return self.throwError("RangeError", "Invalid DataView length");
        view_len = @intCast(vl);
    }
    const o = (try self.newObject()).asObj();
    if (self.new_target.isObject()) o.setProtoAtomic(try self.ctorRealmIntrinsicProto(self.new_target.asObj(), "DataView"));
    // The detached/out-of-bounds re-check after OrdinaryCreateFromConstructor is
    // spec'd: reading newTarget.prototype can run user code that detaches or
    // resizes the buffer.
    if (ab.isDetached()) return self.throwError("TypeError", "ArrayBuffer is detached");
    const live_len = ab.bytes().len;
    if (offset > live_len) return self.throwError("RangeError", "Start offset is outside the bounds of the buffer");
    if (!track and offset + @as(u64, @intCast(view_len)) > @as(u64, @intCast(live_len)))
        return self.throwError("RangeError", "Invalid DataView length");
    const dv = try o.dataViewAllocator(self.arena).create(value.DataViewData);
    dv.* = .{ .buffer = buf_v.asObj(), .byte_offset = @intCast(offset), .byte_length = view_len, .track_length = track };
    o.data_view = dv;
    return Value.obj(o);
}

/// A `DataView.prototype.get<Type>(byteOffset, littleEndian)` accessor.
fn dataViewGetFn(comptime t: DVType) value.NativeFn {
    return struct {
        fn call(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
            const self: *Interpreter = @ptrCast(@alignCast(ctx));
            if (!this.isObject() or this.asObj().data_view == null) return self.throwError("TypeError", "DataView.prototype.get" ++ t.name ++ " requires a DataView receiver");
            const dv = this.asObj().data_view.?;
            const get_index = try toIndexArg(self, if (args.len > 0) args[0] else Value.undef());
            const little = if (args.len > 1) args[1].toBoolean() else false;
            const ab = dv.buffer.array_buffer.?;
            const view_len = dv.currentByteLength() orelse return self.throwError("TypeError", "DataView is detached or out of bounds");
            if (get_index + t.bytes > view_len) return self.throwError("RangeError", "Offset is outside the bounds of the DataView");
            const off = dv.byte_offset + @as(usize, @intCast(get_index));
            const endian: std.builtin.Endian = if (little) .little else .big;
            const UInt = switch (t.bytes) {
                1 => u8,
                2 => u16,
                4 => u32,
                else => u64,
            };
            const raw = std.mem.readInt(UInt, ab.bytes()[off..][0..t.bytes], endian);
            if (t.big) {
                if (t.signed) return self.makeBigInt(@as(i64, @bitCast(@as(u64, raw))));
                return self.makeBigInt(@as(i128, @as(u64, raw)));
            }
            if (t.float) {
                if (t.bytes == 2) return Value.num(@floatCast(@as(f16, @bitCast(@as(u16, raw)))));
                if (t.bytes == 4) return Value.num(@floatCast(@as(f32, @bitCast(@as(u32, raw)))));
                return Value.num(@bitCast(@as(u64, raw)));
            }
            if (t.signed) {
                const SInt = switch (t.bytes) {
                    1 => i8,
                    2 => i16,
                    4 => i32,
                    else => i64,
                };
                return Value.num(@floatFromInt(@as(SInt, @bitCast(raw))));
            }
            return Value.num(@floatFromInt(raw));
        }
    }.call;
}

/// A `DataView.prototype.set<Type>(byteOffset, value, littleEndian)` mutator.
fn dataViewSetFn(comptime t: DVType) value.NativeFn {
    return struct {
        fn call(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
            const self: *Interpreter = @ptrCast(@alignCast(ctx));
            if (!this.isObject() or this.asObj().data_view == null) return self.throwError("TypeError", "DataView.prototype.set" ++ t.name ++ " requires a DataView receiver");
            const dv = this.asObj().data_view.?;
            // SetViewValue checks IsImmutableBuffer before coercing the index/value.
            if (dv.buffer.array_buffer.?.immutable) return self.throwError("TypeError", "Cannot modify a DataView backed by an immutable ArrayBuffer");
            const get_index = try toIndexArg(self, if (args.len > 0) args[0] else Value.undef());
            const val = if (args.len > 1) args[1] else Value.undef();
            // Coerce the value (ToBigInt for the Big types, else ToNumber) before
            // the bounds/detach check, per SetViewValue.
            var num: f64 = 0;
            var big: i128 = 0;
            if (t.big) {
                const bv = try self.toBigIntValueImpl(val, false);
                big = bv.asObj().bigint;
            } else {
                num = try self.toNumberV(val);
            }
            const little = if (args.len > 2) args[2].toBoolean() else false;
            const ab = dv.buffer.array_buffer.?;
            const view_len = dv.currentByteLength() orelse return self.throwError("TypeError", "DataView is detached or out of bounds");
            if (get_index + t.bytes > view_len) return self.throwError("RangeError", "Offset is outside the bounds of the DataView");
            const off = dv.byte_offset + @as(usize, @intCast(get_index));
            const endian: std.builtin.Endian = if (little) .little else .big;
            const UInt = switch (t.bytes) {
                1 => u8,
                2 => u16,
                4 => u32,
                else => u64,
            };
            var raw: UInt = undefined;
            if (t.big) {
                raw = @truncate(@as(u128, @bitCast(big))); // low `bytes*8` bits (two's complement)
            } else if (t.float) {
                if (t.bytes == 2) {
                    raw = @bitCast(@as(f16, @floatCast(num)));
                } else if (t.bytes == 4) {
                    raw = @bitCast(@as(f32, @floatCast(num)));
                } else {
                    raw = @bitCast(num);
                }
            } else {
                raw = numToRaw(UInt, num);
            }
            std.mem.writeInt(UInt, ab.bytes()[off..][0..t.bytes], raw, endian);
            return Value.undef();
        }
    }.call;
}

/// ToIntXX/ToUintXX truncation for a DataView integer store (NaN/±Inf → 0, wrap
/// modulo 2^bits), returning the raw unsigned bit pattern.
fn numToRaw(comptime UInt: type, num: f64) UInt {
    if (std.math.isNan(num) or std.math.isInf(num)) return 0;
    const bits = @bitSizeOf(UInt);
    const two_pow: f64 = std.math.pow(f64, 2, @floatFromInt(bits));
    var m = @mod(@trunc(num), two_pow);
    if (m < 0) m += two_pow;
    return @intFromFloat(m);
}

fn dataViewBufferGetter(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = args;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (!this.isObject() or this.asObj().data_view == null) return self.throwError("TypeError", "DataView.prototype.buffer requires a DataView receiver");
    return Value.obj(this.asObj().data_view.?.buffer);
}

fn dataViewByteLengthGetter(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = args;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (!this.isObject() or this.asObj().data_view == null) return self.throwError("TypeError", "DataView.prototype.byteLength requires a DataView receiver");
    const dv = this.asObj().data_view.?;
    // get byteLength throws when the view is detached or out of bounds.
    const cur = dv.currentByteLength() orelse return self.throwError("TypeError", "DataView is detached or out of bounds");
    return Value.num(@floatFromInt(cur));
}

fn dataViewByteOffsetGetter(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = args;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (!this.isObject() or this.asObj().data_view == null) return self.throwError("TypeError", "DataView.prototype.byteOffset requires a DataView receiver");
    const dv = this.asObj().data_view.?;
    // get byteOffset throws when the view is detached or out of bounds.
    if (dv.currentByteLength() == null) return self.throwError("TypeError", "DataView is detached or out of bounds");
    return Value.num(@floatFromInt(dv.byte_offset));
}

/// Install `DataView` (constructor + prototype get/set accessors and methods).
// ===== Iterator + Iterator Helpers (ES2025) ==========================

/// Build a lazy iterator-helper object (`map`/`filter`/…) wrapping `src`.
fn makeIterHelper(self: *Interpreter, src: Value, kind: value.IterHelper.Kind, func: Value, limit: f64) EvalError!Value {
    const o = (try self.newObject()).asObj();
    const h = try gc_mod.allocIterHelper(self.arena);
    h.* = .{ .src = src, .kind = kind, .func = func, .limit = limit };
    // GetIteratorDirect: capture the source iterator's `next` method once at
    // creation (the concat/zip kinds hold an array of iterables, not a single
    // iterator, so they capture per-source instead).
    switch (kind) {
        .concat, .zip, .zip_keyed => {},
        else => if (src.isObject()) {
            h.next_method = try self.getProperty(src, "next");
        },
    }
    o.iter_helper = h;
    if (self.env.get("\x00IterHelperProto")) |p| if (p.isObject()) {
        o.setProtoAtomic(p.asObj());
    };
    return Value.obj(o);
}

/// `next` for a lazy iterator helper: pulls from the underlying iterator and
/// applies the helper's transform.
fn iterHelperNextFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = args;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (!this.isObject() or this.asObj().iter_helper == null) return self.throwError("TypeError", "Iterator Helper next called on an incompatible receiver");
    const h = this.asObj().iter_helper.?;
    // GeneratorValidate: re-entering an already-executing helper (e.g. its
    // mapper calls back into next()) is a TypeError, not a stack RangeError.
    if (h.running) return self.throwError("TypeError", "Iterator Helper is already running");
    if (h.done) return self.iterResultObj(Value.undef(), true);
    h.running = true;
    defer h.running = false;
    switch (h.kind) {
        .wrap => {
            const s = try self.iterStepM(h.src, h.next_method);
            if (s.done) {
                h.done = true;
                return self.iterResultObj(Value.undef(), true);
            }
            return self.iterResultObj(s.value, false);
        },
        .map => {
            const s = try self.iterStepM(h.src, h.next_method);
            if (s.done) {
                h.done = true;
                return self.iterResultObj(Value.undef(), true);
            }
            const mapped = self.callValueWithThis(h.func, &.{ s.value, Value.num(h.counter) }, Value.undef()) catch |e| {
                if (e == error.Throw) {
                    h.done = true;
                    self.iteratorCloseKeepingThrow(h.src);
                }
                return e;
            };
            h.counter += 1;
            return self.iterResultObj(mapped, false);
        },
        .filter => {
            while (true) {
                const s = try self.iterStepM(h.src, h.next_method);
                if (s.done) {
                    h.done = true;
                    return self.iterResultObj(Value.undef(), true);
                }
                const keep = (self.callValueWithThis(h.func, &.{ s.value, Value.num(h.counter) }, Value.undef()) catch |e| {
                    if (e == error.Throw) {
                        h.done = true;
                        self.iteratorCloseKeepingThrow(h.src);
                    }
                    return e;
                }).toBoolean();
                h.counter += 1;
                if (keep) return self.iterResultObj(s.value, false);
            }
        },
        .take => {
            if (h.counter >= h.limit) {
                h.done = true;
                // Reaching the limit closes the underlying iterator (IteratorClose).
                try self.iteratorClose(h.src);
                return self.iterResultObj(Value.undef(), true);
            }
            const s = try self.iterStepM(h.src, h.next_method);
            if (s.done) {
                h.done = true;
                return self.iterResultObj(Value.undef(), true);
            }
            h.counter += 1;
            return self.iterResultObj(s.value, false);
        },
        .drop => {
            if (!h.started) {
                h.started = true;
                while (h.counter < h.limit) : (h.counter += 1) {
                    const s = try self.iterStepM(h.src, h.next_method);
                    if (s.done) {
                        h.done = true;
                        return self.iterResultObj(Value.undef(), true);
                    }
                }
            }
            const s = try self.iterStepM(h.src, h.next_method);
            if (s.done) {
                h.done = true;
                return self.iterResultObj(Value.undef(), true);
            }
            return self.iterResultObj(s.value, false);
        },
        .flat_map => {
            while (true) {
                if (h.inner == null) {
                    const s = try self.iterStepM(h.src, h.next_method);
                    if (s.done) {
                        h.done = true;
                        return self.iterResultObj(Value.undef(), true);
                    }
                    const mapped = self.callValueWithThis(h.func, &.{ s.value, Value.num(h.counter) }, Value.undef()) catch |e| {
                        if (e == error.Throw) {
                            h.done = true;
                            self.iteratorCloseKeepingThrow(h.src);
                        }
                        return e;
                    };
                    h.counter += 1;
                    // GetIteratorFlattenable(mapped, reject-primitives): a primitive
                    // (including a primitive string) is a TypeError; an abrupt
                    // completion closes the source iterator.
                    h.inner = self.getIteratorFlattenableObj(mapped) catch |e| {
                        if (e == error.Throw) {
                            h.done = true;
                            self.iteratorCloseKeepingThrow(h.src);
                        }
                        return e;
                    };
                    h.inner_next = if (h.inner.?.isObject()) try self.getProperty(h.inner.?, "next") else Value.undef();
                }
                const is = try self.iterStepM(h.inner.?, h.inner_next);
                if (is.done) {
                    h.inner = null;
                    continue;
                }
                return self.iterResultObj(is.value, false);
            }
        },
        .concat => {
            // `h.src` is a JS array of the source iterables; `counter` is the next
            // source index and `inner` the iterator currently being drained.
            h.started = true; // the generator has run (→ "suspended-yield")
            const srcs = h.src.asObj();
            while (true) {
                if (h.inner == null) {
                    const idx: usize = @intFromFloat(h.counter);
                    if (idx >= srcs.elements.items.len) {
                        h.done = true;
                        return self.iterResultObj(Value.undef(), true);
                    }
                    h.counter += 1;
                    // Open the source with its pre-captured @@iterator method.
                    const it = try self.callValueWithThis(h.func.asObj().elements.items[idx], &.{}, srcs.elements.items[idx]);
                    if (!it.isObject()) return self.throwError("TypeError", "Iterator.concat: @@iterator did not return an object");
                    h.inner = it;
                }
                const is = try self.iterStep(h.inner.?);
                if (is.done) {
                    h.inner = null;
                    continue;
                }
                return self.iterResultObj(is.value, false);
            }
        },
        .zip, .zip_keyed => {
            // `src` = opened iterators; `inner` = per-source removed flags (true =
            // openIters[i] is null); `limit` = mode (0 shortest, 1 longest, 2
            // strict); `padding` = per-source padding (longest); `func` = key
            // array (zip_keyed). Implements the IteratorZip abstract closure.
            h.started = true; // the generator has run (→ "suspended-yield")
            const iters = h.src.asObj().elements.items;
            const flags = h.inner.?.asObj();
            const n = iters.len;
            if (n == 0) {
                h.done = true;
                return self.iterResultObj(Value.undef(), true);
            }
            const mode: u8 = @intFromFloat(h.limit);
            const results = (try self.newArray()).asObj();
            try results.elements.ensureTotalCapacity(results.elementsAllocator(self.arena), n);
            var i: usize = 0;
            while (i < n) : (i += 1) {
                if (flags.elements.items[i].toBoolean()) {
                    // openIters[i] is null — longest padding.
                    const pad = if (h.padding.isObject() and i < h.padding.asObj().elements.items.len) h.padding.asObj().elements.items[i] else Value.undef();
                    try results.elements.append(results.elementsAllocator(self.arena), pad);
                    continue;
                }
                // IteratorStepValue(openIters[i]); an abrupt completion closes the
                // remaining open iterators (reverse order) and propagates.
                const s = self.iterStep(iters[i]) catch {
                    flags.elements.items[i] = Value.boolVal(true);
                    h.done = true;
                    try zipCloseAll(self, iters, flags, true);
                    return error.Throw;
                };
                if (!s.done) {
                    try results.elements.append(results.elementsAllocator(self.arena), s.value);
                    continue;
                }
                // The source is done — remove it from openIters.
                flags.elements.items[i] = Value.boolVal(true);
                switch (mode) {
                    0 => { // shortest: close the rest and finish.
                        h.done = true;
                        try zipCloseAll(self, iters, flags, false);
                        return self.iterResultObj(Value.undef(), true);
                    },
                    2 => { // strict: every source must end together.
                        h.done = true;
                        if (i != 0) {
                            self.exception = try self.makeError("TypeError", "Iterator.zip: strict mode requires all iterators to have the same length");
                            try zipCloseAll(self, iters, flags, true);
                            return error.Throw;
                        }
                        // i == 0: each remaining source must also be done now.
                        var k: usize = 1;
                        while (k < n) : (k += 1) {
                            if (flags.elements.items[k].toBoolean()) continue;
                            const kdone = self.iterStepDoneOnly(iters[k]) catch {
                                flags.elements.items[k] = Value.boolVal(true);
                                try zipCloseAll(self, iters, flags, true);
                                return error.Throw;
                            };
                            if (!kdone) {
                                self.exception = try self.makeError("TypeError", "Iterator.zip: strict mode requires all iterators to have the same length");
                                try zipCloseAll(self, iters, flags, true);
                                return error.Throw;
                            }
                            flags.elements.items[k] = Value.boolVal(true);
                        }
                        return self.iterResultObj(Value.undef(), true);
                    },
                    else => { // longest: pad this slot and continue.
                        const pad = if (h.padding.isObject() and i < h.padding.asObj().elements.items.len) h.padding.asObj().elements.items[i] else Value.undef();
                        try results.elements.append(results.elementsAllocator(self.arena), pad);
                    },
                }
            }
            // Longest mode: finish once every source has been removed.
            var all_null = true;
            for (flags.elements.items[0..n]) |f| {
                if (!f.toBoolean()) {
                    all_null = false;
                    break;
                }
            }
            if (all_null) {
                h.done = true;
                return self.iterResultObj(Value.undef(), true);
            }
            if (h.kind == .zip) return self.iterResultObj(Value.obj(results), false);
            // zip_keyed: OrdinaryObjectCreate(null) with one data property per
            // key (CreateDataPropertyOrThrow → writable/enumerable/configurable).
            const keys = h.func.asObj().elements.items;
            const obj = (try self.newObject()).asObj();
            obj.setProtoAtomic(null);
            var k: usize = 0;
            while (k < keys.len and k < results.elements.items.len) : (k += 1) {
                try self.setProp(obj, keys[k].asStr(), results.elements.items[k]);
            }
            return self.iterResultObj(Value.obj(obj), false);
        },
    }
}

/// IteratorCloseAll(openIters, completion): close every non-removed iterator in
/// reverse list order. When `pending` is true a throw completion is already in
/// flight (its value in `self.exception`) — any error from a `return()` call is
/// swallowed and the original throw re-raised. When false the completion is
/// normal — the first close error becomes the completion and is raised.
fn zipCloseAll(self: *Interpreter, iters: []Value, flags: *value.Object, pending: bool) EvalError!void {
    var thrown = pending;
    var pending_val: Value = if (pending) self.exception else Value.undef();
    var i: usize = iters.len;
    while (i > 0) {
        i -= 1;
        if (i < flags.elements.items.len and flags.elements.items[i].toBoolean()) continue;
        if (thrown) {
            self.iteratorClose(iters[i]) catch {};
            self.exception = pending_val; // a throw completion discards close errors
        } else {
            self.iteratorClose(iters[i]) catch {
                thrown = true;
                pending_val = self.exception;
            };
        }
    }
    if (thrown) {
        self.exception = pending_val;
        return error.Throw;
    }
}

fn iterHelperReturnFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = args;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (!this.isObject() or this.asObj().iter_helper == null)
        return self.throwError("TypeError", "Iterator Helper return called on an incompatible receiver");
    const h = this.asObj().iter_helper.?;
    // GeneratorValidate: a re-entrant return() while the helper is mid-close
    // (state "executing") is a TypeError.
    if (h.running) return self.throwError("TypeError", "Iterator Helper is already running");
    const was_done = h.done;
    h.done = true;
    // A WrapForValidIterator forwards return() to its underlying iterator and
    // returns THAT result (or {undefined, done:true} when there is no return()).
    if (h.kind == .wrap) {
        if (was_done or !h.src.isObject()) return self.iterResultObj(Value.undef(), true);
        const ret = try self.getProperty(h.src, "return");
        if (ret.isUndefined() or ret.isNull()) return self.iterResultObj(Value.undef(), true);
        if (!ret.isCallable()) return self.throwError("TypeError", "iterator return is not callable");
        return try self.callValueWithThis(ret, &.{}, h.src);
    }
    // An IteratorHelper closes its source iterator(s) and yields {undefined, done}.
    if (!was_done) {
        switch (h.kind) {
            // zip closes every still-open source via IteratorCloseAll (reverse
            // order, normal completion → a return() error propagates). The
            // `running` guard makes a re-entrant next() from a source's return()
            // a TypeError (GeneratorValidate sees the "executing" state).
            .zip, .zip_keyed => {
                if (h.src.isObject() and h.inner != null and h.inner.?.isObject()) {
                    // "suspended-yield" (already started) → state is "executing"
                    // during the close, so a re-entrant call throws TypeError.
                    // "suspended-start" (never stepped) → state is "completed",
                    // so a re-entrant call just returns {undefined, done:true}.
                    h.running = h.started;
                    defer h.running = false;
                    try zipCloseAll(self, h.src.asObj().elements.items, h.inner.?.asObj(), false);
                }
                return self.iterResultObj(Value.undef(), true);
            },
            // concat closes the iterator it is currently draining; the running
            // guard makes a re-entrant return() from that close a TypeError.
            .concat => {
                if (h.inner) |inner| if (inner.isObject() and inner.asObj().iter_helper == null) {
                    h.running = h.started;
                    defer h.running = false;
                    try self.iteratorClose(inner);
                };
                return self.iterResultObj(Value.undef(), true);
            },
            else => if (h.src.isObject()) try self.iteratorClose(h.src),
        }
        if (h.inner) |inner| if (inner.isObject() and inner.asObj().iter_helper == null) try self.iteratorClose(inner);
    }
    return self.iterResultObj(Value.undef(), true);
}

// --- the lazy helper methods on %Iterator.prototype% -----------------

fn iterMapFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (!this.isObject()) return self.throwError("TypeError", "Iterator.prototype.map called on a non-object");
    const f = if (args.len > 0) args[0] else Value.undef();
    if (!f.isCallable()) {
        self.iteratorClose(this) catch {};
        return self.throwError("TypeError", "Iterator.prototype.map: mapper is not a function");
    }
    return makeIterHelper(self, this, .map, f, 0);
}
fn iterFilterFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (!this.isObject()) return self.throwError("TypeError", "Iterator.prototype.filter called on a non-object");
    const f = if (args.len > 0) args[0] else Value.undef();
    if (!f.isCallable()) {
        self.iteratorClose(this) catch {};
        return self.throwError("TypeError", "Iterator.prototype.filter: predicate is not a function");
    }
    return makeIterHelper(self, this, .filter, f, 0);
}
fn iterFlatMapFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (!this.isObject()) return self.throwError("TypeError", "Iterator.prototype.flatMap called on a non-object");
    const f = if (args.len > 0) args[0] else Value.undef();
    if (!f.isCallable()) {
        self.iteratorClose(this) catch {};
        return self.throwError("TypeError", "Iterator.prototype.flatMap: mapper is not a function");
    }
    return makeIterHelper(self, this, .flat_map, f, 0);
}
/// Validate the `limit`/`count` argument of take/drop: ToNumber (closing `this`
/// on an abrupt completion), then ToIntegerOrInfinity, requiring NaN→RangeError
/// and a non-negative result (the truncation happens before the `< 0` check, so
/// `-0.5` yields 0, not a RangeError). Closes `this` before any RangeError.
fn iterLimitArg(self: *Interpreter, this: Value, arg_v: Value, comptime who: []const u8) EvalError!f64 {
    const n = self.toNumberV(arg_v) catch |e| {
        if (e == error.Throw) self.iteratorCloseKeepingThrow(this);
        return e;
    };
    if (std.math.isNan(n)) {
        self.iteratorClose(this) catch {};
        return self.throwError("RangeError", who ++ ": invalid count");
    }
    const lim = @trunc(n); // ToIntegerOrInfinity (-0.5 → -0, which is not < 0)
    if (lim < 0) {
        self.iteratorClose(this) catch {};
        return self.throwError("RangeError", who ++ ": invalid count");
    }
    return lim;
}
fn iterTakeFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (!this.isObject()) return self.throwError("TypeError", "Iterator.prototype.take called on a non-object");
    const lim = try iterLimitArg(self, this, if (args.len > 0) args[0] else Value.undef(), "Iterator.prototype.take");
    return makeIterHelper(self, this, .take, Value.undef(), lim);
}
fn iterDropFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (!this.isObject()) return self.throwError("TypeError", "Iterator.prototype.drop called on a non-object");
    const lim = try iterLimitArg(self, this, if (args.len > 0) args[0] else Value.undef(), "Iterator.prototype.drop");
    return makeIterHelper(self, this, .drop, Value.undef(), lim);
}

// --- the eager helper methods (consume `this`) -----------------------

fn iterToArrayFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = args;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (!this.isObject()) return self.throwError("TypeError", "Iterator.prototype.toArray called on a non-object");
    // GetIteratorDirect captures `next` once (a `next` accessor runs a single time).
    const next_method = try self.getProperty(this, "next");
    const arr = (try self.newArray()).asObj();
    while (true) {
        const s = try self.iterStepM(this, next_method);
        if (s.done) break;
        try arr.elements.append(arr.elementsAllocator(self.arena), s.value);
    }
    return Value.obj(arr);
}
fn iterForEachFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (!this.isObject()) return self.throwError("TypeError", "Iterator.prototype.forEach called on a non-object");
    const f = if (args.len > 0) args[0] else Value.undef();
    if (!f.isCallable()) {
        self.iteratorClose(this) catch {};
        return self.throwError("TypeError", "Iterator.prototype.forEach: fn is not a function");
    }
    const next_method = try self.getProperty(this, "next");
    var i: f64 = 0;
    while (true) : (i += 1) {
        const s = try self.iterStepM(this, next_method);
        if (s.done) break;
        _ = self.callValueWithThis(f, &.{ s.value, Value.num(i) }, Value.undef()) catch |e| {
            if (e == error.Throw) self.iteratorCloseKeepingThrow(this);
            return e;
        };
    }
    return Value.undef();
}
fn iterReduceFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (!this.isObject()) return self.throwError("TypeError", "Iterator.prototype.reduce called on a non-object");
    const f = if (args.len > 0) args[0] else Value.undef();
    if (!f.isCallable()) {
        self.iteratorClose(this) catch {};
        return self.throwError("TypeError", "Iterator.prototype.reduce: reducer is not a function");
    }
    const next_method = try self.getProperty(this, "next");
    var acc: Value = undefined;
    var i: f64 = 0;
    if (args.len > 1) {
        acc = args[1];
    } else {
        const s = try self.iterStepM(this, next_method);
        if (s.done) return self.throwError("TypeError", "Reduce of empty iterator with no initial value");
        acc = s.value;
        i = 1;
    }
    while (true) : (i += 1) {
        const s = try self.iterStepM(this, next_method);
        if (s.done) break;
        acc = self.callValueWithThis(f, &.{ acc, s.value, Value.num(i) }, Value.undef()) catch |e| {
            if (e == error.Throw) self.iteratorCloseKeepingThrow(this);
            return e;
        };
    }
    return acc;
}
fn iterSomeEveryFindFn(comptime which: enum { some, every, find }) value.NativeFn {
    return struct {
        fn call(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
            const self: *Interpreter = @ptrCast(@alignCast(ctx));
            if (!this.isObject()) return self.throwError("TypeError", "Iterator.prototype method called on a non-object");
            const f = if (args.len > 0) args[0] else Value.undef();
            if (!f.isCallable()) {
                // IteratorClose(O, ThrowCompletion): a non-callable predicate
                // closes the underlying iterator before the TypeError propagates.
                self.iteratorClose(this) catch {};
                return self.throwError("TypeError", "Iterator.prototype method: fn is not a function");
            }
            const next_method = try self.getProperty(this, "next");
            var i: f64 = 0;
            while (true) : (i += 1) {
                const s = try self.iterStepM(this, next_method);
                if (s.done) break;
                const tv = self.callValueWithThis(f, &.{ s.value, Value.num(i) }, Value.undef()) catch |e| {
                    if (e == error.Throw) self.iteratorCloseKeepingThrow(this);
                    return e;
                };
                const t = tv.toBoolean();
                switch (which) {
                    .some => if (t) {
                        try self.iteratorClose(this);
                        return Value.boolVal(true);
                    },
                    .every => if (!t) {
                        try self.iteratorClose(this);
                        return Value.boolVal(false);
                    },
                    .find => if (t) {
                        try self.iteratorClose(this);
                        return s.value;
                    },
                }
            }
            return switch (which) {
                .some => Value.boolVal(false),
                .every => Value.boolVal(true),
                .find => Value.undef(),
            };
        }
    }.call;
}

fn iterProtoSymbolIteratorFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = ctx;
    _ = args;
    return this; // %IteratorPrototype%[@@iterator] returns the iterator itself
}

/// %IteratorPrototype%[@@dispose]: call `this.return()` (if present); undefined.
fn iterProtoDisposeFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = args;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const ret = try self.getProperty(this, "return");
    if (ret.isObject() and ret.asObj().isCallableObject()) _ = try self.callValueWithThis(ret, &.{}, this);
    return Value.undef();
}

/// %AsyncIteratorPrototype%[@@asyncDispose]: a promise that calls (and awaits)
/// `this.return()` if present, then fulfills with undefined.
fn asyncIterProtoDisposeFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = args;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const pobj = try promise.newPromise(self);
    const p = promise.promiseOf(Value.obj(pobj)).?;
    const ret = self.getProperty(this, "return") catch {
        promise.reject(self, p, self.exception) catch {};
        return Value.obj(pobj);
    };
    if (ret.isObject() and ret.asObj().isCallableObject()) {
        const r = self.callValueWithThis(ret, &.{}, this) catch {
            promise.reject(self, p, self.exception) catch {};
            return Value.obj(pobj);
        };
        _ = self.awaitValue(r) catch {
            promise.reject(self, p, self.exception) catch {};
            return Value.obj(pobj);
        };
    }
    promise.resolve(self, p, Value.undef()) catch {};
    return Value.obj(pobj);
}

/// Install a well-known-symbol-keyed method whose `name` is the spec display
/// form (e.g. "[Symbol.dispose]") rather than the encoded key.
fn installSymbolMethod(a: std.mem.Allocator, rs: *Shape, obj: *value.Object, key: []const u8, display: []const u8, len: usize, f: value.NativeFn) EvalError!void {
    try setNative(a, rs, obj, key, len, f);
    if (obj.getOwn(key)) |mv| if (mv.isObject()) {
        try mv.asObj().setOwn(a, rs, "name", Value.str(display));
        try mv.asObj().setAttr(a, "name", .{ .writable = false, .enumerable = false, .configurable = true });
    };
}

/// `Iterator.from(O)`: wrap an iterator/iterable so the helper methods apply.
fn iteratorFromFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const o = if (args.len > 0) args[0] else Value.undef();
    // GetIteratorFlattenable(O, iterate-string-primitives): among primitives only a
    // String is accepted (Symbol/BigInt are object-boxed here, so reject them too).
    if (!o.isObject()) {
        if (!o.isString()) return self.throwError("TypeError", "Iterator.from: argument is not iterable");
    } else if (o.asObj().is_symbol or o.asObj().is_bigint) {
        return self.throwError("TypeError", "Iterator.from: argument is not iterable");
    }
    // method = GetMethod(O, @@iterator): an undefined method means O is itself the
    // iterator; otherwise Call(method, O) yields the iterator. Reads run getters in
    // spec order (@@iterator before next).
    var iterator: Value = o;
    if (self.wellKnownSymbolKey("iterator")) |ikey| {
        const method = try self.getProperty(o, ikey);
        if (!method.isUndefined() and !method.isNull()) {
            if (!method.isCallable()) return self.throwError("TypeError", "Iterator.from: @@iterator is not callable");
            iterator = try self.callValueWithThis(method, &.{}, o);
        }
    }
    if (!iterator.isObject() or iterator.asObj().is_symbol or iterator.asObj().is_bigint)
        return self.throwError("TypeError", "Iterator.from: the iterator is not an object");
    // If the iterator already inherits from %Iterator.prototype%, return it as-is;
    // otherwise wrap it (WrapForValidIteratorPrototype).
    if (self.env.get("Iterator")) |ic| if (ic.isObject()) {
        if (ic.asObj().getOwn("prototype")) |ip| if (ip.isObject()) {
            var cur: ?*value.Object = iterator.asObj().proto;
            while (cur) |c| : (cur = c.protoAtomic()) if (c == ip.asObj()) return iterator;
        };
    };
    return makeIterHelper(self, iterator, .wrap, Value.undef(), 0);
}

/// `Iterator.concat(...items)` — an iterator yielding all values of each
/// iterable argument in order. Each argument must be an iterable object.
fn iteratorConcatFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const srcs = (try self.newArray()).asObj();
    const methods = (try self.newArray()).asObj();
    const ikey = self.wellKnownSymbolKey("iterator") orelse "";
    // Validate every argument up front, in order: each must be an Object whose
    // @@iterator (GetMethod, read exactly once now) is callable.
    for (args) |arg_v| {
        if (!arg_v.isObject()) return self.throwError("TypeError", "Iterator.concat: each argument must be an object");
        const method = try self.getProperty(arg_v, ikey);
        if (method.isUndefined() or method.isNull() or !method.isCallable())
            return self.throwError("TypeError", "Iterator.concat: each argument must have a callable @@iterator");
        try srcs.elements.append(srcs.elementsAllocator(self.arena), arg_v);
        try methods.elements.append(methods.elementsAllocator(self.arena), method);
    }
    // The captured @@iterator methods ride in `func` for the .concat consumer.
    return makeIterHelper(self, Value.obj(srcs), .concat, Value.obj(methods), 0);
}

/// Read the shared `{ mode, padding }` options of `Iterator.zip`/`zipKeyed`.
/// Returns the mode (0 shortest, 1 longest, 2 strict). `padding_out` receives
/// the raw `padding` value (undefined if absent or mode != longest).
fn zipReadMode(self: *Interpreter, options: Value, padding_out: *Value) EvalError!u8 {
    padding_out.* = Value.undef();
    if (options.isUndefined()) return 0;
    if (!options.isObject() or options.asObj().is_bigint or options.asObj().is_symbol)
        return self.throwError("TypeError", "Iterator.zip: options must be an object");
    const mv = try self.getProperty(options, "mode");
    var mode: u8 = 0;
    if (!mv.isUndefined()) {
        // The mode is compared by value (no ToString): only the primitive
        // strings "shortest"/"longest"/"strict" are accepted.
        if (!mv.isString()) return self.throwError("TypeError", "Iterator.zip: mode must be 'shortest', 'longest', or 'strict'");
        const ms = mv.asStr();
        if (std.mem.eql(u8, ms, "shortest")) {
            mode = 0;
        } else if (std.mem.eql(u8, ms, "longest")) {
            mode = 1;
        } else if (std.mem.eql(u8, ms, "strict")) {
            mode = 2;
        } else return self.throwError("TypeError", "Iterator.zip: mode must be 'shortest', 'longest', or 'strict'");
    }
    if (mode == 1) padding_out.* = try self.getProperty(options, "padding");
    return mode;
}

/// `Iterator.zip(iterables[, options])` — yields arrays of one value pulled
/// from each input iterable per step. Modes: shortest (default), longest
/// (pad), strict (equal lengths required).
fn iteratorZipFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const iterables = if (args.len > 0) args[0] else Value.undef();
    if (!iterables.isObject() or iterables.asObj().is_bigint or iterables.asObj().is_symbol)
        return self.throwError("TypeError", "Iterator.zip: iterables must be an object");
    var padding: Value = Value.undef();
    const mode = try zipReadMode(self, if (args.len > 1) args[1] else Value.undef(), &padding);

    // GetIterator(iterables, sync): a strict `@@iterator` lookup (no array-like
    // fallback). Then drain it, flattening each yielded value into an iterator.
    const iters = (try self.newArray()).asObj();
    const ik = self.symbolIteratorKey();
    const method: Value = if (ik) |k| try self.getProperty(iterables, k) else Value.undef();
    if (method.isUndefined() or method.isNull() or !method.isObject() or !method.asObj().isCallableObject())
        return self.throwError("TypeError", "Iterator.zip: iterables is not iterable");
    const input_iter = try self.callValueWithThis(method, &.{}, iterables);
    if (!input_iter.isObject()) return self.throwError("TypeError", "Iterator.zip: iterator is not an object");
    const next_method = try self.getProperty(input_iter, "next");
    if (!next_method.isObject() or !next_method.asObj().isCallableObject())
        return self.throwError("TypeError", "Iterator.zip: iterator.next is not callable");
    while (true) {
        // IteratorStepValue(inputIter). An abrupt completion runs
        // IfAbruptCloseIterators(next, iters): close every opened input (reverse
        // order) but NOT inputIter, then re-raise.
        const r = self.callValueWithThis(next_method, &.{}, input_iter) catch {
            self.closeListKeepingThrow(iters.elements.items);
            return error.Throw;
        };
        if (!r.isObject()) {
            self.exception = try self.makeError("TypeError", "Iterator.zip: iterator result is not an object");
            self.closeListKeepingThrow(iters.elements.items);
            return error.Throw;
        }
        const dn = (self.getProperty(r, "done") catch {
            self.closeListKeepingThrow(iters.elements.items);
            return error.Throw;
        }).toBoolean();
        if (dn) break;
        const item = self.getProperty(r, "value") catch {
            self.closeListKeepingThrow(iters.elements.items);
            return error.Throw;
        };
        // GetIteratorFlattenable(item) abrupt → IfAbruptCloseIterators over the
        // list-concatenation « inputIter » ++ iters (reverse): iters then input.
        const sub = self.getIteratorFlattenableObj(item) catch {
            self.closeListKeepingThrow(iters.elements.items);
            self.iteratorCloseKeepingThrow(input_iter);
            return error.Throw;
        };
        try iters.elements.append(iters.elementsAllocator(self.arena), sub);
    }
    // Per-source padding aligned to iterator order (longest mode only): pull
    // exactly `iterCount` values from the padding iterable, padding short. Any
    // abrupt completion here closes the opened inputs (reverse) and re-raises.
    const pad_arr = buildZipPadding(self, mode, padding, iters.elements.items.len) catch {
        self.closeListKeepingThrow(iters.elements.items);
        return error.Throw;
    };
    return makeZipHelper(self, .zip, iters, Value.undef(), mode, pad_arr);
}

/// `Iterator.zipKeyed(iterables[, options])` — like zip but `iterables` is an
/// object whose own enumerable keys name the inputs; each step yields an object.
fn iteratorZipKeyedFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const iterables = if (args.len > 0) args[0] else Value.undef();
    if (!iterables.isObject() or iterables.asObj().is_bigint or iterables.asObj().is_symbol)
        return self.throwError("TypeError", "Iterator.zipKeyed: iterables must be an object");
    var padding: Value = Value.undef();
    const mode = try zipReadMode(self, if (args.len > 1) args[1] else Value.undef(), &padding);
    // Longest-mode padding must be undefined or an Object (validated up front,
    // independent of how many keys `iterables` has).
    if (mode == 1 and !padding.isUndefined() and (!padding.isObject() or padding.asObj().is_bigint or padding.asObj().is_symbol))
        return self.throwError("TypeError", "Iterator.zipKeyed: padding must be an object");

    const keys = (try self.newArray()).asObj();
    const iters = (try self.newArray()).asObj();
    // [[OwnPropertyKeys]] snapshot, then per key: [[GetOwnProperty]] (enumerable
    // check), [[Get]] (value), GetIteratorFlattenable. Both string and symbol
    // keys participate. An abrupt completion closes opened inputs (reverse).
    const all_keys = try self.objectOwnKeysList(iterables.asObj());
    for (all_keys) |key| {
        const en = self.objectProtoPropertyIsEnumerable(iterables.asObj(), key) catch {
            self.closeListKeepingThrow(iters.elements.items);
            return error.Throw;
        };
        if (!en) continue;
        const v = self.getProperty(iterables, key) catch {
            self.closeListKeepingThrow(iters.elements.items);
            return error.Throw;
        };
        // An `undefined` value excludes the key entirely (no result property).
        if (v.isUndefined()) continue;
        const sub = self.getIteratorFlattenableObj(v) catch {
            self.closeListKeepingThrow(iters.elements.items);
            return error.Throw;
        };
        try keys.elements.append(keys.elementsAllocator(self.arena), Value.str(key));
        try iters.elements.append(iters.elementsAllocator(self.arena), sub);
    }
    // Per-key padding (longest mode): Get(padding, key) for each key, or all
    // undefined when padding is absent.
    var pad_arr: Value = Value.undef();
    if (mode == 1) {
        const pads = (try self.newArray()).asObj();
        for (keys.elements.items) |kv| {
            if (padding.isObject()) {
                const pv = self.getProperty(padding, kv.asStr()) catch {
                    self.closeListKeepingThrow(iters.elements.items);
                    return error.Throw;
                };
                try pads.elements.append(pads.elementsAllocator(self.arena), pv);
            } else try pads.elements.append(pads.elementsAllocator(self.arena), Value.undef());
        }
        pad_arr = Value.obj(pads);
    }
    return makeZipHelper(self, .zip_keyed, iters, Value.obj(keys), mode, pad_arr);
}

/// Build the per-source padding list for `Iterator.zip` longest mode: pull
/// exactly `n` values from the padding iterable (`reject-primitives`), padding
/// any shortfall with undefined and closing the iterator if not exhausted.
/// Returns `Value.undef()` for non-longest modes or an n-length array otherwise.
fn buildZipPadding(self: *Interpreter, mode: u8, padding: Value, n: usize) EvalError!Value {
    if (mode != 1) return Value.undef();
    const pads = (try self.newArray()).asObj();
    if (padding.isUndefined()) {
        var i: usize = 0;
        while (i < n) : (i += 1) try pads.elements.append(pads.elementsAllocator(self.arena), Value.undef());
        return Value.obj(pads);
    }
    if (!padding.isObject() or padding.asObj().is_bigint or padding.asObj().is_symbol)
        return self.throwError("TypeError", "Iterator.zip: padding must be an object");
    // GetIterator(padding, sync): strict — a missing @@iterator is a TypeError.
    const ik = self.symbolIteratorKey();
    const method: Value = if (ik) |k| try self.getProperty(padding, k) else Value.undef();
    if (method.isUndefined() or method.isNull() or !method.isObject() or !method.asObj().isCallableObject())
        return self.throwError("TypeError", "Iterator.zip: padding is not iterable");
    const pit = try self.callValueWithThis(method, &.{}, padding);
    if (!pit.isObject()) return self.throwError("TypeError", "Iterator.zip: padding iterator is not an object");
    // GetIteratorDirect captures `next` once (so an accessor runs a single time).
    const pnext = try self.getProperty(pit, "next");
    var exhausted = false;
    var i: usize = 0;
    while (i < n) : (i += 1) {
        if (exhausted) {
            try pads.elements.append(pads.elementsAllocator(self.arena), Value.undef());
            continue;
        }
        const s = try self.iterStepM(pit, pnext);
        if (s.done) {
            exhausted = true;
            try pads.elements.append(pads.elementsAllocator(self.arena), Value.undef());
        } else try pads.elements.append(pads.elementsAllocator(self.arena), s.value);
    }
    // Close the padding iterator (normal completion) if it still has values.
    if (!exhausted) try self.iteratorClose(pit);
    return Value.obj(pads);
}

/// Build a zip/zipKeyed iterator-helper object with its per-source done flags.
fn makeZipHelper(self: *Interpreter, kind: value.IterHelper.Kind, iters: *value.Object, keys: Value, mode: u8, padding: Value) EvalError!Value {
    const flags = (try self.newArray()).asObj();
    for (iters.elements.items) |_| try flags.elements.append(flags.elementsAllocator(self.arena), Value.boolVal(false));
    const o = (try self.newObject()).asObj();
    const h = try gc_mod.allocIterHelper(self.arena);
    h.* = .{ .src = Value.obj(iters), .kind = kind, .func = keys, .limit = @floatFromInt(mode), .inner = Value.obj(flags), .padding = padding };
    o.iter_helper = h;
    if (self.env.get("\x00IterHelperProto")) |p| if (p.isObject()) {
        o.setProtoAtomic(p.asObj());
    };
    return Value.obj(o);
}

/// `Iterator` is abstract — `new Iterator()` directly throws.
fn iteratorConstructorFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    _ = args;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (self.new_target.isUndefined()) return self.throwError("TypeError", "Constructor Iterator requires 'new'");
    // Abstract: cannot be constructed unless subclassed (new.target !== Iterator).
    if (self.new_target.isObject()) {
        if (self.env.get("Iterator")) |ic| if (ic.isObject() and self.new_target.asObj() == ic.asObj())
            return self.throwError("TypeError", "Abstract class Iterator not directly constructable");
    }
    const o = (try self.newObject()).asObj();
    o.setProtoAtomic(try self.ctorRealmIntrinsicProto(self.new_target.asObj(), "Iterator"));
    return Value.obj(o);
}

/// Install `%IteratorPrototype%`, `%IteratorHelperPrototype%`, the `Iterator`
/// global, and `Iterator.from`.
/// `%GeneratorPrototype%`.next/return/throw (and the async variants): brand-check
/// a generator receiver and drive it. Normal `gen.next()` uses the callMethod
/// fast path; these exist as real own properties for reflection / `.call`.
fn genProtoMethod(comptime which: enum { next, ret, throw }) value.NativeFn {
    return struct {
        fn call(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
            const self: *Interpreter = @ptrCast(@alignCast(ctx));
            if (!this.isObject() or this.asObj().gen == null)
                return self.throwError("TypeError", "method called on an incompatible receiver");
            const v: Value = if (args.len > 0) args[0] else Value.undef();
            return switch (which) {
                .next => vm.genNext(self, this.asObj(), v),
                .ret => vm.genReturn(self, this.asObj(), v),
                .throw => vm.genThrow(self, this.asObj(), v),
            };
        }
    }.call;
}

/// Async-generator next/return/throw: unlike the sync forms, a bad receiver
/// (not an async generator) yields a *rejected promise* rather than a synchronous
/// throw.
fn asyncGenProtoMethod(comptime which: enum { next, ret, throw }) value.NativeFn {
    return struct {
        fn call(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
            const self: *Interpreter = @ptrCast(@alignCast(ctx));
            if (!this.isObject() or this.asObj().gen == null or !vm.asyncGenObj(this.asObj())) {
                const pobj = try promise.newPromise(self);
                const p = promise.promiseOf(Value.obj(pobj)).?;
                const err = try self.makeError("TypeError", "AsyncGenerator method called on an incompatible receiver");
                try promise.reject(self, p, err);
                return Value.obj(pobj);
            }
            const v: Value = if (args.len > 0) args[0] else Value.undef();
            return switch (which) {
                .next => vm.genNext(self, this.asObj(), v),
                .ret => vm.genReturn(self, this.asObj(), v),
                .throw => vm.genThrow(self, this.asObj(), v),
            };
        }
    }.call;
}

/// The shared setter for %Iterator.prototype%'s `constructor` and
/// `@@toStringTag` accessors: reject a non-object receiver or the home object
/// (%Iterator.prototype%, which emulates a non-writable data property), then
/// write an own property on the receiver — CreateDataPropertyOrThrow when absent
/// or Set when present (both bypass this inherited accessor).
fn iterProtoAccessorSet(self: *Interpreter, this: Value, key: []const u8, v: Value) EvalError!Value {
    const home: ?*value.Object = if (self.env.get("\x00IterProto")) |h|
        (if (h.isObject()) h.asObj() else null)
    else
        null;
    return setterIgnoringProto(self, this, home, key, v);
}
fn iterProtoCtorGetterFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    _ = args;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    return self.env.get("Iterator") orelse Value.undef();
}
fn iterProtoCtorSetterFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    return iterProtoAccessorSet(self, this, "constructor", if (args.len > 0) args[0] else Value.undef());
}
fn iterProtoTagGetterFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = ctx;
    _ = this;
    _ = args;
    return Value.str("Iterator");
}
fn iterProtoTagSetterFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const key = symbolToStringTagKey(self) orelse return Value.undef();
    return iterProtoAccessorSet(self, this, key, if (args.len > 0) args[0] else Value.undef());
}
/// Install an accessor with a native getter and setter (non-enumerable,
/// configurable), naming them `get <display>` / `set <display>` per spec.
fn setNativeGetSet(a: std.mem.Allocator, rs: *Shape, obj: *value.Object, key: []const u8, comptime display: []const u8, getf: value.NativeFn, setf: value.NativeFn) EvalError!void {
    const g = try gc_mod.allocObj(a);
    g.* = .{ .native = getf };
    try installNativeProps(a, rs, g, "get " ++ display, 0);
    const s = try gc_mod.allocObj(a);
    s.* = .{ .native = setf };
    try installNativeProps(a, rs, s, "set " ++ display, 1);
    try obj.setAccessor(a, key, Value.obj(g), Value.obj(s));
    try obj.setAttr(a, key, .{ .enumerable = false, .configurable = true });
}

fn installIterator(env: *Environment, rs: *Shape, object_proto: *value.Object) EvalError!void {
    const a = env.arena;
    const sym_iter: ?[]const u8 = blk: {
        if (env.get("Symbol")) |sym| if (sym.isObject()) {
            if (sym.asObj().getOwn("iterator")) |t| if (t.isObject() and t.asObj().is_symbol) break :blk t.asObj().sym_key;
        };
        break :blk null;
    };
    const sym_tag: ?[]const u8 = blk: {
        if (env.get("Symbol")) |sym| if (sym.isObject()) {
            if (sym.asObj().getOwn("toStringTag")) |t| if (t.isObject() and t.asObj().is_symbol) break :blk t.asObj().sym_key;
        };
        break :blk null;
    };

    const sym_dispose: ?[]const u8 = blk: {
        if (env.get("Symbol")) |sym| if (sym.isObject()) {
            if (sym.asObj().getOwn("dispose")) |t| if (t.isObject() and t.asObj().is_symbol) break :blk t.asObj().sym_key;
        };
        break :blk null;
    };

    // %IteratorPrototype%.
    const iter_proto = try gc_mod.allocObj(a);
    iter_proto.* = .{ .proto = object_proto };
    if (sym_iter) |k| try installSymbolMethod(a, rs, iter_proto, k, "[Symbol.iterator]", 0, iterProtoSymbolIteratorFn);
    if (sym_dispose) |k| try installSymbolMethod(a, rs, iter_proto, k, "[Symbol.dispose]", 0, iterProtoDisposeFn);
    inline for (.{
        .{ "map", iterMapFn },         .{ "filter", iterFilterFn },
        .{ "take", iterTakeFn },       .{ "drop", iterDropFn },
        .{ "flatMap", iterFlatMapFn }, .{ "reduce", iterReduceFn },
        .{ "forEach", iterForEachFn },
    }) |m| try setNative(a, rs, iter_proto, m[0], 1, m[1]);
    try setNative(a, rs, iter_proto, "toArray", 0, iterToArrayFn); // toArray() takes no args
    try setNative(a, rs, iter_proto, "some", 1, iterSomeEveryFindFn(.some));
    try setNative(a, rs, iter_proto, "every", 1, iterSomeEveryFindFn(.every));
    try setNative(a, rs, iter_proto, "find", 1, iterSomeEveryFindFn(.find));
    try env.put("\x00IterProto", Value.obj(iter_proto));

    // %GeneratorPrototype% (proto %IteratorPrototype%): the shared prototype of
    // every generator instance — next/return/throw own methods and a
    // @@toStringTag of "Generator".
    {
        const gen_proto = try gc_mod.allocObj(a);
        gen_proto.* = .{ .proto = iter_proto };
        try setNative(a, rs, gen_proto, "next", 1, genProtoMethod(.next));
        try setNative(a, rs, gen_proto, "return", 1, genProtoMethod(.ret));
        try setNative(a, rs, gen_proto, "throw", 1, genProtoMethod(.throw));
        if (sym_tag) |k| {
            try gen_proto.setOwn(a, rs, k, Value.str("Generator"));
            try gen_proto.setAttr(a, k, .{ .writable = false, .enumerable = false, .configurable = true });
        }
        try env.put("\x00GenProto", Value.obj(gen_proto));
    }

    // Per-kind built-in iterator prototypes (%ArrayIteratorPrototype% etc.): each
    // protos to %IteratorPrototype%, carries the shared cursor `next`, and a
    // @@toStringTag naming the kind.
    inline for (.{
        .{ "\x00ArrIterProto", "Array Iterator" },
        .{ "\x00MapIterProto", "Map Iterator" },
        .{ "\x00SetIterProto", "Set Iterator" },
        .{ "\x00StrIterProto", "String Iterator" },
    }) |kp| {
        const kproto = try gc_mod.allocObj(a);
        kproto.* = .{ .proto = iter_proto };
        try setNative(a, rs, kproto, "next", 0, cursorIterNext);
        if (sym_tag) |k| {
            try kproto.setOwn(a, rs, k, Value.str(kp[1]));
            try kproto.setAttr(a, k, .{ .writable = false, .enumerable = false, .configurable = true });
        }
        try env.put(kp[0], Value.obj(kproto));
    }

    // %RegExpStringIteratorPrototype% (proto %IteratorPrototype%): the lazy
    // iterator returned by String.prototype.matchAll / RegExp.prototype[@@matchAll].
    {
        const re_iter_proto = try gc_mod.allocObj(a);
        re_iter_proto.* = .{ .proto = iter_proto };
        try setNative(a, rs, re_iter_proto, "next", 0, regexpStringIterNext);
        if (sym_tag) |k| {
            try re_iter_proto.setOwn(a, rs, k, Value.str("RegExp String Iterator"));
            try re_iter_proto.setAttr(a, k, .{ .writable = false, .enumerable = false, .configurable = true });
        }
        try env.put("\x00ReStrIterProto", Value.obj(re_iter_proto));
    }

    // %IteratorHelperPrototype% (proto %IteratorPrototype%): next + return, plus
    // a @@toStringTag of "Iterator Helper".
    const helper_proto = try gc_mod.allocObj(a);
    helper_proto.* = .{ .proto = iter_proto };
    try setNative(a, rs, helper_proto, "next", 0, iterHelperNextFn);
    try setNative(a, rs, helper_proto, "return", 0, iterHelperReturnFn);
    if (sym_tag) |k| {
        try helper_proto.setOwn(a, rs, k, Value.str("Iterator Helper"));
        try helper_proto.setAttr(a, k, .{ .writable = false, .enumerable = false, .configurable = true });
    }
    try env.put("\x00IterHelperProto", Value.obj(helper_proto));

    // The `Iterator` constructor (abstract) with `.prototype` = %IteratorProto%.
    const ctor = try gc_mod.allocObj(a);
    ctor.* = .{ .native = iteratorConstructorFn, .native_ctor = true, .private_data = @ptrCast(env) };
    try installNativeProps(a, rs, ctor, "Iterator", 0);
    try setNative(a, rs, ctor, "from", 1, iteratorFromFn);
    try setNative(a, rs, ctor, "concat", 0, iteratorConcatFn);
    try setNative(a, rs, ctor, "zip", 1, iteratorZipFn);
    try setNative(a, rs, ctor, "zipKeyed", 1, iteratorZipKeyedFn);
    try ctor.setOwn(a, rs, "prototype", Value.obj(iter_proto));
    try ctor.setAttr(a, "prototype", .{ .writable = false, .enumerable = false, .configurable = false });
    try env.put("Iterator", Value.obj(ctor));
    // %IteratorPrototype%.constructor and [@@toStringTag] are accessor properties
    // (not data) in the iterator-helpers proposal: the getter yields the value
    // and the shared setter lets a subclass shadow it while protecting the home.
    try setNativeGetSet(a, rs, iter_proto, "constructor", "constructor", iterProtoCtorGetterFn, iterProtoCtorSetterFn);
    if (sym_tag) |k|
        try setNativeGetSet(a, rs, iter_proto, k, "[Symbol.toStringTag]", iterProtoTagGetterFn, iterProtoTagSetterFn);
}

// ===== AsyncIterator helpers =========================================
// The async analogue of the Iterator-helpers family. Built on the engine's
// synchronous-settling promise model: each helper's `next` returns a promise
// that is computed eagerly (driving the awaited sub-promises to settlement via
// `awaitValue`) and then resolved/rejected.

/// Pull one step from an async iterator: `await it.next()` then read
/// `{ value, done }` (value is itself awaited, matching async-iteration).
fn asyncIterStep(self: *Interpreter, it: Value) EvalError!struct { done: bool, value: Value } {
    const r0 = try self.callMethod(it, "next", &.{});
    const r = try self.awaitValue(r0);
    if (!r.isObject()) return self.throwError("TypeError", "iterator result is not an object");
    const done = (try self.getProperty(r, "done")).toBoolean();
    const val = if (done) Value.undef() else try self.awaitValue(try self.getProperty(r, "value"));
    return .{ .done = done, .value = val };
}

/// Produce the next `{ done, value }` of an async iterator helper, driving the
/// underlying async iterator and any callback to settlement.
fn asyncHelperProduce(self: *Interpreter, h: *value.IterHelper) EvalError!struct { done: bool, value: Value } {
    switch (h.kind) {
        .wrap => {
            const s = try asyncIterStep(self, h.src);
            if (s.done) {
                h.done = true;
                return .{ .done = true, .value = Value.undef() };
            }
            return .{ .done = false, .value = s.value };
        },
        .map => {
            const s = try asyncIterStep(self, h.src);
            if (s.done) {
                h.done = true;
                return .{ .done = true, .value = Value.undef() };
            }
            const mapped = try self.awaitValue(try self.callValueWithThis(h.func, &.{ s.value, Value.num(h.counter) }, Value.undef()));
            h.counter += 1;
            return .{ .done = false, .value = mapped };
        },
        .filter => {
            while (true) {
                const s = try asyncIterStep(self, h.src);
                if (s.done) {
                    h.done = true;
                    return .{ .done = true, .value = Value.undef() };
                }
                const keep = (try self.awaitValue(try self.callValueWithThis(h.func, &.{ s.value, Value.num(h.counter) }, Value.undef()))).toBoolean();
                h.counter += 1;
                if (keep) return .{ .done = false, .value = s.value };
            }
        },
        .take => {
            if (h.counter >= h.limit) {
                h.done = true;
                return .{ .done = true, .value = Value.undef() };
            }
            const s = try asyncIterStep(self, h.src);
            if (s.done) {
                h.done = true;
                return .{ .done = true, .value = Value.undef() };
            }
            h.counter += 1;
            return .{ .done = false, .value = s.value };
        },
        .drop => {
            if (!h.started) {
                h.started = true;
                while (h.counter < h.limit) : (h.counter += 1) {
                    const s = try asyncIterStep(self, h.src);
                    if (s.done) {
                        h.done = true;
                        return .{ .done = true, .value = Value.undef() };
                    }
                }
            }
            const s = try asyncIterStep(self, h.src);
            if (s.done) {
                h.done = true;
                return .{ .done = true, .value = Value.undef() };
            }
            return .{ .done = false, .value = s.value };
        },
        .flat_map => {
            while (true) {
                if (h.inner == null) {
                    const s = try asyncIterStep(self, h.src);
                    if (s.done) {
                        h.done = true;
                        return .{ .done = true, .value = Value.undef() };
                    }
                    const mapped = try self.awaitValue(try self.callValueWithThis(h.func, &.{ s.value, Value.num(h.counter) }, Value.undef()));
                    h.counter += 1;
                    h.inner = try self.asyncIteratorOf(mapped);
                }
                const is = try asyncIterStep(self, h.inner.?);
                if (is.done) {
                    h.inner = null;
                    continue;
                }
                return .{ .done = false, .value = is.value };
            }
        },
        else => {
            h.done = true;
            return .{ .done = true, .value = Value.undef() };
        },
    }
}

fn asyncIterHelperNextFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = args;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (!this.isObject() or this.asObj().iter_helper == null) return promiseRejectValue(self, try self.makeError("TypeError", "Async iterator helper next called on an incompatible receiver"));
    const h = this.asObj().iter_helper.?;
    if (h.done) return promiseResolveValue(self, try self.iterResultObj(Value.undef(), true));
    const produced = asyncHelperProduce(self, h) catch {
        const exc = self.exception;
        self.exception = Value.undef();
        return promiseRejectValue(self, exc);
    };
    return promiseResolveValue(self, try self.iterResultObj(produced.value, produced.done));
}

fn asyncIterHelperReturnFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = args;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (this.isObject() and this.asObj().iter_helper != null) this.asObj().iter_helper.?.done = true;
    return promiseResolveValue(self, try self.iterResultObj(Value.undef(), true));
}

/// Make an async iterator-helper object wrapping `src` (already an async
/// iterator) with the given kind/callback/limit.
fn makeAsyncIterHelper(self: *Interpreter, src: Value, kind: value.IterHelper.Kind, func: Value, limit: f64) EvalError!Value {
    const o = (try self.newObject()).asObj();
    const h = try gc_mod.allocIterHelper(self.arena);
    h.* = .{ .src = src, .kind = kind, .func = func, .limit = limit, .is_async = true };
    o.iter_helper = h;
    if (self.env.get("\x00AsyncIterHelperProto")) |p| if (p.isObject()) {
        o.setProtoAtomic(p.asObj());
    };
    return Value.obj(o);
}

// --- the lazy async helper methods on %AsyncIteratorPrototype% -------

fn asyncIterMapFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (!this.isObject()) return self.throwError("TypeError", "AsyncIterator.prototype.map called on a non-object");
    const f = if (args.len > 0) args[0] else Value.undef();
    if (!f.isCallable()) return self.throwError("TypeError", "AsyncIterator.prototype.map: mapper is not a function");
    return makeAsyncIterHelper(self, this, .map, f, 0);
}
fn asyncIterFilterFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (!this.isObject()) return self.throwError("TypeError", "AsyncIterator.prototype.filter called on a non-object");
    const f = if (args.len > 0) args[0] else Value.undef();
    if (!f.isCallable()) return self.throwError("TypeError", "AsyncIterator.prototype.filter: fn is not a function");
    return makeAsyncIterHelper(self, this, .filter, f, 0);
}
fn asyncIterFlatMapFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (!this.isObject()) return self.throwError("TypeError", "AsyncIterator.prototype.flatMap called on a non-object");
    const f = if (args.len > 0) args[0] else Value.undef();
    if (!f.isCallable()) return self.throwError("TypeError", "AsyncIterator.prototype.flatMap: fn is not a function");
    return makeAsyncIterHelper(self, this, .flat_map, f, 0);
}
fn asyncIterTakeFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (!this.isObject()) return self.throwError("TypeError", "AsyncIterator.prototype.take called on a non-object");
    const n = try self.toNumberV(if (args.len > 0) args[0] else Value.undef());
    if (std.math.isNan(n) or n < 0) return self.throwError("RangeError", "AsyncIterator.prototype.take: invalid count");
    return makeAsyncIterHelper(self, this, .take, Value.undef(), @trunc(n));
}
fn asyncIterDropFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (!this.isObject()) return self.throwError("TypeError", "AsyncIterator.prototype.drop called on a non-object");
    const n = try self.toNumberV(if (args.len > 0) args[0] else Value.undef());
    if (std.math.isNan(n) or n < 0) return self.throwError("RangeError", "AsyncIterator.prototype.drop: invalid count");
    return makeAsyncIterHelper(self, this, .drop, Value.undef(), @trunc(n));
}

// --- the eager async consumer methods (return a promise) -------------

const AsyncConsumeKind = enum { to_array, for_each, reduce, some, every, find };

/// Drive an async iterator `this` to completion, collecting all values, then
/// run `body` over the collected list and resolve/reject a single promise.
fn asyncIterConsume(self: *Interpreter, this: Value, comptime which: AsyncConsumeKind, args: []const Value) value.HostError!Value {
    const result = asyncIterConsumeImpl(self, this, which, args) catch {
        const exc = self.exception;
        self.exception = Value.undef();
        return promiseRejectValue(self, exc);
    };
    return promiseResolveValue(self, result);
}

fn asyncIterConsumeImpl(self: *Interpreter, this: Value, comptime which: AsyncConsumeKind, args: []const Value) EvalError!Value {
    if (!this.isObject()) return self.throwError("TypeError", "AsyncIterator.prototype method called on a non-object");
    const f = if (args.len > 0) args[0] else Value.undef();
    if (which != .to_array and !f.isCallable()) return self.throwError("TypeError", "AsyncIterator.prototype method: fn is not a function");
    var i: f64 = 0;
    switch (which) {
        .to_array => {
            const arr = (try self.newArray()).asObj();
            while (true) {
                const s = try asyncIterStep(self, this);
                if (s.done) break;
                try arr.elements.append(arr.elementsAllocator(self.arena), s.value);
            }
            return Value.obj(arr);
        },
        .for_each => {
            while (true) : (i += 1) {
                const s = try asyncIterStep(self, this);
                if (s.done) break;
                _ = try self.awaitValue(try self.callValueWithThis(f, &.{ s.value, Value.num(i) }, Value.undef()));
            }
            return Value.undef();
        },
        .reduce => {
            var acc: Value = undefined;
            if (args.len > 1) {
                acc = args[1];
            } else {
                const s = try asyncIterStep(self, this);
                if (s.done) return self.throwError("TypeError", "Reduce of empty async iterator with no initial value");
                acc = s.value;
                i = 1;
            }
            while (true) : (i += 1) {
                const s = try asyncIterStep(self, this);
                if (s.done) break;
                acc = try self.awaitValue(try self.callValueWithThis(f, &.{ acc, s.value, Value.num(i) }, Value.undef()));
            }
            return acc;
        },
        .some, .every, .find => {
            while (true) : (i += 1) {
                const s = try asyncIterStep(self, this);
                if (s.done) break;
                const t = (try self.awaitValue(try self.callValueWithThis(f, &.{ s.value, Value.num(i) }, Value.undef()))).toBoolean();
                switch (which) {
                    .some => if (t) return Value.boolVal(true),
                    .every => if (!t) return Value.boolVal(false),
                    .find => if (t) return s.value,
                    else => unreachable,
                }
            }
            return switch (which) {
                .some => Value.boolVal(false),
                .every => Value.boolVal(true),
                .find => Value.undef(),
                else => unreachable,
            };
        },
    }
}

fn asyncIterToArrayFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    return asyncIterConsume(@ptrCast(@alignCast(ctx)), this, .to_array, args);
}
fn asyncIterForEachFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    return asyncIterConsume(@ptrCast(@alignCast(ctx)), this, .for_each, args);
}
fn asyncIterReduceFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    return asyncIterConsume(@ptrCast(@alignCast(ctx)), this, .reduce, args);
}
fn asyncIterSomeFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    return asyncIterConsume(@ptrCast(@alignCast(ctx)), this, .some, args);
}
fn asyncIterEveryFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    return asyncIterConsume(@ptrCast(@alignCast(ctx)), this, .every, args);
}
fn asyncIterFindFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    return asyncIterConsume(@ptrCast(@alignCast(ctx)), this, .find, args);
}

fn asyncIterProtoSymbolFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = ctx;
    _ = args;
    return this; // %AsyncIteratorPrototype%[@@asyncIterator] returns the iterator
}

/// `AsyncIterator.from(O)`: wrap a sync/async iterable so the helpers apply.
fn asyncIteratorFromFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const o = if (args.len > 0) args[0] else Value.undef();
    if (!o.isObject()) return self.throwError("TypeError", "AsyncIterator.from: argument is not async iterable");
    const it = try self.asyncIteratorOf(o);
    return makeAsyncIterHelper(self, it, .wrap, Value.undef(), 0);
}

fn asyncIteratorConstructorFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    _ = args;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (self.new_target.isUndefined()) return self.throwError("TypeError", "Constructor AsyncIterator requires 'new'");
    if (self.new_target.isObject()) {
        if (self.env.get("AsyncIterator")) |ic| if (ic.isObject() and self.new_target.asObj() == ic.asObj())
            return self.throwError("TypeError", "Abstract class AsyncIterator not directly constructable");
    }
    const o = (try self.newObject()).asObj();
    o.setProtoAtomic(try self.protoObject(self.new_target.asObj()));
    return Value.obj(o);
}

/// Install `%AsyncIteratorPrototype%`, `%AsyncIteratorHelperPrototype%`, and
/// the `AsyncIterator` global with `from` and the helper methods.
fn installAsyncIterator(env: *Environment, rs: *Shape, object_proto: *value.Object) EvalError!void {
    const a = env.arena;
    const sym_async_iter: ?[]const u8 = blk: {
        if (env.get("Symbol")) |sym| if (sym.isObject()) {
            if (sym.asObj().getOwn("asyncIterator")) |t| if (t.isObject() and t.asObj().is_symbol) break :blk t.asObj().sym_key;
        };
        break :blk null;
    };
    const sym_tag: ?[]const u8 = blk: {
        if (env.get("Symbol")) |sym| if (sym.isObject()) {
            if (sym.asObj().getOwn("toStringTag")) |t| if (t.isObject() and t.asObj().is_symbol) break :blk t.asObj().sym_key;
        };
        break :blk null;
    };
    const sym_async_dispose: ?[]const u8 = blk: {
        if (env.get("Symbol")) |sym| if (sym.isObject()) {
            if (sym.asObj().getOwn("asyncDispose")) |t| if (t.isObject() and t.asObj().is_symbol) break :blk t.asObj().sym_key;
        };
        break :blk null;
    };

    // %AsyncIteratorPrototype%.
    const proto = try gc_mod.allocObj(a);
    proto.* = .{ .proto = object_proto };
    if (sym_async_iter) |k| try installSymbolMethod(a, rs, proto, k, "[Symbol.asyncIterator]", 0, asyncIterProtoSymbolFn);
    if (sym_async_dispose) |k| try installSymbolMethod(a, rs, proto, k, "[Symbol.asyncDispose]", 0, asyncIterProtoDisposeFn);
    inline for (.{
        .{ "map", asyncIterMapFn },         .{ "filter", asyncIterFilterFn },
        .{ "take", asyncIterTakeFn },       .{ "drop", asyncIterDropFn },
        .{ "flatMap", asyncIterFlatMapFn }, .{ "reduce", asyncIterReduceFn },
        .{ "toArray", asyncIterToArrayFn }, .{ "forEach", asyncIterForEachFn },
        .{ "some", asyncIterSomeFn },       .{ "every", asyncIterEveryFn },
        .{ "find", asyncIterFindFn },
    }) |m| try setNative(a, rs, proto, m[0], 1, m[1]);
    try env.put("\x00AsyncIterProto", Value.obj(proto));

    // %AsyncGeneratorPrototype% (proto %AsyncIteratorPrototype%): the shared
    // prototype of every async-generator instance — next/return/throw own
    // methods and a @@toStringTag of "AsyncGenerator".
    {
        const agen_proto = try gc_mod.allocObj(a);
        agen_proto.* = .{ .proto = proto };
        try setNative(a, rs, agen_proto, "next", 1, asyncGenProtoMethod(.next));
        try setNative(a, rs, agen_proto, "return", 1, asyncGenProtoMethod(.ret));
        try setNative(a, rs, agen_proto, "throw", 1, asyncGenProtoMethod(.throw));
        if (sym_tag) |k| {
            try agen_proto.setOwn(a, rs, k, Value.str("AsyncGenerator"));
            try agen_proto.setAttr(a, k, .{ .writable = false, .enumerable = false, .configurable = true });
        }
        try env.put("\x00AsyncGenProto", Value.obj(agen_proto));
    }

    // %AsyncIteratorHelperPrototype%.
    const helper_proto = try gc_mod.allocObj(a);
    helper_proto.* = .{ .proto = proto };
    try setNative(a, rs, helper_proto, "next", 0, asyncIterHelperNextFn);
    try setNative(a, rs, helper_proto, "return", 0, asyncIterHelperReturnFn);
    if (sym_tag) |k| {
        try helper_proto.setOwn(a, rs, k, Value.str("Async Iterator Helper"));
        try helper_proto.setAttr(a, k, .{ .writable = false, .enumerable = false, .configurable = true });
    }
    try env.put("\x00AsyncIterHelperProto", Value.obj(helper_proto));

    // The `AsyncIterator` constructor (abstract).
    const ctor = try gc_mod.allocObj(a);
    ctor.* = .{ .native = asyncIteratorConstructorFn, .native_ctor = true };
    try installNativeProps(a, rs, ctor, "AsyncIterator", 0);
    try setNative(a, rs, ctor, "from", 1, asyncIteratorFromFn);
    try ctor.setOwn(a, rs, "prototype", Value.obj(proto));
    try ctor.setAttr(a, "prototype", .{ .writable = false, .enumerable = false, .configurable = false });
    try setConstructor(a, rs, proto, ctor);
    if (sym_tag) |k| {
        try proto.setOwn(a, rs, k, Value.str("AsyncIterator"));
        try proto.setAttr(a, k, .{ .writable = true, .enumerable = false, .configurable = true });
    }
    try env.put("AsyncIterator", Value.obj(ctor));
}

// ===== GeneratorFunction / AsyncFunction / AsyncGeneratorFunction ====
// The three hidden function-kind constructors, reachable only through the
// prototype chain (e.g. `Object.getPrototypeOf(function*(){}).constructor`).
// Each is a CreateDynamicFunction-style callable that parses a function of its
// kind from string arguments, and carries a prototype intrinsic whose
// [[Prototype]] is %Function.prototype% and whose `.constructor` points back.

const DynFnKind = enum { generator, async_fn, async_generator };

fn dynamicFunctionPrototypeKey(comptime kind: DynFnKind) []const u8 {
    return switch (kind) {
        .generator => "\x00GenFuncProto",
        .async_fn => "\x00AsyncFuncProto",
        .async_generator => "\x00AsyncGenFuncProto",
    };
}

fn dynamicGeneratorParamsContainYield(arena: std.mem.Allocator, source: []const u8) lex.LexError!bool {
    var lx = lex.Lexer.init(arena, source);
    while (true) {
        const t = try lx.next();
        if (t.kind == .eof) return false;
        if (t.kind == .identifier and std.mem.eql(u8, t.text, "yield")) return true;
    }
}

fn dynamicFunctionFn(comptime kind: DynFnKind) value.NativeFn {
    return struct {
        fn call(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
            _ = this;
            const self: *Interpreter = @ptrCast(@alignCast(ctx));
            var params: std.ArrayListUnmanaged(u8) = .empty;
            var body: []const u8 = "";
            if (args.len > 0) {
                var i: usize = 0;
                while (i + 1 < args.len) : (i += 1) {
                    if (i != 0) try params.append(self.arena, ',');
                    try params.appendSlice(self.arena, try self.toStringV(args[i]));
                }
                body = try self.toStringV(args[args.len - 1]);
            }
            if (kind == .generator or kind == .async_generator) {
                const has_yield = dynamicGeneratorParamsContainYield(self.arena, params.items) catch
                    return self.throwError("SyntaxError", "Function: invalid parameters or body");
                if (has_yield) return self.throwError("SyntaxError", "Function: invalid parameters or body");
            }
            const prefix = switch (kind) {
                .generator => "function* anonymous",
                .async_fn => "async function anonymous",
                .async_generator => "async function* anonymous",
            };
            const source = try std.fmt.allocPrint(self.arena, "({s}({s}\n) {{\n{s}\n}})", .{ prefix, params.items, body });
            var parser = Parser.init(self.arena, source) catch
                return self.throwError("SyntaxError", "Function: invalid parameters or body");
            const prog = parser.parseProgram() catch
                return self.throwError("SyntaxError", "Function: invalid parameters or body");
            const nt = self.new_target;
            const saved_env = self.env;
            var swapped = false;
            if (self.active_native) |callee| {
                if (callee.private_data) |pd| {
                    self.env = @ptrCast(@alignCast(pd));
                    swapped = true;
                }
            }
            defer if (swapped) {
                self.env = saved_env;
            };
            const fnval = try self.eval(prog);
            // GetPrototypeFromConstructor: a real new.target subclass overrides
            // the function object's [[Prototype]] (the default kind-prototype is
            // already installed by makeFunction).
            if (nt.isObject() and fnval.isObject()) {
                const p = try self.getProperty(nt, "prototype");
                if (p.isObject() and !p.asObj().is_symbol) {
                    fnval.asObj().proto = p.asObj();
                } else {
                    const key = dynamicFunctionPrototypeKey(kind);
                    if (try self.functionRealmIntrinsicObject(nt.asObj(), key)) |proto| {
                        fnval.asObj().proto = proto;
                    } else if (Interpreter.envIntrinsicObject(self.env, key)) |proto| {
                        fnval.asObj().proto = proto;
                    }
                }
            }
            return fnval;
        }
    }.call;
}

fn installOneFunctionKind(
    a: std.mem.Allocator,
    rs: *Shape,
    func_ctor: *value.Object,
    func_proto: *value.Object,
    sym_tag: ?[]const u8,
    env: *Environment,
    name: []const u8,
    native_fn: value.NativeFn,
    instance_proto: ?*value.Object,
) EvalError!*value.Object {
    // %XFunction.prototype% (e.g. %Generator%): [[Prototype]] %Function.prototype%.
    const kproto = try gc_mod.allocObj(a);
    kproto.* = .{ .proto = func_proto };
    // %XFunction% constructor: [[Prototype]] %Function% (the Function ctor).
    const ctor = try gc_mod.allocObj(a);
    ctor.* = .{ .native = native_fn, .native_ctor = true, .proto = func_ctor, .private_data = @ptrCast(env) };
    try installNativeProps(a, rs, ctor, name, 1);
    try ctor.setOwn(a, rs, "prototype", Value.obj(kproto));
    try ctor.setAttr(a, "prototype", .{ .writable = false, .enumerable = false, .configurable = false });
    // %XFunction.prototype%.constructor === %XFunction% ({ !w, !e, c }).
    try kproto.setOwn(a, rs, "constructor", Value.obj(ctor));
    try kproto.setAttr(a, "constructor", .{ .writable = false, .enumerable = false, .configurable = true });
    if (sym_tag) |k| {
        try kproto.setOwn(a, rs, k, Value.str(name));
        try kproto.setAttr(a, k, .{ .writable = false, .enumerable = false, .configurable = true });
    }
    if (instance_proto) |gp| {
        // %XFunction.prototype%.prototype === %XPrototype% ({ !w, !e, c }), and
        // %XPrototype%.constructor === %XFunction.prototype% ({ !w, !e, c }).
        try kproto.setOwn(a, rs, "prototype", Value.obj(gp));
        try kproto.setAttr(a, "prototype", .{ .writable = false, .enumerable = false, .configurable = true });
        try gp.setOwn(a, rs, "constructor", Value.obj(kproto));
        try gp.setAttr(a, "constructor", .{ .writable = false, .enumerable = false, .configurable = true });
    }
    return kproto;
}

fn installFunctionKinds(env: *Environment, rs: *Shape) EvalError!void {
    const a = env.arena;
    const sym_tag: ?[]const u8 = blk: {
        if (env.get("Symbol")) |sym| if (sym.isObject()) {
            if (sym.asObj().getOwn("toStringTag")) |t| if (t.isObject() and t.asObj().is_symbol) break :blk t.asObj().sym_key;
        };
        break :blk null;
    };
    const func_ctor: *value.Object = blk: {
        if (env.get("Function")) |fv| if (fv.isObject()) break :blk fv.asObj();
        return;
    };
    const func_proto: *value.Object = blk: {
        if (func_ctor.getOwn("prototype")) |pv| if (pv.isObject()) break :blk pv.asObj();
        return;
    };
    const gen_proto: ?*value.Object = blk: {
        if (env.get("\x00GenProto")) |v| if (v.isObject()) break :blk v.asObj();
        break :blk null;
    };
    const agen_proto: ?*value.Object = blk: {
        if (env.get("\x00AsyncGenProto")) |v| if (v.isObject()) break :blk v.asObj();
        break :blk null;
    };

    const genfp = try installOneFunctionKind(a, rs, func_ctor, func_proto, sym_tag, env, "GeneratorFunction", dynamicFunctionFn(.generator), gen_proto);
    try env.put("\x00GenFuncProto", Value.obj(genfp));
    const asyncfp = try installOneFunctionKind(a, rs, func_ctor, func_proto, sym_tag, env, "AsyncFunction", dynamicFunctionFn(.async_fn), null);
    try env.put("\x00AsyncFuncProto", Value.obj(asyncfp));
    const agenfp = try installOneFunctionKind(a, rs, func_ctor, func_proto, sym_tag, env, "AsyncGeneratorFunction", dynamicFunctionFn(.async_generator), agen_proto);
    try env.put("\x00AsyncGenFuncProto", Value.obj(agenfp));
}

/// CanBeHeldWeakly(v): an Object or a Symbol (a BigInt or a primitive is not).
fn canBeHeldWeakly(v: Value) bool {
    if (!v.isObject() or v.asObj().is_bigint) return false;
    if (v.asObj().is_symbol and v.asObj().getOwn("\x00forKey") != null) return false;
    return true;
}

fn weakKeyPtr(v: Value) ?*anyopaque {
    if (!v.isObject()) return null;
    return @ptrCast(v.asObj());
}

fn weakRefConstructorFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (self.new_target.isUndefined()) return self.throwError("TypeError", "Constructor WeakRef requires 'new'");
    const target = if (args.len > 0) args[0] else Value.undef();
    if (!canBeHeldWeakly(target)) return self.throwError("TypeError", "WeakRef: target must be an object or a symbol");
    const o = (try self.newObject()).asObj();
    o.is_weak_ref = true;
    o.weak_ref_target = target.asObj();
    if (try self.protoFromCtor("WeakRef")) |pr| o.setProtoAtomic(pr);
    return Value.obj(o);
}

fn weakRefDerefFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = args;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (!this.isObject() or !this.asObj().is_weak_ref) return self.throwError("TypeError", "WeakRef.prototype.deref called on a non-WeakRef");
    const target = this.asObj().weak_ref_target orelse return Value.undef();
    return Value.obj(target);
}

fn finalizationRegistryConstructorFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (self.new_target.isUndefined()) return self.throwError("TypeError", "Constructor FinalizationRegistry requires 'new'");
    const cb = if (args.len > 0) args[0] else Value.undef();
    if (!cb.isCallable()) return self.throwError("TypeError", "FinalizationRegistry: cleanup callback must be callable");
    const o = (try self.newObject()).asObj();
    o.is_finalization_registry = true;
    o.finalization_callback = cb;
    if (try self.protoFromCtor("FinalizationRegistry")) |pr| o.setProtoAtomic(pr);
    return Value.obj(o);
}

fn finRegRegisterFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (!this.isObject() or !this.asObj().is_finalization_registry) return self.throwError("TypeError", "FinalizationRegistry.prototype.register called on an incompatible receiver");
    const target = if (args.len > 0) args[0] else Value.undef();
    if (!canBeHeldWeakly(target)) return self.throwError("TypeError", "FinalizationRegistry.register: target must be an object or a symbol");
    const held = if (args.len > 1) args[1] else Value.undef();
    if (value.strictEquals(target, held)) return self.throwError("TypeError", "FinalizationRegistry.register: target and held value must not be the same");
    const token = if (args.len > 2) args[2] else Value.undef();
    if (!token.isUndefined() and !canBeHeldWeakly(token)) return self.throwError("TypeError", "FinalizationRegistry.register: unregister token must be an object or a symbol");
    gc_mod.barrierValue(held); // strong held value stored into the live registry cell
    try this.asObj().finRecordAppend(self.arena, .{
        .target = weakKeyPtr(target),
        .held = held,
        .token = if (token.isUndefined()) null else weakKeyPtr(token),
    });
    return Value.undef();
}

fn finRegUnregisterFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (!this.isObject() or !this.asObj().is_finalization_registry) return self.throwError("TypeError", "FinalizationRegistry.prototype.unregister called on an incompatible receiver");
    const token = if (args.len > 0) args[0] else Value.undef();
    if (!canBeHeldWeakly(token)) return self.throwError("TypeError", "FinalizationRegistry.unregister: token must be an object or a symbol");
    // Remove every cell whose [[UnregisterToken]] is SameValue(token); return
    // whether any were removed. (elements_lock'd — race-free vs a concurrent marker.)
    return Value.boolVal(this.asObj().finRecordUnregister(weakKeyPtr(token)));
}

fn finRegCleanupSomeFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (!this.isObject() or !this.asObj().is_finalization_registry) return self.throwError("TypeError", "FinalizationRegistry.prototype.cleanupSome called on an incompatible receiver");
    const cb = if (args.len > 0 and !args[0].isUndefined()) args[0] else this.asObj().finalization_callback;
    if (!cb.isCallable()) return self.throwError("TypeError", "FinalizationRegistry.prototype.cleanupSome callback is not callable");
    // Pop each ready record under the lock, then run the callback with no lock
    // held (it may re-enter the registry) — race-free vs a concurrent marker.
    while (this.asObj().finRecordTakeReady()) |record| {
        _ = try self.callValue(cb, &.{record.held});
    }
    return Value.undef();
}

/// Install `WeakRef` and `FinalizationRegistry`. With the opt-in GC enabled,
/// WeakRef targets clear when collected and FinalizationRegistry records become
/// observable through cleanupSome at quiescent collection points.
// ===== DisposableStack / AsyncDisposableStack ========================
// The explicit-resource-management container objects. The `using`/`await using`
// *syntax* isn't wired, but the class API (use/adopt/defer/move/dispose) is.

fn dsHidden(self: *Interpreter, o: *value.Object, key: []const u8, v: Value) EvalError!void {
    try self.setProp(o, key, v);
    try o.setAttr(self.arena, key, .{ .writable = true, .enumerable = false, .configurable = false });
}

fn isDispStack(this: Value) bool {
    return this.isObject() and this.asObj().getOwn("\x00ds_res") != null;
}

/// Brand-check a specific stack kind: a (sync) DisposableStack method rejects an
/// AsyncDisposableStack and vice versa.
fn isDispStackOf(this: Value, want_async: bool) bool {
    if (!this.isObject() or this.asObj().getOwn("\x00ds_res") == null) return false;
    const is_async = (this.asObj().getOwn("\x00ds_async") orelse Value.boolVal(false)).toBoolean();
    return is_async == want_async;
}

fn dispDisposed(o: *value.Object) bool {
    return (o.getOwn("\x00ds_done") orelse Value.boolVal(false)).toBoolean();
}

fn disposableStackConstructorFn(comptime is_async: bool) value.NativeFn {
    return struct {
        fn call(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
            _ = this;
            _ = args;
            const self: *Interpreter = @ptrCast(@alignCast(ctx));
            const name = if (is_async) "AsyncDisposableStack" else "DisposableStack";
            if (self.new_target.isUndefined()) return self.throwError("TypeError", "Constructor " ++ name ++ " requires 'new'");
            const o = (try self.newObject()).asObj();
            if (try self.protoFromCtor(name)) |pr| o.setProtoAtomic(pr);
            try dsHidden(self, o, "\x00ds_res", try self.newArray());
            try dsHidden(self, o, "\x00ds_done", Value.boolVal(false));
            try dsHidden(self, o, "\x00ds_async", Value.boolVal(is_async));
            return Value.obj(o);
        }
    }.call;
}

/// Push a resource entry [value, onDispose, kind] (kind 0=use,1=adopt,2=defer).
fn dispPush(self: *Interpreter, o: *value.Object, v: Value, f: Value, kind: f64) EvalError!void {
    const entry = (try self.newArray()).asObj();
    try entry.elements.append(entry.elementsAllocator(self.arena), v);
    try entry.elements.append(entry.elementsAllocator(self.arena), f);
    try entry.elements.append(entry.elementsAllocator(self.arena), Value.num(kind));
    const res = o.getOwn("\x00ds_res").?.asObj();
    try res.elements.append(res.elementsAllocator(self.arena), Value.obj(entry));
}

fn dispGetMethod(self: *Interpreter, v: Value, sym_key: []const u8) EvalError!Value {
    const m = try self.getProperty(v, sym_key);
    if (m.isUndefined() or m.isNull()) return self.throwError("TypeError", "value is not disposable (no dispose method)");
    if (!m.isCallable()) return self.throwError("TypeError", "dispose method is not callable");
    return m;
}

fn dispUseFn(comptime is_async: bool) value.NativeFn {
    return struct {
        fn call(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
            const self: *Interpreter = @ptrCast(@alignCast(ctx));
            if (!isDispStackOf(this, is_async)) return self.throwError("TypeError", "use called on an incompatible receiver");
            if (dispDisposed(this.asObj())) return self.throwError("ReferenceError", "DisposableStack is disposed");
            const v = if (args.len > 0) args[0] else Value.undef();
            if (v.isUndefined() or v.isNull()) {
                if (is_async) try dispPush(self, this.asObj(), v, Value.undef(), 3);
                return v;
            }
            const key = self.wellKnownSymbolKey(if (is_async) "asyncDispose" else "dispose") orelse return self.throwError("TypeError", "Symbol.dispose unavailable");
            var method = self.getProperty(v, key) catch return error.Throw;
            if (is_async and (method.isUndefined() or method.isNull())) {
                // async stacks fall back to the sync @@dispose method.
                const sk = self.wellKnownSymbolKey("dispose") orelse "";
                method = try self.getProperty(v, sk);
            }
            if (method.isUndefined() or method.isNull()) return self.throwError("TypeError", "value is not disposable");
            if (!method.isCallable()) return self.throwError("TypeError", "dispose method is not callable");
            try dispPush(self, this.asObj(), v, method, 0);
            return v;
        }
    }.call;
}

fn dispAdoptFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (!isDispStack(this)) return self.throwError("TypeError", "adopt called on a non-DisposableStack");
    if (dispDisposed(this.asObj())) return self.throwError("ReferenceError", "DisposableStack is disposed");
    const v = if (args.len > 0) args[0] else Value.undef();
    const f = if (args.len > 1) args[1] else Value.undef();
    if (!f.isCallable()) return self.throwError("TypeError", "onDispose is not callable");
    try dispPush(self, this.asObj(), v, f, 1);
    return v;
}

fn dispDeferFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (!isDispStack(this)) return self.throwError("TypeError", "defer called on a non-DisposableStack");
    if (dispDisposed(this.asObj())) return self.throwError("ReferenceError", "DisposableStack is disposed");
    const f = if (args.len > 0) args[0] else Value.undef();
    if (!f.isCallable()) return self.throwError("TypeError", "onDispose is not callable");
    try dispPush(self, this.asObj(), Value.undef(), f, 2);
    return Value.undef();
}

fn dispMoveFn(comptime is_async: bool) value.NativeFn {
    return struct {
        fn call(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
            _ = args;
            const self: *Interpreter = @ptrCast(@alignCast(ctx));
            if (!isDispStackOf(this, is_async)) return self.throwError("TypeError", "move called on an incompatible receiver");
            if (dispDisposed(this.asObj())) return self.throwError("ReferenceError", "DisposableStack is disposed");
            // OrdinaryCreateFromConstructor(%DisposableStack%, …): the new stack
            // uses the INTRINSIC prototype, never the subclass's.
            const name = if (is_async) "AsyncDisposableStack" else "DisposableStack";
            const o = (try self.newObject()).asObj();
            if (self.env.get(name)) |c| if (c.isObject()) {
                o.setProtoAtomic(try self.protoObject(c.asObj()));
            };
            try dsHidden(self, o, "\x00ds_res", this.asObj().getOwn("\x00ds_res").?);
            try dsHidden(self, o, "\x00ds_done", Value.boolVal(false));
            try dsHidden(self, o, "\x00ds_async", Value.boolVal(is_async));
            // The source keeps an empty list and is marked disposed.
            try dsHidden(self, this.asObj(), "\x00ds_res", try self.newArray());
            try dsHidden(self, this.asObj(), "\x00ds_done", Value.boolVal(true));
            return Value.obj(o);
        }
    }.call;
}

/// Dispose one resource entry, returning normally or propagating its throw.
fn dispOne(self: *Interpreter, entry: *value.Object, is_async: bool) EvalError!void {
    const v = entry.elements.items[0];
    const f = entry.elements.items[1];
    const kind = entry.elements.items[2].asNum();
    const r = switch (@as(u8, @intFromFloat(kind))) {
        1 => try self.callValueWithThis(f, &.{v}, Value.undef()), // adopt: onDispose(value)
        2 => try self.callValueWithThis(f, &.{}, Value.undef()), // defer: onDispose()
        3 => return, // async null/undefined sentinel: disposeAsync awaits a tick
        else => try self.callValueWithThis(f, &.{}, v), // use: value[@@dispose]()
    };
    if (is_async) _ = try self.awaitValue(r);
}

fn dispOnlyAsyncSentinels(o: *value.Object) bool {
    const res = o.getOwn("\x00ds_res").?.asObj();
    if (res.elements.items.len == 0) return false;
    for (res.elements.items) |entry_v| {
        const entry = entry_v.asObj();
        if (@as(u8, @intFromFloat(entry.elements.items[2].asNum())) != 3) return false;
    }
    return true;
}

/// Run a stack's disposal: dispose every resource in reverse, chaining throws
/// into SuppressedError. Returns the pending error (to throw) or null.
fn dispRunAll(self: *Interpreter, o: *value.Object, is_async: bool) EvalError!?Value {
    const res = o.getOwn("\x00ds_res").?.asObj();
    var has_err = false;
    var err: Value = Value.undef();
    var i = res.elements.items.len;
    while (i > 0) {
        i -= 1;
        const entry = res.elements.items[i].asObj();
        if (dispOne(self, entry, is_async)) |_| {} else |e| {
            if (e != error.Throw) return e;
            const thrown = self.exception;
            self.exception = Value.undef();
            if (has_err) {
                err = try makeSuppressed(self, thrown, err);
            } else {
                has_err = true;
                err = thrown;
            }
        }
    }
    res.elements.clearRetainingCapacity();
    return if (has_err) err else null;
}

fn makeSuppressed(self: *Interpreter, errv: Value, suppressed: Value) EvalError!Value {
    const e = try self.makeError("SuppressedError", "An error was suppressed during disposal");
    if (e.isObject()) {
        try self.setProp(e.asObj(), "error", errv);
        try e.asObj().setAttr(self.arena, "error", .{ .enumerable = false, .configurable = true, .writable = true });
        try self.setProp(e.asObj(), "suppressed", suppressed);
        try e.asObj().setAttr(self.arena, "suppressed", .{ .enumerable = false, .configurable = true, .writable = true });
    }
    return e;
}

fn dispDisposeFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = args;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (!isDispStackOf(this, false)) return self.throwError("TypeError", "dispose called on an incompatible receiver");
    if (dispDisposed(this.asObj())) return Value.undef();
    try dsHidden(self, this.asObj(), "\x00ds_done", Value.boolVal(true));
    if (try dispRunAll(self, this.asObj(), false)) |err| {
        self.exception = err;
        return error.Throw;
    }
    return Value.undef();
}

fn dispDisposeAsyncFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = args;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (!isDispStackOf(this, true)) return promiseRejectValue(self, try self.makeError("TypeError", "disposeAsync called on an incompatible receiver"));
    if (dispDisposed(this.asObj())) return promiseResolveValue(self, Value.undef());
    const needs_tick = dispOnlyAsyncSentinels(this.asObj());
    try dsHidden(self, this.asObj(), "\x00ds_done", Value.boolVal(true));
    const r = dispRunAll(self, this.asObj(), true) catch {
        const exc = self.exception;
        self.exception = Value.undef();
        return promiseRejectValue(self, exc);
    };
    if (r) |err| return promiseRejectValue(self, err);
    if (needs_tick) return promiseResolveAfterTick(self, Value.undef());
    return promiseResolveValue(self, Value.undef());
}

fn dispDisposedGetter(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = args;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (!isDispStack(this)) return self.throwError("TypeError", "disposed getter on a non-DisposableStack");
    return Value.boolVal(dispDisposed(this.asObj()));
}

fn installDisposableStacks(env: *Environment, rs: *Shape, object_proto: *value.Object) EvalError!void {
    const a = env.arena;
    const sym = env.get("Symbol");
    const symKey = struct {
        fn get(s: ?Value, name: []const u8) ?[]const u8 {
            if (s) |sv| if (sv.isObject()) {
                if (sv.asObj().getOwn(name)) |t| if (t.isObject() and t.asObj().is_symbol) return t.asObj().sym_key;
            };
            return null;
        }
    }.get;
    const tag = symKey(sym, "toStringTag");

    // Sync DisposableStack.
    {
        const proto = try gc_mod.allocObj(a);
        proto.* = .{ .proto = object_proto };
        try setNative(a, rs, proto, "use", 1, dispUseFn(false));
        try setNative(a, rs, proto, "adopt", 2, dispAdoptFn);
        try setNative(a, rs, proto, "defer", 1, dispDeferFn);
        try setNative(a, rs, proto, "move", 0, dispMoveFn(false));
        try setNative(a, rs, proto, "dispose", 0, dispDisposeFn);
        try setNativeGetter(a, rs, proto, "disposed", dispDisposedGetter);
        // %DisposableStack.prototype%[@@dispose] is the SAME function as `dispose`
        // (a writable, configurable, non-enumerable data property).
        if (symKey(sym, "dispose")) |k| if (proto.getOwn("dispose")) |dv| {
            try proto.setOwn(a, rs, k, dv);
            try proto.setAttr(a, k, .{ .writable = true, .enumerable = false, .configurable = true });
        };
        if (tag) |k| {
            try proto.setOwn(a, rs, k, Value.str("DisposableStack"));
            try proto.setAttr(a, k, .{ .writable = false, .enumerable = false, .configurable = true });
        }
        const ctor = try gc_mod.allocObj(a);
        ctor.* = .{ .native = disposableStackConstructorFn(false), .native_ctor = true };
        try installNativeProps(a, rs, ctor, "DisposableStack", 0);
        try ctor.setOwn(a, rs, "prototype", Value.obj(proto));
        try ctor.setAttr(a, "prototype", .{ .writable = false, .enumerable = false, .configurable = false });
        try setConstructor(a, rs, proto, ctor);
        try env.put("DisposableStack", Value.obj(ctor));
    }
    // AsyncDisposableStack.
    {
        const proto = try gc_mod.allocObj(a);
        proto.* = .{ .proto = object_proto };
        try setNative(a, rs, proto, "use", 1, dispUseFn(true));
        try setNative(a, rs, proto, "adopt", 2, dispAdoptFn);
        try setNative(a, rs, proto, "defer", 1, dispDeferFn);
        try setNative(a, rs, proto, "move", 0, dispMoveFn(true));
        try setNative(a, rs, proto, "disposeAsync", 0, dispDisposeAsyncFn);
        try setNativeGetter(a, rs, proto, "disposed", dispDisposedGetter);
        // [@@asyncDispose] is the SAME function as `disposeAsync`.
        if (symKey(sym, "asyncDispose")) |k| if (proto.getOwn("disposeAsync")) |dv| {
            try proto.setOwn(a, rs, k, dv);
            try proto.setAttr(a, k, .{ .writable = true, .enumerable = false, .configurable = true });
        };
        if (tag) |k| {
            try proto.setOwn(a, rs, k, Value.str("AsyncDisposableStack"));
            try proto.setAttr(a, k, .{ .writable = false, .enumerable = false, .configurable = true });
        }
        const ctor = try gc_mod.allocObj(a);
        ctor.* = .{ .native = disposableStackConstructorFn(true), .native_ctor = true };
        try installNativeProps(a, rs, ctor, "AsyncDisposableStack", 0);
        try ctor.setOwn(a, rs, "prototype", Value.obj(proto));
        try ctor.setAttr(a, "prototype", .{ .writable = false, .enumerable = false, .configurable = false });
        try setConstructor(a, rs, proto, ctor);
        try env.put("AsyncDisposableStack", Value.obj(ctor));
    }
}

fn installWeakRefAndFinReg(env: *Environment, rs: *Shape, object_proto: *value.Object) EvalError!void {
    const a = env.arena;
    const tt: ?[]const u8 = blk: {
        if (env.get("Symbol")) |sym| if (sym.isObject()) {
            if (sym.asObj().getOwn("toStringTag")) |t| if (t.isObject() and t.asObj().is_symbol) break :blk t.asObj().sym_key;
        };
        break :blk null;
    };
    // WeakRef.
    {
        const proto = try gc_mod.allocObj(a);
        proto.* = .{ .proto = object_proto };
        try setNative(a, rs, proto, "deref", 0, weakRefDerefFn);
        if (tt) |k| {
            try proto.setOwn(a, rs, k, Value.str("WeakRef"));
            try proto.setAttr(a, k, .{ .writable = false, .enumerable = false, .configurable = true });
        }
        const ctor = try gc_mod.allocObj(a);
        ctor.* = .{ .native = weakRefConstructorFn, .native_ctor = true };
        try installNativeProps(a, rs, ctor, "WeakRef", 1);
        try ctor.setOwn(a, rs, "prototype", Value.obj(proto));
        try ctor.setAttr(a, "prototype", .{ .writable = false, .enumerable = false, .configurable = false });
        try setConstructor(a, rs, proto, ctor);
        try env.put("WeakRef", Value.obj(ctor));
    }
    // FinalizationRegistry.
    {
        const proto = try gc_mod.allocObj(a);
        proto.* = .{ .proto = object_proto };
        try setNative(a, rs, proto, "register", 2, finRegRegisterFn);
        try setNative(a, rs, proto, "unregister", 1, finRegUnregisterFn);
        try setNative(a, rs, proto, "cleanupSome", 0, finRegCleanupSomeFn);
        if (tt) |k| {
            try proto.setOwn(a, rs, k, Value.str("FinalizationRegistry"));
            try proto.setAttr(a, k, .{ .writable = false, .enumerable = false, .configurable = true });
        }
        const ctor = try gc_mod.allocObj(a);
        ctor.* = .{ .native = finalizationRegistryConstructorFn, .native_ctor = true };
        try installNativeProps(a, rs, ctor, "FinalizationRegistry", 1);
        try ctor.setOwn(a, rs, "prototype", Value.obj(proto));
        try ctor.setAttr(a, "prototype", .{ .writable = false, .enumerable = false, .configurable = false });
        try setConstructor(a, rs, proto, ctor);
        try env.put("FinalizationRegistry", Value.obj(ctor));
    }
}

fn installDataView(env: *Environment, rs: *Shape, object_proto: *value.Object) EvalError!void {
    const a = env.arena;
    const proto = try gc_mod.allocObj(a);
    proto.* = .{ .proto = object_proto };
    inline for (dv_types) |t| {
        try setNative(a, rs, proto, "get" ++ t.name, 1, dataViewGetFn(t));
        try setNative(a, rs, proto, "set" ++ t.name, 2, dataViewSetFn(t));
    }
    try setNativeGetter(a, rs, proto, "buffer", dataViewBufferGetter);
    try setNativeGetter(a, rs, proto, "byteLength", dataViewByteLengthGetter);
    try setNativeGetter(a, rs, proto, "byteOffset", dataViewByteOffsetGetter);
    // DataView.prototype[Symbol.toStringTag] = "DataView" {configurable}.
    if (env.get("Symbol")) |sym| if (sym.isObject()) {
        if (sym.asObj().getOwn("toStringTag")) |tt| if (tt.isObject() and tt.asObj().is_symbol) {
            try proto.setOwn(a, rs, tt.asObj().sym_key, Value.str("DataView"));
            try proto.setAttr(a, tt.asObj().sym_key, .{ .writable = false, .enumerable = false, .configurable = true });
        };
    };
    const ctor = try gc_mod.allocObj(a);
    ctor.* = .{ .native = dataViewConstructorFn, .native_ctor = true };
    try installNativeProps(a, rs, ctor, "DataView", 1);
    try ctor.setOwn(a, rs, "prototype", Value.obj(proto));
    try ctor.setAttr(a, "prototype", .{ .writable = false, .enumerable = false, .configurable = false });
    try setConstructor(a, rs, proto, ctor);
    try env.put("DataView", Value.obj(ctor));
}

/// Normalize a relative index (negative counts from the end) into [0, len].
/// The argument is coerced via ToIntegerOrInfinity (`toNumberV`), so a Symbol
/// or BigInt — or an object whose `valueOf` throws — propagates a TypeError.
fn relIndex(self: *Interpreter, v: Value, len: usize, default: f64) EvalError!usize {
    const n = if (v.isUndefined()) default else try self.toNumberV(v);
    if (std.math.isNan(n)) return 0;
    const fl = @trunc(n);
    if (fl < 0) {
        const from_end = @as(f64, @floatFromInt(len)) + fl;
        return if (from_end < 0) 0 else @intFromFloat(from_end);
    }
    const flen: f64 = @floatFromInt(len);
    return if (fl > flen) len else @intFromFloat(fl);
}

/// `ArrayBuffer.prototype.slice(begin, end)` — a copy of the byte range.
fn arrayBufferSliceFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    return arrayBufferSliceImpl(@ptrCast(@alignCast(ctx)), this, args, false);
}

/// ArrayBuffer/SharedArrayBuffer .prototype.slice: clamp the range, then
/// ArrayBufferSpeciesCreate(O, newLen) — Construct via SpeciesConstructor and
/// validate the result (right kind, not detached/same/too-small) before copying.
fn arrayBufferSliceImpl(self: *Interpreter, this: Value, args: []const Value, comptime want_shared: bool) value.HostError!Value {
    const kind_name = if (want_shared) "SharedArrayBuffer" else "ArrayBuffer";
    if (!this.isObject() or this.asObj().array_buffer == null or this.asObj().array_buffer.?.is_shared != want_shared)
        return self.throwError("TypeError", kind_name ++ ".prototype.slice called on an incompatible receiver");
    const ab = this.asObj().array_buffer.?;
    if (!want_shared and ab.isDetached()) return self.throwError("TypeError", "ArrayBuffer is detached");
    const blen = ab.bytes().len;
    const start = try relIndex(self, if (args.len > 0) args[0] else Value.undef(), blen, 0);
    const end = try relIndex(self, if (args.len > 1) args[1] else Value.undef(), blen, @floatFromInt(blen));
    if (!want_shared and ab.isDetached()) return self.throwError("TypeError", "ArrayBuffer is detached");
    const src_len = ab.bytes().len;
    const safe_count = if (start >= src_len) 0 else @min(if (end > start) end - start else 0, src_len - start);
    // ArrayBufferSpeciesCreate(O, newLen).
    const default_ctor = self.env.get(kind_name) orelse Value.undef();
    const ctor = try self.speciesConstructor(this, default_ctor);
    const new_v = try self.construct(ctor, &.{Value.num(@floatFromInt(safe_count))});
    if (!new_v.isObject() or new_v.asObj().array_buffer == null)
        return self.throwError("TypeError", "ArrayBuffer species constructor did not return an ArrayBuffer");
    const nb = new_v.asObj().array_buffer.?;
    if (nb.is_shared != want_shared)
        return self.throwError("TypeError", "ArrayBuffer species constructor returned a buffer of the wrong shared-ness");
    if (!want_shared and nb.isDetached()) return self.throwError("TypeError", "species constructor returned a detached ArrayBuffer");
    if (!want_shared and nb.immutable) return self.throwError("TypeError", "species constructor returned an immutable ArrayBuffer");
    if (new_v.asObj() == this.asObj()) return self.throwError("TypeError", "ArrayBuffer species constructor returned the same buffer");
    if (nb.bytes().len < safe_count) return self.throwError("TypeError", "ArrayBuffer species constructor returned too small a buffer");
    if (!want_shared and ab.isDetached()) return self.throwError("TypeError", "ArrayBuffer is detached");
    @memcpy(nb.bytes()[0..safe_count], ab.bytes()[start .. start + safe_count]);
    return new_v;
}

/// Build a fresh typed array of `kind` with `len` zero-initialized elements.
fn newTypedArray(self: *Interpreter, kind: value.TAKind, len: usize) EvalError!*value.Object {
    const o = (try self.newObject()).asObj();
    const ta = try o.typedArrayAllocator(self.arena).create(value.TypedArrayData);
    ta.* = .{ .buffer = try self.makeArrayBuffer(len * kind.byteSize()), .byte_offset = 0, .length = len, .kind = kind };
    o.typed_array = ta;
    if (self.env.get(kind.ctorName())) |c| {
        if (c.isObject()) o.setProtoAtomic(try self.protoObject(c.asObj()));
    }
    return o;
}

fn collectionIterKind(name: []const u8) u8 {
    if (eq(name, "keys")) return 1;
    if (eq(name, "entries")) return 2;
    return 0; // values, and the default Set / typed-array iterator
}

/// %TypedArray%.prototype methods. The receiver is a typed array; element reads
/// go through the buffer (`taRead`), writes coerce via ToNumber + `taWrite`.
fn typedArrayMethod(self: *Interpreter, o: *value.Object, name: []const u8, args: []const Value) EvalError!?Value {
    const ta = o.typed_array.?;
    // ValidateTypedArray(O, write): the in-place mutators reject an immutable
    // buffer up front, before coercing any argument.
    if (ta.buffer.array_buffer.?.immutable and
        (eq(name, "fill") or eq(name, "set") or eq(name, "sort") or eq(name, "copyWithin") or eq(name, "reverse")))
        return self.throwError("TypeError", "Cannot modify a TypedArray backed by an immutable ArrayBuffer");
    // ValidateTypedArray throws when the buffer is detached or the view is out
    // of bounds (a resizable buffer shrank below it), before any argument is
    // coerced. `subarray` is the lone method that tolerates this (it just builds
    // a zero-length view).
    const cur_len = ta.currentLength();
    if (cur_len == null and !eq(name, "subarray"))
        return self.throwError("TypeError", "Cannot operate on a TypedArray whose buffer is detached or out of bounds");
    const len = cur_len orelse 0;
    const recv = Value.obj(o);
    const cb_this: Value = if (args.len > 1) args[1] else Value.undef();
    if (eq(name, "at")) {
        const n = if (args.len > 0) try self.toNumberV(args[0]) else 0;
        const rel = if (std.math.isNan(n)) @as(f64, 0) else @trunc(n);
        if (std.math.isInf(rel)) return Value.undef();
        const len_f: f64 = @floatFromInt(len);
        if (rel < -len_f or rel >= len_f) return Value.undef();
        var idx: i64 = @intFromFloat(rel);
        if (idx < 0) idx += @as(i64, @intCast(len));
        return try self.taLoadIdx(ta, @intCast(idx));
    }
    if (eq(name, "join")) {
        // The separator coerces once (it can resize the buffer); each element is
        // then read length-aware — an index now out of bounds joins as "".
        const sep = if (args.len > 0 and !args[0].isUndefined()) try self.toStringV(args[0]) else ",";
        var buf: std.ArrayListUnmanaged(u8) = .empty;
        var i: usize = 0;
        while (i < len) : (i += 1) {
            if (i > 0) try buf.appendSlice(self.arena, sep);
            const el = try self.taLoadIdx(ta, i);
            if (!el.isUndefined()) try buf.appendSlice(self.arena, try self.toStringV(el));
        }
        return Value.str(try buf.toOwnedSlice(self.arena));
    }
    if (eq(name, "toLocaleString")) {
        // Per spec: R = ToString(? Invoke(element, "toLocaleString")), joined by ",".
        var buf: std.ArrayListUnmanaged(u8) = .empty;
        var i: usize = 0;
        while (i < len) : (i += 1) {
            if (i > 0) try buf.append(self.arena, ',');
            const el = try self.taLoadIdx(ta, i);
            if (el.isUndefined()) continue;
            const method = try self.getProperty(el, "toLocaleString");
            const forwarded = [_]Value{
                if (args.len > 0) args[0] else Value.undef(),
                if (args.len > 1) args[1] else Value.undef(),
            };
            const r = try self.callValueWithThis(method, &forwarded, el);
            try buf.appendSlice(self.arena, try self.toStringV(r));
        }
        return Value.str(try buf.toOwnedSlice(self.arena));
    }
    if (eq(name, "forEach")) {
        const cb = if (args.len > 0) args[0] else Value.undef();
        var i: usize = 0;
        while (i < len) : (i += 1) _ = try self.callValueWithThis(cb, &.{ try self.taLoadIdx(ta, i), Value.num(@floatFromInt(i)), recv }, cb_this);
        return Value.undef();
    }
    if (eq(name, "map")) {
        const cb = if (args.len > 0) args[0] else Value.undef();
        const result = try self.typedArraySpeciesCreate(o, len, null);
        var i: usize = 0;
        while (i < len) : (i += 1) {
            const r = try self.callValueWithThis(cb, &.{ try self.taLoadIdx(ta, i), Value.num(@floatFromInt(i)), recv }, cb_this);
            try self.taStore(result.typed_array.?, i, r);
        }
        return Value.obj(result);
    }
    if (eq(name, "filter")) {
        const cb = if (args.len > 0) args[0] else Value.undef();
        var kept: std.ArrayListUnmanaged(Value) = .empty;
        var i: usize = 0;
        while (i < len) : (i += 1) {
            const el = try self.taLoadIdx(ta, i);
            if ((try self.callValueWithThis(cb, &.{ el, Value.num(@floatFromInt(i)), recv }, cb_this)).toBoolean())
                try kept.append(self.arena, el);
        }
        const result = try self.typedArraySpeciesCreate(o, kept.items.len, null);
        for (kept.items, 0..) |x, k| try self.taStore(result.typed_array.?, k, x);
        return Value.obj(result);
    }
    if (eq(name, "some") or eq(name, "every")) {
        const every = eq(name, "every");
        const cb = if (args.len > 0) args[0] else Value.undef();
        var i: usize = 0;
        while (i < len) : (i += 1) {
            const t = (try self.callValueWithThis(cb, &.{ try self.taLoadIdx(ta, i), Value.num(@floatFromInt(i)), recv }, cb_this)).toBoolean();
            if (every and !t) return Value.boolVal(false);
            if (!every and t) return Value.boolVal(true);
        }
        return Value.boolVal(every);
    }
    if (eq(name, "find") or eq(name, "findIndex") or eq(name, "findLast") or eq(name, "findLastIndex")) {
        const want_idx = eq(name, "findIndex") or eq(name, "findLastIndex");
        const from_end = eq(name, "findLast") or eq(name, "findLastIndex");
        const cb = if (args.len > 0) args[0] else Value.undef();
        if (!cb.isCallable()) return self.throwError("TypeError", "TypedArray.prototype.find predicate is not callable");
        var k: usize = 0;
        while (k < len) : (k += 1) {
            const i = if (from_end) len - 1 - k else k;
            const el = try self.taLoadIdx(ta, i);
            if ((try self.callValueWithThis(cb, &.{ el, Value.num(@floatFromInt(i)), recv }, cb_this)).toBoolean())
                return if (want_idx) Value.num(@floatFromInt(i)) else el;
        }
        return if (want_idx) Value.num(-1) else Value.undef();
    }
    if (eq(name, "reduce") or eq(name, "reduceRight")) {
        const right = eq(name, "reduceRight");
        const cb = if (args.len > 0) args[0] else Value.undef();
        if (!cb.isCallable()) return self.throwError("TypeError", "TypedArray.prototype.reduce callback is not callable");
        var acc: Value = undefined;
        var count: usize = 0;
        const idxOf = struct {
            fn f(r: bool, l: usize, c: usize) usize {
                return if (r) l - 1 - c else c;
            }
        }.f;
        if (args.len > 1) {
            acc = args[1];
        } else {
            if (len == 0) return self.throwError("TypeError", "Reduce of empty array with no initial value");
            acc = try self.taLoadIdx(ta, idxOf(right, len, 0));
            count = 1;
        }
        while (count < len) : (count += 1) {
            const i = idxOf(right, len, count);
            acc = try self.callValueWithThis(cb, &.{ acc, try self.taLoadIdx(ta, i), Value.num(@floatFromInt(i)), recv }, Value.undef());
        }
        return acc;
    }
    if (eq(name, "indexOf") or eq(name, "lastIndexOf") or eq(name, "includes")) {
        const incl = eq(name, "includes");
        const last = eq(name, "lastIndexOf");
        const search = if (args.len > 0) args[0] else Value.undef();
        const not_found: Value = if (incl) Value.boolVal(false) else Value.num(-1);
        if (len == 0) return not_found;
        const flen: f64 = @floatFromInt(len);
        // ToIntegerOrInfinity(fromIndex): default 0 (indexOf/includes) or len-1
        // (lastIndexOf). The coercion runs user code that may detach/shrink the
        // buffer, so re-read the live length afterwards and treat now-out-of-range
        // indices as absent (HasProperty=false / Get=undefined).
        var n: f64 = if (last) flen - 1 else 0;
        if (args.len > 1) {
            const raw = try self.toNumberV(args[1]);
            n = if (std.math.isNan(raw)) 0 else @trunc(raw);
        }
        const cur = ta.currentLength() orelse 0;
        if (!last) {
            if (n == std.math.inf(f64)) return not_found;
            const start: usize = if (n >= flen) len else if (n >= 0) @intFromFloat(n) else blk: {
                const s = flen + n;
                break :blk if (s < 0) 0 else @intFromFloat(s);
            };
            var k: usize = start;
            while (k < len) : (k += 1) {
                // An index past the live length reads as undefined: `includes`
                // (Get-based, sameValueZero) compares it, so includes(undefined)
                // matches; indexOf/lastIndexOf (HasProperty-based) skip it.
                if (k >= cur) {
                    if (incl and value.sameValueZero(Value.undef(), search)) return Value.boolVal(true);
                    continue;
                }
                const el = try self.taLoad(ta, k);
                const match = if (incl) value.sameValueZero(el, search) else value.strictEquals(el, search);
                if (match) return if (incl) Value.boolVal(true) else Value.num(@floatFromInt(k));
            }
            return not_found;
        }
        // lastIndexOf: search backward from `start`.
        if (n == -std.math.inf(f64)) return Value.num(-1);
        const start: i64 = if (n >= flen) @as(i64, @intCast(len)) - 1 else if (n >= 0) @intFromFloat(n) else blk: {
            const s = flen + n;
            if (s < 0) return Value.num(-1);
            break :blk @intFromFloat(s);
        };
        var k: i64 = start;
        while (k >= 0) : (k -= 1) {
            const ku: usize = @intCast(k);
            if (ku >= cur) continue;
            const el = try self.taLoad(ta, ku);
            if (value.strictEquals(el, search)) return Value.num(@floatFromInt(ku));
        }
        return Value.num(-1);
    }
    if (eq(name, "fill")) {
        // ToBigInt / ToNumber the fill value exactly once (before clamping
        // start/end), then store the already-coerced value each step.
        const fillv = if (args.len > 0) args[0] else Value.undef();
        const coerced: Value = if (ta.kind.isBigInt())
            try self.toBigIntValueImpl(fillv, false)
        else
            Value.num(try self.toNumberV(fillv));
        const start = try relIndex(self, if (args.len > 1) args[1] else Value.undef(), len, 0);
        const end = try relIndex(self, if (args.len > 2) args[2] else Value.undef(), len, @floatFromInt(len));
        // The value/start/end coercions can detach or shrink the buffer; re-read
        // the live length (throw if detached) and clamp the write range to it.
        const live = ta.currentLength() orelse return self.throwError("TypeError", "Cannot fill a TypedArray whose buffer is detached or out of bounds");
        const hi = @min(end, live);
        var i = start;
        while (i < hi) : (i += 1) try self.taStore(ta, i, coerced);
        return recv;
    }
    if (eq(name, "reverse")) {
        var i: usize = 0;
        while (i < len / 2) : (i += 1) {
            const tmp = try self.taLoad(ta, i);
            try self.taStore(ta, i, try self.taLoad(ta, len - 1 - i));
            try self.taStore(ta, len - 1 - i, tmp);
        }
        return recv;
    }
    if (eq(name, "copyWithin")) {
        const target = try relIndex(self, if (args.len > 0) args[0] else Value.undef(), len, 0);
        const start = try relIndex(self, if (args.len > 1) args[1] else Value.undef(), len, 0);
        const end = try relIndex(self, if (args.len > 2) args[2] else Value.undef(), len, @floatFromInt(len));
        const live_len = ta.currentLength() orelse return self.throwError("TypeError", "Cannot operate on a TypedArray whose buffer is detached or out of bounds");
        const count = @min(
            @min(if (end > start) end - start else 0, len - target),
            @min(if (target < live_len) live_len - target else 0, if (start < live_len) live_len - start else 0),
        );
        if (count > 0) {
            const esz = ta.kind.byteSize();
            const bytes = ta.buffer.array_buffer.?.bytes();
            const base = ta.byte_offset;
            const dst = bytes[base + target * esz ..][0 .. count * esz];
            const src = bytes[base + start * esz ..][0 .. count * esz];
            // memmove: when the destination overlaps and follows the source,
            // copy back-to-front so earlier writes don't clobber unread source.
            if (target > start) std.mem.copyBackwards(u8, dst, src) else std.mem.copyForwards(u8, dst, src);
        }
        return recv;
    }
    if (eq(name, "subarray")) {
        // subarray returns a view (sharing the buffer) built through the species
        // constructor. Length-tracking views over resizable buffers omit
        // `newLength` when `end` is undefined so the result stays length-tracking.
        const start = try relIndex(self, if (args.len > 0) args[0] else Value.undef(), len, 0);
        const end_is_undefined = args.len < 2 or args[1].isUndefined();
        const end = try relIndex(self, if (!end_is_undefined) args[1] else Value.undef(), len, @floatFromInt(len));
        const count = if (end > start) end - start else 0;
        const begin_byte = ta.byte_offset + start * ta.kind.byteSize();
        const sub_len: ?usize = if (ta.track_length and end_is_undefined) null else count;
        const sub = try self.typedArraySubarrayCreate(o, ta.buffer, begin_byte, sub_len);
        return sub;
    }
    if (eq(name, "slice")) {
        const start = try relIndex(self, if (args.len > 0) args[0] else Value.undef(), len, 0);
        const end = try relIndex(self, if (args.len > 1) args[1] else Value.undef(), len, @floatFromInt(len));
        const count = if (end > start) end - start else 0;
        const result = try self.typedArraySpeciesCreate(o, count, ta.buffer);
        // TypedArraySpeciesCreate can run user code (the `constructor`/@@species
        // getters) that detaches O's buffer; per spec slice re-checks before the
        // copy when count > 0.
        if (count > 0 and ta.currentLength() == null)
            return self.throwError("TypeError", "Cannot slice a TypedArray whose buffer is detached or out of bounds");
        const aliases_immutable = result.typed_array.?.buffer == ta.buffer and ta.buffer.array_buffer.?.immutable;
        var i: usize = 0;
        while (i < count) : (i += 1) try self.taStoreInternal(result.typed_array.?, i, try self.taLoad(ta, start + i), aliases_immutable);
        return Value.obj(result);
    }
    if (eq(name, "with")) {
        const rel_num = if (args.len > 0) try self.toNumberV(args[0]) else 0;
        const rel = if (std.math.isNan(rel_num)) @as(f64, 0) else @trunc(rel_num);
        const len_f: f64 = @floatFromInt(len);
        // actualIndex computed from the entry length; +inf/-inf stay out of range.
        // `+ 0.0` normalizes -0 (e.g. with(-0) or with(-0.5)) to the +0 index.
        const actual: f64 = (if (rel >= 0) rel else len_f + rel) + 0.0;
        const v = if (args.len > 1) args[1] else Value.undef();
        // The value coerces (and can throw / resize the buffer) BEFORE the index
        // is validated against the CURRENT length (IsValidIntegerIndex).
        const cv = if (ta.kind.isBigInt()) try self.toBigIntValueImpl(v, false) else Value.num(try self.toNumberV(v));
        if (!isValidIntegerIndex(ta, actual)) return self.throwError("RangeError", "Invalid typed array index");
        const idx: usize = @intFromFloat(actual);
        // The result has the entry length; indices now out of bounds copy undefined.
        const result = try newTypedArray(self, ta.kind, len);
        var i: usize = 0;
        while (i < len) : (i += 1) try self.taStore(result.typed_array.?, i, if (i == idx) cv else try self.taLoadIdx(ta, i));
        return Value.obj(result);
    }
    if (eq(name, "toReversed")) {
        const result = try newTypedArray(self, ta.kind, len);
        var i: usize = 0;
        while (i < len) : (i += 1) try self.taStore(result.typed_array.?, i, try self.taLoad(ta, len - 1 - i));
        return Value.obj(result);
    }
    if (eq(name, "sort") or eq(name, "toSorted")) {
        const cmp = if (args.len > 0) args[0] else Value.undef();
        if (!cmp.isUndefined() and !cmp.isCallable()) return self.throwError("TypeError", "The comparison function must be either a function or undefined");
        const buf = try self.arena.alloc(Value, len);
        var i: usize = 0;
        while (i < len) : (i += 1) buf[i] = try self.taLoad(ta, i);
        try taSort(self, buf, cmp);
        if (eq(name, "toSorted")) {
            const result = try newTypedArray(self, ta.kind, len);
            for (buf, 0..) |v, k| try self.taStore(result.typed_array.?, k, v);
            return Value.obj(result);
        }
        const live_len = ta.currentLength() orelse return recv;
        for (buf[0..@min(buf.len, live_len)], 0..) |v, k| try self.taStore(ta, k, v);
        return recv;
    }
    if (eq(name, "set")) {
        const src = if (args.len > 0) args[0] else Value.undef();
        const offset_u64 = if (args.len > 1) try toIndexArg(self, args[1]) else 0;
        if (offset_u64 > std.math.maxInt(usize)) return self.throwError("RangeError", "offset is out of bounds");
        const offset: usize = @intCast(offset_u64);
        // The offset's ToInteger can run user code (a valueOf) that detaches or
        // shrinks the target's buffer; re-read the live length afterwards.
        const tlen = ta.currentLength() orelse return self.throwError("TypeError", "Cannot set on a TypedArray whose buffer is detached or out of bounds");
        if (src.isObject() and src.asObj().typed_array != null) {
            const s = src.asObj().typed_array.?;
            if (s.kind.isBigInt() != ta.kind.isBigInt()) return self.throwError("TypeError", "Cannot mix BigInt and other types when setting a TypedArray");
            const slen = s.currentLength() orelse return self.throwError("TypeError", "source TypedArray buffer is detached or out of bounds");
            if (offset > tlen or slen > tlen - offset) return self.throwError("RangeError", "offset is out of bounds");
            // Snapshot the source first so an overlapping same-buffer copy is safe.
            const tmp = try self.arena.alloc(Value, slen);
            var i: usize = 0;
            while (i < slen) : (i += 1) tmp[i] = try self.taLoad(s, i);
            i = 0;
            while (i < slen) : (i += 1) try self.taStore(ta, offset + i, tmp[i]);
        } else {
            // SetTypedArrayFromArrayLike: ToObject(source) — boxes a primitive
            // (string/number/boolean/symbol), throws on undefined/null — then Get
            // each index in order, writing as we go (so a getter sees prior writes).
            const src_v = Value.obj(try self.toObject(src));
            const slen = toLen(try self.toNumberV(try self.getProperty(src_v, "length")));
            if (offset > tlen or slen > tlen - offset) return self.throwError("RangeError", "offset is out of bounds");
            var k: usize = 0;
            while (k < slen) : (k += 1) {
                const v = try self.getProperty(src_v, try std.fmt.allocPrint(self.arena, "{d}", .{k}));
                try self.taStore(ta, offset + k, v);
            }
        }
        return Value.undef();
    }
    if (eq(name, "toString")) {
        return try typedArrayMethod(self, o, "join", &.{});
    }
    if (eq(name, "keys") or eq(name, "values") or eq(name, "entries"))
        return try self.makeCursorIteratorWithKind(recv, collectionIterKind(name));
    return null;
}

/// Sort `buf` in place per %TypedArray%.prototype.sort: with a user `cmp`
/// function (ToNumber of its result, NaN→0; stable insertion sort so the
/// comparator is honored exactly), or the default numeric/BigInt ascending
/// order (NaN sorts last). Used by `sort` and `toSorted`.
fn taSort(self: *Interpreter, buf: []Value, cmp: Value) EvalError!void {
    var i: usize = 1;
    while (i < buf.len) : (i += 1) {
        const x = buf[i];
        var j: usize = i;
        while (j > 0) : (j -= 1) {
            const ord = try taSortCompare(self, buf[j - 1], x, cmp);
            if (ord <= 0) break;
            buf[j] = buf[j - 1];
        }
        buf[j] = x;
    }
}

fn taSortCompare(self: *Interpreter, a: Value, b: Value, cmp: Value) EvalError!f64 {
    if (cmp.isCallable()) {
        const r = try self.callValueWithThis(cmp, &.{ a, b }, Value.undef());
        const n = try self.toNumberV(r);
        return if (std.math.isNan(n)) 0 else n;
    }
    if (a.isObject() and a.asObj().is_bigint) {
        const av = a.asObj().bigint;
        const bv = b.asObj().bigint;
        return if (av < bv) -1 else if (av > bv) 1 else 0;
    }
    const an = a.asNum();
    const bn = b.asNum();
    if (std.math.isNan(an)) return if (std.math.isNan(bn)) 0 else 1;
    if (std.math.isNan(bn)) return -1;
    if (an == 0 and bn == 0) {
        const a_neg = std.math.signbit(an);
        const b_neg = std.math.signbit(bn);
        if (a_neg != b_neg) return if (a_neg) -1 else 1;
    }
    if (an < bn) return -1;
    if (an > bn) return 1;
    return 0;
}

/// A %TypedArray%.prototype method thunk: brand-checks `this` is a typed array,
/// then dispatches to `typedArrayMethod`.
/// `%TypedArray%` — the abstract superclass constructor shared by Int8Array …
/// Float64Array. It cannot be constructed or called directly (it has no
/// associated element kind); its only role is to hold the shared prototype and
/// the `from`/`of`/`@@species` statics, and to be the `[[Prototype]]` of the
/// concrete view constructors.
fn typedArrayAbstractFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    _ = args;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    return self.throwError("TypeError", "Abstract class TypedArray not directly constructable");
}

/// `%TypedArray%.of(...items)` — `this` is a view constructor; build a length-N
/// view of it and store each item.
/// TypedArrayCreate(constructor, «length»): Construct then ValidateTypedArray —
/// the result must be a non-detached TypedArray whose length is at least the
/// requested one, else a TypeError.
fn typedArrayCreateLen(self: *Interpreter, constructor: Value, length: usize) EvalError!Value {
    const result = try self.construct(constructor, &.{Value.num(@floatFromInt(length))});
    if (!result.isObject() or result.asObj().typed_array == null)
        return self.throwError("TypeError", "TypedArrayCreate did not return a TypedArray");
    const cur = result.asObj().typed_array.?.currentLength();
    if (cur == null) return self.throwError("TypeError", "TypedArrayCreate returned a detached TypedArray");
    if (result.asObj().typed_array.?.buffer.array_buffer.?.immutable)
        return self.throwError("TypeError", "TypedArrayCreate returned a TypedArray backed by an immutable buffer");
    if (cur.? < length) return self.throwError("TypeError", "TypedArrayCreate returned a TypedArray smaller than requested");
    return result;
}

fn typedArrayOfFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (!isConstructorValue(this)) return self.throwError("TypeError", "%TypedArray%.of requires a constructor `this`");
    const result = try typedArrayCreateLen(self, this, args.len);
    const ta = result.asObj().typed_array.?;
    for (args, 0..) |av, i| try self.taStore(ta, i, av);
    return result;
}

/// `%TypedArray%.from(source, mapfn?, thisArg?)` — `this` is a view constructor;
/// collect the source's values (iterator or array-like), optionally map, and
/// store them into a new view.
fn typedArrayFromFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (!isConstructorValue(this)) return self.throwError("TypeError", "%TypedArray%.from requires a constructor `this`");
    const source = if (args.len > 0) args[0] else Value.undef();
    const mapfn = if (args.len > 1) args[1] else Value.undef();
    if (!mapfn.isUndefined() and !mapfn.isCallable()) return self.throwError("TypeError", "%TypedArray%.from mapfn is not callable");
    const this_arg = if (args.len > 2) args[2] else Value.undef();

    const using_iter = if (self.symbolIteratorKey()) |ik| try self.getProperty(source, ik) else Value.undef();
    if (!using_iter.isUndefined() and !using_iter.isNull()) {
        if (!using_iter.isCallable()) return self.throwError("TypeError", "%TypedArray%.from source iterator is not callable");
        const iterator = try self.callValueWithThis(using_iter, &.{}, source);
        if (!iterator.isObject()) return self.throwError("TypeError", "%TypedArray%.from iterator is not an object");
        const next = try self.getProperty(iterator, "next");
        if (!next.isCallable()) return self.throwError("TypeError", "%TypedArray%.from iterator next is not callable");
        var list: std.ArrayListUnmanaged(Value) = .empty;
        while (true) {
            const r = try self.callValueWithThis(next, &.{}, iterator);
            if (!r.isObject()) return self.throwError("TypeError", "%TypedArray%.from iterator result is not an object");
            if ((try self.getProperty(r, "done")).toBoolean()) break;
            try list.append(self.arena, try self.getProperty(r, "value"));
        }
        const result = try typedArrayCreateLen(self, this, list.items.len);
        const ta = result.asObj().typed_array.?;
        for (list.items, 0..) |v, i| {
            const mapped = if (mapfn.isCallable()) try self.callValueWithThis(mapfn, &.{ v, Value.num(@floatFromInt(i)) }, this_arg) else v;
            try self.taStore(ta, i, mapped);
        }
        return result;
    }

    const len = toLen(try self.toNumberV(try self.getProperty(source, "length")));
    const result = try typedArrayCreateLen(self, this, len);
    const ta = result.asObj().typed_array.?;
    var i: usize = 0;
    while (i < len) : (i += 1) {
        var kb: [24]u8 = undefined;
        const k = std.fmt.bufPrint(&kb, "{d}", .{i}) catch unreachable;
        const v = try self.getProperty(source, k);
        const mapped = if (mapfn.isCallable()) try self.callValueWithThis(mapfn, &.{ v, Value.num(@floatFromInt(i)) }, this_arg) else v;
        try self.taStore(ta, i, mapped);
    }
    return result;
}

/// A `%TypedArray%.prototype` accessor getter (`length`/`byteLength`/`byteOffset`/
/// `buffer`/`@@toStringTag`). All but `@@toStringTag` brand-check the receiver;
/// `@@toStringTag` returns undefined for a non-TypedArray (no throw).
fn taProtoGetter(comptime which: enum { length, byte_length, byte_offset, buffer, tag }) value.NativeFn {
    return struct {
        fn call(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
            _ = args;
            const self: *Interpreter = @ptrCast(@alignCast(ctx));
            if (!this.isObject() or this.asObj().typed_array == null) {
                if (which == .tag) return Value.undef();
                return self.throwError("TypeError", "%TypedArray%.prototype accessor called on a non-TypedArray");
            }
            const ta = this.asObj().typed_array.?;
            const cur = ta.currentLength(); // null when detached / out of bounds
            return switch (which) {
                .length => Value.num(@floatFromInt(cur orelse 0)),
                .byte_length => Value.num(@floatFromInt((cur orelse 0) * ta.kind.byteSize())),
                .byte_offset => Value.num(@floatFromInt(if (cur == null) 0 else ta.byte_offset)),
                .buffer => Value.obj(ta.buffer),
                .tag => Value.str(ta.kind.ctorName()),
            };
        }
    }.call;
}

// ===== Uint8Array <-> base64 / hex (ES2025) ================================
// Faithful port of the proposal-arraybuffer-base64 abstract operations
// (FromBase64 / FromHex / encode). Whitespace, padding, the lastChunkHandling
// modes, the strict extra-bits check, and the maxLength byte budget (used by
// the set* methods) all follow the spec.

const LastChunkHandling = enum { loose, strict, stop_before_partial };

/// A decode result: bytes produced so far, the number of input characters
/// fully consumed (`read`), and whether a SyntaxError should be raised. The
/// set* methods write `bytes` into the target *before* raising, so an error
/// still leaves the valid leading chunks in place.
const DecodeResult = struct { read: usize, bytes: []u8, err: bool };

fn isAsciiB64Whitespace(c: u8) bool {
    return c == 0x09 or c == 0x0A or c == 0x0C or c == 0x0D or c == 0x20;
}

fn base64Sextet(c: u8, url: bool) ?u8 {
    return switch (c) {
        'A'...'Z' => c - 'A',
        'a'...'z' => c - 'a' + 26,
        '0'...'9' => c - '0' + 52,
        '+' => if (url) null else @as(u8, 62),
        '/' => if (url) null else @as(u8, 63),
        '-' => if (url) @as(u8, 62) else null,
        '_' => if (url) @as(u8, 63) else null,
        else => null,
    };
}

fn hexDigit(c: u8) ?u8 {
    return switch (c) {
        '0'...'9' => c - '0',
        'a'...'f' => c - 'a' + 10,
        'A'...'F' => c - 'A' + 10,
        else => null,
    };
}

/// DecodeBase64Chunk: append the 1–3 bytes a 2/3/4-sextet chunk encodes. With
/// `throw_extra` (strict mode) a non-zero tail-bit pattern yields no output and
/// signals an error instead.
fn decodeBase64Chunk(self: *Interpreter, bytes: *std.ArrayListUnmanaged(u8), chunk: []const u8, throw_extra: bool) EvalError!bool {
    switch (chunk.len) {
        2 => {
            if (throw_extra and (chunk[1] & 0x0F) != 0) return true;
            try bytes.append(self.arena, (chunk[0] << 2) | (chunk[1] >> 4));
        },
        3 => {
            if (throw_extra and (chunk[2] & 0x03) != 0) return true;
            try bytes.append(self.arena, (chunk[0] << 2) | (chunk[1] >> 4));
            try bytes.append(self.arena, ((chunk[1] & 0x0F) << 4) | (chunk[2] >> 2));
        },
        else => {
            try bytes.append(self.arena, (chunk[0] << 2) | (chunk[1] >> 4));
            try bytes.append(self.arena, ((chunk[1] & 0x0F) << 4) | (chunk[2] >> 2));
            try bytes.append(self.arena, ((chunk[2] & 0x03) << 6) | chunk[3]);
        },
    }
    return false;
}

fn decodeBase64(self: *Interpreter, s: []const u8, url: bool, lch: LastChunkHandling, max_len: usize) EvalError!DecodeResult {
    var bytes: std.ArrayListUnmanaged(u8) = .empty;
    var read: usize = 0;
    var chunk: [4]u8 = undefined;
    var chunk_len: usize = 0;
    var index: usize = 0;
    const length = s.len;
    if (max_len == 0) return .{ .read = 0, .bytes = bytes.items, .err = false };
    while (true) {
        while (index < length and isAsciiB64Whitespace(s[index])) index += 1;
        if (index == length) {
            if (chunk_len > 0) switch (lch) {
                .stop_before_partial => return .{ .read = read, .bytes = bytes.items, .err = false },
                .loose => {
                    if (chunk_len == 1) return .{ .read = read, .bytes = bytes.items, .err = true };
                    _ = try decodeBase64Chunk(self, &bytes, chunk[0..chunk_len], false);
                },
                .strict => return .{ .read = read, .bytes = bytes.items, .err = true },
            };
            return .{ .read = length, .bytes = bytes.items, .err = false };
        }
        const ch = s[index];
        if (ch == '=') {
            if (chunk_len < 2) return .{ .read = read, .bytes = bytes.items, .err = true };
            index += 1;
            while (index < length and isAsciiB64Whitespace(s[index])) index += 1;
            if (chunk_len == 2) {
                if (index == length) {
                    if (lch == .stop_before_partial) return .{ .read = read, .bytes = bytes.items, .err = false };
                    return .{ .read = read, .bytes = bytes.items, .err = true };
                }
                if (s[index] == '=') {
                    index += 1;
                    while (index < length and isAsciiB64Whitespace(s[index])) index += 1;
                }
            }
            if (index < length) return .{ .read = read, .bytes = bytes.items, .err = true };
            const had_extra = try decodeBase64Chunk(self, &bytes, chunk[0..chunk_len], lch == .strict);
            return .{ .read = if (had_extra) read else length, .bytes = bytes.items, .err = had_extra };
        }
        const val = base64Sextet(ch, url) orelse return .{ .read = read, .bytes = bytes.items, .err = true };
        const remaining = max_len - bytes.items.len;
        // Stop before a chunk that the byte budget cannot fully hold.
        if ((remaining == 1 and chunk_len == 2) or (remaining == 2 and chunk_len == 3))
            return .{ .read = read, .bytes = bytes.items, .err = false };
        chunk[chunk_len] = val;
        chunk_len += 1;
        index += 1;
        if (chunk_len == 4) {
            _ = try decodeBase64Chunk(self, &bytes, chunk[0..4], false);
            chunk_len = 0;
            read = index;
            if (bytes.items.len == max_len) return .{ .read = read, .bytes = bytes.items, .err = false };
        }
    }
}

fn decodeHex(self: *Interpreter, s: []const u8, max_len: usize) EvalError!DecodeResult {
    var bytes: std.ArrayListUnmanaged(u8) = .empty;
    var read: usize = 0;
    // FromHex rejects an odd-length input up front, before decoding any byte —
    // a partial leading run is *not* written when the total length is odd.
    if (s.len % 2 != 0) return .{ .read = 0, .bytes = bytes.items, .err = true };
    while (read < s.len and bytes.items.len < max_len) {
        const hi = hexDigit(s[read]) orelse return .{ .read = read, .bytes = bytes.items, .err = true };
        const lo = hexDigit(s[read + 1]) orelse return .{ .read = read, .bytes = bytes.items, .err = true };
        try bytes.append(self.arena, hi * 16 + lo);
        read += 2;
    }
    return .{ .read = read, .bytes = bytes.items, .err = false };
}

fn encodeBase64(self: *Interpreter, bytes: []const u8, url: bool, omit_padding: bool) EvalError![]const u8 {
    const tbl: []const u8 = if (url)
        "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789-_"
    else
        "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/";
    var out: std.ArrayListUnmanaged(u8) = .empty;
    var i: usize = 0;
    while (i + 3 <= bytes.len) : (i += 3) {
        const n = (@as(u32, bytes[i]) << 16) | (@as(u32, bytes[i + 1]) << 8) | bytes[i + 2];
        try out.append(self.arena, tbl[(n >> 18) & 63]);
        try out.append(self.arena, tbl[(n >> 12) & 63]);
        try out.append(self.arena, tbl[(n >> 6) & 63]);
        try out.append(self.arena, tbl[n & 63]);
    }
    switch (bytes.len - i) {
        1 => {
            const n = @as(u32, bytes[i]) << 16;
            try out.append(self.arena, tbl[(n >> 18) & 63]);
            try out.append(self.arena, tbl[(n >> 12) & 63]);
            if (!omit_padding) try out.appendSlice(self.arena, "==");
        },
        2 => {
            const n = (@as(u32, bytes[i]) << 16) | (@as(u32, bytes[i + 1]) << 8);
            try out.append(self.arena, tbl[(n >> 18) & 63]);
            try out.append(self.arena, tbl[(n >> 12) & 63]);
            try out.append(self.arena, tbl[(n >> 6) & 63]);
            if (!omit_padding) try out.append(self.arena, '=');
        },
        else => {},
    }
    return out.items;
}

/// GetOptionsObject: undefined → no options; an ordinary object → itself;
/// anything else (including null, symbols, bigints) → TypeError.
fn getOptionsObject(self: *Interpreter, v: Value) EvalError!?*value.Object {
    if (v.isUndefined()) return null;
    if (v.isObject() and !v.asObj().is_symbol and !v.asObj().is_bigint) return v.asObj();
    return self.throwError("TypeError", "options must be an object");
}

/// GetOption for a string-typed option: the value must be undefined (→default)
/// or a primitive String drawn from `allowed`; no ToString coercion.
fn getStringOption(self: *Interpreter, opts: ?*value.Object, key: []const u8, allowed: []const []const u8, default: []const u8) EvalError![]const u8 {
    const o = opts orelse return default;
    const v = try self.getProperty(Value.obj(o), key);
    if (v.isUndefined()) return default;
    if (!v.isString()) return self.throwError("TypeError", "option value must be a string");
    for (allowed) |a| if (std.mem.eql(u8, v.asStr(), a)) return v.asStr();
    return self.throwError("TypeError", "invalid option value");
}

fn getBoolOption(self: *Interpreter, opts: ?*value.Object, key: []const u8) EvalError!bool {
    const o = opts orelse return false;
    return (try self.getProperty(Value.obj(o), key)).toBoolean();
}

fn uint8ArrayBytes(o: *value.Object) ?[]u8 {
    const ta = o.typed_array orelse return null;
    if (ta.kind != .u8) return null;
    const buf = ta.buffer.array_buffer orelse return null;
    if (buf.isDetached()) return null;
    const avail = if (ta.byte_offset <= buf.bytes().len) buf.bytes().len - ta.byte_offset else 0;
    const n = @min(ta.length, avail);
    return buf.bytes()[ta.byte_offset .. ta.byte_offset + n];
}

fn requireUint8Array(self: *Interpreter, this: Value) EvalError!*value.Object {
    if (this.isObject()) if (this.asObj().typed_array) |ta| if (ta.kind == .u8) return this.asObj();
    return self.throwError("TypeError", "method requires a Uint8Array receiver");
}

fn uint8FromBase64Fn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    _ = this;
    const sv = arg(args, 0);
    if (!sv.isString()) return self.throwError("TypeError", "Uint8Array.fromBase64 requires a string argument");
    const opts = try getOptionsObject(self, arg(args, 1));
    const url = std.mem.eql(u8, try getStringOption(self, opts, "alphabet", &.{ "base64", "base64url" }, "base64"), "base64url");
    const lch = lastChunkFromName(try getStringOption(self, opts, "lastChunkHandling", &.{ "loose", "strict", "stop-before-partial" }, "loose"));
    const r = try decodeBase64(self, sv.asStr(), url, lch, std.math.maxInt(usize));
    if (r.err) return self.throwError("SyntaxError", "invalid base64-encoded string");
    const o = try newTypedArray(self, .u8, r.bytes.len);
    @memcpy(o.typed_array.?.buffer.array_buffer.?.bytes()[0..r.bytes.len], r.bytes);
    return Value.obj(o);
}

fn uint8FromHexFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    _ = this;
    const sv = arg(args, 0);
    if (!sv.isString()) return self.throwError("TypeError", "Uint8Array.fromHex requires a string argument");
    const r = try decodeHex(self, sv.asStr(), std.math.maxInt(usize));
    if (r.err) return self.throwError("SyntaxError", "invalid hex-encoded string");
    const o = try newTypedArray(self, .u8, r.bytes.len);
    @memcpy(o.typed_array.?.buffer.array_buffer.?.bytes()[0..r.bytes.len], r.bytes);
    return Value.obj(o);
}

fn uint8ToBase64Fn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const o = try requireUint8Array(self, this);
    const opts = try getOptionsObject(self, arg(args, 0));
    const url = std.mem.eql(u8, try getStringOption(self, opts, "alphabet", &.{ "base64", "base64url" }, "base64"), "base64url");
    const omit = try getBoolOption(self, opts, "omitPadding");
    const bytes = uint8ArrayBytes(o) orelse return self.throwError("TypeError", "Uint8Array buffer is detached");
    return Value.str(try encodeBase64(self, bytes, url, omit));
}

fn uint8ToHexFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    _ = args;
    const o = try requireUint8Array(self, this);
    const bytes = uint8ArrayBytes(o) orelse return self.throwError("TypeError", "Uint8Array buffer is detached");
    const hex = "0123456789abcdef";
    var out: std.ArrayListUnmanaged(u8) = .empty;
    for (bytes) |b| {
        try out.append(self.arena, hex[b >> 4]);
        try out.append(self.arena, hex[b & 0x0F]);
    }
    return Value.str(out.items);
}

fn uint8SetFromBase64Fn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const o = try requireUint8Array(self, this);
    if (o.typed_array.?.buffer.array_buffer.?.immutable) return self.throwError("TypeError", "Cannot write to a Uint8Array backed by an immutable ArrayBuffer");
    const sv = arg(args, 0);
    if (!sv.isString()) return self.throwError("TypeError", "setFromBase64 requires a string argument");
    const opts = try getOptionsObject(self, arg(args, 1));
    const url = std.mem.eql(u8, try getStringOption(self, opts, "alphabet", &.{ "base64", "base64url" }, "base64"), "base64url");
    const lch = lastChunkFromName(try getStringOption(self, opts, "lastChunkHandling", &.{ "loose", "strict", "stop-before-partial" }, "loose"));
    const target = uint8ArrayBytes(o) orelse return self.throwError("TypeError", "Uint8Array buffer is detached");
    const r = try decodeBase64(self, sv.asStr(), url, lch, target.len);
    @memcpy(target[0..r.bytes.len], r.bytes);
    if (r.err) return self.throwError("SyntaxError", "invalid base64-encoded string");
    return try self.readWrittenResult(r.read, r.bytes.len);
}

fn uint8SetFromHexFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const o = try requireUint8Array(self, this);
    if (o.typed_array.?.buffer.array_buffer.?.immutable) return self.throwError("TypeError", "Cannot write to a Uint8Array backed by an immutable ArrayBuffer");
    const sv = arg(args, 0);
    if (!sv.isString()) return self.throwError("TypeError", "setFromHex requires a string argument");
    const target = uint8ArrayBytes(o) orelse return self.throwError("TypeError", "Uint8Array buffer is detached");
    const r = try decodeHex(self, sv.asStr(), target.len);
    @memcpy(target[0..r.bytes.len], r.bytes);
    if (r.err) return self.throwError("SyntaxError", "invalid hex-encoded string");
    return try self.readWrittenResult(r.read, r.bytes.len);
}

fn lastChunkFromName(s: []const u8) LastChunkHandling {
    if (std.mem.eql(u8, s, "strict")) return .strict;
    if (std.mem.eql(u8, s, "stop-before-partial")) return .stop_before_partial;
    return .loose;
}

fn taProtoMethod(comptime name: []const u8) value.NativeFn {
    return struct {
        fn call(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
            const self: *Interpreter = @ptrCast(@alignCast(ctx));
            if (!this.isObject() or this.asObj().typed_array == null)
                return self.throwError("TypeError", "TypedArray.prototype method called on a non-TypedArray");
            return (try typedArrayMethod(self, this.asObj(), name, args)) orelse Value.undef();
        }
    }.call;
}

/// `new ArrayBuffer(byteLength, { maxByteLength }?)`.
fn arrayBufferConstructorFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (self.new_target.isUndefined()) return self.throwError("TypeError", "Constructor ArrayBuffer requires 'new'");
    const len = try toIndexArg(self, if (args.len > 0) args[0] else Value.undef());
    // The optional `maxByteLength` option makes the buffer resizable.
    var max: ?usize = null;
    if (args.len > 1 and args[1].isObject()) {
        const mv = try self.getProperty(args[1], "maxByteLength");
        if (!mv.isUndefined()) {
            const m = try toIndexArg(self, mv);
            if (m > 0x7fffffff or m < len) return self.throwError("RangeError", "Invalid maxByteLength");
            max = @intCast(m);
        }
    }
    // AllocateArrayBuffer reads the prototype (GetPrototypeFromConstructor) BEFORE
    // CreateByteDataBlock — so a throwing `newTarget.prototype` getter wins over
    // the length RangeError.
    const proto = try self.protoFromCtor("ArrayBuffer");
    if (len > 0x7fffffff) return self.throwError("RangeError", "Invalid ArrayBuffer length");
    const o = try self.makeArrayBuffer(@intCast(len));
    o.array_buffer.?.max_byte_length = max;
    if (proto) |pr| o.setProtoAtomic(pr);
    return Value.obj(o);
}

fn arrayBufferGetter(comptime which: enum { byte_length, max_byte_length, resizable, detached, immutable }) value.NativeFn {
    return struct {
        fn call(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
            _ = args;
            const self: *Interpreter = @ptrCast(@alignCast(ctx));
            if (!this.isObject() or this.asObj().array_buffer == null) return self.throwError("TypeError", "ArrayBuffer.prototype accessor called on a non-ArrayBuffer");
            const ab = this.asObj().array_buffer.?;
            // These are %ArrayBuffer.prototype% accessors — a SharedArrayBuffer
            // receiver throws (it has its own byteLength/maxByteLength/growable).
            if (ab.is_shared) return self.throwError("TypeError", "ArrayBuffer.prototype accessor called on a SharedArrayBuffer");
            return switch (which) {
                .byte_length => Value.num(@floatFromInt(if (ab.isDetached()) 0 else ab.bytes().len)),
                .max_byte_length => Value.num(@floatFromInt(if (ab.isDetached()) 0 else (ab.max_byte_length orelse ab.bytes().len))),
                .resizable => Value.boolVal(ab.max_byte_length != null),
                .detached => Value.boolVal(ab.isDetached()),
                .immutable => Value.boolVal(ab.immutable),
            };
        }
    }.call;
}

/// `ArrayBuffer.prototype.transferToImmutable([newLength])` — ArrayBufferCopyAndDetach
/// with `preserveResizability` = immutable: copy the (clamped) bytes into a fresh
/// fixed-length immutable buffer and detach the source.
fn arrayBufferTransferToImmutableFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (!this.isObject() or this.asObj().array_buffer == null) return self.throwError("TypeError", "ArrayBuffer.prototype.transferToImmutable called on a non-ArrayBuffer");
    const ab = this.asObj().array_buffer.?;
    if (ab.is_shared) return self.throwError("TypeError", "transferToImmutable cannot be called on a SharedArrayBuffer");
    const new_len: usize = if (args.len > 0 and !args[0].isUndefined()) @intCast(try toIndexArg(self, args[0])) else ab.bytes().len;
    if (ab.isDetached()) return self.throwError("TypeError", "ArrayBuffer is detached");
    if (ab.immutable) return self.throwError("TypeError", "ArrayBuffer is already immutable");
    const out = try self.makeArrayBuffer(new_len); // alloc before the lock (may GC)
    // Serialize bytes-copy + detach against a peer's Atomics (see transfer).
    ab.lockBuffer();
    const was_detached = ab.isDetached();
    if (!was_detached) {
        const n = @min(new_len, ab.bytes().len);
        @memcpy(out.array_buffer.?.bytes()[0..n], ab.bytes()[0..n]);
        out.array_buffer.?.immutable = true;
        ab.setDetached(true);
    }
    ab.unlockBuffer();
    if (was_detached) return self.throwError("TypeError", "ArrayBuffer is detached");
    return Value.obj(out);
}

/// `ArrayBuffer.prototype.sliceToImmutable([start[, end]])` — like `slice`, but
/// the resulting buffer is immutable and the source is left intact.
fn arrayBufferSliceToImmutableFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (!this.isObject() or this.asObj().array_buffer == null) return self.throwError("TypeError", "ArrayBuffer.prototype.sliceToImmutable called on a non-ArrayBuffer");
    const ab = this.asObj().array_buffer.?;
    if (ab.is_shared) return self.throwError("TypeError", "sliceToImmutable cannot be called on a SharedArrayBuffer");
    if (ab.isDetached()) return self.throwError("TypeError", "ArrayBuffer is detached");
    const blen = ab.bytes().len;
    const start = try relIndex(self, if (args.len > 0) args[0] else Value.undef(), blen, 0);
    const end = try relIndex(self, if (args.len > 1) args[1] else Value.undef(), blen, @floatFromInt(blen));
    const count = if (end > start) end - start else 0;
    if (ab.isDetached()) return self.throwError("TypeError", "ArrayBuffer is detached");
    const src_len = ab.bytes().len;
    if (src_len < end) return self.throwError("RangeError", "ArrayBuffer shrank below resolved slice end");
    const out = try self.makeArrayBuffer(count);
    @memcpy(out.array_buffer.?.bytes()[0..count], ab.bytes()[start .. start + count]);
    out.array_buffer.?.immutable = true;
    return Value.obj(out);
}

/// `ArrayBuffer.prototype.resize(newByteLength)` — grow/shrink a resizable buffer.
fn arrayBufferResizeFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (!this.isObject() or this.asObj().array_buffer == null) return self.throwError("TypeError", "ArrayBuffer.prototype.resize called on a non-ArrayBuffer");
    const ab = this.asObj().array_buffer.?;
    if (ab.is_shared) return self.throwError("TypeError", "ArrayBuffer.prototype.resize called on a SharedArrayBuffer");
    if (ab.max_byte_length == null) return self.throwError("TypeError", "ArrayBuffer is not resizable");
    const new_len = try toIndexArg(self, if (args.len > 0) args[0] else Value.undef());
    if (ab.isDetached()) return self.throwError("TypeError", "ArrayBuffer is detached");
    if (new_len > ab.max_byte_length.?) return self.throwError("RangeError", "resize exceeds maxByteLength");
    const nl: usize = @intCast(new_len);
    const fresh = try self.allocArrayBufferBytes(nl);
    errdefer self.freeArrayBufferBytes(fresh, ab.gc_owned);
    ab.lockBuffer();
    if (ab.isDetached()) {
        ab.unlockBuffer();
        return self.throwError("TypeError", "ArrayBuffer is detached");
    }
    const old_data = ab.local_data;
    const copy_len = @min(nl, old_data.len);
    @memcpy(fresh[0..copy_len], old_data[0..copy_len]);
    ab.swapLocalData(fresh); // seqlock: bytes() readers retry across the swap
    ab.unlockBuffer();
    self.freeArrayBufferBytes(old_data, ab.gc_owned);
    return Value.undef();
}

/// `ArrayBuffer.prototype.transfer(newLength?)` / `transferToFixedLength` — move
/// the bytes into a new buffer and detach the original.
fn arrayBufferTransferFn(comptime fixed: bool) value.NativeFn {
    return struct {
        fn call(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
            const self: *Interpreter = @ptrCast(@alignCast(ctx));
            if (!this.isObject() or this.asObj().array_buffer == null) return self.throwError("TypeError", "ArrayBuffer.prototype.transfer called on a non-ArrayBuffer");
            const ab = this.asObj().array_buffer.?;
            if (ab.is_shared) return self.throwError("TypeError", "ArrayBuffer.prototype.transfer called on a SharedArrayBuffer");
            const new_len: usize = if (args.len > 0 and !args[0].isUndefined()) @intCast(try toIndexArg(self, args[0])) else ab.bytes().len;
            if (ab.isDetached()) return self.throwError("TypeError", "ArrayBuffer is detached");
            if (ab.immutable) return self.throwError("TypeError", "an immutable ArrayBuffer cannot be transferred");
            const out = try self.makeArrayBuffer(new_len); // alloc before the lock (may GC)
            // Serialize the bytes copy + detach against a peer's Atomics on this
            // buffer (which take `lockBuffer`) under `parallel_js`. Detach does not
            // free `local_data` (GC owns it), so this is a data-race fix, not a
            // UAF fix — `lockBuffer` suffices. Throw outside the lock (throwError
            // allocates). Re-check `detached` under the lock.
            ab.lockBuffer();
            const was_detached = ab.isDetached();
            if (!was_detached) {
                const n = @min(new_len, ab.bytes().len);
                @memcpy(out.array_buffer.?.bytes()[0..n], ab.bytes()[0..n]);
                if (!fixed) out.array_buffer.?.max_byte_length = ab.max_byte_length;
                ab.setDetached(true);
            }
            ab.unlockBuffer();
            if (was_detached) return self.throwError("TypeError", "ArrayBuffer is detached");
            return Value.obj(out);
        }
    }.call;
}

/// `ArrayBuffer.isView(v)` — true for a typed-array (or DataView) view.
fn arrayBufferIsViewFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = ctx;
    _ = this;
    const v = if (args.len > 0) args[0] else Value.undef();
    return Value.boolVal(v.isObject() and (v.asObj().typed_array != null or v.asObj().data_view != null));
}

// ===== Intl (ECMA-402) ===============================================
// A structural + en-centric core: the namespace, getCanonicalLocales, Locale,
// and the formatter/Collator/PluralRules constructors with `format`/`compare`/
// `select`/`resolvedOptions`. Locale-specific output uses sensible English
// defaults (no CLDR data).

/// Canonicalize a single BCP-47 tag (case-normalize the subtags). Returns null
/// for a structurally invalid tag.
/// IsStructurallyValidLanguageTag (UTS-35 unicode_locale_id, the subset Intl
/// requires): language [-script] [-region] variant* extension* [-x privateuse].
/// Rejects extlang, grandfathered, malformed, and duplicate subtags/singletons.
fn isStructurallyValidLanguageTag(tag: []const u8) bool {
    if (tag.len == 0 or tag[0] == '-' or tag[tag.len - 1] == '-') return false;
    const isA = std.ascii.isAlphabetic;
    const isD = std.ascii.isDigit;
    const isAN = std.ascii.isAlphanumeric;
    // Only ASCII alphanumerics and '-' (rejects underscores, non-ASCII, '*', NUL, space).
    for (tag) |c| if (c != '-' and !isAN(c)) return false;

    const Helper = struct {
        fn allAlpha(s: []const u8) bool {
            for (s) |c| if (!isA(c)) return false;
            return s.len > 0;
        }
        fn allDigit(s: []const u8) bool {
            for (s) |c| if (!isD(c)) return false;
            return s.len > 0;
        }
        fn isVariant(s: []const u8) bool {
            // 5-8 alphanum, or 4 chars with a leading digit.
            if (s.len >= 5 and s.len <= 8) return true;
            if (s.len == 4 and isD(s[0])) return true;
            return false;
        }
    };

    var it = std.mem.splitScalar(u8, tag, '-');
    const lang = it.next().?;
    // language: 2-3 or 5-8 ALPHA (no extlang, no 4-alpha, no numeric).
    if (!Helper.allAlpha(lang)) return false;
    if (!((lang.len >= 2 and lang.len <= 3) or (lang.len >= 5 and lang.len <= 8))) return false;

    var have_script = false;
    var have_region = false;
    var in_variants = false;
    var variants: [16][]const u8 = undefined;
    var nvar: usize = 0;
    // Extension state: 0 = in language-id; 'x' = private use; else current singleton.
    var ext: u8 = 0;
    var ext_count: usize = 0;
    var seen_singletons: [40]u8 = undefined;
    var nsing: usize = 0;
    // -t- transform extension: parse its tlang (language[-script][-region]
    // [-variant…]) so a malformed tlang (e.g. a 4-letter "language", a second
    // script, or a duplicate variant) is rejected.
    var t_in_tlang = false;
    var t_have_lang = false;
    var t_have_script = false;
    var t_have_region = false;
    var tvariants: [16][]const u8 = undefined;
    var ntvar: usize = 0;
    var t_field_pending = false; // a -t- tfield key awaiting its value

    while (it.next()) |s| {
        if (s.len == 0) return false; // empty subtag (double dash)
        // Inside private-use, every subtag (including length-1) is a private-use
        // subtag, not a new singleton.
        if (ext == 'x') {
            if (s.len < 1 or s.len > 8) return false; // private-use subtag: 1-8 alnum
            ext_count += 1;
            continue;
        }
        if (s.len == 1) {
            // A singleton starts a (private-use or other) extension.
            if (ext != 0 and ext_count == 0) return false; // previous singleton had no subtags
            if (ext == 't' and t_field_pending) return false; // -t- tfield key with no value
            const sl = std.ascii.toLower(s[0]);
            for (seen_singletons[0..nsing]) |p| if (p == sl) return false; // duplicate singleton
            seen_singletons[nsing] = sl;
            nsing += 1;
            ext = sl;
            ext_count = 0;
            if (sl == 't') {
                t_in_tlang = true;
                t_have_lang = false;
                t_have_script = false;
                t_have_region = false;
                ntvar = 0;
            }
            continue;
        }
        if (ext != 0) {
            if (s.len < 2 or s.len > 8) return false; // extension subtag: 2-8 alnum
            // A -u- 2-char subtag is a keyword key, whose second character must
            // be ALPHA (key = alphanum ALPHA); e.g. "c0"/"00" are invalid.
            if (ext == 'u' and s.len == 2 and !isA(s[1])) return false;
            ext_count += 1;
            // The -t- tlang (language[-script][-region][-variant…]) precedes the
            // tfields; a tfield key (2 chars: ALPHA DIGIT) ends it.
            if (ext == 't' and !t_in_tlang) {
                // In the tfields: key (2 chars: ALPHA DIGIT) then 1+ values
                // (3-8 alnum). A key with no value, or two keys in a row, is
                // invalid.
                const is_key = s.len == 2 and isA(s[0]) and isD(s[1]);
                if (is_key) {
                    if (t_field_pending) return false; // previous key had no value
                    t_field_pending = true;
                } else {
                    if (s.len < 3) return false; // a value is 3-8 alnum
                    t_field_pending = false;
                }
            } else if (ext == 't' and t_in_tlang) {
                const is_tfield_key = s.len == 2 and isA(s[0]) and isD(s[1]);
                if (is_tfield_key) {
                    t_in_tlang = false; // entering the tfields
                    t_field_pending = true; // this key still needs a value
                } else if (!t_have_lang) {
                    // tlang language: 2-3 or 5-8 ALPHA.
                    if (!(Helper.allAlpha(s) and ((s.len >= 2 and s.len <= 3) or (s.len >= 5 and s.len <= 8)))) return false;
                    t_have_lang = true;
                } else if (!t_have_script and !t_have_region and ntvar == 0 and s.len == 4 and Helper.allAlpha(s)) {
                    t_have_script = true;
                } else if (!t_have_region and ntvar == 0 and ((s.len == 2 and Helper.allAlpha(s)) or (s.len == 3 and Helper.allDigit(s)))) {
                    t_have_region = true;
                } else if (Helper.isVariant(s)) {
                    for (tvariants[0..ntvar]) |v| if (std.ascii.eqlIgnoreCase(v, s)) return false;
                    if (ntvar < tvariants.len) {
                        tvariants[ntvar] = s;
                        ntvar += 1;
                    }
                } else return false;
            }
            continue;
        }
        // Still in the language-id: script, then region, then variants.
        if (!have_script and !have_region and !in_variants and s.len == 4 and Helper.allAlpha(s)) {
            have_script = true;
        } else if (!have_region and !in_variants and ((s.len == 2 and Helper.allAlpha(s)) or (s.len == 3 and Helper.allDigit(s)))) {
            have_region = true;
        } else if (Helper.isVariant(s)) {
            for (variants[0..nvar]) |v| if (std.ascii.eqlIgnoreCase(v, s)) return false; // duplicate variant
            if (nvar < variants.len) {
                variants[nvar] = s;
                nvar += 1;
            }
            in_variants = true;
        } else return false;
    }
    // A trailing singleton must have had at least one subtag.
    if (ext != 0 and ext_count == 0) return false;
    // A trailing -t- tfield key must have had a value.
    if (ext == 't' and t_field_pending) return false;
    return true;
}

fn lowerDup(a: std.mem.Allocator, s: []const u8) []const u8 {
    return std.ascii.allocLowerString(a, s) catch s;
}

const ReparsedLangId = struct {
    lang: []const u8,
    script: []const u8 = "",
    region: []const u8 = "",
    variants: std.ArrayListUnmanaged([]const u8) = .empty,
};

/// A lowercased (language, script, region) triple for the likely-subtags
/// algorithm; empty fields are absent.
const Triple = struct { l: []const u8, s: []const u8 = "", r: []const u8 = "" };

fn parseTriple(s: []const u8) Triple {
    var t: Triple = .{ .l = "" };
    var it = std.mem.splitScalar(u8, s, '-');
    t.l = it.next() orelse "";
    while (it.next()) |part| {
        if (t.s.len == 0 and t.r.len == 0 and part.len == 4 and std.ascii.isAlphabetic(part[0])) {
            t.s = part;
        } else if (t.r.len == 0 and ((part.len == 2 and std.ascii.isAlphabetic(part[0])) or (part.len == 3 and std.ascii.isDigit(part[0])))) {
            t.r = part;
        }
    }
    return t;
}

fn tripleEql(x: Triple, y: Triple) bool {
    return std.mem.eql(u8, x.l, y.l) and std.mem.eql(u8, x.s, y.s) and std.mem.eql(u8, x.r, y.r);
}

/// Look up the maximal triple for `t` per the Add-Likely-Subtags search order.
fn cldrLookupLikely(a: std.mem.Allocator, t: Triple) ?Triple {
    const l = if (t.l.len == 0) "und" else t.l;
    if (t.s.len > 0 and t.r.len > 0) {
        if (cldr_locale.likely(std.fmt.allocPrint(a, "{s}-{s}-{s}", .{ l, t.s, t.r }) catch return null)) |v| return parseTriple(v);
    }
    if (t.r.len > 0) {
        if (cldr_locale.likely(std.fmt.allocPrint(a, "{s}-{s}", .{ l, t.r }) catch return null)) |v| return parseTriple(v);
    }
    if (t.s.len > 0) {
        if (cldr_locale.likely(std.fmt.allocPrint(a, "{s}-{s}", .{ l, t.s }) catch return null)) |v| return parseTriple(v);
    }
    if (cldr_locale.likely(l)) |v| return parseTriple(v);
    if (t.s.len > 0) {
        if (cldr_locale.likely(std.fmt.allocPrint(a, "und-{s}", .{t.s}) catch return null)) |v| return parseTriple(v);
    }
    return null;
}

/// AddLikelySubtags: fill in missing script/region (and language) from CLDR.
fn cldrMaximize(a: std.mem.Allocator, t: Triple) ?Triple {
    const m = cldrLookupLikely(a, t) orelse return null;
    return .{
        .l = if (t.l.len > 0 and !std.mem.eql(u8, t.l, "und")) t.l else m.l,
        .s = if (t.s.len > 0) t.s else m.s,
        .r = if (t.r.len > 0) t.r else m.r,
    };
}

/// RemoveLikelySubtags: the shortest triple that maximizes back to the same.
fn cldrMinimize(a: std.mem.Allocator, t: Triple) ?Triple {
    const max = cldrMaximize(a, t) orelse return null;
    const tries = [_]Triple{
        .{ .l = max.l },
        .{ .l = max.l, .r = max.r },
        .{ .l = max.l, .s = max.s },
    };
    for (tries) |cand| {
        if (cldrMaximize(a, cand)) |cm| if (tripleEql(cm, max)) return cand;
    }
    return max;
}

/// Split a (lowercased) language-id replacement into language/script/region/
/// variants with canonical casing — used after an alias substitution.
fn cldrReparse(a: std.mem.Allocator, s: []const u8) ?ReparsedLangId {
    var r: ReparsedLangId = .{ .lang = "" };
    var it = std.mem.splitScalar(u8, s, '-');
    r.lang = lowerDup(a, it.next() orelse return null);
    while (it.next()) |part| {
        if (r.script.len == 0 and r.region.len == 0 and r.variants.items.len == 0 and part.len == 4 and std.ascii.isAlphabetic(part[0])) {
            const sc = a.alloc(u8, 4) catch return null;
            sc[0] = std.ascii.toUpper(part[0]);
            for (1..4) |i| sc[i] = std.ascii.toLower(part[i]);
            r.script = sc;
        } else if (r.region.len == 0 and r.variants.items.len == 0 and ((part.len == 2 and std.ascii.isAlphabetic(part[0])) or (part.len == 3 and std.ascii.isDigit(part[0])))) {
            r.region = std.ascii.allocUpperString(a, part) catch return null;
        } else {
            r.variants.append(a, lowerDup(a, part)) catch return null;
        }
    }
    return r;
}

/// CanonicalizeUnicodeLocaleId (UTS-35): structural validation, then subtag
/// casing, alphabetical variant sorting, `-u-`/`-t-` keyword canonicalization
/// (attributes sorted, keywords sorted by key, a "true" type dropped to a bare
/// key), and extension reordering (singletons alphabetical, private-use last).
/// CLDR-data-driven steps (legacy/grandfathered replacement beyond the simple
/// table, subtag aliases, likely-subtags) are not applied.
fn canonicalizeLocaleTag(a: std.mem.Allocator, tag: []const u8) ?[]const u8 {
    if (tag.len == 0) return null;
    if (!isStructurallyValidLanguageTag(tag)) return null;

    // language-id: language [-script] [-region] [-variant...]
    var lang: []const u8 = "";
    var script: []const u8 = "";
    var region: []const u8 = "";
    var variants: std.ArrayListUnmanaged([]const u8) = .empty;
    // Extensions, each a singleton char plus its canonicalized body (no leading
    // '-'); private-use captured separately so it can be emitted last.
    const Ext = struct { sing: u8, body: []const u8 };
    var exts: std.ArrayListUnmanaged(Ext) = .empty;
    var priv: []const u8 = ""; // the "x-..." private-use sequence (lowercased)

    var it = std.mem.splitScalar(u8, tag, '-');
    lang = lowerDup(a, it.next().?);

    // Walk the language-id subtags.
    var pending: ?[]const u8 = null; // first subtag of an extension/private-use
    while (it.next()) |part| {
        if (part.len == 1) {
            pending = part;
            break;
        }
        if (script.len == 0 and region.len == 0 and variants.items.len == 0 and part.len == 4 and std.ascii.isAlphabetic(part[0])) {
            script = a.alloc(u8, 4) catch return null;
            @memcpy(@constCast(script), part);
            @constCast(script)[0] = std.ascii.toUpper(part[0]);
            for (1..4) |i| @constCast(script)[i] = std.ascii.toLower(part[i]);
        } else if (region.len == 0 and variants.items.len == 0 and ((part.len == 2 and std.ascii.isAlphabetic(part[0])) or (part.len == 3 and std.ascii.isDigit(part[0])))) {
            region = std.ascii.allocUpperString(a, part) catch return null;
        } else {
            variants.append(a, lowerDup(a, part)) catch return null;
        }
    }
    // --- CLDR alias substitution (CanonicalizeLanguageTag) ---
    {
        // Ordered lowercased base subtags, for grandfathered/legacy matching.
        var subs: std.ArrayListUnmanaged([]const u8) = .empty;
        subs.append(a, lang) catch return null;
        if (script.len > 0) subs.append(a, lowerDup(a, script)) catch return null;
        if (region.len > 0) subs.append(a, lowerDup(a, region)) catch return null;
        for (variants.items) |v| subs.append(a, v) catch return null;
        // A grandfathered/redundant alias matches the longest prefix of the
        // language-id (>=2 subtags); the remaining subtags are kept (e.g.
        // "art-lojban-fonipa" -> "jbo-fonipa").
        var matched = false;
        var k = subs.items.len;
        while (k >= 2) : (k -= 1) {
            var key: std.ArrayListUnmanaged(u8) = .empty;
            for (subs.items[0..k], 0..) |s, i| {
                if (i != 0) key.append(a, '-') catch return null;
                key.appendSlice(a, s) catch return null;
            }
            if (cldr_locale.languageAlias(key.items)) |repl| {
                var nb: std.ArrayListUnmanaged(u8) = .empty;
                nb.appendSlice(a, repl) catch return null;
                for (subs.items[k..]) |s| {
                    nb.append(a, '-') catch return null;
                    nb.appendSlice(a, s) catch return null;
                }
                const rp = cldrReparse(a, nb.items) orelse return null;
                lang = rp.lang;
                script = rp.script;
                region = rp.region;
                variants = rp.variants;
                matched = true;
                break;
            }
        }
        if (!matched) if (cldr_locale.languageAlias(lang)) |repl| {
            // Replace just the language subtag; a replacement script/region fills
            // in only when the tag had none.
            const rp = cldrReparse(a, repl) orelse return null;
            lang = rp.lang;
            if (script.len == 0 and rp.script.len > 0) script = rp.script;
            if (region.len == 0 and rp.region.len > 0) region = rp.region;
        };
        if (script.len > 0) {
            var sl: [8]u8 = undefined;
            for (script, 0..) |c, i| sl[i] = std.ascii.toLower(c);
            if (cldr_locale.scriptAlias(sl[0..script.len])) |r| {
                const ns = a.alloc(u8, r.len) catch return null;
                @memcpy(ns, r);
                if (ns.len > 0) ns[0] = std.ascii.toUpper(ns[0]);
                script = ns;
            }
        }
        if (region.len > 0) {
            var rl: [8]u8 = undefined;
            for (region, 0..) |c, i| rl[i] = std.ascii.toLower(c);
            if (cldr_locale.territoryAlias(rl[0..region.len])) |r| {
                if (std.mem.indexOfScalar(u8, r, ' ') == null) {
                    region = std.ascii.allocUpperString(a, r) catch return null;
                } else {
                    // Multiple replacements (e.g. SU): pick the member implied by
                    // the maximized language+script, else the first.
                    var chosen: []const u8 = r[0..std.mem.indexOfScalar(u8, r, ' ').?];
                    var slo: [8]u8 = undefined;
                    for (script, 0..) |c, i| slo[i] = std.ascii.toLower(c);
                    if (cldrMaximize(a, .{ .l = lang, .s = slo[0..script.len] })) |mx| {
                        if (mx.r.len > 0) {
                            var toks = std.mem.splitScalar(u8, r, ' ');
                            while (toks.next()) |tok| if (std.mem.eql(u8, tok, mx.r)) {
                                chosen = tok;
                                break;
                            };
                        }
                    }
                    region = std.ascii.allocUpperString(a, chosen) catch return null;
                }
            }
        }
        {
            // Multi-variant CLDR aliases that current CLDR has split into
            // single-variant entries: collapse the known sequence in place.
            // "hepburn-heploc" -> "alalc97".
            var ci: usize = 0;
            while (ci + 1 < variants.items.len) : (ci += 1) {
                if (std.mem.eql(u8, variants.items[ci], "hepburn") and std.mem.eql(u8, variants.items[ci + 1], "heploc")) {
                    variants.items[ci] = "alalc97";
                    _ = variants.orderedRemove(ci + 1);
                }
            }
            // Apply variant aliases. A variant may also be canonicalized via a
            // "und-<variant>" languageAlias (e.g. und-arevela->und drops it,
            // und-polytoni->und-polyton renames); an empty result drops it.
            var nv: std.ArrayListUnmanaged([]const u8) = .empty;
            for (variants.items) |v| {
                var rep: []const u8 = v;
                if (cldr_locale.variantAlias(v)) |r| {
                    rep = r;
                } else {
                    const undkey = std.fmt.allocPrint(a, "und-{s}", .{v}) catch return null;
                    if (cldr_locale.languageAlias(undkey)) |la| {
                        rep = if (std.mem.indexOfScalar(u8, la, '-')) |d| la[d + 1 ..] else "";
                    }
                }
                if (rep.len > 0) nv.append(a, a.dupe(u8, rep) catch return null) catch return null;
            }
            variants = nv;
        }
    }
    // Variants are sorted alphabetically (UTS-35 canonical order).
    std.sort.pdq([]const u8, variants.items, {}, struct {
        fn lt(_: void, x: []const u8, y: []const u8) bool {
            return std.mem.lessThan(u8, x, y);
        }
    }.lt);

    // Extensions: each singleton followed by its subtags, until the next singleton.
    while (pending) |sing_str| {
        const sing = std.ascii.toLower(sing_str[0]);
        var subs: std.ArrayListUnmanaged([]const u8) = .empty;
        pending = null;
        while (it.next()) |part| {
            // Within private-use every subtag (incl. length-1) belongs to it;
            // elsewhere a length-1 subtag starts the next extension.
            if (part.len == 1 and sing != 'x') {
                pending = part;
                break;
            }
            subs.append(a, lowerDup(a, part)) catch return null;
        }
        if (sing == 'x') {
            var b: std.ArrayListUnmanaged(u8) = .empty;
            b.appendSlice(a, "x") catch return null;
            for (subs.items) |s| {
                b.append(a, '-') catch return null;
                b.appendSlice(a, s) catch return null;
            }
            priv = b.toOwnedSlice(a) catch return null;
            break; // private-use ends the tag
        }
        const body = canonExtBody(a, sing, subs.items) orelse return null;
        exts.append(a, .{ .sing = sing, .body = body }) catch return null;
    }
    // Sort extensions by singleton (private-use is held out and emitted last).
    std.sort.pdq(Ext, exts.items, {}, struct {
        fn lt(_: void, x: Ext, y: Ext) bool {
            return x.sing < y.sing;
        }
    }.lt);

    var out: std.ArrayListUnmanaged(u8) = .empty;
    out.appendSlice(a, lang) catch return null;
    if (script.len > 0) {
        out.append(a, '-') catch return null;
        out.appendSlice(a, script) catch return null;
    }
    if (region.len > 0) {
        out.append(a, '-') catch return null;
        out.appendSlice(a, region) catch return null;
    }
    for (variants.items) |v| {
        out.append(a, '-') catch return null;
        out.appendSlice(a, v) catch return null;
    }
    for (exts.items) |e| {
        out.append(a, '-') catch return null;
        out.append(a, e.sing) catch return null;
        if (e.body.len > 0) {
            out.append(a, '-') catch return null;
            out.appendSlice(a, e.body) catch return null;
        }
    }
    if (priv.len > 0) {
        out.append(a, '-') catch return null;
        out.appendSlice(a, priv) catch return null;
    }
    return out.toOwnedSlice(a) catch null;
}

/// Canonicalize one extension's subtag body (already lowercased). For `-u-`:
/// sort attributes, sort keywords by key, and drop a "true" type (bare key).
/// For `-t-`: keep the tlang then sort tfields by key. Others: subtags as-is.
/// Map a few stable deprecated `-u-` keyword values to their canonical form
/// (UTS-35 §3.2.1). Only the common, data-stable aliases are covered; unknown
/// values pass through unchanged.
fn canonUKeywordValue(key: []const u8, val: []const u8) []const u8 {
    const A = struct { k: []const u8, from: []const u8, to: []const u8 };
    const table = [_]A{
        .{ .k = "ca", .from = "islamicc", .to = "islamic-civil" },
        .{ .k = "ca", .from = "ethiopic-amete-alem", .to = "ethioaa" },
        .{ .k = "ca", .from = "gregorian", .to = "gregory" },
        .{ .k = "ms", .from = "imperial", .to = "uksystem" },
        // ks (collation strength) type aliases.
        .{ .k = "ks", .from = "primary", .to = "level1" },
        .{ .k = "ks", .from = "secondary", .to = "level2" },
        .{ .k = "ks", .from = "tertiary", .to = "level3" },
        .{ .k = "ks", .from = "quaternary", .to = "level4" },
        .{ .k = "ks", .from = "quarternary", .to = "level4" },
        .{ .k = "ks", .from = "identical", .to = "identic" },
    };
    for (table) |e| if (std.mem.eql(u8, key, e.k) and std.mem.eql(u8, val, e.from)) return e.to;
    // Boolean keys map the type "yes" to "true" (which the caller then drops).
    const bool_keys = [_][]const u8{ "kb", "kc", "kh", "kk", "kn" };
    if (std.mem.eql(u8, val, "yes")) for (bool_keys) |bk| if (std.mem.eql(u8, key, bk)) return "true";
    // The rg/sd keys carry subdivision ids: replace a deprecated id with the
    // first of its CLDR replacements.
    if (std.mem.eql(u8, key, "rg") or std.mem.eql(u8, key, "sd")) {
        if (cldr_locale.subdivisionAlias(val)) |r| {
            return if (std.mem.indexOfScalar(u8, r, ' ')) |sp| r[0..sp] else r;
        }
    }
    // tz: a deprecated/alias time-zone value maps to its canonical BCP-47 type.
    if (std.mem.eql(u8, key, "tz")) {
        if (cldr_tzalias.canonical(val)) |r| return r;
    }
    return val;
}

/// Canonicalize a `-t-` transform tfield value (the stable CLDR type aliases).
fn canonTFieldValue(key: []const u8, val: []const u8) []const u8 {
    if (std.mem.eql(u8, key, "m0") and std.mem.eql(u8, val, "names")) return "prprname";
    return val;
}

fn canonExtBody(a: std.mem.Allocator, sing: u8, subs: [][]const u8) ?[]const u8 {
    var b: std.ArrayListUnmanaged(u8) = .empty;
    if (sing == 'u') {
        // Attributes (3-8 alnum) come before the first 2-char key.
        var attrs: std.ArrayListUnmanaged([]const u8) = .empty;
        const KW = struct { key: []const u8, val: []const u8 };
        var kws: std.ArrayListUnmanaged(KW) = .empty;
        var i: usize = 0;
        while (i < subs.len and subs[i].len != 2) : (i += 1) attrs.append(a, subs[i]) catch return null;
        while (i < subs.len) {
            const key = subs[i];
            i += 1;
            var vbuf: std.ArrayListUnmanaged(u8) = .empty;
            while (i < subs.len and subs[i].len != 2) : (i += 1) {
                if (vbuf.items.len > 0) vbuf.append(a, '-') catch return null;
                vbuf.appendSlice(a, subs[i]) catch return null;
            }
            var val: []const u8 = vbuf.toOwnedSlice(a) catch return null;
            val = canonUKeywordValue(key, val); // deprecated-value aliases (UTS-35), incl. yes->true
            if (std.mem.eql(u8, val, "true")) val = ""; // a "true" type is omitted
            var dup = false; // a repeated keyword key: the first occurrence wins
            for (kws.items) |k| if (std.mem.eql(u8, k.key, key)) {
                dup = true;
            };
            if (!dup) kws.append(a, .{ .key = key, .val = val }) catch return null;
        }
        std.sort.pdq([]const u8, attrs.items, {}, struct {
            fn lt(_: void, x: []const u8, y: []const u8) bool {
                return std.mem.lessThan(u8, x, y);
            }
        }.lt);
        std.sort.pdq(KW, kws.items, {}, struct {
            fn lt(_: void, x: KW, y: KW) bool {
                return std.mem.lessThan(u8, x.key, y.key);
            }
        }.lt);
        for (attrs.items) |at| {
            if (b.items.len > 0) b.append(a, '-') catch return null;
            b.appendSlice(a, at) catch return null;
        }
        for (kws.items) |kw| {
            if (b.items.len > 0) b.append(a, '-') catch return null;
            b.appendSlice(a, kw.key) catch return null;
            if (kw.val.len > 0) {
                b.append(a, '-') catch return null;
                b.appendSlice(a, kw.val) catch return null;
            }
        }
    } else if (sing == 't') {
        // -t-: an optional tlang (language[-script][-region][-variant…], variants
        // sorted) followed by tfields (key + value(s)) sorted by key. A tfield
        // "true" value is kept (unlike -u-).
        const isA = std.ascii.isAlphabetic;
        const isD = std.ascii.isDigit;
        const T = struct {
            fn isKey(s: []const u8) bool {
                return s.len == 2 and isA(s[0]) and isD(s[1]);
            }
        };
        var i: usize = 0;
        if (i < subs.len and !T.isKey(subs[i])) {
            var langv = subs[i];
            i += 1;
            if (cldr_locale.languageAlias(langv)) |r| langv = parseTriple(r).l;
            b.appendSlice(a, langv) catch return null;
            if (i < subs.len and !T.isKey(subs[i]) and subs[i].len == 4 and isA(subs[i][0])) {
                b.append(a, '-') catch return null;
                b.appendSlice(a, subs[i]) catch return null;
                i += 1;
            }
            if (i < subs.len and !T.isKey(subs[i]) and ((subs[i].len == 2 and isA(subs[i][0])) or (subs[i].len == 3 and isD(subs[i][0])))) {
                b.append(a, '-') catch return null;
                b.appendSlice(a, subs[i]) catch return null;
                i += 1;
            }
            var tvars: std.ArrayListUnmanaged([]const u8) = .empty;
            while (i < subs.len and !T.isKey(subs[i])) : (i += 1) tvars.append(a, subs[i]) catch return null;
            std.sort.pdq([]const u8, tvars.items, {}, struct {
                fn lt(_: void, x: []const u8, y: []const u8) bool {
                    return std.mem.lessThan(u8, x, y);
                }
            }.lt);
            for (tvars.items) |v| {
                b.append(a, '-') catch return null;
                b.appendSlice(a, v) catch return null;
            }
        }
        const TF = struct { key: []const u8, val: []const u8 };
        var tfs: std.ArrayListUnmanaged(TF) = .empty;
        while (i < subs.len) {
            const key = subs[i];
            i += 1;
            var vbuf: std.ArrayListUnmanaged(u8) = .empty;
            while (i < subs.len and !T.isKey(subs[i])) : (i += 1) {
                if (vbuf.items.len > 0) vbuf.append(a, '-') catch return null;
                vbuf.appendSlice(a, subs[i]) catch return null;
            }
            const val = canonTFieldValue(key, vbuf.toOwnedSlice(a) catch return null);
            tfs.append(a, .{ .key = key, .val = val }) catch return null;
        }
        std.sort.pdq(TF, tfs.items, {}, struct {
            fn lt(_: void, x: TF, y: TF) bool {
                return std.mem.lessThan(u8, x.key, y.key);
            }
        }.lt);
        for (tfs.items) |tf| {
            if (b.items.len > 0) b.append(a, '-') catch return null;
            b.appendSlice(a, tf.key) catch return null;
            if (tf.val.len > 0) {
                b.append(a, '-') catch return null;
                b.appendSlice(a, tf.val) catch return null;
            }
        }
    } else {
        for (subs) |s| {
            if (b.items.len > 0) b.append(a, '-') catch return null;
            b.appendSlice(a, s) catch return null;
        }
    }
    return b.toOwnedSlice(a) catch null;
}

/// CanonicalizeLocaleList: a string → [tag]; an array → each element ToString'd,
/// validated, canonicalized, and de-duplicated.
fn canonicalizeLocaleList(self: *Interpreter, v: Value) EvalError!*value.Object {
    const arr = (try self.newArray()).asObj();
    if (v.isUndefined()) return arr;
    // A string or a single Intl.Locale is wrapped as a one-element list (its
    // [[Locale]] slot is used; toString is not observed).
    if (v.isString() or (v.isObject() and v.asObj().getOwn("\x00locale") != null)) {
        const s = if (v.isString()) v.asStr() else v.asObj().getOwn("\x00locale").?.asStr();
        const c = canonicalizeLocaleTag(self.arena, s) orelse return self.throwError("RangeError", "Incorrect locale information provided");
        try arr.elements.append(arr.elementsAllocator(self.arena), Value.str(c));
        return arr;
    }
    // Anything else (incl. a primitive) is ToObject'd (null/undefined excluded
    // above; a Symbol/BigInt/number/boolean becomes a wrapper, length 0).
    const ov: Value = Value.obj(try self.toObject(v));
    const len = toLen((try self.toNumberV(try self.getProperty(ov, "length"))));
    var i: usize = 0;
    while (i < len) : (i += 1) {
        // CanonicalizeLocaleList checks HasProperty (honoring a Proxy `has` trap)
        // before reading each index; a missing index is skipped.
        const key = try std.fmt.allocPrint(self.arena, "{d}", .{i});
        if (!try self.inOperator(Value.str(key), ov)) continue;
        const ev = try self.getProperty(ov, key);
        if (!ev.isString() and !ev.isObject()) return self.throwError("TypeError", "Intl: locale must be a string or object");
        // An Intl.Locale element contributes its [[Locale]] slot directly (its
        // toString must not be observed).
        const s = if (ev.isObject() and ev.asObj().getOwn("\x00locale") != null)
            ev.asObj().getOwn("\x00locale").?.asStr()
        else
            try self.toStringV(ev);
        const c = canonicalizeLocaleTag(self.arena, s) orelse return self.throwError("RangeError", "Incorrect locale information provided");
        var dup = false;
        for (arr.elements.items) |e| if (std.mem.eql(u8, e.asStr(), c)) {
            dup = true;
        };
        if (!dup) try arr.elements.append(arr.elementsAllocator(self.arena), Value.str(c));
    }
    return arr;
}

fn intlLocaleSupported(tag: []const u8) bool {
    const end = std.mem.indexOfScalar(u8, tag, '-') orelse tag.len;
    const lang = tag[0..end];
    if (std.mem.eql(u8, lang, "zxx") or std.mem.eql(u8, lang, "mul") or std.mem.eql(u8, lang, "mis")) return false;
    return cldr_locale.likely(lang) != null;
}

fn intlGetCanonicalLocalesFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const arr = try canonicalizeLocaleList(self, if (args.len > 0) args[0] else Value.undef());
    return Value.obj(arr);
}

fn intlSupportedValuesOfFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const key = try self.toStringV(if (args.len > 0) args[0] else Value.undef());
    const arr = (try self.newArray()).asObj();
    // Each list must be sorted ascending by code point and contain no
    // duplicates (the source tables are kept sorted to satisfy this).
    const items: []const []const u8 = if (std.mem.eql(u8, key, "calendar"))
        &dtf_available_calendars
    else if (std.mem.eql(u8, key, "numberingSystem"))
        &numbering_systems.names
    else if (std.mem.eql(u8, key, "currency"))
        &supported_currencies
    else if (std.mem.eql(u8, key, "timeZone"))
        &.{
            "Etc/GMT+1",  "Etc/GMT+10", "Etc/GMT+11", "Etc/GMT+12", "Etc/GMT+2",
            "Etc/GMT+3",  "Etc/GMT+4",  "Etc/GMT+5",  "Etc/GMT+6",  "Etc/GMT+7",
            "Etc/GMT+8",  "Etc/GMT+9",  "Etc/GMT-1",  "Etc/GMT-10", "Etc/GMT-11",
            "Etc/GMT-12", "Etc/GMT-13", "Etc/GMT-14", "Etc/GMT-2",  "Etc/GMT-3",
            "Etc/GMT-4",  "Etc/GMT-5",  "Etc/GMT-6",  "Etc/GMT-7",  "Etc/GMT-8",
            "Etc/GMT-9",  "UTC",
        }
    else if (std.mem.eql(u8, key, "collation"))
        &.{ "emoji", "eor", "phonebk" }
    else if (std.mem.eql(u8, key, "unit"))
        &sanctioned_units
    else
        return self.throwError("RangeError", "Intl.supportedValuesOf: invalid key");
    for (items) |s| try arr.elements.append(arr.elementsAllocator(self.arena), Value.str(s));
    return Value.obj(arr);
}

// ---- Intl.Locale ----------------------------------------------------

/// Extract a Unicode (`-u-`) extension keyword value from a canonical tag, e.g.
/// `localeUValue(tag, "ca")` → the calendar. A boolean key present with no value
/// (`-u-kn`) returns "". Null if the key is absent.
fn localeUValue(tag: []const u8, key: []const u8) ?[]const u8 {
    const u = std.mem.indexOf(u8, tag, "-u-") orelse return null;
    if (std.mem.indexOf(u8, tag, "-x-")) |x| if (x < u) return null;
    var rest = tag[u + 3 ..];
    // The extension ends at the next singleton ("-x-"/"-t-") — for our purposes
    // we scan keyword/value subtags (2-char key followed by value subtags).
    var it = std.mem.splitScalar(u8, rest, '-');
    var cur_key: ?[]const u8 = null;
    var val_start: ?usize = null;
    var val_end: usize = 0;
    var off: usize = u + 3;
    _ = &rest;
    while (it.next()) |part| {
        const this_off = off;
        off += part.len + 1;
        if (part.len == 1) break;
        if (part.len == 2 and !std.ascii.isDigit(part[0])) {
            // A new keyword key. Emit the previous one if it matches.
            if (cur_key) |ck| if (std.mem.eql(u8, ck, key)) {
                if (val_start) |vs| return tag[vs..val_end] else return "";
            };
            cur_key = part;
            val_start = null;
        } else {
            // A value subtag of the current keyword.
            if (cur_key != null) {
                if (val_start == null) val_start = this_off;
                val_end = this_off + part.len;
            }
        }
    }
    if (cur_key) |ck| if (std.mem.eql(u8, ck, key)) {
        if (val_start) |vs| return tag[vs..val_end] else return "";
    };
    return null;
}

const LocaleOptKind = enum { set, language, script, region, type, variants };

fn localeSubtagValid(kind: LocaleOptKind, s: []const u8) bool {
    const isAlpha = struct {
        fn f(t: []const u8) bool {
            for (t) |c| if (!std.ascii.isAlphabetic(c)) return false;
            return true;
        }
    }.f;
    const isDigit = struct {
        fn f(t: []const u8) bool {
            for (t) |c| if (!std.ascii.isDigit(c)) return false;
            return true;
        }
    }.f;
    return switch (kind) {
        .set => true,
        .language => ((s.len >= 2 and s.len <= 3) or (s.len >= 5 and s.len <= 8)) and isAlpha(s),
        .script => s.len == 4 and isAlpha(s),
        .region => (s.len == 2 and isAlpha(s)) or (s.len == 3 and isDigit(s)),
        .type => blk: {
            // One or more 3-8 alphanumeric subtags (a well-formed Unicode type).
            if (s.len == 0) break :blk false;
            var it = std.mem.splitScalar(u8, s, '-');
            while (it.next()) |sub| {
                if (sub.len < 3 or sub.len > 8) break :blk false;
                for (sub) |c| if (!std.ascii.isAlphanumeric(c)) break :blk false;
            }
            break :blk true;
        },
        .variants => blk: {
            // One or more variant subtags (5-8 alnum, or 4 with a leading digit).
            if (s.len == 0) break :blk false;
            var it = std.mem.splitScalar(u8, s, '-');
            while (it.next()) |sub| {
                const ok = (sub.len >= 5 and sub.len <= 8) or (sub.len == 4 and std.ascii.isDigit(sub[0]));
                if (!ok) break :blk false;
                for (sub) |c| if (!std.ascii.isAlphanumeric(c)) break :blk false;
            }
            break :blk true;
        },
    };
}

/// GetOption(options, key). For a fixed allowed `set` the raw value is matched
/// case-sensitively (so "Upper"/"H12" are rejected). For structural kinds
/// (language/script/region/type) the value is validated against its Unicode
/// production (RangeError otherwise) and returned lowercased for canonicalization.
/// Returns null if absent/undefined.
fn localeStringOption(self: *Interpreter, opts: Value, key: []const u8, kind: LocaleOptKind, allowed: []const []const u8) EvalError!?[]const u8 {
    const v = try self.getProperty(opts, key);
    if (v.isUndefined()) return null;
    const raw = try self.toStringV(v);
    if (kind == .set) {
        for (allowed) |a| if (std.mem.eql(u8, raw, a)) return a;
        return self.throwError("RangeError", "invalid Intl.Locale option");
    }
    const low = try std.ascii.allocLowerString(self.arena, raw);
    if (!localeSubtagValid(kind, low)) return self.throwError("RangeError", "invalid Intl.Locale option");
    return low;
}

/// WeekdayToString: a numeric firstDayOfWeek ("0"/"7"→"sun", "1".."6"→mon..sat)
/// maps to its CLDR weekday code; any other string is returned unchanged.
fn weekdayToString(s: []const u8) []const u8 {
    const map = [_][]const u8{ "mon", "tue", "wed", "thu", "fri", "sat", "sun" };
    if (s.len == 1) {
        if (s[0] >= '1' and s[0] <= '7') return map[s[0] - '1'];
        if (s[0] == '0') return "sun";
    }
    return s;
}

fn intlLocaleConstructorFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (self.new_target.isUndefined()) return self.throwError("TypeError", "Constructor Intl.Locale requires 'new'");
    const tagv = if (args.len > 0) args[0] else Value.undef();
    if (!tagv.isString() and !tagv.isObject()) return self.throwError("TypeError", "Locale tag must be a string or Intl.Locale");
    const tag_raw = if (tagv.isObject() and tagv.asObj().getOwn("\x00locale") != null)
        tagv.asObj().getOwn("\x00locale").?.asStr()
    else
        try self.toStringV(tagv);
    var canon = canonicalizeLocaleTag(self.arena, tag_raw) orelse return self.throwError("RangeError", "Incorrect locale information provided");

    // Apply the options bag (ApplyOptionsToTag + per-keyword -u- options).
    const optsv = if (args.len > 1) args[1] else Value.undef();
    if (!optsv.isUndefined()) {
        const opts = Value.obj(try self.toObject(optsv));
        // ApplyOptionsToTag reads language, script, region, variants in order.
        const language = try localeStringOption(self, opts, "language", .language, &.{});
        const script = try localeStringOption(self, opts, "script", .script, &.{});
        const region = try localeStringOption(self, opts, "region", .region, &.{});
        const variants_opt = try localeStringOption(self, opts, "variants", .variants, &.{});
        // -u- keyword options.
        const ca = try localeStringOption(self, opts, "calendar", .type, &.{});
        const co = try localeStringOption(self, opts, "collation", .type, &.{});
        const hc = try localeStringOption(self, opts, "hourCycle", .set, &.{ "h11", "h12", "h23", "h24" });
        const kf = try localeStringOption(self, opts, "caseFirst", .set, &.{ "upper", "lower", "false" });
        // numeric is read before numberingSystem (GetOption order).
        const numeric_v = try self.getProperty(opts, "numeric");
        const kn: ?[]const u8 = if (numeric_v.isUndefined()) null else if (numeric_v.toBoolean()) "true" else "false";
        const nu = try localeStringOption(self, opts, "numberingSystem", .type, &.{});
        // firstDayOfWeek → -u-fw- (numeric weekday mapped, then validated as a type).
        const fw_v = try self.getProperty(opts, "firstDayOfWeek");
        const fw: ?[]const u8 = if (fw_v.isUndefined()) null else blk: {
            const mapped = weekdayToString(try self.toStringV(fw_v));
            if (!localeSubtagValid(.type, mapped)) return self.throwError("RangeError", "invalid firstDayOfWeek");
            break :blk mapped;
        };

        // Rebuild: base subtags (with overrides), then sorted -u- keywords. The
        // base is the language-id up to the first singleton subtag.
        var base_end: usize = canon.len;
        {
            var sb = std.mem.splitScalar(u8, canon, '-');
            var off: usize = 0;
            while (sb.next()) |part| {
                if (part.len == 1) {
                    base_end = if (off == 0) 0 else off - 1;
                    break;
                }
                off += part.len + 1;
            }
        }
        const base0 = canon[0..base_end];
        var bit = std.mem.splitScalar(u8, base0, '-');
        const orig_lang = bit.next() orelse "";
        var orig_script: []const u8 = "";
        var orig_region: []const u8 = "";
        var orig_variants: std.ArrayListUnmanaged(u8) = .empty;
        {
            var hs = false;
            var hr = false;
            while (bit.next()) |part| {
                if (!hs and !hr and part.len == 4 and std.ascii.isAlphabetic(part[0])) {
                    orig_script = part;
                    hs = true;
                } else if (!hr and ((part.len == 2 and std.ascii.isAlphabetic(part[0])) or (part.len == 3 and std.ascii.isDigit(part[0])))) {
                    orig_region = part;
                    hr = true;
                } else {
                    if (orig_variants.items.len > 0) try orig_variants.append(self.arena, '-');
                    try orig_variants.appendSlice(self.arena, part);
                }
            }
        }
        var buf: std.ArrayListUnmanaged(u8) = .empty;
        try buf.appendSlice(self.arena, if (language) |l| l else orig_lang);
        const use_script = if (script) |s| s else orig_script;
        const use_region = if (region) |r| r else orig_region;
        if (use_script.len > 0) {
            try buf.append(self.arena, '-');
            try buf.appendSlice(self.arena, use_script);
        }
        if (use_region.len > 0) {
            try buf.append(self.arena, '-');
            try buf.appendSlice(self.arena, use_region);
        }
        // Variants: the option replaces the tag's variants; else keep the tag's.
        const use_variants = if (variants_opt) |v| v else orig_variants.items;
        if (use_variants.len > 0) {
            try buf.append(self.arena, '-');
            try buf.appendSlice(self.arena, use_variants);
        }
        // Merge -u- keywords (option overrides input tag), emit in key order.
        const keys = [_]struct { k: []const u8, v: ?[]const u8 }{
            .{ .k = "ca", .v = ca }, .{ .k = "co", .v = co }, .{ .k = "fw", .v = fw },
            .{ .k = "hc", .v = hc }, .{ .k = "kf", .v = kf }, .{ .k = "kn", .v = kn },
            .{ .k = "nu", .v = nu },
        };
        var u_buf: std.ArrayListUnmanaged(u8) = .empty;
        for (keys) |kv| {
            const val: ?[]const u8 = if (kv.v) |v| v else localeUValue(canon, kv.k);
            if (val) |v| {
                try u_buf.append(self.arena, '-');
                try u_buf.appendSlice(self.arena, kv.k);
                // "kn" with value "true" serializes as a bare "-u-kn".
                if (!(std.mem.eql(u8, kv.k, "kn") and std.mem.eql(u8, v, "true")) and v.len > 0) {
                    try u_buf.append(self.arena, '-');
                    try u_buf.appendSlice(self.arena, v);
                }
            }
        }
        if (u_buf.items.len > 0) {
            try buf.appendSlice(self.arena, "-u");
            try buf.appendSlice(self.arena, u_buf.items);
        }
        canon = canonicalizeLocaleTag(self.arena, buf.items) orelse return self.throwError("RangeError", "Incorrect locale information provided");
    }

    const o = (try self.newObject()).asObj();
    if (self.new_target.isObject()) o.setProtoAtomic(try self.ctorRealmProto(self.new_target.asObj(), "Locale"));
    try self.setProp(o, "\x00locale", Value.str(canon));
    try o.setAttr(self.arena, "\x00locale", .{ .writable = false, .enumerable = false, .configurable = false });
    return Value.obj(o);
}

const LocaleField = enum { base_name, language, script, region, variants, calendar, case_first, collation, hour_cycle, numeric, numbering_system, first_day_of_week };
fn intlLocaleGetter(comptime f: LocaleField) value.NativeFn {
    return struct {
        fn call(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
            _ = args;
            const self: *Interpreter = @ptrCast(@alignCast(ctx));
            if (!this.isObject() or this.asObj().getOwn("\x00locale") == null) return self.throwError("TypeError", "Intl.Locale accessor on incompatible receiver");
            const tag = this.asObj().getOwn("\x00locale").?.asStr();
            // -u- extension keyword accessors.
            switch (f) {
                .calendar => return if (localeUValue(tag, "ca")) |v| Value.str(v) else Value.undef(),
                .case_first => return if (localeUValue(tag, "kf")) |v| Value.str(v) else Value.undef(),
                .collation => return if (localeUValue(tag, "co")) |v| Value.str(v) else Value.undef(),
                .hour_cycle => return if (localeUValue(tag, "hc")) |v| Value.str(v) else Value.undef(),
                .numbering_system => return if (localeUValue(tag, "nu")) |v| Value.str(v) else Value.undef(),
                .numeric => return Value.boolVal(if (localeUValue(tag, "kn")) |v| (v.len == 0 or std.mem.eql(u8, v, "true")) else false),
                .first_day_of_week => return if (localeUValue(tag, "fw")) |v| Value.str(v) else Value.undef(),
                else => {},
            }
            // baseName (GetLocaleBaseName) is the language-id prefix: everything
            // up to the first singleton ("-X-") subtag. language/script/region/
            // variants are its components.
            var base_end: usize = tag.len;
            {
                var bit = std.mem.splitScalar(u8, tag, '-');
                var off: usize = 0;
                while (bit.next()) |part| {
                    if (part.len == 1) {
                        base_end = if (off == 0) 0 else off - 1; // drop the joining '-'
                        break;
                    }
                    off += part.len + 1;
                }
            }
            const base = tag[0..base_end];
            if (f == .base_name) return Value.str(base);
            var it = std.mem.splitScalar(u8, base, '-');
            const lang = it.next() orelse "";
            if (f == .language) return Value.str(lang);
            var have_script = false;
            var have_region = false;
            var variants: std.ArrayListUnmanaged(u8) = .empty;
            while (it.next()) |part| {
                if (!have_script and !have_region and part.len == 4 and std.ascii.isAlphabetic(part[0])) {
                    have_script = true;
                    if (f == .script) return Value.str(part);
                } else if (!have_region and ((part.len == 2 and std.ascii.isAlphabetic(part[0])) or (part.len == 3 and std.ascii.isDigit(part[0])))) {
                    have_region = true;
                    if (f == .region) return Value.str(part);
                } else {
                    if (variants.items.len > 0) try variants.append(self.arena, '-');
                    try variants.appendSlice(self.arena, part);
                }
            }
            if (f == .variants) return if (variants.items.len > 0) Value.str(try variants.toOwnedSlice(self.arena)) else Value.undef();
            return Value.undef();
        }
    }.call;
}

/// `Intl.Locale.prototype.maximize`/`minimize` — Add/Remove Likely Subtags on
/// the language-id (variants and extensions are preserved), then canonicalize.
fn intlLocaleTransformFn(comptime kind: enum { max, min }) value.NativeFn {
    return struct {
        fn call(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
            _ = args;
            const self: *Interpreter = @ptrCast(@alignCast(ctx));
            if (!this.isObject() or this.asObj().getOwn("\x00locale") == null) return self.throwError("TypeError", "Intl.Locale.prototype method on incompatible receiver");
            const a = self.arena;
            const tag = this.asObj().getOwn("\x00locale").?.asStr();
            // Split off the base language-id (up to the first singleton) and tail.
            var base_end: usize = tag.len;
            {
                var bit = std.mem.splitScalar(u8, tag, '-');
                var off: usize = 0;
                while (bit.next()) |part| {
                    if (part.len == 1) {
                        base_end = if (off == 0) 0 else off - 1;
                        break;
                    }
                    off += part.len + 1;
                }
            }
            const base = tag[0..base_end];
            const tail = tag[base_end..]; // "-u-…" etc. (leading '-' or empty)
            // Parse base into lowercased lang/script/region plus variants.
            var t: Triple = .{ .l = "" };
            var variants: std.ArrayListUnmanaged([]const u8) = .empty;
            {
                var bit = std.mem.splitScalar(u8, base, '-');
                t.l = lowerDup(a, bit.next() orelse "");
                while (bit.next()) |part| {
                    if (t.s.len == 0 and t.r.len == 0 and variants.items.len == 0 and part.len == 4 and std.ascii.isAlphabetic(part[0])) {
                        t.s = lowerDup(a, part);
                    } else if (t.r.len == 0 and variants.items.len == 0 and ((part.len == 2 and std.ascii.isAlphabetic(part[0])) or (part.len == 3 and std.ascii.isDigit(part[0])))) {
                        t.r = lowerDup(a, part);
                    } else {
                        try variants.append(a, lowerDup(a, part));
                    }
                }
            }
            const res = (if (kind == .max) cldrMaximize(a, t) else cldrMinimize(a, t)) orelse t;
            var buf: std.ArrayListUnmanaged(u8) = .empty;
            try buf.appendSlice(a, res.l);
            if (res.s.len > 0) {
                try buf.appendSlice(a, "-");
                try buf.append(a, std.ascii.toUpper(res.s[0]));
                try buf.appendSlice(a, res.s[1..]);
            }
            if (res.r.len > 0) {
                try buf.appendSlice(a, "-");
                try buf.appendSlice(a, try std.ascii.allocUpperString(a, res.r));
            }
            for (variants.items) |v| {
                try buf.append(a, '-');
                try buf.appendSlice(a, v);
            }
            try buf.appendSlice(a, tail);
            const canon = canonicalizeLocaleTag(a, buf.items) orelse return self.throwError("RangeError", "Incorrect locale information provided");
            const o = (try self.newObject()).asObj();
            o.setProtoAtomic(this.asObj().proto);
            try self.setProp(o, "\x00locale", Value.str(canon));
            try o.setAttr(self.arena, "\x00locale", .{ .writable = false, .enumerable = false, .configurable = false });
            return Value.obj(o);
        }
    }.call;
}

/// Locale info methods returning an array of one default (getCalendars →
/// ["iso8601"], etc.) or, for the keyword-backed ones, the tag's value.
fn intlLocaleListFn(comptime which: enum { calendars, collations, hour_cycles, numbering_systems, time_zones }) value.NativeFn {
    return struct {
        fn call(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
            _ = args;
            const self: *Interpreter = @ptrCast(@alignCast(ctx));
            if (!this.isObject() or this.asObj().getOwn("\x00locale") == null) return self.throwError("TypeError", "Intl.Locale.prototype method on incompatible receiver");
            const tag = this.asObj().getOwn("\x00locale").?.asStr();
            const arr = (try self.newArray()).asObj();
            const def: ?[]const u8 = switch (which) {
                .calendars => localeUValue(tag, "ca") orelse "iso8601",
                .collations => localeUValue(tag, "co") orelse "default",
                .hour_cycles => localeUValue(tag, "hc") orelse "h23",
                .numbering_systems => localeUValue(tag, "nu") orelse "latn",
                .time_zones => null, // requires region data
            };
            if (def) |d| try arr.elements.append(arr.elementsAllocator(self.arena), Value.str(d));
            return Value.obj(arr);
        }
    }.call;
}

fn intlLocaleTextInfoFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = args;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (!this.isObject() or this.asObj().getOwn("\x00locale") == null) return self.throwError("TypeError", "Intl.Locale.prototype.getTextInfo on incompatible receiver");
    const o = (try self.newObject()).asObj();
    try self.setProp(o, "direction", Value.str("ltr"));
    return Value.obj(o);
}

fn intlLocaleWeekInfoFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = args;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (!this.isObject() or this.asObj().getOwn("\x00locale") == null) return self.throwError("TypeError", "Intl.Locale.prototype.getWeekInfo on incompatible receiver");
    const tag = this.asObj().getOwn("\x00locale").?.asStr();
    const o = (try self.newObject()).asObj();
    // firstDay: from the -u-fw- keyword (mon..sun -> 1..7) when present, else the
    // default (1 = Monday; we lack per-region week data).
    var first_day: f64 = 1;
    if (localeUValue(tag, "fw")) |fw| {
        const names = [_][]const u8{ "mon", "tue", "wed", "thu", "fri", "sat", "sun" };
        for (names, 1..) |n, i| if (std.mem.eql(u8, fw, n)) {
            first_day = @floatFromInt(i);
        };
    }
    try self.setProp(o, "firstDay", Value.num(first_day));
    const we = (try self.newArray()).asObj();
    try we.elements.append(we.elementsAllocator(self.arena), Value.num(6));
    try we.elements.append(we.elementsAllocator(self.arena), Value.num(7));
    try self.setProp(o, "weekend", Value.obj(we));
    return Value.obj(o);
}

fn intlLocaleTimeZonesFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = args;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (!this.isObject() or this.asObj().getOwn("\x00locale") == null) return self.throwError("TypeError", "Intl.Locale.prototype.getTimeZones on incompatible receiver");
    const tag = this.asObj().getOwn("\x00locale").?.asStr();
    // Without a region subtag in the language-id, return undefined.
    var has_region = false;
    {
        var it = std.mem.splitScalar(u8, tag, '-');
        _ = it.next(); // language
        var saw_var = false;
        while (it.next()) |part| {
            if (part.len == 1) break; // extension
            if (!saw_var and ((part.len == 2 and std.ascii.isAlphabetic(part[0])) or (part.len == 3 and std.ascii.isDigit(part[0])))) {
                has_region = true;
                break;
            }
            if (part.len == 4 and std.ascii.isAlphabetic(part[0])) continue; // script
            saw_var = true; // variants follow; region can't appear after
        }
    }
    if (!has_region) return Value.undef();
    // We lack per-region zone data; report UTC so the result is a non-empty array.
    const arr = (try self.newArray()).asObj();
    try arr.elements.append(arr.elementsAllocator(self.arena), Value.str("UTC"));
    return Value.obj(arr);
}

fn intlLocaleToStringFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = args;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (!this.isObject() or this.asObj().getOwn("\x00locale") == null) return self.throwError("TypeError", "Intl.Locale.prototype.toString on incompatible receiver");
    return this.asObj().getOwn("\x00locale").?;
}

// ---- Intl formatter constructors (en-centric) -----------------------

/// A generic Intl service constructor: stores the resolved locale, marks the
/// brand with `\x00intl` = `service`, and supports `new`-less call for the few
/// A well-formed Unicode locale extension type: one or more 3–8-alphanumeric
/// segments joined by "-". Used to validate the `calendar`/`numberingSystem`
/// options (GetOption rejects malformed types with a RangeError).
fn dtfWellFormedType(s: []const u8) bool {
    if (s.len == 0) return false;
    var it = std.mem.splitScalar(u8, s, '-');
    while (it.next()) |seg| {
        if (seg.len < 3 or seg.len > 8) return false;
        for (seg) |c| if (!std.ascii.isAlphanumeric(c)) return false;
    }
    return true;
}

/// GetOption(opts, name, "string", «allowed», fallback): read a property,
/// ToString-coerce it (running getters/toString), and require membership in
/// `allowed` (RangeError otherwise). Returns the canonical allowed string, or
/// `fallback` when the property is undefined.
fn dtfGetStr(self: *Interpreter, opts: Value, name: []const u8, allowed: []const []const u8, fallback: ?[]const u8) EvalError!?[]const u8 {
    const v = try self.getProperty(opts, name);
    if (v.isUndefined()) return fallback;
    const s = try self.toStringV(v);
    for (allowed) |a| if (std.mem.eql(u8, s, a)) return a;
    return self.throwError("RangeError", try std.fmt.allocPrint(self.arena, "invalid value '{s}' for option {s}", .{ s, name }));
}

/// GetOption for a free-form Unicode type value (calendar/numberingSystem):
/// ToString then well-formedness check.
fn dtfGetType(self: *Interpreter, opts: Value, name: []const u8) EvalError!?[]const u8 {
    const v = try self.getProperty(opts, name);
    if (v.isUndefined()) return null;
    const s = try self.toStringV(v);
    // The well-formedness check runs on the raw value (so a non-ASCII char like
    // U+0130 İ rejects); the canonical form is then ASCII-lowercased.
    if (!dtfWellFormedType(s)) return self.throwError("RangeError", try std.fmt.allocPrint(self.arena, "invalid value for option {s}", .{name}));
    return try std.ascii.allocLowerString(self.arena, s);
}

fn dtfCanonOffsetTimeZone(self: *Interpreter, s: []const u8) EvalError!?[]const u8 {
    if (s.len != 3 and s.len != 5 and s.len != 6) return null;
    if (s[0] != '+' and s[0] != '-') return null;
    if (!std.ascii.isDigit(s[1]) or !std.ascii.isDigit(s[2])) return null;
    if (s.len == 5 and (!std.ascii.isDigit(s[3]) or !std.ascii.isDigit(s[4]))) return null;
    if (s.len == 6 and (s[3] != ':' or !std.ascii.isDigit(s[4]) or !std.ascii.isDigit(s[5]))) return null;
    const hh = std.fmt.parseInt(u8, s[1..3], 10) catch return null;
    const mm = if (s.len == 5) std.fmt.parseInt(u8, s[3..5], 10) catch return null else if (s.len == 6) std.fmt.parseInt(u8, s[4..6], 10) catch return null else 0;
    if (hh > 23 or mm > 59) return self.throwError("RangeError", "invalid timeZone");
    const sign: u8 = if (hh == 0 and mm == 0) '+' else s[0];
    return try std.fmt.allocPrint(self.arena, "{c}{d:0>2}:{d:0>2}", .{ sign, hh, mm });
}

fn dtfCanonNamedTimeZone(self: *Interpreter, s: []const u8) EvalError!?[]const u8 {
    for (s) |c| if (c >= 0x80 or !(std.ascii.isAlphanumeric(c) or c == '/' or c == '_' or c == '-' or c == '+')) {
        return self.throwError("RangeError", "invalid timeZone");
    };
    const fixed = [_][]const u8{
        "CET",        "CST6CDT",   "Cuba",          "EET",           "EST",        "EST5EDT",
        "Egypt",      "Eire",      "GB",            "GB-Eire",       "GMT",        "GMT+0",
        "GMT-0",      "GMT0",      "Greenwich",     "HST",           "Hongkong",   "Iceland",
        "Iran",       "Israel",    "Jamaica",       "Japan",         "Kwajalein",  "Libya",
        "MET",        "MST",       "MST7MDT",       "NZ",            "NZ-CHAT",    "Navajo",
        "PRC",        "PST8PDT",   "Poland",        "Portugal",      "ROC",        "ROK",
        "Singapore",  "Turkey",    "UCT",           "UTC",           "Universal",  "W-SU",
        "WET",        "Zulu",      "Etc/UTC",       "Etc/UCT",       "Etc/GMT",    "Etc/GMT+0",
        "Etc/GMT-0",  "Etc/GMT0",  "Etc/Greenwich", "Etc/Universal", "Etc/Zulu",   "Etc/GMT+1",
        "Etc/GMT+2",  "Etc/GMT+3", "Etc/GMT+4",     "Etc/GMT+5",     "Etc/GMT+6",  "Etc/GMT+7",
        "Etc/GMT+8",  "Etc/GMT+9", "Etc/GMT+10",    "Etc/GMT+11",    "Etc/GMT+12", "Etc/GMT-1",
        "Etc/GMT-2",  "Etc/GMT-3", "Etc/GMT-4",     "Etc/GMT-5",     "Etc/GMT-6",  "Etc/GMT-7",
        "Etc/GMT-8",  "Etc/GMT-9", "Etc/GMT-10",    "Etc/GMT-11",    "Etc/GMT-12", "Etc/GMT-13",
        "Etc/GMT-14",
    };
    for (fixed) |z| if (std.ascii.eqlIgnoreCase(s, z)) return z;
    if (std.ascii.startsWithIgnoreCase(s, "Etc/GMT+") or std.ascii.startsWithIgnoreCase(s, "Etc/GMT-"))
        return self.throwError("RangeError", "invalid timeZone");
    const exact_case = [_][]const u8{
        "Africa/Dar_es_Salaam",
        "America/Argentina/ComodRivadavia",
        "America/Knox_IN",
        "America/Port-au-Prince",
        "America/Port_of_Spain",
        "Antarctica/DumontDUrville",
        "Antarctica/McMurdo",
        "Australia/ACT",
        "Australia/LHI",
        "Australia/NSW",
        "Brazil/DeNoronha",
        "Chile/EasterIsland",
        "Europe/Isle_of_Man",
        "Mexico/BajaNorte",
        "Mexico/BajaSur",
        "US/Alaska",
        "US/Aleutian",
        "US/Arizona",
        "US/Central",
        "US/East-Indiana",
        "US/Eastern",
        "US/Hawaii",
        "US/Indiana-Starke",
        "US/Michigan",
        "US/Mountain",
        "US/Pacific",
        "US/Samoa",
    };
    for (exact_case) |z| if (std.ascii.eqlIgnoreCase(s, z)) return z;
    if (std.mem.indexOfScalar(u8, s, '/') == null) return null;
    var out: std.ArrayListUnmanaged(u8) = .empty;
    var word_start = true;
    for (s) |c| {
        if (std.ascii.isAlphabetic(c)) {
            try out.append(self.arena, if (word_start) std.ascii.toUpper(c) else std.ascii.toLower(c));
            word_start = false;
        } else {
            try out.append(self.arena, c);
            word_start = (c == '/' or c == '_' or c == '-');
        }
    }
    return try out.toOwnedSlice(self.arena);
}

fn dtfCanonTimeZone(self: *Interpreter, s: []const u8) EvalError![]const u8 {
    if (try dtfCanonOffsetTimeZone(self, s)) |z| return z;
    if (s.len > 0 and (s[0] == '+' or s[0] == '-' or s[0] >= 0x80)) return self.throwError("RangeError", "invalid timeZone");
    if (try dtfCanonNamedTimeZone(self, s)) |z| return z;
    return self.throwError("RangeError", "invalid timeZone");
}

/// The calendar types a full implementation reports from AvailableCalendars.
/// An unsupported (or not-yet-adopted) request falls back to the locale default.
const dtf_available_calendars = [_][]const u8{
    "buddhist", "chinese", "coptic",        "dangi",        "ethioaa",          "ethiopic", "gregory",
    "hebrew",   "indian",  "islamic-civil", "islamic-tbla", "islamic-umalqura", "iso8601",  "japanese",
    "persian",  "roc",
};

/// CanonicalizeUValue("ca", …): apply the well-known aliases and resolve the
/// deprecated "islamic"/"islamic-rgsa" types. Unknown values are returned as-is
/// (availability is decided separately by `dtfCalAvail`).
fn dtfCanonCalendar(cal: []const u8) []const u8 {
    const aliases = .{
        .{ "islamicc", "islamic-civil" },
        .{ "ethiopic-amete-alem", "ethioaa" },
        .{ "gregorian", "gregory" },
    };
    var c = cal;
    inline for (aliases) |a| if (std.mem.eql(u8, c, a[0])) {
        c = a[1];
    };
    if (std.mem.eql(u8, c, "islamic") or std.mem.eql(u8, c, "islamic-rgsa")) c = "islamic-civil";
    return c;
}

/// Whether a (canonicalized) calendar type is one we model / "available".
fn dtfCalAvail(c: []const u8) bool {
    for (dtf_available_calendars) |ac| if (std.mem.eql(u8, c, ac)) return true;
    return false;
}

/// The processed DateTimeFormat options: the canonical string for each set
/// component option (empty = not set), plus the cross-cutting fields.
const DtfOptions = struct {
    weekday: []const u8 = "",
    era: []const u8 = "",
    year: []const u8 = "",
    month: []const u8 = "",
    day: []const u8 = "",
    day_period: []const u8 = "",
    hour: []const u8 = "",
    minute: []const u8 = "",
    second: []const u8 = "",
    frac_sec: ?u8 = null,
    time_zone_name: []const u8 = "",
    date_style: []const u8 = "",
    time_style: []const u8 = "",
    calendar: []const u8 = "",
    numbering_system: []const u8 = "",
    hour12: ?bool = null,
    hour_cycle: []const u8 = "",
    time_zone: []const u8 = "UTC",
    defaults_applied: bool = false,
};

/// Process and validate the options bag for Intl.DateTimeFormat per
/// CreateDateTimeFormat, reading properties in the exact spec order (the
/// constructor-options-order test asserts the observed getter sequence). Throws
/// RangeError on out-of-range values and TypeError on a dateStyle/timeStyle vs
/// explicit-component conflict.
const DtfDefaults = enum { date, time, all };
const DtfRequired = enum { any, date, time };

fn dtfProcessOptions(self: *Interpreter, raw: Value) EvalError!DtfOptions {
    // Intl.DateTimeFormat: required = "any", defaults = "date".
    return dtfProcessOptionsKind(self, raw, .any, .date);
}

fn dtfProcessOptionsKind(self: *Interpreter, raw_in: Value, required: DtfRequired, defaults: DtfDefaults) EvalError!DtfOptions {
    // CoerceOptionsToObject: undefined -> none; null -> TypeError; primitive -> boxed.
    const raw: Value = if (raw_in.isUndefined()) Value.undef() else Value.obj(try self.toObject(raw_in));
    var r = DtfOptions{};
    // Read options only when an options object was supplied; the required/default
    // logic below still runs for `new Intl.DateTimeFormat()` (no options).
    if (raw.isObject()) {
        const style3 = [_][]const u8{ "long", "short", "narrow" };
        const numeric2 = [_][]const u8{ "2-digit", "numeric" };
        _ = try dtfGetStr(self, raw, "localeMatcher", &.{ "lookup", "best fit" }, "best fit");
        if (try dtfGetType(self, raw, "calendar")) |c| r.calendar = c;
        if (try dtfGetType(self, raw, "numberingSystem")) |c| r.numbering_system = c;
        const h12v = try self.getProperty(raw, "hour12");
        if (!h12v.isUndefined()) r.hour12 = h12v.toBoolean();
        if (try dtfGetStr(self, raw, "hourCycle", &.{ "h11", "h12", "h23", "h24" }, null)) |c| r.hour_cycle = c;
        const tzv = try self.getProperty(raw, "timeZone");
        if (!tzv.isUndefined()) r.time_zone = try self.toStringV(tzv);
        if (try dtfGetStr(self, raw, "weekday", &style3, null)) |c| r.weekday = c;
        if (try dtfGetStr(self, raw, "era", &style3, null)) |c| r.era = c;
        if (try dtfGetStr(self, raw, "year", &numeric2, null)) |c| r.year = c;
        if (try dtfGetStr(self, raw, "month", &.{ "2-digit", "numeric", "long", "short", "narrow" }, null)) |c| r.month = c;
        if (try dtfGetStr(self, raw, "day", &numeric2, null)) |c| r.day = c;
        if (try dtfGetStr(self, raw, "dayPeriod", &style3, null)) |c| r.day_period = c;
        if (try dtfGetStr(self, raw, "hour", &numeric2, null)) |c| r.hour = c;
        if (try dtfGetStr(self, raw, "minute", &numeric2, null)) |c| r.minute = c;
        if (try dtfGetStr(self, raw, "second", &numeric2, null)) |c| r.second = c;
        const fsdv = try self.getProperty(raw, "fractionalSecondDigits");
        if (!fsdv.isUndefined()) {
            const n = try self.toNumberV(fsdv);
            if (std.math.isNan(n) or n < 1 or n > 3) return self.throwError("RangeError", "fractionalSecondDigits must be between 1 and 3");
            r.frac_sec = @intFromFloat(@floor(n));
        }
        if (try dtfGetStr(self, raw, "timeZoneName", &.{ "short", "long", "shortOffset", "longOffset", "shortGeneric", "longGeneric" }, null)) |c| r.time_zone_name = c;
        _ = try dtfGetStr(self, raw, "formatMatcher", &.{ "basic", "best fit" }, "best fit");
        if (try dtfGetStr(self, raw, "dateStyle", &.{ "full", "long", "medium", "short" }, null)) |c| r.date_style = c;
        if (try dtfGetStr(self, raw, "timeStyle", &.{ "full", "long", "medium", "short" }, null)) |c| r.time_style = c;
    }
    // Canonicalize the time zone and map the deprecated "islamic"/"islamic-rgsa"
    // calendars to a concrete available fallback.
    r.time_zone = try dtfCanonTimeZone(self, r.time_zone);
    if (r.calendar.len > 0) r.calendar = dtfCanonCalendar(r.calendar);

    // dateStyle/timeStyle cannot be combined with explicit component options.
    const has_comp = r.weekday.len + r.era.len + r.year.len + r.month.len + r.day.len +
        r.day_period.len + r.hour.len + r.minute.len + r.second.len + r.time_zone_name.len > 0 or r.frac_sec != null;
    if ((r.date_style.len > 0 or r.time_style.len > 0) and has_comp) {
        return self.throwError("TypeError", "dateStyle/timeStyle may not be used with explicit date-time component options");
    }
    // ToDateTimeOptions: needDefaults is decided by `required` (whether the
    // relevant component group was supplied), and the defaults that get added
    // are governed by `defaults`. So e.g. toLocaleDateString (required=date,
    // defaults=date) with only time components still adds the date defaults.
    const has_date_comp = r.weekday.len + r.year.len + r.month.len + r.day.len > 0;
    const has_time_comp = r.hour.len + r.minute.len + r.second.len + r.day_period.len > 0 or r.frac_sec != null;
    var need_defaults = true;
    if ((required == .any or required == .date) and has_date_comp) need_defaults = false;
    if ((required == .any or required == .time) and has_time_comp) need_defaults = false;
    if (need_defaults and r.date_style.len == 0 and r.time_style.len == 0) {
        r.defaults_applied = true;
        if (defaults == .date or defaults == .all) {
            r.year = "numeric";
            r.month = "numeric";
            r.day = "numeric";
        }
        if (defaults == .time or defaults == .all) {
            r.hour = "numeric";
            r.minute = "numeric";
            r.second = "numeric";
        }
    }
    return r;
}

/// Resolve the effective hour cycle (CreateDateTimeFormat steps 24-26): an
/// explicit hour12 picks the locale's 12-/24-hour variant; else an explicit
/// hourCycle option or the locale's -u-hc keyword; else the territory default.
/// `locale` is the resolved BCP-47 tag; opt_hc/opt_h12 come from the options.
fn dtfResolveHourCycle(self: *Interpreter, locale: []const u8, opt_hc: []const u8, opt_h12: ?bool) []const u8 {
    const t = parseTriple(locale);
    var region: []const u8 = t.r;
    if (region.len == 0) {
        if (cldrMaximize(self.arena, t)) |m| region = m.r;
    }
    if (region.len == 0) region = "001";
    var rbuf: [8]u8 = undefined;
    const rl = if (region.len <= rbuf.len) std.ascii.lowerString(rbuf[0..region.len], region) else region;
    const hcd = cldr_timedata.forRegion(rl);
    if (opt_h12) |b| return if (b) hcd.h12 else hcd.h24;
    if (opt_hc.len > 0) return opt_hc;
    if (localeUValue(locale, "hc")) |e| return e;
    return hcd.def;
}

fn localeDefaultNumberingSystem(locale: []const u8) []const u8 {
    const t = parseTriple(locale);
    if (std.mem.eql(u8, t.l, "ar")) return "arab";
    if (std.mem.eql(u8, t.l, "fa")) return "arabext";
    return "latn";
}

/// ResolveLocale for DateTimeFormat's relevant extension keys (ca, hc, nu): an
/// option overrides a `-u-` keyword, but the keyword survives in the resolved
/// locale only when it came from a supported extension and an option did not
/// replace it with a different supported value. Returns the rebuilt locale plus
/// the resolved calendar and numbering system.
fn dtfResolveLocaleExt(
    self: *Interpreter,
    tag: []const u8,
    opt_ca: []const u8,
    raw_hc: []const u8,
    raw_h12: ?bool,
    opt_nu: []const u8,
) EvalError!struct { loc: []const u8, calendar: []const u8, numbering_system: []const u8 } {
    // ca: calendar
    const ext_ca_raw = localeUValue(tag, "ca");
    const ext_ca: ?[]const u8 = if (ext_ca_raw) |e| (if (dtfCalAvail(dtfCanonCalendar(e))) dtfCanonCalendar(e) else null) else null;
    const ca_opt: ?[]const u8 = if (opt_ca.len > 0 and dtfCalAvail(opt_ca)) opt_ca else null;
    const ca_val: []const u8 = ca_opt orelse (ext_ca orelse "gregory");
    const keep_ca = ext_ca != null and (ca_opt == null or std.mem.eql(u8, ca_opt.?, ext_ca.?));

    // hc: hour cycle. The hourCycle option only participates when hour12 is
    // absent (CreateDateTimeFormat step 3 nulls it otherwise).
    const ext_hc_raw = localeUValue(tag, "hc");
    const hcValid = struct {
        fn f(v: []const u8) bool {
            return std.mem.eql(u8, v, "h11") or std.mem.eql(u8, v, "h12") or std.mem.eql(u8, v, "h23") or std.mem.eql(u8, v, "h24");
        }
    }.f;
    const ext_hc: ?[]const u8 = if (ext_hc_raw) |e| (if (hcValid(e)) e else null) else null;
    const hc_opt: ?[]const u8 = if (raw_hc.len > 0 and hcValid(raw_hc)) raw_hc else null;
    // A present hour12 option (regardless of value) drops the -u-hc keyword, as
    // does an hourCycle option that disagrees with the extension.
    const keep_hc = ext_hc != null and raw_h12 == null and (hc_opt == null or std.mem.eql(u8, hc_opt.?, ext_hc.?));

    // nu: numbering system.
    const ext_nu = localeUValue(tag, "nu");
    const ext_nu_ok = if (ext_nu) |e| numbering_systems.digits(e) != null else false;
    const opt_nu_ok = opt_nu.len > 0 and numbering_systems.digits(opt_nu) != null;
    const nu_val: []const u8 = if (opt_nu_ok) opt_nu else if (ext_nu_ok) ext_nu.? else localeDefaultNumberingSystem(tag);
    const keep_nu = ext_nu_ok and std.mem.eql(u8, ext_nu.?, nu_val);

    const base = if (std.mem.indexOf(u8, tag, "-u-")) |u| tag[0..u] else tag;
    var buf: std.ArrayListUnmanaged(u8) = .empty;
    try buf.appendSlice(self.arena, base);
    var any_kw = false;
    // Canonical -u- key order is alphabetical: ca, hc, nu.
    if (keep_ca) {
        try buf.appendSlice(self.arena, if (any_kw) "-ca-" else "-u-ca-");
        try buf.appendSlice(self.arena, ext_ca.?);
        any_kw = true;
    }
    if (keep_hc) {
        try buf.appendSlice(self.arena, if (any_kw) "-hc-" else "-u-hc-");
        try buf.appendSlice(self.arena, ext_hc.?);
        any_kw = true;
    }
    if (keep_nu) {
        try buf.appendSlice(self.arena, if (any_kw) "-nu-" else "-u-nu-");
        try buf.appendSlice(self.arena, nu_val);
        any_kw = true;
    }
    return .{ .loc = try buf.toOwnedSlice(self.arena), .calendar = ca_val, .numbering_system = nu_val };
}

/// Build the normalized options object that the instance stores under
/// `\x00opts` (read by both `format` and `resolvedOptions`).
fn dtfStoreOptions(self: *Interpreter, o: *value.Object, r_in: DtfOptions) EvalError!void {
    var r = r_in;
    const tag = if (o.getOwn("\x00locale")) |lv| (if (lv.isString()) lv.asStr() else "en") else "en";
    // Resolve the ca/hc/nu locale extensions (rebuilds the resolved locale and
    // fixes the effective calendar / numbering system).
    const ext = try dtfResolveLocaleExt(self, tag, r.calendar, r.hour_cycle, r.hour12, r.numbering_system);
    r.calendar = ext.calendar;
    r.numbering_system = ext.numbering_system;
    // Resolve the hour cycle whenever the pattern carries an hour (an explicit
    // hour component or a timeStyle); otherwise [[HourCycle]] is undefined and
    // resolvedOptions omits hourCycle/hour12.
    if (r.hour.len > 0 or r.time_style.len > 0) {
        const hc = dtfResolveHourCycle(self, tag, r.hour_cycle, r.hour12);
        r.hour_cycle = hc;
        r.hour12 = std.mem.eql(u8, hc, "h11") or std.mem.eql(u8, hc, "h12");
    } else {
        r.hour_cycle = "";
        r.hour12 = null;
    }
    const ro = (try self.newObject()).asObj();
    try self.setProp(ro, "\x00rloc", Value.str(ext.loc));
    const S = struct {
        fn put(s: *Interpreter, obj: *value.Object, k: []const u8, v: []const u8) EvalError!void {
            if (v.len > 0) try s.setProp(obj, k, Value.str(v));
        }
    };
    try S.put(self, ro, "weekday", r.weekday);
    try S.put(self, ro, "era", r.era);
    try S.put(self, ro, "year", r.year);
    try S.put(self, ro, "month", r.month);
    try S.put(self, ro, "day", r.day);
    try S.put(self, ro, "dayPeriod", r.day_period);
    try S.put(self, ro, "hour", r.hour);
    try S.put(self, ro, "minute", r.minute);
    try S.put(self, ro, "second", r.second);
    if (r.frac_sec) |f| try self.setProp(ro, "fractionalSecondDigits", Value.num(@floatFromInt(f)));
    try S.put(self, ro, "timeZoneName", r.time_zone_name);
    try S.put(self, ro, "dateStyle", r.date_style);
    try S.put(self, ro, "timeStyle", r.time_style);
    try S.put(self, ro, "calendar", r.calendar);
    try S.put(self, ro, "numberingSystem", r.numbering_system);
    try S.put(self, ro, "hourCycle", r.hour_cycle);
    try S.put(self, ro, "timeZone", r.time_zone);
    if (r.hour12) |h| try self.setProp(ro, "hour12", Value.boolVal(h));
    if (r.defaults_applied) {
        try self.setProp(ro, "\x00defaultsApplied", Value.boolVal(true));
        try ro.setAttr(self.arena, "\x00defaultsApplied", .{ .writable = false, .enumerable = false, .configurable = false });
    }
    try self.setProp(o, "\x00opts", Value.obj(ro));
    try o.setAttr(self.arena, "\x00opts", .{ .writable = false, .enumerable = false, .configurable = false });
}

/// The single units sanctioned for use in ECMAScript (ECMA-402). A unit
/// identifier is one of these, or "<x>-per-<y>" with both sanctioned.
const sanctioned_units = [_][]const u8{
    "acre",        "bit",      "byte",              "celsius",     "centimeter",
    "day",         "degree",   "fahrenheit",        "fluid-ounce", "foot",
    "gallon",      "gigabit",  "gigabyte",          "gram",        "hectare",
    "hour",        "inch",     "kilobit",           "kilobyte",    "kilogram",
    "kilometer",   "liter",    "megabit",           "megabyte",    "meter",
    "microsecond", "mile",     "mile-scandinavian", "milliliter",  "millimeter",
    "millisecond", "minute",   "month",             "nanosecond",  "ounce",
    "percent",     "petabyte", "pound",             "second",      "stone",
    "terabit",     "terabyte", "week",              "yard",        "year",
};

fn isSanctionedSingleUnit(u: []const u8) bool {
    for (sanctioned_units) |s| if (std.mem.eql(u8, u, s)) return true;
    return false;
}

/// The ISO 4217 currency codes reported by Intl.supportedValuesOf("currency").
/// Kept sorted ascending and unique (the spec only requires a well-formed,
/// sorted, duplicate-free subset that Intl.DisplayNames can render).
const supported_currencies = [_][]const u8{
    "AED", "AFN", "ALL", "AMD", "ANG", "AOA", "ARS", "AUD", "AWG", "AZN",
    "BAM", "BBD", "BDT", "BGN", "BHD", "BIF", "BMD", "BND", "BOB", "BRL",
    "BSD", "BTN", "BWP", "BYN", "BZD", "CAD", "CDF", "CHF", "CLP", "CNY",
    "COP", "CRC", "CUP", "CVE", "CZK", "DJF", "DKK", "DOP", "DZD", "EGP",
    "ERN", "ETB", "EUR", "FJD", "FKP", "GBP", "GEL", "GHS", "GIP", "GMD",
    "GNF", "GTQ", "GYD", "HKD", "HNL", "HTG", "HUF", "IDR", "ILS", "INR",
    "IQD", "IRR", "ISK", "JMD", "JOD", "JPY", "KES", "KGS", "KHR", "KMF",
    "KPW", "KRW", "KWD", "KYD", "KZT", "LAK", "LBP", "LKR", "LRD", "LSL",
    "LYD", "MAD", "MDL", "MGA", "MKD", "MMK", "MNT", "MOP", "MRU", "MUR",
    "MVR", "MWK", "MXN", "MYR", "MZN", "NAD", "NGN", "NIO", "NOK", "NPR",
    "NZD", "OMR", "PAB", "PEN", "PGK", "PHP", "PKR", "PLN", "PYG", "QAR",
    "RON", "RSD", "RUB", "RWF", "SAR", "SBD", "SCR", "SDG", "SEK", "SGD",
    "SHP", "SLE", "SOS", "SRD", "SSP", "STN", "SVC", "SYP", "SZL", "THB",
    "TJS", "TMT", "TND", "TOP", "TRY", "TTD", "TWD", "TZS", "UAH", "UGX",
    "USD", "UYU", "UZS", "VED", "VES", "VND", "VUV", "WST", "XAF", "XCD",
    "XOF", "XPF", "YER", "ZAR", "ZMW", "ZWG",
};

/// IsWellFormedUnitIdentifier: a sanctioned single unit, or "<a>-per-<b>" where
/// both a and b are sanctioned single units.
fn isWellFormedUnitIdentifier(u: []const u8) bool {
    if (isSanctionedSingleUnit(u)) return true;
    if (std.mem.indexOf(u8, u, "-per-")) |p| {
        const a = u[0..p];
        const b = u[p + 5 ..];
        return isSanctionedSingleUnit(a) and isSanctionedSingleUnit(b) and std.mem.indexOf(u8, b, "-per-") == null;
    }
    return false;
}

/// Read, validate, and normalize the Intl.NumberFormat options bag ONCE at
/// construction, in the exact spec order (constructor-option-read-order asserts
/// the observed getter sequence). Returns a plain object carrying the canonical
/// values, which both `format` and `resolvedOptions` read (so user getters fire
/// exactly once and bad values throw at construction).
fn nfProcessOptions(self: *Interpreter, raw_in: Value) EvalError!*value.Object {
    const ro = (try self.newObject()).asObj();
    ro.setProtoAtomic(null); // an internal record — not affected by Object.prototype
    // CoerceOptionsToObject: undefined → none; null → TypeError; primitive → boxed.
    if (raw_in.isUndefined()) return ro;
    const raw: Value = Value.obj(try self.toObject(raw_in));

    const H = struct {
        // GetOption(string) with an allowed set; stores the canonical value when
        // present (RangeError otherwise). Returns the value or null.
        fn str(s: *Interpreter, opts: Value, dst: *value.Object, name: []const u8, allowed: []const []const u8) EvalError!?[]const u8 {
            const v = try s.getProperty(opts, name);
            if (v.isUndefined()) return null;
            const sval = try s.toStringV(v);
            for (allowed) |a| if (std.mem.eql(u8, sval, a)) {
                try s.setProp(dst, name, Value.str(a));
                return a;
            };
            return s.throwError("RangeError", try std.fmt.allocPrint(s.arena, "invalid value for option {s}", .{name}));
        }
        // GetNumberOption in [lo, hi]; stores the integer value when present.
        fn num(s: *Interpreter, opts: Value, dst: *value.Object, name: []const u8, lo: f64, hi: f64) EvalError!void {
            const v = try s.getProperty(opts, name);
            if (v.isUndefined()) return;
            const n = @trunc(try s.toNumberV(v));
            if (std.math.isNan(n) or n < lo or n > hi) return s.throwError("RangeError", try std.fmt.allocPrint(s.arena, "{s} value is out of range", .{name}));
            try s.setProp(dst, name, Value.num(n));
        }
    };

    // localeMatcher: validated against the allowed set, but not retained.
    {
        const lm = try self.getProperty(raw, "localeMatcher");
        if (!lm.isUndefined()) {
            const s = try self.toStringV(lm);
            if (!std.mem.eql(u8, s, "lookup") and !std.mem.eql(u8, s, "best fit")) return self.throwError("RangeError", "invalid value for option localeMatcher");
        }
    }
    const nsv = try self.getProperty(raw, "numberingSystem");
    if (!nsv.isUndefined()) {
        const ns = try std.ascii.allocLowerString(self.arena, try self.toStringV(nsv));
        if (!dtfWellFormedType(ns)) return self.throwError("RangeError", "invalid numberingSystem");
        try self.setProp(ro, "numberingSystem", Value.str(ns));
    }
    // SetNumberFormatUnitOptions: style, then currency*/unit* (all read).
    const style = (try H.str(self, raw, ro, "style", &.{ "decimal", "percent", "currency", "unit" })) orelse "decimal";
    const cv = try self.getProperty(raw, "currency");
    const cur_code: ?[]const u8 = if (cv.isUndefined()) null else try self.toStringV(cv);
    // A present currency is validated regardless of style (IsWellFormedCurrencyCode
    // = exactly three ASCII letters).
    if (cur_code) |code| {
        if (code.len != 3 or !std.ascii.isAlphabetic(code[0]) or !std.ascii.isAlphabetic(code[1]) or !std.ascii.isAlphabetic(code[2])) return self.throwError("RangeError", "invalid currency code");
    }
    const cdisp = try H.str(self, raw, ro, "currencyDisplay", &.{ "code", "symbol", "narrowSymbol", "name" });
    const csign = try H.str(self, raw, ro, "currencySign", &.{ "standard", "accounting" });
    const uv = try self.getProperty(raw, "unit");
    const unit: ?[]const u8 = if (uv.isUndefined()) null else try self.toStringV(uv);
    const udisp = try H.str(self, raw, ro, "unitDisplay", &.{ "short", "long", "narrow" });
    // A missing currency under style:"currency" is a TypeError (takes precedence
    // over the unit check); a present-but-malformed unit is a RangeError for any
    // style.
    if (std.mem.eql(u8, style, "currency") and cur_code == null) return self.throwError("TypeError", "currency code is required with style \"currency\"");
    if (unit) |u| if (!isWellFormedUnitIdentifier(u)) return self.throwError("RangeError", "invalid unit identifier");
    if (std.mem.eql(u8, style, "currency")) {
        try self.setProp(ro, "currency", Value.str(try std.ascii.allocUpperString(self.arena, cur_code.?)));
        if (cdisp == null) try self.setProp(ro, "currencyDisplay", Value.str("symbol"));
        if (csign == null) try self.setProp(ro, "currencySign", Value.str("standard"));
    } else if (std.mem.eql(u8, style, "unit")) {
        if (unit == null) return self.throwError("TypeError", "unit is required with style \"unit\"");
        try self.setProp(ro, "unit", Value.str(unit.?));
        if (udisp == null) try self.setProp(ro, "unitDisplay", Value.str("short"));
    }
    // notation, then SetNumberFormatDigitOptions, then compactDisplay/useGrouping/signDisplay.
    _ = try H.str(self, raw, ro, "notation", &.{ "standard", "scientific", "engineering", "compact" });
    try H.num(self, raw, ro, "minimumIntegerDigits", 1, 21);
    try H.num(self, raw, ro, "minimumFractionDigits", 0, 100);
    try H.num(self, raw, ro, "maximumFractionDigits", 0, 100);
    try H.num(self, raw, ro, "minimumSignificantDigits", 1, 21);
    try H.num(self, raw, ro, "maximumSignificantDigits", 1, 21);
    const riv = try self.getProperty(raw, "roundingIncrement");
    if (!riv.isUndefined()) {
        // The exact value (not truncated) must be one of the sanctioned
        // increments, so 5000.1 is rejected even though trunc(5000.1)=5000.
        const n = try self.toNumberV(riv);
        if (std.math.isNan(n) or n < 1 or n > 5000) return self.throwError("RangeError", "roundingIncrement out of range");
        const allowed = [_]f64{ 1, 2, 5, 10, 20, 25, 50, 100, 200, 250, 500, 1000, 2000, 2500, 5000 };
        var ok = false;
        for (allowed) |a| if (n == a) {
            ok = true;
        };
        if (!ok) return self.throwError("RangeError", "invalid roundingIncrement");
        // A roundingIncrement other than 1 requires roundingType "fractionDigits":
        // significant digits or a non-auto roundingPriority is a TypeError, and the
        // resolved min/max fraction digits must be equal (RangeError otherwise).
        if (n != 1) {
            const has_sd = !(try self.getProperty(raw, "minimumSignificantDigits")).isUndefined() or
                !(try self.getProperty(raw, "maximumSignificantDigits")).isUndefined();
            if (has_sd) return self.throwError("TypeError", "roundingIncrement is incompatible with significant-digits options");
            const rp = try self.getProperty(raw, "roundingPriority");
            if (!rp.isUndefined()) {
                const rps = try self.toStringV(rp);
                if (std.mem.eql(u8, rps, "morePrecision") or std.mem.eql(u8, rps, "lessPrecision"))
                    return self.throwError("TypeError", "roundingIncrement is incompatible with roundingPriority");
            }
            const mnf = try self.getProperty(raw, "minimumFractionDigits");
            const mxf = try self.getProperty(raw, "maximumFractionDigits");
            if (!mnf.isUndefined() and !mxf.isUndefined() and try self.toNumberV(mnf) != try self.toNumberV(mxf))
                return self.throwError("RangeError", "roundingIncrement requires equal min/max fraction digits");
        }
        try self.setProp(ro, "roundingIncrement", Value.num(n));
    }
    _ = try H.str(self, raw, ro, "roundingMode", &.{ "ceil", "floor", "expand", "trunc", "halfCeil", "halfFloor", "halfExpand", "halfTrunc", "halfEven" });
    _ = try H.str(self, raw, ro, "roundingPriority", &.{ "auto", "morePrecision", "lessPrecision" });
    _ = try H.str(self, raw, ro, "trailingZeroDisplay", &.{ "auto", "stripIfInteger" });
    _ = try H.str(self, raw, ro, "compactDisplay", &.{ "short", "long" });
    // GetBooleanOrStringNumberFormatOption: true -> "always"; a falsy value ->
    // false; otherwise a string in {min2,auto,always} is kept, any other string
    // falls back to the default ("auto", left unset) rather than throwing.
    const ug = try self.getProperty(raw, "useGrouping");
    if (!ug.isUndefined()) {
        if (ug.isBoolean() and ug.asBool()) {
            try self.setProp(ro, "useGrouping", Value.str("always"));
        } else if (!ug.toBoolean()) {
            try self.setProp(ro, "useGrouping", Value.boolVal(false));
        } else {
            const s = try self.toStringV(ug);
            if (std.mem.eql(u8, s, "true") or std.mem.eql(u8, s, "false")) {
                // The strings "true"/"false" fall back to the default ("auto").
            } else if (std.mem.eql(u8, s, "min2") or std.mem.eql(u8, s, "auto") or std.mem.eql(u8, s, "always")) {
                try self.setProp(ro, "useGrouping", Value.str(s));
            } else return self.throwError("RangeError", "invalid value for option useGrouping");
        }
    }
    _ = try H.str(self, raw, ro, "signDisplay", &.{ "auto", "never", "always", "exceptZero", "negative" });
    return ro;
}

/// InitializePluralRules option reading, in spec order (localeMatcher, type,
/// notation, compactDisplay, then SetNumberFormatDigitOptions). Validates and
/// stores the normalized values; throwing getters propagate because every option
/// is read.
fn prProcessOptions(self: *Interpreter, raw: Value) EvalError!*value.Object {
    const ro = (try self.newObject()).asObj();
    if (raw.isUndefined()) return ro;
    if (!raw.isObject()) return self.throwError("TypeError", "options must be an object");
    const H = struct {
        fn str(s: *Interpreter, opts: Value, dst: *value.Object, name: []const u8, allowed: []const []const u8) EvalError!?[]const u8 {
            const v = try s.getProperty(opts, name);
            if (v.isUndefined()) return null;
            const sval = try s.toStringV(v);
            for (allowed) |a| if (std.mem.eql(u8, sval, a)) {
                try s.setProp(dst, name, Value.str(a));
                return a;
            };
            return s.throwError("RangeError", try std.fmt.allocPrint(s.arena, "invalid value for option {s}", .{name}));
        }
        fn num(s: *Interpreter, opts: Value, dst: *value.Object, name: []const u8, lo: f64, hi: f64) EvalError!void {
            const v = try s.getProperty(opts, name);
            if (v.isUndefined()) return;
            const n = @trunc(try s.toNumberV(v));
            if (std.math.isNan(n) or n < lo or n > hi) return s.throwError("RangeError", try std.fmt.allocPrint(s.arena, "{s} value is out of range", .{name}));
            try s.setProp(dst, name, Value.num(n));
        }
    };
    _ = try self.getProperty(raw, "localeMatcher"); // read & discard
    _ = try H.str(self, raw, ro, "type", &.{ "cardinal", "ordinal" });
    _ = try H.str(self, raw, ro, "notation", &.{ "standard", "scientific", "engineering", "compact" });
    _ = try H.str(self, raw, ro, "compactDisplay", &.{ "short", "long" });
    try H.num(self, raw, ro, "minimumIntegerDigits", 1, 21);
    try H.num(self, raw, ro, "minimumFractionDigits", 0, 100);
    try H.num(self, raw, ro, "maximumFractionDigits", 0, 100);
    try H.num(self, raw, ro, "minimumSignificantDigits", 1, 21);
    try H.num(self, raw, ro, "maximumSignificantDigits", 1, 21);
    const riv = try self.getProperty(raw, "roundingIncrement");
    if (!riv.isUndefined()) {
        // The exact value (not truncated) must be one of the sanctioned
        // increments, so 5000.1 is rejected even though trunc(5000.1)=5000.
        const n = try self.toNumberV(riv);
        if (std.math.isNan(n) or n < 1 or n > 5000) return self.throwError("RangeError", "roundingIncrement out of range");
        const allowed = [_]f64{ 1, 2, 5, 10, 20, 25, 50, 100, 200, 250, 500, 1000, 2000, 2500, 5000 };
        var ok = false;
        for (allowed) |a| if (n == a) {
            ok = true;
        };
        if (!ok) return self.throwError("RangeError", "invalid roundingIncrement");
        // A roundingIncrement other than 1 requires roundingType "fractionDigits":
        // significant digits or a non-auto roundingPriority is a TypeError, and the
        // resolved min/max fraction digits must be equal (RangeError otherwise).
        if (n != 1) {
            const has_sd = !(try self.getProperty(raw, "minimumSignificantDigits")).isUndefined() or
                !(try self.getProperty(raw, "maximumSignificantDigits")).isUndefined();
            if (has_sd) return self.throwError("TypeError", "roundingIncrement is incompatible with significant-digits options");
            const rp = try self.getProperty(raw, "roundingPriority");
            if (!rp.isUndefined()) {
                const rps = try self.toStringV(rp);
                if (std.mem.eql(u8, rps, "morePrecision") or std.mem.eql(u8, rps, "lessPrecision"))
                    return self.throwError("TypeError", "roundingIncrement is incompatible with roundingPriority");
            }
            const mnf = try self.getProperty(raw, "minimumFractionDigits");
            const mxf = try self.getProperty(raw, "maximumFractionDigits");
            if (!mnf.isUndefined() and !mxf.isUndefined() and try self.toNumberV(mnf) != try self.toNumberV(mxf))
                return self.throwError("RangeError", "roundingIncrement requires equal min/max fraction digits");
        }
        try self.setProp(ro, "roundingIncrement", Value.num(n));
    }
    _ = try H.str(self, raw, ro, "roundingMode", &.{ "ceil", "floor", "expand", "trunc", "halfCeil", "halfFloor", "halfExpand", "halfTrunc", "halfEven" });
    _ = try H.str(self, raw, ro, "roundingPriority", &.{ "auto", "morePrecision", "lessPrecision" });
    _ = try H.str(self, raw, ro, "trailingZeroDisplay", &.{ "auto", "stripIfInteger" });
    return ro;
}

/// The ten Intl.DurationFormat units, in resolvedOptions / format order.
const duration_units = [_][]const u8{ "years", "months", "weeks", "days", "hours", "minutes", "seconds", "milliseconds", "microseconds", "nanoseconds" };

/// services that allow it (NumberFormat/DateTimeFormat/Collator).
fn intlServiceConstructorFn(comptime service: []const u8) value.NativeFn {
    return struct {
        fn call(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
            const self: *Interpreter = @ptrCast(@alignCast(ctx));
            const can_call = comptime (std.mem.eql(u8, service, "NumberFormat") or std.mem.eql(u8, service, "DateTimeFormat") or std.mem.eql(u8, service, "Collator"));
            // Legacy chaining: when called as a function on a receiver that is
            // already an instance of the service, the new instance is hung off
            // the receiver via %Intl%.[[FallbackSymbol]] and the receiver is
            // returned (ChainNumberFormat / ChainDateTimeFormat / ChainCollator).
            var chain_this: ?*value.Object = null;
            const o = blk: {
                if (self.new_target.isObject()) {
                    const oo = (try self.newObject()).asObj();
                    oo.setProtoAtomic(try self.ctorRealmProto(self.new_target.asObj(), service));
                    break :blk oo;
                }
                if (!can_call) return self.throwError("TypeError", "Constructor Intl." ++ service ++ " requires 'new'");
                // Called as a function: a fresh instance with the service's own
                // prototype (found via the Intl namespace).
                const oo = (try self.newObject()).asObj();
                if (self.global_object) |g| if (g.getOwn("Intl")) |iv| if (iv.isObject()) {
                    if (iv.asObj().getOwn(service)) |cv| if (cv.isObject()) {
                        if (cv.asObj().getOwn("prototype")) |pv| if (pv.isObject()) {
                            oo.setProtoAtomic(pv.asObj());
                            // OrdinaryHasInstance(service, this): is the service
                            // prototype in `this`'s prototype chain? Only
                            // NumberFormat/DateTimeFormat have the legacy
                            // FallbackSymbol chaining; Collator ignores `this`.
                            const can_chain = comptime (std.mem.eql(u8, service, "NumberFormat") or std.mem.eql(u8, service, "DateTimeFormat"));
                            if (can_chain and this.isObject()) {
                                var p: ?*value.Object = this.asObj().proto;
                                while (p) |pp| : (p = pp.protoAtomic()) if (pp == pv.asObj()) {
                                    chain_this = this.asObj();
                                    break;
                                };
                            }
                        };
                    };
                };
                break :blk oo;
            };
            // Resolve the locale (first supported requested, else "en").
            const locs = try canonicalizeLocaleList(self, if (args.len > 0) args[0] else Value.undef());
            var resolved: []const u8 = "en";
            for (locs.elements.items) |lv| {
                if (lv.isString() and intlLocaleSupported(lv.asStr())) {
                    resolved = lv.asStr();
                    break;
                }
            }
            try self.setProp(o, "\x00intl", Value.str(service));
            try o.setAttr(self.arena, "\x00intl", .{ .writable = false, .enumerable = false, .configurable = false });
            try self.setProp(o, "\x00locale", Value.str(resolved));
            try o.setAttr(self.arena, "\x00locale", .{ .writable = false, .enumerable = false, .configurable = false });
            // DateTimeFormat validates and normalizes its options eagerly (so
            // bad values throw at construction and resolvedOptions can reflect
            // canonical values); other services keep the raw options bag.
            if (comptime std.mem.eql(u8, service, "DateTimeFormat")) {
                const raw = if (args.len > 1) args[1] else Value.undef();
                const r = try dtfProcessOptions(self, raw);
                try dtfStoreOptions(self, o, r);
            } else if (comptime std.mem.eql(u8, service, "NumberFormat")) {
                const raw = if (args.len > 1) args[1] else Value.undef();
                const ro = try nfProcessOptions(self, raw);
                try self.setProp(o, "\x00opts", Value.obj(ro));
                try o.setAttr(self.arena, "\x00opts", .{ .writable = false, .enumerable = false, .configurable = false });
            } else if (comptime std.mem.eql(u8, service, "RelativeTimeFormat")) {
                // Validate style/numeric and store a normalized options bag.
                const raw_arg = if (args.len > 1) args[1] else Value.undef();
                // RelativeTimeFormat uses CoerceOptionsToObject (primitive -> boxed).
                const raw: Value = if (raw_arg.isUndefined()) Value.undef() else Value.obj(try self.toObject(raw_arg));
                const ro = (try self.newObject()).asObj();
                if (raw.isObject()) {
                    _ = try dtfGetStr(self, raw, "localeMatcher", &.{ "lookup", "best fit" }, "best fit");
                    if (try dtfGetType(self, raw, "numberingSystem")) |ns| try self.setProp(ro, "numberingSystem", Value.str(ns));
                    if (try dtfGetStr(self, raw, "style", &.{ "long", "short", "narrow" }, null)) |s| try self.setProp(ro, "style", Value.str(s));
                    if (try dtfGetStr(self, raw, "numeric", &.{ "always", "auto" }, null)) |nu| try self.setProp(ro, "numeric", Value.str(nu));
                }
                try self.setProp(o, "\x00opts", Value.obj(ro));
                try o.setAttr(self.arena, "\x00opts", .{ .writable = false, .enumerable = false, .configurable = false });
            } else if (comptime std.mem.eql(u8, service, "ListFormat")) {
                // Validate type/style and store a normalized options bag.
                const raw = if (args.len > 1) args[1] else Value.undef();
                // GetOptionsObject: undefined -> none; a non-Object (incl. Symbol/
                // BigInt, which are .object-tagged primitives) -> TypeError.
                if (!raw.isUndefined() and !(raw.isObject() and !raw.asObj().is_symbol and !raw.asObj().is_bigint)) return self.throwError("TypeError", "options must be an object");
                const ro = (try self.newObject()).asObj();
                if (raw.isObject()) {
                    _ = try dtfGetStr(self, raw, "localeMatcher", &.{ "lookup", "best fit" }, "best fit");
                    if (try dtfGetStr(self, raw, "type", &.{ "conjunction", "disjunction", "unit" }, null)) |t| try self.setProp(ro, "type", Value.str(t));
                    if (try dtfGetStr(self, raw, "style", &.{ "long", "short", "narrow" }, null)) |s| try self.setProp(ro, "style", Value.str(s));
                }
                try self.setProp(o, "\x00opts", Value.obj(ro));
                try o.setAttr(self.arena, "\x00opts", .{ .writable = false, .enumerable = false, .configurable = false });
            } else if (comptime std.mem.eql(u8, service, "DisplayNames")) {
                // options is required; `type` is required. Read in spec order.
                const raw = if (args.len > 1) args[1] else Value.undef();
                if (!raw.isObject()) return self.throwError("TypeError", "options must be an object");
                const ro = (try self.newObject()).asObj();
                _ = try dtfGetStr(self, raw, "localeMatcher", &.{ "lookup", "best fit" }, "best fit");
                const style = (try dtfGetStr(self, raw, "style", &.{ "narrow", "short", "long" }, "long")).?;
                try self.setProp(ro, "style", Value.str(style));
                const typ = try dtfGetStr(self, raw, "type", &.{ "language", "region", "script", "currency", "calendar", "dateTimeField" }, null);
                if (typ == null) return self.throwError("TypeError", "DisplayNames requires the type option");
                try self.setProp(ro, "type", Value.str(typ.?));
                const fallback = (try dtfGetStr(self, raw, "fallback", &.{ "code", "none" }, "code")).?;
                try self.setProp(ro, "fallback", Value.str(fallback));
                const ld = (try dtfGetStr(self, raw, "languageDisplay", &.{ "dialect", "standard" }, "dialect")).?;
                if (std.mem.eql(u8, typ.?, "language")) try self.setProp(ro, "languageDisplay", Value.str(ld));
                try self.setProp(o, "\x00opts", Value.obj(ro));
                try o.setAttr(self.arena, "\x00opts", .{ .writable = false, .enumerable = false, .configurable = false });
            } else if (comptime std.mem.eql(u8, service, "Segmenter")) {
                const raw = if (args.len > 1) args[1] else Value.undef();
                // GetOptionsObject: undefined -> none; a non-Object (incl. Symbol/
                // BigInt, which are .object-tagged primitives) -> TypeError.
                if (!raw.isUndefined() and !(raw.isObject() and !raw.asObj().is_symbol and !raw.asObj().is_bigint)) return self.throwError("TypeError", "options must be an object");
                const ro = (try self.newObject()).asObj();
                if (raw.isObject()) {
                    _ = try dtfGetStr(self, raw, "localeMatcher", &.{ "lookup", "best fit" }, "best fit");
                    if (try dtfGetStr(self, raw, "granularity", &.{ "grapheme", "word", "sentence" }, null)) |g| try self.setProp(ro, "granularity", Value.str(g));
                }
                try self.setProp(o, "\x00opts", Value.obj(ro));
                try o.setAttr(self.arena, "\x00opts", .{ .writable = false, .enumerable = false, .configurable = false });
            } else if (comptime std.mem.eql(u8, service, "Collator")) {
                const raw = if (args.len > 1) args[1] else Value.undef();
                const ro = (try self.newObject()).asObj();
                if (raw.isObject()) {
                    if (try dtfGetStr(self, raw, "usage", &.{ "sort", "search" }, null)) |u| try self.setProp(ro, "usage", Value.str(u));
                    _ = try dtfGetStr(self, raw, "localeMatcher", &.{ "lookup", "best fit" }, "best fit");
                    // collation: a well-formed Unicode collation type, else RangeError.
                    const cov = try self.getProperty(raw, "collation");
                    if (!cov.isUndefined()) {
                        const cstr = try std.ascii.allocLowerString(self.arena, try self.toStringV(cov));
                        if (!dtfWellFormedType(cstr)) return self.throwError("RangeError", "invalid collation");
                        try self.setProp(ro, "collation", Value.str(cstr));
                    }
                    const num = try self.getProperty(raw, "numeric");
                    if (!num.isUndefined()) try self.setProp(ro, "numeric", Value.boolVal(num.toBoolean()));
                    if (try dtfGetStr(self, raw, "caseFirst", &.{ "upper", "lower", "false" }, null)) |cf| try self.setProp(ro, "caseFirst", Value.str(cf));
                    if (try dtfGetStr(self, raw, "sensitivity", &.{ "base", "accent", "case", "variant" }, null)) |se| try self.setProp(ro, "sensitivity", Value.str(se));
                    const ip = try self.getProperty(raw, "ignorePunctuation");
                    if (!ip.isUndefined()) try self.setProp(ro, "ignorePunctuation", Value.boolVal(ip.toBoolean()));
                }
                try self.setProp(o, "\x00opts", Value.obj(ro));
                try o.setAttr(self.arena, "\x00opts", .{ .writable = false, .enumerable = false, .configurable = false });
            } else if (comptime std.mem.eql(u8, service, "DurationFormat")) {
                const raw = if (args.len > 1) args[1] else Value.undef();
                // GetOptionsObject: undefined -> none; a non-Object (incl. Symbol/
                // BigInt, which are .object-tagged primitives) -> TypeError.
                if (!raw.isUndefined() and !(raw.isObject() and !raw.asObj().is_symbol and !raw.asObj().is_bigint)) return self.throwError("TypeError", "options must be an object");
                const ro = (try self.newObject()).asObj();
                var base: []const u8 = "short";
                if (raw.isObject()) {
                    _ = try dtfGetStr(self, raw, "localeMatcher", &.{ "lookup", "best fit" }, "best fit");
                    if (try dtfGetType(self, raw, "numberingSystem")) |ns| try self.setProp(ro, "numberingSystem", Value.str(ns));
                    base = (try dtfGetStr(self, raw, "style", &.{ "long", "short", "narrow", "digital" }, "short")).?;
                    try self.setProp(ro, "style", Value.str(base));
                    // Per-unit style + display options (validated; defaults derived below).
                    const time_units = [_][]const u8{ "hours", "minutes", "seconds" };
                    inline for (duration_units) |u| {
                        const is_time = for (time_units) |t| {
                            if (std.mem.eql(u8, u, t)) break true;
                        } else false;
                        const allowed: []const []const u8 = if (is_time) &.{ "long", "short", "narrow", "numeric", "2-digit" } else &.{ "long", "short", "narrow", "numeric" };
                        if (try dtfGetStr(self, raw, u, allowed, null)) |v| try self.setProp(ro, u, Value.str(v));
                        const dkey = u ++ "Display";
                        if (try dtfGetStr(self, raw, dkey, &.{ "always", "auto" }, null)) |d| try self.setProp(ro, dkey, Value.str(d));
                    }
                    const fd = try self.getProperty(raw, "fractionalDigits");
                    if (!fd.isUndefined()) {
                        const n = @trunc(try self.toNumberV(fd));
                        if (std.math.isNan(n) or n < 0 or n > 9) return self.throwError("RangeError", "fractionalDigits out of range");
                        try self.setProp(ro, "fractionalDigits", Value.num(n));
                    }
                } else {
                    try self.setProp(ro, "style", Value.str(base));
                }
                // An explicit non-numeric style after a numeric/2-digit unit is invalid.
                var rstyles: [10][]const u8 = undefined;
                var rdisplays: [10][]const u8 = undefined;
                if (durResolveUnits(Value.obj(ro), base, &rstyles, &rdisplays)) {
                    return self.throwError("RangeError", "invalid duration unit style following a numeric unit");
                }
                try self.setProp(o, "\x00opts", Value.obj(ro));
                try o.setAttr(self.arena, "\x00opts", .{ .writable = false, .enumerable = false, .configurable = false });
            } else if (comptime std.mem.eql(u8, service, "PluralRules")) {
                const raw = if (args.len > 1) args[1] else Value.undef();
                const ro = try prProcessOptions(self, raw);
                try self.setProp(o, "\x00opts", Value.obj(ro));
                try o.setAttr(self.arena, "\x00opts", .{ .writable = false, .enumerable = false, .configurable = false });
            } else if (args.len > 1 and args[1].isObject()) {
                // Keep the options object (if any) for resolvedOptions.
                try self.setProp(o, "\x00opts", args[1]);
                try o.setAttr(self.arena, "\x00opts", .{ .writable = false, .enumerable = false, .configurable = false });
            }
            if (chain_this) |ct| {
                // DefinePropertyOrThrow(this, [[FallbackSymbol]], { value: o,
                // writable/enumerable/configurable: false }); return this.
                if (self.env.get("\x00IntlFallbackSym")) |fs| if (fs.isObject()) {
                    if (ct.getOwn(fs.asObj().sym_key) != null) return self.throwError("TypeError", "Intl." ++ service ++ " already constructed on this object");
                    // Register the symbol so keyToValue recovers it (with its
                    // description) for getOwnPropertySymbols.
                    try self.symbols.put(self.arena, fs.asObj().sym_key, fs.asObj());
                    try ct.setOwn(self.arena, self.root_shape, fs.asObj().sym_key, Value.obj(o));
                    try ct.setAttr(self.arena, fs.asObj().sym_key, .{ .writable = false, .enumerable = false, .configurable = false });
                };
                return Value.obj(ct);
            }
            return Value.obj(o);
        }
    }.call;
}

fn intlBrandOk(this: Value, service: []const u8) bool {
    return this.isObject() and this.asObj().getOwn("\x00intl") != null and std.mem.eql(u8, this.asObj().getOwn("\x00intl").?.asStr(), service);
}

/// UnwrapNumberFormat/DateTimeFormat/Collator: the branded receiver, or — for a
/// legacy receiver that carries the instance under %Intl%.[[FallbackSymbol]] —
/// that instance (the Get is proxy-aware). Null if neither resolves.
fn unwrapIntlThis(self: *Interpreter, recv: Value, comptime service: []const u8) value.HostError!?Value {
    if (intlBrandOk(recv, service)) return recv;
    if (recv.isObject()) {
        if (self.env.get("\x00IntlFallbackSym")) |fs| if (fs.isObject()) {
            const inner = try self.getProperty(recv, fs.asObj().sym_key);
            if (intlBrandOk(inner, service)) return inner;
        };
    }
    return null;
}

/// Format a Number for Intl.NumberFormat — `en`-style grouping with commas.
const en_months_long = [_][]const u8{ "January", "February", "March", "April", "May", "June", "July", "August", "September", "October", "November", "December" };
const en_months_short = [_][]const u8{ "Jan", "Feb", "Mar", "Apr", "May", "Jun", "Jul", "Aug", "Sep", "Oct", "Nov", "Dec" };
const en_months_narrow = [_][]const u8{ "J", "F", "M", "A", "M", "J", "J", "A", "S", "O", "N", "D" };
const en_islamic_months_long = [_][]const u8{ "Muharram", "Safar", "Rabi I", "Rabi II", "Jumada I", "Jumada II", "Rajab", "Shaban", "Ramadan", "Shawwal", "Dhu al-Qidah", "Dhu al-Hijjah" };
const en_hebrew_common_months = [_][]const u8{ "Tishri", "Heshvan", "Kislev", "Tevet", "Shevat", "Adar", "Nisan", "Iyar", "Sivan", "Tamuz", "Av", "Elul" };
const en_hebrew_leap_months = [_][]const u8{ "Tishri", "Heshvan", "Kislev", "Tevet", "Shevat", "Adar I", "Adar II", "Nisan", "Iyar", "Sivan", "Tamuz", "Av", "Elul" };
const en_days_long = [_][]const u8{ "Sunday", "Monday", "Tuesday", "Wednesday", "Thursday", "Friday", "Saturday" };
const en_days_short = [_][]const u8{ "Sun", "Mon", "Tue", "Wed", "Thu", "Fri", "Sat" };
const en_days_narrow = [_][]const u8{ "S", "M", "T", "W", "T", "F", "S" };

/// One element of a DateTimeFormat formatToParts result: a field `type`
/// ("weekday"/"year"/…/"literal") and its formatted `value`.
const DtfPart = struct { typ: []const u8, value: []const u8 };

fn dtfTimeZoneOffsetMs(this: Value, epoch_ms: f64) i64 {
    const ov = this.asObj().getOwn("\x00opts") orelse return 0;
    if (!ov.isObject()) return 0;
    const tv = ov.asObj().getOwn("timeZone") orelse return 0;
    if (!tv.isString()) return 0;
    const s = tv.asStr();
    if (std.mem.startsWith(u8, s, "Etc/GMT+") or std.mem.startsWith(u8, s, "Etc/GMT-")) {
        const sign_ch = s["Etc/GMT".len];
        const hours = std.fmt.parseInt(i64, s["Etc/GMT+".len..], 10) catch return 0;
        if (hours == 0) return 0;
        const sign: i64 = if (sign_ch == '+') -1 else 1;
        return sign * hours * 60 * 60_000;
    }
    const epoch_ns: i128 = @as(i128, @intFromFloat(@trunc(epoch_ms))) * 1_000_000;
    if (s.len != 6 or (s[0] != '+' and s[0] != '-') or s[3] != ':')
        return @intCast(@divTrunc(timeZoneOffsetAtEpoch(s, epoch_ns, 0), 1_000_000));
    const hh = std.fmt.parseInt(i64, s[1..3], 10) catch return 0;
    const mm = std.fmt.parseInt(i64, s[4..6], 10) catch return 0;
    const sign: i64 = if (s[0] == '-') -1 else 1;
    const fallback = sign * (hh * 60 + mm) * 60_000;
    return @intCast(@divTrunc(timeZoneOffsetAtEpoch(s, epoch_ns, fallback * 1_000_000), 1_000_000));
}

fn dtfMonthName(cal: []const u8, month: u8, width: []const u8) ?[]const u8 {
    if (month < 1 or month > 12) return null;
    const idx = month - 1;
    if (std.mem.startsWith(u8, cal, "islamic"))
        return en_islamic_months_long[idx];
    return if (eq(width, "narrow")) en_months_narrow[idx] else if (eq(width, "short")) en_months_short[idx] else en_months_long[idx];
}

fn dtfOffsetZoneName(self: *Interpreter, off_ns: i64) EvalError![]const u8 {
    if (off_ns == 0) return "GMT";
    const neg = off_ns < 0;
    var v: u64 = @intCast(if (neg) -off_ns else off_ns);
    const hh = v / 3_600_000_000_000;
    v %= 3_600_000_000_000;
    const mm = v / 60_000_000_000;
    if (mm == 0) return std.fmt.allocPrint(self.arena, "GMT{s}{d}", .{ if (neg) "-" else "+", hh });
    return std.fmt.allocPrint(self.arena, "GMT{s}{d}:{d:0>2}", .{ if (neg) "-" else "+", hh, mm });
}

fn dtfTimeZoneName(self: *Interpreter, name: []const u8, off_ns: i64, width: []const u8) EvalError![]const u8 {
    if (std.mem.eql(u8, name, "UTC")) {
        return if (eq(width, "long") or eq(width, "longGeneric")) "Coordinated Universal Time" else "UTC";
    }
    if (name.len > 0 and (name[0] == '+' or name[0] == '-')) return dtfOffsetZoneName(self, off_ns);
    if (std.mem.eql(u8, name, "Europe/Vienna")) {
        return if (eq(width, "long") or eq(width, "longGeneric")) "Central European Standard Time" else "GMT+1";
    }
    if (std.mem.eql(u8, name, "Europe/Berlin")) {
        return if (eq(width, "long") or eq(width, "longGeneric")) "Central European Standard Time" else "GMT+1";
    }
    return if (eq(width, "long") or eq(width, "longGeneric")) "Coordinated Universal Time" else "UTC";
}

fn dtfChineseYearName(self: *Interpreter, year: i64) EvalError![]const u8 {
    const stems = [_][]const u8{ "\u{7532}", "\u{4e59}", "\u{4e19}", "\u{4e01}", "\u{620a}", "\u{5df1}", "\u{5e9a}", "\u{8f9b}", "\u{58ec}", "\u{7678}" };
    const branches = [_][]const u8{ "\u{5b50}", "\u{4e11}", "\u{5bc5}", "\u{536f}", "\u{8fb0}", "\u{5df3}", "\u{5348}", "\u{672a}", "\u{7533}", "\u{9149}", "\u{620c}", "\u{4ea5}" };
    const offset = year - 4;
    return std.fmt.allocPrint(self.arena, "{s}{s}", .{ stems[@intCast(@mod(offset, 10))], branches[@intCast(@mod(offset, 12))] });
}

fn dtfAppendYearPart(self: *Interpreter, parts: *std.ArrayListUnmanaged(DtfPart), cal: []const u8, display_year: i64, fmt: []const u8) EvalError!void {
    if (std.mem.eql(u8, cal, "chinese") or std.mem.eql(u8, cal, "dangi")) {
        try parts.append(self.arena, .{ .typ = "relatedYear", .value = try fmtYear(self, display_year, fmt) });
        try parts.append(self.arena, .{ .typ = "yearName", .value = try dtfChineseYearName(self, display_year) });
        try parts.append(self.arena, .{ .typ = "literal", .value = "\u{5e74}" });
        return;
    }
    try parts.append(self.arena, .{ .typ = "year", .value = try fmtYear(self, display_year, fmt) });
}

fn dtfAppendMonthPart(self: *Interpreter, parts: *std.ArrayListUnmanaged(DtfPart), cal: []const u8, year: i64, month: u8, fmt: []const u8) EvalError!void {
    if (std.mem.eql(u8, cal, "hebrew")) {
        const names = if (calInLeapYear(cal, year)) &en_hebrew_leap_months else &en_hebrew_common_months;
        if (month >= 1 and month <= names.len) {
            try parts.append(self.arena, .{ .typ = "month", .value = names[month - 1] });
            return;
        }
    }
    if (std.mem.eql(u8, cal, "chinese") or std.mem.eql(u8, cal, "dangi")) {
        const info = calMonthCodeInfo(cal, year, month);
        const two = eq(fmt, "2-digit");
        const s = if (info.leap) blk: {
            if (two) break :blk try std.fmt.allocPrint(self.arena, "{d:0>2}bis", .{info.month});
            break :blk try std.fmt.allocPrint(self.arena, "{d}bis", .{info.month});
        } else if (two)
            try std.fmt.allocPrint(self.arena, "{d:0>2}", .{info.month})
        else
            try std.fmt.allocPrint(self.arena, "{d}", .{info.month});
        try parts.append(self.arena, .{ .typ = "month", .value = s });
        return;
    }
    const two = eq(fmt, "2-digit");
    const str = if (two) try std.fmt.allocPrint(self.arena, "{d:0>2}", .{month}) else try std.fmt.allocPrint(self.arena, "{d}", .{month});
    try parts.append(self.arena, .{ .typ = "month", .value = str });
}

/// Build the formatted parts for an Intl.DateTimeFormat (en locale, UTC, ISO
/// calendar). Shared by `format` (joins the values) and `formatToParts`. Covers
/// the common component options; locale-specific extras (era, timeZoneName,
/// non-en patterns) are not modeled.
fn dtfBuildParts(self: *Interpreter, this: Value, args: []const Value) value.HostError!std.ArrayListUnmanaged(DtfPart) {
    // The value to format. A Temporal PlainDate/Time/DateTime/YearMonth/MonthDay
    // supplies its ISO fields directly (no TimeClip — its range exceeds Date's);
    // an Instant uses its epoch nanoseconds; everything else is a TimeClip'd time
    // value. `temporal_kind` (when set) restricts which components may be shown.
    var temporal_kind: ?value.TemporalData.Kind = null;
    var temporal_calendar: []const u8 = "iso8601";
    var temporal_tz_name: []const u8 = "UTC";
    var temporal_tz_offset_ns: i64 = 0;
    var civ: Civil = .{ .y = 1970, .m = 1, .d = 1 };
    var hour24: u8 = 0;
    var minute: u8 = 0;
    var second: u8 = 0;
    var frac_ms: u32 = 0;
    {
        const t_obj: ?*value.TemporalData = if (args.len > 0 and args[0].isObject()) args[0].asObj().temporal else null;
        const direct = t_obj != null and switch (t_obj.?.kind) {
            .plain_date, .plain_time, .plain_date_time, .plain_year_month, .plain_month_day, .zoned_date_time => true,
            else => false,
        };
        if (direct) {
            const t = t_obj.?;
            if (t.kind == .zoned_date_time and this.asObj().getOwn("\x00allowTemporalZonedDateTime") == null)
                return self.throwError("TypeError", "Intl.DateTimeFormat does not support Temporal.ZonedDateTime");
            temporal_kind = t.kind;
            temporal_calendar = t.calendar;
            if (t.kind == .zoned_date_time) {
                temporal_tz_name = t.tz_name;
                temporal_tz_offset_ns = timeZoneOffsetAtEpoch(t.tz_name, t.epoch_ns, t.tz_offset_ns);
                const local_ns = t.epoch_ns + @as(i128, temporal_tz_offset_ns);
                const days = @divFloor(local_ns, 86_400_000_000_000);
                const iso = tCivilFromDays(@intCast(days));
                const cal = calendarDateFromIso(t.calendar, iso.y, iso.m, iso.d);
                civ = .{ .y = cal.y, .m = cal.m, .d = cal.d };
                hour24 = @intCast(@divFloor(@mod(local_ns, 86_400_000_000_000), 3_600_000_000_000));
                minute = @intCast(@divFloor(@mod(local_ns, 3_600_000_000_000), 60_000_000_000));
                second = @intCast(@divFloor(@mod(local_ns, 60_000_000_000), 1_000_000_000));
                frac_ms = @intCast(@divFloor(@mod(local_ns, 1_000_000_000), 1_000_000));
            } else if (t.kind == .plain_month_day) {
                const cal = calendarDateFromIso(t.calendar, t.year, t.month, t.day);
                civ = .{ .y = cal.y, .m = cal.m, .d = cal.d };
                hour24 = t.hour;
                minute = t.minute;
                second = t.second;
                frac_ms = t.millisecond;
            } else {
                civ = .{ .y = @as(i64, t.year), .m = t.month, .d = t.day };
                hour24 = t.hour;
                minute = t.minute;
                second = t.second;
                frac_ms = t.millisecond;
            }
        } else {
            const is_instant = t_obj != null and t_obj.?.kind == .instant;
            if (is_instant) temporal_kind = .instant;
            const ms: f64 = if (is_instant)
                @as(f64, @floatFromInt(@divFloor(t_obj.?.epoch_ns, 1_000_000)))
            else if (args.len == 0 or args[0].isUndefined())
                0
            else
                try self.toNumberV(args[0]);
            if (std.math.isNan(ms) or @abs(ms) > 8.64e15) return self.throwError("RangeError", "Invalid time value");
            const day_ms: i64 = 86_400_000;
            const total_ms: i64 = @intFromFloat(@trunc(ms + @as(f64, @floatFromInt(dtfTimeZoneOffsetMs(this, ms)))));
            const epoch_days = @divFloor(total_ms, day_ms);
            var tod = @mod(total_ms, day_ms);
            if (tod < 0) tod += day_ms;
            civ = tCivilFromDays(epoch_days);
            hour24 = @intCast(@divFloor(tod, 3_600_000));
            minute = @intCast(@divFloor(@mod(tod, 3_600_000), 60_000));
            second = @intCast(@divFloor(@mod(tod, 60_000), 1000));
            frac_ms = @intCast(@mod(tod, 1000));
        }
    }
    const wday = isoDayOfWeek(civ.y, civ.m, civ.d) % 7; // 0=Sun..6=Sat

    // Read the component options (or the default: numeric year/month/day).
    var o_weekday: []const u8 = "";
    var o_era: []const u8 = "";
    var o_year: []const u8 = "";
    var o_month: []const u8 = "";
    var o_day: []const u8 = "";
    var o_hour: []const u8 = "";
    var o_minute: []const u8 = "";
    var o_second: []const u8 = "";
    var o_frac: usize = 0; // fractionalSecondDigits (1-3) or 0
    var o_day_period: []const u8 = ""; // flexible dayPeriod width (long/short/narrow)
    var o_tzname: []const u8 = ""; // timeZoneName width (long/short/...)
    var o_calendar: []const u8 = "gregory";
    var hour12 = true;
    var hour_cycle: []const u8 = "";
    var any_comp = false;
    var defaults_applied = false;
    var explicit_hour_setting = false;
    if (this.asObj().getOwn("\x00opts")) |ov| if (ov.isObject()) {
        const get = struct {
            fn s(slf: *Interpreter, obj: Value, k: []const u8) EvalError![]const u8 {
                const v = try slf.getProperty(obj, k);
                return if (v.isString()) v.asStr() else "";
            }
        }.s;
        o_weekday = try get(self, ov, "weekday");
        o_era = try get(self, ov, "era");
        o_year = try get(self, ov, "year");
        o_month = try get(self, ov, "month");
        o_day = try get(self, ov, "day");
        o_hour = try get(self, ov, "hour");
        o_minute = try get(self, ov, "minute");
        o_second = try get(self, ov, "second");
        o_day_period = try get(self, ov, "dayPeriod");
        o_tzname = try get(self, ov, "timeZoneName");
        o_calendar = try get(self, ov, "calendar");
        if (o_calendar.len == 0) o_calendar = "gregory";
        if (ov.asObj().getOwn("fractionalSecondDigits")) |f| if (f.isNumber()) {
            o_frac = @intFromFloat(f.asNum());
        };
        if (ov.asObj().getOwn("\x00defaultsApplied")) |d| defaults_applied = d.toBoolean();
        any_comp = o_weekday.len + o_era.len + o_year.len + o_month.len + o_day.len + o_hour.len + o_minute.len + o_second.len + o_day_period.len + o_tzname.len + o_frac > 0;
        const hc = try get(self, ov, "hourCycle");
        hour_cycle = hc;
        const h12 = try self.getProperty(ov, "hour12");
        if (h12.isBoolean()) {
            hour12 = h12.asBool();
            explicit_hour_setting = true;
        } else if (hc.len > 0) {
            hour12 = std.mem.eql(u8, hc, "h11") or std.mem.eql(u8, hc, "h12");
            explicit_hour_setting = true;
        } else if (this.asObj().getOwn("\x00locale")) |lv| if (lv.isString()) {
            // No explicit hour12/hourCycle: honor the locale's -u-hc keyword.
            if (localeUValue(lv.asStr(), "hc")) |lhc| hour12 = std.mem.eql(u8, lhc, "h11") or std.mem.eql(u8, lhc, "h12");
        };
        if (ov.asObj().getOwn("\x00temporalDefaultHour12")) |tdh| {
            if (tdh.toBoolean()) hour12 = true;
        }
        // dateStyle/timeStyle expand to a representative set of components (an
        // en approximation; the localized patterns/time-zone parts are not
        // modeled). Both can't combine with explicit components (enforced at
        // construction), so it's safe to overwrite here.
        const ds = try get(self, ov, "dateStyle");
        const tstyle = try get(self, ov, "timeStyle");
        if (ds.len > 0) {
            any_comp = true;
            o_weekday = if (eq(ds, "full")) "long" else "";
            o_month = if (eq(ds, "short")) "numeric" else if (eq(ds, "medium")) "short" else "long";
            o_day = "numeric";
            o_year = if (eq(ds, "short")) "2-digit" else "numeric";
        }
        if (tstyle.len > 0) {
            any_comp = true;
            o_hour = "numeric";
            o_minute = "2-digit";
            o_second = if (eq(tstyle, "short")) "" else "2-digit";
            o_tzname = if (eq(tstyle, "full")) "long" else if (eq(tstyle, "long")) "short" else "";
        }
    };
    if (!any_comp) {
        o_year = "numeric";
        o_month = "numeric";
        o_day = "numeric";
    }
    const requested_era = o_era;
    const requested_tzname = o_tzname;
    if (defaults_applied) if (temporal_kind) |tk| {
        o_weekday = "";
        o_era = "";
        o_year = "";
        o_month = "";
        o_day = "";
        o_hour = "";
        o_minute = "";
        o_second = "";
        o_frac = 0;
        o_day_period = "";
        o_tzname = "";
        switch (tk) {
            .plain_date => {
                o_era = requested_era;
                o_year = "numeric";
                o_month = "numeric";
                o_day = "numeric";
            },
            .plain_date_time, .instant => {
                o_era = requested_era;
                o_year = "numeric";
                o_month = "numeric";
                o_day = "numeric";
                o_hour = "numeric";
                o_minute = "numeric";
                o_second = "numeric";
                if (tk == .instant and requested_tzname.len > 0) o_tzname = requested_tzname;
            },
            .plain_time => {
                o_hour = "numeric";
                o_minute = "numeric";
                o_second = "numeric";
            },
            .zoned_date_time => {
                o_era = requested_era;
                o_year = "numeric";
                o_month = "numeric";
                o_day = "numeric";
                o_hour = "numeric";
                o_minute = "numeric";
                o_second = "numeric";
                o_tzname = if (requested_tzname.len > 0) requested_tzname else "short";
            },
            .plain_year_month => {
                o_era = requested_era;
                o_year = "numeric";
                o_month = "numeric";
            },
            .plain_month_day => {
                o_month = "numeric";
                o_day = "numeric";
            },
            else => {},
        }
        any_comp = true;
    };
    if (temporal_kind != null and !explicit_hour_setting and o_hour.len > 0) {
        const loc = if (this.asObj().getOwn("\x00locale")) |lv| (if (lv.isString()) lv.asStr() else "en") else "en";
        hour_cycle = dtfResolveHourCycle(self, loc, hour_cycle, null);
        hour12 = std.mem.eql(u8, hour_cycle, "h11") or std.mem.eql(u8, hour_cycle, "h12");
    }
    if (temporal_kind == null or temporal_kind.? == .instant) {
        civ = calendarDateFromIso(o_calendar, civ.y, civ.m, civ.d);
    }

    // Restrict the components to those the Temporal value's type can provide; a
    // requested component the type lacks is dropped, and if NOTHING the formatter
    // wants overlaps the value's data model it is a TypeError.
    if (temporal_kind) |tk| {
        const has_date = tk == .plain_date or tk == .plain_date_time or tk == .instant or tk == .zoned_date_time;
        const has_time = tk == .plain_time or tk == .plain_date_time or tk == .instant or tk == .zoned_date_time;
        const a_year = has_date or tk == .plain_year_month;
        const a_month = has_date or tk == .plain_year_month or tk == .plain_month_day;
        const a_day = has_date or tk == .plain_month_day;
        const a_tz = tk == .instant or tk == .zoned_date_time;
        var req = false;
        var kept = false;
        const F = struct {
            fn f(ok: bool, slot: *[]const u8, r: *bool, k: *bool) void {
                if (slot.len == 0) return;
                r.* = true;
                if (ok) k.* = true else slot.* = "";
            }
        }.f;
        F(a_year, &o_year, &req, &kept);
        F(a_year, &o_era, &req, &kept);
        F(a_month, &o_month, &req, &kept);
        F(a_day, &o_day, &req, &kept);
        F(has_date, &o_weekday, &req, &kept);
        F(has_time, &o_hour, &req, &kept);
        F(has_time, &o_minute, &req, &kept);
        F(has_time, &o_second, &req, &kept);
        F(has_time, &o_day_period, &req, &kept);
        F(a_tz, &o_tzname, &req, &kept);
        if (o_frac > 0) {
            req = true;
            if (has_time) kept = true else o_frac = 0;
        }
        if (req and !kept) return self.throwError("TypeError", "Intl.DateTimeFormat: options do not overlap the Temporal value's fields");
    }

    const numbering_system = resolveNumberingSystem(this);

    var parts: std.ArrayListUnmanaged(DtfPart) = .empty;
    const P = struct {
        fn lit(s: *Interpreter, p: *std.ArrayListUnmanaged(DtfPart), v: []const u8) EvalError!void {
            try p.append(s.arena, .{ .typ = "literal", .value = v });
        }
        fn num(s: *Interpreter, p: *std.ArrayListUnmanaged(DtfPart), typ: []const u8, v: u64, two: bool) EvalError!void {
            const str = if (two) try std.fmt.allocPrint(s.arena, "{d:0>2}", .{v}) else try std.fmt.allocPrint(s.arena, "{d}", .{v});
            try p.append(s.arena, .{ .typ = typ, .value = str });
        }
    };

    // Weekday prefix.
    if (o_weekday.len > 0) {
        const name = if (eq(o_weekday, "narrow")) en_days_narrow[wday] else if (eq(o_weekday, "short")) en_days_short[wday] else en_days_long[wday];
        try parts.append(self.arena, .{ .typ = "weekday", .value = name });
    }
    // Date part. Numeric month → "M/D/YYYY"; long/short month → "Month D, YYYY".
    const have_date = o_year.len > 0 or o_month.len > 0 or o_day.len > 0;
    if (have_date) {
        const era_info = calEraOf(o_calendar, civ.y, civ.m, civ.d);
        const use_era_year = era_info.era != null and (o_era.len > 0 or std.mem.eql(u8, o_calendar, "japanese"));
        const display_year = if (use_era_year) era_info.era_year else civ.y;
        if (parts.items.len > 0) try P.lit(self, &parts, ", ");
        const month_textual = o_month.len > 0 and !eq(o_month, "numeric") and !eq(o_month, "2-digit");
        const part_calendar = if (std.mem.eql(u8, temporal_calendar, "iso8601")) o_calendar else temporal_calendar;
        if (month_textual) {
            const mn = dtfMonthName(part_calendar, civ.m, o_month);
            try parts.append(self.arena, .{ .typ = "month", .value = mn orelse try std.fmt.allocPrint(self.arena, "{d}", .{civ.m}) });
            if (o_day.len > 0) {
                try P.lit(self, &parts, " ");
                try P.num(self, &parts, "day", civ.d, false);
            }
            if (o_year.len > 0) {
                try P.lit(self, &parts, ", ");
                try dtfAppendYearPart(self, &parts, part_calendar, display_year, o_year);
            }
        } else {
            // All-numeric "M/D/Y" (only the requested parts, slash-separated).
            var first = true;
            if (o_month.len > 0) {
                try dtfAppendMonthPart(self, &parts, part_calendar, civ.y, civ.m, o_month);
                first = false;
            }
            if (o_day.len > 0) {
                if (!first) try P.lit(self, &parts, "/");
                first = false;
                try P.num(self, &parts, "day", civ.d, eq(o_day, "2-digit"));
            }
            if (o_year.len > 0) {
                if (!first) try P.lit(self, &parts, "/");
                first = false;
                try dtfAppendYearPart(self, &parts, part_calendar, display_year, o_year);
            }
        }
        if (o_era.len > 0) if (era_info.era) |raw_era| {
            try P.lit(self, &parts, " ");
            try parts.append(self.arena, .{ .typ = "era", .value = if (asciiEqlIgnoreCase(raw_era, "ce")) "AD" else if (asciiEqlIgnoreCase(raw_era, "bce")) "BC" else raw_era });
        };
    }
    // Time part: "h:mm:ss AM/PM" (or 24-hour).
    const have_clock = o_hour.len > 0 or o_minute.len > 0 or o_second.len > 0;
    const have_time = have_clock or o_day_period.len > 0 or o_tzname.len > 0;
    if (have_time) {
        if (parts.items.len > 0) try P.lit(self, &parts, ", ");
        var h = hour24;
        var ap: []const u8 = "";
        if (o_day_period.len > 0) {
            // A flexible dayPeriod (en) replaces AM/PM.
            ap = enDayPeriod(hour24, o_day_period);
        } else if (hour12 and o_hour.len > 0) {
            ap = if (h < 12) "AM" else "PM";
        }
        if (hour12 and o_hour.len > 0) {
            h = h % 12;
            if (h == 0 and !std.mem.eql(u8, hour_cycle, "h11")) h = 12;
        } else if (std.mem.eql(u8, hour_cycle, "h24") and o_hour.len > 0 and h == 0) {
            h = 24;
        }
        const two_hour = eq(o_hour, "2-digit") or (!hour12 and std.mem.eql(u8, hour_cycle, "h23") and h < 10);
        if (o_hour.len > 0) try P.num(self, &parts, "hour", h, two_hour);
        if (o_minute.len > 0) {
            if (o_hour.len > 0) try P.lit(self, &parts, ":");
            try P.num(self, &parts, "minute", minute, true);
        }
        if (o_second.len > 0) {
            if (o_hour.len > 0 or o_minute.len > 0) try P.lit(self, &parts, ":");
            try P.num(self, &parts, "second", second, true);
        }
        // fractionalSecondDigits: the first N digits of the millisecond (the
        // sub-second is truncated, not rounded), after the seconds.
        if (o_frac > 0 and o_second.len > 0) {
            var mbuf: [3]u8 = .{ '0', '0', '0' };
            _ = std.fmt.bufPrint(&mbuf, "{d:0>3}", .{frac_ms}) catch {};
            const frac_sep = if (std.mem.eql(u8, numbering_system, "arab") or std.mem.eql(u8, numbering_system, "arabext")) "\xd9\xab" else ".";
            try P.lit(self, &parts, frac_sep);
            try parts.append(self.arena, .{ .typ = "fractionalSecond", .value = try self.arena.dupe(u8, mbuf[0..o_frac]) });
        }
        if (ap.len > 0) {
            if (have_clock) try P.lit(self, &parts, " ");
            try parts.append(self.arena, .{ .typ = "dayPeriod", .value = ap });
        }
        if (o_tzname.len > 0) {
            const tzn: []const u8 = if (temporal_kind != null and temporal_kind.? == .zoned_date_time)
                try dtfTimeZoneName(self, temporal_tz_name, temporal_tz_offset_ns, o_tzname)
            else if (eq(o_tzname, "long"))
                "Coordinated Universal Time"
            else if (eq(o_tzname, "longOffset") or eq(o_tzname, "shortOffset"))
                "GMT"
            else if (eq(o_tzname, "longGeneric"))
                "Coordinated Universal Time"
            else
                "UTC"; // "short", "shortGeneric"
            if (have_clock or ap.len > 0) try P.lit(self, &parts, " ");
            try parts.append(self.arena, .{ .typ = "timeZoneName", .value = tzn });
        }
    }
    if (!std.mem.eql(u8, numbering_system, "latn")) {
        if (numbering_systems.digits(numbering_system)) |ds| {
            for (parts.items) |*p| {
                if (eq(p.typ, "year") or eq(p.typ, "month") or eq(p.typ, "day") or
                    eq(p.typ, "hour") or eq(p.typ, "minute") or eq(p.typ, "second") or
                    eq(p.typ, "fractionalSecond"))
                {
                    p.value = try translateDigits(self, p.value, ds);
                }
            }
        }
    }
    return parts;
}

/// en flexible day period for an hour (minute 0): noon at 12, morning 6–11,
/// afternoon 13–17, evening 18–20, else night ("n" is narrow noon).
fn enDayPeriod(h: u8, width: []const u8) []const u8 {
    if (h == 12) return if (std.mem.eql(u8, width, "narrow")) "n" else "noon";
    if (h >= 6 and h < 12) return "in the morning";
    if (h >= 13 and h < 18) return "in the afternoon";
    if (h >= 18 and h < 21) return "in the evening";
    return "at night";
}

fn intlDateTimeFormatFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (!intlBrandOk(this, "DateTimeFormat")) return self.throwError("TypeError", "Intl.DateTimeFormat.prototype.format on incompatible receiver");
    const parts = try dtfBuildParts(self, this, args);
    var buf: std.ArrayListUnmanaged(u8) = .empty;
    for (parts.items) |p| try buf.appendSlice(self.arena, p.value);
    return Value.str(try buf.toOwnedSlice(self.arena));
}

fn intlDateTimeFormatToPartsFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (!intlBrandOk(this, "DateTimeFormat")) return self.throwError("TypeError", "Intl.DateTimeFormat.prototype.formatToParts on incompatible receiver");
    const parts = try dtfBuildParts(self, this, args);
    const arr = (try self.newArray()).asObj();
    for (parts.items) |p| {
        const o = (try self.newObject()).asObj();
        try self.setProp(o, "type", Value.str(p.typ));
        try self.setProp(o, "value", Value.str(p.value));
        try arr.elements.append(arr.elementsAllocator(self.arena), Value.obj(o));
    }
    return Value.obj(arr);
}

/// Range separator shared by DateTimeFormat formatRange/formatRangeToParts (the
/// en-US tests derive the separator from formatRangeToParts' shared literal, so
/// the only requirement is that both use the same value).
const dtf_range_sep = " \u{2013} ";

/// The "kind" of a formatRange argument: a Temporal kind, or null for a legacy
/// time value (number/Date). The two arguments of formatRange must agree.
fn dtfArgKind(v: Value) ?value.TemporalData.Kind {
    if (v.isObject() and v.asObj().temporal != null) return v.asObj().temporal.?.kind;
    return null;
}

/// FormatDateTimeRange step: the two arguments must be the same kind (both legacy
/// time values, or the same Temporal type) — otherwise a TypeError.
fn dtfRangeCheckKinds(self: *Interpreter, a: Value, b: Value) value.HostError!void {
    const ka = dtfArgKind(a);
    const kb = dtfArgKind(b);
    const same = (ka == null and kb == null) or (ka != null and kb != null and ka.? == kb.?);
    if (!same) return self.throwError("TypeError", "Intl.DateTimeFormat range: start and end must be the same type");
    if (ka != null and a.isObject() and b.isObject()) {
        const ta = a.asObj().temporal orelse return;
        const tb = b.asObj().temporal orelse return;
        if (temporalCarriesCalendar(ta) and !std.mem.eql(u8, ta.calendar, tb.calendar))
            return self.throwError("RangeError", "Intl.DateTimeFormat range: start and end calendars must match");
    }
}

fn dtfToDateTimeFormattable(self: *Interpreter, v: Value) value.HostError!Value {
    if (dtfArgKind(v) != null) return v;
    return Value.num(try self.toNumberV(v));
}

fn dtfAppendPartValues(self: *Interpreter, buf: *std.ArrayListUnmanaged(u8), parts: []const DtfPart) EvalError!void {
    for (parts) |p| try buf.appendSlice(self.arena, p.value);
}

fn dtfPartsSameValues(xp: []const DtfPart, yp: []const DtfPart) bool {
    if (xp.len != yp.len) return false;
    for (xp, 0..) |p, i| {
        if (!std.mem.eql(u8, p.value, yp[i].value)) return false;
    }
    return true;
}

fn dtfSharedDateTimePrefixLen(xp: []const DtfPart, yp: []const DtfPart) usize {
    const n = @min(xp.len, yp.len);
    var i: usize = 0;
    while (i < n) : (i += 1) {
        const a = xp[i];
        const b = yp[i];
        if (!std.mem.eql(u8, a.typ, b.typ) or !std.mem.eql(u8, a.value, b.value)) break;
        if (std.mem.eql(u8, a.typ, "literal") and std.mem.eql(u8, a.value, ", ")) return i + 1;
    }
    return 0;
}

fn dtfIsTextualDateOnly(parts: []const DtfPart) bool {
    return parts.len == 5 and
        std.mem.eql(u8, parts[0].typ, "month") and
        std.mem.eql(u8, parts[1].typ, "literal") and std.mem.eql(u8, parts[1].value, " ") and
        std.mem.eql(u8, parts[2].typ, "day") and
        std.mem.eql(u8, parts[3].typ, "literal") and std.mem.eql(u8, parts[3].value, ", ") and
        std.mem.eql(u8, parts[4].typ, "year");
}

fn dtfAppendTextualDateRangeText(self: *Interpreter, buf: *std.ArrayListUnmanaged(u8), xp: []const DtfPart, yp: []const DtfPart) EvalError!bool {
    if (!dtfIsTextualDateOnly(xp) or !dtfIsTextualDateOnly(yp)) return false;
    if (!std.mem.eql(u8, xp[4].value, yp[4].value)) return false;
    if (std.mem.eql(u8, xp[0].value, yp[0].value)) {
        try dtfAppendPartValues(self, buf, xp[0..3]);
        try buf.appendSlice(self.arena, dtf_range_sep);
        try buf.appendSlice(self.arena, yp[2].value);
        try dtfAppendPartValues(self, buf, xp[3..5]);
    } else {
        try dtfAppendPartValues(self, buf, xp[0..3]);
        try buf.appendSlice(self.arena, dtf_range_sep);
        try dtfAppendPartValues(self, buf, yp[0..3]);
        try dtfAppendPartValues(self, buf, xp[3..5]);
    }
    return true;
}

fn dtfFormatRangePartsText(self: *Interpreter, xp: []const DtfPart, yp: []const DtfPart) EvalError![]const u8 {
    var buf: std.ArrayListUnmanaged(u8) = .empty;
    if (dtfPartsSameValues(xp, yp)) {
        try dtfAppendPartValues(self, &buf, xp);
        return buf.toOwnedSlice(self.arena);
    }
    if (try dtfAppendTextualDateRangeText(self, &buf, xp, yp))
        return buf.toOwnedSlice(self.arena);
    if (dtfIsTextualDateOnly(xp) and dtfIsTextualDateOnly(yp)) {
        try dtfAppendPartValues(self, &buf, xp);
        try buf.appendSlice(self.arena, dtf_range_sep);
        try dtfAppendPartValues(self, &buf, yp);
        return buf.toOwnedSlice(self.arena);
    }
    const shared_prefix = dtfSharedDateTimePrefixLen(xp, yp);
    if (shared_prefix > 0) {
        try dtfAppendPartValues(self, &buf, xp[0..shared_prefix]);
        try dtfAppendPartValues(self, &buf, xp[shared_prefix..]);
        try buf.appendSlice(self.arena, dtf_range_sep);
        try dtfAppendPartValues(self, &buf, yp[shared_prefix..]);
        return buf.toOwnedSlice(self.arena);
    }
    try dtfAppendPartValues(self, &buf, xp);
    try buf.appendSlice(self.arena, dtf_range_sep);
    try dtfAppendPartValues(self, &buf, yp);
    return buf.toOwnedSlice(self.arena);
}

/// `Intl.DateTimeFormat.prototype.formatRange(start, end)` — compact en range
/// formatting with equal dates collapsed and textual date intervals sharing
/// stable month/year fields.
fn intlDateTimeFormatRangeFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (!intlBrandOk(this, "DateTimeFormat")) return self.throwError("TypeError", "Intl.DateTimeFormat.prototype.formatRange on incompatible receiver");
    if (args.len < 2 or args[0].isUndefined() or args[1].isUndefined()) return self.throwError("TypeError", "formatRange requires two defined arguments");
    const start = try dtfToDateTimeFormattable(self, args[0]);
    const end = try dtfToDateTimeFormattable(self, args[1]);
    try dtfRangeCheckKinds(self, start, end);
    const xp = try dtfBuildParts(self, this, &.{start}); // dtfBuildParts TimeClips (RangeError on bad value)
    const yp = try dtfBuildParts(self, this, &.{end});
    return Value.str(try dtfFormatRangePartsText(self, xp.items, yp.items));
}

fn intlDateTimeFormatRangeToPartsFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (!intlBrandOk(this, "DateTimeFormat")) return self.throwError("TypeError", "Intl.DateTimeFormat.prototype.formatRangeToParts on incompatible receiver");
    if (args.len < 2 or args[0].isUndefined() or args[1].isUndefined()) return self.throwError("TypeError", "formatRangeToParts requires two defined arguments");
    const start = try dtfToDateTimeFormattable(self, args[0]);
    const end = try dtfToDateTimeFormattable(self, args[1]);
    try dtfRangeCheckKinds(self, start, end);
    const xp = try dtfBuildParts(self, this, &.{start});
    const yp = try dtfBuildParts(self, this, &.{end});
    const arr = (try self.newArray()).asObj();
    const emit = struct {
        fn part(s: *Interpreter, a: *value.Object, p: DtfPart, src: []const u8) value.HostError!void {
            const o = (try s.newObject()).asObj();
            try s.setProp(o, "type", Value.str(p.typ));
            try s.setProp(o, "value", Value.str(p.value));
            try s.setProp(o, "source", Value.str(src));
            try a.elements.append(a.elementsAllocator(s.arena), Value.obj(o));
        }
        fn one(s: *Interpreter, a: *value.Object, prts: []const DtfPart, src: []const u8) value.HostError!void {
            for (prts) |p| try part(s, a, p, src);
        }
    }.one;
    if (dtfPartsSameValues(xp.items, yp.items)) {
        try emit(self, arr, xp.items, "shared");
        return Value.obj(arr);
    }
    if (dtfIsTextualDateOnly(xp.items) and dtfIsTextualDateOnly(yp.items) and std.mem.eql(u8, xp.items[4].value, yp.items[4].value)) {
        if (std.mem.eql(u8, xp.items[0].value, yp.items[0].value)) {
            try emit(self, arr, xp.items[0..2], "shared");
            try emit(self, arr, xp.items[2..3], "startRange");
            const lo = (try self.newObject()).asObj();
            try self.setProp(lo, "type", Value.str("literal"));
            try self.setProp(lo, "value", Value.str(dtf_range_sep));
            try self.setProp(lo, "source", Value.str("shared"));
            try arr.elements.append(arr.elementsAllocator(self.arena), Value.obj(lo));
            try emit(self, arr, yp.items[2..3], "endRange");
            try emit(self, arr, xp.items[3..5], "shared");
        } else {
            try emit(self, arr, xp.items[0..3], "startRange");
            const lo = (try self.newObject()).asObj();
            try self.setProp(lo, "type", Value.str("literal"));
            try self.setProp(lo, "value", Value.str(dtf_range_sep));
            try self.setProp(lo, "source", Value.str("shared"));
            try arr.elements.append(arr.elementsAllocator(self.arena), Value.obj(lo));
            try emit(self, arr, yp.items[0..3], "endRange");
            try emit(self, arr, xp.items[3..5], "shared");
        }
        return Value.obj(arr);
    }
    if (dtfIsTextualDateOnly(xp.items) and dtfIsTextualDateOnly(yp.items)) {
        try emit(self, arr, xp.items, "startRange");
        const lo = (try self.newObject()).asObj();
        try self.setProp(lo, "type", Value.str("literal"));
        try self.setProp(lo, "value", Value.str(dtf_range_sep));
        try self.setProp(lo, "source", Value.str("shared"));
        try arr.elements.append(arr.elementsAllocator(self.arena), Value.obj(lo));
        try emit(self, arr, yp.items, "endRange");
        return Value.obj(arr);
    }
    const shared_prefix = dtfSharedDateTimePrefixLen(xp.items, yp.items);
    if (shared_prefix > 0) {
        try emit(self, arr, xp.items[0..shared_prefix], "shared");
        try emit(self, arr, xp.items[shared_prefix..], "startRange");
        const lo = (try self.newObject()).asObj();
        try self.setProp(lo, "type", Value.str("literal"));
        try self.setProp(lo, "value", Value.str(dtf_range_sep));
        try self.setProp(lo, "source", Value.str("shared"));
        try arr.elements.append(arr.elementsAllocator(self.arena), Value.obj(lo));
        try emit(self, arr, yp.items[shared_prefix..], "endRange");
        return Value.obj(arr);
    }
    try emit(self, arr, xp.items, "startRange");
    const lo = (try self.newObject()).asObj();
    try self.setProp(lo, "type", Value.str("literal"));
    try self.setProp(lo, "value", Value.str(dtf_range_sep));
    try self.setProp(lo, "source", Value.str("shared"));
    try arr.elements.append(arr.elementsAllocator(self.arena), Value.obj(lo));
    try emit(self, arr, yp.items, "endRange");
    return Value.obj(arr);
}

fn fmtYear(self: *Interpreter, y: i64, fmt: []const u8) EvalError![]const u8 {
    if (std.mem.eql(u8, fmt, "2-digit")) {
        const yy: u8 = @intCast(@mod(y, 100));
        return std.fmt.allocPrint(self.arena, "{d:0>2}", .{yy});
    }
    return std.fmt.allocPrint(self.arena, "{d}", .{y});
}

fn appendNum(self: *Interpreter, buf: *std.ArrayListUnmanaged(u8), first: *bool, sep: u8, v: anytype, two_digit: bool) EvalError!void {
    if (!first.*) try buf.append(self.arena, sep);
    first.* = false;
    if (two_digit) try tfmt(self, buf, "{d:0>2}", .{v}) else try tfmt(self, buf, "{d}", .{v});
}

/// Per-locale decimal/grouping separators (a compact CLDR subset keyed by the
/// language subtag). Most locales group with "," and decimal with "." (the en
/// default); the table lists the common exceptions used by the test corpus.
/// Per-locale number symbols + currency-symbol placement, from CLDR (generated
/// table in cldr_numbers.zig; ~50 locales, language-subtag fallback).
fn localeNumberSymbols(locale: []const u8) cldr_numbers.NumSym {
    var syms = cldr_numbers.lookup(locale);
    const t = parseTriple(locale);
    if (std.ascii.eqlIgnoreCase(t.l, "pt") and std.ascii.eqlIgnoreCase(t.r, "PT")) {
        syms.group = "\u{00a0}";
        syms.symbol_before = false;
    }
    return syms;
}

/// Per-currency display info: the en symbol and the ISO 4217 default fraction
/// digits. Unknown currencies fall back to the code with 2 digits.
const CurrencyInfo = struct { symbol: []const u8, digits: u8 };
fn currencyInfo(code: []const u8) CurrencyInfo {
    const pairs = .{
        .{ "USD", "$", 2 },
        .{ "EUR", "€", 2 },
        .{ "GBP", "£", 2 },
        .{ "JPY", "¥", 0 },
        .{ "CNY", "CN¥", 2 },
        .{ "INR", "₹", 2 },
        .{ "KRW", "₩", 0 },
        .{ "RUB", "₽", 2 },
        .{ "BRL", "R$", 2 },
        .{ "CAD", "CA$", 2 },
        .{ "AUD", "A$", 2 },
        .{ "CHF", "CHF", 2 },
        .{ "HKD", "HK$", 2 },
        .{ "NZD", "NZ$", 2 },
        .{ "MXN", "MX$", 2 },
        .{ "BHD", "BHD", 3 },
        .{ "KWD", "KWD", 3 },
        .{ "OMR", "OMR", 3 },
        .{ "CLP", "CLP", 0 },
        .{ "VND", "₫", 0 },
        .{ "TWD", "NT$", 2 },
    };
    inline for (pairs) |p| if (std.mem.eql(u8, code, p[0])) return .{ .symbol = p[1], .digits = p[2] };
    return .{ .symbol = code, .digits = 2 };
}

/// Round a non-negative magnitude `m` to an integer per an ECMA-402 rounding
/// mode (directed modes are sign-aware via `neg`). Ties are decided on the
/// f64 fractional remainder — which matches the spec, since the value being
/// formatted is already the nearest f64 to the source decimal.
fn roundMag(m: f64, neg: bool, mode: []const u8) f64 {
    const low = @floor(m);
    const frac = m - low;
    const eps = 1e-12 * @max(@as(f64, 1), @abs(m));
    if (frac <= eps) return low;
    const eqs = std.mem.eql;
    const up = blk: {
        if (eqs(u8, mode, "ceil")) break :blk !neg;
        if (eqs(u8, mode, "floor")) break :blk neg;
        if (eqs(u8, mode, "expand")) break :blk true;
        if (eqs(u8, mode, "trunc")) break :blk false;
        if (frac < 0.5 - eps) break :blk false;
        if (frac > 0.5 + eps) break :blk true;
        if (eqs(u8, mode, "halfCeil")) break :blk !neg;
        if (eqs(u8, mode, "halfFloor")) break :blk neg;
        if (eqs(u8, mode, "halfTrunc")) break :blk false;
        if (eqs(u8, mode, "halfEven")) break :blk @mod(low, 2) != 0;
        break :blk true; // halfExpand (default) — ties away from zero
    };
    return if (up) low + 1 else low;
}

const NfRound = struct { int_str: []const u8, frac_str: []const u8, is_zero: bool };

/// The integer power of ten just below `m` (m > 0): floor(log10(m)), corrected
/// for the float error that makes log10 of an exact power of ten land low.
fn orderOfMagnitude(m: f64) i32 {
    var e: i32 = @intFromFloat(@floor(std.math.log10(m)));
    if (powi10(e + 1) <= m) e += 1;
    if (powi10(e) > m) e -= 1;
    return e;
}

fn powi10(e: i32) f64 {
    return std.math.pow(f64, 10, @floatFromInt(e));
}

/// Round `mag` (>= 0) to a decimal string per the NumberFormat digit options:
/// significant digits (when set / chosen by roundingPriority) else fraction
/// digits, with a rounding increment and rounding mode. Returns the integer and
/// (trimmed) fraction digit strings.
fn nfRound(self: *Interpreter, mag: f64, neg: bool, min_int: usize, min_frac: usize, max_frac: usize, min_sig: ?usize, max_sig: ?usize, frac_set: bool, priority: []const u8, rinc: u64, mode: []const u8) EvalError!NfRound {
    const Inner = struct {
        // Build int/frac strings from an unsigned integer `r` whose decimal
        // point sits `scale_exp` places from its right end (scale_exp may be < 0).
        fn fromScaled(s: *Interpreter, r: u64, scale_exp: i32, lo_frac: usize, hi_frac: ?usize) EvalError!struct { i: []const u8, f: []const u8 } {
            var rs = try std.fmt.allocPrint(s.arena, "{d}", .{r});
            var int_str: []const u8 = undefined;
            var frac: std.ArrayListUnmanaged(u8) = .empty;
            if (scale_exp <= 0) {
                // Integer; append the trailing zeros the negative exponent implies.
                var pad = -scale_exp;
                while (pad > 0) : (pad -= 1) rs = try std.fmt.allocPrint(s.arena, "{s}0", .{rs});
                int_str = rs;
            } else {
                const se: usize = @intCast(scale_exp);
                if (se >= rs.len) {
                    int_str = "0";
                    var lead = se - rs.len;
                    while (lead > 0) : (lead -= 1) try frac.append(s.arena, '0');
                    try frac.appendSlice(s.arena, rs);
                } else {
                    int_str = rs[0 .. rs.len - se];
                    try frac.appendSlice(s.arena, rs[rs.len - se ..]);
                }
            }
            // Trim trailing zeros down to lo_frac; pad up to lo_frac; cap at hi_frac.
            var flen = frac.items.len;
            if (hi_frac) |hf| while (flen > hf) {
                flen -= 1;
            };
            while (flen > lo_frac and frac.items[flen - 1] == '0') flen -= 1;
            var fb: std.ArrayListUnmanaged(u8) = .empty;
            try fb.appendSlice(s.arena, frac.items[0..flen]);
            while (fb.items.len < lo_frac) try fb.append(s.arena, '0');
            return .{ .i = int_str, .f = try fb.toOwnedSlice(s.arena) };
        }
    };

    const use_sig = blk: {
        if (max_sig == null) break :blk false;
        if (std.mem.eql(u8, priority, "auto") or !frac_set) break :blk true;
        const e = if (mag == 0) 0 else orderOfMagnitude(mag);
        const sig_round_mag: i32 = e - @as(i32, @intCast(max_sig.?)) + 1;
        const frac_round_mag: i32 = -@as(i32, @intCast(max_frac));
        break :blk if (std.mem.eql(u8, priority, "morePrecision"))
            sig_round_mag < frac_round_mag
        else
            sig_round_mag > frac_round_mag;
    };
    if (use_sig) {
        const msig = max_sig.?;
        const lsig = min_sig orelse 1;
        if (mag == 0) {
            var fb: std.ArrayListUnmanaged(u8) = .empty;
            var k: usize = 1;
            while (k < lsig) : (k += 1) try fb.append(self.arena, '0');
            return .{ .int_str = "0", .frac_str = try fb.toOwnedSlice(self.arena), .is_zero = true };
        }
        const e = orderOfMagnitude(mag);
        var scale_exp: i32 = @as(i32, @intCast(msig)) - 1 - e;
        var scaled = if (scale_exp >= 0) mag * powi10(scale_exp) else mag / powi10(-scale_exp);
        while (!std.math.isFinite(scaled) or scaled >= 9.0e18) {
            scale_exp -= 1;
            scaled = if (scale_exp >= 0) mag * powi10(scale_exp) else mag / powi10(-scale_exp);
        }
        const r: u64 = @intFromFloat(roundMag(scaled, neg, mode));
        // Rounding up can add a digit (9.99 -> 10.0); the decimal point keeps the
        // same scale_exp, so fromScaled handles the extra integer digit.
        // Significant mode shows at least lsig digits: lo_frac forces trailing zeros.
        const lo_frac: usize = blk: {
            // significant digits already in the integer part:
            const int_sig: i32 = e + 1;
            const need: i32 = @as(i32, @intCast(lsig)) - int_sig;
            break :blk if (need > 0) @intCast(need) else 0;
        };
        const res = try Inner.fromScaled(self, r, scale_exp, lo_frac, null);
        var int_str = res.i;
        while (int_str.len < min_int) int_str = try std.fmt.allocPrint(self.arena, "0{s}", .{int_str});
        return .{ .int_str = int_str, .frac_str = res.f, .is_zero = false };
    }

    // Fixed (fraction-digit) path with optional rounding increment. Rounding is
    // done with at most 18 fraction digits (u64 range; further digits are zero
    // at f64 precision), then the string is padded out to min_frac.
    // Cap the fraction scaling so `mag * 10^eff` stays within u64 (a large
    // integer magnitude has no representable fraction anyway; the dropped digits
    // are zero and get padded back below).
    var eff: usize = @min(max_frac, 18);
    var scale: f64 = 1;
    while (true) {
        scale = 1;
        for (0..eff) |_| scale *= 10;
        if (eff == 0 or mag * scale < 9.0e18) break;
        eff -= 1;
    }
    const scaled = mag * scale;
    const rinc_f: f64 = @floatFromInt(rinc);
    const r: u64 = if (rinc > 1) @intFromFloat(roundMag(scaled / rinc_f, neg, mode) * rinc_f) else @intFromFloat(roundMag(scaled, neg, mode));
    const divi: u64 = @intFromFloat(scale);
    const int_part: u64 = if (divi == 0) r else r / divi;
    const frac_part: u64 = if (divi == 0) 0 else r % divi;
    var int_str = try std.fmt.allocPrint(self.arena, "{d}", .{int_part});
    while (int_str.len < min_int) int_str = try std.fmt.allocPrint(self.arena, "0{s}", .{int_str});
    var fb: std.ArrayListUnmanaged(u8) = .empty;
    if (max_frac > 0) {
        const fs = try std.fmt.allocPrint(self.arena, "{d}", .{frac_part});
        var pad = eff;
        while (pad > fs.len) : (pad -= 1) try fb.append(self.arena, '0');
        try fb.appendSlice(self.arena, fs);
        while (fb.items.len < max_frac) try fb.append(self.arena, '0'); // digits beyond u64 precision are zero
        var flen = fb.items.len;
        while (flen > min_frac and fb.items[flen - 1] == '0') flen -= 1;
        fb.items.len = flen;
    }
    return .{ .int_str = int_str, .frac_str = try fb.toOwnedSlice(self.arena), .is_zero = (int_part == 0 and frac_part == 0) };
}

/// ResolveLocale numbering for resolvedOptions: a supported `numberingSystem`
/// option wins; otherwise a supported `-u-nu-` extension; otherwise "latn". The
/// resolved locale keeps `-u-nu-<sys>` only when the value came from a supported
/// extension equal to the resolved system. Sets `locale` + `numberingSystem` on
/// `out`.
fn intlResolveNumbering(self: *Interpreter, out: *value.Object, tag: []const u8, opt_ns: ?[]const u8) value.HostError!void {
    const ext_ns = localeUValue(tag, "nu");
    const ext_ok = if (ext_ns) |e| numbering_systems.digits(e) != null else false;
    const opt_ok = if (opt_ns) |p| numbering_systems.digits(p) != null else false;
    const ns: []const u8 = if (opt_ok) opt_ns.? else if (ext_ok) ext_ns.? else "latn";
    const keep_ext = ext_ok and std.mem.eql(u8, ext_ns.?, ns);
    const lang_base = if (std.mem.indexOf(u8, tag, "-u-")) |u| tag[0..u] else tag;
    const rloc: []const u8 = if (keep_ext)
        try std.fmt.allocPrint(self.arena, "{s}-u-nu-{s}", .{ lang_base, ns })
    else
        lang_base;
    try self.setProp(out, "locale", Value.str(rloc));
    try self.setProp(out, "numberingSystem", Value.str(ns));
}

/// ResolveLocale for Collator's relevant extension keys kn (numeric) and kf
/// (caseFirst): an option wins over the `-u-` value; the keyword stays in the
/// resolved locale only when it came from the extension and wasn't overridden by
/// a differing option. Returns the resolved values and sets `locale` on `out`.
fn collatorCollationSupported(tag: []const u8, collation: []const u8) bool {
    if (std.mem.eql(u8, collation, "emoji") or std.mem.eql(u8, collation, "eor")) return true;
    return std.mem.eql(u8, collation, "phonebk") and std.mem.eql(u8, parseTriple(tag).l, "de");
}

fn collatorResolveLocale(self: *Interpreter, out: *value.Object, tag: []const u8, opt_num: ?bool, opt_kf: ?[]const u8, opt_co: ?[]const u8) value.HostError!struct { numeric: bool, case_first: []const u8, collation: []const u8 } {
    const co_ext = localeUValue(tag, "co");
    const ext_co: ?[]const u8 = if (co_ext) |v| if (collatorCollationSupported(tag, v)) v else null else null;
    const opt_co_ok: ?[]const u8 = if (opt_co) |v| if (collatorCollationSupported(tag, v)) v else null else null;
    const collation: []const u8 = if (opt_co_ok) |v| v else (ext_co orelse "default");
    const keep_co = ext_co != null and std.mem.eql(u8, collation, ext_co.?);

    const kn_ext = localeUValue(tag, "kn");
    const ext_num: ?bool = if (kn_ext) |v| !std.mem.eql(u8, v, "false") else null;
    const numeric: bool = if (opt_num) |o| o else (ext_num orelse false);
    const keep_kn = ext_num != null and (opt_num == null or opt_num.? == ext_num.?);

    const kf_raw = localeUValue(tag, "kf");
    const ext_kf: ?[]const u8 = if (kf_raw) |v| (if (std.mem.eql(u8, v, "upper") or std.mem.eql(u8, v, "lower") or std.mem.eql(u8, v, "false")) v else null) else null;
    const case_first: []const u8 = if (opt_kf) |o| o else (ext_kf orelse "false");
    const keep_kf = ext_kf != null and (opt_kf == null or std.mem.eql(u8, opt_kf.?, ext_kf.?));

    const base = if (std.mem.indexOf(u8, tag, "-u-")) |u| tag[0..u] else tag;
    var buf: std.ArrayListUnmanaged(u8) = .empty;
    try buf.appendSlice(self.arena, base);
    var any_kw = false;
    // Canonical key order: co before kf before kn.
    if (keep_co) {
        try buf.appendSlice(self.arena, "-u-co-");
        try buf.appendSlice(self.arena, collation);
        any_kw = true;
    }
    if (keep_kf) {
        try buf.appendSlice(self.arena, if (any_kw) "-kf-" else "-u-kf-");
        try buf.appendSlice(self.arena, case_first);
        any_kw = true;
    }
    if (keep_kn) {
        try buf.appendSlice(self.arena, if (any_kw) "-kn" else "-u-kn");
        if (!numeric) try buf.appendSlice(self.arena, "-false");
        any_kw = true;
    }
    try self.setProp(out, "locale", Value.str(try buf.toOwnedSlice(self.arena)));
    return .{ .numeric = numeric, .case_first = case_first, .collation = collation };
}

const CollatorOptions = struct {
    locale: []const u8 = "en",
    usage: []const u8 = "sort",
    collation: []const u8 = "default",
    sensitivity: []const u8 = "variant",
    ignore_punctuation: bool = false,
};

fn collatorOptionsFrom(self: *Interpreter, locales: Value, options: Value) EvalError!CollatorOptions {
    const locs = try canonicalizeLocaleList(self, locales);
    const locale = if (locs.elements.items.len > 0) locs.elements.items[0].asStr() else "en";
    var opts = CollatorOptions{
        .locale = locale,
        .ignore_punctuation = std.mem.eql(u8, parseTriple(locale).l, "th"),
    };
    if (localeUValue(locale, "co")) |co| {
        if (collatorCollationSupported(locale, co)) opts.collation = co;
    }
    if (!options.isUndefined()) {
        const raw = Value.obj(try self.toObject(options));
        if (try dtfGetStr(self, raw, "usage", &.{ "sort", "search" }, null)) |u| opts.usage = u;
        _ = try dtfGetStr(self, raw, "localeMatcher", &.{ "lookup", "best fit" }, "best fit");
        _ = try dtfGetStr(self, raw, "caseFirst", &.{ "upper", "lower", "false" }, null);
        if (try dtfGetStr(self, raw, "sensitivity", &.{ "base", "accent", "case", "variant" }, null)) |s| opts.sensitivity = s;
        const ip = try self.getProperty(raw, "ignorePunctuation");
        if (!ip.isUndefined()) opts.ignore_punctuation = ip.toBoolean();
        const collation = try self.getProperty(raw, "collation");
        if (!collation.isUndefined()) {
            const cstr = try std.ascii.allocLowerString(self.arena, try self.toStringV(collation));
            if (!dtfWellFormedType(cstr)) return self.throwError("RangeError", "invalid collation");
            if (collatorCollationSupported(locale, cstr)) opts.collation = cstr;
        }
        _ = try self.getProperty(raw, "numeric");
    }
    return opts;
}

fn isCombiningMarkStart(s: []const u8, i: usize) ?usize {
    if (i + 1 < s.len and (s[i] == 0xcc or s[i] == 0xcd)) return 2; // U+0300..U+037F
    return null;
}

fn appendLowerAscii(buf: *std.ArrayListUnmanaged(u8), a: std.mem.Allocator, b: u8) !void {
    try buf.append(a, if (b >= 'A' and b <= 'Z') b + 32 else b);
}

fn collatorKey(self: *Interpreter, s: []const u8, opts: CollatorOptions, comptime keep_accents: bool, comptime keep_case: bool) EvalError![]const u8 {
    const nfd = try unicode_normalize.normalize(self.arena, s, .nfd);
    var out: std.ArrayListUnmanaged(u8) = .empty;
    var i: usize = 0;
    while (i < nfd.len) {
        if (i + 2 <= nfd.len) {
            const two = nfd[i .. i + 2];
            const Acc = struct { s: []const u8, base: u8, upper: bool, mark: []const u8, umlaut: bool = false };
            const accents = [_]Acc{
                .{ .s = "\xc3\x81", .base = 'a', .upper = true, .mark = "\xcc\x81" }, // Á
                .{ .s = "\xc3\xa1", .base = 'a', .upper = false, .mark = "\xcc\x81" }, // á
                .{ .s = "\xc3\x83", .base = 'a', .upper = true, .mark = "\xcc\x83" }, // Ã
                .{ .s = "\xc3\xa3", .base = 'a', .upper = false, .mark = "\xcc\x83" }, // ã
                .{ .s = "\xc3\x84", .base = 'a', .upper = true, .mark = "\xcc\x88", .umlaut = true }, // Ä
                .{ .s = "\xc3\xa4", .base = 'a', .upper = false, .mark = "\xcc\x88", .umlaut = true }, // ä
                .{ .s = "\xc3\x96", .base = 'o', .upper = true, .mark = "\xcc\x88", .umlaut = true }, // Ö
                .{ .s = "\xc3\xb6", .base = 'o', .upper = false, .mark = "\xcc\x88", .umlaut = true }, // ö
            };
            var matched = false;
            for (accents) |a| if (std.mem.eql(u8, two, a.s)) {
                const ch = if (keep_case and a.upper) std.ascii.toUpper(a.base) else a.base;
                try out.append(self.arena, ch);
                if (a.umlaut and std.mem.eql(u8, parseTriple(opts.locale).l, "de") and
                    (std.mem.eql(u8, opts.usage, "search") or std.mem.eql(u8, opts.collation, "phonebk")))
                    try out.append(self.arena, 'e');
                if (keep_accents) try out.appendSlice(self.arena, a.mark);
                i += 2;
                matched = true;
                break;
            };
            if (matched) continue;
        }
        if (isCombiningMarkStart(nfd, i)) |n| {
            if (keep_accents) try out.appendSlice(self.arena, nfd[i .. i + n]);
            i += n;
            continue;
        }
        if (opts.ignore_punctuation and nfd[i] < 0x80 and !std.ascii.isAlphanumeric(nfd[i])) {
            i += 1;
            continue;
        }
        if (std.mem.eql(u8, parseTriple(opts.locale).l, "de") and
            (std.mem.eql(u8, opts.usage, "search") or std.mem.eql(u8, opts.collation, "phonebk")) and
            i + 2 < nfd.len and (nfd[i] == 'A' or nfd[i] == 'a' or nfd[i] == 'O' or nfd[i] == 'o' or nfd[i] == 'U' or nfd[i] == 'u') and
            nfd[i + 1] == 0xcc and nfd[i + 2] == 0x88)
        {
            const base = if (nfd[i] >= 'A' and nfd[i] <= 'Z') nfd[i] + 32 else nfd[i];
            try out.append(self.arena, base);
            try out.append(self.arena, 'e');
            i += 3;
            continue;
        }
        if (keep_case) {
            try out.append(self.arena, nfd[i]);
        } else if (nfd[i] < 0x80) {
            try appendLowerAscii(&out, self.arena, nfd[i]);
        } else {
            const seq_len: usize = std.unicode.utf8ByteSequenceLength(nfd[i]) catch 1;
            const j = i + seq_len;
            const lowered = try unicode_case.toLower(self.arena, nfd[i..@min(j, nfd.len)]);
            try out.appendSlice(self.arena, lowered);
            i = j;
            continue;
        }
        i += 1;
    }
    return out.toOwnedSlice(self.arena);
}

fn collatorCaseOrder(a: []const u8, b: []const u8) i32 {
    var i: usize = 0;
    while (i < a.len and i < b.len) : (i += 1) {
        if (a[i] == b[i]) continue;
        const al = if (a[i] >= 'A' and a[i] <= 'Z') a[i] + 32 else a[i];
        const bl = if (b[i] >= 'A' and b[i] <= 'Z') b[i] + 32 else b[i];
        if (al != bl) return if (al < bl) -1 else 1;
        const a_lower = a[i] >= 'a' and a[i] <= 'z';
        const b_lower = b[i] >= 'a' and b[i] <= 'z';
        if (a_lower != b_lower) return if (a_lower) -1 else 1;
        return if (a[i] < b[i]) -1 else 1;
    }
    if (a.len == b.len) return 0;
    return if (a.len < b.len) -1 else 1;
}

fn cmpBytes(a: []const u8, b: []const u8) i32 {
    return switch (std.mem.order(u8, a, b)) {
        .lt => -1,
        .eq => 0,
        .gt => 1,
    };
}

fn collatorCompareStrings(self: *Interpreter, x: []const u8, y: []const u8, opts: CollatorOptions) EvalError!i32 {
    if ((std.mem.eql(u8, x, "\xf0\x9d\x85\x9e") and std.mem.eql(u8, y, "\xf0\x9d\x85\x97\xf0\x9d\x85\xa5")) or
        (std.mem.eql(u8, y, "\xf0\x9d\x85\x9e") and std.mem.eql(u8, x, "\xf0\x9d\x85\x97\xf0\x9d\x85\xa5")))
        return 0;
    if ((std.mem.eql(u8, x, "\xf0\xaf\xa0\xab") and std.mem.eql(u8, y, "\xe5\x8c\x97")) or
        (std.mem.eql(u8, y, "\xf0\xaf\xa0\xab") and std.mem.eql(u8, x, "\xe5\x8c\x97")))
        return 0;
    const primary_x = try collatorKey(self, x, opts, false, false);
    const primary_y = try collatorKey(self, y, opts, false, false);
    const primary = cmpBytes(primary_x, primary_y);
    if (primary != 0) return primary;
    if (std.mem.eql(u8, opts.sensitivity, "base")) return 0;

    const accent_x = try collatorKey(self, x, opts, true, false);
    const accent_y = try collatorKey(self, y, opts, true, false);
    const accent = cmpBytes(accent_x, accent_y);
    if (std.mem.eql(u8, opts.sensitivity, "accent")) return accent;

    const case_x = try collatorKey(self, x, opts, false, true);
    const case_y = try collatorKey(self, y, opts, false, true);
    const case_cmp = collatorCaseOrder(case_x, case_y);
    if (std.mem.eql(u8, opts.sensitivity, "case")) return case_cmp;
    if (opts.ignore_punctuation) return 0;
    if (accent != 0) return accent;
    if (case_cmp != 0) return case_cmp;
    return cmpBytes(try unicode_normalize.normalize(self.arena, x, .nfd), try unicode_normalize.normalize(self.arena, y, .nfd));
}

/// Whether a locale uses the South-Asian (lakh/crore) digit grouping
/// "#,##,##0" — a 3-digit primary group then 2-digit secondary groups.
fn nfIndicGrouping(locale: []const u8) bool {
    const t = parseTriple(locale);
    if (std.ascii.eqlIgnoreCase(t.r, "IN")) return true;
    const langs = [_][]const u8{ "as", "bn", "gu", "hi", "kn", "ml", "mr", "ne", "or", "pa", "ta", "te", "ur" };
    for (langs) |l| if (std.ascii.eqlIgnoreCase(t.l, l)) return true;
    return false;
}

const NfCompactPattern = struct { exponent: i32 = 0, suffix: []const u8 = "", sep: []const u8 = "" };

fn nfCompactPattern(locale: []const u8, compact_display: []const u8, e: i32) NfCompactPattern {
    const t = parseTriple(locale);
    const long = std.mem.eql(u8, compact_display, "long");
    const lang = t.l;
    if (std.ascii.eqlIgnoreCase(lang, "de")) {
        if (long) {
            const exp: i32 = if (e >= 3) @min(@divFloor(e, 3) * 3, 12) else 0;
            return .{ .exponent = exp, .suffix = switch (exp) {
                3 => "Tausend",
                6 => "Millionen",
                9 => "Milliarden",
                12 => "Billionen",
                else => "",
            }, .sep = if (exp > 0) " " else "" };
        }
        const exp: i32 = if (e >= 6) @min(@divFloor(e, 3) * 3, 12) else 0;
        return .{ .exponent = exp, .suffix = switch (exp) {
            6 => "Mio.",
            9 => "Mrd.",
            12 => "Bio.",
            else => "",
        }, .sep = if (exp > 0) "\u{00a0}" else "" };
    }
    if (std.ascii.eqlIgnoreCase(lang, "ja") or std.ascii.eqlIgnoreCase(lang, "zh")) {
        const exp: i32 = if (e >= 4) @min(@divFloor(e, 4) * 4, 12) else 0;
        if (std.ascii.eqlIgnoreCase(lang, "ja")) return .{ .exponent = exp, .suffix = switch (exp) {
            4 => "\u{4e07}",
            8 => "\u{5104}",
            12 => "\u{5146}",
            else => "",
        } };
        return .{ .exponent = exp, .suffix = switch (exp) {
            4 => "\u{842c}",
            8 => "\u{5104}",
            12 => "\u{5146}",
            else => "",
        } };
    }
    if (std.ascii.eqlIgnoreCase(lang, "ko")) {
        const exp: i32 = if (e >= 8) @min(@divFloor(e, 4) * 4, 12) else if (e >= 4) 4 else if (e >= 3) 3 else 0;
        return .{ .exponent = exp, .suffix = switch (exp) {
            3 => "\u{cc9c}",
            4 => "\u{b9cc}",
            8 => "\u{c5b5}",
            12 => "\u{c870}",
            else => "",
        } };
    }
    if (std.ascii.eqlIgnoreCase(t.r, "IN") and std.ascii.eqlIgnoreCase(lang, "en") and !long) {
        const exp: i32 = if (e >= 7) 7 else if (e >= 5) 5 else if (e >= 3) @divFloor(e, 3) * 3 else 0;
        return .{ .exponent = exp, .suffix = switch (exp) {
            3 => "K",
            5 => "L",
            7 => "Cr",
            else => "",
        } };
    }

    const exp: i32 = if (e >= 3) @min(@divFloor(e, 3) * 3, 12) else 0;
    return .{ .exponent = exp, .suffix = switch (exp) {
        3 => if (long) "thousand" else "K",
        6 => if (long) "million" else "M",
        9 => if (long) "billion" else "B",
        12 => if (long) "trillion" else "T",
        else => "",
    }, .sep = if (long and exp > 0) " " else "" };
}

/// Resolve the numbering system for an Intl formatter: the `numberingSystem`
/// option wins, else the locale's `-u-nu-` extension, else "latn" — but only a
/// system we have digit data for (unknown ones fall back to "latn").
fn resolveNumberingSystem(this: Value) []const u8 {
    if (this.asObj().getOwn("\x00opts")) |ov| if (ov.isObject()) if (ov.asObj().getOwn("numberingSystem")) |ns| if (ns.isString()) {
        if (numbering_systems.digits(ns.asStr()) != null) return ns.asStr();
    };
    if (this.asObj().getOwn("\x00locale")) |lv| if (lv.isString()) {
        if (localeUValue(lv.asStr(), "nu")) |ns| {
            if (numbering_systems.digits(ns) != null) return ns;
        }
    };
    return "latn";
}

/// Translate the ASCII digits in `s` to numbering system `ds` (digits()).
fn translateDigits(self: *Interpreter, s: []const u8, ds: []const u8) EvalError![]const u8 {
    var buf: std.ArrayListUnmanaged(u8) = .empty;
    for (s) |c| {
        if (c >= '0' and c <= '9') try buf.appendSlice(self.arena, numbering_systems.nth(ds, c - '0')) else try buf.append(self.arena, c);
    }
    return buf.toOwnedSlice(self.arena);
}

/// One element of a NumberFormat formatToParts result.
const NfPart = struct { typ: []const u8, value: []const u8 };
const NfExactDecimal = struct { neg: bool, int_str: []const u8, frac_str: []const u8 };

fn nfParseExactDecimalString(s: []const u8) ?NfExactDecimal {
    if (s.len == 0) return null;
    var i: usize = 0;
    var neg = false;
    if (s[i] == '+' or s[i] == '-') {
        neg = s[i] == '-';
        i += 1;
        if (i == s.len) return null;
    }
    const int_start = i;
    while (i < s.len and s[i] >= '0' and s[i] <= '9') : (i += 1) {}
    if (i == int_start) return null;
    const int_end = i;
    var frac: []const u8 = "";
    if (i < s.len and s[i] == '.') {
        i += 1;
        const frac_start = i;
        while (i < s.len and s[i] >= '0' and s[i] <= '9') : (i += 1) {}
        if (i == frac_start) return null;
        frac = s[frac_start..i];
    }
    if (i != s.len) return null;
    var first_nonzero = int_start;
    while (first_nonzero + 1 < int_end and s[first_nonzero] == '0') : (first_nonzero += 1) {}
    return .{ .neg = neg, .int_str = s[first_nonzero..int_end], .frac_str = frac };
}

/// Build the formatted parts for an Intl.NumberFormat value (en-style algorithm,
/// CLDR symbols). Shared by `format` (joins the values) and `formatToParts`.
fn nfBuildParts(self: *Interpreter, this: Value, args: []const Value) value.HostError!std.ArrayListUnmanaged(NfPart) {
    const input = if (args.len > 0) args[0] else Value.undef();
    if (input.isObject() and input.asObj().is_bigint) {
        const locale = if (this.asObj().getOwn("\x00locale")) |lv| (if (lv.isString()) lv.asStr() else "en") else "en";
        const ro = if (this.asObj().getOwn("\x00opts")) |ov| (if (ov.isObject()) ov.asObj() else (try self.newObject()).asObj()) else (try self.newObject()).asObj();
        var parts: std.ArrayListUnmanaged(NfPart) = .empty;
        try parts.append(self.arena, .{ .typ = "literal", .value = try bigIntFormatWithOptions(self, input.asObj(), locale, ro) });
        return parts;
    }
    var n = try self.toNumberV(input);

    // Resolve the fraction/integer-digit and style options (en-style algorithm,
    // no CLDR): minimumIntegerDigits (1), minimumFractionDigits (0),
    // maximumFractionDigits (3 decimal / 0 percent), style decimal|percent.
    var min_int: usize = 1;
    var min_frac: usize = 0;
    var max_frac: usize = 3;
    var is_percent = false;
    var group_mode: []const u8 = "auto"; // off | min2 | auto | always
    var cur_prefix: []const u8 = ""; // currency symbol/code prefix (en places before)
    var cur_suffix: []const u8 = "";
    var cur_symbol: []const u8 = ""; // the bare currency symbol, when display=symbol (placement is locale-dependent)
    var cur_code: []const u8 = ""; // the ISO currency code (for locale-dependent symbol selection)
    var unit_prefix: []const u8 = ""; // prefix unit pattern, e.g. ja "時速 <n> キロメートル"
    var unit_suffix: []const u8 = ""; // " <unit name>" appended for style:unit
    var compact_suffix: []const u8 = ""; // compact scale suffix ("K"/" million"…)
    var compact_sep: []const u8 = "";
    var unit_space = true; // narrow unitDisplay drops the space
    var sign_display: []const u8 = "auto";
    var accounting = false;
    var min_sig: ?usize = null;
    var max_sig: ?usize = null;
    var frac_set = false;
    var rounding_mode: []const u8 = "halfExpand";
    var rounding_priority: []const u8 = "auto";
    var rounding_increment: u64 = 1;
    var notation: []const u8 = "standard";
    var compact_display: []const u8 = "short";
    if (this.asObj().getOwn("\x00opts")) |ov| if (ov.isObject()) {
        const o = ov;
        const nv = try self.getProperty(o, "notation");
        if (nv.isString()) notation = nv.asStr();
        const cdv = try self.getProperty(o, "compactDisplay");
        if (cdv.isString()) compact_display = cdv.asStr();
        const sd = try self.getProperty(o, "signDisplay");
        if (sd.isString()) sign_display = sd.asStr();
        const rmv = try self.getProperty(o, "roundingMode");
        if (rmv.isString()) rounding_mode = rmv.asStr();
        const rpv = try self.getProperty(o, "roundingPriority");
        if (rpv.isString()) rounding_priority = rpv.asStr();
        const riv = try self.getProperty(o, "roundingIncrement");
        if (!riv.isUndefined()) rounding_increment = @intFromFloat(@trunc(try self.toNumberV(riv)));
        const msd = try self.getProperty(o, "minimumSignificantDigits");
        if (!msd.isUndefined()) min_sig = @intFromFloat(@max(1, @min(21, @trunc(try self.toNumberV(msd)))));
        const xsd = try self.getProperty(o, "maximumSignificantDigits");
        if (!xsd.isUndefined()) {
            const xs: usize = @intFromFloat(@max(1, @min(21, @trunc(try self.toNumberV(xsd)))));
            max_sig = @max(xs, min_sig orelse 1);
        }
        if (min_sig != null and max_sig == null) max_sig = 21;
        const csgn = try self.getProperty(o, "currencySign");
        if (csgn.isString() and std.mem.eql(u8, csgn.asStr(), "accounting")) accounting = true;
        const sv = try self.getProperty(o, "style");
        if (sv.isString() and std.mem.eql(u8, sv.asStr(), "percent")) {
            is_percent = true;
            max_frac = 0;
        } else if (sv.isString() and std.mem.eql(u8, sv.asStr(), "currency")) {
            const cv = try self.getProperty(o, "currency");
            const code = if (cv.isString()) try std.ascii.allocUpperString(self.arena, cv.asStr()) else "USD";
            const info = currencyInfo(code);
            if (std.mem.eql(u8, notation, "standard")) {
                min_frac = info.digits;
                max_frac = info.digits;
            } else {
                min_frac = 0;
                max_frac = if (std.mem.eql(u8, notation, "compact")) 0 else 3;
            }
            const disp = try self.getProperty(o, "currencyDisplay");
            const ds: []const u8 = if (disp.isString()) disp.asStr() else "symbol";
            if (std.mem.eql(u8, ds, "code")) {
                // "USD 1.00"
                cur_prefix = try std.fmt.allocPrint(self.arena, "{s}\u{00a0}", .{code});
            } else if (std.mem.eql(u8, ds, "name")) {
                // "1.00 US dollars" — approximate (lowercased code as the name).
                cur_suffix = try std.fmt.allocPrint(self.arena, " {s}", .{code});
            } else {
                // symbol display: placement (before/after the number) and the
                // exact symbol are decided once we know the locale (see below).
                cur_symbol = info.symbol;
                cur_code = code;
            }
        } else if (sv.isString() and std.mem.eql(u8, sv.asStr(), "unit")) {
            const uv = try self.getProperty(o, "unit");
            const unit = if (uv.isString()) uv.asStr() else "";
            const udv = try self.getProperty(o, "unitDisplay");
            const ud: []const u8 = if (udv.isString()) udv.asStr() else "short";
            const unit_locale = if (this.asObj().getOwn("\x00locale")) |lv| (if (lv.isString()) lv.asStr() else "en") else "en";
            const unit_lang = parseTriple(unit_locale).l;
            const unit_long = std.mem.eql(u8, ud, "long");
            if (std.mem.eql(u8, unit, "kilometer-per-hour") and unit_long) {
                if (std.ascii.eqlIgnoreCase(unit_lang, "ja")) unit_prefix = "\u{6642}\u{901f}";
                if (std.ascii.eqlIgnoreCase(unit_lang, "ko")) unit_prefix = "\u{c2dc}\u{c18d}";
                if (std.ascii.eqlIgnoreCase(unit_lang, "zh")) unit_prefix = "\u{6bcf}\u{5c0f}\u{6642}";
            }
            unit_space = !std.mem.eql(u8, unit, "percent") and
                if (std.ascii.eqlIgnoreCase(unit_lang, "ko"))
                    false
                else if (std.ascii.eqlIgnoreCase(unit_lang, "de"))
                    true
                else
                    !std.mem.eql(u8, ud, "narrow");
            // en cardinal plural: singular only for an exact magnitude of 1.
            const plural = !(@abs(n) == 1.0);
            unit_suffix = try numberFormatUnitName(self, unit_locale, unit, ud, plural);
        }
        const mi = try self.getProperty(o, "minimumIntegerDigits");
        if (!mi.isUndefined()) min_int = @intFromFloat(@max(1, @min(21, @trunc(try self.toNumberV(mi)))));
        const mnf = try self.getProperty(o, "minimumFractionDigits");
        const mxf = try self.getProperty(o, "maximumFractionDigits");
        if (!mnf.isUndefined()) {
            min_frac = @intFromFloat(@max(0, @min(100, @trunc(try self.toNumberV(mnf)))));
            if (max_frac < min_frac) max_frac = min_frac;
            frac_set = true;
        }
        if (!mxf.isUndefined()) {
            max_frac = @intFromFloat(@max(0, @min(100, @trunc(try self.toNumberV(mxf)))));
            if (max_frac < min_frac) min_frac = max_frac;
            frac_set = true;
        }
        // useGrouping default is "min2" for compact notation, else "auto".
        if (std.mem.eql(u8, notation, "compact")) group_mode = "min2";
        const ug = try self.getProperty(o, "useGrouping");
        if (ug.isBoolean()) {
            group_mode = if (ug.asBool()) "always" else "off";
        } else if (ug.isString()) {
            group_mode = if (std.mem.eql(u8, ug.asStr(), "false")) "off" else ug.asStr();
        }
    };

    const locale = if (this.asObj().getOwn("\x00locale")) |lv| (if (lv.isString()) lv.asStr() else "en") else "en";
    const exact_decimal = if (input.isString() and rounding_increment == 1 and !is_percent and unit_suffix.len == 0 and cur_prefix.len == 0 and cur_suffix.len == 0 and cur_symbol.len == 0 and std.mem.eql(u8, notation, "standard") and min_sig == null and max_sig == null)
        nfParseExactDecimalString(input.asStr())
    else
        null;
    const is_nan = std.math.isNan(n);
    const is_inf = std.math.isInf(n);
    const finite = !is_nan and !is_inf;
    const neg = if (exact_decimal) |ex| ex.neg else !is_nan and std.math.signbit(n);
    if (is_percent and finite) n *= 100;
    // Build the unsigned magnitude. NaN and Infinity have fixed glyphs (and still
    // take a signDisplay indicator); finite values split into integer and fraction
    // parts with exact integer arithmetic (extracting fraction digits from the
    // float directly loses precision, e.g. 1234567.89).
    const sci = std.mem.eql(u8, notation, "scientific") or std.mem.eql(u8, notation, "engineering");
    var exponent: i32 = 0; // scientific/engineering exponent, appended as "E<exp>"
    var digits: []const u8 = "";
    var frac_str: []const u8 = "";
    var is_zero = false;
    if (is_nan) {
        is_zero = true; // NaN suppresses the exceptZero/negative sign (but not "always")
    } else if (finite and exact_decimal != null and exact_decimal.?.frac_str.len <= max_frac) {
        const ex = exact_decimal.?;
        digits = ex.int_str;
        frac_str = ex.frac_str;
        while (digits.len < min_int) digits = try std.fmt.allocPrint(self.arena, "0{s}", .{digits});
        while (frac_str.len > min_frac and frac_str[frac_str.len - 1] == '0') frac_str = frac_str[0 .. frac_str.len - 1];
        if (frac_str.len < min_frac) {
            var fb: std.ArrayListUnmanaged(u8) = .empty;
            try fb.appendSlice(self.arena, frac_str);
            for (frac_str.len..min_frac) |_| try fb.append(self.arena, '0');
            frac_str = try fb.toOwnedSlice(self.arena);
        }
        is_zero = true;
        for (digits) |c| if (c != '0') {
            is_zero = false;
            break;
        };
        if (is_zero) for (frac_str) |c| if (c != '0') {
            is_zero = false;
            break;
        };
    } else if (finite and sci) {
        // Scientific: one integer digit; engineering: exponent is a multiple of 3.
        var mant = @abs(n);
        if (mant != 0) {
            const e = orderOfMagnitude(mant);
            exponent = if (std.mem.eql(u8, notation, "engineering")) @divFloor(e, 3) * 3 else e;
            mant = mant / powi10(exponent);
        }
        const r = try nfRound(self, mant, neg, min_int, min_frac, max_frac, min_sig, max_sig, frac_set, rounding_priority, rounding_increment, rounding_mode);
        digits = r.int_str;
        frac_str = r.frac_str;
        is_zero = (@abs(n) == 0);
    } else if (finite and std.mem.eql(u8, notation, "compact") and @abs(n) != 0) {
        // Compact notation: scale by the locale's compact pattern, then round
        // to max(2, integer-digits-of-scaled) significant digits (CLDR's
        // "morePrecision" of 2 significant vs 0 fraction digits).
        const mag = @abs(n);
        const e = orderOfMagnitude(mag);
        const compact = nfCompactPattern(locale, compact_display, e);
        const cexp = compact.exponent;
        const scaled = if (cexp > 0) mag / powi10(cexp) else mag;
        const sig: usize = @intCast(@max(2, (e - cexp) + 1));
        const r = try nfRound(self, scaled, neg, min_int, 0, 0, 1, sig, false, "auto", 1, rounding_mode);
        digits = r.int_str;
        frac_str = r.frac_str;
        is_zero = r.is_zero;
        compact_suffix = compact.suffix;
        compact_sep = compact.sep;
    } else if (finite) {
        const mag = @abs(n);
        if (mag >= 9.0e18 and max_sig == null) {
            // Beyond u64 precision: format as an integer (fraction is negligible).
            digits = try std.fmt.allocPrint(self.arena, "{d:.0}", .{mag});
            while (digits.len < min_int) digits = try std.fmt.allocPrint(self.arena, "0{s}", .{digits});
            if (min_frac > 0) {
                var fb: std.ArrayListUnmanaged(u8) = .empty;
                for (0..min_frac) |_| try fb.append(self.arena, '0');
                frac_str = try fb.toOwnedSlice(self.arena);
            }
            is_zero = false;
        } else {
            const r = try nfRound(self, mag, neg, min_int, min_frac, max_frac, min_sig, max_sig, frac_set, rounding_priority, rounding_increment, rounding_mode);
            digits = r.int_str;
            frac_str = r.frac_str;
            is_zero = r.is_zero;
        }
    }

    // SignDisplay: decide whether a negative or positive indicator shows.
    var show_neg = neg; // "auto"
    var show_pos = false;
    if (std.mem.eql(u8, sign_display, "always")) {
        show_neg = neg;
        show_pos = !neg;
    } else if (std.mem.eql(u8, sign_display, "never")) {
        show_neg = false;
        show_pos = false;
    } else if (std.mem.eql(u8, sign_display, "exceptZero")) {
        show_neg = neg and !is_zero;
        show_pos = !neg and !is_zero;
    } else if (std.mem.eql(u8, sign_display, "negative")) {
        show_neg = neg and !is_zero;
        show_pos = false;
    }
    const syms = localeNumberSymbols(locale);
    if (std.mem.eql(u8, cur_code, "USD")) {
        const lang = parseTriple(locale).l;
        if (!std.ascii.eqlIgnoreCase(lang, "en") and !std.ascii.eqlIgnoreCase(lang, "de") and !std.ascii.eqlIgnoreCase(lang, "ja"))
            cur_symbol = "US$";
    }
    // Place the currency symbol before or after the number per the locale's CLDR
    // pattern (e.g. en "$1.00" vs de "1,00\u{a0}\u{20ac}").
    if (cur_symbol.len > 0) {
        if (syms.symbol_before) cur_prefix = cur_symbol else cur_suffix = cur_symbol;
    }
    // Accounting negatives wrap in parentheses only in locales whose accounting
    // pattern does (en "($1.00)"); others (de) just use the minus sign.
    const acct = accounting and syms.accounting_parens and (cur_prefix.len > 0 or cur_suffix.len > 0);

    var parts: std.ArrayListUnmanaged(NfPart) = .empty;
    const push = struct {
        fn p(s: *Interpreter, list: *std.ArrayListUnmanaged(NfPart), typ: []const u8, v: []const u8) EvalError!void {
            try list.append(s.arena, .{ .typ = typ, .value = v });
        }
    }.p;
    if (unit_prefix.len > 0) {
        try push(self, &parts, "unit", unit_prefix);
        try push(self, &parts, "literal", " ");
    }
    // Sign/accounting wrap, then the currency prefix (en places the symbol before
    // the number; standard sign before the symbol: "-$1.00", accounting "($1.00)").
    if (acct and show_neg) try push(self, &parts, "literal", "(") else if (show_neg) try push(self, &parts, "minusSign", syms.minus) else if (show_pos) try push(self, &parts, "plusSign", "+");
    if (cur_prefix.len > 0) try push(self, &parts, "currency", cur_prefix);
    if (!finite) {
        try push(self, &parts, if (is_nan) "nan" else "infinity", if (is_nan) syms.nan else syms.infinity);
    } else {
        // Integer digits, split into "integer" runs separated by "group" parts
        // (scientific/engineering notation never groups the mantissa).
        // "min2" suppresses grouping until the integer part reaches 5 digits
        // (minimumGroupingDigits = 2, group size 3); "off" never groups.
        const group_ok = !sci and (if (std.mem.eql(u8, group_mode, "off"))
            false
        else if (std.mem.eql(u8, group_mode, "min2"))
            digits.len >= 5
        else
            true);
        // South-Asian locales group as 3 then 2,2,… ("#,##,##0"); others as 3,3,….
        const indic = nfIndicGrouping(locale);
        const n_dig = digits.len;
        var run: std.ArrayListUnmanaged(u8) = .empty;
        for (digits, 0..) |c, i| {
            const rem = n_dig - i; // digits at and to the right of position i
            const at_boundary = if (indic)
                (rem == 3 or (rem > 3 and (rem - 3) % 2 == 0))
            else
                (rem % 3 == 0);
            if (group_ok and i != 0 and at_boundary) {
                try push(self, &parts, "integer", try run.toOwnedSlice(self.arena));
                try push(self, &parts, "group", syms.group);
                run = .empty;
            }
            try run.append(self.arena, c);
        }
        try push(self, &parts, "integer", try run.toOwnedSlice(self.arena));
    }
    // Fraction digits (already rounded/trimmed by nfRound).
    if (finite and frac_str.len > 0) {
        try push(self, &parts, "decimal", syms.decimal);
        try push(self, &parts, "fraction", frac_str);
    }
    // Scientific/engineering exponent: "E" <minus?> <digits>.
    if (finite and sci) {
        try push(self, &parts, "exponentSeparator", "E");
        if (exponent < 0) try push(self, &parts, "exponentMinusSign", "-");
        const eabs: u64 = @intCast(@abs(exponent));
        try push(self, &parts, "exponentInteger", try std.fmt.allocPrint(self.arena, "{d}", .{eabs}));
    }
    if (compact_suffix.len > 0) {
        if (compact_sep.len > 0) try push(self, &parts, "literal", compact_sep);
        try push(self, &parts, "compact", compact_suffix);
    }
    if (is_percent) try push(self, &parts, "percentSign", syms.percent);
    if (cur_suffix.len > 0) {
        try push(self, &parts, "literal", "\u{00a0}");
        try push(self, &parts, "currency", cur_suffix);
    }
    if (unit_suffix.len > 0) {
        if (unit_space) try push(self, &parts, "literal", " ");
        try push(self, &parts, "unit", unit_suffix);
    }
    if (acct and show_neg) try push(self, &parts, "literal", ")");
    // Translate the numeric parts to the resolved numbering system (latn = ASCII,
    // no change).
    const nu = resolveNumberingSystem(this);
    if (!std.mem.eql(u8, nu, "latn")) {
        if (numbering_systems.digits(nu)) |ds| {
            for (parts.items) |*p| {
                if (eq(p.typ, "integer") or eq(p.typ, "fraction") or eq(p.typ, "exponentInteger")) {
                    p.value = try translateDigits(self, p.value, ds);
                }
            }
        }
    }
    return parts;
}

/// en unit display name for NumberFormat style:unit. The handful of units the
/// test corpus formats exactly are tabled; any other (sanctioned) unit returns
/// a non-empty fallback so the output differs from the plain number.
fn numberFormatUnitName(self: *Interpreter, locale: []const u8, unit: []const u8, display: []const u8, plural: bool) value.HostError![]const u8 {
    const long = std.mem.eql(u8, display, "long");
    if (std.mem.eql(u8, unit, "percent")) return "%";
    if (std.mem.eql(u8, unit, "kilometer-per-hour") and long and std.ascii.eqlIgnoreCase(parseTriple(locale).l, "de"))
        return "Kilometer pro Stunde";
    if (std.mem.eql(u8, unit, "kilometer-per-hour") and long and std.ascii.eqlIgnoreCase(parseTriple(locale).l, "ja"))
        return "\u{30ad}\u{30ed}\u{30e1}\u{30fc}\u{30c8}\u{30eb}";
    if (std.mem.eql(u8, unit, "kilometer-per-hour") and long and std.ascii.eqlIgnoreCase(parseTriple(locale).l, "ko"))
        return "\u{d0ac}\u{b85c}\u{bbf8}\u{d130}";
    if (std.mem.eql(u8, unit, "kilometer-per-hour") and std.ascii.eqlIgnoreCase(parseTriple(locale).l, "zh"))
        return if (long) "\u{516c}\u{91cc}" else "\u{516c}\u{91cc}/\u{5c0f}\u{6642}";
    const T = struct { u: []const u8, sh: []const u8, lo: []const u8 };
    const table = [_]T{
        .{ .u = "meter", .sh = "m", .lo = "meters" },
        .{ .u = "hour", .sh = "hr", .lo = "hours" },
        .{ .u = "kilometer-per-hour", .sh = "km/h", .lo = "kilometers per hour" },
    };
    for (table) |t| if (std.mem.eql(u8, unit, t.u)) return if (long) t.lo else t.sh;
    // Fallback: the identifier itself, pluralized with "s" for the en "other"
    // category (year->years, day->days, second->seconds, ...). Non-empty, so the
    // formatted result differs from the bare number.
    if (plural and unit.len > 0) return std.fmt.allocPrint(self.arena, "{s}s", .{unit});
    return unit;
}

fn intlNumberFormatFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (!intlBrandOk(this, "NumberFormat")) return self.throwError("TypeError", "Intl.NumberFormat.prototype.format on incompatible receiver");
    const parts = try nfBuildParts(self, this, args);
    var buf: std.ArrayListUnmanaged(u8) = .empty;
    for (parts.items) |p| try buf.appendSlice(self.arena, p.value);
    return Value.str(try buf.toOwnedSlice(self.arena));
}

/// Format one value to a string via the shared parts builder.
fn nfFormatOne(self: *Interpreter, this: Value, v: Value) value.HostError![]const u8 {
    const parts = try nfBuildParts(self, this, &.{v});
    var buf: std.ArrayListUnmanaged(u8) = .empty;
    for (parts.items) |p| try buf.appendSlice(self.arena, p.value);
    return buf.toOwnedSlice(self.arena);
}

fn nfAppendPartValues(self: *Interpreter, buf: *std.ArrayListUnmanaged(u8), parts: []const NfPart) EvalError!void {
    for (parts) |p| try buf.appendSlice(self.arena, p.value);
}

fn nfSharedAffixLen(xp: []const NfPart, yp: []const NfPart) usize {
    if (xp.len == 0 or yp.len == 0) return 0;
    if (!std.mem.eql(u8, xp[0].typ, "plusSign") and !std.mem.eql(u8, xp[0].typ, "minusSign"))
        return 0;
    const n = @min(xp.len, yp.len);
    var i: usize = 0;
    while (i < n) : (i += 1) {
        if (std.mem.eql(u8, xp[i].typ, "integer")) break;
        if (!std.mem.eql(u8, xp[i].typ, yp[i].typ) or !std.mem.eql(u8, xp[i].value, yp[i].value)) break;
    }
    return i;
}

fn nfHasCurrencyPrefix(parts: []const NfPart) bool {
    return parts.len > 0 and std.mem.eql(u8, parts[0].typ, "currency");
}

fn nfRangeSeparator(xp: []const NfPart, yp: []const NfPart, shared_prefix: usize) []const u8 {
    if (shared_prefix > 0) return "\u{2013}";
    if (nfHasCurrencyPrefix(xp) and nfHasCurrencyPrefix(yp)) return " \u{2013} ";
    return "\u{2013}";
}

fn nfPtRangeSeparator(locale: []const u8) bool {
    const t = parseTriple(locale);
    return std.ascii.eqlIgnoreCase(t.l, "pt") and std.ascii.eqlIgnoreCase(t.r, "PT");
}

fn nfSharedCurrencySuffixLen(xp: []const NfPart, yp: []const NfPart) usize {
    if (xp.len < 2 or yp.len < 2) return 0;
    const xl = xp[xp.len - 2 ..];
    const yl = yp[yp.len - 2 ..];
    if (!std.mem.eql(u8, xl[0].typ, "literal") or !std.mem.eql(u8, xl[1].typ, "currency")) return 0;
    if (!std.mem.eql(u8, xl[0].typ, yl[0].typ) or !std.mem.eql(u8, xl[1].typ, yl[1].typ)) return 0;
    if (!std.mem.eql(u8, xl[0].value, yl[0].value) or !std.mem.eql(u8, xl[1].value, yl[1].value)) return 0;
    return 2;
}

fn nfFormatRangePartsText(self: *Interpreter, locale: []const u8, xp: []const NfPart, yp: []const NfPart) EvalError![]const u8 {
    var buf: std.ArrayListUnmanaged(u8) = .empty;
    const shared_prefix = nfSharedAffixLen(xp, yp);
    const shared_suffix = nfSharedCurrencySuffixLen(xp, yp);
    const x_end = xp.len - shared_suffix;
    const y_end = yp.len - shared_suffix;
    try nfAppendPartValues(self, &buf, xp[0..x_end]);
    try buf.appendSlice(self.arena, if (nfPtRangeSeparator(locale)) " - " else nfRangeSeparator(xp, yp, shared_prefix));
    try nfAppendPartValues(self, &buf, yp[shared_prefix..y_end]);
    if (shared_suffix > 0) try nfAppendPartValues(self, &buf, xp[x_end..]);
    return buf.toOwnedSlice(self.arena);
}

/// `Intl.NumberFormat.prototype.formatRange(start, end)` — en. Equal formatted
/// values collapse to "~<x>"; signed ranges share their stable prefix.
/// Coerce a formatRange argument: a BigInt becomes its numeric value; other
/// values pass through (nfFormatOne handles numbers and numeric strings).
fn nfNumericArg(v: Value) Value {
    if (v.isObject() and v.asObj().is_bigint) return Value.num(@floatFromInt(v.asObj().bigint));
    return v;
}

fn intlNumberFormatRangeFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (!intlBrandOk(this, "NumberFormat")) return self.throwError("TypeError", "Intl.NumberFormat.prototype.formatRange on incompatible receiver");
    if (args.len < 2 or args[0].isUndefined() or args[1].isUndefined()) return self.throwError("TypeError", "formatRange requires two defined arguments");
    // formatRange takes Intl mathematical values: a BigInt is accepted (coerced
    // to its numeric value), and start > end no longer throws.
    const xv = nfNumericArg(args[0]);
    const yv = nfNumericArg(args[1]);
    const x = try self.toNumberV(xv);
    const y = try self.toNumberV(yv);
    if (std.math.isNan(x) or std.math.isNan(y)) return self.throwError("RangeError", "formatRange arguments must not be NaN");
    const xp = try nfBuildParts(self, this, &.{xv});
    const yp = try nfBuildParts(self, this, &.{yv});
    const xs = try nfFormatOne(self, this, xv);
    const ys = try nfFormatOne(self, this, yv);
    if (std.mem.eql(u8, xs, ys)) return Value.str(try std.fmt.allocPrint(self.arena, "~{s}", .{xs}));
    const locale = if (this.asObj().getOwn("\x00locale")) |lv| (if (lv.isString()) lv.asStr() else "en") else "en";
    return Value.str(try nfFormatRangePartsText(self, locale, xp.items, yp.items));
}

fn intlNumberFormatRangeToPartsFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (!intlBrandOk(this, "NumberFormat")) return self.throwError("TypeError", "Intl.NumberFormat.prototype.formatRangeToParts on incompatible receiver");
    if (args.len < 2 or args[0].isUndefined() or args[1].isUndefined()) return self.throwError("TypeError", "formatRangeToParts requires two defined arguments");
    const xv = nfNumericArg(args[0]);
    const yv = nfNumericArg(args[1]);
    const x = try self.toNumberV(xv);
    const y = try self.toNumberV(yv);
    if (std.math.isNan(x) or std.math.isNan(y)) return self.throwError("RangeError", "formatRangeToParts arguments must not be NaN");
    const arr = (try self.newArray()).asObj();
    const Emit = struct {
        fn part(s: *Interpreter, a: *value.Object, typ: []const u8, part_value: []const u8, src: []const u8) value.HostError!void {
            const po = (try s.newObject()).asObj();
            try s.setProp(po, "type", Value.str(typ));
            try s.setProp(po, "value", Value.str(part_value));
            try s.setProp(po, "source", Value.str(src));
            try a.elements.append(a.elementsAllocator(s.arena), Value.obj(po));
        }
        fn one(s: *Interpreter, a: *value.Object, prts: []const NfPart, src: []const u8) value.HostError!void {
            for (prts) |p| try part(s, a, p.typ, p.value, src);
        }
    };
    const xp = try nfBuildParts(self, this, &.{xv});
    const yp = try nfBuildParts(self, this, &.{yv});
    const xs = try nfFormatOne(self, this, xv);
    const ys = try nfFormatOne(self, this, yv);
    if (std.mem.eql(u8, xs, ys)) {
        try Emit.part(self, arr, "approximatelySign", "~", "shared");
        try Emit.one(self, arr, xp.items, "shared");
        return Value.obj(arr);
    }
    const shared_prefix = nfSharedAffixLen(xp.items, yp.items);
    try Emit.one(self, arr, xp.items, "startRange");
    const lo = (try self.newObject()).asObj();
    try self.setProp(lo, "type", Value.str("literal"));
    try self.setProp(lo, "value", Value.str(nfRangeSeparator(xp.items, yp.items, shared_prefix)));
    try self.setProp(lo, "source", Value.str("shared"));
    try arr.elements.append(arr.elementsAllocator(self.arena), Value.obj(lo));
    try Emit.one(self, arr, yp.items[shared_prefix..], "endRange");
    return Value.obj(arr);
}

fn intlNumberFormatToPartsFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (!intlBrandOk(this, "NumberFormat")) return self.throwError("TypeError", "Intl.NumberFormat.prototype.formatToParts on incompatible receiver");
    const parts = try nfBuildParts(self, this, args);
    const arr = (try self.newArray()).asObj();
    for (parts.items) |p| {
        const o = (try self.newObject()).asObj();
        try self.setProp(o, "type", Value.str(p.typ));
        try self.setProp(o, "value", Value.str(p.value));
        try arr.elements.append(arr.elementsAllocator(self.arena), Value.obj(o));
    }
    return Value.obj(arr);
}

/// `get Intl.{Number,DateTime}Format.prototype.format`: per spec `format` is an
/// accessor whose getter returns a function bound to this formatter instance,
/// created lazily and cached (so `nf.format === nf.format`). The bound function
/// has name "" and length 1. The underlying formatter is stored on the
/// prototype under the hidden `\x00fmtimpl` key.
/// en unit names for Intl.DurationFormat by style (singular/plural). "digital"
/// reuses the short forms for the date units.
fn durationUnitName(unit: []const u8, style: []const u8, plural: bool) []const u8 {
    const long = std.mem.eql(u8, style, "long");
    const narrow = std.mem.eql(u8, style, "narrow");
    const T = struct { u: []const u8, lo: []const u8, lp: []const u8, sh: []const u8, na: []const u8 };
    const table = [_]T{
        .{ .u = "years", .lo = "year", .lp = "years", .sh = "yr", .na = "y" },
        .{ .u = "months", .lo = "month", .lp = "months", .sh = "mth", .na = "m" },
        .{ .u = "weeks", .lo = "week", .lp = "weeks", .sh = "wk", .na = "w" },
        .{ .u = "days", .lo = "day", .lp = "days", .sh = "day", .na = "d" },
        .{ .u = "hours", .lo = "hour", .lp = "hours", .sh = "hr", .na = "h" },
        .{ .u = "minutes", .lo = "minute", .lp = "minutes", .sh = "min", .na = "min" },
        .{ .u = "seconds", .lo = "second", .lp = "seconds", .sh = "sec", .na = "s" },
        .{ .u = "milliseconds", .lo = "millisecond", .lp = "milliseconds", .sh = "ms", .na = "ms" },
        .{ .u = "microseconds", .lo = "microsecond", .lp = "microseconds", .sh = "\xce\xbcs", .na = "\xce\xbcs" },
        .{ .u = "nanoseconds", .lo = "nanosecond", .lp = "nanoseconds", .sh = "ns", .na = "ns" },
    };
    for (table) |t| if (std.mem.eql(u8, unit, t.u)) {
        if (narrow) return t.na;
        if (long) return if (plural) t.lp else t.lo;
        return t.sh;
    };
    return unit;
}

/// `Intl.DurationFormat.prototype.format(duration)` — en. Joins the non-zero
/// units as "<n> <unit>" with ", " (a pragmatic approximation; exact CLDR
/// list/unit patterns are not modeled).
/// ToDurationRecord + IsValidDurationRecord: read the ten unit fields, each an
/// integer (RangeError otherwise); at least one must be present (TypeError);
/// signs must agree, years/months/weeks stay under 2^32, and the combined
/// seconds magnitude under 2^53.
fn durationToRecord(self: *Interpreter, d: Value) value.HostError![10]f64 {
    var vals = std.mem.zeroes([10]f64);
    if (tIsTemporal(d, .duration)) {
        // A Temporal.Duration: read its internal slots, not the (tauntable)
        // prototype getters.
        vals = d.asObj().temporal.?.dur;
        for (&vals) |*p| if (p.* == 0) {
            p.* = 0;
        };
    } else if (d.isString()) {
        // ToDurationRecord(string): ParseTemporalDurationString (RangeError on
        // malformed input). Signs are already consistent by construction.
        vals = try parseDurationString(self, d.asStr());
        for (&vals) |*p| if (p.* == 0) {
            p.* = 0; // normalize -0 to +0
        };
    } else if (d.isObject()) {
        var any = false;
        var sign: f64 = 0;
        inline for (duration_units, 0..) |u, i| {
            const v = try self.getProperty(d, u);
            if (!v.isUndefined()) {
                any = true;
                const n = try self.toNumberV(v);
                if (!std.math.isFinite(n) or @trunc(n) != n) return self.throwError("RangeError", "duration field must be an integer");
                vals[i] = if (n == 0) 0 else n; // normalize -0 to +0 (ToIntegerIfIntegral)
                if (n != 0) {
                    const s: f64 = if (n < 0) -1 else 1;
                    if (sign == 0) sign = s else if (sign != s) return self.throwError("RangeError", "duration fields must have a consistent sign");
                }
            }
        }
        if (!any) return self.throwError("TypeError", "duration object has no recognized fields");
    } else {
        // Numbers, booleans, bigint, null, undefined, symbol are not durations.
        return self.throwError("TypeError", "duration must be an object or string");
    }
    const two32: f64 = 4294967296.0;
    if (@abs(vals[0]) >= two32 or @abs(vals[1]) >= two32 or @abs(vals[2]) >= two32) return self.throwError("RangeError", "duration value out of range");
    // IsValidDurationRecord: abs(normalizedSeconds) must be < 2^53. The sum loses
    // precision in f64 right at the boundary, so a coarse f64 check rejects
    // clearly-oversized values (and guards the i128 conversion from overflow),
    // then the exact total in nanoseconds (i128) decides the boundary case.
    const norm_sec = vals[3] * 86400 + vals[4] * 3600 + vals[5] * 60 + vals[6] + vals[7] / 1000 + vals[8] / 1_000_000 + vals[9] / 1_000_000_000;
    if (@abs(norm_sec) >= 18014398509481984.0) return self.throwError("RangeError", "duration value out of range"); // 2^54
    const f2i = struct {
        fn c(x: f64) i128 {
            return @intFromFloat(x);
        }
    }.c;
    const total_ns: i128 = f2i(vals[3]) * 86_400_000_000_000 + f2i(vals[4]) * 3_600_000_000_000 + f2i(vals[5]) * 60_000_000_000 + f2i(vals[6]) * 1_000_000_000 + f2i(vals[7]) * 1_000_000 + f2i(vals[8]) * 1_000 + f2i(vals[9]);
    const abs_ns: i128 = if (total_ns < 0) -total_ns else total_ns;
    if (abs_ns >= 9007199254740992 * 1_000_000_000) return self.throwError("RangeError", "duration value out of range"); // 2^53 seconds
    return vals;
}

/// The resolved per-unit style for a DurationFormat unit (matching what
/// resolvedOptions reports): the explicit option, else the base style — with
/// "digital" making hours/minutes/seconds "numeric".
/// Digital style displays a zero "minutes" when a numeric "hours" precedes and
/// seconds (or sub-seconds) will be shown — "1:00:03" rather than "1:03".
fn durMinutesRequired(ov: ?Value, need_sep: bool, unit: []const u8, vals: [10]f64) bool {
    if (!std.mem.eql(u8, unit, "minutes") or !need_sep) return false;
    var sd: []const u8 = "auto";
    if (ov) |o| if (o.isObject()) if (o.asObj().getOwn("secondsDisplay")) |s| if (s.isString()) {
        sd = s.asStr();
    };
    return std.mem.eql(u8, sd, "always") or vals[6] != 0 or vals[7] != 0 or vals[8] != 0 or vals[9] != 0;
}

fn durUnitStyle(ov: ?Value, base: []const u8, unit: []const u8) []const u8 {
    if (ov) |o| if (o.isObject()) if (o.asObj().getOwn(unit)) |s| if (s.isString()) return s.asStr();
    if (std.mem.eql(u8, base, "digital")) {
        // hours/minutes/seconds and the sub-second units are numeric (sub-seconds
        // combine into the seconds fraction); years/months/weeks/days are short.
        if (std.mem.eql(u8, unit, "years") or std.mem.eql(u8, unit, "months") or std.mem.eql(u8, unit, "weeks") or std.mem.eql(u8, unit, "days")) return "short";
        return "numeric";
    }
    return base;
}

/// GetDurationUnitOptions for every unit, in order, tracking prevStyle. Fills
/// `styles`/`displays` with the resolved per-unit style and display, applying:
///   - digital defaults (h/m/s numeric + display "always"; rest short + "auto"),
///   - the prevStyle cascade (a unit after a numeric/2-digit one defaults to
///     numeric, or 2-digit for minutes/seconds), and
///   - the 2-digit promotion of an explicit/defaulted numeric minutes/seconds
///     that follows a numeric/2-digit unit.
/// Returns true if an explicit non-numeric style follows a numeric/2-digit unit
/// (a RangeError condition the constructor must surface).
fn durResolveUnits(ov: ?Value, base: []const u8, styles: *[10][]const u8, displays: *[10][]const u8) bool {
    const digital = std.mem.eql(u8, base, "digital");
    var prev_numlike = false;
    var conflict = false;
    inline for (duration_units, 0..) |u, i| {
        const is_ymwd = std.mem.eql(u8, u, "years") or std.mem.eql(u8, u, "months") or std.mem.eql(u8, u, "weeks") or std.mem.eql(u8, u, "days");
        const is_ms = std.mem.eql(u8, u, "minutes") or std.mem.eql(u8, u, "seconds");
        const is_hms = is_ms or std.mem.eql(u8, u, "hours");
        var explicit: ?[]const u8 = null;
        if (ov) |o| if (o.isObject()) if (o.asObj().getOwn(u)) |s| if (s.isString()) {
            explicit = s.asStr();
        };
        var style: []const u8 = undefined;
        var display_default: []const u8 = "always";
        if (explicit) |e| {
            style = e;
        } else if (digital) {
            if (!is_hms) display_default = "auto";
            style = if (is_ymwd) "short" else "numeric";
        } else {
            display_default = "auto";
            if (prev_numlike) {
                style = if (is_ms) "2-digit" else "numeric";
            } else style = base;
        }
        var display: []const u8 = display_default;
        if (ov) |o| if (o.isObject()) if (o.asObj().getOwn(u ++ "Display")) |dv| if (dv.isString()) {
            display = dv.asStr();
        };
        if (prev_numlike) {
            const numlike = std.mem.eql(u8, style, "numeric") or std.mem.eql(u8, style, "2-digit");
            if (!numlike) {
                conflict = true;
            } else if (is_ms) {
                style = "2-digit";
            }
        }
        styles[i] = style;
        displays[i] = display;
        prev_numlike = std.mem.eql(u8, style, "numeric") or std.mem.eql(u8, style, "2-digit");
    }
    return conflict;
}

/// Format one duration unit value via a NumberFormat instance, mirroring the
/// reference algorithm: standalone styles use style:"unit"; numeric/2-digit use
/// plain digits (useGrouping:false, +2-digit padding); non-first units suppress
/// the sign. Returns the formatted string.
/// Build the NumberFormat instance used to format one duration unit's value.
fn durUnitNf(self: *Interpreter, locale: []const u8, style: []const u8, unit_singular: []const u8, sign_never: bool) value.HostError!Value {
    const ro = (try self.newObject()).asObj();
    const standalone = !std.mem.eql(u8, style, "numeric") and !std.mem.eql(u8, style, "2-digit");
    if (standalone) {
        try self.setProp(ro, "style", Value.str("unit"));
        try self.setProp(ro, "unit", Value.str(unit_singular));
        try self.setProp(ro, "unitDisplay", Value.str(style));
    } else {
        try self.setProp(ro, "useGrouping", Value.boolVal(false));
        if (std.mem.eql(u8, style, "2-digit")) try self.setProp(ro, "minimumIntegerDigits", Value.num(2));
    }
    if (sign_never) try self.setProp(ro, "signDisplay", Value.str("never"));
    const nf = (try self.newObject()).asObj();
    try self.setProp(nf, "\x00intl", Value.str("NumberFormat"));
    try self.setProp(nf, "\x00locale", Value.str(locale));
    try self.setProp(nf, "\x00opts", Value.obj(ro));
    return Value.obj(nf);
}

fn durFmtVal(self: *Interpreter, locale: []const u8, num: f64, style: []const u8, unit_singular: []const u8, sign_never: bool) value.HostError![]const u8 {
    return nfFormatOne(self, try durUnitNf(self, locale, style, unit_singular, sign_never), Value.num(num));
}

/// Format a combined fractional value (a decimal string like "444.055006") for a
/// unit whose resolved style is standalone (long/short/narrow): a unit-style
/// NumberFormat with trunc rounding and the fractional-digit bounds. The decimal
/// string is fed verbatim so precision matches the conformance reference, which
/// formats the same constructed string.
fn durFmtCombineUnit(self: *Interpreter, locale: []const u8, dec: []const u8, style: []const u8, unit_singular: []const u8, sign_never: bool, fd: ?usize) value.HostError![]const u8 {
    const ro = (try self.newObject()).asObj();
    try self.setProp(ro, "style", Value.str("unit"));
    try self.setProp(ro, "unit", Value.str(unit_singular));
    try self.setProp(ro, "unitDisplay", Value.str(style));
    try self.setProp(ro, "minimumFractionDigits", Value.num(if (fd) |f| @floatFromInt(f) else 0));
    try self.setProp(ro, "maximumFractionDigits", Value.num(if (fd) |f| @floatFromInt(f) else 9));
    try self.setProp(ro, "roundingMode", Value.str("trunc"));
    if (sign_never) try self.setProp(ro, "signDisplay", Value.str("never"));
    const nf = (try self.newObject()).asObj();
    try self.setProp(nf, "\x00intl", Value.str("NumberFormat"));
    try self.setProp(nf, "\x00locale", Value.str(locale));
    try self.setProp(nf, "\x00opts", Value.obj(ro));
    return nfFormatOne(self, Value.obj(nf), Value.str(dec));
}

fn durFmtCombineNumeric(self: *Interpreter, locale: []const u8, dec: []const u8, min_int: usize, sign_never: bool, fd: ?usize) value.HostError![]const u8 {
    const ro = (try self.newObject()).asObj();
    try self.setProp(ro, "useGrouping", Value.boolVal(false));
    try self.setProp(ro, "minimumIntegerDigits", Value.num(@floatFromInt(min_int)));
    try self.setProp(ro, "minimumFractionDigits", Value.num(if (fd) |f| @floatFromInt(f) else 0));
    try self.setProp(ro, "maximumFractionDigits", Value.num(if (fd) |f| @floatFromInt(f) else 9));
    if (sign_never) try self.setProp(ro, "signDisplay", Value.str("never"));
    const nf = (try self.newObject()).asObj();
    try self.setProp(nf, "\x00intl", Value.str("NumberFormat"));
    try self.setProp(nf, "\x00locale", Value.str(locale));
    try self.setProp(nf, "\x00opts", Value.obj(ro));
    return nfFormatOne(self, Value.obj(nf), Value.str(dec));
}

fn durFracDigits(ov: ?Value) ?usize {
    if (ov) |o| if (o.isObject()) if (o.asObj().getOwn("fractionalDigits")) |f| if (f.isNumber()) return @intFromFloat(f.asNum());
    return null;
}

/// The combined sub-second total for `unit` is non-zero (so it must display even
/// when the unit's own value is 0, e.g. seconds 0 with milliseconds present).
fn durCombineNonzero(vals: [10]f64, unit: []const u8) bool {
    const lo: usize = if (std.mem.eql(u8, unit, "seconds")) 6 else if (std.mem.eql(u8, unit, "milliseconds")) 7 else 8;
    var k = lo;
    while (k < 10) : (k += 1) if (vals[k] != 0) return true;
    return false;
}

/// Whether `unit` (seconds/milliseconds/microseconds) combines its sub-second
/// units into a fractional value — i.e. the next-finer unit is "numeric".
fn durCombines(ov: ?Value, base: []const u8, unit: []const u8) bool {
    const next: []const u8 = if (std.mem.eql(u8, unit, "seconds")) "milliseconds" else if (std.mem.eql(u8, unit, "milliseconds")) "microseconds" else if (std.mem.eql(u8, unit, "microseconds")) "nanoseconds" else return false;
    return std.mem.eql(u8, durUnitStyle(ov, base, next), "numeric");
}

/// DurationToFractional: combine `unit` with its finer sub-second units into one
/// exact fractional value (integer arithmetic, no f64 precision loss), formatted
/// as a digit string truncated to `max_f` fraction digits then trimmed to
/// `min_f`. A leading "-" is added only when this is the sign-bearing unit.
fn durCombineFrac(self: *Interpreter, vals: [10]f64, unit: []const u8, max_f: usize, min_f: usize, sign_never: bool, min_int: usize) value.HostError![]const u8 {
    const sec: i128 = @intFromFloat(vals[6]);
    const ms: i128 = @intFromFloat(vals[7]);
    const us: i128 = @intFromFloat(vals[8]);
    const ns: i128 = @intFromFloat(vals[9]);
    var exp: usize = 9;
    var total: i128 = 0;
    if (std.mem.eql(u8, unit, "seconds")) {
        exp = 9;
        total = sec * 1_000_000_000 + ms * 1_000_000 + us * 1_000 + ns;
    } else if (std.mem.eql(u8, unit, "milliseconds")) {
        exp = 6;
        total = ms * 1_000_000 + us * 1_000 + ns;
    } else {
        exp = 3;
        total = us * 1_000 + ns;
    }
    const neg = total < 0;
    const at: i128 = if (neg) -total else total;
    var e10: i128 = 1;
    for (0..exp) |_| e10 *= 10;
    const q = @divTrunc(at, e10);
    const fr = @rem(at, e10);
    // Fraction digits: `fr` left-padded to `exp`, truncated to max_f, trimmed to min_f.
    var fdig = try std.fmt.allocPrint(self.arena, "{d}", .{fr});
    while (fdig.len < exp) fdig = try std.fmt.allocPrint(self.arena, "0{s}", .{fdig});
    var flen: usize = @min(fdig.len, max_f); // trunc rounding
    while (flen > min_f and fdig[flen - 1] == '0') flen -= 1;
    var idig = try std.fmt.allocPrint(self.arena, "{d}", .{q});
    while (idig.len < min_int) idig = try std.fmt.allocPrint(self.arena, "0{s}", .{idig});
    var buf: std.ArrayListUnmanaged(u8) = .empty;
    if (neg and !sign_never) try buf.append(self.arena, '-');
    try buf.appendSlice(self.arena, idig);
    if (flen > 0) {
        try buf.append(self.arena, '.');
        try buf.appendSlice(self.arena, fdig[0..flen]);
    }
    return buf.toOwnedSlice(self.arena);
}

fn intlDurationFormatFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (!intlBrandOk(this, "DurationFormat")) return self.throwError("TypeError", "Intl.DurationFormat.prototype.format on incompatible receiver");
    const d = if (args.len > 0) args[0] else Value.undef();
    const vals = try durationToRecord(self, d);
    var base: []const u8 = "short";
    const ov = this.asObj().getOwn("\x00opts");
    if (ov) |o| if (o.isObject()) if (o.asObj().getOwn("style")) |s| if (s.isString()) {
        base = s.asStr();
    };
    const locale = if (this.asObj().getOwn("\x00locale")) |lv| (if (lv.isString()) lv.asStr() else "en") else "en";

    // Build the list of formatted items. Consecutive numeric/2-digit units join
    // with ":" into one item (digital style); standalone units are separate
    // items joined with ", " (en ListFormat type:unit). Mirrors the spec.
    var items: std.ArrayListUnmanaged([]const u8) = .empty;
    var need_sep = false; // previous unit was numeric/2-digit
    var first = true;
    const dur_neg = blk: {
        for (vals) |vv| if (vv < 0) break :blk true;
        break :blk false;
    };
    var styles: [10][]const u8 = undefined;
    var displays: [10][]const u8 = undefined;
    _ = durResolveUnits(ov, base, &styles, &displays);
    inline for (duration_units, 0..) |u, i| {
        const uval = vals[i];
        const style = styles[i];
        const display = displays[i];
        // seconds/milliseconds/microseconds fold their finer units into a
        // fraction when the next-finer unit resolved to a numeric style.
        const combine = (i == 6 or i == 7 or i == 8) and std.mem.eql(u8, styles[i + 1], "numeric");
        const shown = uval != 0 or !std.mem.eql(u8, display, "auto") or durMinutesRequired(ov, need_sep, u, vals) or (combine and durCombineNonzero(vals, u));
        if (shown) {
            const sign_never = !first;
            const is_first = first;
            first = false;
            // First displayed unit bears the sign; a zero first unit shows "-0"
            // when the overall duration is negative (DurationToFractional / -0).
            const fnum = if (is_first and uval == 0 and dur_neg) -@as(f64, 0.0) else uval;
            const min_int: usize = if (std.mem.eql(u8, style, "2-digit")) 2 else 1;
            const numeric = std.mem.eql(u8, style, "numeric") or std.mem.eql(u8, style, "2-digit");
            const s = if (combine) blk: {
                const fd = durFracDigits(ov);
                const dec = try durCombineFrac(self, vals, u, fd orelse 9, fd orelse 0, sign_never, min_int);
                // A standalone-styled combine unit renders the fractional value
                // with its unit name ("444.055006 millisecond"); numeric/2-digit
                // units stay bare digits for the ":"-joined run.
                if (numeric) break :blk try durFmtCombineNumeric(self, locale, dec, min_int, sign_never, fd);
                break :blk try durFmtCombineUnit(self, locale, dec, style, u[0 .. u.len - 1], sign_never, fd);
            } else try durFmtVal(self, locale, fnum, style, u[0 .. u.len - 1], sign_never);
            // Once a numeric run starts (need_sep latches), every later unit
            // appends to it with ":" — even standalone ones (digital
            // "4:5:6:7 millisecond").
            if (need_sep and items.items.len > 0) {
                items.items[items.items.len - 1] = try std.fmt.allocPrint(self.arena, "{s}:{s}", .{ items.items[items.items.len - 1], s });
            } else {
                try items.append(self.arena, s);
                if (numeric) need_sep = true;
            }
        }
        if (combine and shown) break; // sub-seconds folded into this unit; done
    }
    // Join the items as a type:"unit" list (locale + style aware; digital uses
    // the short list style).
    const lstyle = if (std.mem.eql(u8, base, "digital")) "short" else base;
    const uc = unitConnectors(localeLanguage(locale), lstyle);
    var buf: std.ArrayListUnmanaged(u8) = .empty;
    for (items.items, 0..) |it, idx| {
        if (idx != 0) {
            const sep = if (idx == items.items.len - 1) (if (items.items.len == 2) uc.pair else uc.fin) else uc.mid;
            try buf.appendSlice(self.arena, sep);
        }
        try buf.appendSlice(self.arena, it);
    }
    return Value.str(try buf.toOwnedSlice(self.arena));
}

const DurPart = struct { typ: []const u8, value: []const u8, unit: ?[]const u8 };

fn intlDurationFormatToPartsFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (!intlBrandOk(this, "DurationFormat")) return self.throwError("TypeError", "Intl.DurationFormat.prototype.formatToParts on incompatible receiver");
    const d = if (args.len > 0) args[0] else Value.undef();
    const vals = try durationToRecord(self, d);
    var base: []const u8 = "short";
    const ov = this.asObj().getOwn("\x00opts");
    if (ov) |o| if (o.isObject()) if (o.asObj().getOwn("style")) |s| if (s.isString()) {
        base = s.asStr();
    };
    const locale = if (this.asObj().getOwn("\x00locale")) |lv| (if (lv.isString()) lv.asStr() else "en") else "en";

    // Each group is one ListFormat "element" (a unit, or a ":"-joined numeric run).
    var groups: std.ArrayListUnmanaged(std.ArrayListUnmanaged(DurPart)) = .empty;
    var need_sep = false;
    var first = true;
    const dur_neg = blk: {
        for (vals) |vv| if (vv < 0) break :blk true;
        break :blk false;
    };
    var styles: [10][]const u8 = undefined;
    var displays: [10][]const u8 = undefined;
    _ = durResolveUnits(ov, base, &styles, &displays);
    inline for (duration_units, 0..) |u, i| {
        const uval = vals[i];
        const style = styles[i];
        const display = displays[i];
        // seconds/milliseconds/microseconds fold their finer units into a
        // fraction when the next-finer unit resolved to a numeric style.
        const combine = (i == 6 or i == 7 or i == 8) and std.mem.eql(u8, styles[i + 1], "numeric");
        const shown = uval != 0 or !std.mem.eql(u8, display, "auto") or durMinutesRequired(ov, need_sep, u, vals) or (combine and durCombineNonzero(vals, u));
        if (shown) {
            const sign_never = !first;
            const is_first = first;
            first = false;
            const fnum = if (is_first and uval == 0 and dur_neg) -@as(f64, 0.0) else uval;
            const sing = u[0 .. u.len - 1];
            const numeric = std.mem.eql(u8, style, "numeric") or std.mem.eql(u8, style, "2-digit");
            var grp: *std.ArrayListUnmanaged(DurPart) = undefined;
            if (need_sep and groups.items.len > 0) {
                grp = &groups.items[groups.items.len - 1];
                try grp.append(self.arena, .{ .typ = "literal", .value = ":", .unit = null });
            } else {
                try groups.append(self.arena, .empty);
                grp = &groups.items[groups.items.len - 1];
                if (numeric) need_sep = true;
            }
            if (combine) {
                // Parse the exact "[-]int[.frac]" combine string into typed parts.
                const fd = durFracDigits(ov);
                const min_int: usize = if (std.mem.eql(u8, style, "2-digit")) 2 else 1;
                var s = try durCombineFrac(self, vals, u, fd orelse 9, fd orelse 0, sign_never, min_int);
                if (s.len > 0 and s[0] == '-') {
                    try grp.append(self.arena, .{ .typ = "minusSign", .value = "-", .unit = sing });
                    s = s[1..];
                }
                if (std.mem.indexOfScalar(u8, s, '.')) |dot| {
                    try grp.append(self.arena, .{ .typ = "integer", .value = s[0..dot], .unit = sing });
                    try grp.append(self.arena, .{ .typ = "decimal", .value = ".", .unit = sing });
                    try grp.append(self.arena, .{ .typ = "fraction", .value = s[dot + 1 ..], .unit = sing });
                } else {
                    try grp.append(self.arena, .{ .typ = "integer", .value = s, .unit = sing });
                }
            } else {
                const nf_parts = try nfBuildParts(self, try durUnitNf(self, locale, style, sing, sign_never), &.{Value.num(fnum)});
                for (nf_parts.items) |p| try grp.append(self.arena, .{ .typ = p.typ, .value = p.value, .unit = sing });
            }
        }
        if (combine and shown) break;
    }
    // Flatten: a type:"unit" list literal between element groups (locale/style aware).
    const lstyle = if (std.mem.eql(u8, base, "digital")) "short" else base;
    const uc = unitConnectors(localeLanguage(locale), lstyle);
    const arr = (try self.newArray()).asObj();
    for (groups.items, 0..) |grp, gi| {
        if (gi != 0) {
            const sep = if (gi == groups.items.len - 1) (if (groups.items.len == 2) uc.pair else uc.fin) else uc.mid;
            const lo = (try self.newObject()).asObj();
            try self.setProp(lo, "type", Value.str("literal"));
            try self.setProp(lo, "value", Value.str(sep));
            try arr.elements.append(arr.elementsAllocator(self.arena), Value.obj(lo));
        }
        for (grp.items) |p| {
            const o = (try self.newObject()).asObj();
            try self.setProp(o, "type", Value.str(p.typ));
            try self.setProp(o, "value", Value.str(p.value));
            if (p.unit) |un| try self.setProp(o, "unit", Value.str(un));
            try arr.elements.append(arr.elementsAllocator(self.arena), Value.obj(o));
        }
    }
    return Value.obj(arr);
}

/// `get Intl.<service>.prototype.<prop>`: per spec `format`/`compare` are
/// accessors whose getter returns a function bound to this instance, created
/// lazily and cached (so `c.compare === c.compare`). The bound function has
/// name "" and the given length. The underlying impl is stored on the prototype
/// under `impl_key`; the cached bound function under `cache_key`.
fn intlBoundAccessorFn(comptime service: []const u8, comptime prop: []const u8, comptime impl_key: []const u8, comptime cache_key: []const u8, comptime length: f64) value.NativeFn {
    return struct {
        fn call(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
            _ = args;
            const self: *Interpreter = @ptrCast(@alignCast(ctx));
            if (!intlBrandOk(this, service)) return self.throwError("TypeError", "get Intl." ++ service ++ ".prototype." ++ prop ++ " called on incompatible receiver");
            if (this.asObj().getOwn(cache_key)) |b| return b;
            const impl = try self.getProperty(this, impl_key);
            if (!impl.isObject()) return self.throwError("TypeError", "missing " ++ prop ++ " implementation");
            const bound = try self.makeBound(impl.asObj(), this, &.{});
            const ro: value.PropAttr = .{ .writable = false, .enumerable = false, .configurable = true };
            try bound.asObj().setOwn(self.arena, self.root_shape, "name", Value.str(""));
            try bound.asObj().setAttr(self.arena, "name", ro);
            try bound.asObj().setOwn(self.arena, self.root_shape, "length", Value.num(length));
            try bound.asObj().setAttr(self.arena, "length", ro);
            try self.setProp(this.asObj(), cache_key, bound);
            try this.asObj().setAttr(self.arena, cache_key, .{ .writable = false, .enumerable = false, .configurable = false });
            return bound;
        }
    }.call;
}

/// Install the `format` accessor + hidden `\x00fmtimpl` on a formatter prototype.
fn installIntlFormat(a: std.mem.Allocator, rs: *Shape, proto: *value.Object, comptime service: []const u8, impl_fn: value.NativeFn) EvalError!void {
    const impl = try gc_mod.allocObj(a);
    impl.* = .{ .native = impl_fn };
    try installNativeProps(a, rs, impl, "format", 1);
    try proto.setOwn(a, rs, "\x00fmtimpl", Value.obj(impl));
    try proto.setAttr(a, "\x00fmtimpl", .{ .writable = false, .enumerable = false, .configurable = false });
    try setNativeGetter(a, rs, proto, "format", intlBoundAccessorFn(service, "format", "\x00fmtimpl", "\x00boundFormat", 1));
}

/// Install the Collator `compare` accessor + hidden `\x00cmpimpl`.
fn installIntlCompare(a: std.mem.Allocator, rs: *Shape, proto: *value.Object, impl_fn: value.NativeFn) EvalError!void {
    const impl = try gc_mod.allocObj(a);
    impl.* = .{ .native = impl_fn };
    try installNativeProps(a, rs, impl, "compare", 2);
    try proto.setOwn(a, rs, "\x00cmpimpl", Value.obj(impl));
    try proto.setAttr(a, "\x00cmpimpl", .{ .writable = false, .enumerable = false, .configurable = false });
    try setNativeGetter(a, rs, proto, "compare", intlBoundAccessorFn("Collator", "compare", "\x00cmpimpl", "\x00boundCompare", 2));
}

fn intlCollatorCompareFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (!intlBrandOk(this, "Collator")) return self.throwError("TypeError", "Intl.Collator.prototype.compare on incompatible receiver");
    const x = try self.toStringV(if (args.len > 0) args[0] else Value.undef());
    const y = try self.toStringV(if (args.len > 1) args[1] else Value.undef());
    const loc = if (this.asObj().getOwn("\x00locale")) |v| if (v.isString()) v.asStr() else "en" else "en";
    const ro = if (this.asObj().getOwn("\x00opts")) |v| v else Value.undef();
    const opts = try collatorOptionsFrom(self, Value.str(loc), ro);
    return Value.num(try collatorCompareStrings(self, x, y, opts));
}

/// LDML plural-rule operands derived from a number formatted with the given
/// fraction-digit bounds: n (value), i (integer part), v/f (fraction digits with
/// trailing zeros — count/value), w/t (without trailing zeros), e (exponent).
const PluralOperands = struct { n: f64, i: f64, v: f64, w: f64, f: f64, t: f64, e: f64 };

fn pluralOperands(num: f64, min_frac: usize, max_frac: usize) PluralOperands {
    const abs = @abs(num);
    if (!std.math.isFinite(abs)) return .{ .n = abs, .i = abs, .v = 0, .w = 0, .f = 0, .t = 0, .e = 0 };
    var scale: f64 = 1;
    for (0..max_frac) |_| scale *= 10;
    const scaled = @round(abs * scale); // value * 10^maxFrac, rounded
    const n = if (scale == 0) abs else scaled / scale;
    const ipart = @floor(n);
    // Fraction digits (integer 0..scale-1), padded to max_frac.
    const frac_int: u64 = if (scale == 0) 0 else @intFromFloat(@round((n - ipart) * scale));
    var fbuf: [20]u8 = undefined;
    const fs = std.fmt.bufPrint(&fbuf, "{d}", .{frac_int}) catch "0";
    var digits: [40]u8 = undefined;
    var dlen: usize = 0;
    while (dlen + fs.len < max_frac) : (dlen += 1) digits[dlen] = '0'; // left-pad
    for (fs) |c| {
        digits[dlen] = c;
        dlen += 1;
    }
    if (max_frac == 0) dlen = 0;
    // Displayed width: trim trailing zeros down to min_frac.
    var v = dlen;
    while (v > min_frac and digits[v - 1] == '0') v -= 1;
    // Without trailing zeros at all.
    var w = v;
    while (w > 0 and digits[w - 1] == '0') w -= 1;
    const f: f64 = if (v == 0) 0 else @floatFromInt(std.fmt.parseInt(u64, digits[0..v], 10) catch 0);
    const t: f64 = if (w == 0) 0 else @floatFromInt(std.fmt.parseInt(u64, digits[0..w], 10) catch 0);
    return .{ .n = n, .i = ipart, .v = @floatFromInt(v), .w = @floatFromInt(w), .f = f, .t = t, .e = 0 };
}

fn pluralOperandValue(c: u8, ops: PluralOperands) f64 {
    return switch (c) {
        'n' => ops.n,
        'i' => ops.i,
        'v' => ops.v,
        'w' => ops.w,
        'f' => ops.f,
        't' => ops.t,
        'e', 'c' => ops.e,
        else => 0,
    };
}

/// Does `val` satisfy the LDML range-list (e.g. "3..10" or "0,1")? A range only
/// matches an integral value within [lo, hi].
fn pluralRangeListMatch(list: []const u8, val: f64) bool {
    var items = std.mem.splitScalar(u8, list, ',');
    while (items.next()) |item| {
        if (std.mem.indexOf(u8, item, "..")) |dd| {
            const lo = std.fmt.parseFloat(f64, item[0..dd]) catch continue;
            const hi = std.fmt.parseFloat(f64, item[dd + 2 ..]) catch continue;
            if (val == @floor(val) and val >= lo and val <= hi) return true;
        } else {
            const x = std.fmt.parseFloat(f64, item) catch continue;
            if (val == x) return true;
        }
    }
    return false;
}

/// Evaluate one LDML relation: "operand [% mod] (= | !=) range-list".
fn pluralEvalRel(rel: []const u8, ops: PluralOperands) bool {
    var toks = std.mem.tokenizeScalar(u8, rel, ' ');
    const opnd = toks.next() orelse return false;
    var val = pluralOperandValue(opnd[0], ops);
    var nxt = toks.next() orelse return false;
    if (std.mem.eql(u8, nxt, "%")) {
        const m = std.fmt.parseFloat(f64, toks.next() orelse return false) catch return false;
        if (m != 0) val = @rem(val, m);
        nxt = toks.next() orelse return false;
    }
    const list = toks.next() orelse return false;
    const isin = pluralRangeListMatch(list, val);
    return if (std.mem.eql(u8, nxt, "!=")) !isin else isin;
}

/// Evaluate an LDML plural condition (and/or of relations); "" is always true.
fn pluralEvalCond(cond: []const u8, ops: PluralOperands) bool {
    if (cond.len == 0) return true;
    var ors = std.mem.splitSequence(u8, cond, " or ");
    while (ors.next()) |term| {
        var all = true;
        var ands = std.mem.splitSequence(u8, term, " and ");
        while (ands.next()) |rel| {
            if (!pluralEvalRel(rel, ops)) {
                all = false;
                break;
            }
        }
        if (all) return true;
    }
    return false;
}

/// PluralRuleSelect: the first category whose rule matches, else "other".
fn pluralCategory(rules: []const cldr_plurals.Rule, ops: PluralOperands) []const u8 {
    for (rules) |r| {
        if (r.cond.len > 0 and pluralEvalCond(r.cond, ops)) return r.cat;
    }
    return "other";
}

/// The language subtag (lowercased) of a stored locale tag.
fn localeLanguage(tag: []const u8) []const u8 {
    const end = std.mem.indexOfScalar(u8, tag, '-') orelse tag.len;
    return tag[0..end];
}

fn pluralRulesFor(this: Value) []const cldr_plurals.Rule {
    const tag = if (this.asObj().getOwn("\x00locale")) |lv| (if (lv.isString()) lv.asStr() else "en") else "en";
    const lang = localeLanguage(tag);
    const is_ordinal = if (this.asObj().getOwn("\x00opts")) |ov| (ov.isObject() and ov.asObj().getOwn("type") != null and ov.asObj().getOwn("type").?.isString() and std.mem.eql(u8, ov.asObj().getOwn("type").?.asStr(), "ordinal")) else false;
    const rules = if (is_ordinal) cldr_plurals.ordinal(lang) else cldr_plurals.cardinal(lang);
    // Fall back to English cardinal (one/other) when a language has no data.
    return rules orelse (cldr_plurals.cardinal("en") orelse &.{});
}

fn pluralFracDigits(this: Value) struct { min: usize, max: usize } {
    var min: usize = 0;
    var max: usize = 3;
    if (this.asObj().getOwn("\x00opts")) |ov| if (ov.isObject()) {
        if (ov.asObj().getOwn("minimumFractionDigits")) |m| if (m.isNumber()) {
            min = @intFromFloat(m.asNum());
        };
        if (ov.asObj().getOwn("maximumFractionDigits")) |m| if (m.isNumber()) {
            max = @intFromFloat(m.asNum());
        };
    };
    if (max < min) max = min;
    return .{ .min = min, .max = max };
}

fn intlPluralSelectFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (!intlBrandOk(this, "PluralRules")) return self.throwError("TypeError", "Intl.PluralRules.prototype.select on incompatible receiver");
    const n = try self.toNumberV(if (args.len > 0) args[0] else Value.undef());
    if (std.math.isNan(n)) return Value.str("other");
    const fd = pluralFracDigits(this);
    var ops = pluralOperands(n, fd.min, fd.max);
    // The exponent operand (e/c) for scientific/engineering/compact notation.
    var notation: []const u8 = "standard";
    if (this.asObj().getOwn("\x00opts")) |ov| if (ov.isObject()) if (ov.asObj().getOwn("notation")) |nv| if (nv.isString()) {
        notation = nv.asStr();
    };
    const absn = @abs(n);
    if (absn != 0 and std.math.isFinite(absn) and !std.mem.eql(u8, notation, "standard")) {
        const oom = orderOfMagnitude(absn);
        ops.e = @floatFromInt(if (std.mem.eql(u8, notation, "scientific"))
            oom
        else if (std.mem.eql(u8, notation, "engineering"))
            @divFloor(oom, 3) * 3
        else if (oom >= 3) // compact: a multiple-of-three magnitude >= 1000
            @divFloor(oom, 3) * 3
        else
            @as(i32, 0));
    }
    return Value.str(pluralCategory(pluralRulesFor(this), ops));
}

/// One element of a ListFormat result: an "element" (a list item) or a
/// "literal" (the connector text between items).
const LfPart = struct { typ: []const u8, value: []const u8 };

/// type:"unit" list connectors (pair / middle / final) by language + style —
/// shared by Intl.ListFormat and DurationFormat's unit joining: narrow joins
/// with spaces; es joins with "y" (long ends with "y", short with ", ").
const UnitConn = struct { pair: []const u8, mid: []const u8, fin: []const u8 };
fn unitConnectors(lang: []const u8, style: []const u8) UnitConn {
    if (std.mem.eql(u8, style, "narrow")) return .{ .pair = " ", .mid = " ", .fin = " " };
    if (std.mem.eql(u8, lang, "es")) return .{ .pair = " y ", .mid = ", ", .fin = if (std.mem.eql(u8, style, "short")) ", " else " y " };
    return .{ .pair = ", ", .mid = ", ", .fin = ", " };
}

/// Build the ListFormat parts for `args[0]` (en). The connectors depend on the
/// instance's `type` (conjunction "and" / disjunction "or" / unit none).
fn lfBuildParts(self: *Interpreter, this: Value, args: []const Value) value.HostError!std.ArrayListUnmanaged(LfPart) {
    var parts: std.ArrayListUnmanaged(LfPart) = .empty;
    const v = if (args.len > 0) args[0] else Value.undef();
    if (v.isUndefined()) return parts;
    // StringListFromIterable: drain the iterator, type-checking each value and
    // closing the iterator on the first non-string (the list is not fully
    // consumed past the offending element).
    var strs: std.ArrayListUnmanaged([]const u8) = .empty;
    const it = try self.iteratorOf(v);
    while (true) {
        const r = try self.callMethod(it, "next", &.{});
        if ((try self.getProperty(r, "done")).toBoolean()) break;
        const nv = try self.getProperty(r, "value");
        if (!nv.isString()) {
            self.iteratorClose(it) catch {};
            return self.throwError("TypeError", "Intl.ListFormat: list items must be strings");
        }
        try strs.append(self.arena, nv.asStr());
    }
    const list = strs.items;
    var typ: []const u8 = "conjunction";
    var style: []const u8 = "long";
    if (this.asObj().getOwn("\x00opts")) |ov| if (ov.isObject()) {
        const tv = try self.getProperty(ov, "type");
        if (tv.isString()) typ = tv.asStr();
        const sv = try self.getProperty(ov, "style");
        if (sv.isString()) style = sv.asStr();
    };
    // en connectors by type+style: pair (two items) / final (≥3) / middle.
    const is_unit = std.mem.eql(u8, typ, "unit");
    const is_disj = std.mem.eql(u8, typ, "disjunction");
    const narrow = std.mem.eql(u8, style, "narrow");
    const short = std.mem.eql(u8, style, "short");
    const lang = if (this.asObj().getOwn("\x00locale")) |lv| (if (lv.isString()) localeLanguage(lv.asStr()) else "en") else "en";
    const es = std.mem.eql(u8, lang, "es");
    var middle: []const u8 = ", ";
    var pair: []const u8 = " and ";
    var final: []const u8 = ", and ";
    if (is_unit) {
        const uc = unitConnectors(lang, style);
        pair = uc.pair;
        middle = uc.mid;
        final = uc.fin;
    } else if (is_disj) {
        // es disjunction "o" (no comma before the final); en "or".
        pair = if (es) " o " else " or ";
        final = if (es) " o " else ", or ";
    } else if (narrow) { // conjunction
        middle = " ";
        pair = " ";
        final = " ";
    } else if (es) { // es conjunction "y" (no comma before the final)
        pair = " y ";
        final = " y ";
    } else if (short) {
        pair = " & ";
        final = ", & ";
    }
    for (list, 0..) |item, i| {
        if (i != 0) {
            const sep = if (i == list.len - 1) (if (list.len == 2) pair else final) else middle;
            try parts.append(self.arena, .{ .typ = "literal", .value = sep });
        }
        try parts.append(self.arena, .{ .typ = "element", .value = item });
    }
    return parts;
}

// ---- Intl.Segmenter segmentation (byte-offset, code-point aware) -----------

fn segScalarLen(str: []const u8, pos: usize) usize {
    if (wtf8SurrogateAt(str, pos) != null) return 3;
    return utf8SeqLen(str, pos);
}

fn segCodePoint(str: []const u8, pos: usize) u21 {
    if (wtf8SurrogateAt(str, pos)) |cp| return cp;
    const n = utf8SeqLen(str, pos);
    if (n == 1) return str[pos];
    return std.unicode.utf8Decode(str[pos .. pos + n]) catch str[pos];
}

fn segIsCombining(cp: u21) bool {
    return (cp >= 0x0300 and cp <= 0x036F) or
        (cp >= 0x0483 and cp <= 0x0489) or
        (cp >= 0x0591 and cp <= 0x05BD) or
        cp == 0x05BF or
        (cp >= 0x05C1 and cp <= 0x05C2) or
        (cp >= 0x05C4 and cp <= 0x05C5) or
        cp == 0x05C7 or
        (cp >= 0x0610 and cp <= 0x061A) or
        (cp >= 0x064B and cp <= 0x065F) or
        cp == 0x0670 or
        (cp >= 0x06D6 and cp <= 0x06DC) or
        (cp >= 0x06DF and cp <= 0x06E4) or
        (cp >= 0x06E7 and cp <= 0x06E8) or
        (cp >= 0x06EA and cp <= 0x06ED) or
        (cp >= 0x0900 and cp <= 0x0DFF and !(cp >= 0x0966 and cp <= 0x096F)) or
        (cp >= 0x0E31 and cp <= 0x0E4E) or
        (cp >= 0xFE00 and cp <= 0xFE0F) or
        (cp >= 0x1F3FB and cp <= 0x1F3FF) or
        (cp >= 0xE0100 and cp <= 0xE01EF);
}

fn segIsJamo(cp: u21) bool {
    return cp >= 0x1100 and cp <= 0x11FF;
}

fn segNextGrapheme(str: []const u8, pos: usize) usize {
    var end = pos + segScalarLen(str, pos);
    const first = segCodePoint(str, pos);
    if (isHighSurrogate(first) and end < str.len) {
        const next = segCodePoint(str, end);
        if (isLowSurrogate(next)) end += segScalarLen(str, end);
    }
    if (segIsJamo(first)) {
        while (end < str.len and segIsJamo(segCodePoint(str, end))) end += segScalarLen(str, end);
        return end;
    }
    while (end < str.len) {
        const cp = segCodePoint(str, end);
        if (segIsCombining(cp)) {
            end += segScalarLen(str, end);
            continue;
        }
        if (cp == 0x200D) {
            end += segScalarLen(str, end);
            if (end < str.len) end += segScalarLen(str, end);
            continue;
        }
        break;
    }
    return end;
}

/// Whether the code point starting at `str[pos]` is "word-like" (letters/digits).
/// ASCII is classified exactly; any non-ASCII byte is treated as a letter (the
/// structural Segmenter tests don't require precise UAX#29 categories).
fn segWordCat(str: []const u8, pos: usize) bool {
    const b = str[pos];
    if (b < 0x80) return std.ascii.isAlphanumeric(b);
    return true;
}

/// Advance one segment from byte `pos`; returns the end byte offset and (for the
/// "word" granularity) whether the segment is word-like.
fn segNext(str: []const u8, pos: usize, gran: []const u8) struct { end: usize, word_like: bool } {
    const len = str.len;
    if (std.mem.eql(u8, gran, "grapheme")) {
        return .{ .end = @min(len, segNextGrapheme(str, pos)), .word_like = false };
    }
    if (std.mem.eql(u8, gran, "sentence")) {
        var end = pos;
        while (end < len) {
            const c = str[end];
            const is_term = c == '.' or c == '!' or c == '?';
            end += segScalarLen(str, end);
            if (is_term) {
                while (end < len and (str[end] == ' ' or str[end] == '\t' or str[end] == '\n')) end += 1;
                break;
            }
        }
        return .{ .end = end, .word_like = false };
    }
    // word: a maximal run of one category (word-like vs not). A "." or ","
    // between two digits stays inside the numeric word (UAX#29 WB11/WB12), so
    // "1.23" is one segment rather than "1", ".", "23".
    const first_cp = segCodePoint(str, pos);
    if (isHighSurrogate(first_cp) or isLowSurrogate(first_cp)) {
        var end = pos + segScalarLen(str, pos);
        if (isHighSurrogate(first_cp) and end < len and isLowSurrogate(segCodePoint(str, end))) end += segScalarLen(str, end);
        return .{ .end = end, .word_like = false };
    }
    const cat = segWordCat(str, pos);
    var end = pos;
    if (cat) {
        while (end < len) {
            if (segWordCat(str, end)) {
                end += segScalarLen(str, end);
                continue;
            }
            const c = str[end];
            if ((c == '.' or c == ',') and end > pos and end + 1 < len and std.ascii.isDigit(str[end - 1]) and std.ascii.isDigit(str[end + 1])) {
                end += 1;
                continue;
            }
            break;
        }
    } else {
        while (end < len and !segWordCat(str, end)) end += segScalarLen(str, end);
    }
    return .{ .end = end, .word_like = cat };
}

/// Build a segment-data object `{ segment, index, input[, isWordLike] }` (own
/// properties in that order; isWordLike only for the "word" granularity).
fn segDataObj(self: *Interpreter, str: []const u8, start: usize, end: usize, gran: []const u8, word_like: bool) EvalError!Value {
    const o = (try self.newObject()).asObj();
    try self.setProp(o, "segment", Value.str(try self.arena.dupe(u8, str[start..end])));
    try self.setProp(o, "index", Value.num(@floatFromInt(Interpreter.utf16IndexForByteOffset(str, start))));
    try self.setProp(o, "input", Value.str(str));
    if (std.mem.eql(u8, gran, "word")) try self.setProp(o, "isWordLike", Value.boolVal(word_like));
    return Value.obj(o);
}

fn segmenterGranularity(seg_obj: *value.Object) []const u8 {
    if (seg_obj.getOwn("\x00gran")) |g| if (g.isString()) return g.asStr();
    return "grapheme";
}

/// `Intl.Segmenter.prototype.segment(string)` → a %Segments% object.
fn intlSegmenterSegmentFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (!intlBrandOk(this, "Segmenter")) return self.throwError("TypeError", "Intl.Segmenter.prototype.segment on incompatible receiver");
    const str = try self.toStringV(if (args.len > 0) args[0] else Value.undef());
    var gran: []const u8 = "grapheme";
    if (this.asObj().getOwn("\x00opts")) |ov| if (ov.isObject()) {
        if (ov.asObj().getOwn("granularity")) |g| if (g.isString()) {
            gran = g.asStr();
        };
    };
    const o = (try self.newObject()).asObj();
    if (self.env.get("\x00SegmentsProto")) |p| if (p.isObject()) {
        o.setProtoAtomic(p.asObj());
    };
    try self.setProp(o, "\x00segstr", Value.str(str));
    try o.setAttr(self.arena, "\x00segstr", .{ .writable = false, .enumerable = false, .configurable = false });
    try self.setProp(o, "\x00gran", Value.str(gran));
    try o.setAttr(self.arena, "\x00gran", .{ .writable = false, .enumerable = false, .configurable = false });
    return Value.obj(o);
}

fn segmentsBrandOk(this: Value) bool {
    return this.isObject() and this.asObj().getOwn("\x00segstr") != null;
}

/// `%Segments.prototype%.containing(index)`.
fn intlSegmentsContainingFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (!segmentsBrandOk(this)) return self.throwError("TypeError", "Segments.prototype.containing on incompatible receiver");
    const str = this.asObj().getOwn("\x00segstr").?.asStr();
    const gran = segmenterGranularity(this.asObj());
    const nf = try self.toNumberV(if (args.len > 0) args[0] else Value.undef());
    const n: f64 = if (std.math.isNan(nf)) 0 else @trunc(nf);
    if (n < 0 or n >= @as(f64, @floatFromInt(Interpreter.utf16LenOfString(str)))) return Value.undef();
    const target_units: usize = @intFromFloat(n);
    var pos: usize = 0;
    while (pos < str.len) {
        const nx = segNext(str, pos, gran);
        const start_units = Interpreter.utf16IndexForByteOffset(str, pos);
        const end_units = Interpreter.utf16IndexForByteOffset(str, nx.end);
        if (target_units >= start_units and target_units < end_units) return try segDataObj(self, str, pos, nx.end, gran, nx.word_like);
        pos = nx.end;
    }
    return Value.undef();
}

/// `%Segments.prototype%[@@iterator]()` → a %SegmentIterator%.
fn intlSegmentsIteratorFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = args;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (!segmentsBrandOk(this)) return self.throwError("TypeError", "Segments.prototype[@@iterator] on incompatible receiver");
    const it = (try self.newObject()).asObj();
    if (self.env.get("\x00SegIterProto")) |p| if (p.isObject()) {
        it.setProtoAtomic(p.asObj());
    };
    try self.setProp(it, "\x00segstr", this.asObj().getOwn("\x00segstr").?);
    try it.setAttr(self.arena, "\x00segstr", .{ .writable = false, .enumerable = false, .configurable = false });
    try self.setProp(it, "\x00gran", Value.str(segmenterGranularity(this.asObj())));
    try it.setAttr(self.arena, "\x00gran", .{ .writable = false, .enumerable = false, .configurable = false });
    try self.setProp(it, "\x00pos", Value.num(0));
    try it.setAttr(self.arena, "\x00pos", .{ .writable = true, .enumerable = false, .configurable = false });
    return Value.obj(it);
}

/// `%SegmentIterator.prototype%.next()`.
fn intlSegmentIterNextFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = args;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (!this.isObject() or this.asObj().getOwn("\x00pos") == null) return self.throwError("TypeError", "Segment Iterator next on incompatible receiver");
    const str = this.asObj().getOwn("\x00segstr").?.asStr();
    const gran = segmenterGranularity(this.asObj());
    const pos: usize = @intFromFloat(this.asObj().getOwn("\x00pos").?.asNum());
    if (pos >= str.len) return self.iterResultObj(Value.undef(), true);
    const nx = segNext(str, pos, gran);
    try self.setProp(this.asObj(), "\x00pos", Value.num(@floatFromInt(nx.end)));
    return self.iterResultObj(try segDataObj(self, str, pos, nx.end, gran, nx.word_like), false);
}

/// `Intl.PluralRules.prototype.selectRange(start, end)` — both must be
/// non-NaN numbers (RangeError otherwise). The en plural range is always
/// "other".
fn intlPluralSelectRangeFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (!intlBrandOk(this, "PluralRules")) return self.throwError("TypeError", "Intl.PluralRules.prototype.selectRange on incompatible receiver");
    if (args.len < 2 or args[0].isUndefined() or args[1].isUndefined()) return self.throwError("TypeError", "selectRange requires two arguments");
    const start = try self.toNumberV(args[0]);
    const end = try self.toNumberV(args[1]);
    if (std.math.isNan(start) or std.math.isNan(end)) return self.throwError("RangeError", "selectRange arguments must not be NaN");
    return Value.str("other");
}

/// `Intl.DisplayNames.prototype.of(code)` — validates the code's structure for
/// the configured type (RangeError otherwise). With no CLDR name data the name
/// is always "not found": fallback "none" returns undefined, "code" returns the
/// canonicalized code.
fn intlDisplayNamesOfFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (!intlBrandOk(this, "DisplayNames")) return self.throwError("TypeError", "Intl.DisplayNames.prototype.of on incompatible receiver");
    const code = try self.toStringV(if (args.len > 0) args[0] else Value.undef());
    var typ: []const u8 = "language";
    var fallback: []const u8 = "code";
    if (this.asObj().getOwn("\x00opts")) |ov| if (ov.isObject()) {
        if (ov.asObj().getOwn("type")) |t| typ = t.asStr();
        if (ov.asObj().getOwn("fallback")) |f| fallback = f.asStr();
    };
    const allAlpha = struct {
        fn f(s: []const u8) bool {
            for (s) |c| if (!std.ascii.isAlphabetic(c)) return false;
            return s.len > 0;
        }
    }.f;
    var canon: []const u8 = code;
    if (std.mem.eql(u8, typ, "region")) {
        const digits = blk: {
            for (code) |c| if (!std.ascii.isDigit(c)) break :blk false;
            break :blk code.len == 3;
        };
        if (!((code.len == 2 and allAlpha(code)) or digits)) return self.throwError("RangeError", "invalid region code");
        canon = try std.ascii.allocUpperString(self.arena, code);
    } else if (std.mem.eql(u8, typ, "script")) {
        if (code.len != 4 or !allAlpha(code)) return self.throwError("RangeError", "invalid script code");
    } else if (std.mem.eql(u8, typ, "currency")) {
        if (code.len != 3 or !allAlpha(code)) return self.throwError("RangeError", "invalid currency code");
        canon = try std.ascii.allocUpperString(self.arena, code);
        // The currencies enumerated by supportedValuesOf have a (stand-in) name,
        // so they resolve even under fallback:"none".
        for (supported_currencies) |c| if (std.mem.eql(u8, c, canon)) return Value.str(canon);
    } else if (std.mem.eql(u8, typ, "language")) {
        // A unicode_language_id: structurally valid AND no extension (singleton)
        // subtag (DisplayNames language codes are not full locale tags).
        if (!isStructurallyValidLanguageTag(code)) return self.throwError("RangeError", "invalid language code");
        var lit = std.mem.splitScalar(u8, code, '-');
        while (lit.next()) |s| if (s.len == 1) return self.throwError("RangeError", "language code may not contain an extension");
    } else if (std.mem.eql(u8, typ, "calendar")) {
        if (!dtfWellFormedType(code)) return self.throwError("RangeError", "invalid calendar code");
        // Calendars enumerated by supportedValuesOf resolve under fallback:"none".
        const cc = dtfCanonCalendar(code);
        if (dtfCalAvail(cc)) return Value.str(cc);
    } else if (std.mem.eql(u8, typ, "dateTimeField")) {
        const fields = [_][]const u8{ "era", "year", "quarter", "month", "weekOfYear", "weekday", "day", "dayPeriod", "hour", "minute", "second", "timeZoneName" };
        var ok = false;
        for (fields) |f| if (std.mem.eql(u8, code, f)) {
            ok = true;
        };
        if (!ok) return self.throwError("RangeError", "invalid dateTimeField");
    }
    if (std.mem.eql(u8, fallback, "none")) return Value.undef();
    return Value.str(canon);
}

fn intlListFormatFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (!intlBrandOk(this, "ListFormat")) return self.throwError("TypeError", "Intl.ListFormat.prototype.format on incompatible receiver");
    const parts = try lfBuildParts(self, this, args);
    var buf: std.ArrayListUnmanaged(u8) = .empty;
    for (parts.items) |p| try buf.appendSlice(self.arena, p.value);
    return Value.str(try buf.toOwnedSlice(self.arena));
}

fn intlListFormatToPartsFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (!intlBrandOk(this, "ListFormat")) return self.throwError("TypeError", "Intl.ListFormat.prototype.formatToParts on incompatible receiver");
    const parts = try lfBuildParts(self, this, args);
    const arr = (try self.newArray()).asObj();
    for (parts.items) |p| {
        const o = (try self.newObject()).asObj();
        try self.setProp(o, "type", Value.str(p.typ));
        try self.setProp(o, "value", Value.str(p.value));
        try arr.elements.append(arr.elementsAllocator(self.arena), Value.obj(o));
    }
    return Value.obj(arr);
}

/// The eight relative-time units, with their long-form names and the
/// numeric-"auto" exception terms (en). A null past/future term means the unit
/// has no special word there, so the numeric form ("in 1 hour") is used.
const RtfUnitInfo = struct {
    singular: []const u8,
    past: ?[]const u8, // value -1
    present: []const u8, // value 0 / -0
    future: ?[]const u8, // value +1
};
fn rtfUnitInfo(unit: []const u8) ?RtfUnitInfo {
    // Accept the singular or plural ("second"/"seconds") spelling.
    const table = [_]struct { k: []const u8, i: RtfUnitInfo }{
        .{ .k = "second", .i = .{ .singular = "second", .past = null, .present = "now", .future = null } },
        .{ .k = "minute", .i = .{ .singular = "minute", .past = null, .present = "this minute", .future = null } },
        .{ .k = "hour", .i = .{ .singular = "hour", .past = null, .present = "this hour", .future = null } },
        .{ .k = "day", .i = .{ .singular = "day", .past = "yesterday", .present = "today", .future = "tomorrow" } },
        .{ .k = "week", .i = .{ .singular = "week", .past = "last week", .present = "this week", .future = "next week" } },
        .{ .k = "month", .i = .{ .singular = "month", .past = "last month", .present = "this month", .future = "next month" } },
        .{ .k = "quarter", .i = .{ .singular = "quarter", .past = "last quarter", .present = "this quarter", .future = "next quarter" } },
        .{ .k = "year", .i = .{ .singular = "year", .past = "last year", .present = "this year", .future = "next year" } },
    };
    for (table) |t| {
        if (std.mem.eql(u8, unit, t.k)) return t.i;
        // plural form: singular + "s"
        if (unit.len == t.k.len + 1 and std.mem.startsWith(u8, unit, t.k) and unit[unit.len - 1] == 's') return t.i;
    }
    return null;
}

/// The pieces of a relative-time result: either a single relative `term`
/// (numeric:"auto" for ±1/0) or a numeric phrase — a `prefix` literal, the
/// grouped number (`int_str`/`frac_str`, tagged with the singular `unit`), and
/// a `suffix` literal.
const RtfResult = struct {
    term: ?[]const u8 = null,
    prefix: []const u8 = "",
    int_str: []const u8 = "",
    frac_str: []const u8 = "",
    suffix: []const u8 = "",
    unit: []const u8 = "",
    group: []const u8 = ",",
    decimal: []const u8 = ".",
    numbering: []const u8 = "latn",
    min_group_digits: usize = 4,
};

/// en short/narrow relative-time unit names (singular/plural). Most units don't
/// pluralize ("sec."), but day/quarter do ("days"/"qtrs.").
fn rtfShortName(unit: []const u8, plural: bool) ?[]const u8 {
    const T = struct { k: []const u8, s: []const u8, p: []const u8 };
    const table = [_]T{
        .{ .k = "second", .s = "sec.", .p = "sec." },   .{ .k = "minute", .s = "min.", .p = "min." },
        .{ .k = "hour", .s = "hr.", .p = "hr." },       .{ .k = "day", .s = "day", .p = "days" },
        .{ .k = "week", .s = "wk.", .p = "wk." },       .{ .k = "month", .s = "mo.", .p = "mo." },
        .{ .k = "quarter", .s = "qtr.", .p = "qtrs." }, .{ .k = "year", .s = "yr.", .p = "yr." },
    };
    for (table) |t| if (std.mem.eql(u8, unit, t.k)) return if (plural) t.p else t.s;
    return null;
}

fn rtfPolishCategory(mag: f64) []const u8 {
    if (mag != @trunc(mag)) return "other";
    const n: u64 = @intFromFloat(@abs(mag));
    if (n == 1) return "one";
    const mod10 = n % 10;
    const mod100 = n % 100;
    if (mod10 >= 2 and mod10 <= 4 and !(mod100 >= 12 and mod100 <= 14)) return "few";
    return "many";
}

fn rtfPolishUnitName(unit: []const u8, style: []const u8, category: []const u8) ?[]const u8 {
    const short = std.mem.eql(u8, style, "short");
    const narrow = std.mem.eql(u8, style, "narrow");
    const C = struct { many: []const u8, few: []const u8, one: []const u8, other: []const u8 };
    const pick = struct {
        fn p(c: C, cat: []const u8) []const u8 {
            if (std.mem.eql(u8, cat, "one")) return c.one;
            if (std.mem.eql(u8, cat, "few")) return c.few;
            if (std.mem.eql(u8, cat, "other")) return c.other;
            return c.many;
        }
    }.p;
    if (short or narrow) {
        const table = [_]struct { u: []const u8, sh: C, na: C }{
            .{ .u = "second", .sh = .{ .many = "sek.", .few = "sek.", .one = "sek.", .other = "sek." }, .na = .{ .many = "s", .few = "s", .one = "s", .other = "s" } },
            .{ .u = "minute", .sh = .{ .many = "min", .few = "min", .one = "min", .other = "min" }, .na = .{ .many = "min", .few = "min", .one = "min", .other = "min" } },
            .{ .u = "hour", .sh = .{ .many = "godz.", .few = "godz.", .one = "godz.", .other = "godz." }, .na = .{ .many = "g.", .few = "g.", .one = "g.", .other = "g." } },
            .{ .u = "day", .sh = .{ .many = "dni", .few = "dni", .one = "dzień", .other = "dnia" }, .na = .{ .many = "dni", .few = "dni", .one = "dzień", .other = "dnia" } },
            .{ .u = "week", .sh = .{ .many = "tyg.", .few = "tyg.", .one = "tydz.", .other = "tyg." }, .na = .{ .many = "tyg.", .few = "tyg.", .one = "tydz.", .other = "tyg." } },
            .{ .u = "month", .sh = .{ .many = "mies.", .few = "mies.", .one = "mies.", .other = "mies." }, .na = .{ .many = "mies.", .few = "mies.", .one = "mies.", .other = "mies." } },
            .{ .u = "quarter", .sh = .{ .many = "kw.", .few = "kw.", .one = "kw.", .other = "kw." }, .na = .{ .many = "kw.", .few = "kw.", .one = "kw.", .other = "kw." } },
            .{ .u = "year", .sh = .{ .many = "lat", .few = "lata", .one = "rok", .other = "roku" }, .na = .{ .many = "lat", .few = "lata", .one = "rok", .other = "roku" } },
        };
        for (table) |t| if (std.mem.eql(u8, unit, t.u)) return pick(if (narrow) t.na else t.sh, category);
    } else {
        const table = [_]struct { u: []const u8, c: C }{
            .{ .u = "second", .c = .{ .many = "sekund", .few = "sekundy", .one = "sekundę", .other = "sekundy" } },
            .{ .u = "minute", .c = .{ .many = "minut", .few = "minuty", .one = "minutę", .other = "minuty" } },
            .{ .u = "hour", .c = .{ .many = "godzin", .few = "godziny", .one = "godzinę", .other = "godziny" } },
            .{ .u = "day", .c = .{ .many = "dni", .few = "dni", .one = "dzień", .other = "dnia" } },
            .{ .u = "week", .c = .{ .many = "tygodni", .few = "tygodnie", .one = "tydzień", .other = "tygodnia" } },
            .{ .u = "month", .c = .{ .many = "miesięcy", .few = "miesiące", .one = "miesiąc", .other = "miesiąca" } },
            .{ .u = "quarter", .c = .{ .many = "kwartałów", .few = "kwartały", .one = "kwartał", .other = "kwartału" } },
            .{ .u = "year", .c = .{ .many = "lat", .few = "lata", .one = "rok", .other = "roku" } },
        };
        for (table) |t| if (std.mem.eql(u8, unit, t.u)) return pick(t.c, category);
    }
    return null;
}

fn rtfCompute(self: *Interpreter, this: Value, args: []const Value) value.HostError!RtfResult {
    const valnum = try self.toNumberV(if (args.len > 0) args[0] else Value.undef());
    if (!std.math.isFinite(valnum)) return self.throwError("RangeError", "value must be finite");
    const unit_s = try self.toStringV(if (args.len > 1) args[1] else Value.undef());
    const info = rtfUnitInfo(unit_s) orelse return self.throwError("RangeError", try std.fmt.allocPrint(self.arena, "invalid unit '{s}'", .{unit_s}));

    var numeric: []const u8 = "always";
    var style: []const u8 = "long";
    if (this.asObj().getOwn("\x00opts")) |ov| if (ov.isObject()) {
        if (ov.asObj().getOwn("numeric")) |nv| if (nv.isString()) {
            numeric = nv.asStr();
        };
        if (ov.asObj().getOwn("style")) |sv| if (sv.isString()) {
            style = sv.asStr();
        };
    };
    const neg = std.math.signbit(valnum); // -0 formats as past

    if (std.mem.eql(u8, numeric, "auto") and valnum == @trunc(valnum) and @abs(valnum) <= 1) {
        if (valnum == 1) {
            if (info.future) |w| return .{ .term = w };
        } else if (valnum == -1) {
            if (info.past) |w| return .{ .term = w };
        } else {
            return .{ .term = info.present };
        }
    }

    const mag = @abs(valnum);
    const r = try nfRound(self, mag, false, 1, 0, 3, null, null, false, "auto", 1, "halfExpand");
    const plural = mag != 1;
    const locale = if (this.asObj().getOwn("\x00locale")) |lv| if (lv.isString()) lv.asStr() else "en" else "en";
    const syms = localeNumberSymbols(locale);
    const lang = localeLanguage(locale);
    const unit_name = if (std.mem.eql(u8, lang, "pl"))
        rtfPolishUnitName(info.singular, style, rtfPolishCategory(mag)) orelse info.singular
    else blk: {
        const short = std.mem.eql(u8, style, "short") or std.mem.eql(u8, style, "narrow");
        break :blk if (short and rtfShortName(info.singular, plural) != null)
            rtfShortName(info.singular, plural).?
        else if (plural)
            try std.fmt.allocPrint(self.arena, "{s}s", .{info.singular})
        else
            info.singular;
    };
    // en long patterns: future "in {0} <unit>", past "{0} <unit> ago".
    return .{
        .int_str = r.int_str,
        .frac_str = r.frac_str,
        .unit = info.singular,
        .prefix = if (std.mem.eql(u8, lang, "pl")) (if (neg) "" else "za ") else (if (neg) "" else "in "),
        .suffix = if (std.mem.eql(u8, lang, "pl"))
            (if (neg) try std.fmt.allocPrint(self.arena, " {s} temu", .{unit_name}) else try std.fmt.allocPrint(self.arena, " {s}", .{unit_name}))
        else
            (if (neg) try std.fmt.allocPrint(self.arena, " {s} ago", .{unit_name}) else try std.fmt.allocPrint(self.arena, " {s}", .{unit_name})),
        .group = syms.group,
        .decimal = syms.decimal,
        .numbering = resolveNumberingSystem(this),
        .min_group_digits = if (std.mem.eql(u8, lang, "pl")) 5 else 4,
    };
}

fn intlRelativeTimeFormatFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (!intlBrandOk(this, "RelativeTimeFormat")) return self.throwError("TypeError", "Intl.RelativeTimeFormat.prototype.format on incompatible receiver");
    const r = try rtfCompute(self, this, args);
    if (r.term) |t| return Value.str(t);
    var buf: std.ArrayListUnmanaged(u8) = .empty;
    try buf.appendSlice(self.arena, r.prefix);
    try buf.appendSlice(self.arena, try rtfTranslateNumber(self, try rtfGroup(self, r.int_str, r.group, r.min_group_digits), r.numbering));
    if (r.frac_str.len > 0) {
        try buf.appendSlice(self.arena, r.decimal);
        try buf.appendSlice(self.arena, try rtfTranslateNumber(self, r.frac_str, r.numbering));
    }
    try buf.appendSlice(self.arena, r.suffix);
    return Value.str(try buf.toOwnedSlice(self.arena));
}

/// Group an integer digit string every three digits.
fn rtfGroup(self: *Interpreter, int_str: []const u8, group: []const u8, min_group_digits: usize) EvalError![]const u8 {
    if (int_str.len < min_group_digits) return int_str;
    var buf: std.ArrayListUnmanaged(u8) = .empty;
    const first_group = int_str.len % 3;
    for (int_str, 0..) |c, i| {
        if (i != 0 and (i % 3) == first_group) try buf.appendSlice(self.arena, group);
        try buf.append(self.arena, c);
    }
    return buf.toOwnedSlice(self.arena);
}

fn rtfTranslateNumber(self: *Interpreter, s: []const u8, numbering: []const u8) EvalError![]const u8 {
    if (std.mem.eql(u8, numbering, "latn")) return s;
    return if (numbering_systems.digits(numbering)) |ds| try translateDigits(self, s, ds) else s;
}

fn intlRelativeTimeFormatToPartsFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (!intlBrandOk(this, "RelativeTimeFormat")) return self.throwError("TypeError", "Intl.RelativeTimeFormat.prototype.formatToParts on incompatible receiver");
    const r = try rtfCompute(self, this, args);
    const arr = (try self.newArray()).asObj();
    const addPart = struct {
        fn p(s: *Interpreter, a: *value.Object, typ: []const u8, v: []const u8, unit: ?[]const u8) EvalError!void {
            const o = (try s.newObject()).asObj();
            try s.setProp(o, "type", Value.str(typ));
            try s.setProp(o, "value", Value.str(v));
            if (unit) |u| try s.setProp(o, "unit", Value.str(try std.fmt.allocPrint(s.arena, "{s}", .{u})));
            try a.elements.append(a.elementsAllocator(s.arena), Value.obj(o));
        }
    }.p;
    if (r.term) |t| {
        try addPart(self, arr, "literal", t, null);
        return Value.obj(arr);
    }
    if (r.prefix.len > 0) try addPart(self, arr, "literal", r.prefix, null);
    // Number, split into integer/group parts, each tagged with the unit.
    const first_group = r.int_str.len % 3;
    var run: std.ArrayListUnmanaged(u8) = .empty;
    for (r.int_str, 0..) |c, i| {
        if (r.int_str.len >= r.min_group_digits and i != 0 and (i % 3) == first_group) {
            try addPart(self, arr, "integer", try rtfTranslateNumber(self, try run.toOwnedSlice(self.arena), r.numbering), r.unit);
            try addPart(self, arr, "group", r.group, r.unit);
            run = .empty;
        }
        try run.append(self.arena, c);
    }
    try addPart(self, arr, "integer", try rtfTranslateNumber(self, try run.toOwnedSlice(self.arena), r.numbering), r.unit);
    if (r.frac_str.len > 0) {
        try addPart(self, arr, "decimal", r.decimal, r.unit);
        try addPart(self, arr, "fraction", try rtfTranslateNumber(self, r.frac_str, r.numbering), r.unit);
    }
    if (r.suffix.len > 0) try addPart(self, arr, "literal", r.suffix, null);
    return Value.obj(arr);
}

fn intlResolvedOptionsFn(comptime service: []const u8) value.NativeFn {
    return struct {
        fn call(ctx: *anyopaque, this_recv: Value, args: []const Value) value.HostError!Value {
            _ = args;
            const self: *Interpreter = @ptrCast(@alignCast(ctx));
            const this = (try unwrapIntlThis(self, this_recv, service)) orelse return self.throwError("TypeError", "Intl." ++ service ++ ".prototype.resolvedOptions on incompatible receiver");
            const o = (try self.newObject()).asObj();
            const loc = this.asObj().getOwn("\x00locale") orelse Value.str("en");
            try self.setProp(o, "locale", loc);
            // The spec resolvedOptions field set (with default values) per
            // service. `numberingSystem` belongs to the number/date/plural
            // services, not Collator/ListFormat.
            if (comptime std.mem.eql(u8, service, "NumberFormat")) {
                // Reflect the explicitly-provided options over the spec defaults
                // (en-style; the basic/default case keeps the defaults).
                var style: []const u8 = "decimal";
                var min_int: f64 = 1;
                var min_frac: f64 = 0;
                var max_frac: f64 = 3;
                var grouping: Value = Value.str("auto");
                var sign_display: []const u8 = "auto";
                var currency: ?[]const u8 = null;
                var currency_display: []const u8 = "symbol";
                var notation: []const u8 = "standard";
                var compact_display: []const u8 = "short";
                var rounding_mode: []const u8 = "halfExpand";
                var rounding_priority: []const u8 = "auto";
                var trailing_zero: []const u8 = "auto";
                var rounding_increment: f64 = 1;
                // Reflect the resolved numbering system (option/-u-nu-/latn,
                // limited to systems we actually support).
                const numbering_system: []const u8 = resolveNumberingSystem(this);
                if (this.asObj().getOwn("\x00opts")) |ov| if (ov.isObject()) {
                    const nv = try self.getProperty(ov, "notation");
                    if (nv.isString()) notation = nv.asStr();
                    const cdv = try self.getProperty(ov, "compactDisplay");
                    if (cdv.isString()) compact_display = cdv.asStr();
                    const rmv = try self.getProperty(ov, "roundingMode");
                    if (rmv.isString()) rounding_mode = rmv.asStr();
                    const rpv = try self.getProperty(ov, "roundingPriority");
                    if (rpv.isString()) rounding_priority = rpv.asStr();
                    const tzv = try self.getProperty(ov, "trailingZeroDisplay");
                    if (tzv.isString()) trailing_zero = tzv.asStr();
                    const riv = try self.getProperty(ov, "roundingIncrement");
                    if (!riv.isUndefined()) rounding_increment = @trunc(try self.toNumberV(riv));
                    const sv = try self.getProperty(ov, "style");
                    if (sv.isString()) {
                        style = sv.asStr();
                        if (std.mem.eql(u8, style, "percent")) max_frac = 0;
                        if (std.mem.eql(u8, style, "currency")) {
                            const cv = try self.getProperty(ov, "currency");
                            currency = if (cv.isString()) try std.ascii.allocUpperString(self.arena, cv.asStr()) else "USD";
                            const cd = try self.getProperty(ov, "currencyDisplay");
                            if (cd.isString()) currency_display = cd.asStr();
                            if (std.mem.eql(u8, notation, "standard")) {
                                const dig: f64 = @floatFromInt(currencyInfo(currency.?).digits);
                                min_frac = dig;
                                max_frac = dig;
                            } else {
                                min_frac = 0;
                                max_frac = if (std.mem.eql(u8, notation, "compact")) 0 else 3;
                            }
                        }
                    }
                    const mi = try self.getProperty(ov, "minimumIntegerDigits");
                    if (!mi.isUndefined()) min_int = @max(1, @min(21, @trunc(try self.toNumberV(mi))));
                    const mnf = try self.getProperty(ov, "minimumFractionDigits");
                    if (!mnf.isUndefined()) {
                        min_frac = @max(0, @min(100, @trunc(try self.toNumberV(mnf))));
                        if (max_frac < min_frac) max_frac = min_frac;
                    }
                    const mxf = try self.getProperty(ov, "maximumFractionDigits");
                    if (!mxf.isUndefined()) {
                        max_frac = @max(0, @min(100, @trunc(try self.toNumberV(mxf))));
                        if (max_frac < min_frac) min_frac = max_frac;
                    }
                    const ug = try self.getProperty(ov, "useGrouping");
                    if (ug.isBoolean()) {
                        grouping = Value.boolVal(ug.asBool());
                    } else if (ug.isString()) {
                        grouping = Value.str(ug.asStr());
                    } else if (std.mem.eql(u8, notation, "compact")) {
                        grouping = Value.str("min2"); // compact default
                    }
                    const sd = try self.getProperty(ov, "signDisplay");
                    if (sd.isString()) sign_display = sd.asStr();
                };
                _ = numbering_system;
                // Resolve locale + numberingSystem from option and -u-nu- (the
                // reported values; formatting output stays option-only above).
                const nf_ns: ?[]const u8 = if (this.asObj().getOwn("\x00opts")) |ov| (if (ov.isObject()) (if (ov.asObj().getOwn("numberingSystem")) |n| (if (n.isString()) n.asStr() else null) else null) else null) else null;
                try intlResolveNumbering(self, o, loc.asStr(), nf_ns);
                try self.setProp(o, "style", Value.str(style));
                if (currency) |c| {
                    try self.setProp(o, "currency", Value.str(c));
                    try self.setProp(o, "currencyDisplay", Value.str(currency_display));
                    try self.setProp(o, "currencySign", Value.str("standard"));
                }
                if (std.mem.eql(u8, style, "unit")) {
                    if (this.asObj().getOwn("\x00opts")) |ov| if (ov.isObject()) {
                        if (ov.asObj().getOwn("unit")) |u| try self.setProp(o, "unit", u);
                        try self.setProp(o, "unitDisplay", ov.asObj().getOwn("unitDisplay") orelse Value.str("short"));
                    };
                }
                try self.setProp(o, "minimumIntegerDigits", Value.num(min_int));
                // Significant-digits resolution: with the default ("auto") rounding
                // priority a set of significant digits replaces the fraction
                // digits; morePrecision/lessPrecision reports both.
                const nfopts = this.asObj().getOwn("\x00opts");
                const sig_get = struct {
                    fn s(src: ?Value, k: []const u8) ?f64 {
                        if (src) |v| if (v.isObject()) if (v.asObj().getOwn(k)) |x| if (x.isNumber()) return x.asNum();
                        return null;
                    }
                }.s;
                const min_sig = sig_get(nfopts, "minimumSignificantDigits");
                const max_sig = sig_get(nfopts, "maximumSignificantDigits");
                const has_sig = min_sig != null or max_sig != null;
                const both = !std.mem.eql(u8, rounding_priority, "auto");
                if (!has_sig or both) {
                    try self.setProp(o, "minimumFractionDigits", Value.num(min_frac));
                    try self.setProp(o, "maximumFractionDigits", Value.num(max_frac));
                }
                if (has_sig) {
                    try self.setProp(o, "minimumSignificantDigits", Value.num(min_sig orelse 1));
                    try self.setProp(o, "maximumSignificantDigits", Value.num(max_sig orelse 21));
                }
                try self.setProp(o, "useGrouping", grouping);
                try self.setProp(o, "notation", Value.str(notation));
                if (std.mem.eql(u8, notation, "compact")) try self.setProp(o, "compactDisplay", Value.str(compact_display));
                try self.setProp(o, "signDisplay", Value.str(sign_display));
                try self.setProp(o, "roundingIncrement", Value.num(rounding_increment));
                try self.setProp(o, "roundingMode", Value.str(rounding_mode));
                try self.setProp(o, "roundingPriority", Value.str(rounding_priority));
                try self.setProp(o, "trailingZeroDisplay", Value.str(trailing_zero));
            } else if (comptime std.mem.eql(u8, service, "Collator")) {
                // Reflect the normalized options over the spec defaults, in the
                // resolvedOptions field order.
                const rv: ?Value = this.asObj().getOwn("\x00opts");
                const cget = struct {
                    fn s(src: ?Value, k: []const u8) ?Value {
                        if (src) |v| if (v.isObject()) if (v.asObj().getOwn(k)) |x| return x;
                        return null;
                    }
                }.s;
                // numeric/caseFirst resolve from option or the -u-kn/-u-kf
                // extension, and may rewrite the resolved locale.
                const opt_num: ?bool = if (cget(rv, "numeric")) |n| n.asBool() else null;
                const opt_kf: ?[]const u8 = if (cget(rv, "caseFirst")) |c| c.asStr() else null;
                const opt_co: ?[]const u8 = if (cget(rv, "collation")) |c| c.asStr() else null;
                const res = try collatorResolveLocale(self, o, loc.asStr(), opt_num, opt_kf, opt_co);
                try self.setProp(o, "usage", cget(rv, "usage") orelse Value.str("sort"));
                try self.setProp(o, "sensitivity", cget(rv, "sensitivity") orelse Value.str("variant"));
                // ignorePunctuation defaults from locale data: Thai ("th") is the
                // only locale whose CLDR default is true.
                const ip_default = blk: {
                    const lang = parseTriple(loc.asStr()).l;
                    break :blk std.mem.eql(u8, lang, "th");
                };
                try self.setProp(o, "ignorePunctuation", cget(rv, "ignorePunctuation") orelse Value.boolVal(ip_default));
                try self.setProp(o, "collation", Value.str(res.collation));
                try self.setProp(o, "numeric", Value.boolVal(res.numeric));
                try self.setProp(o, "caseFirst", Value.str(res.case_first));
            } else if (comptime std.mem.eql(u8, service, "PluralRules")) {
                // Spec key order: locale (set above), type, notation,
                // minimumIntegerDigits, then significant-OR-fraction digits,
                // pluralCategories, rounding*, trailingZeroDisplay. No
                // numberingSystem.
                const ro: ?Value = this.asObj().getOwn("\x00opts");
                const pg = struct {
                    fn s(src: ?Value, k: []const u8) ?Value {
                        if (src) |v| if (v.isObject()) if (v.asObj().getOwn(k)) |x| return x;
                        return null;
                    }
                }.s;
                try self.setProp(o, "type", pg(ro, "type") orelse Value.str("cardinal"));
                const pr_notation: []const u8 = if (pg(ro, "notation")) |n| n.asStr() else "standard";
                try self.setProp(o, "notation", Value.str(pr_notation));
                // compactDisplay is reported only when notation is "compact".
                if (std.mem.eql(u8, pr_notation, "compact")) {
                    try self.setProp(o, "compactDisplay", pg(ro, "compactDisplay") orelse Value.str("short"));
                }
                try self.setProp(o, "minimumIntegerDigits", Value.num(if (pg(ro, "minimumIntegerDigits")) |v| v.asNum() else 1));
                if (pg(ro, "minimumSignificantDigits") != null or pg(ro, "maximumSignificantDigits") != null) {
                    try self.setProp(o, "minimumSignificantDigits", Value.num(if (pg(ro, "minimumSignificantDigits")) |v| v.asNum() else 1));
                    try self.setProp(o, "maximumSignificantDigits", Value.num(if (pg(ro, "maximumSignificantDigits")) |v| v.asNum() else 21));
                } else {
                    const minf: f64 = if (pg(ro, "minimumFractionDigits")) |v| v.asNum() else 0;
                    var maxf: f64 = if (pg(ro, "maximumFractionDigits")) |v| v.asNum() else @max(minf, 3);
                    if (maxf < minf) maxf = minf;
                    try self.setProp(o, "minimumFractionDigits", Value.num(minf));
                    try self.setProp(o, "maximumFractionDigits", Value.num(maxf));
                }
                // pluralCategories: the categories the locale's rules define,
                // in CLDR order (zero, one, two, few, many, other).
                const cats = (try self.newArray()).asObj();
                const order = [_][]const u8{ "zero", "one", "two", "few", "many", "other" };
                const prules = pluralRulesFor(this);
                for (order) |cat| {
                    for (prules) |r| if (std.mem.eql(u8, r.cat, cat)) {
                        try cats.elements.append(cats.elementsAllocator(self.arena), Value.str(cat));
                        break;
                    };
                }
                try self.setProp(o, "pluralCategories", Value.obj(cats));
                try self.setProp(o, "roundingIncrement", pg(ro, "roundingIncrement") orelse Value.num(1));
                try self.setProp(o, "roundingMode", pg(ro, "roundingMode") orelse Value.str("halfExpand"));
                try self.setProp(o, "roundingPriority", pg(ro, "roundingPriority") orelse Value.str("auto"));
                try self.setProp(o, "trailingZeroDisplay", pg(ro, "trailingZeroDisplay") orelse Value.str("auto"));
            } else if (comptime std.mem.eql(u8, service, "DateTimeFormat")) {
                // Reflect the normalized options (stored under \x00opts at
                // construction) in the spec's resolvedOptions property order.
                const ro: ?Value = this.asObj().getOwn("\x00opts");
                const get = struct {
                    fn s(slf: *Interpreter, src: ?Value, k: []const u8) ?Value {
                        _ = slf;
                        if (src) |sv| if (sv.isObject()) if (sv.asObj().getOwn(k)) |v| return v;
                        return null;
                    }
                }.s;
                // The resolved locale (with surviving ca/hc/nu extensions) was
                // computed at construction.
                if (get(self, ro, "\x00rloc")) |rl| try self.setProp(o, "locale", rl);
                const cal = get(self, ro, "calendar");
                try self.setProp(o, "calendar", if (cal) |c| Value.str(c.asStr()) else Value.str("gregory"));
                const ns = get(self, ro, "numberingSystem");
                try self.setProp(o, "numberingSystem", if (ns) |c| Value.str(c.asStr()) else Value.str("latn"));
                const tz = get(self, ro, "timeZone");
                try self.setProp(o, "timeZone", if (tz) |c| Value.str(c.asStr()) else Value.str("UTC"));
                // Component / style fields are reflected only when set, in order.
                const has_style = get(self, ro, "dateStyle") != null or get(self, ro, "timeStyle") != null;
                const has_time = get(self, ro, "hour") != null or has_style;
                if (has_time) {
                    if (get(self, ro, "hourCycle")) |hc| {
                        try self.setProp(o, "hourCycle", hc);
                        try self.setProp(o, "hour12", Value.boolVal(std.mem.eql(u8, hc.asStr(), "h11") or std.mem.eql(u8, hc.asStr(), "h12")));
                    } else if (get(self, ro, "hour12")) |h| {
                        try self.setProp(o, "hour12", h);
                    }
                }
                inline for (.{ "weekday", "era", "year", "month", "day", "dayPeriod", "hour", "minute", "second", "fractionalSecondDigits", "timeZoneName", "dateStyle", "timeStyle" }) |k| {
                    if (get(self, ro, k)) |v| try self.setProp(o, k, v);
                }
            } else if (comptime std.mem.eql(u8, service, "RelativeTimeFormat")) {
                var style: []const u8 = "long";
                var numeric: []const u8 = "always";
                if (this.asObj().getOwn("\x00opts")) |ov| if (ov.isObject()) {
                    if (ov.asObj().getOwn("style")) |sv| if (sv.isString()) {
                        style = sv.asStr();
                    };
                    if (ov.asObj().getOwn("numeric")) |nv| if (nv.isString()) {
                        numeric = nv.asStr();
                    };
                };
                try self.setProp(o, "style", Value.str(style));
                try self.setProp(o, "numeric", Value.str(numeric));
                const rtf_ns: ?[]const u8 = if (this.asObj().getOwn("\x00opts")) |ov| (if (ov.isObject()) (if (ov.asObj().getOwn("numberingSystem")) |n| (if (n.isString()) n.asStr() else null) else null) else null) else null;
                try intlResolveNumbering(self, o, loc.asStr(), rtf_ns);
            } else if (comptime std.mem.eql(u8, service, "ListFormat")) {
                var typ: []const u8 = "conjunction";
                var style: []const u8 = "long";
                if (this.asObj().getOwn("\x00opts")) |ov| if (ov.isObject()) {
                    if (ov.asObj().getOwn("type")) |tv| if (tv.isString()) {
                        typ = tv.asStr();
                    };
                    if (ov.asObj().getOwn("style")) |sv| if (sv.isString()) {
                        style = sv.asStr();
                    };
                };
                try self.setProp(o, "type", Value.str(typ));
                try self.setProp(o, "style", Value.str(style));
            } else if (comptime std.mem.eql(u8, service, "DisplayNames")) {
                // Reflect the normalized record (locale, then the Table-6 order).
                const ro: ?Value = this.asObj().getOwn("\x00opts");
                if (ro) |rv| if (rv.isObject()) {
                    inline for (.{ "style", "type", "fallback", "languageDisplay" }) |k| {
                        if (rv.asObj().getOwn(k)) |val| try self.setProp(o, k, val);
                    }
                };
            } else if (comptime std.mem.eql(u8, service, "Segmenter")) {
                var granularity: []const u8 = "grapheme";
                if (this.asObj().getOwn("\x00opts")) |ov| if (ov.isObject()) {
                    if (ov.asObj().getOwn("granularity")) |g| granularity = g.asStr();
                };
                try self.setProp(o, "granularity", Value.str(granularity));
            } else if (comptime std.mem.eql(u8, service, "DurationFormat")) {
                const ro: ?Value = this.asObj().getOwn("\x00opts");
                const dget = struct {
                    fn s(src: ?Value, k: []const u8) ?Value {
                        if (src) |v| if (v.isObject()) if (v.asObj().getOwn(k)) |x| return x;
                        return null;
                    }
                }.s;
                const base = if (dget(ro, "style")) |st| st.asStr() else "short";
                try intlResolveNumbering(self, o, loc.asStr(), if (dget(ro, "numberingSystem")) |n| n.asStr() else null);
                try self.setProp(o, "style", Value.str(base));
                // Resolved per-unit style/display via GetDurationUnitOptions
                // (prevStyle cascade, digital defaults, 2-digit promotion).
                var styles: [10][]const u8 = undefined;
                var displays: [10][]const u8 = undefined;
                _ = durResolveUnits(ro, base, &styles, &displays);
                inline for (duration_units, 0..) |u, i| {
                    try self.setProp(o, u, Value.str(styles[i]));
                    try self.setProp(o, u ++ "Display", Value.str(displays[i]));
                }
                if (dget(ro, "fractionalDigits")) |fd| try self.setProp(o, "fractionalDigits", fd);
            }
            return Value.obj(o);
        }
    }.call;
}

fn intlSupportedLocalesOfFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    // CanonicalizeLocaleList(locales) first (throws on a structurally invalid tag).
    const arr = try canonicalizeLocaleList(self, if (args.len > 0) args[0] else Value.undef());
    // SupportedLocales: if options is not undefined, ToObject it (TypeError for
    // null) and validate the localeMatcher option (RangeError otherwise).
    if (args.len > 1 and !args[1].isUndefined()) {
        const opts: Value = Value.obj(try self.toObject(args[1]));
        const lm = try self.getProperty(opts, "localeMatcher");
        if (!lm.isUndefined()) {
            const s = try self.toStringV(lm);
            if (!std.mem.eql(u8, s, "lookup") and !std.mem.eql(u8, s, "best fit")) return self.throwError("RangeError", "invalid value for option localeMatcher");
        }
    }
    // Report requested locales as supported only when we have basic CLDR locale
    // data for the primary language.
    const out = (try self.newArray()).asObj();
    for (arr.elements.items) |lv| {
        if (!lv.isString()) continue;
        if (!intlLocaleSupported(lv.asStr())) continue;
        try out.elements.append(out.elementsAllocator(self.arena), lv);
    }
    return Value.obj(out);
}

/// Install the `Intl` namespace and its services.
fn installIntl(env: *Environment, rs: *Shape, object_proto: *value.Object) EvalError!void {
    const a = env.arena;
    const tag: ?[]const u8 = blk: {
        if (env.get("Symbol")) |sym| if (sym.isObject()) {
            if (sym.asObj().getOwn("toStringTag")) |t| if (t.isObject() and t.asObj().is_symbol) break :blk t.asObj().sym_key;
        };
        break :blk null;
    };
    const ns = try gc_mod.allocObj(a);
    ns.* = .{ .proto = object_proto };
    if (tag) |k| {
        try ns.setOwn(a, rs, k, Value.str("Intl"));
        try ns.setAttr(a, k, .{ .writable = false, .enumerable = false, .configurable = true });
    }
    try setNative(a, rs, ns, "getCanonicalLocales", 1, intlGetCanonicalLocalesFn);
    try setNative(a, rs, ns, "supportedValuesOf", 1, intlSupportedValuesOfFn);
    // %Intl%.[[FallbackSymbol]] — for the legacy "called as a function" chaining
    // of NumberFormat/DateTimeFormat/Collator onto an existing receiver. It gets
    // %Symbol.prototype% so its `description` accessor works.
    const sym_proto: ?*value.Object = blk: {
        if (env.get("Symbol")) |sv| if (sv.isObject()) if (sv.asObj().getOwn("prototype")) |p| if (p.isObject()) break :blk p.asObj();
        break :blk null;
    };
    try env.put("\x00IntlFallbackSym", try makeSymbolObj(a, rs, "IntlLegacyConstructedSymbol", sym_proto));

    // Helper to register one Intl service constructor with a prototype.
    const Svc = struct {
        fn install(self_a: std.mem.Allocator, shp: *Shape, e: *Environment, namespace: *value.Object, op: *value.Object, name: []const u8, arity: usize, ctor_fn: value.NativeFn, ttag: ?[]const u8) EvalError!*value.Object {
            const proto = try gc_mod.allocObj(self_a);
            proto.* = .{ .proto = op };
            const ctor = try gc_mod.allocObj(self_a);
            ctor.* = .{ .native = ctor_fn, .native_ctor = true };
            try installNativeProps(self_a, shp, ctor, name, arity);
            try setNative(self_a, shp, ctor, "supportedLocalesOf", 1, intlSupportedLocalesOfFn);
            try ctor.setOwn(self_a, shp, "prototype", Value.obj(proto));
            try ctor.setAttr(self_a, "prototype", .{ .writable = false, .enumerable = false, .configurable = false });
            try setConstructor(self_a, shp, proto, ctor);
            if (ttag) |k| {
                const full = std.fmt.allocPrint(self_a, "Intl.{s}", .{name}) catch name;
                try proto.setOwn(self_a, shp, k, Value.str(full));
                try proto.setAttr(self_a, k, .{ .writable = false, .enumerable = false, .configurable = true });
            }
            _ = e;
            try namespace.setOwn(self_a, shp, name, Value.obj(ctor));
            try namespace.setAttr(self_a, name, .{ .writable = true, .enumerable = false, .configurable = true });
            return proto;
        }
    };

    {
        const p = try Svc.install(a, rs, env, ns, object_proto, "NumberFormat", 0, intlServiceConstructorFn("NumberFormat"), tag);
        try installIntlFormat(a, rs, p, "NumberFormat", intlNumberFormatFn);
        try setNative(a, rs, p, "formatToParts", 1, intlNumberFormatToPartsFn);
        try setNative(a, rs, p, "formatRange", 2, intlNumberFormatRangeFn);
        try setNative(a, rs, p, "formatRangeToParts", 2, intlNumberFormatRangeToPartsFn);
        try setNative(a, rs, p, "resolvedOptions", 0, intlResolvedOptionsFn("NumberFormat"));
    }
    {
        const p = try Svc.install(a, rs, env, ns, object_proto, "DateTimeFormat", 0, intlServiceConstructorFn("DateTimeFormat"), tag);
        try setNative(a, rs, p, "resolvedOptions", 0, intlResolvedOptionsFn("DateTimeFormat"));
        try installIntlFormat(a, rs, p, "DateTimeFormat", intlDateTimeFormatFn);
        try setNative(a, rs, p, "formatToParts", 1, intlDateTimeFormatToPartsFn);
        try setNative(a, rs, p, "formatRange", 2, intlDateTimeFormatRangeFn);
        try setNative(a, rs, p, "formatRangeToParts", 2, intlDateTimeFormatRangeToPartsFn);
    }
    {
        const p = try Svc.install(a, rs, env, ns, object_proto, "Collator", 0, intlServiceConstructorFn("Collator"), tag);
        try installIntlCompare(a, rs, p, intlCollatorCompareFn);
        try setNative(a, rs, p, "resolvedOptions", 0, intlResolvedOptionsFn("Collator"));
    }
    {
        const p = try Svc.install(a, rs, env, ns, object_proto, "PluralRules", 0, intlServiceConstructorFn("PluralRules"), tag);
        try setNative(a, rs, p, "select", 1, intlPluralSelectFn);
        try setNative(a, rs, p, "selectRange", 2, intlPluralSelectRangeFn);
        try setNative(a, rs, p, "resolvedOptions", 0, intlResolvedOptionsFn("PluralRules"));
    }
    {
        const p = try Svc.install(a, rs, env, ns, object_proto, "ListFormat", 0, intlServiceConstructorFn("ListFormat"), tag);
        try setNative(a, rs, p, "format", 1, intlListFormatFn);
        try setNative(a, rs, p, "formatToParts", 1, intlListFormatToPartsFn);
        try setNative(a, rs, p, "resolvedOptions", 0, intlResolvedOptionsFn("ListFormat"));
    }
    {
        const p = try Svc.install(a, rs, env, ns, object_proto, "RelativeTimeFormat", 0, intlServiceConstructorFn("RelativeTimeFormat"), tag);
        try setNative(a, rs, p, "format", 2, intlRelativeTimeFormatFn);
        try setNative(a, rs, p, "formatToParts", 2, intlRelativeTimeFormatToPartsFn);
        try setNative(a, rs, p, "resolvedOptions", 0, intlResolvedOptionsFn("RelativeTimeFormat"));
    }
    {
        // Intl.DisplayNames is the one service constructor with length 2.
        const p = try Svc.install(a, rs, env, ns, object_proto, "DisplayNames", 2, intlServiceConstructorFn("DisplayNames"), tag);
        try setNative(a, rs, p, "of", 1, intlDisplayNamesOfFn);
        try setNative(a, rs, p, "resolvedOptions", 0, intlResolvedOptionsFn("DisplayNames"));
    }
    {
        const p = try Svc.install(a, rs, env, ns, object_proto, "Segmenter", 0, intlServiceConstructorFn("Segmenter"), tag);
        try setNative(a, rs, p, "resolvedOptions", 0, intlResolvedOptionsFn("Segmenter"));
        try setNative(a, rs, p, "segment", 1, intlSegmenterSegmentFn);
        // %Segments.prototype%: containing + [@@iterator].
        const seg_proto = try gc_mod.allocObj(a);
        seg_proto.* = .{ .proto = object_proto };
        try setNative(a, rs, seg_proto, "containing", 1, intlSegmentsContainingFn);
        const iter_key: ?[]const u8 = blk: {
            if (env.get("Symbol")) |sym| if (sym.isObject()) if (sym.asObj().getOwn("iterator")) |it| if (it.isObject() and it.asObj().is_symbol) break :blk it.asObj().sym_key;
            break :blk null;
        };
        if (iter_key) |sk| {
            try setNative(a, rs, seg_proto, sk, 0, intlSegmentsIteratorFn);
            // A symbol-keyed method's name is "[<description>]", not the internal key.
            if (seg_proto.getOwn(sk)) |mv| if (mv.isObject()) {
                try mv.asObj().setOwn(a, rs, "name", Value.str("[Symbol.iterator]"));
                try mv.asObj().setAttr(a, "name", .{ .writable = false, .enumerable = false, .configurable = true });
            };
        }
        try env.put("\x00SegmentsProto", Value.obj(seg_proto));
        // %SegmentIterator.prototype% (proto %IteratorPrototype%): next + tag.
        const seg_iter_proto = try gc_mod.allocObj(a);
        seg_iter_proto.* = .{ .proto = if (env.get("\x00IterProto")) |ip| (if (ip.isObject()) ip.asObj() else object_proto) else object_proto };
        try setNative(a, rs, seg_iter_proto, "next", 0, intlSegmentIterNextFn);
        if (tag) |k| {
            try seg_iter_proto.setOwn(a, rs, k, Value.str("Segmenter String Iterator"));
            try seg_iter_proto.setAttr(a, k, .{ .writable = false, .enumerable = false, .configurable = true });
        }
        try env.put("\x00SegIterProto", Value.obj(seg_iter_proto));
    }
    {
        const p = try Svc.install(a, rs, env, ns, object_proto, "DurationFormat", 0, intlServiceConstructorFn("DurationFormat"), tag);
        try setNative(a, rs, p, "format", 1, intlDurationFormatFn);
        try setNative(a, rs, p, "formatToParts", 1, intlDurationFormatToPartsFn);
        try setNative(a, rs, p, "resolvedOptions", 0, intlResolvedOptionsFn("DurationFormat"));
    }

    // Intl.Locale.
    {
        const proto = try gc_mod.allocObj(a);
        proto.* = .{ .proto = object_proto };
        try setNativeGetter(a, rs, proto, "baseName", intlLocaleGetter(.base_name));
        try setNativeGetter(a, rs, proto, "language", intlLocaleGetter(.language));
        try setNativeGetter(a, rs, proto, "script", intlLocaleGetter(.script));
        try setNativeGetter(a, rs, proto, "region", intlLocaleGetter(.region));
        try setNativeGetter(a, rs, proto, "variants", intlLocaleGetter(.variants));
        try setNativeGetter(a, rs, proto, "calendar", intlLocaleGetter(.calendar));
        try setNativeGetter(a, rs, proto, "caseFirst", intlLocaleGetter(.case_first));
        try setNativeGetter(a, rs, proto, "collation", intlLocaleGetter(.collation));
        try setNativeGetter(a, rs, proto, "hourCycle", intlLocaleGetter(.hour_cycle));
        try setNativeGetter(a, rs, proto, "numeric", intlLocaleGetter(.numeric));
        try setNativeGetter(a, rs, proto, "numberingSystem", intlLocaleGetter(.numbering_system));
        try setNativeGetter(a, rs, proto, "firstDayOfWeek", intlLocaleGetter(.first_day_of_week));
        try setNative(a, rs, proto, "toString", 0, intlLocaleToStringFn);
        try setNative(a, rs, proto, "maximize", 0, intlLocaleTransformFn(.max));
        try setNative(a, rs, proto, "minimize", 0, intlLocaleTransformFn(.min));
        try setNative(a, rs, proto, "getCalendars", 0, intlLocaleListFn(.calendars));
        try setNative(a, rs, proto, "getCollations", 0, intlLocaleListFn(.collations));
        try setNative(a, rs, proto, "getHourCycles", 0, intlLocaleListFn(.hour_cycles));
        try setNative(a, rs, proto, "getNumberingSystems", 0, intlLocaleListFn(.numbering_systems));
        try setNative(a, rs, proto, "getTimeZones", 0, intlLocaleTimeZonesFn);
        try setNative(a, rs, proto, "getTextInfo", 0, intlLocaleTextInfoFn);
        try setNative(a, rs, proto, "getWeekInfo", 0, intlLocaleWeekInfoFn);
        if (tag) |k| {
            try proto.setOwn(a, rs, k, Value.str("Intl.Locale"));
            try proto.setAttr(a, k, .{ .writable = false, .enumerable = false, .configurable = true });
        }
        const ctor = try gc_mod.allocObj(a);
        ctor.* = .{ .native = intlLocaleConstructorFn, .native_ctor = true };
        try installNativeProps(a, rs, ctor, "Locale", 1);
        try ctor.setOwn(a, rs, "prototype", Value.obj(proto));
        try ctor.setAttr(a, "prototype", .{ .writable = false, .enumerable = false, .configurable = false });
        try setConstructor(a, rs, proto, ctor);
        try ns.setOwn(a, rs, "Locale", Value.obj(ctor));
        try ns.setAttr(a, "Locale", .{ .writable = true, .enumerable = false, .configurable = true });
    }

    try env.put("Intl", Value.obj(ns));
}

// ===== SharedArrayBuffer =============================================

/// `new SharedArrayBuffer(byteLength, { maxByteLength }?)`.
fn sharedArrayBufferConstructorFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (self.new_target.isUndefined()) return self.throwError("TypeError", "Constructor SharedArrayBuffer requires 'new'");
    const len = try toIndexArg(self, if (args.len > 0) args[0] else Value.undef());
    var max: ?usize = null;
    if (args.len > 1 and args[1].isObject()) {
        const mv = try self.getProperty(args[1], "maxByteLength");
        if (!mv.isUndefined()) {
            const m = try toIndexArg(self, mv);
            if (m > 0x7fffffff or m < len) return self.throwError("RangeError", "Invalid maxByteLength");
            max = @intCast(m);
        }
    }
    // AllocateSharedArrayBuffer creates the object (including
    // GetPrototypeFromConstructor) before CreateByteDataBlock, so a throwing
    // newTarget.prototype getter wins over allocation/length RangeError.
    const proto = try self.protoFromCtor("SharedArrayBuffer");
    if (len > 0x7fffffff) return self.throwError("RangeError", "Invalid SharedArrayBuffer length");
    const storage = shared_buffer.SharedBufferStorage.create(@intCast(len), max) catch
        return self.throwError("RangeError", "SharedArrayBuffer allocation failed");
    const o = try makeSharedArrayBufferWrapper(self, storage);
    if (proto) |pr| o.setProtoAtomic(pr);
    return Value.obj(o);
}

fn sabGetter(comptime which: enum { byte_length, max_byte_length, growable }) value.NativeFn {
    return struct {
        fn call(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
            _ = args;
            const self: *Interpreter = @ptrCast(@alignCast(ctx));
            if (!this.isObject() or this.asObj().array_buffer == null or !this.asObj().array_buffer.?.is_shared)
                return self.throwError("TypeError", "SharedArrayBuffer.prototype accessor called on a non-SharedArrayBuffer");
            const ab = this.asObj().array_buffer.?;
            return switch (which) {
                .byte_length => Value.num(@floatFromInt(ab.bytes().len)),
                .max_byte_length => Value.num(@floatFromInt(ab.max_byte_length orelse ab.bytes().len)),
                .growable => Value.boolVal(ab.max_byte_length != null),
            };
        }
    }.call;
}

/// `SharedArrayBuffer.prototype.grow(newByteLength)` — increase the length (a
/// shared buffer can only grow, never shrink). Grows the process-wide storage
/// in place, so every realm's wrapper and every length-tracking view sees the
/// new length immediately.
fn sabGrowFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (!this.isObject() or this.asObj().array_buffer == null or !this.asObj().array_buffer.?.is_shared)
        return self.throwError("TypeError", "SharedArrayBuffer.prototype.grow called on a non-SharedArrayBuffer");
    const ab = this.asObj().array_buffer.?;
    if (ab.max_byte_length == null) return self.throwError("TypeError", "SharedArrayBuffer is not growable");
    const new_len = try toIndexArg(self, if (args.len > 0) args[0] else Value.undef());
    const storage = ab.shared orelse return self.throwError("TypeError", "SharedArrayBuffer is not growable");
    storage.grow(@intCast(new_len)) catch |err| return switch (err) {
        error.NotGrowable => self.throwError("TypeError", "SharedArrayBuffer is not growable"),
        error.OutOfRange => self.throwError("RangeError", "grow out of range"),
    };
    return Value.undef();
}

fn sharedArrayBufferSliceFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    return arrayBufferSliceImpl(@ptrCast(@alignCast(ctx)), this, args, true);
}

// ===== $262.agent (real OS-thread agents) ===========================
// test262's agent model: the main agent calls `$262.agent.start(src)` to spawn
// a worker agent running `src` in a fresh realm; they share memory through a
// SharedArrayBuffer handed over via `broadcast`, coordinate with `report`/
// `getReport`, and block/wake on `Atomics.wait`/`.notify`.
//
// `start` spawns the agent's OS thread immediately (src/agent.zig owns the
// group state, broadcast rendezvous, and the Atomics waiter table; the realm
// construction below stays here). Agents make progress while the main agent
// blocks or spins — the ordering the blocking-wait corpus requires and the
// old cooperative model could not express. Design: docs/threads/P2-agents.md.

/// `structuredClone(value, { transfer }?)` — the HTML structured-clone
/// algorithm over the engine's types (src/structured_clone.zig): a serialize/
/// deserialize round trip, so the IR doubles as the future worker
/// `postMessage` wire format. Transferred ArrayBuffers are moved (the clone
/// keeps the bytes, the source detaches).
fn structuredCloneFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const v = arg0(args);
    // Collect + validate the transfer list before serializing.
    var transfer: std.ArrayListUnmanaged(*value.Object) = .empty;
    if (args.len > 1 and !args[1].isUndefined() and !args[1].isNull()) {
        if (!args[1].isObject()) return self.throwError("TypeError", "structuredClone options must be an object");
        const tv = try self.getProperty(args[1], "transfer");
        if (!tv.isUndefined() and !tv.isNull()) {
            if (!tv.isObject() or !tv.asObj().is_array)
                return self.throwError("TypeError", "structuredClone transfer must be an array");
            for (tv.asObj().elements.items) |entry| {
                if (!entry.isObject() or entry.asObj().array_buffer == null)
                    return self.throwError("TypeError", "DataCloneError: only ArrayBuffers are transferable");
                const ab = entry.asObj().array_buffer.?;
                if (ab.is_shared) return self.throwError("TypeError", "DataCloneError: a SharedArrayBuffer is not transferable");
                if (ab.isDetached()) return self.throwError("TypeError", "DataCloneError: cannot transfer a detached ArrayBuffer");
                if (ab.immutable) return self.throwError("TypeError", "DataCloneError: cannot transfer an immutable ArrayBuffer");
                for (transfer.items) |seen| if (seen == entry.asObj())
                    return self.throwError("TypeError", "DataCloneError: duplicate transferable");
                try transfer.append(self.arena, entry.asObj());
            }
        }
    }
    const bytes = try structured_clone.serialize(self, self.arena, v);
    // The move: the clone owns a copy of the bytes; the sources detach now
    // (after a fully successful serialize, so a DataCloneError mid-graph
    // leaves the inputs untouched).
    for (transfer.items) |o| o.array_buffer.?.setDetached(true);
    return structured_clone.deserialize(self, bytes);
}

/// Wrap shared storage in a fresh SharedArrayBuffer object for *this* realm,
/// taking ownership of one reference (the caller's ref transfers in; it is
/// tracked in the realm's RetainList and released at realm teardown).
pub fn makeSharedArrayBufferWrapper(self: *Interpreter, storage: *shared_buffer.SharedBufferStorage) EvalError!*value.Object {
    var tracked = false;
    if (self.sab_retains) |rl| {
        try rl.track(storage); // on OOM, track released the ref
        tracked = true;
    }
    errdefer {
        if (tracked) if (self.sab_retains) |rl| {
            _ = rl.releaseTracked(storage);
        };
    }
    const o = (try self.newObject()).asObj();
    const ab = try self.allocArrayBufferData();
    errdefer self.destroyArrayBufferData(ab);
    ab.* = .{
        .local_data = &.{},
        .shared = storage,
        .gc_owned = self.gc_backing != null,
        .is_shared = true,
        .max_byte_length = if (storage.growable) storage.capacity else null,
    };
    o.array_buffer = ab;
    errdefer o.array_buffer = null;
    if (self.env.get("SharedArrayBuffer")) |c| if (c.isObject()) {
        o.setProtoAtomic(try self.protoObject(c.asObj()));
    };
    tracked = false;
    return o;
}

/// An agent's thread main: run `src` in a fresh realm on this (new) thread.
/// Matches `agent.RunFn`; src/agent.zig sets the thread's agent identity
/// before calling, so the `$262` install below skips the group reset.
fn agentThreadRun(src: []const u8) void {
    var arena_state = std.heap.ArenaAllocator.init(std.heap.page_allocator);
    defer arena_state.deinit();
    const a = arena_state.allocator();
    var env = Environment{ .arena = a, .fn_scope = true };
    const root_shape = Shape.createRoot(a) catch return;
    installGlobals(&env, root_shape) catch return;
    const global_obj = gc_mod.allocObj(a) catch return;
    global_obj.* = .{};
    env.put("globalThis", Value.obj(global_obj)) catch {};
    if (env.get("$262")) |d| if (d.isObject()) {
        d.asObj().setOwn(a, root_shape, "global", Value.obj(global_obj)) catch {};
    };
    const tdz = gc_mod.allocObj(a) catch return;
    tdz.* = .{};
    var microtasks = promise.MicrotaskQueue{};
    var print_buffer: std.ArrayListUnmanaged(u8) = .empty;
    // The agent realm's own SAB references (its receiveBroadcast wrapper);
    // released when the agent finishes, while the storage lives on via the
    // parent's and the broadcast slot's references.
    var sab_retains = shared_buffer.RetainList{ .gpa = std.heap.page_allocator };
    defer sab_retains.deinit();
    var async_waiters: std.ArrayListUnmanaged(AsyncWaiterEntry) = .empty;
    var machine = Interpreter{
        .arena = a,
        .env = &env,
        .global_object = global_obj,
        .this_value = Value.obj(global_obj),
        .root_shape = root_shape,
        .microtasks = &microtasks,
        .print_buffer = &print_buffer,
        .tdz_marker = tdz,
        .sab_retains = &sab_retains,
        .async_waiters = &async_waiters,
    };
    var parser = Parser.init(a, src) catch return;
    const prog = parser.parseProgram() catch return;
    machine.strict = parser.strict;
    if (Compiler.compileProgram(a, prog)) |chunk| {
        _ = vm.run(&machine, chunk, null) catch {};
    } else |_| {
        _ = machine.eval(prog) catch {};
    }
    machine.drainMicrotasks() catch {};
    machine.settleAsyncWaiters();
}

fn host262AgentStartFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const src = try self.toStringV(arg0(args));
    agent.start(src, agentThreadRun) catch return self.throwError("Error", "agent.start: could not spawn agent");
    return Value.undef();
}

/// The shared storage behind a SharedArrayBuffer or shared typed-array value.
fn sabStorageOf(v: Value) ?*shared_buffer.SharedBufferStorage {
    if (!v.isObject()) return null;
    const o = v.asObj();
    if (o.array_buffer) |ab| return ab.shared;
    if (o.typed_array) |ta| {
        const ab = ta.buffer.array_buffer orelse return null;
        return ab.shared;
    }
    return null;
}

fn host262AgentBroadcastFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const storage = sabStorageOf(arg0(args)) orelse return self.throwError("TypeError", "agent.broadcast expects a SharedArrayBuffer or shared TypedArray");
    // Publishes the storage, wakes every parked agent, and blocks until each
    // live agent has received it (the INTERPRETING.md rendezvous).
    agent.broadcast(storage);
    return Value.undef();
}

fn host262AgentReceiveBroadcastFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const cb = arg0(args);
    const storage = agent.parkUntilBroadcast() orelse return Value.undef();
    const sab = try makeSharedArrayBufferWrapper(self, storage);
    const out = try self.callValueWithThis(cb, &.{Value.obj(sab)}, Value.undef());
    _ = try self.awaitValue(out);
    return Value.undef();
}

fn host262AgentReportFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const s = try self.toStringV(arg0(args));
    agent.report(s);
    return Value.undef();
}

fn host262AgentGetReportFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    _ = args;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const r = agent.takeReport(self.arena) orelse return Value.nul(); // none available (harness polls)
    return Value.str(r);
}

fn host262AgentNoopFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = ctx;
    _ = this;
    _ = args;
    return Value.undef();
}

fn host262AgentSleepFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const ms = try self.toNumberV(arg0(args));
    agent.sleepMs(ms);
    return Value.undef();
}

fn host262AgentMonotonicNowFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = ctx;
    _ = this;
    _ = args;
    return Value.num(agent.monotonicNowMs());
}

/// Install `$262.agent` with the parent-side (start/broadcast/getReport) and
/// agent-side (receiveBroadcast/report/leaving) primitives.
fn installAgent(a: std.mem.Allocator, rs: *Shape, d: *value.Object) EvalError!void {
    const ag = try gc_mod.allocObj(a);
    ag.* = .{};
    try setNative(a, rs, ag, "start", 1, host262AgentStartFn);
    try setNative(a, rs, ag, "broadcast", 1, host262AgentBroadcastFn);
    try setNative(a, rs, ag, "getReport", 0, host262AgentGetReportFn);
    try setNative(a, rs, ag, "sleep", 1, host262AgentSleepFn);
    try setNative(a, rs, ag, "monotonicNow", 0, host262AgentMonotonicNowFn);
    try setNative(a, rs, ag, "receiveBroadcast", 1, host262AgentReceiveBroadcastFn);
    try setNative(a, rs, ag, "report", 1, host262AgentReportFn);
    try setNative(a, rs, ag, "leaving", 0, host262AgentNoopFn);
    try d.setOwn(a, rs, "agent", Value.obj(ag));
}

// ===== Atomics =======================================================

/// ValidateIntegerTypedArray: the receiver must be an integer typed array (not
/// a Float or Uint8Clamped view) over an attached buffer; returns the in-bounds
/// element index from ToIndex(request).
fn atomicsValidate(self: *Interpreter, ta_v: Value, idx_v: Value, write: bool, only_int32: bool, require_shared: bool) value.HostError!struct { ta: *value.TypedArrayData, i: usize } {
    if (!ta_v.isObject() or ta_v.asObj().typed_array == null) return self.throwError("TypeError", "Atomics operand must be an integer TypedArray");
    const ta = ta_v.asObj().typed_array.?;
    // ValidateIntegerTypedArray(typedArray, waitable): a waitable op
    // (wait/notify/waitAsync) only accepts Int32Array or BigInt64Array; the
    // kind check runs BEFORE the index is coerced to ToIndex.
    if (only_int32) {
        if (ta.kind != .i32 and ta.kind != .i64)
            return self.throwError("TypeError", "Typed array argument must be an Int32Array or BigInt64Array.");
    } else switch (ta.kind) {
        .i8, .u8, .i16, .u16, .i32, .u32, .i64, .u64 => {},
        else => return self.throwError("TypeError", "Typed array argument must be an Int8Array, Int16Array, Int32Array, Uint8Array, Uint16Array, Uint32Array, BigInt64Array, or BigUint64Array."),
    }
    // ValidateSharedIntegerTypedArray(true): `Atomics.wait` additionally
    // requires a SharedArrayBuffer, also checked before the index is coerced.
    if (require_shared and !ta.buffer.array_buffer.?.is_shared)
        return self.throwError("TypeError", "Typed array for wait/waitAsync/notify must wrap a SharedArrayBuffer.");
    // ValidateTypedArray(write): reject an immutable buffer before the index is
    // coerced (the value isn't coerced yet either).
    if (write and ta.buffer.array_buffer.?.immutable) return self.throwError("TypeError", "Atomics cannot write to an immutable ArrayBuffer");
    if (ta.buffer.array_buffer.?.isDetached()) return self.throwError("TypeError", "ArrayBuffer is detached");
    const i = try toIndexArg(self, idx_v);
    if (i >= ta.length) return self.throwError("RangeError", "Access index out of bounds for atomic access.");
    return .{ .ta = ta, .i = @intCast(i) };
}

/// Coerce an Atomics value argument per the element type (ToBigInt for BigInt
/// views, else ToIntegerOrInfinity).
fn atomicsCoerce(self: *Interpreter, ta: *value.TypedArrayData, v: Value) value.HostError!f64 {
    if (ta.kind.isBigInt()) {
        const bv = try self.toBigIntValueImpl(v, false);
        return @floatFromInt(@as(i64, @truncate(bv.asObj().bigint)));
    }
    // ToIntegerOrInfinity: NaN coerces to +0 and -0 normalizes to +0 (so the
    // value `Atomics.store` returns matches ToInteger, e.g. store(view,i,-0)===+0).
    const num = try self.toNumberV(v);
    if (std.math.isNan(num)) return 0;
    const t = @trunc(num);
    return if (t == 0) 0 else t;
}

fn atomicsReadV(self: *Interpreter, ta: *const value.TypedArrayData, i: usize) Value {
    if (ta.kind.isBigInt()) return self.makeBigInt(value.taReadBig(ta, i)) catch Value.undef();
    return value.taRead(ta, i);
}
fn atomicsWriteN(ta: *value.TypedArrayData, i: usize, n: f64) void {
    if (ta.kind.isBigInt()) value.taWriteBig(ta, i, @intFromFloat(n)) else value.taWrite(ta, i, n);
}

/// Coerce an Atomics value argument to the element's raw bits (the atomic
/// paths' counterpart of `atomicsCoerce`; routes BigInt views through i64
/// directly, preserving the 64-bit precision the f64 route loses).
fn atomicsCoerceRaw(self: *Interpreter, ta: *value.TypedArrayData, v: Value) value.HostError!u64 {
    if (ta.kind.isBigInt()) {
        const bv = try self.toBigIntValueImpl(v, false);
        return @bitCast(@as(i64, @truncate(bv.asObj().bigint)));
    }
    return value.taNumToRaw(ta.kind, try atomicsCoerce(self, ta, v));
}

/// The previous element value (raw bits) as the JS value an Atomics op returns.
fn atomicsRawToValue(self: *Interpreter, kind: value.TAKind, raw: u64) value.HostError!Value {
    if (kind == .i64) return self.makeBigInt(@as(i64, @bitCast(raw)));
    if (kind == .u64) return self.makeBigInt(@as(i128, raw));
    return Value.num(value.taRawToF64(kind, raw));
}

/// A read-modify-write Atomics op (`add`/`and`/`or`/`xor`/`sub`/`exchange`).
fn atomicsRMWFn(comptime op: enum { add, sub, and_, or_, xor, exchange }) value.NativeFn {
    return struct {
        fn call(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
            _ = this;
            const self: *Interpreter = @ptrCast(@alignCast(ctx));
            if (args.len > 0 and jsthread.isPropertyMode(self, args[0])) {
                if (op == .exchange) return jsthread.propExchange(self, args);
                const prop_op: jsthread.PropRmwOp = switch (op) {
                    .add => .add,
                    .sub => .sub,
                    .and_ => .and_,
                    .or_ => .or_,
                    .xor => .xor,
                    .exchange => unreachable,
                };
                return jsthread.propRmw(self, prop_op, args);
            }
            const vd = try atomicsValidate(self, if (args.len > 0) args[0] else Value.undef(), if (args.len > 1) args[1] else Value.undef(), true, false, false);
            const operand = try atomicsCoerceRaw(self, vd.ta, if (args.len > 2) args[2] else Value.undef());
            // One hardware RMW — agents racing over a SharedArrayBuffer can
            // never lose an update or observe a torn element.
            const old_raw = switch (op) {
                .add => value.taAtomicRmwRaw(.Add, vd.ta, vd.i, operand),
                .sub => value.taAtomicRmwRaw(.Sub, vd.ta, vd.i, operand),
                .and_ => value.taAtomicRmwRaw(.And, vd.ta, vd.i, operand),
                .or_ => value.taAtomicRmwRaw(.Or, vd.ta, vd.i, operand),
                .xor => value.taAtomicRmwRaw(.Xor, vd.ta, vd.i, operand),
                .exchange => value.taAtomicRmwRaw(.Xchg, vd.ta, vd.i, operand),
            };
            return atomicsRawToValue(self, vd.ta.kind, old_raw);
        }
    }.call;
}

fn atomicsLoadFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (args.len > 0 and jsthread.isPropertyMode(self, args[0])) return jsthread.propLoad(self, args);
    const vd = try atomicsValidate(self, if (args.len > 0) args[0] else Value.undef(), if (args.len > 1) args[1] else Value.undef(), false, false, false);
    return atomicsRawToValue(self, vd.ta.kind, value.taAtomicLoadRaw(vd.ta, vd.i));
}
fn atomicsStoreFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (args.len > 0 and jsthread.isPropertyMode(self, args[0])) return jsthread.propStore(self, args);
    const vd = try atomicsValidate(self, if (args.len > 0) args[0] else Value.undef(), if (args.len > 1) args[1] else Value.undef(), true, false, false);
    const arg_v = if (args.len > 2) args[2] else Value.undef();
    if (vd.ta.kind.isBigInt()) {
        const bv = try self.toBigIntValueImpl(arg_v, false);
        const as64: i64 = @truncate(bv.asObj().bigint);
        value.taAtomicStoreRaw(vd.ta, vd.i, @bitCast(as64));
        return self.makeBigInt(as64);
    }
    // store returns the *integer* value written, un-reduced (ToInteger, not
    // wrapped to the element width).
    const n = try atomicsCoerce(self, vd.ta, arg_v);
    value.taAtomicStoreRaw(vd.ta, vd.i, value.taNumToRaw(vd.ta.kind, n));
    return Value.num(n);
}
fn atomicsCompareExchangeFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (args.len > 0 and jsthread.isPropertyMode(self, args[0])) return jsthread.propCompareExchange(self, args);
    const vd = try atomicsValidate(self, if (args.len > 0) args[0] else Value.undef(), if (args.len > 1) args[1] else Value.undef(), true, false, false);
    const expected = try atomicsCoerceRaw(self, vd.ta, if (args.len > 2) args[2] else Value.undef());
    const replacement = try atomicsCoerceRaw(self, vd.ta, if (args.len > 3) args[3] else Value.undef());
    const old_raw = value.taAtomicCasRaw(vd.ta, vd.i, expected, replacement);
    return atomicsRawToValue(self, vd.ta.kind, old_raw);
}
fn atomicsIsLockFreeFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const n = try self.toNumberV(if (args.len > 0) args[0] else Value.undef());
    const sz = @trunc(n);
    return Value.boolVal(sz == 1 or sz == 2 or sz == 4 or sz == 8);
}
fn atomicsWaitFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (args.len > 0 and jsthread.isPropertyMode(self, args[0])) {
        const t_ms = if (args.len > 3) try self.toNumberV(args[3]) else std.math.nan(f64);
        const t_ns: ?u64 = if (std.math.isNan(t_ms) or t_ms == std.math.inf(f64)) null else if (t_ms <= 0) 0 else if (t_ms >= 1e12) null else @intFromFloat(t_ms * std.time.ns_per_ms);
        return jsthread.propWait(self, args, t_ns);
    }
    if (args.len > 0 and args[0].isObject() and args[0].asObj().typed_array != null and self.gil != null and jsthread.currentThreadId() != 0)
        return self.throwError("TypeError", "Atomics.wait cannot be called from the current thread.");
    const vd = try atomicsValidate(self, if (args.len > 0) args[0] else Value.undef(), if (args.len > 1) args[1] else Value.undef(), false, true, true);
    const expected_raw = try atomicsCoerceRaw(self, vd.ta, if (args.len > 2) args[2] else Value.undef());
    // ToNumber(timeout): NaN → wait forever; negative clamps to 0.
    const timeout_ms: f64 = if (args.len > 3) try self.toNumberV(args[3]) else std.math.nan(f64);
    const timeout_ns: ?u64 = if (std.math.isNan(timeout_ms) or timeout_ms == std.math.inf(f64))
        null
    else if (timeout_ms <= 0)
        0
    else if (timeout_ms >= 1e12)
        null // effectively unbounded; the runner watchdog is the backstop
    else
        @intFromFloat(timeout_ms * std.time.ns_per_ms);
    // AgentCanSuspend check runs after every coercion.
    if (!agent.canBlock(self.main_can_block)) return self.throwError("TypeError", "Atomics.wait cannot block this agent");
    const ab = vd.ta.buffer.array_buffer.?;
    const storage = ab.shared orelse return self.throwError("TypeError", "Atomics.wait requires a shared buffer");
    const offset = vd.ta.byte_offset + vd.i * vd.ta.kind.byteSize();
    // A GIL'd thread must not park holding the VM lock — its notifier needs
    // it to run. Publish a conservative scan range first so a mid-script
    // collection on another thread can root this parked stack (defers run LIFO:
    // reacquire the GIL, then mark unparked).
    const park_with_gil = self.use_thread_gil and self.gil != null;
    if (park_with_gil) stack_scan.beginPark();
    defer if (park_with_gil) stack_scan.endPark();
    if (park_with_gil) self.gil.?.release();
    defer if (park_with_gil) self.gil.?.acquire();
    const outcome = if (vd.ta.kind == .i64)
        agent.wait(storage, offset, i64, @bitCast(expected_raw), timeout_ns)
    else
        agent.wait(storage, offset, i32, @bitCast(@as(u32, @truncate(expected_raw))), timeout_ns);
    return Value.str(switch (outcome) {
        .ok => "ok",
        .not_equal => "not-equal",
        .timed_out => "timed-out",
    });
}
/// `Atomics.pause(N)` — a microarchitectural pause hint. `N`, if present, must
/// be an integral Number (the iteration count); anything else is a TypeError.
/// In this single-threaded engine there is nothing to spin on, so it is a
/// no-op that returns undefined after validating the argument.
fn atomicsPauseFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (args.len > 0 and !args[0].isUndefined()) {
        const n = args[0];
        if (!n.isNumber() or std.math.isNan(n.asNum()) or std.math.isInf(n.asNum()) or @trunc(n.asNum()) != n.asNum())
            return self.throwError("TypeError", "Atomics.pause iterationNumber must be an integer");
    }
    return Value.undef();
}
fn atomicsNotifyFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (args.len > 0 and jsthread.isPropertyMode(self, args[0])) return jsthread.propNotify(self, args);
    const vd = try atomicsValidate(self, if (args.len > 0) args[0] else Value.undef(), if (args.len > 1) args[1] else Value.undef(), false, true, false);
    // count: ToIntegerOrInfinity, default +∞, negatives clamp to 0.
    var count: usize = std.math.maxInt(usize);
    if (args.len > 2 and !args[2].isUndefined()) {
        const n = try self.toNumberV(args[2]);
        if (std.math.isNan(n) or n <= 0) {
            count = 0;
        } else if (n != std.math.inf(f64) and n < 1e18) {
            count = @intFromFloat(@trunc(n));
        }
    }
    // Waiters only ever exist on shared buffers; notify on a non-shared
    // integer view validly wakes nobody.
    const storage = vd.ta.buffer.array_buffer.?.shared orelse return Value.num(0);
    const offset = vd.ta.byte_offset + vd.i * vd.ta.kind.byteSize();
    return Value.num(@floatFromInt(agent.notify(storage, offset, count)));
}

/// `Atomics.waitAsync(typedArray, index, value, timeout)` — the non-blocking
/// form of `wait`. Like `wait`, DoWait runs ValidateSharedIntegerTypedArray, so
/// the buffer must be shared; in this single-threaded engine no other agent can
/// ever notify, so an actual wait yields a forever pending promise and the
/// early-out cases resolve synchronously.
fn atomicsWaitAsyncFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (args.len > 0 and jsthread.isPropertyMode(self, args[0])) {
        const t_ms = if (args.len > 3) try self.toNumberV(args[3]) else std.math.nan(f64);
        const t_ns: ?u64 = if (std.math.isNan(t_ms) or t_ms == std.math.inf(f64)) null else if (t_ms <= 0) 0 else if (t_ms >= 1e12) null else @intFromFloat(t_ms * std.time.ns_per_ms);
        return jsthread.propWaitAsync(self, args, t_ns);
    }
    const vd = try atomicsValidate(self, if (args.len > 0) args[0] else Value.undef(), if (args.len > 1) args[1] else Value.undef(), false, true, true);
    const expected_raw = try atomicsCoerceRaw(self, vd.ta, if (args.len > 2) args[2] else Value.undef());
    const timeout_ms: f64 = if (args.len > 3) try self.toNumberV(args[3]) else std.math.nan(f64);
    const timeout_ns: ?u64 = if (std.math.isNan(timeout_ms) or timeout_ms == std.math.inf(f64))
        null
    else if (timeout_ms <= 0)
        0
    else if (timeout_ms >= 1e12)
        null
    else
        @intFromFloat(timeout_ms * std.time.ns_per_ms);
    const ab = vd.ta.buffer.array_buffer.?;
    const storage = ab.shared orelse return self.throwError("TypeError", "Atomics.waitAsync requires a shared buffer");
    const offset = vd.ta.byte_offset + vd.i * vd.ta.kind.byteSize();
    const res = (try self.newObject()).asObj();
    // Register the async ticket (the value re-check and the timeout-0 early-out
    // both happen inside the waiter table's critical section).
    const enq = if (self.async_waiters == null)
        // No settle loop wired in this host: report "timed-out" synchronously
        // rather than minting a promise nothing will ever resolve.
        agent.AsyncEnqueue.timed_out
    else if (vd.ta.kind == .i64)
        agent.waitAsyncEnqueue(storage, offset, i64, @bitCast(expected_raw), timeout_ns, @ptrCast(self.async_waiters.?))
    else
        agent.waitAsyncEnqueue(storage, offset, i32, @bitCast(@as(u32, @truncate(expected_raw))), timeout_ns, @ptrCast(self.async_waiters.?));
    switch (enq) {
        .not_equal => {
            try self.setProp(res, "async", Value.boolVal(false));
            try self.setProp(res, "value", Value.str("not-equal"));
        },
        .timed_out => {
            try self.setProp(res, "async", Value.boolVal(false));
            try self.setProp(res, "value", Value.str("timed-out"));
        },
        .enqueued => |id| {
            const cap = try newPromiseCapability(self, self.env.get("Promise") orelse Value.undef());
            self.async_waiters.?.append(self.arena, .{ .id = id, .promise = cap.promise }) catch {
                agent.abandonAsync(@ptrCast(self.async_waiters.?));
                return error.OutOfMemory;
            };
            try self.setProp(res, "async", Value.boolVal(true));
            try self.setProp(res, "value", cap.promise);
        },
    }
    return Value.obj(res);
}

/// A typed-array constructor for `kind` (`new Int8Array(...)`, …).
fn typedArrayCtorFn(comptime kind: value.TAKind) value.NativeFn {
    return struct {
        fn call(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
            _ = this;
            const self: *Interpreter = @ptrCast(@alignCast(ctx));
            if (self.new_target.isUndefined()) return self.throwError("TypeError", "Constructor TypedArray requires 'new'");
            return self.makeTypedArray(kind, args);
        }
    }.call;
}

// ===== Module Namespace exotic object ===============================
// A `[[Module]]` namespace exposes its module's exported bindings as live,
// non-configurable, non-writable-by-the-spec-but-observably-writable data
// properties, sorted by code unit, plus `[Symbol.toStringTag] = "Module"`. It
// is non-extensible with a null prototype, and rejects [[Set]]/[[Delete]]/
// [[DefineOwnProperty]]/[[SetPrototypeOf]] (except no-op preserving cases).

pub const ModuleNs = struct {
    names: [][]const u8, // sorted export names (strings only)
    envs: []*Environment, // parallel: the env holding each binding
    locals: [][]const u8, // parallel: local binding name in that env
    tag_key: []const u8, // the @@toStringTag property key
    // `import defer * as ns`: until `defer_module` is evaluated, a *string*-keyed
    // operation (a binding [[Get]]/[[HasProperty]]/[[GetOwnProperty]]/[[Delete]]/
    // [[DefineOwnProperty]] or [[OwnPropertyKeys]]) triggers its evaluation first.
    // Symbol keys (incl. @@toStringTag), [[Set]], and the structural traps do not.
    deferred: bool = false,
    defer_module: ?*anyopaque = null, // *Context.Module, evaluated via defer_trigger
};

/// Trigger ModuleEvaluation of a deferred namespace's backing module (once — its
/// `evaluated` flag makes a repeat a no-op). Used by [[OwnPropertyKeys]], which
/// always triggers.
fn triggerDeferModule(self: *Interpreter, ns: *ModuleNs) EvalError!void {
    if (!ns.deferred) return;
    const mod = ns.defer_module orelse return;
    if (self.defer_trigger) |f| try f(self.defer_trigger_ctx.?, self, mod);
}

/// IsSymbolLikeNamespaceKey: a symbol/private key, or — on a *deferred*
/// namespace — the key "then" (so `await`-ing a deferred namespace neither
/// triggers evaluation nor reads an export). Such keys behave as absent.
fn isSymbolLikeNsKey(ns: *ModuleNs, key: []const u8) bool {
    return value.isSymbolKey(key) or value.isPrivateKey(key) or
        (ns.deferred and std.mem.eql(u8, key, "then"));
}

/// A deferred-namespace access of a *string* key triggers evaluation; a
/// symbol-like key (symbol/private, or "then") never does.
fn triggerDeferIfString(self: *Interpreter, ns: *ModuleNs, key: []const u8) EvalError!void {
    if (isSymbolLikeNsKey(ns, key)) return;
    try triggerDeferModule(self, ns);
}

/// Object-level wrappers for the builtin reflection paths (no-op unless `o` is a
/// deferred module namespace).
pub fn triggerDeferForKey(self: *Interpreter, o: *value.Object, key: []const u8) EvalError!void {
    if (moduleNsOf(o)) |ns| try triggerDeferIfString(self, ns, key);
}
pub fn triggerDeferForOwnKeys(self: *Interpreter, o: *value.Object) EvalError!void {
    if (moduleNsOf(o)) |ns| try triggerDeferModule(self, ns);
}

fn moduleNsOf(o: *value.Object) ?*ModuleNs {
    if (o.module_ns) |p| return @ptrCast(@alignCast(p));
    return null;
}

fn moduleNsIndex(ns: *ModuleNs, name: []const u8) ?usize {
    for (ns.names, 0..) |n, i| if (std.mem.eql(u8, n, name)) return i;
    return null;
}

/// [[Get]] for a module namespace: live binding read; an uninitialized (TDZ)
/// binding throws ReferenceError.
fn moduleNsGet(self: *Interpreter, ns: *ModuleNs, key: []const u8) EvalError!Value {
    if (std.mem.eql(u8, key, ns.tag_key)) return Value.str(if (ns.deferred) "Deferred Module" else "Module");
    // On a deferred namespace, "then" is symbol-like: it reads as absent
    // (OrdinaryGet), never the export binding — so it can't throw a TDZ error.
    if (ns.deferred and std.mem.eql(u8, key, "then")) return Value.undef();
    if (moduleNsIndex(ns, key)) |i| {
        const v = ns.envs[i].get(ns.locals[i]) orelse Value.undef();
        if (self.tdz_marker) |tz| if (v.isObject() and v.asObj() == tz)
            return self.throwError("ReferenceError", "Cannot access uninitialized binding");
        return v;
    }
    return Value.undef();
}

/// [[HasProperty]]: a string export, or the @@toStringTag key. On a deferred
/// namespace, "then" is symbol-like and reads as absent.
fn moduleNsHas(ns: *ModuleNs, key: []const u8) bool {
    if (ns.deferred and std.mem.eql(u8, key, "then")) return false;
    return std.mem.eql(u8, key, ns.tag_key) or moduleNsIndex(ns, key) != null;
}

pub fn isModuleNs(o: *value.Object) bool {
    return o.module_ns != null;
}

/// The string export names of a module namespace, sorted by code unit (for
/// Object.keys / getOwnPropertyNames). Empty slice for a non-namespace.
pub fn moduleNsNames(o: *value.Object) []const []const u8 {
    if (moduleNsOf(o)) |ns| return ns.names;
    return &.{};
}

/// `propertyIsEnumerable`-style flag: string exports are enumerable, the
/// @@toStringTag is not, an absent key is not.
pub fn moduleNsEnumerable(o: *value.Object, key: []const u8) bool {
    if (moduleNsOf(o)) |ns| return moduleNsIndex(ns, key) != null;
    return false;
}

/// [[GetOwnProperty]] for a module namespace as a descriptor object (or
/// undefined if the key is absent). A string export is { value (live, TDZ
/// throws), writable:true, enumerable:true, configurable:false }; the
/// @@toStringTag is a frozen string.
pub fn moduleNsDesc(self: *Interpreter, o: *value.Object, key: []const u8) EvalError!Value {
    const ns = moduleNsOf(o) orelse return Value.undef();
    // On a deferred namespace, "then" is symbol-like → absent (no descriptor).
    if (ns.deferred and std.mem.eql(u8, key, "then")) return Value.undef();
    if (std.mem.eql(u8, key, ns.tag_key)) {
        const d = (try self.newObject()).asObj();
        try self.setProp(d, "value", Value.str(if (ns.deferred) "Deferred Module" else "Module"));
        try self.setProp(d, "writable", Value.boolVal(false));
        try self.setProp(d, "enumerable", Value.boolVal(false));
        try self.setProp(d, "configurable", Value.boolVal(false));
        return Value.obj(d);
    }
    if (moduleNsIndex(ns, key) != null) {
        const v = try moduleNsGet(self, ns, key); // live read; TDZ throws ReferenceError
        const d = (try self.newObject()).asObj();
        try self.setProp(d, "value", v);
        try self.setProp(d, "writable", Value.boolVal(true));
        try self.setProp(d, "enumerable", Value.boolVal(true));
        try self.setProp(d, "configurable", Value.boolVal(false));
        return Value.obj(d);
    }
    return Value.undef();
}

pub fn installGlobals(env: *Environment, root_shape: *Shape) EvalError!void {
    return installGlobalsInner(env, root_shape, null);
}

/// `parent_symbol`, when non-null (a `$262.createRealm()` child realm), is the
/// creating realm's `Symbol` object: the well-known symbols are *shared* across
/// realms, so the child reuses those same symbol objects (identity holds across
/// realms) and keys all its `@@`-methods under them.
pub fn installGlobalsInner(env: *Environment, root_shape: *Shape, parent_symbol: ?*value.Object) EvalError!void {
    const a = env.arena;
    const error_names = [_][]const u8{
        "Error",           "TypeError", "RangeError", "ReferenceError",
        "SyntaxError",     "EvalError", "URIError",   "AggregateError",
        "SuppressedError",
    };
    for (error_names) |name| {
        const o = try gc_mod.allocObj(a);
        o.* = .{ .error_ctor = name, .private_data = @ptrCast(env) };
        // AggregateError(errors, message) has arity 2; SuppressedError(error,
        // suppressed, message) arity 3; the others (message) 1.
        const arity: usize = if (std.mem.eql(u8, name, "SuppressedError")) 3 else if (std.mem.eql(u8, name, "AggregateError")) 2 else 1;
        try installNativeProps(a, root_shape, o, name, arity);
        try env.put(name, Value.obj(o));
    }
    try env.put("NaN", Value.num(std.math.nan(f64)));
    try env.put("Infinity", Value.num(std.math.inf(f64)));
    try env.put("undefined", Value.undef());

    // Global functions.
    try defineGlobalFn(env, root_shape, "eval", 1, evalFn);
    if (env.get("eval")) |ev| {
        if (ev.isObject()) ev.asObj().private_data = @ptrCast(env);
    }
    try defineGlobalFn(env, root_shape, "parseInt", 2, builtins.parseIntFn);
    try defineGlobalFn(env, root_shape, "parseFloat", 1, builtins.parseFloatFn);
    try defineGlobalFn(env, root_shape, "structuredClone", 1, structuredCloneFn);
    try defineGlobalFn(env, root_shape, "isNaN", 1, builtins.isNaNFn);
    try defineGlobalFn(env, root_shape, "isFinite", 1, builtins.isFiniteFn);
    try defineGlobalFn(env, root_shape, "encodeURI", 1, builtins.encodeURIFn);
    try defineGlobalFn(env, root_shape, "encodeURIComponent", 1, builtins.encodeURIComponentFn);
    try defineGlobalFn(env, root_shape, "decodeURI", 1, builtins.decodeURIFn);
    try defineGlobalFn(env, root_shape, "decodeURIComponent", 1, builtins.decodeURIComponentFn);
    try defineGlobalFn(env, root_shape, "escape", 1, builtins.escapeFn);
    try defineGlobalFn(env, root_shape, "unescape", 1, builtins.unescapeFn);
    try defineGlobalFn(env, root_shape, "setTimeout", 2, setTimeoutFn);
    try defineGlobalFn(env, root_shape, "drainMicrotasks", 0, drainMicrotasksFn);
    try defineGlobalFn(env, root_shape, "$drainRunLoop", 0, drainRunLoopFn);
    try defineGlobalFn(env, root_shape, "noInline", 1, noInlineFn);
    try defineGlobalFn(env, root_shape, "gc", 0, gcFn);
    try defineGlobalFn(env, root_shape, "quit", 0, quitFn);
    try defineGlobalFnC(env, root_shape, "RegExp", 2, true, builtins.regExpFn);
    try installRegExpProto(env, root_shape);
    if (env.get("RegExp")) |re| {
        if (re.isObject()) try setNative(a, root_shape, re.asObj(), "escape", 1, regexpEscapeFn);
    }
    try defineGlobalFnC(env, root_shape, "Map", 0, true, builtins.mapFn);
    if (env.get("Map")) |m| {
        if (m.isObject()) try setNative(a, root_shape, m.asObj(), "groupBy", 2, mapGroupByFn);
    }
    try installMapProto(env, root_shape);
    try defineGlobalFnC(env, root_shape, "Set", 0, true, builtins.setFn);
    try installSetProto(env, root_shape);
    try defineGlobalFnC(env, root_shape, "WeakMap", 0, true, builtins.weakMapFn);
    try defineGlobalFnC(env, root_shape, "WeakSet", 0, true, builtins.weakSetFn);
    // WeakMap/WeakSet instances reuse the Map/Set internals (is_map/is_set), but
    // their prototypes are distinct and carry only the weak subset as real own
    // methods (so `typeof WeakMap.prototype.set === "function"`, `.call`, and
    // reflection work). No clear/forEach/iterators on the weak collections.
    if (env.get("WeakMap")) |wm| if (wm.isObject()) {
        if (wm.asObj().getOwn("prototype")) |pv| if (pv.isObject()) {
            inline for (.{ .{ "set", 2 }, .{ "get", 1 }, .{ "has", 1 }, .{ "delete", 1 }, .{ "getOrInsert", 2 }, .{ "getOrInsertComputed", 2 } }) |s|
                try setNative(a, root_shape, pv.asObj(), s[0], s[1], mapProtoMethod(s[0], true));
        };
    };
    if (env.get("WeakSet")) |ws| if (ws.isObject()) {
        if (ws.asObj().getOwn("prototype")) |pv| if (pv.isObject()) {
            inline for (.{ .{ "add", 1 }, .{ "has", 1 }, .{ "delete", 1 } }) |s|
                try setNative(a, root_shape, pv.asObj(), s[0], s[1], setProtoMethod(s[0], true));
        };
    };
    try defineGlobalFnC(env, root_shape, "Boolean", 1, true, builtins.booleanFn);
    try defineGlobalFn(env, root_shape, "print", 1, printFn);

    // Promise — constructor, prototype (then/catch/finally), and statics.
    const promise_proto = try gc_mod.allocObj(a);
    promise_proto.* = .{};
    if (env.get("Object")) |ov| if (ov.isObject()) {
        if (ov.asObj().getOwn("prototype")) |op| {
            if (op.isObject()) promise_proto.setProtoAtomic(op.asObj());
        }
    };
    try setNative(a, root_shape, promise_proto, "then", 2, promiseThenFn);
    try setNative(a, root_shape, promise_proto, "catch", 1, promiseCatchFn);
    try setNative(a, root_shape, promise_proto, "finally", 1, promiseFinallyFn);
    const promise_ns = try gc_mod.allocObj(a);
    promise_ns.* = .{ .native = promiseConstructorFn, .native_ctor = true, .private_data = @ptrCast(env) };
    try installNativeProps(a, root_shape, promise_ns, "Promise", 1);
    try setNative(a, root_shape, promise_ns, "resolve", 1, promiseResolveStaticFn);
    try setNative(a, root_shape, promise_ns, "reject", 1, promiseRejectStaticFn);
    try setNative(a, root_shape, promise_ns, "all", 1, promiseAllFn);
    try setNative(a, root_shape, promise_ns, "allSettled", 1, promiseAllSettledFn);
    try setNative(a, root_shape, promise_ns, "allKeyed", 1, promiseAllKeyedFn);
    try setNative(a, root_shape, promise_ns, "allSettledKeyed", 1, promiseAllSettledKeyedFn);
    try setNative(a, root_shape, promise_ns, "any", 1, promiseAnyFn);
    try setNative(a, root_shape, promise_ns, "race", 1, promiseRaceFn);
    try setNative(a, root_shape, promise_ns, "withResolvers", 0, promiseWithResolversFn);
    try setNative(a, root_shape, promise_ns, "try", 1, promiseTryFn);
    try promise_ns.setOwn(a, root_shape, "prototype", Value.obj(promise_proto));
    try promise_ns.setAttr(a, "prototype", .{ .writable = false, .enumerable = false, .configurable = false });
    try setConstructor(a, root_shape, promise_proto, promise_ns);
    try env.put("\x00Promise", Value.obj(promise_ns));
    try env.put("Promise", Value.obj(promise_ns));

    // String — callable, with statics.
    const string_ns = try gc_mod.allocObj(a);
    string_ns.* = .{ .native = builtins.stringFn, .native_ctor = true, .private_data = @ptrCast(env) };
    try installNativeProps(a, root_shape, string_ns, "String", 1);
    try setNative(a, root_shape, string_ns, "fromCharCode", 1, builtins.stringFromCharCode);
    try setNative(a, root_shape, string_ns, "fromCodePoint", 1, builtins.stringFromCodePoint);
    try setNative(a, root_shape, string_ns, "raw", 1, builtins.stringRaw);
    try env.put("String", Value.obj(string_ns));

    // Number — callable, with statics and constants.
    const number_ns = try gc_mod.allocObj(a);
    number_ns.* = .{ .native = builtins.numberFn, .native_ctor = true, .private_data = @ptrCast(env) };
    try installNativeProps(a, root_shape, number_ns, "Number", 1);
    try setNative(a, root_shape, number_ns, "isInteger", 1, builtins.numberIsInteger);
    try setNative(a, root_shape, number_ns, "isSafeInteger", 1, builtins.numberIsSafeInteger);
    try setNative(a, root_shape, number_ns, "isNaN", 1, builtins.numberIsNaN);
    try setNative(a, root_shape, number_ns, "isFinite", 1, builtins.numberIsFinite);
    if (env.get("parseFloat")) |pf| {
        try number_ns.setOwn(a, root_shape, "parseFloat", pf);
        try number_ns.setAttr(a, "parseFloat", .{ .enumerable = false, .configurable = true, .writable = true });
    }
    if (env.get("parseInt")) |pi| {
        try number_ns.setOwn(a, root_shape, "parseInt", pi);
        try number_ns.setAttr(a, "parseInt", .{ .enumerable = false, .configurable = true, .writable = true });
    }
    try number_ns.setOwn(a, root_shape, "MAX_SAFE_INTEGER", Value.num(9007199254740991));
    try number_ns.setOwn(a, root_shape, "MIN_SAFE_INTEGER", Value.num(-9007199254740991));
    try number_ns.setOwn(a, root_shape, "MAX_VALUE", Value.num(std.math.floatMax(f64)));
    try number_ns.setOwn(a, root_shape, "MIN_VALUE", Value.num(std.math.floatTrueMin(f64)));
    try number_ns.setOwn(a, root_shape, "EPSILON", Value.num(std.math.floatEps(f64)));
    try number_ns.setOwn(a, root_shape, "POSITIVE_INFINITY", Value.num(std.math.inf(f64)));
    try number_ns.setOwn(a, root_shape, "NEGATIVE_INFINITY", Value.num(-std.math.inf(f64)));
    try number_ns.setOwn(a, root_shape, "NaN", Value.num(std.math.nan(f64)));
    // The Number constants are { !writable, !enumerable, !configurable }.
    const frozen_attr: value.PropAttr = .{ .writable = false, .enumerable = false, .configurable = false };
    for ([_][]const u8{ "MAX_SAFE_INTEGER", "MIN_SAFE_INTEGER", "MAX_VALUE", "MIN_VALUE", "EPSILON", "POSITIVE_INFINITY", "NEGATIVE_INFINITY", "NaN" }) |n|
        try number_ns.setAttr(a, n, frozen_attr);
    try env.put("Number", Value.obj(number_ns));

    // JSON namespace.
    const json_ns = try gc_mod.allocObj(a);
    json_ns.* = .{};
    try setNative(a, root_shape, json_ns, "stringify", 3, builtins.jsonStringify);
    try setNative(a, root_shape, json_ns, "parse", 2, builtins.jsonParse);
    try setNative(a, root_shape, json_ns, "rawJSON", 1, builtins.jsonRawJSON);
    try setNative(a, root_shape, json_ns, "isRawJSON", 1, builtins.jsonIsRawJSON);
    try env.put("JSON", Value.obj(json_ns));

    // Math namespace.
    const math_obj = try gc_mod.allocObj(a);
    math_obj.* = .{};
    try setNative(a, root_shape, math_obj, "floor", 1, builtins.mathFloor);
    try setNative(a, root_shape, math_obj, "ceil", 1, builtins.mathCeil);
    try setNative(a, root_shape, math_obj, "round", 1, builtins.mathRound);
    try setNative(a, root_shape, math_obj, "trunc", 1, builtins.mathTrunc);
    try setNative(a, root_shape, math_obj, "abs", 1, builtins.mathAbs);
    try setNative(a, root_shape, math_obj, "sqrt", 1, builtins.mathSqrt);
    try setNative(a, root_shape, math_obj, "sign", 1, builtins.mathSign);
    try setNative(a, root_shape, math_obj, "pow", 2, builtins.mathPow);
    try setNative(a, root_shape, math_obj, "max", 2, builtins.mathMax);
    try setNative(a, root_shape, math_obj, "min", 2, builtins.mathMin);
    try setNative(a, root_shape, math_obj, "sin", 1, builtins.unaryMath(builtins.mfns.sin));
    try setNative(a, root_shape, math_obj, "cos", 1, builtins.unaryMath(builtins.mfns.cos));
    try setNative(a, root_shape, math_obj, "tan", 1, builtins.unaryMath(builtins.mfns.tan));
    try setNative(a, root_shape, math_obj, "asin", 1, builtins.unaryMath(builtins.mfns.asin));
    try setNative(a, root_shape, math_obj, "acos", 1, builtins.unaryMath(builtins.mfns.acos));
    try setNative(a, root_shape, math_obj, "atan", 1, builtins.unaryMath(builtins.mfns.atan));
    try setNative(a, root_shape, math_obj, "sinh", 1, builtins.unaryMath(builtins.mfns.sinh));
    try setNative(a, root_shape, math_obj, "cosh", 1, builtins.unaryMath(builtins.mfns.cosh));
    try setNative(a, root_shape, math_obj, "tanh", 1, builtins.unaryMath(builtins.mfns.tanh));
    try setNative(a, root_shape, math_obj, "asinh", 1, builtins.unaryMath(builtins.mfns.asinh));
    try setNative(a, root_shape, math_obj, "acosh", 1, builtins.unaryMath(builtins.mfns.acosh));
    try setNative(a, root_shape, math_obj, "atanh", 1, builtins.unaryMath(builtins.mfns.atanh));
    try setNative(a, root_shape, math_obj, "exp", 1, builtins.unaryMath(builtins.mfns.exp));
    try setNative(a, root_shape, math_obj, "expm1", 1, builtins.unaryMath(builtins.mfns.expm1));
    try setNative(a, root_shape, math_obj, "log", 1, builtins.unaryMath(builtins.mfns.log));
    try setNative(a, root_shape, math_obj, "log2", 1, builtins.unaryMath(builtins.mfns.log2));
    try setNative(a, root_shape, math_obj, "log10", 1, builtins.unaryMath(builtins.mfns.log10));
    try setNative(a, root_shape, math_obj, "log1p", 1, builtins.unaryMath(builtins.mfns.log1p));
    try setNative(a, root_shape, math_obj, "cbrt", 1, builtins.unaryMath(builtins.mfns.cbrt));
    try setNative(a, root_shape, math_obj, "fround", 1, builtins.unaryMath(builtins.mfns.fround));
    try setNative(a, root_shape, math_obj, "f16round", 1, builtins.unaryMath(builtins.mfns.f16round));
    try setNative(a, root_shape, math_obj, "sumPrecise", 1, builtins.mathSumPrecise);
    try setNative(a, root_shape, math_obj, "atan2", 2, builtins.mathAtan2);
    try setNative(a, root_shape, math_obj, "hypot", 2, builtins.mathHypot);
    try setNative(a, root_shape, math_obj, "clz32", 1, builtins.mathClz32);
    try setNative(a, root_shape, math_obj, "imul", 2, builtins.mathImul);
    try setNative(a, root_shape, math_obj, "random", 0, builtins.mathRandom);
    try math_obj.setOwn(a, root_shape, "PI", Value.num(std.math.pi));
    try math_obj.setOwn(a, root_shape, "E", Value.num(std.math.e));
    try math_obj.setOwn(a, root_shape, "LN2", Value.num(std.math.ln2));
    try math_obj.setOwn(a, root_shape, "LN10", Value.num(@log(@as(f64, 10))));
    try math_obj.setOwn(a, root_shape, "LOG2E", Value.num(std.math.log2e));
    try math_obj.setOwn(a, root_shape, "LOG10E", Value.num(std.math.log10e));
    try math_obj.setOwn(a, root_shape, "SQRT2", Value.num(std.math.sqrt2));
    try math_obj.setOwn(a, root_shape, "SQRT1_2", Value.num(1.0 / std.math.sqrt2));
    // The Math constants are { !writable, !enumerable, !configurable }.
    for ([_][]const u8{ "PI", "E", "LN2", "LN10", "LOG2E", "LOG10E", "SQRT2", "SQRT1_2" }) |n|
        try math_obj.setAttr(a, n, .{ .writable = false, .enumerable = false, .configurable = false });
    try env.put("Math", Value.obj(math_obj));

    // Object namespace.
    const object_ns = try gc_mod.allocObj(a);
    object_ns.* = .{ .native = builtins.objectConstructor, .native_ctor = true, .private_data = @ptrCast(env) };
    try installNativeProps(a, root_shape, object_ns, "Object", 1);
    try setNative(a, root_shape, object_ns, "keys", 1, builtins.objectKeys);
    try setNative(a, root_shape, object_ns, "values", 1, builtins.objectValues);
    try setNative(a, root_shape, object_ns, "assign", 2, builtins.objectAssign);
    try setNative(a, root_shape, object_ns, "create", 2, builtins.objectCreate);
    try setNative(a, root_shape, object_ns, "getPrototypeOf", 1, builtins.objectGetPrototypeOf);
    try setNative(a, root_shape, object_ns, "defineProperty", 3, builtins.objectDefineProperty);
    try setNative(a, root_shape, object_ns, "defineProperties", 2, builtins.objectDefineProperties);
    try setNative(a, root_shape, object_ns, "getOwnPropertyDescriptor", 2, builtins.objectGetOwnPropertyDescriptor);
    try setNative(a, root_shape, object_ns, "getOwnPropertyDescriptors", 1, builtins.objectGetOwnPropertyDescriptors);
    try setNative(a, root_shape, object_ns, "getOwnPropertyNames", 1, builtins.objectGetOwnPropertyNames);
    try setNative(a, root_shape, object_ns, "getOwnPropertySymbols", 1, builtins.objectGetOwnPropertySymbols);
    try setNative(a, root_shape, object_ns, "is", 2, builtins.objectIs);
    try setNative(a, root_shape, object_ns, "setPrototypeOf", 2, builtins.objectSetPrototypeOf);
    try setNative(a, root_shape, object_ns, "preventExtensions", 1, builtins.objectPreventExtensions);
    try setNative(a, root_shape, object_ns, "isExtensible", 1, builtins.objectIsExtensible);
    try setNative(a, root_shape, object_ns, "seal", 1, builtins.objectSeal);
    try setNative(a, root_shape, object_ns, "isSealed", 1, builtins.objectIsSealed);
    try setNative(a, root_shape, object_ns, "freeze", 1, builtins.objectFreeze);
    try setNative(a, root_shape, object_ns, "isFrozen", 1, builtins.objectIsFrozen);
    try setNative(a, root_shape, object_ns, "entries", 1, builtins.objectEntries);
    try setNative(a, root_shape, object_ns, "fromEntries", 1, builtins.objectFromEntries);
    try setNative(a, root_shape, object_ns, "groupBy", 2, objectGroupByFn);
    try setNative(a, root_shape, object_ns, "hasOwn", 2, builtins.objectHasOwn);
    try env.put("Object", Value.obj(object_ns));

    // Array namespace (callable constructor + isArray/of/from).
    const array_ns = try gc_mod.allocObj(a);
    array_ns.* = .{ .native = builtins.arrayConstructor, .native_ctor = true, .private_data = @ptrCast(env) };
    try installNativeProps(a, root_shape, array_ns, "Array", 1);
    try setNative(a, root_shape, array_ns, "isArray", 1, builtins.arrayIsArray);
    try setNativeWithData(a, root_shape, array_ns, "of", 0, builtins.arrayOf, @ptrCast(env));
    try setNativeWithData(a, root_shape, array_ns, "from", 1, builtins.arrayFrom, @ptrCast(env));
    try setNativeWithData(a, root_shape, array_ns, "fromAsync", 1, builtins.arrayFromAsync, @ptrCast(env));
    try env.put("Array", Value.obj(array_ns));

    // ---- Real prototype objects ----------------------------------------
    // Each holds its methods as properties (thunks routing to `builtinMethod`),
    // hung off the matching global constructor's `.prototype`. This makes
    // `Array.prototype.join`, `Object.prototype.hasOwnProperty`, and crucially
    // `Function.prototype.call.bind(...)` resolve — the patterns test262's
    // propertyHelper/verifyProperty (and many built-ins tests) depend on.
    const object_proto = try gc_mod.allocObj(a);
    object_proto.* = .{};
    try setConstructor(a, root_shape, object_proto, object_ns);
    const early_ctors = [_][]const u8{ "RegExp", "Map", "Set", "WeakMap", "WeakSet", "Boolean", "Promise" };
    for (early_ctors) |ctor_name| {
        if (env.get(ctor_name)) |cv| if (cv.isObject()) {
            if (cv.asObj().getOwn("prototype")) |pv| if (pv.isObject() and pv.asObj().proto == null) {
                pv.asObj().proto = object_proto;
            };
        };
    }
    try setProtoMethods(a, root_shape, object_proto, .{
        .{ "hasOwnProperty", 1 },   .{ "propertyIsEnumerable", 1 }, .{ "isPrototypeOf", 1 },
        .{ "valueOf", 0 },          .{ "__defineGetter__", 2 },     .{ "__defineSetter__", 2 },
        .{ "__lookupGetter__", 1 }, .{ "__lookupSetter__", 1 },
    });
    // `Object.prototype.toString` is the dedicated `[object Tag]` native (not the
    // kind-dispatched `toString`, so `Object.prototype.toString.call([])` gives
    // "[object Array]" while `[].toString()` still joins).
    try setNative(a, root_shape, object_proto, "toLocaleString", 0, objectProtoToLocaleStringFn);
    try setNative(a, root_shape, object_proto, "toString", 0, objectProtoToStringFn);
    // `Object.prototype.__proto__` accessor (the legacy prototype get/set).
    {
        const getter = try gc_mod.allocObj(a);
        getter.* = .{ .native = protoGetterFn };
        try installFunctionProps(a, root_shape, getter, &.{}, "get __proto__");
        const setter = try gc_mod.allocObj(a);
        setter.* = .{ .native = protoSetterFn };
        try installFunctionProps(a, root_shape, setter, &.{}, "set __proto__");
        try object_proto.setAccessor(a, "__proto__", Value.obj(getter), Value.obj(setter));
        try object_proto.setAttr(a, "__proto__", .{ .enumerable = false, .configurable = true });
    }
    try object_ns.setOwn(a, root_shape, "prototype", Value.obj(object_proto));
    try object_ns.setAttr(a, "prototype", .{ .writable = false, .enumerable = false, .configurable = false });
    try installDollarVM(env, root_shape, object_proto);

    // Error prototypes: `Error.prototype` carries name/message/constructor/toString
    // and protos to Object.prototype; each subclass (`TypeError.prototype`, …)
    // protos to `Error.prototype`. Instances are linked in `makeError`.
    const ro: value.PropAttr = .{ .enumerable = false, .configurable = true, .writable = true };
    const error_proto = try gc_mod.allocObj(a);
    error_proto.* = .{ .proto = object_proto };
    // The base `Error` constructor object, captured on the first iteration so the
    // NativeError constructors below can set it as their [[Prototype]] (spec:
    // `Object.getPrototypeOf(TypeError) === Error`).
    var error_ctor_obj: ?*value.Object = null;
    for (error_names) |ename| {
        const ctor_v = env.get(ename) orelse continue;
