    if (std.mem.eql(u8, cal, "hebrew")) return if (calInLeapYear(cal, year)) 6 else 0;
    if (std.mem.eql(u8, cal, "chinese") or std.mem.eql(u8, cal, "dangi")) {
        const LeapMonth = struct { y: i64, m: u8 };
