            .{ .y = 1984, .m = 11 }, .{ .y = 1987, .m = 7 },  .{ .y = 1990, .m = 6 },  .{ .y = 1993, .m = 4 },
            .{ .y = 1995, .m = 9 },  .{ .y = 1998, .m = 6 },  .{ .y = 2001, .m = 5 },  .{ .y = 2004, .m = 3 },
            .{ .y = 2006, .m = 8 },  .{ .y = 2009, .m = 6 },  .{ .y = 2012, .m = 5 },  .{ .y = 2014, .m = 10 },
            .{ .y = 2017, .m = 7 },  .{ .y = 2020, .m = 5 },  .{ .y = 2023, .m = 3 },  .{ .y = 2025, .m = 7 },
            .{ .y = 2028, .m = 6 },  .{ .y = 2031, .m = 4 },  .{ .y = 2033, .m = 12 }, .{ .y = 2036, .m = 7 },
            .{ .y = 2039, .m = 6 },  .{ .y = 2042, .m = 3 },  .{ .y = 2044, .m = 8 },  .{ .y = 2047, .m = 6 },
            .{ .y = 2050, .m = 6 },  .{ .y = 2099, .m = 12 },
        };
        const dangi = [_]LeapMonth{
            .{ .y = 1938, .m = 8 },  .{ .y = 1941, .m = 7 }, .{ .y = 1944, .m = 5 },  .{ .y = 1947, .m = 3 },
            .{ .y = 1952, .m = 6 },  .{ .y = 1955, .m = 4 }, .{ .y = 1957, .m = 9 },  .{ .y = 1960, .m = 7 },
            .{ .y = 1963, .m = 5 },  .{ .y = 1966, .m = 4 }, .{ .y = 1968, .m = 8 },  .{ .y = 1971, .m = 6 },
            .{ .y = 1974, .m = 5 },  .{ .y = 1976, .m = 9 }, .{ .y = 1979, .m = 7 },  .{ .y = 1982, .m = 5 },
            .{ .y = 1984, .m = 11 }, .{ .y = 1987, .m = 7 }, .{ .y = 1990, .m = 6 },  .{ .y = 1993, .m = 4 },
            .{ .y = 1995, .m = 9 },  .{ .y = 1998, .m = 6 }, .{ .y = 2001, .m = 5 },  .{ .y = 2004, .m = 3 },
            .{ .y = 2006, .m = 8 },  .{ .y = 2009, .m = 6 }, .{ .y = 2012, .m = 4 },  .{ .y = 2014, .m = 10 },
            .{ .y = 2017, .m = 6 },  .{ .y = 2020, .m = 5 }, .{ .y = 2023, .m = 3 },  .{ .y = 2025, .m = 7 },
            .{ .y = 2028, .m = 6 },  .{ .y = 2031, .m = 4 }, .{ .y = 2036, .m = 7 },  .{ .y = 2039, .m = 6 },
            .{ .y = 2042, .m = 3 },  .{ .y = 2044, .m = 8 }, .{ .y = 2033, .m = 12 }, .{ .y = 2047, .m = 6 },
            .{ .y = 2050, .m = 6 },
