fn temporalDateTimeFromFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const item = if (args.len > 0) args[0] else Value.undef();
    const options = if (args.len > 1) args[1] else Value.undef();
    const t = if (isObjectLike(item) and !isAnyTemporal(item)) blk: {
        const fields = try readPlainDateTimeBagFields(self, item);
        const reject = try readOverflowReject(self, options);
        break :blk try finishPlainDateTimeBagFields(self, fields, !reject);
    } else blk: {
        const parsed = try toPlainDateTimeData(self, item, true);
        _ = try readOverflowReject(self, options);
        break :blk parsed;
    };
    const o = try makeTemporal(self, .plain_date_time, "\x00T.PlainDateTime");
    o.temporal.?.* = t;
    o.temporal.?.kind = .plain_date_time;
    return Value.obj(o);
}

// ---- PlainDate conversions / diff -----------------------------------

fn temporalPlainDateUntilFn(comptime sign: f64) value.NativeFn {
    return struct {
        fn call(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
            const self: *Interpreter = @ptrCast(@alignCast(ctx));
            if (!tIsTemporal(this, .plain_date)) return self.throwError("TypeError", "non-PlainDate");
            const t = this.asObj().temporal.?;
            const b = try toPlainDateFields(self, if (args.len > 0) args[0] else Value.undef(), true);
            if (!temporalCalendarIdsEqual(t.calendar, b.cal)) return self.throwError("RangeError", "calendar mismatch");
            const opts = try readRoundOpts(self, if (args.len > 1) args[1] else Value.undef(), .{ .largest = .day, .smallest = .day, .mode = .trunc, .increment = 1 }, false);
            const largest = if (!opts.largest_set and @intFromEnum(opts.smallest) < @intFromEnum(TUnit.day)) opts.smallest else opts.largest;
            if (@intFromEnum(largest) > @intFromEnum(TUnit.day)) return self.throwError("RangeError", "PlainDate largestUnit cannot be a time unit");
            if (@intFromEnum(opts.smallest) > @intFromEnum(TUnit.day)) return self.throwError("RangeError", "PlainDate smallestUnit cannot be a time unit");
            if (!(@intFromEnum(opts.smallest) < @intFromEnum(TUnit.day) or opts.increment != 1)) {
                var dd = calendarDateDiff(t.calendar, t.year, t.month, t.day, b.y, b.m, b.d, largest);
                if (sign < 0) for (&dd) |*c| {
                    c.* = -c.*;
                };
                return makeDuration(self, dd);
            }
            const fwd = calendarEpochDay(t.calendar, t.year, t.month, t.day) <= calendarEpochDay(t.calendar, b.y, b.m, b.d);
            const e = if (fwd) IsoYMD{ .y = t.year, .m = t.month, .d = t.day } else b;
            const l = if (fwd) b else IsoYMD{ .y = t.year, .m = t.month, .d = t.day };
            var dd = calendarDateDiff(t.calendar, e.y, e.m, e.d, l.y, l.m, l.d, largest);
            const s2 = sign * (if (fwd) @as(f64, 1) else -1);
            const mode = if (s2 < 0) negateRoundMode(opts.mode) else opts.mode;
            const rel = if (opts.smallest == .month and switch (mode) {
                .half_ceil, .half_floor, .half_expand, .half_trunc, .half_even => true,
                else => false,
            }) IsoYMD{ .y = t.year, .m = t.month, .d = t.day } else e;
            dd = try roundDurationRel(self, dd, .{ .y = rel.y, .m = rel.m, .d = rel.d, .time_ns = 0 }, .{ .largest = largest, .smallest = opts.smallest, .mode = mode, .increment = opts.increment });
            if (s2 < 0) for (&dd) |*c| {
                c.* = -c.*;
            };
            return makeDuration(self, dd);
        }
    }.call;
}

