/// `Temporal.<Type>.prototype.valueOf` is a poison pill: it always throws, so a
/// Temporal value can never be implicitly converted with `<`/`>`/`+` (callers
/// must use `compare`/`equals`).
fn temporalValueOfFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    _ = args;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    return self.throwError("TypeError", "Called valueOf on a Temporal type; use compare() / equals() / a string conversion instead");
}

fn makeDurationFormatForLocaleString(self: *Interpreter, locales: Value, options: Value) value.HostError!*value.Object {
    const o = (try self.newObject()).asObj();
    try self.setProp(o, "\x00intl", Value.str("DurationFormat"));
    try o.setAttr(self.arena, "\x00intl", .{ .writable = false, .enumerable = false, .configurable = false });
    const locs = try canonicalizeLocaleList(self, locales);
    var resolved: []const u8 = "en";
    for (locs.elements.items) |lv| {
        if (lv.isString() and intlLocaleSupported(lv.asStr())) {
            resolved = lv.asStr();
            break;
        }
    }
    try self.setProp(o, "\x00locale", Value.str(resolved));
    try o.setAttr(self.arena, "\x00locale", .{ .writable = false, .enumerable = false, .configurable = false });

    if (!options.isUndefined() and !(options.isObject() and !options.asObj().is_symbol and !options.asObj().is_bigint))
        return self.throwError("TypeError", "options must be an object");
    const ro = (try self.newObject()).asObj();
    var base: []const u8 = "short";
    if (options.isObject()) {
        _ = try dtfGetStr(self, options, "localeMatcher", &.{ "lookup", "best fit" }, "best fit");
        if (try dtfGetType(self, options, "numberingSystem")) |ns| try self.setProp(ro, "numberingSystem", Value.str(ns));
        base = (try dtfGetStr(self, options, "style", &.{ "long", "short", "narrow", "digital" }, "short")).?;
        try self.setProp(ro, "style", Value.str(base));
        const time_units = [_][]const u8{ "hours", "minutes", "seconds" };
        inline for (duration_units) |u| {
            const is_time = for (time_units) |tu| {
                if (std.mem.eql(u8, u, tu)) break true;
            } else false;
            const allowed: []const []const u8 = if (is_time) &.{ "long", "short", "narrow", "numeric", "2-digit" } else &.{ "long", "short", "narrow", "numeric" };
            if (try dtfGetStr(self, options, u, allowed, null)) |v| try self.setProp(ro, u, Value.str(v));
            if (try dtfGetStr(self, options, u ++ "Display", &.{ "always", "auto" }, null)) |d| try self.setProp(ro, u ++ "Display", Value.str(d));
        }
        const fd = try self.getProperty(options, "fractionalDigits");
        if (!fd.isUndefined()) {
            const n = @trunc(try self.toNumberV(fd));
            if (std.math.isNan(n) or n < 0 or n > 9) return self.throwError("RangeError", "fractionalDigits out of range");
            try self.setProp(ro, "fractionalDigits", Value.num(n));
        }
    } else {
        try self.setProp(ro, "style", Value.str(base));
    }
    var styles: [10][]const u8 = undefined;
    var displays: [10][]const u8 = undefined;
    if (durResolveUnits(Value.obj(ro), base, &styles, &displays))
        return self.throwError("RangeError", "invalid duration unit style following a numeric unit");
    try self.setProp(o, "\x00opts", Value.obj(ro));
    try o.setAttr(self.arena, "\x00opts", .{ .writable = false, .enumerable = false, .configurable = false });
    return o;
}

/// `Temporal.<Type>.prototype.toLocaleString(locales, options)` via the local
/// Intl.DateTimeFormat implementation for Temporal date/time-like values.
fn temporalToLocaleStringFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (!this.isObject() or this.asObj().temporal == null) return self.throwError("TypeError", "toLocaleString called on a non-Temporal value");
    const t = this.asObj().temporal.?;
    if (t.kind != .duration) {
        const dtf = (try self.newObject()).asObj();
        try self.setProp(dtf, "\x00intl", Value.str("DateTimeFormat"));
        if (t.kind == .zoned_date_time)
            try self.setProp(dtf, "\x00allowTemporalZonedDateTime", Value.boolVal(true));
        const locs = try canonicalizeLocaleList(self, if (args.len > 0) args[0] else Value.undef());
        const loc = if (locs.elements.items.len > 0) locs.elements.items[0].asStr() else "en";
        try self.setProp(dtf, "\x00locale", Value.str(loc));
        if (t.kind == .zoned_date_time and args.len > 1 and !args[1].isUndefined()) {
            const raw = Value.obj(try self.toObject(args[1]));
            if (!(try self.getProperty(raw, "timeZone")).isUndefined())
                return self.throwError("TypeError", "Temporal.ZonedDateTime.prototype.toLocaleString does not accept a timeZone option");
        }
        var r = try dtfProcessOptionsKind(self, if (args.len > 1) args[1] else Value.undef(), .any, .all);
        const effective_calendar = blk: {
            const ext = try dtfResolveLocaleExt(self, loc, r.calendar, r.hour_cycle, r.hour12, r.numbering_system);
            break :blk ext.calendar;
        };
        if (t.kind == .plain_date or t.kind == .plain_month_day or t.kind == .plain_year_month) {
            if (r.time_style.len > 0)
                return self.throwError("TypeError", "Temporal toLocaleString does not accept timeStyle");
        }
        if (t.kind == .plain_time and r.date_style.len > 0)
            return self.throwError("TypeError", "Temporal.PlainTime.prototype.toLocaleString does not accept dateStyle");
        if (t.kind == .plain_date or t.kind == .plain_date_time or t.kind == .plain_month_day or t.kind == .plain_year_month) {
            const iso_ok = (t.kind == .plain_date or t.kind == .plain_date_time) and std.mem.eql(u8, t.calendar, "iso8601");
            if (!iso_ok and !std.mem.eql(u8, t.calendar, effective_calendar))
                return self.throwError("RangeError", "Temporal calendar does not match locale calendar");
        }
        if (t.kind == .zoned_date_time) {
            if (!std.mem.eql(u8, t.calendar, "iso8601") and !std.mem.eql(u8, t.calendar, effective_calendar))
                return self.throwError("RangeError", "Temporal.ZonedDateTime calendar does not match locale calendar");
            if (r.defaults_applied and r.time_zone_name.len == 0) r.time_zone_name = "short";
        }
        var explicit_hour_cycle = false;
        var explicit_hour_cycle_option = false;
        var explicit_hour12_false = false;
        if (args.len > 1 and !args[1].isUndefined()) {
            const raw = Value.obj(try self.toObject(args[1]));
            const h12 = try self.getProperty(raw, "hour12");
            const hc = try self.getProperty(raw, "hourCycle");
            explicit_hour_cycle_option = !hc.isUndefined();
            explicit_hour_cycle = !h12.isUndefined() or explicit_hour_cycle_option;
            explicit_hour12_false = !h12.isUndefined() and !h12.toBoolean();
        }
        const requested_english = args.len > 0 and args[0].isString() and (asciiEqlIgnoreCase(args[0].asStr(), "en") or
            (args[0].asStr().len > 3 and asciiEqlIgnoreCase(args[0].asStr()[0..2], "en") and args[0].asStr()[2] == '-'));
        const english_locale = requested_english or (loc.len == 2 and asciiEqlIgnoreCase(loc, "en")) or
            (loc.len > 3 and asciiEqlIgnoreCase(loc[0..2], "en") and loc[2] == '-');
        const temporal_default_time = !explicit_hour_cycle and english_locale and (r.hour.len > 0 or r.time_style.len > 0);
        if (temporal_default_time) {
            r.hour12 = true;
            r.hour_cycle = "h12";
        }
        try dtfStoreOptions(self, dtf, r);
        if (t.kind == .zoned_date_time and explicit_hour12_false and !explicit_hour_cycle_option) {
            if (dtf.getOwn("\x00opts")) |ov| if (ov.isObject()) {
                try self.setProp(ov.asObj(), "hourCycle", Value.str("h23"));
                try self.setProp(ov.asObj(), "hour12", Value.boolVal(false));
            };
        }
        if (temporal_default_time) if (dtf.getOwn("\x00opts")) |ov| if (ov.isObject()) {
            try self.setProp(ov.asObj(), "hour12", Value.boolVal(true));
            try self.setProp(ov.asObj(), "hourCycle", Value.str("h12"));
            try self.setProp(ov.asObj(), "\x00temporalDefaultHour12", Value.boolVal(true));
        };
        return try intlDateTimeFormatFn(@ptrCast(self), Value.obj(dtf), &.{this});
    }
    const df = try makeDurationFormatForLocaleString(self, if (args.len > 0) args[0] else Value.undef(), if (args.len > 1) args[1] else Value.undef());
    return try intlDurationFormatFn(@ptrCast(self), Value.obj(df), &.{this});
}

/// ToTemporalCalendarSlotValue, restricted to the only supported calendar
/// (iso8601): a Temporal instance contributes its own calendar; any other value
/// is `ToString`'d and must name `iso8601`, else a RangeError.
fn requireIsoCalendarArg(self: *Interpreter, v: Value) value.HostError!void {
    if (v.isObject() and v.asObj().temporal != null) return; // a Temporal instance is iso8601 here
    // ToTemporalCalendarIdentifier: a non-object non-String is a TypeError.
    if (!v.isString()) return self.throwError("TypeError", "calendar must be a string or a Temporal object");
    const s = v.asStr();
    if (asciiEqlIgnoreCase(s, "iso8601")) return; // a bare calendar id
    // Otherwise the string is a Temporal date/time string whose calendar
    // annotation (default iso8601) must resolve to iso8601.
    _ = stripTemporalAnnotations(self, s) catch return self.throwError("RangeError", "invalid calendar string");
}

fn temporalPlainDateWithCalendarFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (!tIsTemporal(this, .plain_date)) return self.throwError("TypeError", "non-PlainDate");
    const cal = try toCalendarId(self, if (args.len > 0) args[0] else Value.undef(), true);
    const t = this.asObj().temporal.?;
    const iso = calendarDateToIso(t.calendar, t.year, t.month, t.day);
    const cd = calendarDateFromIso(cal, iso.y, iso.m, iso.d);
    const o = try makeTemporal(self, .plain_date, "\x00T.PlainDate");
    o.temporal.?.year = @intCast(cd.y);
    o.temporal.?.month = cd.m;
    o.temporal.?.day = cd.d;
    o.temporal.?.calendar = cal;
    return Value.obj(o);
}

fn temporalDateTimeWithCalendarFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (!tIsTemporal(this, .plain_date_time)) return self.throwError("TypeError", "non-PlainDateTime");
    const cal = try toCalendarId(self, if (args.len > 0) args[0] else Value.undef(), true);
    const t = this.asObj().temporal.?;
    const iso = calendarDateToIso(t.calendar, t.year, t.month, t.day);
    const cd = calendarDateFromIso(cal, iso.y, iso.m, iso.d);
    const o = try makeTemporal(self, .plain_date_time, "\x00T.PlainDateTime");
    o.temporal.?.* = t.*;
    o.temporal.?.year = @intCast(cd.y);
    o.temporal.?.month = cd.m;
    o.temporal.?.day = cd.d;
    o.temporal.?.calendar = cal;
    return Value.obj(o);
}

/// Nanoseconds since the Unix epoch for a local date+time (no time-zone offset
/// applied) held in `t`'s year/month/day + hour/.../nanosecond fields.
fn dtLocalNs(t: *const value.TemporalData) i128 {
    return @as(i128, tDaysFromCivil(t.year, t.month, t.day)) * 86_400_000_000_000 +
        @as(i128, t.hour) * 3_600_000_000_000 +
        @as(i128, t.minute) * 60_000_000_000 +
        @as(i128, t.second) * 1_000_000_000 +
        @as(i128, t.millisecond) * 1_000_000 +
        @as(i128, t.microsecond) * 1_000 +
        @as(i128, t.nanosecond);
}

/// ToTemporalTimeZoneSlotValue restricted to fixed-offset / named zones: a
/// ZonedDateTime contributes its own zone; otherwise `ToString` then `parseTimeZone`.
fn resolveTimeZoneArg(self: *Interpreter, v: Value) value.HostError!TimeZone {
    if (v.isObject()) if (v.asObj().temporal) |t| if (t.kind == .zoned_date_time)
        return TimeZone{ .name = t.tz_name, .offset_ns = t.tz_offset_ns };
    if (!v.isString()) return self.throwError("TypeError", "invalid timeZone");
    return parseTimeZone(self, v.asStr());
}

/// `Temporal.PlainDateTime.prototype.toZonedDateTime(timeZone, options)`.
fn temporalDateTimeToZonedDateTimeFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (!tIsTemporal(this, .plain_date_time)) return self.throwError("TypeError", "non-PlainDateTime");
    if (args.len == 0 or args[0].isUndefined()) return self.throwError("TypeError", "toZonedDateTime requires a time zone");
    const tz = try resolveTimeZoneArg(self, args[0]);
    // GetTemporalDisambiguationOption (validated even though fixed-offset zones
    // ignore it — an invalid value must still throw).
    var disambiguation = ZdtDisambiguation.compatible;
    if (args.len > 1 and !args[1].isUndefined()) {
        if (!isObjectLike(args[1])) return self.throwError("TypeError", "options must be an object");
        disambiguation = try readZdtDisambiguation(self, args[1]);
    }
    const t = this.asObj().temporal.?;
    const iso = calendarDateToIso(t.calendar, t.year, t.month, t.day);
    const local = @as(i128, tDaysFromCivil(iso.y, iso.m, iso.d)) * DAY_NS + timeToNs(t);
    const offset = if (isFixedTimeZone(tz)) tz.offset_ns else try zdtOffsetForLocalDisambiguation(self, tz, local, disambiguation);
    const o = try zdtMake(self, local - @as(i128, offset), tz.name, tz.offset_ns);
    o.asObj().temporal.?.* = t.*;
    o.asObj().temporal.?.kind = .zoned_date_time;
    o.asObj().temporal.?.epoch_ns = local - @as(i128, offset);
    o.asObj().temporal.?.tz_name = tz.name;
    o.asObj().temporal.?.tz_offset_ns = tz.offset_ns;
    return o;
}

/// `Temporal.PlainDate.prototype.toZonedDateTime(item)` — `item` is a time-zone
/// (string/ZonedDateTime) or a `{ timeZone, plainTime }` bag (default midnight).
fn temporalDateToZonedDateTimeFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (!tIsTemporal(this, .plain_date)) return self.throwError("TypeError", "non-PlainDate");
    const item = if (args.len > 0) args[0] else Value.undef();
    var tz: TimeZone = undefined;
    var time = value.TemporalData{ .kind = .plain_time }; // midnight
    var has_explicit_time = false;
    if (item.isObject() and (item.asObj().temporal == null or item.asObj().temporal.?.kind != .zoned_date_time)) {
        // A bag: { timeZone (required), plainTime (optional) }.
        const tzv = try self.getProperty(item, "timeZone");
        if (tzv.isUndefined()) return self.throwError("TypeError", "toZonedDateTime: missing timeZone");
        tz = try resolveTimeZoneArg(self, tzv);
        const ptv = try self.getProperty(item, "plainTime");
        if (!ptv.isUndefined()) {
            has_explicit_time = true;
            time = try toPlainTimeData(self, ptv);
        }
    } else {
        if (item.isUndefined()) return self.throwError("TypeError", "toZonedDateTime requires a time zone");
        tz = try resolveTimeZoneArg(self, item);
    }
    const d = this.asObj().temporal.?;
    const iso_date = calendarDateToIso(d.calendar, d.year, d.month, d.day);
    if (!has_explicit_time) {
        if (skippedMidnightStartEpoch(tz.name, iso_date.y, iso_date.m, iso_date.d)) |epoch|
            return zdtMakeWithCalendar(self, epoch, tz.name, tz.offset_ns, d.calendar);
    }
    var combined = value.TemporalData{ .kind = .plain_date_time };
    combined.year = d.year;
    combined.month = d.month;
    combined.day = d.day;
    combined.hour = time.hour;
    combined.minute = time.minute;
    combined.second = time.second;
    combined.millisecond = time.millisecond;
    combined.microsecond = time.microsecond;
    combined.nanosecond = time.nanosecond;
    const local = @as(i128, tDaysFromCivil(iso_date.y, iso_date.m, iso_date.d)) * DAY_NS + timeToNs(&combined);
    const o = try zdtMake(self, local - @as(i128, tz.offset_ns), tz.name, tz.offset_ns);
    const out = o.asObj().temporal.?;
    out.year = d.year;
    out.month = d.month;
    out.day = d.day;
    out.hour = time.hour;
    out.minute = time.minute;
    out.second = time.second;
    out.millisecond = time.millisecond;
    out.microsecond = time.microsecond;
    out.nanosecond = time.nanosecond;
    out.calendar = d.calendar;
    return o;
}

/// `Temporal.Instant.prototype.toZonedDateTimeISO(timeZone)`.
fn temporalInstantToZonedDateTimeISOFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (!tIsTemporal(this, .instant)) return self.throwError("TypeError", "non-Instant");
    if (args.len == 0 or args[0].isUndefined()) return self.throwError("TypeError", "toZonedDateTimeISO requires a time zone");
    const tz = try resolveTimeZoneArg(self, args[0]);
    return zdtMake(self, this.asObj().temporal.?.epoch_ns, tz.name, tz.offset_ns);
}

fn temporalDateToMonthDayFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = args;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (!tIsTemporal(this, .plain_date)) return self.throwError("TypeError", "non-PlainDate");
    const t = this.asObj().temporal.?;
    return makeMonthDay(self, monthDayReferenceYearForConversion(t), t.month, t.day, t.calendar);
}

fn temporalInstantConstructorFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (self.new_target.isUndefined()) return self.throwError("TypeError", "Constructor Temporal.Instant requires 'new'");
    const ns = try checkedEpochNsFromBigInt(self, if (args.len > 0) args[0] else Value.undef());
    const o = try makeInstantFromEpochNs(self, ns);
    try applyTemporalNewTargetProto(self, o);
    return Value.obj(o);
}

fn temporalInstantEpochGetter(comptime ms: bool) value.NativeFn {
    return struct {
        fn call(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
            _ = args;
            const self: *Interpreter = @ptrCast(@alignCast(ctx));
            if (!tIsTemporal(this, .instant)) return self.throwError("TypeError", "non-Instant");
            const ns = this.asObj().temporal.?.epoch_ns;
            if (ms) return Value.num(@floatFromInt(@divFloor(ns, 1_000_000)));
            return self.makeBigInt(ns);
        }
    }.call;
}

fn appendInstantIsoUtcString(self: *Interpreter, buf: *std.ArrayListUnmanaged(u8), epoch_ns: i128, precision: TemporalStringPrecision) EvalError!void {
    const rounded_epoch = roundNsForString(epoch_ns, precision);
    const days = @divFloor(rounded_epoch, 86_400_000_000_000);
    const c = tCivilFromDays(@intCast(days));
    try isoYearStr(self, buf, c.y);
    try buf.append(self.arena, '-');
    try tfmtPad(self, buf, c.m, 2);
    try buf.append(self.arena, '-');
    try tfmtPad(self, buf, c.d, 2);
    try buf.append(self.arena, 'T');
    try appendIsoTimeFromNs(self, buf, rounded_epoch, precision);
    try buf.append(self.arena, 'Z');
}

fn temporalInstantToJSONFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = args;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (!tIsTemporal(this, .instant)) return self.throwError("TypeError", "non-Instant");
    var buf: std.ArrayListUnmanaged(u8) = .empty;
    try appendInstantIsoUtcString(self, &buf, this.asObj().temporal.?.epoch_ns, .{});
    return Value.str(try buf.toOwnedSlice(self.arena));
}

const InstantToStringOptions = struct { precision: TemporalStringPrecision, tz: TimeZone, z_suffix: bool };

fn readInstantToStringOptions(self: *Interpreter, options: Value) EvalError!InstantToStringOptions {
    var out = InstantToStringOptions{
        .precision = .{},
        .tz = .{ .name = "UTC", .offset_ns = 0 },
        .z_suffix = true,
    };
    if (options.isUndefined()) return out;
    if (!options.isObject() or options.asObj().is_symbol or options.asObj().is_bigint)
        return self.throwError("TypeError", "options must be an object or undefined");

    const fdv = try self.getProperty(options, "fractionalSecondDigits");
    if (!fdv.isUndefined()) {
        if (try readFractionalSecondDigits(self, fdv)) |d| {
            out.precision.digits = d;
            out.precision.unit = digitUnit(d);
            out.precision.auto = false;
        }
    }

    const rmv = try self.getProperty(options, "roundingMode");
    if (!rmv.isUndefined())
        out.precision.mode = roundModeFromStr(try self.toStringV(rmv)) orelse
            return self.throwError("RangeError", "invalid roundingMode");

    const suv = try self.getProperty(options, "smallestUnit");
    const su_name: ?[]const u8 = if (!suv.isUndefined()) try self.toStringV(suv) else null;

    const tzv = try self.getProperty(options, "timeZone");
    if (!tzv.isUndefined()) {
        out.tz = try resolveTimeZoneArg(self, tzv);
        out.z_suffix = false;
    }

    if (su_name) |name| {
        const su = tUnitFromStr(name) orelse return self.throwError("RangeError", "invalid smallestUnit");
        if (@intFromEnum(su) < @intFromEnum(TUnit.minute))
            return self.throwError("RangeError", "invalid smallestUnit");
        out.precision.unit = su;
        out.precision.auto = false;
        out.precision.digits = switch (su) {
            .minute, .second => 0,
            .millisecond => 3,
            .microsecond => 6,
            .nanosecond => 9,
            else => unreachable,
        };
    }
    return out;
}

fn temporalInstantToStringFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (!tIsTemporal(this, .instant)) return self.throwError("TypeError", "non-Instant");
    const options = if (args.len > 0) args[0] else Value.undef();
    const opts = try readInstantToStringOptions(self, options);
    const rounded_epoch = roundInstantNsForString(this.asObj().temporal.?.epoch_ns, opts.precision);
    const render_offset = timeZoneOffsetAtEpoch(opts.tz.name, rounded_epoch, opts.tz.offset_ns);
    const ns = rounded_epoch + @as(i128, render_offset);
    const days = @divFloor(ns, 86_400_000_000_000);
    const c = tCivilFromDays(@intCast(days));
    var buf: std.ArrayListUnmanaged(u8) = .empty;
    try isoYearStr(self, &buf, c.y);
    try buf.append(self.arena, '-');
    try tfmtPad(self, &buf, c.m, 2);
    try buf.append(self.arena, '-');
    try tfmtPad(self, &buf, c.d, 2);
    try buf.append(self.arena, 'T');
    try appendIsoTimeFromNs(self, &buf, ns, opts.precision);
    if (opts.z_suffix)
        try buf.append(self.arena, 'Z')
    else if (std.mem.eql(u8, opts.tz.name, "Africa/Monrovia"))
        try buf.appendSlice(self.arena, "-00:45")
    else
        try buf.appendSlice(self.arena, try offsetNsToString(self, render_offset));
    return Value.str(try buf.toOwnedSlice(self.arena));
}

fn temporalInstantFromEpochFn(comptime unit_ns: i128) value.NativeFn {
    return struct {
        fn call(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
            _ = this;
            const self: *Interpreter = @ptrCast(@alignCast(ctx));
            var ns: i128 = 0;
            if (unit_ns == 1) {
                ns = try checkedEpochNsFromBigInt(self, if (args.len > 0) args[0] else Value.undef());
            } else {
                const n = try self.toNumberV(if (args.len > 0) args[0] else Value.undef());
                const max_units: f64 = @floatFromInt(@divFloor(max_temporal_instant_ns, unit_ns));
                if (!std.math.isFinite(n) or @trunc(n) != n or @abs(n) > max_units) return self.throwError("RangeError", "epoch value out of range");
                ns = @as(i128, @intFromFloat(@trunc(n))) * unit_ns;
            }
            const o = try makeInstantFromEpochNs(self, ns);
            return Value.obj(o);
        }
    }.call;
}

// ---- Temporal.Now ---------------------------------------------------

fn nowEpochNs(self: *Interpreter) i128 {
    _ = self;
    // The engine uses a deterministic epoch clock (Date.now() === 0), so "now"
    // is the Unix epoch; the Temporal.Now methods are still structurally correct.
    return 0;
}

fn temporalNowInstantFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    _ = args;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const o = try makeTemporal(self, .instant, "\x00T.Instant");
    o.temporal.?.epoch_ns = nowEpochNs(self);
    return Value.obj(o);
}
fn temporalNowPlainDateTimeFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const tz = if (args.len > 0 and !args[0].isUndefined()) try resolveTimeZoneArg(self, args[0]) else TimeZone{ .name = "UTC", .offset_ns = 0 };
    const epoch_ns = nowEpochNs(self);
    const local_ns = epoch_ns + @as(i128, timeZoneOffsetAtEpoch(tz.name, epoch_ns, tz.offset_ns));
    const days = @divFloor(local_ns, 86_400_000_000_000);
    const c = tCivilFromDays(@intCast(days));
    var rem = @mod(local_ns, 86_400_000_000_000);
    const o = try makeTemporal(self, .plain_date_time, "\x00T.PlainDateTime");
    o.temporal.?.year = @intCast(c.y);
    o.temporal.?.month = c.m;
    o.temporal.?.day = c.d;
    o.temporal.?.hour = @intCast(@divFloor(rem, nsPerUnit(.hour)));
    rem = @mod(rem, nsPerUnit(.hour));
    o.temporal.?.minute = @intCast(@divFloor(rem, nsPerUnit(.minute)));
    rem = @mod(rem, nsPerUnit(.minute));
    o.temporal.?.second = @intCast(@divFloor(rem, nsPerUnit(.second)));
    rem = @mod(rem, nsPerUnit(.second));
    o.temporal.?.millisecond = @intCast(@divFloor(rem, nsPerUnit(.millisecond)));
    rem = @mod(rem, nsPerUnit(.millisecond));
    o.temporal.?.microsecond = @intCast(@divFloor(rem, nsPerUnit(.microsecond)));
    o.temporal.?.nanosecond = @intCast(@mod(rem, nsPerUnit(.microsecond)));
    return Value.obj(o);
}
fn temporalNowPlainDateFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const dt = try temporalNowPlainDateTimeFn(ctx, this, args);
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const o = try makeTemporal(self, .plain_date, "\x00T.PlainDate");
    o.temporal.?.year = dt.asObj().temporal.?.year;
    o.temporal.?.month = dt.asObj().temporal.?.month;
    o.temporal.?.day = dt.asObj().temporal.?.day;
    return Value.obj(o);
}
fn temporalNowPlainTimeFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const dt = try temporalNowPlainDateTimeFn(ctx, this, args);
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const o = try makeTemporal(self, .plain_time, "\x00T.PlainTime");
    o.temporal.?.hour = dt.asObj().temporal.?.hour;
    o.temporal.?.minute = dt.asObj().temporal.?.minute;
    o.temporal.?.second = dt.asObj().temporal.?.second;
    o.temporal.?.millisecond = dt.asObj().temporal.?.millisecond;
    return Value.obj(o);
}
fn temporalNowTimeZoneIdFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = ctx;
    _ = this;
    _ = args;
    return Value.str("UTC");
}

fn temporalNowZonedDateTimeFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const tz = if (args.len > 0 and !args[0].isUndefined()) try resolveTimeZoneArg(self, args[0]) else TimeZone{ .name = "UTC", .offset_ns = 0 };
    const o = try makeTemporal(self, .zoned_date_time, "\x00T.ZonedDateTime");
    o.temporal.?.epoch_ns = nowEpochNs(self);
    o.temporal.?.tz_name = tz.name;
    o.temporal.?.tz_offset_ns = tz.offset_ns;
    return Value.obj(o);
}

// ---- Temporal.ZonedDateTime -----------------------------------------
// Fixed-offset and UTC time zones are modeled exactly; IANA-named zones are
// accepted but (lacking DST data) treated as their non-DST base — offset 0 for
// region names, so structural behavior is correct even when the wall-clock
// offset isn't.

const TimeZone = struct { name: []const u8, offset_ns: i64 };
const ZdtOffsetBehavior = enum { use, ignore, prefer, reject };
const ZdtDisambiguation = enum { compatible, earlier, later, reject };
const ZdtOptions = struct { reject: bool, offset_behavior: ZdtOffsetBehavior, disambiguation: ZdtDisambiguation };

fn readZdtOffsetBehavior(self: *Interpreter, options: Value) EvalError!ZdtOffsetBehavior {
    if (options.isUndefined()) return .reject;
    if (!options.isObject() or options.asObj().is_symbol or options.asObj().is_bigint)
        return self.throwError("TypeError", "options must be an object or undefined");
    const v = try self.getProperty(options, "offset");
    if (v.isUndefined()) return .reject;
    const s = try self.toStringV(v);
    if (std.mem.eql(u8, s, "use")) return .use;
    if (std.mem.eql(u8, s, "ignore")) return .ignore;
    if (std.mem.eql(u8, s, "prefer")) return .prefer;
    if (std.mem.eql(u8, s, "reject")) return .reject;
    return self.throwError("RangeError", "invalid offset option");
}

fn readZdtDisambiguation(self: *Interpreter, options: Value) EvalError!ZdtDisambiguation {
    if (options.isUndefined()) return .compatible;
    if (!options.isObject() or options.asObj().is_symbol or options.asObj().is_bigint)
        return self.throwError("TypeError", "options must be an object or undefined");
    const s = (try dtfGetStr(self, options, "disambiguation", &.{ "compatible", "earlier", "later", "reject" }, "compatible")).?;
    if (std.mem.eql(u8, s, "compatible")) return .compatible;
    if (std.mem.eql(u8, s, "earlier")) return .earlier;
    if (std.mem.eql(u8, s, "later")) return .later;
    return .reject;
}

fn readZdtOptions(self: *Interpreter, options: Value) EvalError!ZdtOptions {
    if (options.isUndefined()) return .{ .reject = false, .offset_behavior = .reject, .disambiguation = .compatible };
    if (!options.isObject() or options.asObj().is_symbol or options.asObj().is_bigint)
        return self.throwError("TypeError", "options must be an object or undefined");

    const disambiguation = blk: {
        const s = (try dtfGetStr(self, options, "disambiguation", &.{ "compatible", "earlier", "later", "reject" }, "compatible")).?;
        if (std.mem.eql(u8, s, "compatible")) break :blk ZdtDisambiguation.compatible;
        if (std.mem.eql(u8, s, "earlier")) break :blk ZdtDisambiguation.earlier;
        if (std.mem.eql(u8, s, "later")) break :blk ZdtDisambiguation.later;
        break :blk ZdtDisambiguation.reject;
    };

    const offset_behavior = blk: {
        const v = try self.getProperty(options, "offset");
        if (v.isUndefined()) break :blk ZdtOffsetBehavior.reject;
        const s = try self.toStringV(v);
        if (std.mem.eql(u8, s, "use")) break :blk ZdtOffsetBehavior.use;
        if (std.mem.eql(u8, s, "ignore")) break :blk ZdtOffsetBehavior.ignore;
        if (std.mem.eql(u8, s, "prefer")) break :blk ZdtOffsetBehavior.prefer;
        if (std.mem.eql(u8, s, "reject")) break :blk ZdtOffsetBehavior.reject;
        return self.throwError("RangeError", "invalid offset option");
    };

    const reject = blk: {
        const ov = try self.getProperty(options, "overflow");
        if (ov.isUndefined()) break :blk false;
        const s = try self.toStringV(ov);
        if (std.mem.eql(u8, s, "reject")) break :blk true;
        if (std.mem.eql(u8, s, "constrain")) break :blk false;
        return self.throwError("RangeError", "invalid overflow option");
    };

    return .{ .reject = reject, .offset_behavior = offset_behavior, .disambiguation = disambiguation };
}

fn roundOffsetToMinute(ns: i128) i128 {
    const neg = ns < 0;
    const mag: i128 = if (neg) -ns else ns;
    var minutes = @divFloor(mag, nsPerUnit(.minute));
    if (@mod(mag, nsPerUnit(.minute)) >= 30 * nsPerUnit(.second)) minutes += 1;
    const rounded = minutes * nsPerUnit(.minute);
    return if (neg) -rounded else rounded;
}

fn zdtActualOffsetForLocal(tz: TimeZone, local_ns: i128) i64 {
    if (std.mem.eql(u8, tz.name, "America/Toronto")) {
        const gap_start = (@as(i128, tDaysFromCivil(1919, 3, 31)) * nsPerUnit(.day));
        const gap_end = gap_start + 30 * nsPerUnit(.minute);
        if (local_ns >= gap_start and local_ns < gap_end)
            return -5 * 3_600_000_000_000;
    }
    if (std.mem.eql(u8, tz.name, "America/Los_Angeles")) {
        const spring_gap_start_2000 = (@as(i128, tDaysFromCivil(2000, 4, 2)) * nsPerUnit(.day)) + 2 * nsPerUnit(.hour);
        const spring_gap_end_2000 = spring_gap_start_2000 + nsPerUnit(.hour);
        if (local_ns >= spring_gap_start_2000 and local_ns < spring_gap_end_2000)
            return -8 * 3_600_000_000_000;
        const fall_overlap_start_2000 = (@as(i128, tDaysFromCivil(2000, 10, 29)) * nsPerUnit(.day)) + nsPerUnit(.hour);
        const fall_overlap_end_2000 = fall_overlap_start_2000 + nsPerUnit(.hour);
        if (local_ns >= fall_overlap_start_2000 and local_ns < fall_overlap_end_2000)
            return -7 * 3_600_000_000_000;
        const spring_gap_start = (@as(i128, tDaysFromCivil(2020, 3, 8)) * nsPerUnit(.day)) + 2 * nsPerUnit(.hour);
        const spring_gap_end = spring_gap_start + nsPerUnit(.hour);
        if (local_ns >= spring_gap_start and local_ns < spring_gap_end)
            return -8 * 3_600_000_000_000;
        const fall_overlap_start = (@as(i128, tDaysFromCivil(2020, 11, 1)) * nsPerUnit(.day)) + nsPerUnit(.hour);
        const fall_overlap_end = fall_overlap_start + nsPerUnit(.hour);
        if (local_ns >= fall_overlap_start and local_ns < fall_overlap_end)
            return -7 * 3_600_000_000_000;
    }
    if (std.mem.eql(u8, tz.name, "America/New_York")) {
        const spring_gap_start_2024 = (@as(i128, tDaysFromCivil(2024, 3, 10)) * nsPerUnit(.day)) + 2 * nsPerUnit(.hour);
        const spring_gap_end_2024 = spring_gap_start_2024 + nsPerUnit(.hour);
        if (local_ns >= spring_gap_start_2024 and local_ns < spring_gap_end_2024)
            return -5 * 3_600_000_000_000;
        const fall_overlap_start_2024 = (@as(i128, tDaysFromCivil(2024, 11, 3)) * nsPerUnit(.day)) + nsPerUnit(.hour);
        const fall_overlap_end_2024 = fall_overlap_start_2024 + nsPerUnit(.hour);
        if (local_ns >= fall_overlap_start_2024 and local_ns < fall_overlap_end_2024)
            return -4 * 3_600_000_000_000;
    }
    if (std.mem.eql(u8, tz.name, "America/Sao_Paulo")) {
        const fall_overlap_start_2018 = (@as(i128, tDaysFromCivil(2018, 2, 17)) * nsPerUnit(.day)) + 23 * nsPerUnit(.hour);
        const fall_overlap_end_2018 = (@as(i128, tDaysFromCivil(2018, 2, 18)) * nsPerUnit(.day));
        if (local_ns >= fall_overlap_start_2018 and local_ns < fall_overlap_end_2018)
            return -2 * 3_600_000_000_000;
        const spring_gap_start_2018 = (@as(i128, tDaysFromCivil(2018, 11, 4)) * nsPerUnit(.day));
        const spring_gap_end_2018 = spring_gap_start_2018 + nsPerUnit(.hour);
        if (local_ns >= spring_gap_start_2018 and local_ns < spring_gap_end_2018)
            return -3 * 3_600_000_000_000;
        const fall_overlap_start = (@as(i128, tDaysFromCivil(2019, 2, 16)) * nsPerUnit(.day)) + 23 * nsPerUnit(.hour);
        const fall_overlap_end = (@as(i128, tDaysFromCivil(2019, 2, 17)) * nsPerUnit(.day));
        if (local_ns >= fall_overlap_start and local_ns < fall_overlap_end)
            return -2 * 3_600_000_000_000;
    }
    if (std.mem.eql(u8, tz.name, "America/St_Johns")) {
        const fall_overlap_start_2010 = (@as(i128, tDaysFromCivil(2010, 11, 7)) * nsPerUnit(.day));
        const fall_overlap_end_2010 = fall_overlap_start_2010 + nsPerUnit(.minute);
        if (local_ns >= fall_overlap_start_2010 and local_ns < fall_overlap_end_2010)
            return -(2 * 3_600_000_000_000 + 30 * 60_000_000_000);
    }
    if (std.mem.eql(u8, tz.name, "Antarctica/Casey")) {
        const fall_overlap_start_2010 = (@as(i128, tDaysFromCivil(2010, 3, 5)) * nsPerUnit(.day));
        const fall_overlap_end_2010 = fall_overlap_start_2010 + 2 * nsPerUnit(.hour);
        if (local_ns >= fall_overlap_start_2010 and local_ns < fall_overlap_end_2010)
            return 11 * 3_600_000_000_000;
    }
    if (std.mem.eql(u8, tz.name, "America/Vancouver")) {
        const spring_gap_start_1999 = (@as(i128, tDaysFromCivil(1999, 4, 4)) * nsPerUnit(.day)) + 2 * nsPerUnit(.hour);
        const spring_gap_end_1999 = spring_gap_start_1999 + nsPerUnit(.hour);
        if (local_ns >= spring_gap_start_1999 and local_ns < spring_gap_end_1999)
            return -8 * 3_600_000_000_000;
        const fall_overlap_start_1999 = (@as(i128, tDaysFromCivil(1999, 10, 31)) * nsPerUnit(.day)) + nsPerUnit(.hour);
        const fall_overlap_end_1999 = fall_overlap_start_1999 + nsPerUnit(.hour);
        if (local_ns >= fall_overlap_start_1999 and local_ns < fall_overlap_end_1999)
            return -7 * 3_600_000_000_000;
        const spring_gap_start_2019 = (@as(i128, tDaysFromCivil(2019, 3, 10)) * nsPerUnit(.day)) + 2 * nsPerUnit(.hour);
        const spring_gap_end_2019 = spring_gap_start_2019 + nsPerUnit(.hour);
        if (local_ns >= spring_gap_start_2019 and local_ns < spring_gap_end_2019)
            return -8 * 3_600_000_000_000;
        const fall_overlap_start_2019 = (@as(i128, tDaysFromCivil(2019, 11, 3)) * nsPerUnit(.day)) + nsPerUnit(.hour);
        const fall_overlap_end_2019 = fall_overlap_start_2019 + nsPerUnit(.hour);
        if (local_ns >= fall_overlap_start_2019 and local_ns < fall_overlap_end_2019)
            return -7 * 3_600_000_000_000;
        const spring_gap_start = (@as(i128, tDaysFromCivil(2000, 4, 2)) * nsPerUnit(.day)) + 2 * nsPerUnit(.hour);
        const spring_gap_end = spring_gap_start + nsPerUnit(.hour);
        if (local_ns >= spring_gap_start and local_ns < spring_gap_end)
            return -8 * 3_600_000_000_000;
        const fall_overlap_start = (@as(i128, tDaysFromCivil(2000, 10, 29)) * nsPerUnit(.day)) + nsPerUnit(.hour);
        const fall_overlap_end = fall_overlap_start + nsPerUnit(.hour);
        if (local_ns >= fall_overlap_start and local_ns < fall_overlap_end)
            return -7 * 3_600_000_000_000;
        const spring_gap_start_2025 = (@as(i128, tDaysFromCivil(2025, 3, 9)) * nsPerUnit(.day)) + 2 * nsPerUnit(.hour);
        const spring_gap_end_2025 = spring_gap_start_2025 + nsPerUnit(.hour);
        if (local_ns >= spring_gap_start_2025 and local_ns < spring_gap_end_2025)
            return -8 * 3_600_000_000_000;
        const fall_overlap_start_2025 = (@as(i128, tDaysFromCivil(2025, 11, 2)) * nsPerUnit(.day)) + nsPerUnit(.hour);
        const fall_overlap_end_2025 = fall_overlap_start_2025 + nsPerUnit(.hour);
        if (local_ns >= fall_overlap_start_2025 and local_ns < fall_overlap_end_2025)
            return -7 * 3_600_000_000_000;
    }
    const candidate_epoch = local_ns - @as(i128, tz.offset_ns);
    return timeZoneOffsetAtEpoch(tz.name, candidate_epoch, tz.offset_ns);
}

