        if (local_ns >= fall_overlap_start_2025 and local_ns < fall_overlap_end_2025) {
            return switch (disambiguation) {
                .compatible, .earlier => daylight,
                .later => standard,
                .reject => self.throwError("RangeError", "ambiguous or nonexistent local time"),
            };
        }
    }
    return zdtActualOffsetForLocal(tz, local_ns);
}

fn skippedMidnightStartEpoch(tz_name: []const u8, iso_year: i64, iso_month: u8, iso_day: u8) ?i128 {
    if (std.mem.eql(u8, tz_name, "America/Toronto") and iso_year == 1919 and iso_month == 3 and iso_day == 31)
        return (@as(i128, tDaysFromCivil(1919, 3, 31)) * nsPerUnit(.day)) + 4 * nsPerUnit(.hour) + 30 * nsPerUnit(.minute);
    if (std.mem.eql(u8, tz_name, "Asia/Singapore") and iso_year == 1933 and iso_month == 1 and iso_day == 1)
        return (@as(i128, tDaysFromCivil(1933, 1, 1)) * nsPerUnit(.day)) - 7 * nsPerUnit(.hour);
    if (std.mem.eql(u8, tz_name, "Pacific/Apia") and iso_year == 2011 and iso_month == 12 and iso_day == 30)
        return (@as(i128, tDaysFromCivil(2011, 12, 30)) * nsPerUnit(.day)) + 10 * nsPerUnit(.hour);
    if (std.mem.eql(u8, tz_name, "America/Noronha") and iso_year == 2000 and iso_month == 10 and iso_day == 8)
        return (@as(i128, tDaysFromCivil(2000, 10, 8)) * nsPerUnit(.day)) + 2 * nsPerUnit(.hour);
    if (std.mem.eql(u8, tz_name, "America/Boa_Vista") and iso_year == 2000 and iso_month == 10 and iso_day == 8)
        return (@as(i128, tDaysFromCivil(2000, 10, 8)) * nsPerUnit(.day)) + 4 * nsPerUnit(.hour);
    return null;
}

fn zdtOffsetMatchesLocal(tz: TimeZone, local_ns: i128, offset_ns: i128) bool {
    if (offset_ns < std.math.minInt(i64) or offset_ns > std.math.maxInt(i64)) return false;
    const off: i64 = @intCast(offset_ns);
    const candidate_epoch = local_ns - offset_ns;
    return timeZoneOffsetAtEpoch(tz.name, candidate_epoch, tz.offset_ns) == off;
}

fn zdtEpochFromParsed(self: *Interpreter, tz: TimeZone, p: ParsedDT, behavior: ZdtOffsetBehavior, disambiguation: ZdtDisambiguation) EvalError!i128 {
    const local_ns = p.epoch_ns + p.offset_ns;
    const skip_wall_range = p.has_offset and (behavior == .use or (behavior == .ignore and isFixedTimeZone(tz)));
    if (!skip_wall_range) try checkZdtLocalDateTimeNs(self, local_ns);
    const epoch_ns: i128 = if (p.z) p.epoch_ns else blk: {
        const actual = if (p.has_offset and p.offset_has_seconds)
            timeZoneOffsetAtEpoch(tz.name, p.epoch_ns, tz.offset_ns)
        else
            try zdtOffsetForLocalDisambiguation(self, tz, local_ns, disambiguation);
        if (!p.has_offset) break :blk local_ns - @as(i128, actual);
        if (isFixedTimeZone(tz)) {
            const tz_off: i128 = @as(i128, tz.offset_ns);
            break :blk switch (behavior) {
                .use => local_ns - p.offset_ns,
                .ignore => local_ns - tz_off,
                .prefer => if (p.offset_ns == tz_off) local_ns - tz_off else local_ns - p.offset_ns,
                .reject => if (p.offset_ns == tz_off) local_ns - tz_off else return self.throwError("RangeError", "offset does not match time zone"),
            };
        }
        const exact_match = zdtOffsetMatchesLocal(tz, local_ns, p.offset_ns);
        const rounded_match = !p.offset_has_seconds and p.offset_ns == roundOffsetToMinute(@as(i128, actual));
        break :blk switch (behavior) {
            .use => local_ns - p.offset_ns,
            .ignore => local_ns - @as(i128, actual),
            .prefer => if (rounded_match) local_ns - @as(i128, actual) else if (exact_match) local_ns - p.offset_ns else local_ns - @as(i128, actual),
            .reject => if (rounded_match) local_ns - @as(i128, actual) else if (exact_match) local_ns - p.offset_ns else return self.throwError("RangeError", "offset does not match time zone"),
        };
    };
    try checkInstantEpochNs(self, epoch_ns);
    return epoch_ns;
}

