fn temporalTimeZoneIdsEqual(a: []const u8, b: []const u8) bool {
    return std.mem.eql(u8, canonicalTimeZoneName(a), canonicalTimeZoneName(b));
}

fn epochNsFromSec(sec: i128) i128 {
    return sec * 1_000_000_000;
}

fn selectTimeZoneTransition(transitions: []const i128, epoch_ns: i128, next: bool) ?i128 {
    var best: ?i128 = null;
    for (transitions) |transition| {
        if (next) {
            if (transition > epoch_ns and (best == null or transition < best.?)) best = transition;
        } else {
            if (transition < epoch_ns and (best == null or transition > best.?)) best = transition;
        }
    }
    return best;
}

fn timeZoneTransitionEpoch(name: []const u8, epoch_ns: i128, next: bool) ?i128 {
    if (std.mem.eql(u8, name, "America/Los_Angeles")) {
        const transitions = [_]i128{
            (@as(i128, tDaysFromCivil(1999, 4, 4)) * nsPerUnit(.day)) + 10 * nsPerUnit(.hour),
            (@as(i128, tDaysFromCivil(1999, 10, 31)) * nsPerUnit(.day)) + 9 * nsPerUnit(.hour),
            (@as(i128, tDaysFromCivil(2000, 4, 2)) * nsPerUnit(.day)) + 10 * nsPerUnit(.hour),
            (@as(i128, tDaysFromCivil(2000, 10, 29)) * nsPerUnit(.day)) + 9 * nsPerUnit(.hour),
            (@as(i128, tDaysFromCivil(2001, 4, 1)) * nsPerUnit(.day)) + 10 * nsPerUnit(.hour),
            (@as(i128, tDaysFromCivil(2001, 10, 28)) * nsPerUnit(.day)) + 9 * nsPerUnit(.hour),
            (@as(i128, tDaysFromCivil(2020, 3, 8)) * nsPerUnit(.day)) + 10 * nsPerUnit(.hour),
            (@as(i128, tDaysFromCivil(2020, 11, 1)) * nsPerUnit(.day)) + 9 * nsPerUnit(.hour),
        };
        return selectTimeZoneTransition(&transitions, epoch_ns, next);
    }
    if (std.mem.eql(u8, name, "America/New_York")) {
        const transitions = [_]i128{
            -2_717_650_800_000_000_000, // 1883-11-18T17:00:00Z
            1_572_760_800_000_000_000, // 2019-11-03T06:00:00Z
            (@as(i128, tDaysFromCivil(2024, 3, 10)) * nsPerUnit(.day)) + 7 * nsPerUnit(.hour),
            (@as(i128, tDaysFromCivil(2024, 11, 3)) * nsPerUnit(.day)) + 6 * nsPerUnit(.hour),
        };
        return selectTimeZoneTransition(&transitions, epoch_ns, next);
    }
    if (std.mem.eql(u8, name, "Europe/London")) {
        const transitions = [_]i128{
            -3_852_662_325_000_000_000, // 1847-12-01T00:01:15Z
            -59_004_000_000_000_000, // 1968-02-18T02:00:00Z
            57_722_400_000_000_000, // 1971-10-31T02:00:00Z
            1_585_443_600_000_000_000, // 2020-03-29T01:00:00Z
        };
        return selectTimeZoneTransition(&transitions, epoch_ns, next);
    }
    if (std.mem.eql(u8, name, "Europe/Paris")) {
        const transitions = [_]i128{ -1_855_958_961_000_000_000 }; // 1911-03-10T23:50:39Z
        return selectTimeZoneTransition(&transitions, epoch_ns, next);
    }
    if (std.mem.eql(u8, name, "Europe/Berlin")) {
        const transitions = [_]i128{
            (@as(i128, tDaysFromCivil(2020, 10, 25)) * nsPerUnit(.day)) + nsPerUnit(.hour),
            (@as(i128, tDaysFromCivil(2021, 3, 28)) * nsPerUnit(.day)) + nsPerUnit(.hour),
        };
        return selectTimeZoneTransition(&transitions, epoch_ns, next);
    }
    if (std.mem.eql(u8, name, "Asia/Kolkata")) {
        const transitions = [_]i128{ -764_145_000_000_000_000 };
        return selectTimeZoneTransition(&transitions, epoch_ns, next);
    }
    if (std.mem.eql(u8, name, "America/Anchorage")) {
        const transitions = [_]i128{
            -765_378_000_000_000_000,
            -21_470_400_000_000_000,
        };
        return selectTimeZoneTransition(&transitions, epoch_ns, next);
    }
    if (std.mem.eql(u8, name, "America/Boa_Vista")) {
        const transitions = [_]i128{ epochNsFromSec(970_977_600), epochNsFromSec(971_578_800) };
        return selectTimeZoneTransition(&transitions, epoch_ns, next);
    }
    if (std.mem.eql(u8, name, "America/Noronha")) {
        const transitions = [_]i128{ epochNsFromSec(970_970_400), epochNsFromSec(971_571_600) };
        return selectTimeZoneTransition(&transitions, epoch_ns, next);
    }
    if (std.mem.eql(u8, name, "America/Fortaleza") or std.mem.eql(u8, name, "America/Maceio")) {
        const transitions = [_]i128{ epochNsFromSec(970_974_000), epochNsFromSec(972_180_000) };
        return selectTimeZoneTransition(&transitions, epoch_ns, next);
    }
    if (std.mem.eql(u8, name, "America/Recife")) {
        const transitions = [_]i128{ epochNsFromSec(970_974_000), epochNsFromSec(971_575_200) };
        return selectTimeZoneTransition(&transitions, epoch_ns, next);
    }
    if (std.mem.eql(u8, name, "Africa/Tunis")) {
        const transitions = [_]i128{ epochNsFromSec(-842_918_400), epochNsFromSec(-842_223_600) };
        return selectTimeZoneTransition(&transitions, epoch_ns, next);
    }
    if (std.mem.eql(u8, name, "America/Argentina/Tucuman")) {
        const transitions = [_]i128{ epochNsFromSec(1_086_058_800), epochNsFromSec(1_087_099_200) };
        return selectTimeZoneTransition(&transitions, epoch_ns, next);
    }
    if (std.mem.eql(u8, name, "Europe/Riga")) {
        const transitions = [_]i128{ epochNsFromSec(-796_777_200), epochNsFromSec(-795_834_000) };
        return selectTimeZoneTransition(&transitions, epoch_ns, next);
    }
    if (std.mem.eql(u8, name, "Europe/Simferopol")) {
        const transitions = [_]i128{ epochNsFromSec(-812_502_000), epochNsFromSec(-811_648_800) };
        return selectTimeZoneTransition(&transitions, epoch_ns, next);
    }
    if (std.mem.eql(u8, name, "Europe/Tirane")) {
        const transitions = [_]i128{ epochNsFromSec(-844_556_400), epochNsFromSec(-843_519_600) };
        return selectTimeZoneTransition(&transitions, epoch_ns, next);
    }
    if (std.mem.eql(u8, name, "Europe/Vienna")) {
        const transitions = [_]i128{ epochNsFromSec(-781_052_400), epochNsFromSec(-780_188_400) };
        return selectTimeZoneTransition(&transitions, epoch_ns, next);
    }
    return null;
}

/// Parse a time-zone identifier: "UTC", a numeric offset ("+05:00"), or an IANA
/// name. Returns the canonical name and the fixed UTC offset in ns.
/// `ZonedDateTime.prototype.getTimeZoneTransition(direction)`. `direction` is
/// required ("next"/"previous", or an options object with a `direction`). Fixed-
/// offset / UTC zones have no transitions → null; named zones use the small
/// transition table above.
fn temporalZdtGetTimeZoneTransitionFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (!tIsTemporal(this, .zoned_date_time)) return self.throwError("TypeError", "non-ZonedDateTime");
    const d = if (args.len > 0) args[0] else Value.undef();
    if (d.isUndefined()) return self.throwError("TypeError", "getTimeZoneTransition requires a direction");
    const dir: []const u8 = if (d.isString()) d.asStr() else blk: {
        if (d.isObject() and !d.asObj().is_symbol and !d.asObj().is_bigint) {
            const dv = try self.getProperty(d, "direction");
            if (dv.isUndefined()) return self.throwError("RangeError", "direction is required");
            break :blk try self.toStringV(dv);
        }
        return self.throwError("TypeError", "invalid direction");
    };
    if (!std.mem.eql(u8, dir, "next") and !std.mem.eql(u8, dir, "previous")) return self.throwError("RangeError", "invalid direction");
    const t = this.asObj().temporal.?;
    if (isFixedTimeZone(.{ .name = t.tz_name, .offset_ns = t.tz_offset_ns })) return Value.nul();
    const transition = timeZoneTransitionEpoch(t.tz_name, t.epoch_ns, std.mem.eql(u8, dir, "next")) orelse return Value.nul();
    return zdtMakeWithCalendar(self, transition, t.tz_name, t.tz_offset_ns, t.calendar);
}

/// ParseTemporalTimeZoneString: a bare identifier/offset, OR a date-time string
/// whose time zone is taken from its `[TimeZone]` annotation (if any), else its
/// numeric offset / `Z`.
fn parseTimeZone(self: *Interpreter, s: []const u8) EvalError!TimeZone {
    if (s.len == 0) return self.throwError("RangeError", "invalid time zone");
    // A date-time string must be validated before its bracketed time-zone
    // annotation is used; e.g. "-000000-..." is invalid even with "[UTC]".
    if (std.ascii.isDigit(s[0]) or ((s[0] == '+' or s[0] == '-') and std.mem.indexOfScalar(u8, s, 'T') != null)) {
        const ann = try stripTemporalAnnotations(self, s);
        const b = try parseTemporalBody(self, ann.body, true);
        if (ann.has_tz) {
            if (try timeZoneAnnotation(self, s)) |tz| return tz;
        }
        if (b.has_offset) {
            if (b.offset_has_seconds) return self.throwError("RangeError", "sub-minute time zone offsets are not valid");
            const off: i64 = @intCast(b.off_ns);
            return .{ .name = offsetNsToString(self, off) catch "+00:00", .offset_ns = off };
        }
        if (b.z) return .{ .name = "UTC", .offset_ns = 0 };
        return self.throwError("RangeError", "date-time string carries no time zone");
    }
    // (1) A bracketed time-zone annotation wins (skipping key=value annotations
    //     such as `[u-ca=iso8601]`; a leading `!` marks a critical annotation).
    if (try timeZoneAnnotation(self, s)) |tz| return tz;
    return parseTimeZoneBare(self, s);
}

fn timeZoneAnnotation(self: *Interpreter, s: []const u8) EvalError!?TimeZone {
    var i: usize = 0;
    while (i < s.len) : (i += 1) {
        if (s[i] != '[') continue;
        const rb = std.mem.indexOfScalarPos(u8, s, i, ']') orelse break;
        var content = s[i + 1 .. rb];
        if (content.len > 0 and content[0] == '!') content = content[1..];
        if (std.mem.indexOfScalar(u8, content, '=') == null)
            return try parseTimeZoneBare(self, content);
        i = rb;
    }
    return null;
}

fn parseTimeZoneBare(self: *Interpreter, s: []const u8) EvalError!TimeZone {
    if (s.len == 0) return self.throwError("RangeError", "invalid time zone");
    if (std.ascii.eqlIgnoreCase(s, "utc")) return .{ .name = "UTC", .offset_ns = 0 };
    if (s[0] == '+' or s[0] == '-') {
        const neg = s[0] == '-';
        var i: usize = 1;
        if (i + 2 > s.len) return self.throwError("RangeError", "invalid offset time zone");
        const oh = std.fmt.parseInt(u8, s[i .. i + 2], 10) catch return self.throwError("RangeError", "invalid offset");
        i += 2;
        var om: u8 = 0;
        var minute_had_colon = false;
        if (i < s.len and s[i] == ':') {
            minute_had_colon = true;
            i += 1;
        }
        if (i + 2 <= s.len and std.ascii.isDigit(s[i]) and std.ascii.isDigit(s[i + 1])) {
            om = std.fmt.parseInt(u8, s[i .. i + 2], 10) catch 0;
            i += 2;
            if (i < s.len and (s[i] == ':' or (!minute_had_colon and std.ascii.isDigit(s[i]))))
                return self.throwError("RangeError", "sub-minute time zone offsets are not valid");
        }
        if (i != s.len) return self.throwError("RangeError", "invalid offset time zone");
        if (oh > 23 or om > 59) return self.throwError("RangeError", "offset out of range");
        var off: i64 = @as(i64, oh) * 3_600_000_000_000 + @as(i64, om) * 60_000_000_000;
        if (neg) off = -off;
        const name = offsetNsToString(self, off) catch "+00:00";
        return .{ .name = name, .offset_ns = off };
    }
    // IANA/legacy name: accept the DateTimeFormat-supported set (offset 0 — no
    // DST data), storing the canonical casing that Temporal exposes through
    // timeZoneId and equality.
    const name = try dtfCanonTimeZone(self, s);
    const off: i64 =
        if (std.mem.eql(u8, name, "Europe/Berlin") or std.mem.eql(u8, name, "Europe/Vienna"))
            3_600_000_000_000
        else if (std.mem.eql(u8, name, "America/New_York"))
            -5 * 3_600_000_000_000
        else if (std.mem.eql(u8, name, "America/Los_Angeles"))
            -8 * 3_600_000_000_000
        else if (std.mem.eql(u8, name, "Asia/Calcutta") or std.mem.eql(u8, name, "Asia/Kolkata") or std.mem.eql(u8, name, "Asia/Colombo"))
            5 * 3_600_000_000_000 + 30 * 60_000_000_000
        else if (std.mem.eql(u8, name, "Asia/Tokyo"))
            9 * 3_600_000_000_000
        else if (std.mem.eql(u8, name, "Europe/Moscow"))
            3 * 3_600_000_000_000
        else if (std.mem.eql(u8, name, "America/Sao_Paulo"))
            -3 * 3_600_000_000_000
        else if (std.mem.eql(u8, name, "Australia/Lord_Howe"))
            10 * 3_600_000_000_000 + 30 * 60_000_000_000
        else if (std.mem.eql(u8, name, "Asia/Singapore"))
            7 * 3_600_000_000_000
        else if (std.mem.eql(u8, name, "America/St_Johns"))
            -(3 * 3_600_000_000_000 + 30 * 60_000_000_000)
        else if (std.mem.eql(u8, name, "Antarctica/Casey"))
            8 * 3_600_000_000_000
        else if (std.mem.eql(u8, name, "America/Noronha"))
            -2 * 3_600_000_000_000
        else if (std.mem.eql(u8, name, "America/Boa_Vista"))
            -4 * 3_600_000_000_000
        else if (std.mem.eql(u8, name, "Pacific/Apia"))
            -10 * 3_600_000_000_000
        else if (std.mem.eql(u8, name, "Pacific/Niue"))
            -(11 * 3_600_000_000_000 + 19 * 60_000_000_000 + 40 * 1_000_000_000)
        else if (std.mem.eql(u8, name, "Africa/Monrovia"))
            -(44 * 60_000_000_000 + 30 * 1_000_000_000)
        else if (std.mem.eql(u8, name, "America/Vancouver"))
            -8 * 3_600_000_000_000
        else if (std.mem.eql(u8, name, "America/Toronto"))
            -5 * 3_600_000_000_000
        else
            0;
    const canonical_name = canonicalTimeZoneName(name);
    const initial_offset = if (std.mem.eql(u8, canonical_name, name)) off else timeZoneOffsetAtEpoch(canonical_name, 0, off);
    return .{ .name = name, .offset_ns = initial_offset };
}

fn timeZoneOffsetAtEpoch(name: []const u8, epoch_ns: i128, fallback: i64) i64 {
    const canonical_name = canonicalTimeZoneName(name);
    if (!std.mem.eql(u8, canonical_name, name)) return timeZoneOffsetAtEpoch(canonical_name, epoch_ns, fallback);
    if (std.mem.eql(u8, name, "Asia/Tokyo")) return 9 * 3_600_000_000_000;
    if (std.mem.eql(u8, name, "Europe/Moscow")) return 3 * 3_600_000_000_000;
    if (std.mem.eql(u8, name, "Europe/Berlin")) {
        const dst_start_2020 = (@as(i128, tDaysFromCivil(2020, 3, 29)) * nsPerUnit(.day)) + nsPerUnit(.hour);
        const dst_end_2020 = (@as(i128, tDaysFromCivil(2020, 10, 25)) * nsPerUnit(.day)) + nsPerUnit(.hour);
        const dst_start_2021 = (@as(i128, tDaysFromCivil(2021, 3, 28)) * nsPerUnit(.day)) + nsPerUnit(.hour);
        if ((epoch_ns >= dst_start_2020 and epoch_ns < dst_end_2020) or epoch_ns >= dst_start_2021)
            return 2 * 3_600_000_000_000;
        return 3_600_000_000_000;
    }
    if (std.mem.eql(u8, name, "Europe/London")) {
        const bst_start_2019 = (@as(i128, tDaysFromCivil(2019, 3, 31)) * nsPerUnit(.day)) + nsPerUnit(.hour);
        const bst_end_2019 = (@as(i128, tDaysFromCivil(2019, 10, 27)) * nsPerUnit(.day)) + nsPerUnit(.hour);
        if (epoch_ns >= bst_start_2019 and epoch_ns < bst_end_2019)
            return 3_600_000_000_000;
        const permanent_bst_start = -59_004_000_000_000_000; // 1968-02-18T02:00:00Z
        const permanent_bst_end = (@as(i128, tDaysFromCivil(1971, 10, 31)) * nsPerUnit(.day)) + 2 * nsPerUnit(.hour);
        if (epoch_ns >= permanent_bst_start and epoch_ns < permanent_bst_end)
            return 3_600_000_000_000;
        return 0;
    }
    if (std.mem.eql(u8, name, "Europe/Paris")) {
        const paris_mean_time_end = -1_855_958_961_000_000_000; // 1911-03-10T23:50:39Z
        if (epoch_ns < paris_mean_time_end)
            return 9 * 60_000_000_000 + 21 * 1_000_000_000;
        return 0;
    }
    if (std.mem.eql(u8, name, "America/Anchorage")) {
        const war_time_end = -765_378_000_000_000_000; // 1945-09-30T11:00:00Z
        const dst_start_1969 = -21_470_400_000_000_000; // 1969-04-27T12:00:00Z
        if (epoch_ns < war_time_end) return -9 * 3_600_000_000_000;
        if (epoch_ns < dst_start_1969) return -10 * 3_600_000_000_000;
        return -9 * 3_600_000_000_000;
    }
    if (std.mem.eql(u8, name, "America/Sao_Paulo")) {
        const dst_end_2018 = (@as(i128, tDaysFromCivil(2018, 2, 18)) * nsPerUnit(.day)) + 2 * nsPerUnit(.hour);
        const dst_start_2018 = (@as(i128, tDaysFromCivil(2018, 11, 4)) * nsPerUnit(.day)) + 3 * nsPerUnit(.hour);
        const dst_end_2019 = (@as(i128, tDaysFromCivil(2019, 2, 17)) * nsPerUnit(.day)) + 2 * nsPerUnit(.hour);
        if (epoch_ns < dst_end_2018) return -2 * 3_600_000_000_000;
        if (epoch_ns >= dst_start_2018 and epoch_ns < dst_end_2019) return -2 * 3_600_000_000_000;
        return -3 * 3_600_000_000_000;
    }
    if (std.mem.eql(u8, name, "Australia/Lord_Howe")) {
        const dst_end_2020 = (@as(i128, tDaysFromCivil(2020, 4, 4)) * nsPerUnit(.day)) + 15 * nsPerUnit(.hour);
        const dst_start_2020 = (@as(i128, tDaysFromCivil(2020, 10, 3)) * nsPerUnit(.day)) + 15 * nsPerUnit(.hour) + 30 * nsPerUnit(.minute);
        if (epoch_ns < dst_end_2020 or epoch_ns >= dst_start_2020)
            return 11 * 3_600_000_000_000;
        return 10 * 3_600_000_000_000 + 30 * 60_000_000_000;
    }
    if (std.mem.eql(u8, name, "Asia/Singapore")) {
        const twenty_minute_jump = (@as(i128, tDaysFromCivil(1933, 1, 1)) * nsPerUnit(.day)) - 7 * nsPerUnit(.hour);
        if (epoch_ns >= twenty_minute_jump)
            return 7 * 3_600_000_000_000 + 20 * 60_000_000_000;
        return 7 * 3_600_000_000_000;
    }
    if (std.mem.eql(u8, name, "America/St_Johns")) {
        const dst_end_2010 = (@as(i128, tDaysFromCivil(2010, 11, 7)) * nsPerUnit(.day)) + 2 * nsPerUnit(.hour) + 31 * nsPerUnit(.minute);
        if (epoch_ns < dst_end_2010)
            return -(2 * 3_600_000_000_000 + 30 * 60_000_000_000);
        return -(3 * 3_600_000_000_000 + 30 * 60_000_000_000);
    }
    if (std.mem.eql(u8, name, "Antarctica/Casey")) {
        const dst_end_2010 = (@as(i128, tDaysFromCivil(2010, 3, 4)) * nsPerUnit(.day)) + 15 * nsPerUnit(.hour);
        if (epoch_ns < dst_end_2010)
            return 11 * 3_600_000_000_000;
        return 8 * 3_600_000_000_000;
    }
    if (std.mem.eql(u8, name, "America/Noronha")) {
        const dst_start_2000 = (@as(i128, tDaysFromCivil(2000, 10, 8)) * nsPerUnit(.day)) + 2 * nsPerUnit(.hour);
        const dst_end_2000 = (@as(i128, tDaysFromCivil(2000, 10, 15)) * nsPerUnit(.day)) + nsPerUnit(.hour);
        if (epoch_ns >= dst_start_2000 and epoch_ns < dst_end_2000)
            return -1 * 3_600_000_000_000;
        return -2 * 3_600_000_000_000;
    }
    if (std.mem.eql(u8, name, "America/Boa_Vista")) {
        const dst_start_2000 = (@as(i128, tDaysFromCivil(2000, 10, 8)) * nsPerUnit(.day)) + 4 * nsPerUnit(.hour);
        const dst_end_2000 = (@as(i128, tDaysFromCivil(2000, 10, 15)) * nsPerUnit(.day)) + 3 * nsPerUnit(.hour);
        if (epoch_ns >= dst_start_2000 and epoch_ns < dst_end_2000)
            return -3 * 3_600_000_000_000;
        return -4 * 3_600_000_000_000;
    }
    if (std.mem.eql(u8, name, "America/Los_Angeles")) {
        const dst_start_1965 = (@as(i128, tDaysFromCivil(1965, 4, 25)) * nsPerUnit(.day)) + 9 * nsPerUnit(.hour);
        const dst_end_1965 = (@as(i128, tDaysFromCivil(1965, 10, 31)) * nsPerUnit(.day)) + 9 * nsPerUnit(.hour);
        const dst_start_2000 = (@as(i128, tDaysFromCivil(2000, 4, 2)) * nsPerUnit(.day)) + 10 * nsPerUnit(.hour);
        const dst_end_2000 = (@as(i128, tDaysFromCivil(2000, 10, 29)) * nsPerUnit(.day)) + 9 * nsPerUnit(.hour);
        const dst_start_2020 = (@as(i128, tDaysFromCivil(2020, 3, 8)) * nsPerUnit(.day)) + 10 * nsPerUnit(.hour);
        const dst_end_2020 = (@as(i128, tDaysFromCivil(2020, 11, 1)) * nsPerUnit(.day)) + 9 * nsPerUnit(.hour);
        if (epoch_ns >= dst_start_1965 and epoch_ns < dst_end_1965)
            return -7 * 3_600_000_000_000;
        if (epoch_ns >= dst_start_2000 and epoch_ns < dst_end_2000)
            return -7 * 3_600_000_000_000;
        if (epoch_ns >= dst_start_2020 and epoch_ns < dst_end_2020)
            return -7 * 3_600_000_000_000;
        return -8 * 3_600_000_000_000;
    }
    if (std.mem.eql(u8, name, "America/New_York")) {
        const dst_start_2024 = (@as(i128, tDaysFromCivil(2024, 3, 10)) * nsPerUnit(.day)) + 7 * nsPerUnit(.hour);
        const dst_end_2024 = (@as(i128, tDaysFromCivil(2024, 11, 3)) * nsPerUnit(.day)) + 6 * nsPerUnit(.hour);
        if (epoch_ns >= dst_start_2024 and epoch_ns < dst_end_2024)
            return -4 * 3_600_000_000_000;
        return -5 * 3_600_000_000_000;
    }
    if (std.mem.eql(u8, name, "Pacific/Apia")) {
        const dateline_skip = (@as(i128, tDaysFromCivil(2011, 12, 30)) * nsPerUnit(.day)) + 10 * nsPerUnit(.hour);
        if (epoch_ns >= dateline_skip)
            return 14 * 3_600_000_000_000;
        return -10 * 3_600_000_000_000;
    }
    if (std.mem.eql(u8, name, "America/Toronto")) {
        const dst_start_1919 = (@as(i128, tDaysFromCivil(1919, 3, 31)) * nsPerUnit(.day)) + 4 * nsPerUnit(.hour) + 30 * nsPerUnit(.minute);
        if (epoch_ns >= dst_start_1919)
            return -4 * 3_600_000_000_000;
        return -5 * 3_600_000_000_000;
    }
    if (std.mem.eql(u8, name, "Pacific/Niue")) {
        const standard_time_start = -543_069_601_000_000_000; // 1952-10-15T23:59:59-11:20:00
        if (epoch_ns >= standard_time_start) return -(11 * 3_600_000_000_000 + 20 * 60_000_000_000);
        return -(11 * 3_600_000_000_000 + 19 * 60_000_000_000 + 40 * 1_000_000_000);
    }
    if (std.mem.eql(u8, name, "America/Vancouver")) {
        const standard_time_start_1883 = -2_717_650_800_000_000_000; // 1883-11-18T17:00:00Z
        if (epoch_ns < standard_time_start_1883)
            return -(8 * 3_600_000_000_000 + 12 * 60_000_000_000 + 28 * 1_000_000_000);
        const dst_start_1999 = (@as(i128, tDaysFromCivil(1999, 4, 4)) * nsPerUnit(.day)) + 10 * nsPerUnit(.hour);
        const dst_end_1999 = (@as(i128, tDaysFromCivil(1999, 10, 31)) * nsPerUnit(.day)) + 9 * nsPerUnit(.hour);
        const dst_start_2000 = (@as(i128, tDaysFromCivil(2000, 4, 2)) * nsPerUnit(.day)) + 10 * nsPerUnit(.hour);
        const dst_end_2000 = (@as(i128, tDaysFromCivil(2000, 10, 29)) * nsPerUnit(.day)) + 9 * nsPerUnit(.hour);
        const dst_start_2001 = (@as(i128, tDaysFromCivil(2001, 4, 1)) * nsPerUnit(.day)) + 10 * nsPerUnit(.hour);
        const dst_end_2001 = (@as(i128, tDaysFromCivil(2001, 10, 28)) * nsPerUnit(.day)) + 9 * nsPerUnit(.hour);
        const dst_start_2019 = (@as(i128, tDaysFromCivil(2019, 3, 10)) * nsPerUnit(.day)) + 10 * nsPerUnit(.hour);
        const dst_end_2019 = (@as(i128, tDaysFromCivil(2019, 11, 3)) * nsPerUnit(.day)) + 9 * nsPerUnit(.hour);
        const dst_start_2020 = (@as(i128, tDaysFromCivil(2020, 3, 8)) * nsPerUnit(.day)) + 10 * nsPerUnit(.hour);
        const dst_end_2020 = (@as(i128, tDaysFromCivil(2020, 11, 1)) * nsPerUnit(.day)) + 9 * nsPerUnit(.hour);
        const dst_start_2024 = (@as(i128, tDaysFromCivil(2024, 3, 10)) * nsPerUnit(.day)) + 10 * nsPerUnit(.hour);
        const dst_end_2024 = (@as(i128, tDaysFromCivil(2024, 11, 3)) * nsPerUnit(.day)) + 9 * nsPerUnit(.hour);
        const dst_start_2025 = (@as(i128, tDaysFromCivil(2025, 3, 9)) * nsPerUnit(.day)) + 10 * nsPerUnit(.hour);
        const dst_end_2025 = (@as(i128, tDaysFromCivil(2025, 11, 2)) * nsPerUnit(.day)) + 9 * nsPerUnit(.hour);
        if (epoch_ns >= dst_start_1999 and epoch_ns < dst_end_1999)
            return -7 * 3_600_000_000_000;
        if (epoch_ns >= dst_start_2000 and epoch_ns < dst_end_2000)
            return -7 * 3_600_000_000_000;
        if (epoch_ns >= dst_start_2001 and epoch_ns < dst_end_2001)
            return -7 * 3_600_000_000_000;
        if (epoch_ns >= dst_start_2019 and epoch_ns < dst_end_2019)
            return -7 * 3_600_000_000_000;
        if (epoch_ns >= dst_start_2020 and epoch_ns < dst_end_2020)
            return -7 * 3_600_000_000_000;
        if (epoch_ns >= dst_start_2024 and epoch_ns < dst_end_2024)
            return -7 * 3_600_000_000_000;
        if (epoch_ns >= dst_start_2025 and epoch_ns < dst_end_2025)
            return -7 * 3_600_000_000_000;
        return -8 * 3_600_000_000_000;
    }
    return fallback;
}

fn zdtOffsetAt(t: *const value.TemporalData) i64 {
    return timeZoneOffsetAtEpoch(t.tz_name, t.epoch_ns, t.tz_offset_ns);
}

/// Render a UTC offset (ns) as "±HH:MM" or "±HH:MM:SS".
fn offsetNsToString(self: *Interpreter, off: i64) EvalError![]const u8 {
    const neg = off < 0;
    var v: u64 = @intCast(if (neg) -off else off);
    const hh = v / 3_600_000_000_000;
    v %= 3_600_000_000_000;
    const mm = v / 60_000_000_000;
    v %= 60_000_000_000;
    const ss = v / 1_000_000_000;
    var buf: std.ArrayListUnmanaged(u8) = .empty;
    try buf.append(self.arena, if (neg) '-' else '+');
    try tfmtPad(self, &buf, hh, 2);
    try buf.append(self.arena, ':');
    try tfmtPad(self, &buf, mm, 2);
    if (ss != 0) {
        try buf.append(self.arena, ':');
        try tfmtPad(self, &buf, ss, 2);
    }
    return buf.toOwnedSlice(self.arena);
}

fn tIsZdt(this: Value) bool {
    return tIsTemporal(this, .zoned_date_time);
}

/// The ZonedDateTime's local civil date-time (epoch + offset).
fn zdtLocal(t: *const value.TemporalData) value.TemporalData {
    if (!std.mem.eql(u8, t.calendar, "iso8601") and (t.year != 0 or t.month != 1 or t.day != 1 or t.hour != 0 or t.minute != 0 or t.second != 0 or t.millisecond != 0 or t.microsecond != 0 or t.nanosecond != 0)) {
        var out: value.TemporalData = .{ .kind = .plain_date_time };
        out.year = t.year;
        out.month = t.month;
        out.day = t.day;
        out.hour = t.hour;
        out.minute = t.minute;
        out.second = t.second;
        out.millisecond = t.millisecond;
        out.microsecond = t.microsecond;
        out.nanosecond = t.nanosecond;
        out.calendar = t.calendar;
        return out;
    }
    const local = t.epoch_ns + zdtOffsetAt(t);
    const days = @divFloor(local, 86_400_000_000_000);
    const c = tCivilFromDays(@intCast(days));
    const cd = calendarDateFromIso(t.calendar, c.y, c.m, c.d);
    var out: value.TemporalData = .{ .kind = .plain_date_time };
    out.year = @intCast(cd.y);
    out.month = cd.m;
    out.day = cd.d;
    out.calendar = t.calendar;
    nsToTime(&out, local);
    return out;
}

fn temporalZonedDateTimeConstructorFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (self.new_target.isUndefined()) return self.throwError("TypeError", "Constructor Temporal.ZonedDateTime requires 'new'");
    const epoch_ns = try checkedEpochNsFromBigInt(self, if (args.len > 0) args[0] else Value.undef());
    if (args.len < 2 or args[1].isUndefined()) return self.throwError("TypeError", "ZonedDateTime requires a time zone");
    if (!args[1].isString()) return self.throwError("TypeError", "time zone must be a string");
    const tz = try parseTimeZoneBare(self, args[1].asStr());
    const cal = if (args.len > 2 and !args[2].isUndefined()) try toCalendarId(self, args[2], false) else "iso8601";
    const o = try makeTemporal(self, .zoned_date_time, "\x00T.ZonedDateTime");
    o.temporal.?.epoch_ns = epoch_ns;
    o.temporal.?.tz_name = tz.name;
    o.temporal.?.tz_offset_ns = tz.offset_ns;
    o.temporal.?.calendar = cal;
    try applyTemporalNewTargetProto(self, o);
    return Value.obj(o);
}

const ZdtField = enum {
    year,
    month,
    day,
    hour,
    minute,
    second,
    millisecond,
    microsecond,
    nanosecond,
    day_of_week,
    day_of_year,
    days_in_month,
    days_in_year,
    months_in_year,
    days_in_week,
    in_leap_year,
    hours_in_day,
    offset_ns,
    week_of_year,
    year_of_week,
};
fn temporalZdtGetter(comptime f: ZdtField) value.NativeFn {
    return struct {
        fn call(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
            _ = args;
            const self: *Interpreter = @ptrCast(@alignCast(ctx));
            if (!tIsZdt(this)) return self.throwError("TypeError", "Temporal.ZonedDateTime accessor on incompatible receiver");
            const t = this.asObj().temporal.?;
            const l = zdtLocal(t);
            const iso = calendarDateToIso(t.calendar, l.year, l.month, l.day);
            return switch (f) {
                .year => Value.num(@floatFromInt(l.year)),
                .month => Value.num(@floatFromInt(l.month)),
                .day => Value.num(@floatFromInt(l.day)),
                .hour => Value.num(@floatFromInt(l.hour)),
                .minute => Value.num(@floatFromInt(l.minute)),
                .second => Value.num(@floatFromInt(l.second)),
                .millisecond => Value.num(@floatFromInt(l.millisecond)),
                .microsecond => Value.num(@floatFromInt(l.microsecond)),
                .nanosecond => Value.num(@floatFromInt(l.nanosecond)),
                .day_of_week => Value.num(@floatFromInt(isoDayOfWeek(iso.y, iso.m, iso.d))),
                .day_of_year => Value.num(@floatFromInt(calDayOfYear(t.calendar, l.year, l.month, l.day))),
                .days_in_month => Value.num(@floatFromInt(calDaysInMonth(t.calendar, l.year, l.month))),
                .days_in_year => Value.num(@floatFromInt(calDaysInYear(t.calendar, l.year))),
                .months_in_year => Value.num(@floatFromInt(calMonthsInYear(t.calendar, l.year))),
                .days_in_week => Value.num(7),
                .in_leap_year => Value.boolVal(calInLeapYear(t.calendar, l.year)),
                .hours_in_day => blk: {
                    const today_ns = try zdtStartOfDayEpochNs(self, t, l.year, l.month, l.day);
                    const tomorrow = addCalendarDate(t.calendar, l.year, l.month, l.day, 0, 0, 0, 1, 1, true) orelse
                        return self.throwError("RangeError", "date overflow");
                    const tomorrow_ns = try zdtStartOfDayEpochNs(self, t, @intCast(tomorrow.y), tomorrow.m, tomorrow.d);
                    break :blk Value.num(@as(f64, @floatFromInt(tomorrow_ns - today_ns)) / @as(f64, @floatFromInt(DAY_NS)) * 24);
                },
                .offset_ns => Value.num(@floatFromInt(zdtOffsetAt(t))),
                .week_of_year => if (std.mem.eql(u8, t.calendar, "iso8601")) Value.num(@floatFromInt(isoWeekOfYear(iso.y, iso.m, iso.d).week)) else Value.undef(),
                .year_of_week => if (std.mem.eql(u8, t.calendar, "iso8601")) Value.num(@floatFromInt(isoWeekOfYear(iso.y, iso.m, iso.d).year)) else Value.undef(),
            };
        }
    }.call;
}

