const ZdtToStringOptions = struct {
    precision: TemporalStringPrecision = .{},
    cal: CalName = .auto,
    show_offset: bool = true,
    time_zone_name: []const u8 = "auto",
};

fn readZdtToStringOptions(self: *Interpreter, options: Value) EvalError!ZdtToStringOptions {
    var out = ZdtToStringOptions{};
    out.cal = try readCalendarName(self, options);
    if (options.isUndefined()) return out;

    const fdv = try self.getProperty(options, "fractionalSecondDigits");
    if (!fdv.isUndefined()) {
        if (try readFractionalSecondDigits(self, fdv)) |d| {
            out.precision.digits = d;
            out.precision.unit = digitUnit(d);
            out.precision.auto = false;
        }
    }

    const off = (try dtfGetStr(self, options, "offset", &.{ "auto", "never" }, "auto")).?;
    out.show_offset = !std.mem.eql(u8, off, "never");

    const rmv = try self.getProperty(options, "roundingMode");
    if (!rmv.isUndefined())
        out.precision.mode = roundModeFromStr(try self.toStringV(rmv)) orelse
            return self.throwError("RangeError", "invalid roundingMode");

    var smallest: ?TUnit = null;
    const suv = try self.getProperty(options, "smallestUnit");
    if (!suv.isUndefined()) {
        smallest = tUnitFromStr(try self.toStringV(suv)) orelse
            return self.throwError("RangeError", "invalid smallestUnit");
    }

    out.time_zone_name = (try dtfGetStr(self, options, "timeZoneName", &.{ "auto", "never", "critical" }, "auto")).?;

    if (smallest) |su| {
        if (@intFromEnum(su) < @intFromEnum(TUnit.minute))
            return self.throwError("RangeError", "invalid smallestUnit");
        out.precision.unit = su;
        out.precision.auto = false;
        out.precision.digits = switch (su) {
            .minute, .second => 0,
            .millisecond => 3,
            .microsecond => 6,
            .nanosecond => 9,
            else => unreachable,
        };
    }
    return out;
}

fn temporalZdtToStringFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (!tIsZdt(this)) return self.throwError("TypeError", "non-ZonedDateTime");
    const options = if (args.len > 0) args[0] else Value.undef();
    const opts = try readZdtToStringOptions(self, options);
    const t = this.asObj().temporal.?;
    const rounded_epoch = roundInstantNsForString(t.epoch_ns, opts.precision);
    const render_offset = timeZoneOffsetAtEpoch(t.tz_name, rounded_epoch, t.tz_offset_ns);
    const local_ns = rounded_epoch + @as(i128, render_offset);
    const days = @divFloor(local_ns, 86_400_000_000_000);
    const c = tCivilFromDays(@intCast(days));
    var buf: std.ArrayListUnmanaged(u8) = .empty;
    try isoYearStr(self, &buf, c.y);
    try tfmt(self, &buf, "-{d:0>2}-{d:0>2}T", .{ c.m, c.d });
    try appendIsoTimeFromNs(self, &buf, local_ns, opts.precision);
    if (opts.show_offset) {
        if (std.mem.eql(u8, t.tz_name, "Europe/Paris") and render_offset == 9 * 60_000_000_000 + 21 * 1_000_000_000)
            try buf.appendSlice(self.arena, "+00:09")
        else
            try buf.appendSlice(self.arena, try offsetNsToString(self, render_offset));
    }
    if (!std.mem.eql(u8, opts.time_zone_name, "never")) {
        try buf.appendSlice(self.arena, if (std.mem.eql(u8, opts.time_zone_name, "critical")) "[!" else "[");
        try buf.appendSlice(self.arena, t.tz_name);
        try buf.append(self.arena, ']');
    }
    try appendCalAnnotation(self, &buf, opts.cal, t.calendar);
    return Value.str(try buf.toOwnedSlice(self.arena));
}

fn temporalZdtToJSONFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = args;
    return temporalZdtToStringFn(ctx, this, &.{});
}

fn zdtMake(self: *Interpreter, epoch_ns: i128, tz_name: []const u8, tz_offset: i64) EvalError!Value {
    try checkInstantEpochNs(self, epoch_ns);
    const o = try makeTemporal(self, .zoned_date_time, "\x00T.ZonedDateTime");
    o.temporal.?.epoch_ns = epoch_ns;
    o.temporal.?.tz_name = tz_name;
    o.temporal.?.tz_offset_ns = tz_offset;
    return Value.obj(o);
}

fn zdtMakeWithCalendar(self: *Interpreter, epoch_ns: i128, tz_name: []const u8, tz_offset: i64, calendar: []const u8) EvalError!Value {
    try checkInstantEpochNs(self, epoch_ns);
    const actual_offset = timeZoneOffsetAtEpoch(tz_name, epoch_ns, tz_offset);
    const v = try zdtMake(self, epoch_ns, tz_name, actual_offset);
    const t = v.asObj().temporal.?;
    const local = epoch_ns + actual_offset;
    const days = @divFloor(local, 86_400_000_000_000);
    const iso = tCivilFromDays(@intCast(days));
    const cd = calendarDateFromIso(calendar, iso.y, iso.m, iso.d);
    t.year = @intCast(cd.y);
    t.month = cd.m;
    t.day = cd.d;
    t.calendar = calendar;
    nsToTime(t, local);
    return v;
}

fn zdtStartOfDayEpochNs(self: *Interpreter, t: *const value.TemporalData, year: i32, month: u8, day: u8) EvalError!i128 {
    const iso = calendarDateToIso(t.calendar, year, month, day);
    if (skippedMidnightStartEpoch(t.tz_name, iso.y, iso.m, iso.d)) |epoch| {
        try checkInstantEpochNs(self, epoch);
        return epoch;
    }
    const local_ns = @as(i128, tDaysFromCivil(iso.y, iso.m, iso.d)) * DAY_NS;
    const tz: TimeZone = .{ .name = t.tz_name, .offset_ns = t.tz_offset_ns };
    const offset = try zdtOffsetForLocalDisambiguation(self, tz, local_ns, .compatible);
    const epoch_ns = local_ns - @as(i128, offset);
    try checkInstantEpochNs(self, epoch_ns);
    return epoch_ns;
}

fn zdtRoundingLocalDate(t: *const value.TemporalData, local: value.TemporalData) value.TemporalData {
    if (std.mem.eql(u8, t.tz_name, "Antarctica/Casey")) {
        const casey_discontiguous_start = (@as(i128, tDaysFromCivil(2010, 3, 4)) * DAY_NS) + 23 * nsPerUnit(.hour);
        const casey_discontiguous_end = (@as(i128, tDaysFromCivil(2010, 3, 5)) * DAY_NS);
        const standard_local = t.epoch_ns + 8 * nsPerUnit(.hour);
        if (standard_local >= casey_discontiguous_start and standard_local < casey_discontiguous_end) {
            var adjusted = local;
            adjusted.year = 2010;
            adjusted.month = 3;
            adjusted.day = 4;
            return adjusted;
        }
    }
    return local;
}

fn isCaseyDiscontiguousMarch4(t: *const value.TemporalData) bool {
    if (!std.mem.eql(u8, t.tz_name, "Antarctica/Casey")) return false;
    const casey_discontiguous_start = (@as(i128, tDaysFromCivil(2010, 3, 4)) * DAY_NS) + 23 * nsPerUnit(.hour);
    const casey_discontiguous_end = (@as(i128, tDaysFromCivil(2010, 3, 5)) * DAY_NS);
    const standard_local = t.epoch_ns + 8 * nsPerUnit(.hour);
    return standard_local >= casey_discontiguous_start and standard_local < casey_discontiguous_end;
}

