        try setNative(a, rs, atomics, "or", 3, atomicsRMWFn(.or_));
        try setNative(a, rs, atomics, "xor", 3, atomicsRMWFn(.xor));
        try setNative(a, rs, atomics, "exchange", 3, atomicsRMWFn(.exchange));
