    const fn_v = proto.getOwn(method) orelse return;
    try proto.setOwn(a, rs, itv.asObj().sym_key, fn_v);
    try proto.setAttr(a, itv.asObj().sym_key, .{ .writable = true, .enumerable = false, .configurable = true });
}

/// Monotonic id for unique Symbol property-key encodings (single-threaded;
/// test262 workers are separate processes).
// Atomic: concurrent agents minting symbols must never collide on a key
// (bindings.md ruling — racing `+=` could yield duplicate sym_keys, i.e.
// two distinct Symbols comparing equal as property keys).
var symbol_counter = std.atomic.Value(usize).init(0);

/// Create a Symbol object: a tagged object with a unique `sym_key` (a NUL-led
/// string that can't collide with user property names) and a `description`.
fn makeSymbolObj(a: std.mem.Allocator, rs: *Shape, desc: ?[]const u8, proto: ?*value.Object) EvalError!Value {
    _ = rs;
    const o = try gc_mod.allocObj(a);
    o.* = .{ .is_symbol = true, .proto = proto, .sym_desc = desc };
    const n = symbol_counter.fetchAdd(1, .monotonic) + 1;
    o.sym_key = try std.fmt.allocPrint(a, "\x00s{d}", .{n});
    return Value.obj(o);
}

/// `Symbol.prototype`, resolved from the live `Symbol` binding (for linking
/// runtime-created symbols to it). Null only before globals are installed.
fn symbolProto(self: *Interpreter) ?*value.Object {
    const sym = self.env.get("Symbol") orelse return null;
    if (!sym.isObject()) return null;
    const p = sym.asObj().getOwn("prototype") orelse return null;
    return if (p.isObject()) p.asObj() else null;
}

/// `Date(...)` / `new Date(...)` → a Date object for the computed time.
/// Parse an ECMA-262 Date Time String Format string to a time value (ms since
/// epoch), or NaN. Handles YYYY[-MM[-DD]][THH:mm[:ss[.sss]]][Z|±HH:mm]; a
/// date-only or zoneless date-time is interpreted as UTC (this engine has no
/// local time zone).
fn dateParseISO(s_in: []const u8) f64 {
    const nan = std.math.nan(f64);
    const s = std.mem.trim(u8, s_in, " \t\n\r\x0c\x0b");
    if (s.len == 0) return nan;
    if (s[0] < '0' or s[0] > '9') {
        if (s[0] != '+' and s[0] != '-') return dateParseLegacyUTC(s);
    }
    var i: usize = 0;
    const readN = struct {
        fn f(str: []const u8, idx: *usize, count: usize) ?i64 {
            if (idx.* + count > str.len) return null;
            var v: i64 = 0;
            for (str[idx.* .. idx.* + count]) |c| {
                if (c < '0' or c > '9') return null;
                v = v * 10 + (c - '0');
            }
            idx.* += count;
            return v;
        }
    }.f;
    var ysign: i64 = 1;
    var ylen: usize = 4;
    if (s[0] == '+') {
        i += 1;
        ylen = 6;
    } else if (s[0] == '-') {
        ysign = -1;
        i += 1;
        ylen = 6;
    }
    const yv = readN(s, &i, ylen) orelse return nan;
    if (ysign < 0 and yv == 0) return nan;
    const year = ysign * yv;
    var month: i64 = 1;
    var day: i64 = 1;
    if (i < s.len and s[i] == '-') {
        i += 1;
        month = readN(s, &i, 2) orelse return nan;
        if (i < s.len and s[i] == '-') {
            i += 1;
            day = readN(s, &i, 2) orelse return nan;
        }
    }
    var hour: i64 = 0;
    var minute: i64 = 0;
    var sec: i64 = 0;
    var ms: i64 = 0;
    if (i < s.len and (s[i] == 'T' or s[i] == 't')) {
        i += 1;
        hour = readN(s, &i, 2) orelse return nan;
        if (i >= s.len or s[i] != ':') return nan;
        i += 1;
        minute = readN(s, &i, 2) orelse return nan;
        if (minute > 59) return nan;
        if (i < s.len and s[i] == ':') {
            i += 1;
            sec = readN(s, &i, 2) orelse return nan;
            if (i < s.len and s[i] == '.') {
                i += 1;
                var fcount: usize = 0;
                while (i < s.len and s[i] >= '0' and s[i] <= '9') : (i += 1) {
                    if (fcount < 3) {
                        ms = ms * 10 + (s[i] - '0');
                        fcount += 1;
                    }
                }
                if (fcount == 0) return nan;
                while (fcount < 3) : (fcount += 1) ms *= 10;
            }
        }
    }
    if (i < s.len and (s[i] == 'Z' or s[i] == 'z')) {
        i += 1;
    } else if (i < s.len and (s[i] == '+' or s[i] == '-')) {
        const osign: i64 = if (s[i] == '-') -1 else 1;
        i += 1;
        const oh = readN(s, &i, 2) orelse return nan;
        if (i < s.len and s[i] == ':') i += 1;
        const om = readN(s, &i, 2) orelse return nan;
        minute -= osign * (oh * 60 + om);
    }
    if (i != s.len) return nan;
    if (month < 1 or month > 12 or day < 1 or day > 31) return nan;
    if (hour > 24 or sec > 59) return nan;
    if (hour == 24 and (minute != 0 or sec != 0 or ms != 0)) return nan;
    const days = Interpreter.daysFromCivil(year, month, day);
    const total = days * 86_400_000 + hour * 3_600_000 + minute * 60_000 + sec * 1000 + ms;
    const f: f64 = @floatFromInt(total);
    if (std.math.isNan(f) or @abs(f) > 8.64e15) return nan;
    return f;
}

fn dateMonthIndex(s: []const u8) ?i64 {
    inline for (Interpreter.month_names, 0..) |m, i| {
        if (std.mem.eql(u8, s, m)) return @intCast(i + 1);
    }
    return null;
}

fn dateParseTime(s: []const u8, hour: *i64, minute: *i64, sec: *i64) bool {
    if (s.len != 8 or s[2] != ':' or s[5] != ':') return false;
    const read2 = struct {
        fn f(x: []const u8) ?i64 {
            if (x.len != 2 or x[0] < '0' or x[0] > '9' or x[1] < '0' or x[1] > '9') return null;
            return (x[0] - '0') * 10 + (x[1] - '0');
        }
    }.f;
    hour.* = read2(s[0..2]) orelse return false;
    minute.* = read2(s[3..5]) orelse return false;
    sec.* = read2(s[6..8]) orelse return false;
    return hour.* <= 24 and minute.* <= 59 and sec.* <= 59;
}

fn dateParseLegacyUTC(s: []const u8) f64 {
    const nan = std.math.nan(f64);
    var toks: [8][]const u8 = undefined;
    var n: usize = 0;
    var it = std.mem.tokenizeScalar(u8, s, ' ');
    while (it.next()) |tok| {
        if (n == toks.len) break;
        toks[n] = tok;
        n += 1;
    }
    if (n < 6) return nan;

    var day_tok: []const u8 = "";
    var month_tok: []const u8 = "";
    var year_tok: []const u8 = "";
    var time_tok: []const u8 = "";
    if (dateMonthIndex(toks[1]) != null) {
        day_tok = toks[2];
        month_tok = toks[1];
        year_tok = toks[3];
        time_tok = toks[4];
    } else if (dateMonthIndex(toks[2]) != null) {
        day_tok = toks[1];
        month_tok = toks[2];
        year_tok = toks[3];
        time_tok = toks[4];
    } else return nan;

    const month = dateMonthIndex(month_tok) orelse return nan;
    const day = std.fmt.parseInt(i64, day_tok, 10) catch return nan;
    const year = std.fmt.parseInt(i64, year_tok, 10) catch return nan;
    var hour: i64 = 0;
    var minute: i64 = 0;
    var sec: i64 = 0;
    if (!dateParseTime(time_tok, &hour, &minute, &sec)) return nan;
    if (day < 1 or day > 31) return nan;

    const days = Interpreter.daysFromCivil(year, month, day);
    const total = days * 86_400_000 + hour * 3_600_000 + minute * 60_000 + sec * 1000;
    const f: f64 = @floatFromInt(total);
    if (std.math.isNan(f) or @abs(f) > 8.64e15) return nan;
    return f;
}

fn dateParseFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    const s = try self.toStringV(if (args.len > 0) args[0] else Value.undef());
    return Value.num(dateParseISO(s));
}

fn dateConstructor(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (self.new_target.isUndefined()) {
        const d = (try self.makeDate(0)).asObj();
        return (try self.dateMethod(d, "toString", &.{})) orelse Value.str("Invalid Date");
    }
    if (args.len >= 2) {
        // Multi-component form: ToNumber each component once (invoking valueOf),
        // with years 0–99 mapped to 1900–1999.
        const buf = try self.arena.alloc(Value, args.len);
        for (args, 0..) |av, i| buf[i] = Value.num(try self.toNumberV(av));
        const yi = @trunc(buf[0].asNum());
        if (yi >= 0 and yi <= 99) buf[0] = Value.num(yi + 1900);
        return self.makeDate(Interpreter.dateTimeFromArgs(buf));
    }
    if (args.len == 1) {
        // `new Date(dateObject)` copies its time value; otherwise ToPrimitive
        // (a string would be parsed — not yet — else ToNumber).
        if (args[0].isObject() and args[0].asObj().is_date)
            return self.makeDate(args[0].asObj().dateMs());
        const prim = try self.toPrimitive(args[0], .default);
        if (prim.isString()) return self.makeDate(dateParseISO(prim.asStr()));
        // ToNumber(prim): a Symbol or BigInt primitive throws a TypeError.
        return self.makeDate(try self.toNumberV(prim));
    }
    return self.makeDate(0);
}

/// `Date.UTC(year [, month, day, hours, min, sec, ms])` — the time value for
/// the given UTC date components (NaN if any component is NaN; years 0–99 map
/// to 1900–1999).
fn dateUTCFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (args.len == 0) return Value.num(std.math.nan(f64));
    const n = @min(args.len, 7);
    var buf: [7]Value = undefined;
    // ToNumber every argument first, in order (each valueOf/toString runs, and a
    // Symbol/BigInt throws) — a NaN does not short-circuit the remaining coercions.
    var any_nan = false;
    for (0..n) |i| {
        const num = try self.toNumberV(args[i]);
        buf[i] = Value.num(num);
        if (std.math.isNan(num)) any_nan = true;
    }
    if (any_nan) return Value.num(std.math.nan(f64));
    // Years 0–99 are offset to 1900–1999.
    const yi = @trunc(buf[0].asNum());
    if (yi >= 0 and yi <= 99) buf[0] = Value.num(yi + 1900);
    var len = n;
    if (len == 1) {
        buf[1] = Value.num(0);
        len = 2;
    }
    return Value.num(Interpreter.dateTimeFromArgs(buf[0..len]));
}

/// `Date.now()` — monotonic milliseconds for progress-sensitive code. `new Date()`
/// and `Date()` remain deterministic epoch-based until wall-clock Date objects
/// are wired more broadly.
fn dateNow(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    _ = args;
    _ = ctx;
    return Value.num(agent.monotonicNowMs());
}

/// `Symbol([description])` — returns a fresh unique symbol. It has [[Construct]]
/// for IsConstructor probes, but `new Symbol` throws before argument coercion.
fn symbolFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (!self.new_target.isUndefined()) return self.throwError("TypeError", "Symbol is not a constructor");
    // `description` is ToString'd (honoring a `{toString}`/`{valueOf}` object);
    // a Symbol description is a TypeError, and `undefined` means none.
    const desc: ?[]const u8 = if (args.len > 0 and !args[0].isUndefined())
        try self.toStringV(args[0])
    else
        null;
    const sym = try makeSymbolObj(self.arena, self.root_shape, desc, symbolProto(self));
    _ = self.registerSymbol(sym.asObj());
    return sym;
}

/// The cross-realm GlobalSymbolRegistry, kept as a hidden object on the `Symbol`
/// constructor (key → symbol). The Context's `Symbol` binding persists across
/// `evaluate` calls, so the registry does too. NUL-prefixed so it never shows
/// up in enumeration.
fn symbolRegistry(self: *Interpreter) EvalError!?*value.Object {
    // Atomic get-or-create vs. concurrent `Symbol.for` / realm setup on peer
    // threads — otherwise two threads could each create a fresh registry and
    // one set of registrations would be lost.
    if (self.gil) |g| g.lockSymbolRegistry();
    defer if (self.gil) |g| g.unlockSymbolRegistry();
    return symbolRegistryLocked(self);
}

/// The registry get-or-create proper; the caller must already hold
/// `Gil.symbol_registry_lock` (when threads are on). Non-recursive, so a
/// critical section that also does the key lookup calls this, not `symbolRegistry`.
fn symbolRegistryLocked(self: *Interpreter) EvalError!?*value.Object {
    const sym = self.env.get("Symbol") orelse return null;
    if (!sym.isObject()) return null;
    if (sym.asObj().getOwn("\x00registry")) |r| {
        if (r.isObject()) return r.asObj();
    }
    const reg = (try self.newObject()).asObj();
    try sym.asObj().setOwn(self.arena, self.root_shape, "\x00registry", Value.obj(reg));
    return reg;
}

/// `Symbol.for(key)` — return the registered symbol for the string `key`,
/// creating and registering it on first use so equal keys yield the *same*
/// symbol. The registration key is stashed on the symbol (hidden) for `keyFor`.
fn symbolForFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    // `key` is ToString(arg) — honoring a `{toString}`/`{valueOf}` object and
    // throwing for a Symbol — not the raw default stringification.
    const key = if (args.len > 0) try self.toStringV(args[0]) else "undefined";
    // The whole lookup-or-register must be atomic vs. peer `Symbol.for(key)`
    // calls, or two threads could both miss `getOwn(key)` and register distinct
    // symbols for the same key — breaking `Symbol.for(k) === Symbol.for(k)`.
    if (self.gil) |g| g.lockSymbolRegistry();
    defer if (self.gil) |g| g.unlockSymbolRegistry();
    const reg = (try symbolRegistryLocked(self)) orelse return self.throwError("TypeError", "Symbol registry unavailable");
    if (reg.getOwn(key)) |existing| return existing;
    const sym = try makeSymbolObj(self.arena, self.root_shape, key, symbolProto(self));
    _ = self.registerSymbol(sym.asObj());
    try sym.asObj().setOwn(self.arena, self.root_shape, "\x00forKey", Value.str(key));
    try reg.setOwn(self.arena, self.root_shape, key, sym);
    return sym;
}

/// `Symbol.keyFor(sym)` — the registry key a symbol was registered under via
/// `Symbol.for`, or undefined if it isn't a registered symbol.
fn symbolKeyForFn(ctx: *anyopaque, this: Value, args: []const Value) value.HostError!Value {
    _ = this;
    const self: *Interpreter = @ptrCast(@alignCast(ctx));
    if (args.len == 0 or !args[0].isObject() or !args[0].asObj().is_symbol)
        return self.throwError("TypeError", "Symbol.keyFor requires a symbol argument");
    return args[0].asObj().getOwn("\x00forKey") orelse Value.undef();
}

/// Abstract Relational Comparison (subset): string<string is lexicographic,
/// everything else compares as numbers.
/// Streams a code-point-stored (WTF-8) JS string as its UTF-16 code units, so
/// strings compare by code unit — an astral scalar yields its high then low
/// surrogate — as the language's `IsLessThan` requires. Raw UTF-8 byte order
/// disagrees: an astral char's 4-byte form sorts after a BMP char in
/// U+E000..U+FFFF, but its leading surrogate (0xD800..) sorts before it.
const Utf16CodeUnits = struct {
    s: []const u8,
    i: usize = 0,
    low: ?u16 = null, // the trailing surrogate of an astral scalar, pending

    fn next(self: *Utf16CodeUnits) ?u16 {
        if (self.low) |l| {
            self.low = null;
            return l;
        }
        if (self.i >= self.s.len) return null;
        if (wtf8SurrogateAt(self.s, self.i)) |cp| {
            self.i += 3;
            return @intCast(cp);
        }
        const seq_len = utf8SeqLen(self.s, self.i);
        const end = @min(self.i + seq_len, self.s.len);
        const cp = std.unicode.utf8Decode(self.s[self.i..end]) catch {
            const b = self.s[self.i]; // invalid byte: take its value, advance one
            self.i += 1;
            return b;
        };
        self.i = end;
        if (cp > 0xFFFF) {
            const u = cp - 0x10000;
            self.low = @intCast(0xDC00 + (u & 0x3FF));
            return @intCast(0xD800 + (u >> 10));
        }
        return @intCast(cp);
    }
};

/// Lexicographic order of two JS strings by UTF-16 code unit.
fn compareStringsUtf16(a: []const u8, b: []const u8) std.math.Order {
    // Identical bytes are equal under any encoding — the common fast path.
    if (std.mem.eql(u8, a, b)) return .eq;
    var ai = Utf16CodeUnits{ .s = a };
    var bi = Utf16CodeUnits{ .s = b };
    while (true) {
        const ca = ai.next();
        const cb = bi.next();
        if (ca == null) return if (cb == null) .eq else .lt;
        if (cb == null) return .gt;
        if (ca.? != cb.?) return if (ca.? < cb.?) .lt else .gt;
    }
}

fn lessThan(self: *Interpreter, a: Value, b: Value) EvalError!bool {
    if (a.isString() and b.isString()) {
        return compareStringsUtf16(a.asStr(), b.asStr()) == .lt;
    }
    if ((a.isObject() and a.asObj().is_symbol) or (b.isObject() and b.asObj().is_symbol))
        return self.throwError("TypeError", "Cannot convert a Symbol value to a number");
    const x = a.toNumber();
    const y = b.toNumber();
    if (std.math.isNan(x) or std.math.isNan(y)) return false;
    return x < y;
}

/// Does `o` (own or via its prototype chain) have a data or accessor property
/// named `name`? Used by `with`-scope identifier resolution.
/// The root (global) lexical environment — where the installed globals and
/// top-level `var`/function bindings live.
fn rootEnv(env: *Environment) *Environment {
    var root = env;
    while (root.parent) |p| root = p;
    return root;
}

pub fn hasProperty(o: *value.Object, name: []const u8) bool {
    var cur: ?*value.Object = o;
    while (cur) |c| {
        if (c.getOwn(name) != null or c.getAccessor(name) != null) return true;
        // Dense array / typed-array / String-wrapper indices live outside the
        // slot store, so [[HasProperty]] must consult them on each chain object
        // (an inherited array element makes the index present on the receiver).
        if (value.canonicalIndex(name)) |idx| {
            if (c.is_array and idx < c.elements.items.len and !c.isHole(idx)) return true;
            if (c.typed_array) |ta| if (idx < (ta.currentLength() orelse 0)) return true;
            if (c.prim) |p| if (p.isString() and idx < Interpreter.utf16LenOfString(p.asStr())) return true;
        }
        cur = c.protoAtomic();
    }
    return false;
}

/// The parameter name a mapped-arguments index aliases, or null if `o` is not a
/// mapped arguments object or index `i` is unmapped (out of range / severed).
pub fn argMapName(o: *value.Object, i: usize) ?[]const u8 {
    if (o.arg_map_env == null or i >= o.arg_map_names.len) return null;
    const nm = o.arg_map_names[i];
    return if (nm.len == 0) null else nm;
}

/// Read a mapped index's parameter binding (null if unmapped).
pub fn argMapGet(o: *value.Object, i: usize) ?Value {
    const nm = argMapName(o, i) orelse return null;
    const env: *Environment = @ptrCast(@alignCast(o.arg_map_env.?));
    return env.get(nm);
}

/// Write a mapped index's parameter binding.
pub fn argMapSet(o: *value.Object, i: usize, v: Value) void {
    const nm = argMapName(o, i) orelse return;
    const env: *Environment = @ptrCast(@alignCast(o.arg_map_env.?));
    env.assign(nm, v) catch {};
}

/// CanonicalNumericIndexString(key): the Number a key denotes when it is the
/// canonical string form of that Number ("-0", "0", "1", "1.5", "Infinity", …),
/// else null. Used by the Integer-Indexed Exotic Object internal methods so a
/// numeric-looking key on a TypedArray is handled as an index (never as an
/// ordinary/inherited property), even when out of bounds or fractional.
pub fn canonicalNumericIndexString(key: []const u8) ?f64 {
    if (key.len == 0) return null;
    if (std.mem.eql(u8, key, "-0")) return -0.0;
    // A key must start like a number for this to ever match (cheap reject).
    const c0 = key[0];
    if ((c0 < '0' or c0 > '9') and c0 != '-' and c0 != '.' and c0 != 'I' and c0 != 'N') return null;
    const n = value.stringToNumber(key);
    var buf: [512]u8 = undefined;
    var fba = std.heap.FixedBufferAllocator.init(&buf);
    const s = value.numberToString(fba.allocator(), n) catch return null;
    return if (std.mem.eql(u8, s, key)) n else null;
}

/// IsValidIntegerIndex(O, index): true iff `n` is an in-bounds, integral,
/// non-negative, non-`-0` index into the (attached, in-bounds) typed array.
pub fn isValidIntegerIndex(ta: *const value.TypedArrayData, n: f64) bool {
    if (std.math.isNan(n) or std.math.isInf(n) or @trunc(n) != n) return false;
    if (n < 0) return false;
    if (n == 0 and std.math.signbit(n)) return false; // -0
    const len = ta.currentLength() orelse return false;
    return n < @as(f64, @floatFromInt(len));
}

/// Does `o` have `name` as an *own* property (data, accessor, array index, or
/// array `length`)? Backs `hasOwnProperty` / `propertyIsEnumerable` / `Object.hasOwn`.
pub fn objectHasOwn(o: *value.Object, name: []const u8) bool {
    // Private members (`#x`) are internal slots, invisible to all reflection.
    if (value.isPrivateKey(name)) return false;
    if (moduleNsOf(o)) |ns| return moduleNsHas(ns, name);
    // A TypedArray's integer-indexed elements: a canonical numeric key is an own
    // property iff it is a valid index (so "-0"/out-of-bounds/fractional are not).
    if (o.typed_array) |ta| {
        if (canonicalNumericIndexString(name)) |n| return isValidIntegerIndex(ta, n);
    }
    if (o.getOwn(name) != null or o.getAccessor(name) != null) return true;
    if (o.prim) |p| {
        if (p.isString()) {
            if (std.mem.eql(u8, name, "length")) return true;
            if (Interpreter.arrayIndex(name)) |i| return i < Interpreter.utf16LenOfString(p.asStr());
        }
    }
    if (o.is_array) {
        // A real Array always has an own `length`; an arguments object's `length`
        // is an ordinary own property already handled by getOwn above (so a
        // deleted one is genuinely absent).
        if (!o.is_arguments and std.mem.eql(u8, name, "length")) return true;
        if (Interpreter.arrayElementIndex(name)) |i| return o.denseElementPresent(i);
    }
    if (Interpreter.arrayElementIndex(name)) |i| return o.denseElementPresent(i);
    return false;
}

fn arg0(args: []const Value) Value {
    return if (args.len > 0) args[0] else Value.undef();
}

/// Integer `n` formatted in `radix` (2–36), e.g. `(255).toString(16)` → "ff".
/// `n.toString(radix)` for radix ≠ 10 — converts both the integer and (up to a
/// bounded number of digits) the fractional part of a finite number. Works in
/// f64 throughout so it isn't limited to u64-range integers.
fn numberToRadix(arena: std.mem.Allocator, n: f64, radix: usize) ![]const u8 {
    if (n == 0) return "0";
    const digits = "0123456789abcdefghijklmnopqrstuvwxyz";
    const rf: f64 = @floatFromInt(radix);
    const neg = n < 0;
    var int_part = @floor(@abs(n));
    var frac = @abs(n) - int_part;
    var buf: std.ArrayListUnmanaged(u8) = .empty;
    if (neg) try buf.append(arena, '-');
    // Integer part (built least-significant-digit first, then reversed).
    var int_digits: std.ArrayListUnmanaged(u8) = .empty;
    if (int_part == 0) {
        try int_digits.append(arena, '0');
    } else while (int_part >= 1) {
        const d = @mod(int_part, rf);
        try int_digits.append(arena, digits[@intFromFloat(d)]);
        int_part = @floor(int_part / rf);
    }
    std.mem.reverse(u8, int_digits.items);
    try buf.appendSlice(arena, int_digits.items);
    // Fractional part, bounded so an inexact binary fraction terminates.
    if (frac > 0) {
        try buf.append(arena, '.');
        var count: usize = 0;
        while (frac > 0 and count < 52) : (count += 1) {
            frac *= rf;
            const d = @floor(frac);
            try buf.append(arena, digits[@intFromFloat(d)]);
            frac -= d;
        }
    }
    return buf.items;
}

/// `n.toFixed(d)` — fixed-point with `d` decimals (d ≤ 18; no exponent forms).
/// Falls back to the default number string when the scaled value would overflow.
fn toFixed(arena: std.mem.Allocator, n: f64, d: usize) ![]const u8 {
    if (std.math.isNan(n)) return "NaN";
    if (std.math.isInf(n)) return if (n < 0) "-Infinity" else "Infinity";
    const neg = n < 0;
    const abs_n = @abs(n);
    const u64_max_f = @as(f64, @floatFromInt(std.math.maxInt(u64)));
    if (abs_n >= 1e21) return value.numberToString(arena, n);
    if (d > 18 and @trunc(n) == n and abs_n < u64_max_f) {
        var out: std.ArrayListUnmanaged(u8) = .empty;
        if (neg) try out.append(arena, '-');
        try out.print(arena, "{d}", .{@as(u64, @intFromFloat(abs_n))});
        try out.append(arena, '.');
        try out.appendNTimes(arena, '0', d);
        return out.items;
    }
    const scale = std.math.pow(f64, 10, @floatFromInt(d));
    if (std.math.isInf(scale) or scale >= u64_max_f) return value.numberToString(arena, n);
    const scaled_f = @round(@abs(n) * scale);
    if (std.math.isInf(scaled_f) or scaled_f >= u64_max_f) return value.numberToString(arena, n); // too big for fixed-point
    const scaled: u64 = @intFromFloat(scaled_f);
    const scale_u: u64 = @intFromFloat(scale);
    var buf: std.ArrayListUnmanaged(u8) = .empty;
    if (neg) try buf.append(arena, '-');
    try buf.print(arena, "{d}", .{scaled / scale_u});
    if (d > 0) {
        try buf.print(arena, ".{d:0>[1]}", .{ scaled % scale_u, d });
    }
    return buf.items;
}

/// Reformat Zig's scientific output (`1.234e1`, `-9.99e-40`) to JS form, where
/// the exponent always carries a sign (`1.234e+1`, `-9.99e-40`).
fn jsExpFix(arena: std.mem.Allocator, s: []const u8) ![]const u8 {
    const ei = std.mem.indexOfScalar(u8, s, 'e') orelse return arena.dupe(u8, s);
    const mant = s[0..ei];
    const exp = s[ei + 1 ..];
    var sign: u8 = '+';
    var start: usize = 0;
    if (exp.len > 0 and (exp[0] == '-' or exp[0] == '+')) {
        sign = exp[0];
        start = 1;
    }
    while (start + 1 < exp.len and exp[start] == '0') start += 1;
    return std.fmt.allocPrint(arena, "{s}e{c}{s}", .{ mant, sign, exp[start..] });
}

fn renderScientificFixed(arena: std.mem.Allocator, n: f64, frac: usize) ![]const u8 {
    var raw: [512]u8 = undefined;
    const len = snprintf(raw[0..].ptr, raw.len, "%.*e", @as(c_int, @intCast(frac)), @as(f64, n));
    if (len < 0 or @as(usize, @intCast(len)) >= raw.len) return error.OutOfMemory;
    return jsExpFix(arena, raw[0..@intCast(len)]);
}

/// `Number.prototype.toExponential` — scientific notation with `frac` fraction
/// digits (or shortest when null), exponent always signed.
fn toExponentialStr(arena: std.mem.Allocator, n: f64, frac: ?usize) ![]const u8 {
    if (n == 0) {
        var out: std.ArrayListUnmanaged(u8) = .empty;
        try out.append(arena, '0');
        if (frac) |f| if (f > 0) {
            try out.append(arena, '.');
            try out.appendNTimes(arena, '0', f);
        };
        try out.appendSlice(arena, "e+0");
        return out.items;
    }
    var buf: [512]u8 = undefined;
    if (frac) |f| if (f >= 16) return renderScientificFixed(arena, n, f);
    const s = std.fmt.float.render(&buf, n, .{ .mode = .scientific, .precision = frac }) catch return error.OutOfMemory;
    return jsExpFix(arena, s);
}

/// `Number.prototype.toPrecision` — `p` significant digits, choosing fixed or
/// exponential notation per spec (exponential when the decimal exponent is
/// < -6 or >= p).
fn toPrecisionStr(arena: std.mem.Allocator, n: f64, p: usize) ![]const u8 {
    if (n == 0) {
        if (p == 1) return "0";
        var z: std.ArrayListUnmanaged(u8) = .empty;
        try z.appendSlice(arena, "0.");
        try z.appendNTimes(arena, '0', p - 1);
        return z.items;
    }
    const neg = n < 0;
    // Scientific with p-1 fraction digits yields exactly p significant digits.
    const s = try renderScientificFixed(arena, @abs(n), p - 1);
    // Parse "d.ddd...eX": collect the significant digits and the decimal exponent.
    const ei = std.mem.indexOfScalar(u8, s, 'e').?;
    var digits: std.ArrayListUnmanaged(u8) = .empty;
    for (s[0..ei]) |c| if (c != '.') try digits.append(arena, c);
    const exp = std.fmt.parseInt(i32, s[ei + 1 ..], 10) catch 0;
    const nd: i32 = @intCast(digits.items.len);

    var out: std.ArrayListUnmanaged(u8) = .empty;
    if (neg) try out.append(arena, '-');
    if (exp < -6 or exp >= @as(i32, @intCast(p))) {
        // Exponential form: d.ddd e±X
        try out.append(arena, digits.items[0]);
        if (digits.items.len > 1) {
            try out.append(arena, '.');
            try out.appendSlice(arena, digits.items[1..]);
        }
        try out.appendSlice(arena, try jsExpFix(arena, try std.fmt.allocPrint(arena, "e{d}", .{exp})));
    } else if (exp >= 0) {
        const ip: usize = @intCast(exp + 1); // digits before the decimal point
        if (ip >= digits.items.len) {
            try out.appendSlice(arena, digits.items);
            try out.appendNTimes(arena, '0', ip - digits.items.len);
        } else {
            try out.appendSlice(arena, digits.items[0..ip]);
            try out.append(arena, '.');
            try out.appendSlice(arena, digits.items[ip..]);
        }
    } else {
        // exp in [-6, -1]: 0.00…digits
        try out.appendSlice(arena, "0.");
        try out.appendNTimes(arena, '0', @intCast(-exp - 1));
        try out.appendSlice(arena, digits.items);
    }
    _ = nd;
    return out.items;
}

fn arg(args: []const Value, i: usize) Value {
    return if (i < args.len) args[i] else Value.undef();
}

fn labelEq(a: ?[]const u8, b: ?[]const u8) bool {
    if (a == null or b == null) return false;
    return std.mem.eql(u8, a.?, b.?);
}

fn relationalNaN(a: Value, b: Value) bool {
    if (a.isString() and b.isString()) return false;
    return std.math.isNan(a.toNumber()) or std.math.isNan(b.toNumber());
}

// ---------------------------------------------------------------------------
// Tests
// ---------------------------------------------------------------------------

const Parser = @import("parser.zig").Parser;

fn evalSource(arena: std.mem.Allocator, src: []const u8) !Value {
    var parser = try Parser.init(arena, src);
    const prog = try parser.parseProgram();
    var env = Environment{ .arena = arena };
    const root_shape = try Shape.createRoot(arena);
    try installGlobals(&env, root_shape);
    var interp = Interpreter{ .arena = arena, .env = &env, .root_shape = root_shape };
    // The TDZ sentinel (a unique object marking a declared-but-uninitialized
    // let/const) is normally installed by Context.init; this bare test-helper
    // interpreter must create it too, or any TDZ-using program (classes, a
    // let/const read before init) crashes in `tdzVal`.
    const tdz = try arena.create(value.Object);
    tdz.* = .{};
    interp.tdz_marker = tdz;
    return interp.eval(prog);
}

test "interpreter evaluates arithmetic with precedence" {
    var arena = std.heap.ArenaAllocator.init(std.testing.allocator);
    defer arena.deinit();
    const v = try evalSource(arena.allocator(), "1 + 2 * 3");
    try std.testing.expectEqual(@as(f64, 7), v.asNum());
}

