test "interpreter direct eval new target early errors" {
    var arena = std.heap.ArenaAllocator.init(std.testing.allocator);
    defer arena.deinit();
    const a = arena.allocator();

    try std.testing.expect((try evalSource(a,
        \\let seen;
        \\function f() { seen = eval('new.target;'); }
        \\f();
        \\let plain = seen === undefined;
        \\new f();
        \\plain && seen === f
    )).asBool());
    try std.testing.expectEqualStrings("SyntaxError", (try evalSource(a,
        \\let name = "";
        \\try { eval('new.target;'); } catch (e) { name = e.name; }
        \\name
    )).asStr());
    try std.testing.expectEqualStrings("SyntaxError", (try evalSource(a,
        \\let name = "";
        \\let f = () => eval('new.target;');
        \\try { f(); } catch (e) { name = e.name; }
        \\name
    )).asStr());
    try std.testing.expectEqualStrings("SyntaxError", (try evalSource(a,
        \\let name = "";
        \\function f() {
        \\  try { (0, eval)('new.target;'); } catch (e) { name = e.name; }
        \\}
        \\f();
        \\name
    )).asStr());
}

test "interpreter direct eval super early errors run before side effects" {
    var arena = std.heap.ArenaAllocator.init(std.testing.allocator);
    defer arena.deinit();
    const a = arena.allocator();

    try std.testing.expect((try evalSource(a,
        \\let executed = false;
        \\function f() {
        \\  try { eval('executed = true; super();'); } catch (e) { return e instanceof SyntaxError; }
        \\}
        \\f() && executed === false
    )).asBool());
    try std.testing.expect((try evalSource(a,
        \\let evaluated = false;
        \\let obj = { method() {
        \\  try { eval('super(evaluated = true);'); } catch (e) { return e instanceof SyntaxError; }
        \\} };
        \\obj.method() && evaluated === false
    )).asBool());
    try std.testing.expect((try evalSource(a,
        \\let executed = false;
        \\class Base {
        \\  constructor() {
        \\    try { eval('executed = true; super();'); } catch (e) { this.name = e.name; }
        \\  }
        \\}
        \\let base = new Base();
        \\base.name === 'SyntaxError' && executed === false
    )).asBool());
    try std.testing.expectEqual(@as(f64, 42), (try evalSource(a,
        \\class Base { constructor(v) { this.v = v; } }
        \\class Derived extends Base { constructor() { eval('super(42);'); } }
        \\new Derived().v
    )).asNum());
    try std.testing.expectEqual(@as(f64, 7), (try evalSource(a,
        \\class Base { get value() { return 7; } }
        \\class Derived extends Base { method() { return eval('super.value;'); } }
        \\new Derived().method()
    )).asNum());
}

