test "interpreter class private fields/methods and static blocks" {
    var arena = std.heap.ArenaAllocator.init(std.testing.allocator);
    defer arena.deinit();
    const a = arena.allocator();
    // private field + private method
    try std.testing.expectEqual(@as(f64, 30), (try evalSource(a,
        \\class Counter {
        \\  #count = 0;
        \\  #step() { return 10; }
        \\  bump() { this.#count = this.#count + this.#step(); return this.#count; }
        \\}
        \\let c = new Counter();
        \\c.bump(); c.bump(); c.bump()
    )).asNum());
    // static initialization block
    try std.testing.expectEqual(@as(f64, 42), (try evalSource(a,
        \\class C { static x; static { this.x = 42; } }
        \\C.x
    )).asNum());
    // A nested class body can use private names from the enclosing class body.
    try std.testing.expectEqual(@as(f64, 42), (try evalSource(a,
        \\class Outer {
        \\  #x = 42;
        \\  f() {
        \\    var self = this;
        \\    return class Inner { g() { return self.#x; } };
        \\  }
        \\}
        \\var Inner = new Outer().f();
        \\new Inner().g()
    )).asNum());
    try std.testing.expectEqual(@as(f64, 42), (try evalSource(a,
        \\class Base { constructor(obj) { return obj; } }
        \\class C extends Base {
        \\  constructor(obj) { super(obj); }
        \\  #m() { return 42; }
        \\  static val(obj) { return obj.#m(); }
        \\}
        \\C.val(new C({}))
    )).asNum());
    try std.testing.expectError(error.Throw, evalSource(a,
        \\class Base { constructor(obj) { return obj; } }
        \\class C extends Base {
        \\  constructor(obj) { super(obj); }
        \\  #m() { return 42; }
        \\}
        \\new C(Object.preventExtensions({}))
    ));
}

