test "interpreter class extends and super" {
    var arena = std.heap.ArenaAllocator.init(std.testing.allocator);
    defer arena.deinit();
    const a = arena.allocator();
    // super() in constructor + inherited method
    try std.testing.expectEqual(@as(f64, 30), (try evalSource(a,
        \\class Animal { constructor(n) { this.legs = n; } legCount() { return this.legs; } }
        \\class Dog extends Animal { constructor() { super(4); } }
        \\let d = new Dog();
        \\d.legCount() * 7 + 2
    )).asNum());
    // super.method() calls the parent's version
    try std.testing.expectEqual(@as(f64, 11), (try evalSource(a,
        \\class A { val() { return 10; } }
        \\class B extends A { val() { return super.val() + 1; } }
        \\(new B()).val()
    )).asNum());
    // instanceof across the chain
    try std.testing.expect((try evalSource(a,
        \\class A {}
        \\class B extends A {}
        \\let b = new B();
        \\b instanceof B && b instanceof A
    )).asBool());
    // default derived constructor forwards args
    try std.testing.expectEqual(@as(f64, 42), (try evalSource(a,
        \\class Base { constructor(x) { this.x = x; } }
        \\class Sub extends Base {}
        \\(new Sub(42)).x
    )).asNum());
    // inherited static method
    try std.testing.expectEqual(@as(f64, 16), (try evalSource(a,
        \\class P { static sq(n) { return n * n; } }
        \\class C extends P {}
        \\C.sq(4)
    )).asNum());
    try std.testing.expect((try evalSource(a,
        \\var evaluated = false;
        \\var caught;
        \\class C extends Object {
        \\  constructor() {
        \\    try { super(evaluated = true); } catch (e) { caught = e; }
        \\  }
        \\}
        \\Object.setPrototypeOf(C, parseInt);
        \\try { new C(); } catch (e) {}
        \\evaluated && caught instanceof TypeError
    )).asBool());
    try std.testing.expectEqualStrings("Symbol(foo)", (try evalSource(a,
        \\class Base { constructor(v) { this.v = v; } }
        \\class C extends Base {
        \\  constructor() { super(Symbol("foo")); }
        \\}
        \\new C().v.toString()
    )).asStr());
    try std.testing.expectEqualStrings("prop", (try evalSource(a,
        \\var log = "";
        \\class B {}
        \\class C extends B {
        \\  m() {
        \\    function prop() { log += "prop"; throw "stop"; }
        \\    function rhs() { log += "rhs"; }
        \\    try { super[prop()] = rhs(); } catch (e) {}
        \\  }
        \\}
        \\new C().m();
        \\log
    )).asStr());
    try std.testing.expectEqualStrings("rhs,key", (try evalSource(a,
        \\var log = "";
        \\var key = { toString() { log += ",key"; return "x"; } };
        \\class B {}
        \\class C extends B {
        \\  m() {
        \\    function rhs() { log += "rhs"; return 1; }
        \\    super[key] = rhs();
        \\  }
        \\}
        \\new C().m();
        \\log
    )).asStr());
    try std.testing.expectEqual(@as(f64, 1), (try evalSource(a,
        \\var count = 0;
        \\class C { static m() { super.x = count += 1; } }
        \\Object.setPrototypeOf(C, null);
        \\try { C.m(); } catch (e) {}
        \\count
    )).asNum());
    try std.testing.expectError(error.Throw, evalSource(a, "class C {} C()"));
    try std.testing.expectError(error.Throw, evalSource(a,
        \\class C extends Object { constructor() {} }
        \\new C()
    ));
    try std.testing.expectError(error.Throw, evalSource(a,
        \\class C extends Object { constructor() { return null; } }
        \\new C()
    ));
    try std.testing.expect((try evalSource(a,
        \\class C extends Object { constructor() { return { ok: true }; } }
        \\new C().ok
    )).asBool());
}

test "interpreter assignment and parameter destructuring" {
    var arena = std.heap.ArenaAllocator.init(std.testing.allocator);
    defer arena.deinit();
    const a = arena.allocator();
